// Sources: Lewis & Short (public domain), Agricola specialist terms

const LATIN_DICT = {"-cunque":{"lemma":"-cunque","pos":"adv.","gen":"-cunque","def":", v. cumque. cūnŭlae, ārum, f. dim. cunae, a little cradle, Prud. Cath. 7, 164"},"a":{"lemma":"a","pos":"prep.","gen":"","def":"=ab, v. ab. ā, interj.=ah, v. ah. Aărōn (Aārōn, Prud. Psych. 884), indecl. or ōnis, m., Aaron, brother of Moses, and first high-priest of the Hebrews, Vulg. Exod. 4, 14"},"ab-iungo":{"lemma":"ab-jungo","pos":"v.","gen":"-jungo","def":"a. Lit., to unyoke: juvencum, Verg. G. 3, 518.— Hence, Transf., to detach from a thing, to remove, separate: abjuncto Labieno, Caes. B. G. 7"},"ab-iurgo":{"lemma":"ab-jurgo","pos":"v.","gen":"-jurgo","def":"a., to deny or refuse reproachfully: arma alicui, Hyg. Fab. 107. ab-jūro, āvi, ātum, 1, v. a. (abjurassit for abjuraverit, Plaut. Pers. 4, 3, 9)"},"ab-lacto":{"lemma":"ab-lacto","pos":"v.","gen":"-lacto","def":"a., to wean (eccl. Lat.). ablăquĕātĭo, ōnis, f. ablaqueo, a digging or loosening of the soil round the roots of a tree, Col. 4, 4, 2; 4, 8, 2"},"ab-nocto":{"lemma":"ab-nocto","pos":"v.","gen":"-nocto","def":"n. nox, to pass the night abroad, to stay out all night, Sen. Vit. Beat. 26; Gell. 13, 12 fin.; Dig. 1, 18, 15. ab-nōdo, āre, 1, v. a., to cut off knots"},"ab-normis":{"lemma":"ab-normis","pos":"adj.","gen":"-normis","def":"norma, v. ab, III. 1., deviating or departing from a fixed rule, irregular, abnormal: abnormis sapiens, Hor. S. 2, 2, 3 (i. e. qui in nullius verba juravit, belongs to no distinct sect or party"},"ab-rumpo":{"lemma":"ab-rumpo","pos":"v.","gen":"-rumpo","def":"a., to break off something violently, to rend, tear, sever (poet."},"ab-scindo":{"lemma":"ab-scindo","pos":"v.","gen":"-scindo","def":"a., to tear off or away, to rend away (v. preced. art.). Lit.: tunicam a pectore abscidit, he tore the tunic down from his breast, Cic. Verr. 2, 5, 1: cervicibus fractis caput abscidit, cut off"},"ab-soluo":{"lemma":"ab-solvo","pos":"v.","gen":"-solvo","def":"a., to loosen from, to make loose, set free, detach, untie (usu. trop., the fig. being derived from fetters, qs. a vinculis solvere, like vinculis exsolvere, Plaut. Truc. 3, 4"},"ab-sto":{"lemma":"ab-sto","pos":"v.","gen":"-sto","def":"n., to stand off or at a distance from, to stand aloof: si longius abstes, Hor. A. P. 361. abstractĭo, ōnis, f. abstraho, a separation: conjugis, Dict. Cret. 1, 4. abstractus, a, um"},"ab-sum":{"lemma":"ab-sum","pos":"v.","gen":"-sum","def":"n., in its most general signif., to be away from, be absent. In gen. Absol. without designating the distance (opp. adsum): num ab domo absum? Plaut. Ep. 5, 2, 16: me absente atque insciente"},"ab-surdus":{"lemma":"ab-surdus","pos":"adj.","gen":"-surdus","def":"ab, mis-, and Sanscr. svan = sonare; cf. susurrus, and σῦριγξ, = a pipe"},"abaddon":{"lemma":"Abaddon","pos":"","gen":"","def":"indecl. Heb. destruction, the name of the angel of Tartarus, Vulg. Apoc. 9, 11. ăb-aestŭo, āvi, ātum, 1, v. n. (prop. to wave down, hence), poet., to hang down richly: laetis ut vitis abaestuet uvis"},"abas":{"lemma":"Abas","pos":"adj.","gen":"-ant","def":"=˝Αβας. The twelfth king of Argos, son of Lynceus and Hypermnestra, grandson of Danaūs, father of Acrisius, and grandfather of Perseus. His shield was gained by Aeneas, Verg. A. 3"},"abax":{"lemma":"abax","pos":"","gen":"","def":"abacus init. Abba, ae, false read. in Liv. 30, 7, 10, Instead of Obba, q. v.) abba, indecl.,=ůββū , father, Vulg. Marc. 14, 36; ib. Rom. 8, 15"},"abbassus":{"lemma":"Abbassus","pos":"","gen":"","def":", =Ἄμβασον, Abbassus, a town in Phrygia, Liv. 38, 15 fin. abbrĕviătio, ōnis, f. abbrevio, an abbreviation, a diminution, Vulg. Isa. 10, 23. ab-brĕvĭo, āre, v. freq. a. ab or adbrevio, to shorten"},"abella":{"lemma":"Abella","pos":"","gen":"-trees","def":", a town in Campania, near Nolu, abounding in fruit-trees and nuts, now Avella, Sil. 8, 545: malifera, Verg. A. 7, 740. —Hence, Abellāna nux or Avellana, also Abellina, the filbert, Plin. 15, 22, 24"},"abiectus":{"lemma":"abjectus","pos":"","gen":"","def":"abicio, P. a."},"abiicio":{"lemma":"abjicio","pos":"","gen":"","def":"abicio. abjūdĭcātīvus, a, um, adj., in later philos. lang. = negativus, negative, Pseudo pp. Dogm. Plat. p. 30 Elm. (267 Oud.). ab-jūdĭco, āvi, ātum, 1, v. a."},"abortum":{"lemma":"abortum","pos":"","gen":"","def":", v. the foll. art. ăbortus, ūs, m. (abortum, i, n., Dig. 29, 2, 30"},"abruptus":{"lemma":"abruptus","pos":"","gen":"","def":"abrumpo, P. a. abs. prep., v. ab. abs-cēdo, cessi, cessum, 3, v. n. (sync. abscēssem = abscessissem, Sil. 8, 109), to go off or away, to depart. Lit. In gen.: abscede hinc, sis, sycophanta"},"abs-condo":{"lemma":"abs-condo","pos":"v.","gen":"-condo","def":"a. (abscondi, Tac. H. 3, 68; Curt. 6, 6; Gell. 17, 9; Caecil. and Pompon. ap. Non. 75, 25: abscondidi, Plaut. Merc. 2, 3, 25"},"abs-pello":{"lemma":"abs-pello","pos":"","gen":"-pello","def":"asp-."},"abs-que":{"lemma":"abs-que","pos":"prep.","gen":"-que","def":"gov. abl. [from abs and the generalizing -que, like susque deque from sub and de"},"abscessus":{"lemma":"abscessus","pos":"","gen":"","def":"id., a going away, departure, absence: solis, * Cic. N. D. 1, 10, 24; Verg. A. 10, 445; Tac. A. 4, 57: continuus, continued absence, id. ib. 6, 38. — Medic. t. t., an abscess, Cels. 5, 7"},"absegmen":{"lemma":"absegmen","pos":"","gen":"-seco","def":"ab-seco, according to Festus, s. v. penitam, ap. Naev., a piece (of flesh) cut off, Paul. ex Fest. p. 242, 6 Müll. absens, entis (not apsens), Part. of absum. absentĭa, ae, f. absum"},"absento":{"lemma":"absento","pos":"v.","gen":"","def":"a. and n. id.. Act., to cause one to be absent, i. e. to send away: patriis procul absentaverit astris, Claud. Pros. 3, 213 (others read amandaverit, or patriisque procul mandaverit), Cod. Th. 12, 1"},"absyrtis":{"lemma":"Absyrtis","pos":"","gen":"","def":"2 Absyrtus."},"absyrtus":{"lemma":"Absyrtus","pos":"","gen":"","def":", = Ἄψυρτος, a son of Aeetes, king of Colchis, killed by his sister Medea in her flight with Jason"},"abyla":{"lemma":"Abyla","pos":"","gen":"","def":", = Ἀβύλη, a spur of a mountain in Africa, on the strait of Gibraltar, one of the Pillars of Hercules, opposite Calpe, Mel. 15, 3"},"ac":{"lemma":"ac","pos":"conj.","gen":"","def":", v. atque. ăcācĭa, ae, f., = ἀκακία. The acacia-tree, the Egyptian pod-thorn: Mimosa Nilotica, Linn.; described by Plin. 24, 12, 67, § 109 sq.— The juice or gum of the same, Cels. 6, 6"},"ac-canto":{"lemma":"ac-canto","pos":"v.","gen":"-canto","def":"n., to sing at: tumulis, Stat. Silv. 4, 4, 55."},"ac-cendo":{"lemma":"ac-cendo","pos":"v.","gen":"-cendo","def":"a. cf. candeo, prop. to kindle any thing above, so that it may burn downwards (on the contr., succendere, to kindle underneath, so that it may burn upwards"},"ac-centor":{"lemma":"ac-centor","pos":"","gen":"-centor","def":"ad + cantor, one who sings with another, Isid. Orig. 6, 19, 3."},"ac-cognosco":{"lemma":"ac-cognosco","pos":"v.","gen":"-cognosco","def":"a., to know or recognize perfectly, Petr. Fragm. 69 Burm.; Tert. ad Ux. 2, 6"},"acanthus":{"lemma":"Acanthus","pos":"","gen":"","def":", = Ἄκανθος, a town of Macedonia, now Erisso, Liv. 31, 45 fin.; Mel. 2, 2, 9"},"acastus":{"lemma":"Acastus","pos":"","gen":"","def":", = Ἄκαστος. Son of Pelias, king of Thessaly, husband of Astydamia or Cretheis, and father of Laodamia, Ov. M. 8, 306"},"acaunumarga":{"lemma":"acaunumarga","pos":"","gen":"-marl","def":"a Celtic word from agaunum, stone, a kind of marl, perhaps stone-marl, Plin. 17, 7, 4, § 44. ăcaustus, a, um, adj., = ἄκαυστος, incombustible"},"acca":{"lemma":"Acca","pos":"","gen":"-rent","def":"cf. Sct. accā = mater, and the Gr. Ἀκκώ = mater Cereris. Lā-rentĭa, the wife of the shepherd Faustulus, who nursed and brought up the twins Romulus and Remus"},"accantus":{"lemma":"accantus","pos":"","gen":"","def":", = accentus, Mart. Cap. 3, p. 60"},"accendo":{"lemma":"accendo","pos":"","gen":"","def":"2. accendo, an inciter, instigator; read by Salmasius in Tert. de Pall. 6, where the old reading cerdo is to be preferred."},"accensus":{"lemma":"accensus","pos":"","gen":"","def":"Part. of accendo, kindled.— P. a. of accenseo, reckoned among; v. these words."},"accentus":{"lemma":"accentus","pos":"","gen":"","def":"accino, the attuning a thing; hence Lit. In gen., a blast, signal (late Lat.): aeneatorum accentu, Amm. 16, 12, 36: id. 24, 4, 22"},"accepta":{"lemma":"accepta","pos":"","gen":"","def":"accipio (sc. pars), a portion of land granted to an individual by the state, Sicul. Fl. p. 22 Goed. al. acceptābĭlis, e, adj. accepto, acceptable, worthy of acceptance (eccl. Lat.)"},"accepto":{"lemma":"accepto","pos":"","gen":"","def":"freq. a. accipio, to take, receive, accept: argentum, Plaut. Ps. 2, 2, 32; so Quint. 12, 7, 9; Curt. 4, 6, 5"},"acceptor":{"lemma":"acceptor","pos":"","gen":"-class","def":"id.. One who receives a thing (post-class.): donationis, Cod. T. 8, 56, 10.—Hence, absol., a receiver, collector, Inscr. Orell. no. 3199 and 7205.— Fig. One who receives a thing as true"},"acceptrix":{"lemma":"acceptrix","pos":"","gen":"","def":"id., she that receives: neque datori neque acceptrici, Plaut. Truc. 2, 7, 18."},"acceptum":{"lemma":"acceptum","pos":"","gen":"","def":", v. accipio, II. E."},"acceptus":{"lemma":"acceptus","pos":"","gen":"","def":"accipio, P. a."},"accerso":{"lemma":"accerso","pos":"","gen":"","def":"arcesso init."},"accessa":{"lemma":"accessa","pos":"","gen":"-tide","def":", in later Lat. = accessus, the flood-tide, lect. dub., Serv. ad Verg. A. 1, 244 (cf. Salmas. Exerc. p. 203). accessĭbĭlis, e, adj. accedo, accessible (late Lat.), Tert. Adv. Prax. 15. accessĭbĭlĭtas"},"accessus":{"lemma":"accessus","pos":"","gen":"","def":"accedo, a going or coming to or near, an approaching, approach (syn. aditus"},"accipenser":{"lemma":"accipenser","pos":"","gen":"","def":"acipenser. accĭpĭter, tris (earlier also tĕris, Prisc. p. 695 P.), m. (f. Lucr. 4, 1006) [com. deriv. from accipio; see 2. acceptor"},"acco":{"lemma":"Acco","pos":"","gen":"","def":", a chieftain of the Senones, Caes. B. G. 6, 4; 44 al."},"acerrae":{"lemma":"Acerrae","pos":"","gen":"","def":"A town in the interior of Campania, N. E. of Naples, now Acerra, exposed to frequent inundations from the Clanius, on which it is situated"},"acesta":{"lemma":"Acesta","pos":"","gen":"","def":", = Ἄκεστα and Ἀκέστη, a town in the N. W. part of Sicily, near the coast; earlier Egesta, later Segesta, near the modern Alcamo, Verg. A. 5, 718; 9, 218"},"achaetus":{"lemma":"Achaetus","pos":"","gen":"","def":", a river of Sicily, Sil. 14, 268."},"achaeus":{"lemma":"Achaeus","pos":"","gen":"","def":"Son of Xuthus, brother of Ion, and ancestor of the Achaei. — A king of Lydia, Ov. Ib. 301."},"acharnae":{"lemma":"Acharnae","pos":"","gen":"","def":", a demus or borough of Attica, Stat. Th. 12, 623.—Hence, Acharnānus, a, um, of Acharnae, Nep. Them. 1. ăcharnē, ēs, f., a sea-fish, Plin. 32. 11, 53, § 145. (Al. acarne.)"},"acharrae":{"lemma":"Acharrae","pos":"","gen":"","def":", a town of Thessaly, Liv. 32, 13, 13. † ăchātēs, ae, m. and f., = ὁ ἀχάτης, the agate, so called from Achates, a river in Sicily, where it was first found, Plin. 37, 10, 55"},"achilla":{"lemma":"Achilla","pos":"","gen":"","def":"Acholla."},"achillas":{"lemma":"Achillas","pos":"","gen":"","def":", the murderer of Pompey, Caes. B. C. 3, 104; 108"},"achilles":{"lemma":"Achilles","pos":"adj.","gen":"-l","def":", = Ἀχιλλεύς (poet., after the manner of the Gr. Nom., Achilleus, trisyl., Inscr. Grut. 669, 6.—Gen. Achillei, quadrisyl., Hor. C. 1, 15, 34; id. Epod. 17, 14"},"achlis":{"lemma":"achlis","pos":"","gen":"","def":", a wild beast of the North, which modern naturalists consider to be the same as the alces.—Acc. achlin, Plin. 8, 15, 16, § 39."},"acholla":{"lemma":"Acholla","pos":"","gen":"","def":"(also Achilla), a town in Africa, in the vicinity of Thapsus, now El-Aliah, Auct. B. Afr. 33. ăchor, ōris, m., = ἀχώρ, the scab or scald on the head, Macer. de Ruta, 1, 12"},"achras":{"lemma":"achras","pos":"","gen":"-tree","def":", = ἀχράς, a wild pear-tree, Col. 7, 9, 6; 10, 15, 250. ăcĭa, ae, f. 1. acus, a thread for sewing, ῥάμμα, Titin. ap. Non. 3, 21 (Rib. Com. Rel. p. 115)"},"acionna":{"lemma":"Acionna","pos":"","gen":"","def":", a Gallic deity, Inscr. Orell. 1955. ăcĭpenser, ĕris, and ăcĭpensis, is (also aquip., not accipenser), m., = ἀκκιπησίος, a fish very highly esteemed in the age of the greatest luxury of the Romans"},"acis":{"lemma":"Acis","pos":"","gen":"","def":", one of the Cyclades, i. q. Siphnus, Plin. 4, § 66. ăcisco, ĕre, i. q., acesco, Garg. Mart. ap. Maj. Auct. Class. 3, p. 419. ăciscŭlus, i, m. perh. ascia, and so more prop. asciculus, a little adze"},"aclassis":{"lemma":"aclassis","pos":"","gen":"","def":", ̏tunica ab humeris non consuta,˝ Paul. ex Fest. p. 20 Müll. aclys, ydis (better than aclis), = ἀγκυλίς (first used by Verg.), a small javelin, Verg. A. 7, 730; Sil. 33, 362 al."},"acra":{"lemma":"acra","pos":"","gen":"","def":", also ae, f., = ἄκρα, a promontory or headland, App. de Mundo prooem.: Acra Iapygia, a promontory in Magna Graecia, Plin. 3, 11, 16, § 100."},"acrae":{"lemma":"Acrae","pos":"","gen":"","def":", = Ἄκραι. A city of Sicily, on a lofty hill near Syracuse, now Palazzolo, Liv. 24, 36"},"acraeus":{"lemma":"Acraeus","pos":"adj.","gen":"","def":", = ἀκραῖος, dwelling on the heights; an epithet of Jupiter and of Juno, whose temples stood on heights, Liv 38, 2"},"acrillae":{"lemma":"Acrillae","pos":"","gen":"","def":", a town in Sicily, on the road from Syracuse to Agrigentum, Liv. 24, 35, 8. ācrĭmōnĭa, ae, f. 2. acer, sharpness or pungency (so far as it has a quickening, animating power, diff. fr. acerbitas"},"acta":{"lemma":"acta","pos":"","gen":"-shore","def":", = ἀκτή, the sea-shore, as place of resort: in acta jacebat, Cic. Verr. 2, 5, 25; so id. Cael. 15; id. Att. 14, 8; id. Fam. 9, 6; Nep. Ages. 8, 2; Verg. A. 5, 613 al. (perh. also in Verg. Cul. 13"},"actaea":{"lemma":"actaea","pos":"","gen":"","def":", a strong - smelling plant, herb Christopher, Actaea spicata, Linn., Plin. 27, 7, 26, § 43. Actaeōn, ŏnis, m., Ἀκταίων, a grandson of Cadmus, who, having seen Diana bathing naked with her nymphs"},"actaeus":{"lemma":"Actaeus","pos":"adj.","gen":"","def":", Ἀκταῖος, pertaining to Attica, Attic, Athenian: in Actaeo Aracyntho, Verg. E. 2, 24 (as being on the border of Attica): arces, of Athens, Ov. M. 2, 720"},"actor":{"lemma":"actor","pos":"","gen":"","def":"id.. One who drives or moves something: pecoris actor, Ov. H. 1, 95: habenae, a slinger, Stat. Ach. 2, 419.— In gen., he who does any thing, a doer or performer (cf. ago"},"actrix":{"lemma":"actrix","pos":"","gen":"","def":"actor. A female plaintiff, Cod. Th. 7, 16, 41.— A stewardess, Inscr. Murat. 913, 6. actŭālis, e, adj. id., active, practical, Macr. Somn. Scip. 2, 17.—Adv.: ac-tŭālĭter, actively, Myth. Vatic. vol. 3"},"actum":{"lemma":"actum","pos":"","gen":"","def":"ago. actŭōse, adv., see the foll. art. fin. actŭōsus, a, um, adj. actus, full of activity, very active (with the access. idea of zeal, subjective impulse"},"actus":{"lemma":"actus","pos":"","gen":"-way","def":"ago. The moving or driving of an object, impulse, motion: linguae actu, Pacuv. ap. Non. 506, 17: mellis constantior est natura ... et cunctantior actus, Lucr. 3, 192: levi admonitu, non actu"},"ad":{"lemma":"ad","pos":"adj.","gen":"-a","def":"with acc. (from the fourth century after Christ written also at; Etrusc. suf. -a; Osc. az; Umbr. and Old Lat. ar, as in Eug. Tab., in S. C. de Bacch., as arveho for adveho"},"ad-dormisco":{"lemma":"ad-dormisco","pos":"","gen":"-dormisco","def":"inch. n., to go to sleep: quoties post cibum addormisceret, Suet. Claud. 8. Addŭa, ae, m., Ἀδούας (cf. Weichert Poët. Lat. 180), a river in Upper Italy, which flows into the Po near Cremona, now Adde"},"ad-iungo":{"lemma":"ad-jungo","pos":"v.","gen":"-jungo","def":"a., to add, join, annex, or bind to any thing. Lit., of cattle, to yoke, to harness (cf.: jugo, jugum, jungo, etc.): adjunxere feras (preceded by bijugos agitare leones), Lucr. 2, 604: tauros aratro"},"ad-mitto":{"lemma":"ad-mitto","pos":"v.","gen":"-mitto","def":"a. (admĭsse sync. for admisisse, Plaut. Mil. 4, 7, 4: admittier arch. for admitti, as Verg. A. 9, 231), orig. to send to"},"ad-uoluo":{"lemma":"ad-volvo","pos":"v.","gen":"-volvo","def":"a., to roll to or toward. In gen.: robora focis, Verg. G. 3, 377; so id. A. 6, 182: advolvi (for advolvere se) ad ignem, Plin. 11, 37, 70, § 185: advolvit saxum magnum ad ostium, Vulg. Matt. 27, 60"},"addax":{"lemma":"addax","pos":"","gen":"","def":"(an African word, acc. to Plin., l. c.), the name of a wild animal in Africa, with crooked horns, Capra cervicapra, Linn."},"adductor":{"lemma":"adductor","pos":"","gen":"","def":", a procurer (cf. adduco, 1. 2. fin.), Petr. Afran. ap. Meyer, Anthol. II. p. 27. adductus, a, um, P. a. of adduco. ăd-ĕdo, ēdi, ēsum (less correctly, adessum), 3, v. a. (adest = adedit, Luc. 6, 265"},"adherbal":{"lemma":"Adherbal","pos":"","gen":"","def":", a Numidian prince, the son of Micipsa, slain by Jugurtha, Sall. J. 5 al. ăd-hĭbĕo, ŭi, ĭtum, 2, v. a. habeo, to hold toward or to, to turn, bring, add to"},"adiecto":{"lemma":"adjecto","pos":"v.","gen":"","def":"a., false reading in Apic. 8, 2. adjectus, a, um, Part., of adjicio."},"adiectus":{"lemma":"adjectus","pos":"","gen":"","def":"adjicio, an adding or applying to: odoris (ad narīs), Lucr. 4, 673"},"adiunctor":{"lemma":"adjunctor","pos":"","gen":"","def":"id., one who adds, joins, or unites (used only by Cic. in strong indignation): ille Galliae ulterioris adjunctor, i. e. Pompey, by whose influence Gallia Transalpina was granted to Caesar"},"admissor":{"lemma":"admissor","pos":"","gen":"","def":"admitto, one that allows himself to do a thing, a perpetrator (late Lat.), Lact. Epit. 63; Aug. Cic. Div. 7, 3; cf. admitto, II. C."},"admissum":{"lemma":"admissum","pos":"","gen":"","def":"id., a wrong done, a trespass, fault, crime: judicia, quae etiam nullo admisso consequi possent, Cic. Part. Or. 35: tale admissum, Liv. 25, 23: de admissis Poppeae, Tac. A. 11, 4"},"admissus":{"lemma":"admissus","pos":"","gen":"","def":"admitto. A letting in or admission: solis admissu, Pall. 4, 9, 4"},"admistus":{"lemma":"admistus","pos":"","gen":"","def":"admixtus."},"admorsus":{"lemma":"admorsus","pos":"","gen":"","def":"admordeo, a biting at, a gnawing, a bite; trop.: vereor ne libellus iste admorsu duri dentis uratur, Symm. Ep. 1, 15. admōtĭo, ōnis, f. admoveo, a putting, moving, or bringing to, an applying"},"adnascor":{"lemma":"adnascor","pos":"","gen":"","def":"agnascor."},"adnato":{"lemma":"adnato","pos":"","gen":"","def":"annato."},"adnatus":{"lemma":"adnatus","pos":"","gen":"","def":"agnascor."},"adnauigo":{"lemma":"adnavigo","pos":"","gen":"","def":"annavigo."},"adnecto":{"lemma":"adnecto","pos":"","gen":"","def":"annecto. ad-nĕpos (atn-), ōtis, m., a son of the abnepos or of the abneptis, i. e. the grandson of a great-grandson, or of a greatgranddaughter, i. e. a fourth - grandson"},"adnomen":{"lemma":"adnomen","pos":"","gen":"","def":"agnomen, agnominatio, agnosco. adn-. For all words in adn- not found here, v. under ann-. ăd-obrŭo, ĕre, 3, v. a., to cover up with earth, to bury: alte circumfodere et adobruere, Col. 4, 15, 3"},"adolabilis":{"lemma":"adolabilis","pos":"","gen":"","def":"adulabilis. ădŏlātĭo, ōnis, f., = adoratio, a read. in Tert. Apol. 25 fin. ădŏlēfactus, a, um, set on fire, kindled: ARBORES ADOLEFACTAE, fragm. of the Fratr. Arval., Grut. Inscr. p. 121 . Adŏlenda"},"adr-":{"lemma":"adr-","pos":"","gen":"","def":"under arr-. adrachnē, ēs, f. = ἀδράχνη, the wild strawberry-tree: Arbutus adrachne, Linn.; Plin. 13, 22, 40, § 120; 16, 21, 33, § 80"},"aduecto":{"lemma":"advecto","pos":"","gen":"","def":"freq. , to carry or convey to a place often: rei frumentariae copiam, Tac. A. 6, 13."},"aduector":{"lemma":"advector","pos":"","gen":"","def":"adveho, one who conveys or carries a thing to a place, a carrier: advector equus, App. Flor. p. 363 (but in Plaut. As. 2, 2, 92, the correct reading is adventorem, Fleck.). advectus, a, um"},"aduectus":{"lemma":"advectus","pos":"","gen":"","def":"adveho, = advectio, a bringing or conveying to a place: haec de origine et advectu deae, Tac. H. 4, 84. ad-vĕho, xi, ctum, 3, v. a. (advexti = advexisti, Plaut. Merc. 2, 3, 56"},"aduento":{"lemma":"advento","pos":"adv.","gen":"","def":"freq. , to come continually nearer to a point (cotidianis itineribus accedere et appropinquare, Manut. ad Cic. Fam. 2, 6 init.), to come on, to approach"},"aduentor":{"lemma":"adventor","pos":"","gen":"","def":"advenio, one that arrives, a guest, visitor. In gen., Plaut. As. 2, 2, 92.—So in two inscriptions, Orell. 2287, and Grut. 444, 8"},"aduentus":{"lemma":"adventus","pos":"","gen":"","def":"adventi, Ter. Phorm. 1, 3, 2"},"aduocamentum":{"lemma":"advocamentum","pos":"","gen":"","def":", = advocatio: veniam advocamenti peto, Plin. Ep. 5, 8, 11, where the better read. is advocandi, Keil. advŏcātĭo, ōnis, f. advoco"},"aea":{"lemma":"Aea","pos":"","gen":"","def":", = Αἶα (land). In the fable of the Argonauts, a peninsula in Colchis, round which the Phasis flowed, Val. Fl. 1, 742, and 5, 426. Aeăcĭdēĭus, a, um, adj."},"aeaea":{"lemma":"Aeaea","pos":"","gen":"","def":", = Αἰαίη, acc. to fable, the island in the Tyrrhene Sea where the Circe of Homer had her abode, and where, acc. to Plin. 3, 5, 9, § 58, the later Circeii was situated"},"aeaeus":{"lemma":"Aeaeus","pos":"adj.","gen":"","def":", = Αἰαῖος. Belonging to Aea, in Colchis, Colchian: Circe, since Circe is said to have been earlier in Colchis, Verg. A. 3, 386"},"aeas":{"lemma":"Aeas","pos":"","gen":"","def":", a river of Epirus, Mela, 2, 3, 13; Plin. 3, 23, 26, § 145; Ov. M. 1, 580"},"aecae":{"lemma":"Aecae","pos":"","gen":"","def":", a city of Apulia, southeast of Luceria, now Troja, Liv. 24, 20, 5.—Hence, Aecani, orum, m., the inhabitants of Aecae, Plin. 3, 11, 16, § 105. Aecŭlānum or Aeclānum, i, n."},"aedepol":{"lemma":"aedepol","pos":"","gen":"","def":"Pollux. aedēs and aedis (the form aedes is found in Liv. 2, 21, 7; 2, 8, 14; 2, 9, 43 al., and now and then in other writers, but aedis is more common, as in Cic. Verr. 4, 55, § 121"},"aedis":{"lemma":"aedis","pos":"","gen":"","def":"aedes. aedĭtĭmor or aedĭtŭmor an earlier form for aedituor, āri, v. dep., to keep or take care of a temple: aeditumor in templo tuo, Pompon. ap. Gell. 12, 10. Nonius quotes the same passage, 75, 15"},"aegae":{"lemma":"Aegae","pos":"","gen":"","def":"plur., = Αἰγαί. A city of Cilicia, now Ayas, Luc. 3, 227.— A small town on the western coast of Euboea, now Limni, Stat. Th. 7, 371."},"aegaeon":{"lemma":"Aegaeon","pos":"","gen":"-monster","def":", = Αἰγαίων. A giant-monster, the other name of Briareus, Verg. A. 10, 565"},"aegaeus":{"lemma":"Aegaeus","pos":"adj.","gen":"","def":", Aegean"},"aeger":{"lemma":"aeger","pos":"adj.","gen":"-wind","def":"Curtius proposes to connect it with ἐπ-είγω, to press, drive; αἰγίς, storm-wind; αἶγες, waves; and Sanscr. egāmi, to tremble"},"aegis":{"lemma":"aegis","pos":"","gen":"-tree","def":", = αἰγίς, ίδος. The oegis. The shield of Jupiter, Verg. A. 8, 354; Sil. 12, 720.— The shield of Minerva, with Medusa's head, Verg. A. 8, 435: contra sonantem Palladis aegida, Hor. C. 3, 4, 57"},"aegisthus":{"lemma":"Aegisthus","pos":"","gen":"","def":", = Αἴγισθος, the son of Thyestes, who murdered Atreus and Agamemnon, with whose wife, Clytoemnestra, he lived in incest, and was finally slain by Orestes, Cic. N. D. 3, 38"},"aegon":{"lemma":"Aegon","pos":"","gen":"","def":", = Αἴγων. The Aegean Sea (only in the poets), Stat. Th. 5, 56; Val. Fl. 1, 629; 4, 715.— The name of a shepherd, Verg. E. 3, 2"},"aegophthalmos":{"lemma":"aegophthalmos","pos":"","gen":"","def":", = αἰγόφθαλμος (goat's eye), an unknown gem, Plin. 37, 11, 71, § 187. Aegŏs Flūmen, n. trans, of Αἰγὸς ΙΙοταμοι, Goat-rivers, a river and town in the Thracian Chersonesus"},"aegresco":{"lemma":"aegresco","pos":"","gen":"","def":"inch. n. , to become ill, to grow sick (not in Cic.). Lit.: morbis aegrescimus ĭsdem, * Lucr. 5, 349: aegrescunt corvi, Plin. 10, 12, 15, § 32.— Fig. To grow worse: violentia Turni exsuperat magis"},"aegror":{"lemma":"aegror","pos":"","gen":"","def":"aeger; as acror from acer, illness, sickness, disease, only in Lucr. 6, 1132 (for in id. 6, 1259, the correct read. is maeror, v. Lachm. ad h. l.)."},"aegrotaticius":{"lemma":"aegrotaticius","pos":"adj.","gen":"","def":"aegroto, that is often ill, Gloss. Isid. aegrōtātĭo, ōnis, f. aegroto, illness, sickness, disease, infirmity (prop. only of the body, while aegritudo also desig. that of the mind"},"aegyptilla":{"lemma":"aegyptilla","pos":"","gen":"","def":", a precious stone once found in Egypt, prob. a kind of onyx, Plin. 37, 10, 54, § 148"},"aegyptus":{"lemma":"Aegyptus","pos":"","gen":"","def":", = Αἴγυπτος, Egypt, sometimes reckoned by the ancients as belonging to Asia: Asiae prima pars Aegyptus, Mel. 1, 9: proxima Africae incolitur Aegyptus, etc., Plin. 5, 9, 9, § 48; Cic. Agr. 2, 16"},"aenitologium":{"lemma":"aenitologium","pos":"","gen":"","def":"In metre, a dac tylic verse with an iambic penthemimeris, e. g. Carmina bella magis vellem sonare, Serv. in Centim. 1825 P. Aēnŏbarbus (earlier, Aēn-), i, m. aeneus, II., and barba. Red-beard"},"aenus":{"lemma":"Aenus","pos":"","gen":"","def":", the river Inn, Tac. H. 3, 5. ăēnus (trisyl.; less freq. ăhēn-), a, um, adj. aes, of copper or bronze (only poet. for aheneus"},"aepy":{"lemma":"Aepy","pos":"","gen":"","def":", = Αἶπυ, a city of Elis, mentioned by Homer (II. 2, 592), Stat. Th. 4, 180. aequābĭlĭs, e, adj. aequo, that can be made equal, equal, similar, like ( ̏aequalis alterius staturae par"},"aequaeuus":{"lemma":"aequaevus","pos":"adj.","gen":"-aevum","def":"aequus-aevum, of equal age, just as old, coeval (in gen. only poet.; esp. freq. in Claudian): amicus, Verg. A. 5. 452"},"aequi":{"lemma":"Aequi","pos":"adj.","gen":"-cus","def":"A warlike people of ancient Italy, in the neighborhood of the Latins and Volsci, on both sides of the Anio, whose cities were Alba, Tibur, Praeneste, Carseoli"},"aequo":{"lemma":"aequo","pos":"v.","gen":"","def":"a. and n. aequus. Act., to make one thing equal to another"},"aequor":{"lemma":"aequor","pos":"","gen":"","def":"aequus. In gen., an even, level surface (ante-Aug. poet.; only once in Cic. and once in Sallust): speculorum aequor, a plane surface, as of a mirror, Lucr. 4, 106"},"aer":{"lemma":"aer","pos":"n. m.","gen":"aeris","def":"air, atmosphere; mist, fog; the lower air"},"aera":{"lemma":"aera","pos":"","gen":"","def":"[from aera, counters"},"aerem":{"lemma":"aer","pos":"n. m.","gen":"aeris","def":"air, atmosphere; mist, fog; the lower air","form_of":"aer"},"aeri":{"lemma":"aer","pos":"n. m.","gen":"aeris","def":"air, atmosphere; mist, fog; the lower air","form_of":"aer"},"aeris":{"lemma":"aer","pos":"n. m.","gen":"aeris","def":"air, atmosphere; mist, fog; the lower air","form_of":"aer"},"aero":{"lemma":"aero","pos":"","gen":"","def":"aeratus. aero (also written ēro), ōnis, m., = αἴρω, a braided or wicker basket, hamper: aerones ex ulva palustri facti, Vitr. 5, 12: aeronibus harenae plenis, Plin. 36, 14, 21, § 96; Dig. 19, 2, 31"},"aerusco":{"lemma":"aerusco","pos":"v.","gen":"","def":"a. aes, to get money by going about and exhibiting tricks of legerdemain, to play the juggler: aeruscare: aera undique, id est pecunias, colligere, Paul. ex Fest. p. 24 Müll.—Esp."},"aeschylus":{"lemma":"Aeschylus","pos":"","gen":"","def":", = Αἰσχύλος. The first great tragic poet of Greece, the originator of the Greek drama, Hor. A. P. 278"},"aesis":{"lemma":"Aesis","pos":"","gen":"","def":", a river in Umbria, Plin. 11, 42, 97, § 241."},"aesquiliae":{"lemma":"Aesquiliae","pos":"","gen":"","def":"Esquiliae. aestas, ātis, f. akin to αἴθω = to burn, Varr. L. L. 6, § 9; cf.: aestus, aether, aethra; Sanscr. indh = to kindle, iddhas = kindled; O. H. Germ. eiten = to heat"},"aetas":{"lemma":"aetas","pos":"","gen":"-class","def":"contr. from the anteclass. aevitas from aevum, q. v.; Prisc. 595 P.; cf. Welsh oet (gen. plur. aetatum; but freq. also aetatium, Liv. 1, 43; 9, 17; 26, 9; cf. Oud. ad Suet. Aug. 31; Vell. 2, 89"},"aeterno":{"lemma":"aeterno","pos":"v.","gen":"","def":"a. aeternus, to perpetuate, to immortalize (rare, perh. extant only in the two foll. exs.): litteris ac laudibus aeternare, Varr. ap. Non. 75, 20: virtutes in aevum, * Hor. C. 4, 14, 5."},"aeternus":{"lemma":"aeternus","pos":"adj.","gen":"-ternus","def":"contr. from aeviternus, Varr. L. L. 6, § 11 Müll., from aevum, with the termination -ternus as in sempiternus, hesternus, without beginning or end, eternal (sempiternus denotes what is perpetual"},"aethra":{"lemma":"aethra","pos":"","gen":"","def":", = αἴθρα , the upper, pure air, the bright, clear, serene sky: aetheris splendor, qui sereno caelo conspicitur, Serv. ad Verg. A. 3, 585 (poet.): flammea, Jul. ap. Macr. 6"},"aetnaeus":{"lemma":"Aetnaeus","pos":"adj.","gen":"","def":"Aetna. Pertaining to Aetna: ignes, Cic. N. D. 2, 38: fratres, the Cyclopes who forged in Mt. Aetna, Verg. A. 3, 678: fulmen, Prop. 4, 16, 21: Deus, i. e. Vulcan"},"aetnensis":{"lemma":"Aetnensis","pos":"adj.","gen":"","def":"id., pertaining to the town of Aetna (at the foot of Mt. Aetna, v. Strab. 6, p. 185): ager, Cic. Verr. 2, 3, 18. —Hence, Aetnenses, ĭum, m., the inhabitants of Aetna, Plin. 3, 8, 14, § 91. Aetōlĭa"},"affringo":{"lemma":"affringo","pos":"","gen":"","def":"affrango. af-frĭo (better adf-), āre, v. a., to rub or crumble to pieces, or to crumble over: alius aliud adfriat aut adspergit, ut Chalcidicam aut Caricam cretam, Varr. R. R. 1"},"afri":{"lemma":"Afri","pos":"","gen":"","def":"Afer. Afrĭca, ae, f. the Romans received this name from the Carthaginians as designating their country, and in this sense only the Gr. ἡ Ἀφρική occurs. In a restricted sense"},"agger":{"lemma":"agger","pos":"","gen":"-gero","def":"ad-gero. Things brought to a place in order to form an elevation above a surface or plain, as rubbish, stone, earth, sand, brushwood, materials for a rampart, etc. (in the histt., esp. Caes., freq."},"aggestus":{"lemma":"aggestus","pos":"","gen":"","def":", or aggestum (adg-), i, n. id., an elevation formed like a dike or mound: prunas unius aggesti inseruere juncturis, Amm. 20, 11"},"aglaspis":{"lemma":"aglaspis","pos":"","gen":"","def":", = ΑΓΛΑΣΠΙΣ, i. e. ἀγλαόσ-ἀσπίς (with a glittering shield), soldiers with bright shields, Liv. 44, 41 (others, as Weissenb. and Madv., perh. more correctly read chalcaspides, with brazen shields)."},"aglauros":{"lemma":"Aglauros","pos":"","gen":"","def":", a daughter of Cecrops, and sister of Herse and Pandrosos, changed by Mercury into a stone, Ov. M. 2, 560; 739, 819 sq.; Hyg. Fab. 166 agmĕn, ĭnis, n. as if contr. from agimen, from ago"},"agna":{"lemma":"agna","pos":"","gen":"","def":", a blade, a straw, Fest. s. v. pennatus, p. 211 Müull. [kindr. with 2. acus, q. v."},"agnellus":{"lemma":"agnellus","pos":"","gen":"","def":"dim. agnus, a little lamb, lambkin, Plaut. As. 3, 3, 77. agnicellus and agnicellulus, i, m. dim. id., a lambkin, Pomp. Gr. p. 105 Lindem. agnĭcŭlus, i, m. dim. id., a lambkin, Arn. 7, p. 219. agnīnus"},"agnus":{"lemma":"agnus","pos":"","gen":"","def":"(gen. plur. agnūm, Porc. Licin. ap. Gell. 19, 9, 13) [cf. ἀμνός, which Benfey connects with ὄϊς = Sanscr. avis"},"agoce":{"lemma":"Agoce","pos":"","gen":"","def":", a town in Aethiopia, on the borders of Egypt, Plin. 6, 29, 35, § 179. ăgōgae, ārum, f., = ἀγωγαί (or -οί) a conduit or aqueduct), in mines, channels or passages for drawing off water, Plin. 33, 4"},"agragas":{"lemma":"Agragas","pos":"","gen":"","def":"q. Acragas, q. v., and Agrigentum. agrālis, e, adj., = agrarius: vocabula, Front. de Colon. fin. agrammătos, i, m., = ἀγράμματος, illiterate: non debet esse architectus grammaticus"},"agrippa":{"lemma":"Agrippa","pos":"","gen":"-in","def":", a Roman family name. Menenius Agrippa, who related to the people upon Mons Sacer the fable of the Belly and the Limbs, Liv. 2, 32.— Vipsanius Agrippa, son-in-law of Augustus, husband of Julia"},"agylla":{"lemma":"Agylla","pos":"","gen":"","def":", a town in Etruria, called later Caere, now Cervetri, Verg. A. 8, 479"},"aharna":{"lemma":"Aharna","pos":"","gen":"","def":", a town in Etruria, Liv. 10, 25. ăhēnātor, v. aëneator. ăhēnĕus, ahenipes, etc., v. aën-. ai, in old Lat., corresponding to ae: AIDILIS, CAISAR, AITERNOS, for Aedilis, Caesar, aeternus"},"aiens":{"lemma":"aiens","pos":"","gen":"","def":"aio fin. aientĭa, ae, f. aio, an affirmation (opp. negatio), Mart. Cap. 4, p. 75 Vulc. āio, verb. defect. The forms in use are: pres. indic. āio, ăis, ait—aiunt; subj. aias, aiat—aiant"},"alasi":{"lemma":"Alasi","pos":"","gen":"","def":", a tribe of Libya, Plin. 5, 5, 5, § 37."},"alastor":{"lemma":"Alastor","pos":"","gen":"","def":", = ἀλάστωρ (a tormentor). One of the companions of Sarpedon, king of Lycia, killed by Ulysses before Troy, Ov. M. 13, 257.— Name of one of the four horses in the chariot of Pluto, Cland. R. Pros. 1"},"alba":{"lemma":"alba","pos":"","gen":"","def":"albus, a white precious stone, the pearl, Lampr. Hel. 21. Alba or Alba Longa, ae, f. v. albus. The mother city of Rome, built by Ascanius, the son of Aeneas, upon the broad"},"albesco":{"lemma":"albesco","pos":"","gen":"","def":"inch. , to become white (mostly poet. or in post-Aug. prose; once in Cic.), * Lucr. 2, 773"},"albis":{"lemma":"Albis","pos":"","gen":"","def":"v. albus, a river of Germany, now the Elbe, Tac. G. 41"},"albor":{"lemma":"albor","pos":"","gen":"-class","def":"albus. Whiteness, white color (eccl. Lat.): si (caro) versa fuerit in alborem, Vulg. Lev. 13, 16; 13, 25; 13, 29.— The white of an egg, = albamentum (post-class.): ovorum, Pall. 11, 14, 9"},"album":{"lemma":"album","pos":"","gen":"","def":", v. albus, III. albūmen, ĭnis, n. albus, the white of an egg, albumen: ovi, Plin. 28, 6, 18, § 66. albūmentum, i, n. id., the white of an egg: ovi, Veg. Vet. 2, 57. Albŭnĕa, also Albūna, ae"},"alburnum":{"lemma":"alburnum","pos":"","gen":"-wood","def":"albus, the soft, thin, white layer between the bark and wood of trees, sap-wood, alburnum, Plin. 16, 38, 72, § 182."},"alburnus":{"lemma":"alburnus","pos":"","gen":"","def":"id., a white fish, prob. the bleak or blay, Aus. Mos. 126."},"albus":{"lemma":"albus","pos":"adj.","gen":"-star","def":"cf. Umbr. alfu and Sab. alpus = white; ἀλφός = white rash; O. H. Germ. Elbiz = a swan"},"alcaeus":{"lemma":"Alcaeus","pos":"adj.","gen":"","def":", = Ἀλκαῖος, a renowned lyric poet of Mitylene, contemporary with Sappho, 610 B.C., inventor of the metre which bears his name, and which was imitated by the Latin poets, esp. by Horace"},"alcander":{"lemma":"Alcander","pos":"","gen":"","def":"A Trojan, Ov. M. 13, 258.— A companion of Aeneas, Verg. A. 10, 338. Alcăthŏē, ēs, f., = Ἀλκαθόη, the castle of Megara, named after Alcathous"},"alces":{"lemma":"alces","pos":"","gen":"","def":"ἄλκη; O. H. Germ. Elaho; Norse, elgr; Engl. elk, the elk, living in the northern regions: Cervus alces, Linn.; Caes. B. G. 6, 27; Plin. 8, 15, 16, § 39."},"alcestis":{"lemma":"Alcestis","pos":"","gen":"","def":", = Ἄλκηστις or Ἀλκήστη, daughter of Pelias, and wife of Admetus, king of Pheroe, for the preservation of whose life she resigned her own"},"alcis":{"lemma":"Alcis","pos":"","gen":"","def":", = Ἀλκίς , an appellation of Minerva among the Macedonians: Minervae, quam vocant Alcidem, Liv. 42, 51, where Weissenb. reads Alcidemon."},"alcmaeo":{"lemma":"Alcmaeo","pos":"adj.","gen":"","def":"(Alcmaeo, Cic. Ac. 2, 28: Alcmaeus, Plaut. Capt. 3, 4, 30), = Ἀλκμαίων, a son of Amphiaraus and Eriphyle"},"alcyon":{"lemma":"alcyon","pos":"","gen":"","def":"alcedo. Alcyŏnē (Halc-), ēs, f., = Ἀλκυόνη, a daughter of Aeolus, who, from love to her husband Ceyx, who had suffered shipwreck, threw herself into the sea and was changed into a kingfisher (ἀλκυών"},"aleuas":{"lemma":"Aleuas","pos":"","gen":"","def":", = Ἀλεύας. A tyrant of Larissa, slain by his own servants, Ov. Ib. 321 and 509 Merk.— A worker in bronze, Plin. 34, 8, 19, § 86. Ālĕus, another reading for Alius, = Elius, Plaut. Capt."},"alexander":{"lemma":"Alexander","pos":"","gen":"","def":"Ἀλέξανδρος, hence, Charis. 64 P. asserts that there is also a nom. Alexandrus, but gives no example, the name of many persons of antiquity"},"alga":{"lemma":"alga","pos":"","gen":"-weed","def":"from ligo, qs. alliga, as binding, entwining, Van., sea-weed, comprising several kinds, of which one (Fucus vesiculosus, Linn.) was used for coloring red, Plin. 26, 10, 66"},"algensis":{"lemma":"algensis","pos":"adj.","gen":"-weed","def":"alga, that supports itself on sea-weed, lives upon it, Plin. 9, 37, 91, § 131."},"algeo":{"lemma":"algeo","pos":"v.","gen":"","def":"n. acc. to Fest. from ἀλγέω = to feel pain; cf. ἄλγος, algor, and algus, to be cold, to feel cold; cf. Consent. 2051 P. (opp. aestuare; accordingly a subjective coldness"},"algesco":{"lemma":"algesco","pos":"","gen":"","def":"inch. n. . To catch cold: ne ille alserit, Ter. Ad. 1, 1, 11 (cf.: frigus colligere, Hor. Ep. 1, 11, 13, and perfrigescere, Juv. 7, 194).— Post-Aug. (cf. algens) of things"},"algor":{"lemma":"algor","pos":"","gen":"-class","def":"cf. algeo, cold (that is felt), coldness (class., for the ante-class. algus or algu"},"algus":{"lemma":"algus","pos":"","gen":"-class","def":", acc. to Prisc. p. 699 P.; Rudd. I. p. 122, or algu, n., acc. to Charis. 23; 98 P.; cf. Schneid. Gr. 2, 342 sq. , the feeling of cold (subjective), coldness (usu. only in the abl."},"alii":{"lemma":"Alii","pos":"","gen":"","def":"Alis and 1. Alius. ălĭmentārĭus, a, um, adj. alimentum, pertaining to or suitable for nourishing (a legal term; in the class. per. only once"},"alisales":{"lemma":"Alisales","pos":"","gen":"","def":", a tribe of Spain, Inscr. Orell. 156. ălismă, ătis, n., = ἄλισμα, an aquatic plant, water-plantain: Alisma plantago, Linn."},"allaeuo":{"lemma":"allaevo","pos":"","gen":"","def":"2. allēvo. al-lambo (adl-), ēre, v. a. (only postclass.), to lick at or on a thing, to lick: virides adlambunt ora cerastae, Prud. Ham. 135"},"allector":{"lemma":"allector","pos":"","gen":"","def":"2. allĕgo. One that chooses others into a college, Inscr. Orell. 779; 2406.— A deputy under the emperors, who collected the taxes in the provinces, Inscr Orell. 369"},"allex":{"lemma":"allex","pos":"","gen":"","def":", acc. to Isid. Gloss., the great toe"},"alliensis":{"lemma":"Alliensis","pos":"","gen":"","def":"Allia. Allīfae (Alīphae, Allīphae), ārum, also Alīfa, ae, f., = Ἄλλιφαι, a town of Samnium, in a pleasant valley, near the left bank of the Vulturnus, early colonized by the Romans"},"allus":{"lemma":"allus","pos":"","gen":"","def":": pollex scandens proximum digitum, quod velut insiluisse in alium videtur, quod Graece ἅλλεσθαι dicitur, Paul. ex Fest. p. 7 Müll."},"almo":{"lemma":"Almo","pos":"","gen":"-god","def":", a small stream, almost entirely dry in summer, on the south side of Rome, which, crossing the Via Appia and Via Ostiensis"},"almus":{"lemma":"almus","pos":"adj.","gen":"","def":"alo, nourishing, affording nourishment, cherishing (poet. epithet of Ceres, Venus, and other patron deities of the earth, of light, day, wine, etc."},"alnus":{"lemma":"alnus","pos":"","gen":"-wood","def":"akin to Swed. al; A. S. aler; Germ. Eller; Engl. alder, elder, the alder, which flourishes in moist places: Betula alnus, Linn.; cf. Plin. 16, 40, 79, § 218; Cat. 17, 18"},"alpha":{"lemma":"alpha","pos":"","gen":"","def":"indecl., = ἄλφα, the Greek name of the first letter of the alphabet: hoc discunt ante alpha et beta, before their letters, before they learn to read, Juv. 14, 209. —Hence, prov."},"alphus":{"lemma":"alphus","pos":"","gen":"","def":", = ἀλφός, a white spot upon the skin, Cels 5, 28, 19"},"alpis":{"lemma":"Alpis","pos":"","gen":"","def":"Alpes."},"alsidena":{"lemma":"alsidena","pos":"","gen":"","def":"19, 6, 32, § 101. Alsĭensis, e, adj. v. 2. Alsius, of or pertaining to the city of Alsium: in Alsiensi (sc. agro), Cic. Mil. 20: populus, Liv. 27, 38. alsīnē, ēs, f., = ἀλσίνη, a luxuriant plant"},"altellus":{"lemma":"Altellus","pos":"","gen":"","def":", a surname of Romulus, Paul. ex Fest. p. 7 Müll. alter, tĕra, tĕrum"},"altercor":{"lemma":"altercor","pos":"v.","gen":"","def":"dep. alter, to have a discussion or difference with another, to dispute"},"alterno":{"lemma":"alterno","pos":"v.","gen":"","def":"a. and n. alternus: aliquid, to do one thing and then another, to do a thing by turns, to interchange with something, to alternate (first in the poets of the Aug. per."},"alternus":{"lemma":"alternus","pos":"adj.","gen":"-n","def":"alter, one after the other, by turns, interchangeable, alternate (class. and also poet.). In gen.: (Sem)VNIS. ALTERNEI. ADVOCAPIT. CONCTOS (i. e. Semones alterni advocate cunctos)"},"alteruterque":{"lemma":"alteruterque","pos":"","gen":"","def":"the foll. art. altĕr-utrimque, adv., on both sides, in both cases: in causā alterutrimque modus est, Plin. 20, 7, 26, § 64, where Jan reads alterutrāque."},"althaea":{"lemma":"althaea","pos":"","gen":"-mallows","def":", = ἀλθαία, wild mallows, marsh-mallows, = hibiscum; Althaea officinalis, Linn.; Plin. 20, 21, 84, § 222; Pall. Oct. 14, 11; App. Herb. 38."},"altispex":{"lemma":"altispex","pos":"","gen":"-specio","def":"alte-specio, looking down from a height, Att. ap. Non. 357, 7 dub. altĭtŏnans, antis, adj. alte-tonans, thundering from on high: Juppiter, Enn. Ann. 2, 6: pater altitonans, i. e. Jupiter"},"alto":{"lemma":"alto","pos":"v.","gen":"","def":"a. altus, to make high, to raise, elevate (only in the foll. exs.), Sid. Ep. 8, 9: sol altatus, id. ib. 2, 2."},"altor":{"lemma":"altor","pos":"","gen":"-father","def":"alo. Subst., a nourisher, sustainer, foster-father: omnium rerum educator et altor, * Cic. N. D. 2, 34: altore recepto, Ov. M. 11, 101: Curetes altores Jovis, * Sall. ap. Lact. 1, 21 fin."},"altrix":{"lemma":"altrix","pos":"","gen":"-nurse","def":"altor, a female nourisher, cherisher, sustainer (mostly poet."},"altum":{"lemma":"altum","pos":"","gen":"","def":", v. altus, P. a. from alo. altus, a, um, participle from alo., lit., grown or become great, great (altus ab alendo dictus, Paul. ex Fest. p. 7 Müll."},"altus":{"lemma":"altus","pos":"","gen":"","def":"alo, a nourishing, support: terrae altu, Macr. S. 1, 20 fin. ālūcĭnātĭo (all- or hall-), ōnis, f. alucinor, a wandering of mind, dreaminess, revery (acc. to Non. 121, 20"},"alumento":{"lemma":"Alumento","pos":"","gen":"","def":"), for Laomedon, acc. to Paul. ex Fest. p. 18 Müll.; v. Müll. ad h. l. ălūmĭnātus, a, um, adj. alumen, tinctured with alum: aqua, Plin. 31, 6, 32, § 59"},"alyattes":{"lemma":"Alyattes","pos":"","gen":"","def":", = Ἀλυάττης, a king of Lydia, father of Croesus, Plin. 2, 12, 19, § 53: regnum Alyattei, * Hor. C. 3, 16, 41. Alȳmon, ŏnis, m., = Ἀλύμων, father of Iphimedia, Ov. H. 19, 133. ălȳpŏn, i, n., = ἄλυπον"},"amastris":{"lemma":"Amastris","pos":"adj.","gen":"-cus","def":", = Ἄμαστρις, a town in Paphlagonia, on the shore of the Pontus Euxinus, orig. called Sesamum, now Amasserah, Cat. 4, 13; Plin. 6, 2, 2, § 5"},"amb-":{"lemma":"amb-","pos":"","gen":"","def":"ambi-."},"ambactus":{"lemma":"ambactus","pos":"","gen":"","def":"Celt. amb; Goth. andbahti = service"},"ambestrix":{"lemma":"ambestrix","pos":"","gen":"","def":"ambedo, a female consumer, waster: ursae saevae hominis ambestrices, Amm. 29, 3. ambēsus, Part. of ambedo. ambi- (ambe-, Varr. L. L. 7, § 30 Müll.); abbrev. amb-, am-, an-. Insepar. prep. Osc. amfr-"},"amelas":{"lemma":"Amelas","pos":"","gen":"","def":"5, 27, 28, § 101."},"amellus":{"lemma":"amellus","pos":"","gen":"","def":", the purple Italian starwort: Aster amellus, Linn.; Verg. G. 4, 271 (cf. Serv. ad h. 1.); Col. 9, 4, 4. āmēn"},"amfractus":{"lemma":"amfractus","pos":"","gen":"","def":"anfr-. ămĭa, ae, f., and ămĭas, ae, m., = ἀμία, the tunny, a sea-fish: (piscem) amiam vocant cujus etc., Plin. 9, 15, 19, § 49.—The form amias: acc. amian, Lucil. ap. Varr. L. L. 7, § 47 Müll."},"amicinum":{"lemma":"amicinum","pos":"","gen":"","def":", the neck of a winesack, Paul. ex Fest. p. 15 Müll. (neutr. by mistake; cf. amicinus: ἀσκοῦ στόμα, Gloss.). ăm-ĭcĭo, ĭcui, or ixi, ictum, 4, v. a. (fut. amicibor, Plaut. Pers. 2, 5, 6"},"amilcar":{"lemma":"Amilcar","pos":"","gen":"","def":"Hamilcar. Amīnaeus (-ēus), a, um, adj., = Ἀμιναῖος, of or pertaining to Aminoea, a region in the country of the Piceni, distinguished for the culture of the vine: vites, Verg. G. 2, 97"},"ammium":{"lemma":"ammium","pos":"","gen":"","def":"ammi. ammŏchrȳsus, i, m., = ἀμμόχρυσος (gold sand), a precious stone unknown to us, perh. golden mica, Plin. 37, 11, 73, § 188. ammŏdytēs, ae, m., = ἀμμοδύτης (sand-burrower)"},"amnis":{"lemma":"amnis","pos":"","gen":"-flowing","def":"(fem., Plaut. Merc. 5, 2, 18; Naev. and Att. ap. Non. 191, 33; Varr. R. R. 3, 5, 9; cf. Prisc. pp. 652 and 658 P.; Rudd. I. p. 26, n. 37; Schneid. Gram. 2, 98; abl. regularly amne"},"amnon":{"lemma":"Amnon","pos":"","gen":"","def":"6, 28, 32, § 151. ămo, āvi, ātum, 1, v. a. (amāsso = amavero, Plaut. Cas. 5, 4, 23; id. Curc. 4, 4, 22; id. Mil. 4, 2, 16"},"amphisbaena":{"lemma":"amphisbaena","pos":"","gen":"","def":", = ἀμφίσβαινα, a kind of serpent in Libya which can move either backwards or forwards, Plin. 8, 23, 35, § 85; Luc. 9, 719."},"amphissa":{"lemma":"Amphissa","pos":"adj.","gen":"-us","def":", = Ἄμφισσα. The ancient chieftown in Locri Ozoloe, near Phocis, now Salona, Luc. 3, 172; cf. Mann. Gr. 125.— A promontory of Locri Epizephyrii, in Lower Italy"},"amplexor":{"lemma":"amplexor","pos":"v.","gen":"","def":"dep. freq. (act. form amplexo, analog to amplecto, Plaut. Poen. 5, 4, 60; Att. ap. Non. 470, 11; Lucil. ap. Prisc. p. 791 P.; Petr. 63) , to embrace, encircle (more rare than the simple verb"},"amplexus":{"lemma":"amplexus","pos":"","gen":"","def":"amplector, an embracing, encircling, surrounding (mostly poet. and in post-Aug. prose). In gen.: amplexu terrarum, * Lucr. 5, 319: serpentis amplexu, * Cic. Div. 1, 36: exuit amplexus, my embrace"},"amplo":{"lemma":"amplo","pos":"v.","gen":"","def":"a. id., old form for amplifico, to extend, enlarge; trop., to make glorious: qui causam humilem dictis amplent, Pac. ap. Non. p. 506, 26 (Trag. Rel. p. 120 Rib.)."},"amploctor":{"lemma":"amploctor","pos":"","gen":"","def":"amplector init. amplus, a, um, adj. some regard this as a shortened form of ἀνάπλεως, = filled up, full; others, as for ambulus from amb-, rounded out, as superus from super, etc."},"ampulla":{"lemma":"ampulla","pos":"","gen":"","def":"amb- and olla, as having handles on both (opposite) sides, or an irreg. dim. of amphora. A vessel for holding liquids, furnished with two handles and swelling in the middle, a flask, bottle, jar, pot"},"ampullor":{"lemma":"ampullor","pos":"v.","gen":"","def":"dep. id. II., to make use of a bombastic style of discourse, = ληκυθίζω (prob. coined by Hor.): tragicā ampullatur in arte, Hor. Ep. 1, 3, 14. ampŭtātĭo, ōnis, f. amputo, a pruning"},"ampycus":{"lemma":"Ampycus","pos":"","gen":"","def":", = Ἄμπυκος. A priest of Ceres, Ov. M. 5, 110 sq.— Father of the seer Mopsus, Hyg. Fab. 14; 128."},"ampyx":{"lemma":"Ampyx","pos":"","gen":"","def":", = Ἄμπυξ. One of the Lapithoe"},"amycus":{"lemma":"Amycus","pos":"","gen":"","def":", = Ἄμυκος. Son of Neptune, king of the Bebrycians, Val. Fl. 4, 148.— A centaur slain in the contest with the Lapithoe, Ov. M. 12, 245.— A Trojan, Verg. A. 10, 704. ămygdăla, ae, f."},"amyntas":{"lemma":"Amyntas","pos":"","gen":"-d","def":", = Ἀμύντας. The father of the Macedonian king Philip, Nep. Reg. 2"},"amyntor":{"lemma":"Amyntor","pos":"","gen":"-t","def":", = Ἀμύντωρ, king of the Dolopians, and father of Phoenix, Ov. M. 8, 307"},"an-":{"lemma":"an-","pos":"","gen":"","def":"ambi. -ăn. This word appears in forsan, forsitan, and fortasse an (Att. Trag. Rel. p. 151 Rib.) or fortassan, seeming to enhance the idea of uncertainty and doubt belonging to fors, etc."},"anartes":{"lemma":"Anartes","pos":"","gen":"","def":", a people in Transylvania, on the Theis, Caes. B. G. 6, 25. ănăs, ănătis (gen. plur. anatum, Cic. N. D. 2, 48, 124; Plin. 25, 2, 3, § 6; rarely anatium, Varr. R. R. 3, 5, 14"},"anas":{"lemma":"Anas","pos":"","gen":"","def":", a river in Spain, now Guadiana (Arab., i. e. Wadi-Ana, = river Anas), Caes. B. C. 1, 38; Plin. 3, 1, 3, § 3; 4, 22, 35, § 116; Mel. 2, 6; 3, 1; cf. Mann. Hispan. 325."},"anassum":{"lemma":"Anassum","pos":"","gen":"","def":", a small river in the Venetian territory, now Stella, Plin. 3, 18, 22, § 126 Hard.; Anaxum, Jan"},"anaurus":{"lemma":"Anaurus","pos":"","gen":"","def":", = Ἄναυρος, a river in Thessaly, that rises near the foot of Pelion, Luc. 6, 370. Anaxăgŏras, ae, m., = Ἀναξαγόρας, a distinguished Greek philosopher of Clazomenoe, teacher of Pericles and Euripides"},"anaxarchus":{"lemma":"Anaxarchus","pos":"","gen":"","def":", = Ἀνάξαρχος, a philosopher of Abdera, and follower of the philosophy of Democritus, Val. Max. 3, 3, n. 4"},"ancaesa":{"lemma":"ancaesa","pos":"","gen":"-caedo","def":"am-caedo, an old word for caelata: vasa sic dicta, quod circumcaedendo talia fiunt, Paul. ex Fest. p. 20 Müll."},"ancaeus":{"lemma":"Ancaeus","pos":"","gen":"","def":", = Ἀγκαῖος, an Arcadian, slain by the Calydonian bcar, Ov. M. 8, 315; 8, 401"},"ancilla":{"lemma":"ancilla","pos":"","gen":"","def":"dim. ancula, a maidservant, handmaid, female slave (com. used as fem. of servus, instead of serva). Lit."},"ancillor":{"lemma":"ancillor","pos":"v.","gen":"-class","def":"dep. and n. ancilla, pr., to serve as handmaid"},"andes":{"lemma":"Andes","pos":"","gen":"-c","def":", a Gallic tribe in the region of the present Anjou, with a town of the same name, now Angors; form Andes, Caes. B. G. 2, 35.—Form Andecāvi, Tac. A. 3, 41.—Form Andi-cāvi, Plin. 4, 18, 32, § 107 Jan"},"andriscus":{"lemma":"Andriscus","pos":"","gen":"","def":", = Ἀνδρίσκος, a slave who claimed to be the son of the Macedonian king Perseus and occasioned the third Macedonian war, Liv. Epit. 49; Vell. 1, 11"},"angellus":{"lemma":"angellus","pos":"","gen":"-class","def":"dim. angulus, a little angle or corner (only ante- and post-class.), * Lucr. 2, 428; Arn. 7, p. 253. angĕlus, i, m., = ἄγγελος. A messenger, Sen. Ep. 20 med. dub."},"angli":{"lemma":"Angli","pos":"","gen":"","def":", the Angli, a branch of the Suevi in Lower Germany, Tac. G. 40"},"ango":{"lemma":"ango","pos":"v.","gen":"","def":"a. (perf. and sup. rest only on the assertion in Prisc. p. 895 P.; Diom. p. 366 P.; part. anctus, Paul. ex Fest. p. 24 Müll.; acc. to Prisc. l. c., the sup. is sometimes anxum"},"angor":{"lemma":"angor","pos":"","gen":"","def":"ango, = angina. A compression of the neck, a strangling: occupat fauces earum angor, the quinsy, Plin. 8, 27, 41, § 100: aestu et angore vexata, i.e. aestu angorem ac prope suffocationem efficiente"},"angriuarii":{"lemma":"Angrivarii","pos":"","gen":"","def":", a German tribe in the neighborhood of the Teutoburg Forest, on both sides of the Weser, Tac. G. 33 Rup.; id. A. 2, 8; 2, 19; 2, 22; 2, 24; 2, 41."},"anguen":{"lemma":"anguen","pos":"","gen":"","def":"anguis init. anguĕus, a, um, adj. anguis, of or pertaining to a serpent: lapsus, Sol. 24. anguĭcŏmus (four syl.), a, um, adj. anguis-coma, with snaky hair (only in the poets): Gorgon, Ov. M. 4, 699"},"anguilla":{"lemma":"anguilla","pos":"","gen":"","def":"dim. anguis, Varr. L. L. 5, § 77 Müll.; but it may be directly con. with Gr. ἔγχελυς; v. anguis, an eel. Lit.: Muraena anguilla, Linn.; Plin. 9, 21, 38, § 74 al."},"angusto":{"lemma":"angusto","pos":"v.","gen":"","def":"a. angustus, to make narrow, to straiten (first used after the Aug. per.): Cujus (Hellesponti) iter caesis angustans corporum acervis, Cat. 64, 359: (puteus) ore angustatur, Plin. 17, 8, 4"},"angustus":{"lemma":"angustus","pos":"adj.","gen":"-spirited","def":"adj. v. ango, narrow, strait, esp. of local relations, close, contracted, small, not spacious (syn.: artus, brevis, contractus"},"anna":{"lemma":"Anna","pos":"","gen":"","def":", (cf. Gesen. Gesch. Hebr. Spr. p. 228), the sister of Dido, Verg. A. 4, 9 et saep.; Ov. H. 7, 191"},"annascor":{"lemma":"annascor","pos":"","gen":"","def":"agnascor. an-năto (better adn-), āre, v. n. To swim to or toward: ei insulae crocodili non adnatant, Plin. 8, 25, 38, § 93; Jan here reads adnant"},"anne":{"lemma":"anne","pos":"","gen":"","def":"1. an, I. F. an-necto (better adn-), nexui, nexum, 3, v. a., to tie or bind to, to connect, annex. Lit.: (animum) corporibus nostris, * Lucr. 3, 688: funiculus scapham adnexam trahebat, Cic. Inv. 2"},"annellus":{"lemma":"annellus","pos":"","gen":"","def":"anellus. annexĭo (adn-), ōnis, f. annecto, a tying or binding to, a connecting, Pall. Mart. 10, 36. annexus (adn-), a, um, Part. of annecto. annexus (adn-), ūs, m. annecto, a tying or binding to"},"anno":{"lemma":"anno","pos":"v.","gen":"","def":"a. annus, to pass or live through a year, Macr. S. 1, 12; cf. Anna."},"annon":{"lemma":"annon","pos":"","gen":"","def":"1. an. I. E. annōna, ae, f. from annus, as pomona from pomum. In gen., the yearly produce, the annual income of natural products, in the widest sense (cf.: cibaria annua, Cato"},"annus":{"lemma":"annus","pos":"","gen":"-nus","def":"acc. to some, as Corssen, Beitr. 16, for am-nus, from 2. an- am-"},"ansa":{"lemma":"ansa","pos":"","gen":"-hendo","def":"cf. χανδάνω, and pre-hendo, pre-hensum, and λαβή from λαβεῖν, that by which something is taken hold of, a handle, haft; of a vessel, pitcher, vase, and the like. Lit., Cato, R. R. 113; Verg. E. 3, 45"},"ansanctus":{"lemma":"Ansanctus","pos":"","gen":"","def":"Amsanctus. ansātus, a, um, adj. ansa, furnished with or having a handle: capulae a capiendo, quod ansatae, ut prehendi possint, Varr. L. L. 5, 26, 35: vas, Col. 9, 15: tela, darts having a thong"},"anser":{"lemma":"Anser","pos":"","gen":"","def":", a petulant and obscene poet (Ov. Tr. 2, 435), a friend of the triumvir Antonius, who presented him with an estate at Falernum (Cic. Phil. 13, 5). Acc. to Servius"},"antae":{"lemma":"antae","pos":"","gen":"","def":"perh. ante, q. v., pillars or pilasters on each side of (i.e. opposite sides of) doors or at the corners of buildings, Vitr. 3, 1"},"antaeus":{"lemma":"Antaeus","pos":"","gen":"","def":", = Ἀνταῖος, a huge giant in Libya, slain by Hercules, Ov. M. 9, 184"},"antes":{"lemma":"antes","pos":"","gen":"","def":"etym. unc., perh. from ante, as before, over against, one another, rows, e. g. of vines, Verg. G. 2, 417, cf. Paul. ex. Fest. p. 16 Müll.—Also of plants, Col. 10, 376.—Of ranks of soldiers"},"antestor":{"lemma":"antestor","pos":"v.","gen":"","def":"dep [acc. to Corssen, Ausspr. II. p. 564, from an-, the Gr. ἀνά, as in anhelo, q. v. fin., and testor"},"anthra":{"lemma":"Anthra","pos":"","gen":"","def":"ăcis, m., = Ἄνθραξ, name of a slave, Plaut. Aul. 2, 4, 8."},"anthrax":{"lemma":"anthrax","pos":"","gen":"","def":", = ἄνθραξ (coal). Natural cinnabar (the color of which is like a burning coal), Vitr. 7, 8.— In medic., a virulent ulcer (in pure Lat., carbunculus), Aem. Macr. de Herb. c. de Sabina."},"anthriscus":{"lemma":"anthriscus","pos":"","gen":"-um","def":", or -um, i, n., = ἄνθρισκον, the southern chervil: Scandix australis, Linn.; Plin. 22, 22, 38, § 81"},"anthus":{"lemma":"anthus","pos":"","gen":"","def":", = ἄνθος (cf. τὸ ἄνθος = blossom, brilliancy), a small bird, prob. the yellow wagtail: Motacilla flava, Linn.; Plin. 10, 42, 57, § 116"},"anthyllis":{"lemma":"anthyllis","pos":"","gen":"-ivy","def":", = ἀνθυλλίς, a plant, acc. to Sprengel, the musk-ivy: Teucrium iva, Linn."},"antiae":{"lemma":"antiae","pos":"","gen":"","def":"(cf. Charis. p. 20 P.) , the hair growing upon the forehead, forelock; of Apollo, App. Flor. 3, p. 342, 1; of lions, Tert. Pall. 4"},"antiensis":{"lemma":"Antiensis","pos":"","gen":"","def":"Antium. antigerio, an ancient word for valde, Paul. ex Fest. p. 8 Müll. ; cf. Quint. 1, 6, 40"},"antispastus":{"lemma":"antispastus","pos":"","gen":"","def":", = ἀντίσπαστος (reversed), in metre (sc. pes), an antispast, a foot in verse, ˘¯¯˘, i. e. the choriambus reversed, e. g. Mĕdūllīnă, Diom. p. 478 P."},"antissa":{"lemma":"Antissa","pos":"","gen":"-tissaei","def":", = Ἄντισσα, a town in the southern part of the island of Lesbos, now Kalas Limneonas, Liv. 45, 31; Ov. M. 15, 287"},"antisto":{"lemma":"antisto","pos":"","gen":"","def":"antesto. antistro/phē, ēs, f., = ἀντιστροφή. In the chorus of the Greek and Roman tragedy, the antistrophe answering to the strophe, Victorin. p. 2051 P.— A rhetorical figure"},"antlo":{"lemma":"antlo","pos":"","gen":"","def":"anclo. Antŏdĭcē, ēs, f., one of the Danaids, Hyg. Fab. 170. Antōnĭa, v. Antonius. Antōnĭānus, v. Antonius. Antōnĭaster, tri, m. dim. from Antonius, as surdaster from surdus"},"antrum":{"lemma":"antrum","pos":"","gen":"","def":", = ἄντρον, a cave, cavern, grotto (almost entirely confined to the poets). Lit.: succedere antro, Verg. E. 5, 19: subire antra, Ov. M. 1, 121: occulere se antro, Val. Fl. 8, 315: ingens, Verg. A. 6"},"anytus":{"lemma":"Anytus","pos":"","gen":"","def":", = Ἄνυτος, one of the accusers of Socrates, Hor. S. 2, 4, 3. Aoedē (trisyl.), ēs, f., one of the first four Muses, Cic. N. D. 3, 21, 54. Āŏnes, um, m. adj., = Ἄονες, Boeotian: Aonas in montes"},"aornos":{"lemma":"Aornos","pos":"","gen":"","def":"Strab. 1, 26"},"ap-pingo":{"lemma":"ap-pingo","pos":"v.","gen":"-pingo","def":"a. pango, to fasten or joint to: aliquid alicui rei, Paul. ex Fest. p. 8 Müll. Appĭŏlae (better Apĭ-), ae, f., a city of Latium, probably near Bovilloe, Liv. 1, 35, 7 Weissenb. Appĭus, ii, m."},"apella":{"lemma":"Apella","pos":"","gen":"","def":"The name of a Roman freedman, Cic. Att. 12, 19; id. Fam. 7, 25; Planc. ap. Cic. Fam. 10, 17.— The name of a credulous Jew who lived in the time of Horace"},"apello":{"lemma":"Apello","pos":"","gen":"","def":"Apollo. Āpennīnĭcŏla, ae, comm. Apenninus-colo, a dweller among the Apennines, Verg. A. 11, 700. Āpennīnĭgĕna, ae, comm. Apenninus - gigno, born upon the Apennines, originating there, Ov. M. 15, 432"},"aper":{"lemma":"Aper","pos":"","gen":"","def":", a Roman cognomen, Tac. Or. 2; Lampr. Commod. 2; Inscr. Grut. 692, 8. Apĕrantĭa, ae, f., = Ἀπεραντία, a small province in Thessaly, south of the Dolopians, Liv. 36, 33; 38, 3"},"aperta":{"lemma":"Aperta","pos":"","gen":"","def":"e. apertā) cortinā responsa ab eo darentur, Paul. ex Fest. p. 22 Müll. ăpertĭbĭlis, e, adj. aperio, opening, aperient, med. t., Cael. Aur. Acut. 3, 3"},"aphaea":{"lemma":"Aphaea","pos":"","gen":"","def":", = Ἀφαία, an epithet of Britomartis (q. v.), Verg. Cir. 303, ubi v. Wagner. ăphaerĕma, ătis, n., = ἀφαίρεμα, a coarse kind of grits, Plin. 18, 11, 29, § 2. ăphaerĕsis, is, f., = ἀφαίρεσις"},"aphidnae":{"lemma":"Aphidnae","pos":"","gen":"","def":", = Ἄφιδναι, a small place in Attica, Sen. Hippol. 24.—In sing.: Aphidna, Ov. F. 5, 708"},"aphthae":{"lemma":"aphthae","pos":"","gen":"","def":", = ἄφθαι, an eruption in the mouth, the thrush, Marc. Emp. 11 (in Cels. 6, 11, written as Greek). ăphya, ae, or -ē, ēs, f., = ἀφύη, a small fish, usu. called apua, acc. to some the anchovy, Plin. 32"},"appias":{"lemma":"Appias","pos":"","gen":"","def":"id.. An epithet of the nympi at the fountain of Aqua Appia (v. Applus), whose waters gushed forth near the temple of Venus: Non illas lites Appias ipsa probat, Ov. R. Am. 660"},"apprendo":{"lemma":"apprendo","pos":"","gen":"","def":"apprehendo. apprenso (adp-), āre, v. freq. , to seize something with eagerness"},"apsis":{"lemma":"apsis","pos":"","gen":"","def":"absis. Apsŏrŏs (-us), i, f., an island in the Adriatic Sea, Mel. 2, 7, 13."},"apsus":{"lemma":"Apsus","pos":"","gen":"","def":", = Ἄψος, a river of Illyria, falling into the Ionian Sea, now Crevata, Caes. B. C. 3, 13; 3, 19"},"apto":{"lemma":"apto","pos":"","gen":"","def":"freq. , to fit, adapt, accommodate, apply, put on, adjust, etc. (cf. accommodo)"},"aptus":{"lemma":"aptus","pos":"","gen":"","def":"apo, P. a."},"apua":{"lemma":"apua","pos":"","gen":"","def":"aphya. ăpŭd (apud down to the time of Caesar, Corp. Inscr. I. 30; I. 196; and after 45 B. C. both apud, Inscr. Orell. 206; 818, and aput, ib. 206; 15; 34"},"aqua":{"lemma":"aqua","pos":"n. f.","gen":"-ae","def":"water; a body of water, stream, sea; rain"},"aquae":{"lemma":"aqua","pos":"n. f.","gen":"-ae","def":"water; a body of water, stream, sea; rain","form_of":"aqua"},"aquam":{"lemma":"aqua","pos":"n. f.","gen":"-ae","def":"water; a body of water, stream, sea; rain","form_of":"aqua"},"aquarum":{"lemma":"aqua","pos":"n. f.","gen":"-ae","def":"water; a body of water, stream, sea; rain","form_of":"aqua"},"aquas":{"lemma":"aqua","pos":"n. f.","gen":"-ae","def":"water; a body of water, stream, sea; rain","form_of":"aqua"},"aquensis":{"lemma":"Aquensis","pos":"adj.","gen":"","def":"Aquae, of or belonging to Aquoe. To Aquae Taurīnae: Aquenses cognomine Taurini, Plin. 3, 5, 8, § 52.— To Aquae Aureliae: CIVITAS, Inscr. Orell. 928"},"aquicelus":{"lemma":"aquicelus","pos":"","gen":"-kernels","def":", among the Taurini, pine-kernels boiled in honey, Plin. 15, 10, 9, § 36. ăquĭdūcus, a, um, adj. aqua-duco, med. t., for the Gr. ὑδραγωγός, drawing off water medicamina, Cael. Aur. Tard. 3"},"arapennis":{"lemma":"arapennis","pos":"","gen":"","def":"arepennis. Arar (also Arăris, Claud. Ruf. 2, 111; Eutr. 1, 405; Inscr. Orell. 4018; acc. Ararim, Verg. E. 1, 63; Plin. 3, 4, 5, § 33; and Ararin, Claud. B. Get. 298: abl. Arari, Caes. B. G. 1, 13"},"ararauceles":{"lemma":"Ararauceles","pos":"","gen":"","def":", a people in Cyrenaica in Africa, Plin. 5, 5, 5, § 33. ărāter, tri, m. (a rare form for aratrum), a plough, Hyg. Limit. p. 204 Goes. Arātēus (Arātī-), a, um, adj., = Ἀράτειος"},"arauris":{"lemma":"Arauris","pos":"","gen":"","def":", a river in Gallia Narbonensis now Herault, Plin. 3, 4, 5, § 32, where Jan reads Araris; Mel. 2, 5, 6"},"araxes":{"lemma":"Araxes","pos":"","gen":"","def":", = Ἀράξης. A river in Armenia Major, now Aras, Verg. A. 8, 728; Prop. 4, 11, 8; Sen. Hippol. 47; Plin. 6, 9, 9, § 25"},"arbilla":{"lemma":"arbilla","pos":"","gen":"","def":", = arvina, id est pinguedo corporis, Paul. ex Fest. p. 20 Müll."},"arbis":{"lemma":"Arbis","pos":"","gen":"","def":", a town in Gedrosia, on the river Arbis, Plin. 6, 23, 26, § 97."},"arbusto":{"lemma":"arbusto","pos":"v.","gen":"","def":"a. id., to plant with trees: Transpadana Italia, cornu, populo, quercu arbustat agros, Plin. 17, 23, 35, § 201."},"arbustum":{"lemma":"arbustum","pos":"","gen":"","def":"qs. for arbosetum from arbos, as virgultum for virguletum, salictum for salicetum, etc."},"arbustus":{"lemma":"arbustus","pos":"adj.","gen":"","def":"arbos, arbor. Set or planted with trees: ager, * Cic. Rep. 5, 2: locus, Col. 3, 13, 6"},"arca":{"lemma":"arca","pos":"","gen":"-monnaie","def":"arceo: arca et arx quasi res secretae, a quibus omnes arceantur, Serv. ad Verg. A. 1, 262"},"arcae":{"lemma":"Arcae","pos":"","gen":"","def":", a Volscian town between Arpinum and Fabrateria, now Arce, Inscr. Orell. 149"},"arcella":{"lemma":"arcella","pos":"","gen":"","def":"dim. arca; cf. Paul. ex Fest. p. 21 Müll."},"arcto":{"lemma":"arcto","pos":"","gen":"","def":"arto init. Arctŏphylax, ăcis, m., = Ἀρκτοφύλαξ, the Bear-keeper, a constellation, usu. called Bootes, Cic. Arat. Phaen. 394 B. and K.; id. N. D. 2, 42, 109 (as transl. from Arat. 92)"},"arctus":{"lemma":"arctus","pos":"","gen":"","def":", v. arctos. arcŭārĭus, a, um, adj. arcus, pertaining to the bow: fabricae, Veg. Mil. 2, 11. —Hence, subst.: arcŭārius, ii, m., a maker of bows, Dig. 50, 6, 6. arcŭātĭlis, e, adj. arcuo"},"arcubii":{"lemma":"arcubii","pos":"","gen":"","def":": qui excubabant in arce , Paul. ex Fest. p. 25 Müll."},"arcus":{"lemma":"arcus","pos":"","gen":"","def":"(the orthography, arquus (cf. arquatus), is freq. in MSS., like quum for cum, quur for cur, etc.; cf. Freund ad Cic. Mil. p. 31 sq. Thus Charis. p. 92 P. upon Cic. N. D. 3, 20, 51, reads arcuis"},"ardenter":{"lemma":"ardenter","pos":"adv.","gen":"","def":", v. ardeo fin. ardĕo, rsi, rsum, 2, v.n. (perf. subj. ARDVERINT, Inscr. Fratr. Arval., of the time of the emperor Alexander Severus"},"ardesco":{"lemma":"ardesco","pos":"","gen":"","def":"inch. , to take fire, to kindle, to be inflamed (mostly poet. or in post-Aug. prose; not in Cic."},"ardor":{"lemma":"ardor","pos":"","gen":"","def":"ardeo, a flame, fire, heat, burning heat, lit. and trop. Lit.: solis ardor, Lucr. 2, 212: exortus est sol cum ardore, Vulg. Jac. 1, 11: ignium, Lucr. 5, 587: ignis, Vulg. 2 Pet. 3, 12: flammarum"},"ardus":{"lemma":"ardus","pos":"adj.","gen":"","def":", v. aridus."},"arduus":{"lemma":"arduus","pos":"adj.","gen":"-oleo","def":"akin to ΑΡΔΩ, ἄρσω = to water, to cherish; ἀλδαίνω = to make grow; ἀλδήεις = growing; alo, altus, q. v.; 1. ad-oleo, ad-olesco"},"arectaeus":{"lemma":"Arectaeus","pos":"adj.","gen":"","def":"from , acc. to O. T. Gen. 10, 10, an Assyrio-Babylonian town; cf. Amm. 23, 21, Babylonian: campi, Tib. 4, 1, 142 (al. Areccei). ārĕ-făcĭo (contr. arfăcĭo, Cato, R. R. 69"},"arepennis":{"lemma":"arepennis","pos":"","gen":"","def":"Gallic; in mod. Fr. arpent = an acre; syn. with semijugerum, a half acre of ground, Col. 5, 1, 6: arapennis, Isid. Orig. 15, 15, p. 485 Lind."},"ares":{"lemma":"Ares","pos":"","gen":"-god","def":", = Ἄρης, the war-god Mars (in Plaut. jocosely made to correspond with bellator, warrior): si tu ad legionem bellator clues, at ego in culinā Ares, Plaut. Truc. 2, 7, 54. (For the A"},"arganthus":{"lemma":"Arganthus","pos":"","gen":"","def":", a mountain in Mysia, near Bithynia, Gr. Ἀργανθώνιον ὄρος: Arganthi Pegae sub vertice montis, Prop. 1, 20, 33. Argēi, ōrum"},"argennon":{"lemma":"argennon","pos":"","gen":"","def":"ἀργεννός, white, brilliant, white silver, Paul. ex Fest. p. 14 Müll. Argentānum, i, n., a town of the Bruttii, Liv. 30, 19. argentārĭa, ae, f., v. argentarius, II. B. argentārĭum, ii, n."},"argentum":{"lemma":"argentum","pos":"n. n.","gen":"-i","def":"silver; silver coin, money; silverware"},"argestes":{"lemma":"argestes","pos":"","gen":"-southwest","def":", = ἀργέστης, acc. to Vitr. 1, 6, the west-southwest wind; acc. to Plin. 2, 47, 46, § 120, the west-northwest wind."},"argi":{"lemma":"Argi","pos":"","gen":"","def":"Argos init. Argīa, ae, f., = Ἀργεία. Daughter of Adrastus, and wife of Polynices, Stat. Th. 2, 266"},"argilla":{"lemma":"argilla","pos":"","gen":"","def":", = ἄργιλλος (ἀργής, white), white clay, potter's earth, argil; cf. Col. 3, 11, 9"},"argo":{"lemma":"Argo","pos":"adj.","gen":"-us","def":"(gen. Argūs, Prop. 3, 22, 19; acc. Argo, Varr. ap. Charis. p. 94 P.; Argon, Prop 1, 20, 17 Müll."},"argus":{"lemma":"Argus","pos":"adj.","gen":"-eyed","def":", = Ἄργος. The hundred-eyed keeper of Io, after she was changed into a heifer by Jupiter"},"argynnus":{"lemma":"Argynnus","pos":"","gen":"","def":", = Ἄργυννος, a boy from Boeotia, loved by Agamemnon"},"argyraspis":{"lemma":"argyraspis","pos":"adj.","gen":"","def":", = ἀργύρασπις, having a silver shield, armed with a silver shield, Liv. 37, 40; Curt. 4, 13, 15; cf. id. 8, 5, 4"},"argyrippus":{"lemma":"Argyrippus","pos":"","gen":"","def":", = Ἀργύριππος, the name of a man, Plaut. As. 1, 1, 59. argyrītis, ĭdis, f., = ἀργυρῖτις (containing silver), a kind of silver dross, litharge of silver, Plin. 33, 6, 35, § 106.‡ † argyrŏcŏrinthĭus"},"argyros":{"lemma":"argyros","pos":"","gen":"","def":", a plant, otherwise called mercurialis, App. Herb. 82. arhythmus or arhythmātus, a, um, adj. ἀ-ῥυθμός, of unequal measure, inharmonious, only in Mart. Cap. 9, pp. 327, 328. Arīa, ae, f."},"arinca":{"lemma":"arinca","pos":"","gen":"-grained","def":"Gallic, a kind of grain, otherwise called olyra, Plin. 18, 8, 19, § 81; 18, 10, 20, § 92; 22, 25, 27, § 121.— Acc. to Harduin, rye (in Dauphiné, now riguet)"},"ariouistus":{"lemma":"Ariovistus","pos":"","gen":"","def":", the king of a German tribe in the time of Coesar, Caes. B. G. 1, 31 al. ăris, ĭdis, f., = ἀρίς, Galen (ἄρον, ἀρίσαρον, in Theophr. and Dioscor.), a kind of arum"},"aris":{"lemma":"Aris","pos":"","gen":"","def":", a Sardinian, Cic. Scaur. 1, 6; 2, 7."},"arisba":{"lemma":"Arisba","pos":"","gen":"","def":", = Ἀρίσβη. A town in Troas, Verg. A. 9, 264; Plin. 5, 30, 33, § 125.— A town in the island of Lesbos, Mel. 2, 7"},"aristarchus":{"lemma":"Aristarchus","pos":"","gen":"-ch","def":", = Ἀρίσταρχος, a distinguisled critic of Alexandria, who animadverted with special severity upon the poetry of Homer, and contended that many of his verses were spurious, Cic. Fam. 3, 11"},"aristippus":{"lemma":"Aristippus","pos":"adj.","gen":"-stipp","def":", = Ἀρίστιππος, a philosopher of Cyrene, disciple of Socrates, and founder of the Cyrenaic school: qui voluptatem summum bonum dicit, Cic. Fin. 2, 6, 18"},"arma":{"lemma":"arma","pos":"","gen":"","def":"(gen. plur. armūm, Pac. ap. Cic. Or. 46, 155; Att. ap. Non. p. 495, 23, considered by Cic. in the connection armūm judicium as less correct than armorum) [cf. ΑΡΩ, ἀραρίσκω = to fit; ἄρθρον = joint"},"armenta":{"lemma":"armenta","pos":"","gen":"","def":"armentum. armentālis, e, adj. armentum, pertaining to a herd of cattle (except once in Verg., only post-class.): equa, * Verg. A. 11, 571: lac, Symm. Ep. 6, 17"},"armentum":{"lemma":"armentum","pos":"","gen":"-cattle","def":"(old form armenta, ae, f., Liv. Andron. and Enn. ap. Non. p. 190, 20; Enn. ap. Paul. ex Fest. p. 4 Müll.) [contr. for arimentum from aro, Varr. L. L. 5, § 96 Müll."},"armilla":{"lemma":"armilla","pos":"","gen":"","def":"acc. to Paul. ex Fest. p. 25 Müll., from armus"},"armillum":{"lemma":"armillum","pos":"","gen":"-class","def":"acc. to Paul. ex Fest., from armus"},"armo":{"lemma":"armo","pos":"v.","gen":"","def":"a. arma. Lit., to furnish with weapons, to arm, equip, aliquem or aliquem aliquā re: cum in pace multitudinem hominum coëgerit, armārit, instruxerit, Cic. Caecin. 12: milites armari jubet"},"armus":{"lemma":"armus","pos":"","gen":"-blade","def":", = ἁρμός , pr., a joining together"},"arna":{"lemma":"Arna","pos":"","gen":"","def":", a town in Umbria, a mile east of Perusia, now Civitella d'Arno, Sil. 8, 458; Inscr. Orell. 91; cf. Mann. Ital. I. 483.—Hence, Arnātes, um, m., the inhabitants of Arna, Plin. 3, 14, 19, § 113"},"arniensis":{"lemma":"Arniensis","pos":"","gen":"","def":"Arnus."},"arnion":{"lemma":"arnion","pos":"","gen":"","def":"arnoglossa. Arnŏbĭus, ii, m. An African Church father in the time of Diocletian, c. A. D. 295. His work, Adversus Gentes, is distinguished by strength and purity of diction"},"arnoglossa":{"lemma":"arnoglossa","pos":"","gen":"-tongue","def":", = ἀρνόγλωσσον, a plant, sheep's-tongue or plantain: Plantago major, Linn.; App. Herb. 1 (also called arnion; Isid., Orig. 17, 9, 50, calls it arnoglossos)."},"arnus":{"lemma":"Arnus","pos":"adj.","gen":"","def":", = Ἄρνος, a river of Etruria, now the Arno, Plin. 3, 5, 8, § 50; Tac. A. 1, 79 al."},"arpi":{"lemma":"Arpi","pos":"adj.","gen":"-p","def":", a city in Apulia, earlier called Argyripa (q. v.), now Arpa, Plin. 3, 11, 16, § 104"},"arquus":{"lemma":"arquus","pos":"","gen":"","def":", v. arcus."},"arra":{"lemma":"arra","pos":"","gen":"","def":"arrha, arrhabo, arrhalis. arrectārĭus (adr-), a, um, adj. arrectus, in an erect position, erect, perpendicular"},"arrha":{"lemma":"arrha","pos":"","gen":"-class","def":", and arrhăbo (also without aspiration arra and arrăbo), ōnis, m. (the latter form ante-class.; cf. Gell. 17, 2, 21"},"arruns":{"lemma":"Arruns","pos":"","gen":"","def":", v. Aruns. Arruntĭus, ii, m., a Roman nomen. L. Arruntius, consul A.U.C. 759, Tac. A. 1, 13; 3, 11; 6, 5"},"arsella":{"lemma":"arsella","pos":"","gen":"","def":", a plant, also called argemonia, q. v., App. Herb. 31. Arsēnārĭa, ae, f., a Roman colony in Mauretania Caesariensis, now Arzew, Plin. 5, 2, 1, § 19"},"arsinna":{"lemma":"Arsinna","pos":"","gen":"","def":"Arsenaria. Arsĭnŏē, ēs, and Arsĭnŏa, ae, f., = Ἀρσινόη. Arsinoa, mother of the third Mercury, Cic. N. D. 3, 22, 57.— Arsinoë, daughter of Ptolemy Lagus and Berenice, wife of king Lysimachus"},"arsis":{"lemma":"arsis","pos":"","gen":"","def":", = ἄρσις, in metre, the elevation of the voice; opp. thesis, depression (in pure Lat., sublatio, Diom. p. 471 P.), Mart. Cap. 9, p. 328; Don. p. 1738 P."},"artaxerxes":{"lemma":"Artaxerxes","pos":"","gen":"","def":", = Ἀρταξέρξης, the name of several Persian kings, Nep. Reg. 1, 3; Just. 3, 1"},"artopta":{"lemma":"artopta","pos":"","gen":"-pan","def":", = ἀρτόπτης. * A baker, Juv. 5, 72 Ruperti.— A vessel to bake in, a bread-pan, Plaut. Aul. 2, 9, 4"},"artro":{"lemma":"artro","pos":"","gen":"","def":"aratro. artŭa, v. artus init. artŭātim, adv. 2. artus, limb by limb, Firm. Math. 7, 1. artŭātus, a, um, Part. , torn in pieces, Firm. Math. 6, 31. artus (not arctus), a, um, adj. v. arma"},"artus":{"lemma":"artus","pos":"","gen":"","def":"id., mostly plur. (artua, n., Plaut. Men. 5, 2, 102; quoted in Non. p. 191, 12.—Hence, dat. acc. to Vel. Long. p. 2229 P. and Ter. Scaur. p. 2260 P. artibus"},"aruerni":{"lemma":"Arverni","pos":"adj.","gen":"","def":", = Ἀρβερνοί, Plut.; Ἀρουερνοί, Strabo, a people of Gaul, in the present Auvergne, Caes. B. G. 1, 31; 1, 45; 7, 7; Luc. 1, 427"},"aruns":{"lemma":"Aruns","pos":"","gen":"","def":", an Etruscan name of the younger son, while the elder was called Lar or Lars [in pure Etruscan, Arnth."},"aruum":{"lemma":"arvum","pos":"","gen":"","def":", v. arvus, II. B."},"aruus":{"lemma":"arvus","pos":"adj.","gen":"-ground","def":"for aruus from aro. That has been ploughed, but not yet sown, ploughed, arable: ager, arvus et arationes ab arando, Varr. L. L. 5, § 39 Müll.: arvum, quod aratum nec dum satum est, id. R. R. 1, 29"},"arx":{"lemma":"arx","pos":"","gen":"-hill","def":"arx ab arcendo, quod is locus munitissimus rubis, a quo facillime possit hostis prohiberi, Varr. L. L. 5, § 151 Müll; cf. Serv. ad Verg. A. 1, 20; Isid. Orig. 15, 2, 32; Doed. Syn. IV. p. 428"},"as":{"lemma":"as","pos":"","gen":"-um","def":"(nom. assis, Don. ad Ter. Phorm. 1, 1, 9, and Schol. ad Pers. 2, 59; old form assārĭus, ii, m.; and in the gen. plur. assariūm, Varr. L. L. 8, § 71 Müll."},"ascaules":{"lemma":"ascaules","pos":"","gen":"","def":", = ἀσκαύλης, a bagpiper, Mart. 10, 3, 8 (called in Suet. Ner. 54 by the pure Lat. word, utricularius). ascendens (ads-), entis, P. a., v. ascendo fin. ascendĭbĭlis (ads-), e, adj. ascendo"},"asclum":{"lemma":"Asclum","pos":"","gen":"","def":", v. Asculum. Ascōnĭus, ii, m.: Q. Asconius Pedianus, a learned grammarian of Padua (c. A. D. 3-88), who devoted his studies especially to Cicero, Sallust, and Vergil"},"ascra":{"lemma":"Ascra","pos":"adj.","gen":"-craeus","def":", = Ἄσκρα. A village in Boeotia, near Mount Helicon, the birthplace of Hesiod, Ov. P. 4, 14, 31.—Hence, As-craeus, a, um, adj., = Ἀσκραῖος. Ascroean: nemus, Prop. 2, 13, 4: poëta, i. e. Hesiod, id. 2"},"ascyron":{"lemma":"ascyron","pos":"","gen":"-wort","def":", = ἄσκυρον, a plant, also called androsaemon, St. John's-wort, Plin. 27, 4, 10, § 26. Asdrŭbal, v. Hasdrubal. ăsella, ae, f. dim. asina, a small sheass, Ov. A. A. 3, 290. Asellĭo, ōnis, m."},"asnaus":{"lemma":"Asnaus","pos":"","gen":"","def":", a mountain in Macedonia, Liv 32, 5.lt Asōi, ōrum, plur m., a people of India, Plin. 6, 20, 23, § 78. ăsōmătus, a, um, adj., = ἀσὡματος, incorporeal, profatus, Mart. Cap. 3 init. Āsōpĭădes, ae"},"aspar":{"lemma":"Aspar","pos":"","gen":"","def":", a Numidian, Sall. J. 108, 1; 112, 1. Aspărāgĭum, ii, n., a town in Illyria, on the river Genusus, now Iskarpar, Caes. B. C. 3, 30 fin.; 3, 41"},"aspargo":{"lemma":"aspargo","pos":"","gen":"","def":"1. aspergo."},"aspendos":{"lemma":"Aspendos","pos":"adj.","gen":"","def":", = Ἄσπενδος, a town built by the Argives, in Pamphylia, on the Eurymedon, now Minugat, Cic. Verr. 1, 20, 53; Mel. 1, 14, 1.—Also, Aspendum, i, n., Plin. 5, 27, 26, § 96"},"asper":{"lemma":"asper","pos":"adj.","gen":"-bound","def":"(aspra = aspera, Enn. ap. App. Mag. p. 299, but Vahl. ad Enn. p. 166 reads spissa instead of aspra: aspris = asperis, Verg. A. 2, 379; aspro = aspero, Pall. Insit. 67) [etym. dub."},"aspernanter":{"lemma":"aspernanter","pos":"adv.","gen":"","def":", v. aspernor fin. aspernātĭo, ōnis, f. aspernor, a despising, contemning, disdain (very rare): rationis, * Cic. Tusc. 4, 14, 31: naturalis, Sen. Ep. 121 fin.: illius, * Vulg. Eccli. 22"},"aspis":{"lemma":"aspis","pos":"","gen":"","def":"(acc. Gr. aspida, Luc. 9, 701; plur. aspidas, Cic. N. D. 3, 19, 47) [ἀσπίς, com. shield, rarely an asp; this order of frequency is reversed in Lat.]. The asp, viper: Coluber, Linn."},"assa":{"lemma":"assa","pos":"","gen":"","def":"assus, a, um."},"assabinus":{"lemma":"Assabinus","pos":"","gen":"","def":", a deity of the Ethiopians, Plin. 12, 19, 42, § 89. Assărăcus, i, m., = Ἀσσάρακος, King of Phrygia, son of Tros, brother of Ganymede and Ilus, father of Capys, and grandfather of Anchises, Ov. M. 11"},"asser":{"lemma":"asser","pos":"","gen":"","def":"from 2. assero, quod admoveantur haereantque parietibus, Perot."},"assis":{"lemma":"assis","pos":"","gen":"","def":", = as, v. as init."},"assistrix":{"lemma":"assistrix","pos":"","gen":"","def":"assestrix. assĭtus (ads-), a, um, Part., v. 1. assero. as-sĭtus (ads-), a, um, adj. sino, situated near (post-class.): atria viridantibus adsita pratis"},"asso":{"lemma":"asso","pos":"v.","gen":"","def":"a. assus, to roast, broil (late Lat.): assari, App. M. 2, p. 119, 12: assaverunt Phase super ignem, Vulg. 2 Par. 35, 13: assavit carnes ejus, ib. Tob. 6, 6: jecur, Apic. 2, 1. as-sŏcĭo (ads-), āvi"},"assum":{"lemma":"assum","pos":"","gen":"","def":"adsum. assūmentum (ads-), i, n. assuo, that which is to be sewed upon something, a patch: Nemo adsumentum panni rudis adsuit vestimento veteri, Vulg. Marc. 2, 21. as-sūmo (ads-, Lachm., Halm"},"ast":{"lemma":"ast","pos":"conj.","gen":"","def":", v. at init."},"asta":{"lemma":"asta","pos":"","gen":"","def":", v. hasta."},"astensis":{"lemma":"Astensis","pos":"adj.","gen":"","def":", v. Asta."},"aster":{"lemma":"aster","pos":"","gen":"","def":", = ἀστήρ. A star, Macr. Somn. Scip. 1, 14.— Esp. Aster Atticus, the Italian starwort, aster: Aster amellus, Linn.: aster ab aliquis bubonion appellatur, Plin. 27, 5, 19, § 36"},"astercum":{"lemma":"astercum","pos":"","gen":"","def":"astericum. astĕrĭa, ae, f., = ἀστερια, a precious stone, perh. cat's-eye, Plin. 37, 9, 47, § 131.—Called in Isid. Orig. 16, 10, 3. astĕ-rītes"},"astraea":{"lemma":"Astraea","pos":"","gen":"","def":", = Ἀστραία, the goddess of Justice, who, during the Golden Age, lived on the earth, but finally abandoned it, and returned to heaven, Ov. M. 1, 150; Juv. 6, 19; Sen. Oct. 424"},"astraeus":{"lemma":"Astraeus","pos":"","gen":"","def":", = Ἀστραῖος, a Titan, husband of Aurora, and father of the winds, which are hence called Astraei fratres, Ov. M. 14, 545"},"astrum":{"lemma":"astrum","pos":"","gen":"","def":"perh. ἄστρον borrowed; cf. ἀστήρ; Sanscr. staras (plur.); Engl. star; Germ. Stern; Goth. stairno; and stella"},"astur":{"lemma":"astur","pos":"","gen":"","def":", a species of hawk, Firm. Math. 5, 7 fin."},"asturco":{"lemma":"Asturco","pos":"","gen":"","def":"Astur, an Asturian horse, an ambler, distinguished for the beautiful motion of its limbs (cf. the epigram, Mart. 14, 199, and Sil. 3, 336), Auct. ad Her. 4, 50"},"astus":{"lemma":"astus","pos":"adj.","gen":"","def":", v. astutus."},"asty":{"lemma":"asty","pos":"","gen":"","def":"astu. Astyăges, is, m., = Ἀστυάγης. King of Media, father of Mandane, and grandfather of Cyrus, by whom he was deprived of his throne, Just. 1, 4 sq.— An enemy of Perseus"},"astycus":{"lemma":"astycus","pos":"","gen":"","def":"asticus. Astylŏs, i, m., = Ἄστυλος, a centaur and soothsayer, who endeavored to dissuade the other centaurs from the war with the Lapithoe, Ov. M. 12, 308 (called by Hes. Scut. Herc. 185"},"astyra":{"lemma":"Astyra","pos":"","gen":"","def":", a city of Mysia Major, not far from Adramyttium, Mel. 1, 18, 2; Plin. 5, 30, 32, § 122."},"astytis":{"lemma":"astytis","pos":"","gen":"","def":", = ἀστυτίς, a kind of lettuce, Plin. 19, 8, 38, § 127."},"asum":{"lemma":"Asum","pos":"","gen":"","def":", a town in Crete, Plin. 4, 12, 20, § 59. asȳla, ae, f., = ἀσύλη, a plant"},"at-testor":{"lemma":"at-testor","pos":"v.","gen":"-testor","def":"dep., to bear witness to, to attest, prove, confirm, corroborate (very rare, and not before the Aug. per."},"at-texo":{"lemma":"at-texo","pos":"v.","gen":"-texo","def":"a. To weave on or to something (rare, and only in prose): turres contabulantur, pinnae loricaeque ex cratibus attexuntur, Caes. B. G. 5, 40: attexti capite crines, App. M. 11, p. 260, 35.— In gen."},"at-torqueo":{"lemma":"at-torqueo","pos":"v.","gen":"-torqueo","def":"a., to hurl or swing upward (ad designating direction upward, as in assurgo, attollo"},"atax":{"lemma":"Atax","pos":"","gen":"","def":", = Ἄταξ, a small river in Gallia Narbonensis, now Aude, Mel. 2, 5; Plin. 3, 4, 5, § 32; Luc. 1, 403; Sid. Carm. 9, 15"},"ateste":{"lemma":"Ateste","pos":"adj.","gen":"","def":", = Ἀτεστέ (Ptol.), a town in the country of the Venetians, Plin. 3, 19, 23, § 130; 17, 17, 26, § 122; Tac. H. 3, 6; later called Ad Este and Ab Este, whence arose the present name, Este"},"athis":{"lemma":"Athis","pos":"","gen":"","def":"(acc. Athin), a son of Limnate, slain by Perseus, Ov. M. 5, 47; 5, 63; 5, 72 Merk. (al. Athys, Atys, Attis)."},"athla":{"lemma":"athla","pos":"","gen":"","def":"athlon. āthlēta, ae, com. (nom. athletes, Stat. S. 53, 222; acc. athletam, Plin. 7, 20, 19, § 83; v. Neue, Formenl. I. pp. 32, 593), = ἀθλητής, a wrestler, a prize-fighter, athlete, Cic. Sen. 9, 27"},"atrusca":{"lemma":"atrusca","pos":"","gen":"","def":", a kind of grape, Macr. S. 2, 16. atta, like the Gr. ἄττα, a salutation used to old men, father; taken from the lang. of children (cf. Eust. ad Il. 1, 603), Paul. ex Fest. p. 11 Müll."},"atta":{"lemma":"Atta","pos":"","gen":"","def":", a surname for persons who walk upon the tips of their shoes, Paul. ex Fest. p. 11 Müll. (prob. from ᾁττω = ᾁσσω, to spring, to hop). So the comic poet, C. Quintius Atta († 652 A.U.C.)"},"attactus":{"lemma":"attactus","pos":"","gen":"","def":"attingo, a touching, touch (very rare, and only in abl. sing.): Corium attactu non asperum ac durum, Varr. R. R. 2, 5, 8: ille volvitur attactu nullo, Verg. A. 7, 350"},"attentus":{"lemma":"attentus","pos":"","gen":"","def":"attendo, P. a. attentus (adt-), a, um, Part. of attineo. attĕnŭātē (adt-), adv., v. attenuo, P. a. fin. attĕnŭātĭo (adt-), ōnis, f. attenuo, a diminishing"},"attin":{"lemma":"Attin","pos":"","gen":"","def":"Attis. at-tĭnae (adt-), ārum, f. attineo, stones built up like a wall for a boundary mark, Sic. Fl. pp. 4 and 6 Goes. at-tĭnĕo (adt-, Dietsch, Weissenb.), tĭnui, tentum, 2, v. a. and n. teneo. Act."},"attractus":{"lemma":"attractus","pos":"","gen":"","def":"attraho, a drawing to, attraction, Dictys, 5, 11. at-trăho, traxi, tractum, 3, v. a., to draw to or toward, to attract, drag with force, draw (rare but class."},"attys":{"lemma":"Attys","pos":"","gen":"","def":"Attis and Atys. Atūrus (on account of the length of the u, sometimes written Aturrus; cf. Arabia; once ŭ, Luc. 1, 420), i, m., = Ἀτούριος, a river in Aquitania, now Adour, Aus. Parent. 4, 11"},"au":{"lemma":"au","pos":"interj.","gen":"","def":", v. 2. hau. aucella (aucilla), ae, f. dim. as if for avicella, from avis, a little bird (only postclass."},"aua":{"lemma":"ava","pos":"","gen":"","def":"avia. ăvārē, adv., v. avarus fin. Avārĭcum, i, n., a large and fortified town of the Bituriges, in Gaul, now Bourges, in the Dép. du Cher, Caes. B. G. 7, 13; 7, 31"},"auceta":{"lemma":"auceta","pos":"","gen":"","def":"augeo init. Auchētae, ārum, m., = αὐχάται, a Scythian people in the present Ukraine, Plin. 4, 12, 26, § 88.—In sing., acc. to the Gr., Auchātes, ae, an Auchatian, Val. Fl. 6, 132."},"aucilla":{"lemma":"aucilla","pos":"","gen":"","def":"aucella. auctārĭum, ii, n. augeo, an addition or augmentation of a definite measure: auctarium dicebant antiqui, quod super mensuram vel pondus justum adiciebatur"},"aucto":{"lemma":"aucto","pos":"","gen":"","def":"freq. , to increase or enlarge much (perh. only in the foll. exs.): res rationesque vostrorum omnium Bono atque amplo auctare lucro, Plaut. Am. prol. 6: Unde omnis natura creet res auctet alatque"},"auctrix":{"lemma":"auctrix","pos":"adv.","gen":"-class","def":"auctor. She that originates a thing, an author (very rare, and post-class. for auctor, q. v. fin.): materia auctrix universitatis, Tert. adv. Herm. 5: anima auctrix operum carnis, id. adv. Marc. 5"},"auctus":{"lemma":"auctus","pos":"","gen":"","def":"augeo, P. a."},"audacter":{"lemma":"audacter","pos":"adv.","gen":"","def":", v. audax fin. audācŭlus, a, um, adj. dim. , a little bold (rare, and post-class.), Paul. ex Fest. p. 23 Müll.: reprehensor audaculus verborum, Gell. 5, 21; Sulp. Apoll. ap. eund. 15, 5"},"audens":{"lemma":"audens","pos":"","gen":"","def":"audeo, P. a."},"audenter":{"lemma":"audenter","pos":"adv.","gen":"","def":", v. audeo, P. a. fin. audentĭa, ae, f. audens, boldness, courage, spirit, in a good sense (only postAug. and rare"},"auella":{"lemma":"Avella","pos":"","gen":"","def":"Abella. Avellānus, v. Abella. ā-vello, velli or vulsi, vulsum or volsum, 3, v. a. (pluperf. avellerat, Curt. 5, 6, 5"},"auernus":{"lemma":"Avernus","pos":"adj.","gen":"","def":", = ἄορνος. Without birds: loca, where no birds can live, on account of the pestiferous exhalations, Lucr. 6, 738 sq."},"augesco":{"lemma":"augesco","pos":"","gen":"","def":"inch. , to begin to grow, to become greater, to grow, increase (syn.: cresco, incresco)"},"augmen":{"lemma":"augmen","pos":"","gen":"-class","def":"augeo, an increase, enlargement, augmentation, growth (only ante- and post-class.): corporis, Lucr. 2, 495; 3, 268: Augmine vel grandi vel parvo, id. 1, 435: augmine donare, id. 2, 73"},"augmento":{"lemma":"augmento","pos":"v.","gen":"","def":"a. augmentum, to increase: thesauros, Firm. Math. 5, 6. augmentum (in MSS. also augŭ-mentum), i, n. augeo, an increase, growth, augmentation (very rare"},"augusta":{"lemma":"Augusta","pos":"","gen":"","def":"(dat. Augustal) . Under the emperors, a litle of the mother, wife, daughter, and sister of the emperor; like our Imperial Majesty, Imperial Highness, Tac A. 1, 8; 15, 23; 4, 16; 12, 26"},"augusto":{"lemma":"augusto","pos":"v.","gen":"","def":"a. 1. augustus, to render venerable, to glorify: deos, Arn. 6, p. 201.—P. a.: augustātus, a, um, adj., made venerable, i. e. consecrated: mensa, Jus Pap. ap. Macr. S. 3, 11 dub."},"augustobrigenses":{"lemma":"Augustobrigenses","pos":"","gen":"","def":", the inhabitants of the city Augustobriga in Lusitania, Plin. 4, 22. 35, § 118. Augustŏdūnum, i, n., a iown of the Aedui, in Gaul, now Autun. Mel. 3, 2, 4; Tac. A. 3, 43 and 45."},"augustus":{"lemma":"augustus","pos":"adj.","gen":"","def":"from augeo, as angustus from ango; v. augeo, originally belonging to the language of religion, majestic, august, venerable, worthy of honor (class. in prose and poetry"},"aula":{"lemma":"aula","pos":"","gen":"-bee","def":"(gen. aulāī, Verg. A. 3, 354; v. Neue, Formenl I. p 11), = αὐλή Lit., the front court of a Grecian house (mostly poet.; syn. atrium): janitor aulae, i. e. Cerberus, Hor C. 3, 11, 16"},"aulaeum":{"lemma":"aulaeum","pos":"","gen":"","def":", = αὐλαία (Plut.), a splendidly wrought or embroidered stuff, tapestry, arras, esp. a covering, a curtain, hangings: aulaea genus vestis peregrinum, Varr. de Vita populi Rom. lib. III."},"aulax":{"lemma":"aulax","pos":"","gen":"","def":", = αὖλαξ, a furrow, Veg. Art. Vet. 2, 28, 38; Aus. Ep. 10, 10 (old edd., aulix; the true form was restored by Schneider)."},"aulerci":{"lemma":"Aulerci","pos":"","gen":"","def":", = Αὐλίρκιοι, a people in Celtic Gaul, Liv. 5, 34, 5"},"aulestes":{"lemma":"Aulestes","pos":"","gen":"","def":", a Tuscan, a confederate of Aeneas, Verg. A. 12, 290. Aulētes, ae, m., the flute-player, the surname of the exiled Egyptian king Ptolemy, Cic Rab. Post. 10, 28. aulētĭca, ae, f., = αὐλητική, a plant"},"aulis":{"lemma":"Aulis","pos":"","gen":"","def":", = Αὐλίς, a seaport town in Boeotia, from which the Grecian fleet set sail for Troy, Verg. A. 4, 426: Aulin (acc.), Luc. 5, 236."},"aulix":{"lemma":"aulix","pos":"","gen":"","def":"aulax."},"auloedus":{"lemma":"auloedus","pos":"","gen":"","def":", = αὐλὡδός, one who sings to the flute, Cic. Mur. 13 fin. (quoted by Quint. 8, 3, 79); so Jul. Val. Rer. Gest. Alex. M. 1, 66."},"aulon":{"lemma":"Aulon","pos":"","gen":"","def":"A vine - bearing mountain and adjacent valley in Calabria, Hor. C. 2, 6, 18; Mart. 13, 125"},"aulus":{"lemma":"aulus","pos":"","gen":"","def":", = αὐλός (flute), a fluteshaped kind of scollop, Plin. 32, 9, 32, § 103."},"aura":{"lemma":"aura","pos":"","gen":"","def":"sing. aurāï, Verg. A. 6, 747; v. Neue, Formenl. I. p. 11; also, auras, like familias, custodias, terras, etc.; Servius gives this in Verg. A. 11, 801"},"aureax":{"lemma":"aureax","pos":"","gen":"","def":"auriga init. Aurēlĭānus, i, m. Flavius Claudius, a Roman emperor who reigned A. D. 270-275; his life was written by Vopiscus; Inscr. Orell. 489; 1026 sq.; 1535"},"auresco":{"lemma":"auresco","pos":"","gen":"","def":"inch. , to become of the color of gold: aër aurescit, Varr. L. L. 7, § 83 Müll. aurĕus, a, um, adj. id.. Lit. Of gold, golden (syn.: aureolus, auratus, aurifer): patera, Plaut. Am. 1, 1"},"auro":{"lemma":"auro","pos":"v.","gen":"-tus","def":"a. aurum, to overlay with gold, to gild: a metallorum quoque nominibus solent nasci verba, ut ab auro auro, auras"},"aurum":{"lemma":"aurum","pos":"n. n.","gen":"-i","def":"gold; gold coin; anything made of gold"},"aurunci":{"lemma":"Aurunci","pos":"adj.","gen":"-runcus","def":", = Ausones, q.v., = Αὔρουγκοι Tzetz. The Aurunci, Verg. A. 11, 318"},"auruspi":{"lemma":"Auruspi","pos":"","gen":"","def":", a people of Ethiopia, Plin. 6, 30, 35, § 192. auscŭlāri and auscŭlum, v. osculor and osculum. auscultātĭo, ōnis, f. ausculto. A listening"},"ausculto":{"lemma":"ausculto","pos":"","gen":"","def":"freq. [perh. a union of two roots, that of audio, auris ausis, and of the Sanscr. çru = to hear"},"ausim":{"lemma":"ausim","pos":"","gen":"","def":"audeo init."},"auson":{"lemma":"Auson","pos":"","gen":"","def":"Ausones, II. E. Ausŏna, ae, f., an ancient town of the Ausones, near Minturnoe, Liv. 9, 25, 4. Ausŏnes, um, m., = Αὔσονες [prob. of the same root as Oscus or Opicus"},"auspex":{"lemma":"auspex","pos":"","gen":"-spicio","def":"a contraction of avispex, from avis-spicio, a bird inspector, bird-seer, i. e. one who observes the flight, singing, or feeding of birds, and foretells future events therefrom"},"austellus":{"lemma":"austellus","pos":"","gen":"","def":"dim. auster, a gentle south wind, Lucil. ap. Non. p. 98, 22."},"auster":{"lemma":"auster","pos":"","gen":"","def":"Sanscr. ush-, to burn; the burning, hot wind, the south wind (opp. aquilo, the north wind). Lit.: auster fulmine pollens, Lucr. 5, 745: validus, id. 1, 899"},"ausum":{"lemma":"ausum","pos":"","gen":"","def":"audeo, P. a."},"ausus":{"lemma":"ausus","pos":"","gen":"","def":"audeo, P. a."},"aut":{"lemma":"aut","pos":"conj.","gen":"-t","def":"[aut, Osc. auti, Umbr. ote, ute, may be a modification of autem, as at of et, the suffix -t being a relic of the demonstrative -tem, which appears in item, and is the same as -dem in quidem"},"authenta":{"lemma":"authenta","pos":"","gen":"","def":", = αὐθέντης, a chief prince, head, Fulg. Cont. Verg. p. 161 Muncker. authentĭcus, a, um, adj., = αὐθεντικός, that comes from the author, authentic, original"},"authepsa":{"lemma":"authepsa","pos":"","gen":"-cooker","def":", = αὐθέψης , a utensil for cooking (somewhat like our tea - urns): in quibus (vasis) est authepsa illa, quam tanto pretio nuper mercatus est, Cic. Rosc. Am. 46, 133: argenteae"},"auxo":{"lemma":"Auxo","pos":"","gen":"","def":", = Αὐξώ, one of the Hours, daughter of Jupiter and Themis, Hyg. Fab. 183. Auzēa, Auzīa, or Audīa, ae, f., a place in Mauretania Caesariensis, afterwards a Roman colony: castellum semirutum"},"axilla":{"lemma":"axilla","pos":"","gen":"","def":"ala."},"axim":{"lemma":"axim","pos":"","gen":"","def":"ago init. axīnŏmantīa, ae, f., = ἀξινομαντεία, a kind of divination from axes, Plin. 36, 19, 34, § 142; cf. id. 30, 2, 5, § 14. axĭōma, ătis, n., = ἀξίωμα, a principle, axiom, App. Dogm. Plat. 3"},"axis":{"lemma":"axis","pos":"","gen":"-clock","def":"kindred with Gr. ἄξων; Sanscr. akshas = axle, wheel; old Germ. Ahsa; mod. Germ. Achse; Engl. axle, Bopp, Gloss. p. 2, a"},"axon":{"lemma":"axon","pos":"","gen":"","def":", = ἄξων. A line upon the sundial, its axis, Vitr. 9, 5.— A part of the ballista, Vitr. 10, 17.— Axŏnes, um, the laws of Solon engraved on tables of wood (axibus ligneis, Gell. 2, 12"},"aza":{"lemma":"Aza","pos":"","gen":"","def":", a town in Armenia Minor, Plin. 6, 9, 10, § 26. Azăli, ōrum, m., = ̓́Αζαλοι, a people of Pannonia, Plin. 3, 25, 28, § 148."},"azan":{"lemma":"Azan","pos":"","gen":"-nes","def":", = ̓Αζάν"},"babba":{"lemma":"Babba","pos":"","gen":"","def":", a town in Mauritania, called, as a Roman colony, Julia Campestris, Plin. 5, 1, 1, § 5."},"babel":{"lemma":"Babel","pos":"","gen":"","def":", the capital city of Assyria, Aug. Civ. Dei, 16, 3, 11; cf. Vulg. Gen. 11, 9. Babĭa, ae, f., a town of Lower Italy, Plin. 14, 6, 8, § 69."},"babilus":{"lemma":"Babilus","pos":"","gen":"","def":", an astronomer of the time of Nero, Suet. Ner. 36. Babullĭus, ii, m., a rich friend of Coesar, Cic. Att. 13, 48, 1. babŭlus, i, m., a babbler, fool (late Lat.), App. M 4, p. 149, 7. baburrus, a, um"},"baccha":{"lemma":"Baccha","pos":"","gen":"","def":", a kind of Spanish wine, Varr. L. L. 7, § 87 Müll. bacchābundus, a, um, adj. bacchor, revelling in the manner of the Bacchantes, boisterous, noisy, ranting, raving (post-Aug. and rare"},"baccharia":{"lemma":"Baccharia","pos":"","gen":"","def":", the name of a lost play of Plautus, Macr. S. 2, 12. bacchātim, adv. bacchor, in the manner of the Bacchoe or Bacchantes, in a riotous, wanton manner, App. M. 1, p. 108, 3. bacchātĭo, ōnis"},"bacchis":{"lemma":"Bacchis","pos":"","gen":"","def":", = Βακχίς. = 1. Baccha, q. v.— The name of a woman in the Hec. and Heaut. of Terence"},"bacchor":{"lemma":"bacchor","pos":"v.","gen":"-tes","def":"pres. gen. plur. bacchantum"},"bacchus":{"lemma":"Bacchus","pos":"adj.","gen":"-dispeller","def":", = Βάκχος, son of Jupiter and a Theban woman, Semele, Tib. 3, 4, 45"},"bacis":{"lemma":"Bacis","pos":"","gen":"","def":"(Βάκις, ιδος, Pausan.), a soothsayer of Boeotia, Cic. Div. 1, 18, 34. Bacis (Bacchis, Pacis), acc. Bacem, a sacred bull, worshipped at Hermonthis in Upper Egypt, Macr. S. 1, 21."},"bacrio":{"lemma":"bacrio","pos":"","gen":"","def":", a kind of vessel with a long handle, a ladle: i. q. trulla, Paul. ex Fest. p. 31 Müll."},"bactra":{"lemma":"Bactra","pos":"adj.","gen":"-tr","def":"6, 16, 18, § 48), n., = Βάκτρα, the chief city of Bactria or Bactriana, now Balkh, Verg. G. 2, 138; Prop. 3 (4), 1, 16; 3, 11 (4, 10), 26; Hor. C. 3, 29, 28; Curt. 7, 4, 31; cf. Sil. 13, 764"},"bactrum":{"lemma":"Bactrum","pos":"","gen":"","def":"Bactra init. Bactrus (-ŏs), i, m., = Βάκτρος, a river near Bactra, now Dehas, Curt. 7, 4, 31; Luc. 3, 267; cf. Isid. Orig. 13, 21, 14; 14, 3, 30; 15, 1, 11"},"bagada":{"lemma":"Bagada","pos":"","gen":"","def":", a town of Ethiopia, Plin. 6, 29, 35, § 178."},"bagaudae":{"lemma":"Bagaudae","pos":"","gen":"","def":", a class of peasants in Gaul, who rebelled under the emperor Diocletian, and were finally conquered by Maximian, Aur. Vict. Caes. 39"},"baia":{"lemma":"baia","pos":"","gen":"-branch","def":"Copt. bai, whence βάϊς, a palm-branch, Hier. Jovin. 3, 18. Bāiae (dissyl.), ārum, f., = Βαἷαι, a small town in Campania, on the coast between Cumoe and Puteoli"},"balbillus":{"lemma":"Balbillus","pos":"","gen":"","def":", a scholar, prefect in Egypt, Sen. Q. N. 4, 2, 13; Tac. A. 13, 22; Plin. 19, 1, prooem. § 3 Jan. (al. Balbilius, Babbillus)."},"balbus":{"lemma":"balbus","pos":"adj.","gen":"","def":"kindr. with balo"},"balinienses":{"lemma":"Balinienses","pos":"","gen":"","def":", a name given to the Trebulani, Plin. 3, 5, 9, § 64. balĭŏlus, a, um, adj. balius = badius, dark, swarthy, chestnut-colored: amplexari baliolum (sc. Afrum), Plaut. Poen. 5, 5, 22 dub."},"balista":{"lemma":"balista","pos":"","gen":"","def":"ballist-. Balista (Ballista), ae, f., a mountain in Liguria, Liv. 39, 2, 7"},"ballio":{"lemma":"Ballio","pos":"adj.","gen":"","def":", the name of a worthless pimp in the Pseudolus of Plautus; hence, for designating any worthless man, Cic. Phil. 2, 6, 15"},"ballista":{"lemma":"Ballista","pos":"","gen":"","def":"2. Balista. ballistārĭum (balist-), ii, n., = ballista, or the place where the ballista is worked, Plaut. Poen. 1, 1, 74 (cf. ballista fin.). ballistārĭus (balist-"},"ballo":{"lemma":"ballo","pos":"v.","gen":"","def":"n. βάλλω, βαλλίξω, to dance, Aug. Serm. 215 (hence, Fr. bal"},"balneae":{"lemma":"balneae","pos":"","gen":"","def":"balneum. balnĕārĭs, e, adj. balneum, of or pertaining to a bath (post-Aug. for the foll.): argentum, silver utensils used in baths, Dig. 34, 2, 33: jocus, Spart. Had. 17: vestis"},"balsa":{"lemma":"Balsa","pos":"","gen":"","def":", a town in Lusitania, now Javira, Plin. 4, 21, 35, § 117"},"baltia":{"lemma":"Baltia","pos":"","gen":"","def":"Balcia."},"baluca":{"lemma":"baluca","pos":"","gen":"","def":"ball. Bambălĭo, ōnis, m. cf. βαμβάλειν, to stammer, βομβόλη; Engl. bumblebee, = Βαμβαλίων, Dio Cass. 45, 47; 46, 7 and 28: M. Fulvius, the father-in-law of Antonius, Cic. Phil. 3, 6, 16"},"baphyrus":{"lemma":"Baphyrus","pos":"","gen":"","def":", a river in Thessaly, near Mount Olympus, Liv. 44, 6, 15."},"baptae":{"lemma":"Baptae","pos":"","gen":"","def":", = Βάπται [perh. so called from dyeing their hair"},"baptes":{"lemma":"baptes","pos":"","gen":"","def":", an unknown precious stone, perh. colored amber, Plin. 37, 10, 55, § 149."},"baptisma":{"lemma":"baptisma","pos":"","gen":"","def":", = βάπτισμα. A dipping in, dipping under, washing, ablution, Prud. Psych. 103; Apoth. 697; Vulg. Marc. 7, 4"},"baptista":{"lemma":"baptista","pos":"","gen":"","def":", = βαπτιστής, a baptizer, baptist, κατ̓ ἐξοχήν, of John, the forerunner of Christ, Sedul. Pasch. 2, 143"},"baragaza":{"lemma":"Baragaza","pos":"","gen":"","def":", a town of Ethiopia, Plin. 6, 29, 34, § 175."},"baraomutae":{"lemma":"Baraomutae","pos":"","gen":"","def":", a people of India, Plin. 6, 20, 23, § 77. bărāthrum, i, n., = βάραθρον, an abyss, chasm, a deep pit, the Lower World (mostly poet"},"barba":{"lemma":"barba","pos":"","gen":"-leaved","def":"cf. O. H. Germ. part; Germ. Bart; Engl. beard. Lit., the beard, of men: alba, Plaut. Bacch. 5, 1, 15: hirquina, id. Ps. 4, 2, 12: mollis, Lucr. 5, 673: promissa, long, Nep. Dat. 3, 1; Liv. 5, 41, 9"},"barbus":{"lemma":"barbus","pos":"","gen":"","def":"barba, a barbel, a river barbel: Cyprinus barbus, Linn., Aus. Mosell. 94 and 134 (cf. barbatulus mullus, Cic. Par. 5, 2, 38, and barbati mulli, id. Att. 2, 1, 7)."},"barca":{"lemma":"barca","pos":"","gen":"-class","def":", a small boat, a bark, barge (post-class.): barca est, quae cuncta navis commercia ad litus portat. Hanc navis in pelago propter nimias undas suo suscipit gremio, etc., Isid. Orig. 19, 1, 19"},"bardaei":{"lemma":"Bardaei","pos":"adj.","gen":"","def":", an Illyrian people (in Cic. Fam. 5, 9, 2, Vardaei)—Hence, Bardăĭcus, a, um, adj., Bardoean calceus, a kind of soldier's boot, poet. for the soldiers themselves, Juv. 16, 13 (cf. Caligula)' cuculli"},"bargullum":{"lemma":"Bargullum","pos":"","gen":"","def":", a town of Epirus, Liv. 29, 12, 13."},"bargus":{"lemma":"Bargus","pos":"","gen":"","def":", a river of Thrace, tributary to the Ebrus, Plin. 4, 11, 18, § 50. Bargūsĭi, ōrum, m., = Βαργούσιοι, Polyb., a people in Hispania Tarraconensis, near the Pyrenees, Liv. 21, 19, 7"},"bargylus":{"lemma":"Bargylus","pos":"","gen":"","def":", a mountain of Phoenicia, Plin. 5, 20, 17, § 78. Barīnē, ēs, f., name of a freedwoman, Hor. C 2, 8, 2. barīnulae = aquileges, Serv. Verg. G. 1, 109 barippē, ēs, v. baroptenus. bāris, ĭdos"},"barrus":{"lemma":"Barrus","pos":"","gen":"","def":", a cognomen of T, Betucius, Cic. Brut. 46, 169 bărycĕphălus, a, um, = βαρνκέφαλος, or bărycus, a, um, adj , in archit., top-heavy, with low walls and broad roofs, Vitr. 3, 3, 5. bărypīcron, ī, n."},"basaltes":{"lemma":"basaltes","pos":"","gen":"","def":"African, a dark and very hard species of marble in Ethiopia, Isid. Orig. 16, 5, 6"},"bascauda":{"lemma":"bascauda","pos":"","gen":"-holder","def":"British; whence Engl. basket; cf. Wall. basget, basgawd; and Gr βαστάζω, to carry, an article of table furniture, prob. a delicately woven mat, or dish-holder of basket-work, Juv. 12, 46"},"bassus":{"lemma":"Bassus","pos":"","gen":"","def":", a family cognomen; e. g. A poet, a friend of Martial, Mart. 3, 76, 1 al.— Q. Caecilius Bassus, quoestor A. U. C. 695, Cic. Phil. 11, 13, 32; id. Att. 2, 9, 1; 14, 9, 3; id. Fam. 11, 1, 4"},"basterna":{"lemma":"basterna","pos":"","gen":"","def":", a sedan chair or litter, enclosed on all sides, and carried by mules, Pall. 7, 2, 3; Lampr. Elag. 21; Amm. 14, 6, 16; Hier. Ep. 22 ad Eustoch. n. 16"},"bateni":{"lemma":"Bateni","pos":"","gen":"","def":", a people of Asia, on the Oxus, Plin. 6, 16, 18, § 48. bătĕnim, v. 1. bat."},"batha":{"lemma":"Batha","pos":"","gen":"","def":", a town in Ethiopia, Plin. 6, 29, 35, § 179. Băthyllus, i, m., = Βάθυλλος. A Samian boy, beloved by Anacreon, Hor. Epod. 14, 9"},"bathymi":{"lemma":"Bathymi","pos":"","gen":"","def":", a people of Arabia, Plin. 6, 28, 32, § 149."},"bathynias":{"lemma":"Bathynias","pos":"","gen":"","def":", a small river of Thrace, near Byzantium, Plin. 4, 11, 18, § 46. bătĭa, ae, f., an unknown kind of fish, Plin. 32, 7, 25, § 77"},"bato":{"lemma":"Bato","pos":"","gen":"","def":", a leader of insurrection in Dalmatia, Ov. P. 2, 1, 46; cf.: maxima duobus Batonibus ducibus auctoritas erat, Vell. 2, 110, 4"},"battalia":{"lemma":"battalia","pos":"","gen":"","def":"‡ battualia."},"battara":{"lemma":"Battara","pos":"","gen":"","def":", a Roman whose death is mentioned by Cicero A. U. C. 700, Cic. Fam. 7, 9, 2."},"battiades":{"lemma":"Battiades","pos":"","gen":"","def":"Battus, I. b."},"battis":{"lemma":"Battis","pos":"","gen":"","def":", = Βαττίς, the sweetheart of the poet Philetas of Cos, Ov. Tr. 1, 6, 2; id. P. 3, 1, 58 (Merkel, Bittis)."},"batton":{"lemma":"Batton","pos":"","gen":"","def":", a Greek sculptor, Plin. 34, 8, 19, § 73. battŭālĭa or battālia, ium, n. battuo, the fighting and fencing exercises of soldiers and gladiators: inde etiam battuatores τοὺς βασανιστὰς dici puto"},"battus":{"lemma":"Battus","pos":"","gen":"","def":", = Βάττος. A name given to Aristotle of Thera, the founder of Cyrene, Sil. 8, 57; 17, 591; Just. 13, 7, 1.— Hence, Battĭădes, ae, m., an inhabitant of Cyrene, Sil. 2, 61; 3, 252; 17, 592"},"baubor":{"lemma":"baubor","pos":"v.","gen":"","def":"dep. cf. Gr. βαιΐζω; of dogs, to bark gently or moderately (cf. latrare, to bark angrily): et quom desertei baubantur in aedibus. Lucr. 5, 1071"},"baucis":{"lemma":"Baucis","pos":"","gen":"","def":", = Βαῦκις. The wife of Philemon, in Phrygia. She, with her husband, entertained, in a very hospitable manner, Jupiter and Mercury, who came to them in the form of men"},"bauli":{"lemma":"Bauli","pos":"","gen":"","def":", = Βαῦλοι [acc. to the fable, from βοῦς and αὐλή, since here Hercules shut up the cattle taken from Geryon; v. Serv. ad Verg. A. 6, 107; 7, 662"},"bauma":{"lemma":"Bauma","pos":"","gen":"","def":", a town in Ethiopia, Plin 6, 29, 35, § 179. Băvĭus, ii, m., a stupid poet, an enemy of Virgil and Horace: qui Bavium non odit, amet tua carmina, Maevi, Verg. E. 3, 90 (pro poenā ei contingat"},"bebra":{"lemma":"bebra","pos":"","gen":"","def":", a weapon of barbarous nations, acc. to Veg. Mil. 1, 20. Bebriacensis and Bebriacum, v. Bedr-. bebrīnus, a, um, adj. beber = fiber, a beaver, of or pertaining to a beaver: pelles, Schol. Juv. 12"},"beccus":{"lemma":"beccus","pos":"","gen":"","def":"Gallic; cf. Fr. bec; Engl. beak, a beak, bill, esp. of a cock"},"belbus":{"lemma":"belbus","pos":"","gen":"","def":", = hyaena, Capitol. Gord. III. 33, 1. Belena = Helena, v. Quint. 1, 4, 15."},"belenus":{"lemma":"Belenus","pos":"adv.","gen":"","def":", a deity worshipped in Noricum and Aquileia, Tert. Apol. 24; id. adv. Nat. 2, 8; Capitol. Max. 22, 2; Inscr. Orell. 823; 1967."},"belgae":{"lemma":"Belgae","pos":"adj.","gen":"-ga","def":", = Βέλγαι [Balge, in Lower Germany, a low, swampy region], the Belgians, a warlike people, of German and Celtic origin, in the north of Gaul, Caes. B. G. 1, 1; 2, 4; Mel. 3, 2, 4; Tac. A. 1, 43"},"belias":{"lemma":"Belias","pos":"","gen":"","def":"Belial and Belus."},"belides":{"lemma":"Belides","pos":"","gen":"","def":"Belus. belĭon, ii, n., a plant, the same as po lion, q. v., App. Herb. 58. bellārĭa, ōrum, n., that which is used as a dessert, fruit, nuts, confectionery, sweet wine, etc."},"bellax":{"lemma":"bellax","pos":"adj.","gen":"","def":"bello, warlike, martial: gens, Luc. 4, 406; cf. Prisc. p. 1263 P. bellē, adv., v. bellus fin. Bellĕrŏphōn, ontis (Bellĕrŏ-phontes, ae, Aus. Ep. 25 fin.; Serv. ad Verg. A. 5, 118"},"bellis":{"lemma":"bellis","pos":"","gen":"-eye","def":", the white daisy, ox-eye: Bellis perennis, Linn.; Plin. 26, 5, 13, § 26"},"bello":{"lemma":"bello","pos":"v.","gen":"","def":"n. bellum. Prop., to wage or carry on war, to war, to fight in war (class.; cf.: milito, proelior). Absol.: fuit proprium populi Romani longe a domo bellare, Cic. Imp. Pomp. 12, 32; 13, 36"},"bellua":{"lemma":"bellua","pos":"","gen":"-ilis","def":"belua, etc. bellŭlē, adv., v. bellulus fin. bellŭlus, a, um, adj. dim. , pretty, fine, lovely, beautiful (ante- and post-class.); edepol haec quidem bellula est, Plaut. Mil. 4, 1, 43"},"bellus":{"lemma":"bellus","pos":"adj.","gen":"-class","def":"as if for benulus, from benus = bonus, Prisc. p. 556 P.. In gen. Of persons, pretty, handsome, charming, fine, lovely, neat, pleasant, agreeable, etc. (of persons, things, actions, etc."},"belluus":{"lemma":"belluus","pos":"","gen":"","def":"beluus. bēlo, v. balo init. bĕlŏăcŏs or bĕlŏtŏcŏs, a plant, also called dictamnus, App. Herb. 62. bĕlŏnē, ēs, f., = βελόνη, a sea-fish, also called acus, hornpike, garfish, Plin. 9, 51, 76"},"beni":{"lemma":"Beni","pos":"","gen":"","def":", a Thracian people on the Hebrus, Plin. 4, 11, 18, § 40. bĕnignē, adv., v. benignus. bĕnignĭtas, ātis, f. benignus, the quality of one benignus, an affable"},"benna":{"lemma":"benna","pos":"","gen":"-work","def":"(Gallic), a kind of carriage; those who sat in the same benna were called combennones, Fest. p. 27"},"berbex":{"lemma":"berbex","pos":"","gen":"","def":"vervex. Bercorcātes, ium, m., a people of Gallia Aquitanica, Plin. 4, 19, 33, § 108. Bĕrĕcyntus, i, m., = Βερέκυντος, a mountain on the banks of the river Sangarius, in Phrygia, sacred to Cybele"},"bergae":{"lemma":"Bergae","pos":"","gen":"","def":", a people of Scythia, Mel. 3, 5, 1; 3, 6, 9."},"bergi":{"lemma":"Bergi","pos":"","gen":"","def":", an island in the North Sea, Plin. 4, 16, 30, § 104. Bergĭmus, i, m., a deity of the Galli Cenomani, in Upper Italy, Inscr. Orell. 1971 sq."},"berresa":{"lemma":"Berresa","pos":"","gen":"","def":", a town in Ethiopia, Plin. 6, 29, 50, § 180. Berrĭcē, ēs, f., a large island north of Europe, Plin. 4, 16, 30, § 104. berŭla, ae, f., an herb, called also cardamine"},"bes":{"lemma":"bes","pos":"v.","gen":"-is","def":"(nom. bessis, Paul. ex Fest. p. 33 Müll.; Prisc. Ponder. p. 1348 P.) . Two thirds of a unit (the as)"},"besaro":{"lemma":"Besaro","pos":"","gen":"","def":", a town in Spain, Plin. 3, 1, 3, § 15."},"besbicus":{"lemma":"Besbicus","pos":"","gen":"","def":", a small island in the Propontis, Plin. 2, 88, 90, § 204"},"bessi":{"lemma":"Bessi","pos":"adj.","gen":"-eastern","def":", = Βέσσοι, Strab.; Βησσοί, Herod., a savage and marauding people in the north-eastern part of Thrace, about the Hoemus mountains, and in the vicinity of the Hebrus, Veg. Mil. 2, 11; 4, 24"},"bessus":{"lemma":"Bessus","pos":"","gen":"","def":"A Bessian; v. Bessi. — Βῆσσος, a viceroy of Bactria, the murderer of Darius Codomannus, Curt. 5, 8, 4; 5, 9, 2"},"betriacum":{"lemma":"Betriacum","pos":"","gen":"","def":"Bedriacum. Betucĭus, ii, m., a Roman proper name, e. g. T. Betucius Bassus, an orator of Asculum, Cic. Brut. 46. 169. betŭla (also betulla), ae, f., the birch, Plin. 16, 18, 30, § 75"},"bibaga":{"lemma":"Bibaga","pos":"","gen":"","def":", an island near Gedrosia, Plin. 6, 21, 23, § 80."},"bibali":{"lemma":"Bibali","pos":"","gen":"","def":", a people of Hispania Tarraconensis, Plin. 3, 3, 4, § 28. bĭbax, ācis, adj. bibo, given to drink, Nigid. ap. Gell. 3, 12. bĭber, v. bibo init. Bĭbĕrĭus Caldius Mero"},"biblus":{"lemma":"biblus","pos":"","gen":"","def":", = βίβλος?̔βύβλος), the papyrus, a sort of rush that grew largely in Egypt, from the inner bark of which paper was made (poet. for the more usual papyrus): flumineae, Luc. 3, 222"},"bidis":{"lemma":"Bidis","pos":"adj.","gen":"-west","def":", a small town in Sicily, north-west of Syracuse, Cic. Verr. 2, 2, 22, § 53.—Hence, Derivv. Bidinus, a, um, adj., of or pertaining to Bidis: palaestritae, Cic. Verr. 2, 2, 22, § 54.— Bi-dini, ōrum"},"bigerra":{"lemma":"Bigerra","pos":"","gen":"","def":", a town in Hispania Tarraconensis, in the province of the Bastitani, Liv. 24, 41, 11. Bĭgerrĭōnes, um (Bĭgerri, ōrum, Paul. Nol. Ep. ad Aus. 10, 246"},"bilbo":{"lemma":"bilbo","pos":"v.","gen":"","def":"n. onomatop., to make a noise like that of a liquid agitated in a vessel: bilbit factum est a similitudine sonitus, qui fit in vase. Naevius Bilbit amphora inquit"},"birrus":{"lemma":"birrus","pos":"","gen":"","def":"(birrum, i, n., Aug. Serm. Divers. 49), = πυρρός (of yellow color), a cloak to keep off rain (made of silk or wool), Edict. Diocl. p. 20; cf. Salmas. Vop. Carin. 20; Burm. Anth. Lat. 2, p. 408"},"bisambritae":{"lemma":"Bisambritae","pos":"","gen":"","def":", a people on the Indus, Plin. 6, 20, 23, § 78. Bisanthē, ēs, f., = Βισάνθη, a town in Thrace, on the Propontis, a colony of the Samians, afterwards called Π̔αιδεστός, now Rodosto, Mel. 2, 2, 6"},"bispellio":{"lemma":"bispellio","pos":"","gen":"-pellis","def":"bis-pellis, only trop., a man with two skins, a cunning man, Dig. 47, 3, 72; also written bisbel-lio, Dig. 21, 2, 31. bissēnus and bissēni, v. bis fin."},"bissextus":{"lemma":"bissextus","pos":"","gen":"","def":"bisextus. Bistŏnes, um, m., = Βίστονες, the Bistones, a Thracian people south of Mount Rhodope, not far from Abdera, Plin. 4, 11, 18, § 42.—In the poets, In gen., for the Thracians, Luc. 7, 569"},"bithiae":{"lemma":"Bithiae","pos":"","gen":"","def":", the name of certain women in Scythia, said to have two pupils in each eye, Plin. 7, 2, 2, § 17. Bīthȳnĭa, ae, f., = Βιθυνία, a very fruitful province in Asia Minor"},"bittis":{"lemma":"Bittis","pos":"","gen":"","def":", = Βιττίς, a woman beloved by the poet Philetas of Cos, Ov. Tr. 1, 6, 2; id. P. 3, 1, 58 Merkel (al. Battis). Bituītus, i, m., a king of the Arverni, Liv. Epit. 61; Flor. 3, 2, 5; Eutr. 4, 22"},"bitumen":{"lemma":"bitumen","pos":"n. n.","gen":"-inis","def":"bitumen, mineral pitch, asphalt, naphtha"},"bizya":{"lemma":"Bizya","pos":"","gen":"","def":", a town in Thrace, once the royal residence, Plin. 4, 11, 18, § 47. blachnon (blech-), i, n., = βλῆχνον, a kind of fern (filix), Plin. 27, 9, 55, § 78. blactĕro, āre, v. n. cf.: balo, blatio"},"blaesus":{"lemma":"blaesus","pos":"adj.","gen":"","def":", = βλαισός, lisping, stammering, hesitating in utterance, speaking indistinctly (most freq. in poetry): blaesus, cui litterae sibilantes (s, z) molestae sunt vitioseque pronunciantur"},"blandities":{"lemma":"blandities","pos":"","gen":"","def":"blanditia. blandītim, adv. blanditus, from blandior, in a flattering, caressing manner, Lucr. 2, 173. blandītor, ōris, m. blandior, a flatterer (late Lat.), Itin. Alex. M. 39 (90). blandītus, a, um"},"blandus":{"lemma":"blandus","pos":"adj.","gen":"","def":"for mlandus; akin to μείλιχος, mollis, mulier; Goth. milds"},"blatta":{"lemma":"blatta","pos":"","gen":"","def":", an insect that shuns the light; of several kinds, the cockroach, chafer, moth, etc., Plin. 29, 6, 39, § 139; 11, 28, 34, § 99: lucifuga, Verg. G. 4, 243 (per noctem vagans, Serv.); cf. Col. 9, 7, 5"},"blattea":{"lemma":"blattea","pos":"","gen":"","def":"2. blatta, II. blattĕus, a, um, adj. 2. blatta, II., purple-colored, purple: tunicae, Vop. Aur. 46, 4: pallium, id. 45, 5: funes, Eutr. 7, 9. blattĭārĭus, ii, m. 2. blatta, II., a dyer in purple"},"blennus":{"lemma":"blennus","pos":"","gen":"","def":", = βλεννός, a blockhead, dolt, simpleton: stulti, stolidi, fatui, fungi, bardi, blenni, buccones, Plaut. Bacch. 5, 1, 2"},"boaulia":{"lemma":"Boaulia","pos":"","gen":"","def":"Bauli. bobsĕqua, ae, v. bubsequa."},"bocas":{"lemma":"bocas","pos":"","gen":"","def":"box. Bocchar, ăris (in MSS. also Boc-chor, ŏris), m., a king of Mauritania at the time of the second Punic war, Liv. 29, 30, 1"},"bocchus":{"lemma":"Bocchus","pos":"","gen":"-in","def":", a king of Mauritania, father-in-law of Jugurtha, whom he gave up bound to Sulla, Sall. J. 19, 7; 80; 81; 83; 97; 101 sqq.; Vell. 2, 12, 1; Val. Max. 8, 14, 4; Flor. 3, 1, 15; Mel. 1, 5, 5"},"bodincus":{"lemma":"Bodincus","pos":"","gen":"","def":"Ligurian, = bottomless, the Ligurian name of the river Po, Plin. 3, 16, 20, § 122. Bŏdotrĭa, ae, f., = Βοδέρια, Ptol., a bay in Scotland on which the present Edinburgh is situated, now Firth of Forth"},"bohemi":{"lemma":"Bohemi","pos":"","gen":"","def":"Boil."},"boia":{"lemma":"Boia","pos":"","gen":"","def":"Boii. bŏiae, ārum, f. bos, a collar for the neck, κλοιός (orig. of leather; hence the name; but later of wood or iron), Fest. p. 29"},"bombax":{"lemma":"bombax","pos":"interj.","gen":"","def":", = βομβάξ (v. Eustath. Od. p. 1718, a), an exclamation of real or affected surprise, indeed! strange! Ca. Fur. Ba. Babae. Ps. Fugitive. Ba. Bombax, Plaut. Ps. 1, 3, 131 Lambin. bombĭnātor, ōris, m."},"bombus":{"lemma":"bombus","pos":"","gen":"","def":", = βόμβος, a hollow, deep sound, a booming, humming, buzzing: Ennius sonum pedum bombum pedum dixit, Fortun. Dial. (v. Enn. p. 183 fin. Vahl.); of bees; of a horn"},"bombyx":{"lemma":"bombyx","pos":"","gen":"-worm","def":"(f., Plin. 11, 23, 27; Tert. Pall. 3), = βόμβυξ. The silk-worm, Plin. 11, 22, 25, § 75 sqq.; Mart. 8, 33, 16; Serv. ad Verg. G. 2, 121; Isid. Orig. 12, 5, 8"},"bonna":{"lemma":"Bonna","pos":"adj.","gen":"","def":", a city on the Rhine, now Bonn, Tac. H. 4, 19; 4, 25; 70, 77; 5, 22; Flor. 4, 12, 26.—Hence, Bonnensis, e, adj., of Bonna: castra, Tac. H. 4, 20"},"bora":{"lemma":"Bora","pos":"","gen":"","def":", a mountain in Macedonia, now Nitje, Liv. 45, 19, 8 sq. Borcāni, ōrum, m., a people of Apulia, Plin. 3, 11, 16, § 105. bŏrĕālis, e, v. boreas, II. B. bŏrĕas (borras, Prud. Psych. 847"},"boscis":{"lemma":"boscis","pos":"","gen":"","def":", = βοσκάς, a kind of duck, Col. 8, 15, 1 (perh., acc. to the Greek, more correctly boscăs, ădis"},"bostar":{"lemma":"Bostar","pos":"","gen":"","def":", a Carthaginian proper name, Cic. Aem. Scaur. 2, 1 sqq.; 4, 8; Liv. 22, 22, 9 sqq.; 23, 34, 1; Sil. 3, 647."},"bostra":{"lemma":"Bostra","pos":"adj.","gen":"","def":", = Βόστρα, the capital of the Roman province of Arabia from the time of Trajan, now Bozra, Amm. 14, 8, 13. —Called Bosra, Vulg. Isa. 34, 6"},"bostrychus":{"lemma":"bostrychus","pos":"adj.","gen":"","def":", = βόστρυχος, curled, in ringlets: crines, Firm. Math. 4, 12. ‡† bŏtănĭcum herbarium dicitur, quod ibi herbae notentur, Isid. Orig. 4, 10, 4. bŏtănismus, i, m., = βοτανισμός, a weeding"},"boterdum":{"lemma":"Boterdum","pos":"","gen":"","def":", a town in Hispania Tarraconensis, Mart. 1, 49, 7"},"botrus":{"lemma":"botrus","pos":"","gen":"","def":"botrys, I. bōtryītis, ĭdis, f., = βοτρυῗτις and βοτρυώδης (cluster-shaped), a kind of calamine, Cels. 6, 6, n. 6; Plin. 34, 10, 22, § 101"},"boua":{"lemma":"bova","pos":"","gen":"","def":"boa."},"brabyla":{"lemma":"brabyla","pos":"","gen":"","def":", a plant, otherwise unknown, Plin. 27, 8, 32, § 55. brācae (not braccae), ārum (once in sing. brāca, ae, Ov. Tr. 5, 10, 34; and as access. form brāces, Edict. Diocl. p. 20), f. Germ.; Swed. brōk"},"bragae":{"lemma":"Bragae","pos":"","gen":"","def":", an island on the coast of Arabia, Plin. 6, 28, 32, § 150."},"brana":{"lemma":"Brana","pos":"","gen":"","def":", a town of Hispania Baetica, Plin. 3, 1, 3, § 15. brancē, v. brace. branchĭae, ārum (sing. branchia, ae, Aus. Mos. 266; Vulg. Tob. 6, 4), f., = τὰ βράγχια, the gills of fish, Col. 8, 17, 12"},"branchus":{"lemma":"Branchus","pos":"","gen":"","def":", = Βράγχος, a son of Apollo; or, according to others, of Smicrus of Delphi, inspired by Apollo with prophecy, v. Branchidae, Stat. Th. 3, 479; 8, 198 Schol."},"brancosi":{"lemma":"Brancosi","pos":"","gen":"","def":", a people of India, Plin. 6, 20, 23, § 76. brasmătĭae (access. form bras-tae, App. de Mundo, p. 65, 25), ārum, f., = οἱ βρασματίαι (sc. ἄνεμοι) or βράσται, a shaking of the earth"},"brastae":{"lemma":"brastae","pos":"","gen":"","def":"brasmatiae."},"brathy":{"lemma":"brathy","pos":"","gen":"","def":", = βράθυ, the savintree (pure Lat. herba Sabina), Plin. 24, 11, 61, § 102; App. Herb. 85; Scrib. Comp. 154."},"brattea":{"lemma":"brattea","pos":"","gen":"","def":"bractea."},"brattia":{"lemma":"Brattia","pos":"","gen":"","def":", an island of Dalmatia, Plin. 3, 26, 30, § 152."},"bratus":{"lemma":"bratus","pos":"","gen":"","def":", a tree similar to the cypress, Plin. 12, 17, 39, § 78. Bratuspantĭum, ii, n., a town in Gallia Belgica, in the province of the Bellovaci, afterwards called Caesaromagus, Itin. Anton., now Breteuil"},"brauron":{"lemma":"Brauron","pos":"","gen":"","def":"(Braurōnia, ae, f., Mel. 2, 3, 6), = Βραυρών, a village in Attica, not far from Marathon, now Vraona, Plin. 4, 7, 11, § 24; Stat. Th. 12, 615."},"breganticus":{"lemma":"Breganticus","pos":"","gen":"","def":"Briganticus. bregma (brechma) , a defect of pepper, = abortus, Plin. 12, 7, 14, § 27. Bregmentēni, ōrum, m., a people of the Troad, Plin. 5, 30, 33, § 126."},"brenda":{"lemma":"Brenda","pos":"","gen":"","def":"Brundisium."},"brenni":{"lemma":"Brenni","pos":"","gen":"","def":"Breuni."},"brennus":{"lemma":"Brennus","pos":"adj.","gen":"","def":", = Βρέννος, a leader of the Gauls who defeated the Romans at the river Allia, Liv. 5, 38, 3"},"breuci":{"lemma":"Breuci","pos":"","gen":"","def":", = Βρεῦκοι, a people in Pannonia, on the Save, Plin. 3, 25, 28, § 147; Suet. Tib. 9; Inscr. Orell. 126"},"brittii":{"lemma":"Brittii","pos":"","gen":"","def":"Bruttii. Brixellum (Brixillum, Plin. 3, 15, 20, § 115; Inscr. Murat. 239), i, n., a town in Gallia Cisalpina, on the Po, between Parma and Mantua, now Brescello, Plin. 7, 49, 50, § 163; Tac. H. 2, 33"},"brixentes":{"lemma":"Brixentes","pos":"","gen":"","def":", = Βριξάνται, a people in Rhoetia, in the modern Brixen, Plin. 3, 20, 24, § 137."},"brixia":{"lemma":"Brixia","pos":"adj.","gen":"-class","def":", = Βριξία, a town in Gallia Cisalpina, now Brescia, Liv. 5, 35, 1; 32, 30, 6; Plin. 3, 19, 23, § 132; Just. 20, 5; Cat. 67, 32 (id. 33 and 34 suspicious"},"brixillum":{"lemma":"Brixillum","pos":"","gen":"","def":"Brixellum. brocchĭtas, ātis, f. brochus, a projection of the teeth in animals: dentium, Plin. 11, 37, 64, § 169. brŏchŏn, i, n., the gum flowing from the bdellium, Plin. 12, 9, 19, § 35. brŏchus"},"broncus":{"lemma":"broncus","pos":"","gen":"","def":"brochus. Brontē, ēs, f., = Βροντή. Thunder (personified), Plin. 35, 10, 36, § 96.— As nom. propr., the name of one of the horses of the Sun, Hyg. Fab. 183. brontĕa, ae, f. βροντή, the thunderstone"},"brontia":{"lemma":"brontia","pos":"","gen":"","def":"brontea. ‡† Bronton, ontis, adj., = Βροντῶν (the thunderer), an epithet of Jupiter, Inscr. Grut. 34, 5; 17, 12"},"brunda":{"lemma":"Brunda","pos":"","gen":"","def":"Brundisium. Brundĭsĭum (in many MSS., but less correctly Brundŭsĭum; cf. Suet. Caes. 34 Torrent.; Sil. 8, 576 Heins. and Drak.; Flor. 1, 20 Duker.; Luc. 2, 609 Cort."},"bruscum":{"lemma":"bruscum","pos":"","gen":"-tree","def":", an excrescence on the maple-tree, Plin. 16, 16, 27, § 68. brūtesco, ĕre, v. inch. , to become brutish, rough, unreasonable (postclass.), Sid. Ep. 4, 1 fin.; Lact. 7, 12, 24"},"brya":{"lemma":"brya","pos":"","gen":"","def":", = βρυά, a shrub, also called myrice and tamarice, Plin. 13, 21, 37, § 116; 24, 9, 42, § 69. Bryănĭon, v. Bruanion."},"bryaxis":{"lemma":"Bryaxis","pos":"","gen":"","def":", = Βρύαξις, a Grecian sculptor, Vitr. 7, praef. § 13; Col. 1, praef. 31; Plin. 34, 7, 18, § 42; 34, 8, 19, § 73 al."},"bryazon":{"lemma":"Bryazon","pos":"","gen":"","def":", a river in Bithynia, Plin. 5, 32, 43, § 148."},"bryazus":{"lemma":"Bryazus","pos":"","gen":"","def":", the name of a Bithynian god and of his temple, Plin. 31, 2, 18, § 23."},"bryges":{"lemma":"Bryges","pos":"","gen":"","def":", a people of Macedonia, emigrants from Asia Minor, Plin. 5, 32, 41, § 145."},"bryllion":{"lemma":"Bryllion","pos":"","gen":"","def":", a town in Mysia, on the Propontis, Plin. 5, 32, 40, § 144."},"bryon":{"lemma":"bryon","pos":"","gen":"","def":", = βρύον. Moss"},"bu":{"lemma":"bu","pos":"","gen":"","def":"bua."},"bua":{"lemma":"bua","pos":"","gen":"","def":"bu, Paul. ex Fest. s. v. im butum, p. 109 Müll., the natural sound made by infants in asking for their drink, as pappa for their food, Varr. ap. Non. p. 81, 1 sq."},"bubeium":{"lemma":"Bubeium","pos":"","gen":"","def":", a town in Africa, Plin. 5, 5, 5, § 37. Bubetāni, ōrum, m., a people of Latium, Plin. 3, 5, 9, § 69. būbīle (access. form bŏvīle, unus. acc. to Varr. L. L. 8, § 54 Müll."},"bubleum":{"lemma":"bubleum","pos":"","gen":"","def":", a kind of wine, Paul. ex Fest. 32 Müll. [Βύβλινος οῖνος, Hesiod. Op. 587 Göttl.] būbo, ōnis, m. (f. only once Verg. A. 4, 462; cf. Serv. ad loc."},"buccella":{"lemma":"buccella","pos":"","gen":"","def":"dim. id., a small mouthful, morsel, Mart. 6, 75, 3; Apic. 7, 6; Vulg. Ruth, 2, 14: panis, Vulg. Gen. 18, 5.— Small bread divided among the poor, Cod. Th. 14, 17, 5"},"bucco":{"lemma":"bucco","pos":"","gen":"","def":"amplif. [bucca, one who has distended cheeks], a babbler, blockhead, fool (very rare): bucco = garrulus, quod ceteros oris loquacitate, non sensu exsuperat, Isid. Orig. 10, 30: stulti, stolidi, fatui"},"bucinna":{"lemma":"Bucinna","pos":"","gen":"","def":", a small island near Sicily, Plin. 3, 8, 14, § 92. būcĭno (bucc-), āvi, ātum, 1, v. n. bucina, to blow the bucina, to sound or give a signal with the trumpet (mostly impers."},"buda":{"lemma":"buda","pos":"","gen":"","def":", colloq., = ulva, Anthol. Lat. 5, 189, 2; Aug. Ep. 88, 6; Don. ad Verg. A. 2, 135."},"budalia":{"lemma":"Budalia","pos":"","gen":"","def":", a town of Lower Pannonia, Eutr. 9, 4. Būdīni, ōrum, m., a people of Sarmatia, Mel. 1, 9, 19; Plin. 4, 12, 26, § 88. būfălus, i, m., = bubalus, q. v. būfo, ōnis, m. root bu-"},"bulbus":{"lemma":"Bulbus","pos":"","gen":"","def":", a Roman name, Cic. Verr. 2, 2, 32, § 79.—With a play on 1. bulbus, Cic. Clu. 26, 72. būlē, ēs, f., = βουλή, the (Greek) council, the senate, Plin. Ep. 10, 116 (117), 1; 10, 81 (85), 1"},"bulga":{"lemma":"bulga","pos":"","gen":"","def":"Gallic"},"bulla":{"lemma":"bulla","pos":"","gen":"-studs","def":"root vhal-; Gr. φαλ-; cf. φαλλός, φύλλον, any object swelling up, and thus becoming round"},"bullesco":{"lemma":"bullesco","pos":"","gen":"","def":"inch. n. , to bubble, form bubbles, Ampel. 8. Bullĭdenses, -ienses, -īni, and -iōnes, v. Bylli-. bullĭo, īre, v. bullo. bullītus, ūs, m. bullio, the bubbling, gushing up of water: aquae, Vitr. 8, 3."},"bullo":{"lemma":"bullo","pos":"v.","gen":"-cooked","def":"n. bulla, to be in bubbling motion, to be in a state of ebullition, to bubble. Form bullo, āre: ubi bullabit vinum, ignem subducito, Cato, R. R. 105; Cels. 2, 7; 7, 4, 2; Calp. Ecl. 1, 11"},"burgus":{"lemma":"burgus","pos":"","gen":"-burg","def":"cf. πύργος; Germ. Burg, Berg"},"burra":{"lemma":"burra","pos":"","gen":"-class","def":"burrus. A small cow with a red mouth or muzzle, acc. to Fest. s. v.— A shaggy garment, Anthol. Lat. 5, 133, 5.—Hence, plur.: burrae, ārum, f., trifles, nonsense (post-class.): burras, quisquilias"},"bustar":{"lemma":"bustar","pos":"","gen":"","def":"bustum, a place where dead bodies were burned, Charis. p. 25 P. bustĭcētum, i, n. id., post-class. for bustum, a place where dead bodies were burned, Arn. 1, p. 24"},"bustum":{"lemma":"bustum","pos":"","gen":"-pyre","def":"buro = uro, whence also comburo; cf. burrus, red, orig. the place where the bodies of the dead were burned and buried"},"buttuti":{"lemma":"buttuti","pos":"interj.","gen":"","def":", Plaut. ap. Charis. p. 216 P. bŭtŭbatta = nugatoria, trifles, worthless things, Naev. ap. Paul. ex Fest. p. 36 Müll. (Com. Rel. p. 25 Rib.); Charis. 2, 16, p. 216 P.; cf. Comment. p. 351 sq."},"butuntum":{"lemma":"Butuntum","pos":"","gen":"","def":", a town of Calabria, now Bitonte; hence, Butuntinenses, ĭum, m., the inhabitants of Butuntum, Plin. 3, 11, 16, § 105; Front. Col. p. 111. būtȳrum (ȳ, Sid. Carm. 12, 7"},"buxans":{"lemma":"buxans","pos":"adj.","gen":"","def":"buxus, of the color of boxwood: pallor, App. M. 8, p. 211, 5; p. 180 Bip."},"buxentum":{"lemma":"Buxentum","pos":"adj.","gen":"-t","def":", = πυξοῦς, a town in Lucania, of Greek origin, colonized by the Romans after the second Punic war, Vell. 1, 15, 3; Liv. 34, 45, 2; now Policastro, Mel. 2, 4, 9"},"buxum":{"lemma":"buxum","pos":"","gen":"","def":"id., the wood of the boxtree (cf. Neue, Formenl. 1, 509"},"buxus":{"lemma":"buxus","pos":"","gen":"-tree","def":", = πύξος (cf. Prisc. p. 549, and the letter B). Lit., the pale, evergreen box-tree, Enn. ap. Phylarg. l. l.: buxus densa foliis, Ov. A. A. 3, 691: crispata, Claud. Rapt. Pros. 2, 110: horrida"},"buzae":{"lemma":"Buzae","pos":"","gen":"","def":", a people of India, Plin. 6, 20, 23, § 76. Buzēri, ōrum, m., a people of Pontus, Mel. 1, 19, 11"},"byblis":{"lemma":"Byblis","pos":"","gen":"","def":"(voc. Bybli, Ov. M. 9, 580; 9, 651; acc. Byblida, id. ib. 9, 453"},"byrsa":{"lemma":"Byrsa","pos":"adj.","gen":"","def":", = Βύρσα, the citadel of Carthage, Verg. A. 1, 367"},"byssus":{"lemma":"byssus","pos":"","gen":"","def":"(byssum, i, n., Isid. Orig. 19, 27, 4), = βύσσος , cotton, cotton stuff, App. M. 11, p. 258, 20; Mart. Cap. 2, § 114"},"c":{"lemma":"C","pos":"","gen":"-na","def":"indecl., or f., the third letter of the Latin alphabet; corresponded originally in sound to the Greek Γ (which in inscrr., esp. in the Doric, was frequently written like the Latin C"},"cachla":{"lemma":"cachla","pos":"","gen":"","def":", = κάχλα, a plant, also called buphthalmos, oxeye, Plin. 25, 8, 42, § 82."},"cachrys":{"lemma":"cachrys","pos":"","gen":"","def":", = κάχρυς?̔κάγχρυς). An appendage to the catkin of certain trees in autumn, a cone, Plin. 16, 8, 11, § 30; Cels. 5, 18, n. 5; admixta cachry, Plin. 22, 22, 32, § 71"},"cactus":{"lemma":"cactus","pos":"","gen":"","def":", = κάκτος, a prickly plant with edible stalks, etc., found in Sicily, Spanish artichoke: Cynara cardunculus, Linn."},"cadmus":{"lemma":"Cadmus","pos":"adj.","gen":"-m","def":", = Κάδμος. Son of the Phoenician king Agenor, brother of Europa, husband of Harmonia, father of Polydorus, Ino, Semele, Autonoë, and Agave"},"cadytas":{"lemma":"cadytas","pos":"","gen":"","def":", = καδύτας, a Syrian parasitical pl'ant, Plin. 16, 44, 92, § 244. caecātor, ōris, m. caeco, prop. one who makes blind, hence, he who stops or obstructs a fountain, Paul. Nol. Carm. Nat. S. Fel. 24"},"caeciae":{"lemma":"Caeciae","pos":"","gen":"","def":", two small islands, opposite the promontory of Spiroeum, in Argolis, Plin. 4, 12, 19, § 57. caecĭas, ae, m., = καικίας, the northeast wind (acc. to more accurate nautical designation"},"caeco":{"lemma":"caeco","pos":"v.","gen":"","def":"a. id., to make blind, to blind. Lit.: sol caecat, Lucr. 4, 325 (300); Paul. Nol. Carm. Nat. S. Fel. 20, 7"},"caeculto":{"lemma":"caeculto","pos":"v.","gen":"-sighted","def":"n. contr for caeculĭto, from caecus, as ausculto for ausculito, from auris, to be like one blind, to be dim-sighted: caecultare est caecos imitari, Paul. ex Fest. p. 45 Müll.: caeculto άμβλυώττω"},"caecus":{"lemma":"Caecus","pos":"","gen":"","def":"; agnomen of Appius Claudius Crassus, as being blind, Cic. Brut. 14, 55; cf. Liv. 9, 29, 11"},"caedes":{"lemma":"caedes","pos":"","gen":"-class","def":"plur. regularly caedium, Liv. 1, 13, 3; Just. 11, 13, 9; Flor. 3, 18, 14 al.; but caedum, Sil. 2, 665; 4, 353; 4, 423; 4, 796; 5, 220; 10, 233; Amm. 22, 12, 1; 29, 5, 27"},"caelo":{"lemma":"caelo","pos":"v.","gen":"","def":"a. 1. caelum. Lit., answering to the Gr. τορεύω, to engrave in relief upon metals (esp. silver) or wory, to make raised work, to carve, engrave; later also, to cast (cf. O. Müll. Archaeol. § 311 sq."},"caelus":{"lemma":"caelus","pos":"","gen":"","def":"caelum init. and I. 2."},"caementa":{"lemma":"caementa","pos":"","gen":"","def":", v. caementum. caementārĭus, ii, m. caementum, a stone-cutter, a mason, a builder of walls, Hier. Ep. 53, 6"},"caementum":{"lemma":"caementum","pos":"","gen":"-menta","def":"(access. form cae-menta, ae, f., like armenta, ae, to armentum, Enn. ap. Non. p. 196, 30, or Trag. v. 422 Vahl.; v 373 Rib.) [contr. from caedimentum, from caedo"},"caenis":{"lemma":"Caenis","pos":"","gen":"","def":"V Caeneus.— A mistress of Vespasian, Suet. Vesp. 3, 23. Caenophrūrĭum (-frūrĭum), i, n., a town in Thrace, on the road from Apollonia to Selymbria, now Bivados, Eutr. 9, 15; Vop. Aur. 35, 5"},"caepitium":{"lemma":"caepitium","pos":"","gen":"","def":", v. caepa."},"caepuila":{"lemma":"caepuila","pos":"","gen":"","def":"caepina init."},"caere":{"lemma":"Caere","pos":"adj.","gen":"-citizens","def":"indecl. (gen. Caerĭtis. f., Verg. A. 8, 597; abl. Caerēte, id. ib. 10, 183), = Καιρη Steph., Καιρέα Strab., a very ancient city of Etruria, one of the twelve"},"caesa":{"lemma":"caesa","pos":"","gen":"","def":"caedo (only in the milit. lang. of Veget.), a cut, Veg. Mil. 1, 12. caesăpon, i, n., a kind of lettuce, Plin. 1 ind. libr. xx. n. 25; 20, 7, 25, § 59. Caesar, ăris (CAESERIS, C. I. L. 4, 2308"},"caesor":{"lemma":"caesor","pos":"","gen":"-class","def":"caedo, one who hews something (post-class.): lignorum caesores, hewers of wood, Hier. Ep. 53, n. 6, after the Vulg. Deut. 29, 11: lapidum, stone-breaker, Ambros. Luc. 2, 89 fin.; Vulg. 2 Par. 24, 12"},"caesum":{"lemma":"caesum","pos":"","gen":"","def":", v caedo fin. caesūra, ae, f. caedo A cutting, felling, hewing, hewing off ligni, Plin. 16, 43, 84, § 230"},"caesus":{"lemma":"caesus","pos":"","gen":"","def":"caedo, a cutting, a cutting off: frondium, Auct. Itin. Alex. M. p. 102 Mai caetĕrus, a, um, with its derivatives"},"caeus":{"lemma":"Caeus","pos":"","gen":"","def":"Cea. Caeus, i, = Coeus, q. v."},"caeyx":{"lemma":"Caeyx","pos":"","gen":"","def":""},"caia":{"lemma":"Caia","pos":"","gen":"","def":"Caius. caia, ae caio, a cudgel, acc. to Isid. Orig. 18, 7, 7. cāiātĭo, ōnis, f. caio, a striking, a cudgelling or beating of children, Fulg. Cont. Virg. p. 162 Munck. Căīcus (Căȳcus, Ov. M. 12, 111)"},"calcar":{"lemma":"calcar","pos":"","gen":"","def":"for carcar; cf. Sanscr. kar, wound"},"calco":{"lemma":"calco","pos":"v.","gen":"","def":"a. 1. calx, to tread something or upon something, to tread under foot. In gen. Lit. (very freq.; mostly poet. or in post-Aug. prose; not in Cic.)' astructos morientum acervos, Ov. M. 5, 88"},"calcus":{"lemma":"calcus","pos":"","gen":"","def":"the preced. fin."},"calda":{"lemma":"calda","pos":"","gen":"","def":"calidus, I. B. 1. caldāmentum, i, n. calidus, a fermentation (late Lat.) Marc. Emp. 5. caldārĭŏla, ae, f. dim. caldaria, a small vessel for heating fluids, Schol. ad Juv. 5"},"caldor":{"lemma":"caldor","pos":"","gen":"-class","def":"caldus = calidus, warmth, heat (ante- and post-class.), Varr. R. R. 3, 9, 15; 1, 41, 1; 1, 55, 6; Gell. 17, 8, 10; 19, 4, 4 and 5; Arn. 7, 240. caldum, i, v caldus. caldus, a, um, v calidus."},"caldus":{"lemma":"Caldus","pos":"","gen":"","def":", a Roman cognomen, v. Cic. Inv 2, 9, 28.—Esp.: C. Caelius Caldus, quaestor A. U. C. 704, Cic. Fam. 2, 19 tit. Călēdŏnĭa, ae, f, also Călī- cf. Welsh celydd, a woody shelter, and Lat. celo"},"calfacio":{"lemma":"calfacio","pos":"","gen":"","def":"calefacio. călĭcāta aedĭfĭcia, calce polita, plastered with lime, Paul. ex Fest. 47 Müll."},"calim":{"lemma":"calim","pos":"","gen":"","def":"clam."},"calingae":{"lemma":"Calingae","pos":"","gen":"","def":", a people of India, Plin. 6, 17, 21, § 64 sq.; 6, 20, 23, § 72; 7, 2, 2, § 30."},"calingii":{"lemma":"Calingii","pos":"","gen":"","def":", a people of Arabia, Plin. 6, 28, 32, § 159. ‡† caliptra, a kind of covering for the head, Paul. ex Fest. p. 47, 5 Müll. . călix, ĭcis, m. root cal-, cover; cf. caligo"},"calla":{"lemma":"calla","pos":"","gen":"","def":"calsa."},"callaecia":{"lemma":"Callaecia","pos":"","gen":"-icus","def":"Gallaeci. callaïs, ĭdis, f., = καλλαΐς, a sea-green precious stone, the turquoise, Plin. 37, 10, 56, § 151 (in Sol. 20 called callaica).—Hence, callăĭnus, a, um, adj., turquoisecolored: lacernae"},"callens":{"lemma":"callens","pos":"","gen":"","def":"calleo, P. a."},"callenter":{"lemma":"callenter","pos":"adv.","gen":"","def":", v. calleo, P. a. fin. callĕo, ēre, v. n. and a. . Neutr. Lit., to be callous, to be thickskinned (rare): plagis costae callent, Plaut. Ps. 1, 2, 4"},"callis":{"lemma":"callis","pos":"","gen":"-path","def":"(fem., Varr. R. R. 2, 2, 10; Liv. 22, 14, 8; 31, 42, 8; 36, 15, 9; Curt. 3, 10, 10; 4, 16, 11; Amm. 30, 1, 15; 31, 10, 9; cf. Neue, Formenl. 1, p. 673) [etym. dub."},"callisco":{"lemma":"callisco","pos":"","gen":"","def":"inch. , to become dull, insensible: aures nobis calliscerunt ad injurias, Cato ap. Non. p. 89, 27 sq. (Meyer, calliscunt, Or. Rom. Fragm. p. 118). Callisthĕnes, is, m., = Καλλισθένης"},"callisto":{"lemma":"Callisto","pos":"","gen":"-bear","def":"ad. Verg. G. 1, 67), f., = Καλλιστώ, daughter of the Arcadian king Lycaon (hence, Lycaonis, Ov. F. 2, 173: virgo Tegeaea, id. ib. 2, 167: Maenalia, id. ib. 2, 192: virgo Nonacrina, id. M. 2, 409)"},"callithrix":{"lemma":"callithrix","pos":"","gen":"-haired","def":", = καλλίθριξ (fair-haired). A plant used for coloring the hair, also called trichomanes, Plin. 26, 15, 90, § 160; 26, 14, 87, § 147"},"callon":{"lemma":"Callon","pos":"","gen":"","def":", = Κάλλων. A statuary of Aegina, Quint. 12, 10, 7.—Plur.: Callones, i. e. people like Callon, Quint. 12, 10, 10.— A statuary of Elis, who flourished about 430 B. C., Plin. 34, 8, 19"},"callum":{"lemma":"callum","pos":"","gen":"","def":"(callus, i, m., Cels. 5, 18, 36; 5, 26, 31 al.; Domit. Mars. ap. Charis. p. 55; plur. calli, Scrib. Comp. 37; 205; Suet. Aug. 80) [cf. Gr. καλάμη"},"calpar":{"lemma":"calpar","pos":"","gen":"-pitcher","def":"κάλπη?͂ κάλπις, a vessel for liquids, esp. for wine, a winecask, wine-pitcher, Non. p. 546, 32 sq.: calpar genus vasis fictilis, Paul. ex Fest. p. 46 Müll.— Calpar = vinum novum"},"caltha":{"lemma":"caltha","pos":"","gen":"","def":"(calthum, i, n., Prud. Cath. 5, 114) , a strongsmelling yellow flower, prob. our pot marigold: Calendula officinalis, Linn.; Plin. 21, 6, 15, § 28; Verg. E. 2, 50; Col. 10, 97"},"calua":{"lemma":"calva","pos":"","gen":"","def":"calvus. calvārĭa, ae, f. calva, calvus. The skull of man, Cels. 8, 1; Vulg. 4 Reg. 9, 35: calvariae locus, id. Matt. 27, 33"},"caluesco":{"lemma":"calvesco","pos":"","gen":"","def":"inch. n. , to become bald (post-Aug.), Col. 6, 14, 7; Veg. 3, 4, 27"},"caluio":{"lemma":"calvio","pos":"","gen":"","def":"calvor. Calvĭsĭus, ii, m., the name of several Romans; esp., C. Calvisius Sabinus, lieutenant of Caesar, and afterwards proetor in Africa, Caes. B. C. 3, 34 sq.; Cic. Phil. 3, 10, 26"},"caluor":{"lemma":"calvor","pos":"v.","gen":"-vo","def":"dep. a. (access. form cal-vo, ĕre, v. infra"},"caluus":{"lemma":"calvus","pos":"adj.","gen":"","def":"cf. O. H. Germ. chalo; Germ. kahl, bald, without hair (whether by nature or by shaving or shearing; rare"},"calx":{"lemma":"calx","pos":"","gen":"","def":"(m., Pers. 3, 105 dub.; Sil. 7, 696; cf. App. M. 7, p. 483 Oud.; Pers. 3, 105; Grat. Cyn. 278. Whether Lucil. ap. Charis, p. 72 P. belongs here or to 2. calx is undecided) [Sanscr. kar-, wound, kill"},"cama":{"lemma":"cama","pos":"","gen":"","def":"χαμαί = humi, a small bed near the ground, Isid. Orig. 20, 11, 2. cămăcum, v. comacum. Camaldūnum (Camalod-), i, n., v. Camuldunum. camara, ae, v camera. Cămărīna (in MSS. also Cămĕrī-na"},"cambio":{"lemma":"cambio","pos":"v.","gen":"-class","def":"n. (perf. campsi, acc. to Charis. pp. 219 and 233 P., and Prisc. p. 906 ib.) [whence the Ital. and mercantile cambio, cambiare, cambiatura, etc.; Fr. change, changer, etc."},"camilla":{"lemma":"Camilla","pos":"","gen":"","def":", a Volscian heroine, who perished in the war between Aeneas and Turnus, Verg. A. 7, 803; 11, 535."},"camillum":{"lemma":"camillum","pos":"","gen":"","def":"cumera."},"campa":{"lemma":"campa","pos":"","gen":"","def":"campe. campăgus, i, m., a kind of boot worn by military officers (late Lat.), Treb Gall. 16; Capitol. Max. jun. c. 2; Edict. Diocl. p. 24."},"campana":{"lemma":"campana","pos":"","gen":"","def":"Ital. campana, a bell; campanile, a belfry, a bell (late Lat.), Dig. 41, 1, 12. Campāna, ae, f., v. Campania, II. A. 1. campānĕus or campānĭus, a, um, adj. campus"},"campso":{"lemma":"campso","pos":"v.","gen":"","def":"a. κάμπτω, to bend, to turn, to turn around a place, to sail by, to double: Leucatam, Enn. ap. Prisc. p. 906 P. (Ann. v. 334 Vahl.; cf. campter and flecto)."},"camptaules":{"lemma":"camptaules","pos":"","gen":"","def":", an unknown kind of musician, Vop. Carin. 19."},"campter":{"lemma":"campter","pos":"","gen":"","def":", = καμπτήρ, a bending, turning, an angle, Pac. ap. Non. p. 65, 1 (Trag. Rel. v. 48 Rib.)."},"campus":{"lemma":"campus","pos":"","gen":"-cri","def":"cf. κῆπος, Dor. κᾶπος; perh. for scampus from σκάπτω, to dig, scabo; whence Campania, and perh. Capua"},"camum":{"lemma":"camum","pos":"","gen":"","def":", a kind of beer, Dig. 33, 7, 12; Edict. Diocl. p. 28."},"camur":{"lemma":"camur","pos":"adj.","gen":"","def":"acc. to Macr. S. 6, 4 fin., peregrinum verbum; prob. root of κάμπτω; cf.: camera, καμάρα, Non. p. 30, 8; Paul. ex Fest. p. 43 Müll.; Serv. ad Verg. G. 3, 55; nom. camur, Isid. Orig. 12, 1, 35"},"canae":{"lemma":"Canae","pos":"","gen":"","def":", = Κάναι, a town on the coast of Aeolis, opposite Mytilene, now Kanot-Koli, Liv. 36, 45, 8; cf. Mel. 1, 18"},"cancello":{"lemma":"cancello","pos":"v.","gen":"-wise","def":"a. cancelli (post-Aug.). In gen., to make like a lattice, to lattice: solum, i. e. with vines, Col. 4, 2, 2: cancellata cutis (elephanti), Plin. 8, 10, 10, § 30"},"cancellus":{"lemma":"cancellus","pos":"","gen":"","def":", v. cancelli."},"cancer":{"lemma":"cancer","pos":"","gen":"-crab","def":"canceris, Lucr. 5, 616; Arn. 1, p. 30; acc. plur. canceres, Cato, R. R. 157, 3), m. (neutr. Claudius, Quadrig. ap. Prisc. p. 697 P.; Scrib. Comp. 206 and 240) [cf. καρκίνος; root kar-, to be hard"},"candentia":{"lemma":"candentia","pos":"","gen":"","def":"candens, a white, clear lustre, whiteness: lunae, Vitr. 9, 2, 2."},"candeo":{"lemma":"candeo","pos":"v.","gen":"","def":"n. Sanscr candami, to be light; candra, the moon; connected with caneo as ardeo with areo, to be brilliant, glittering, to shine, glitter, glisten (cf. candidus and albus"},"candesco":{"lemma":"candesco","pos":"","gen":"","def":"inch. n. , to become of a bright, glittering white, to begin to glisten or radiate (rare; mostly poet.): ut solet aër candescere solis ab ortu, Ov. M. 6, 49"},"candicantia":{"lemma":"candicantia","pos":"","gen":"","def":"37, 13, 76, § 200; v. Sillig ad h. l. candĭco, āre, v. n. candeo, like albico, from albeo, to be whitish or white (first used by Plin. the elder), Plin. 37, 11, 73, § 189; 34, 12, 32, § 127"},"candosoccus":{"lemma":"candosoccus","pos":"","gen":"","def":"Gallic; in husbandry, a layer of a plant"},"cangi":{"lemma":"Cangi","pos":"","gen":"","def":", = Καγγανοί, a people in the western part of Britain, Tac. A. 12, 32. canĭa, ae, f., a kind of wild nettle, Plin. 21, 15, 55, § 92. canĭcae, ārum, f."},"canius":{"lemma":"Canius","pos":"","gen":"","def":", a Roman proper name. C. Canius. a Roman of learning, Cic. Off. 3, 14, 58 sq.; id. de Or. 2, 69, 280.— Canius Rufus, a poet, Mart. 1, 61, 9; 8, 20, 1."},"canna":{"lemma":"canna","pos":"","gen":"-pipe","def":", = κάννα, a reed, cane (less freq. than harundo), Col. 7, 9, 7; 4, 32, 3: palustris, Ov. M. 4, 298: tremulae, id. ib. 6, 326 al.— Transf., any thing made of reed. A reed-pipe, flute, Ov. M. 2, 682"},"cannae":{"lemma":"Cannae","pos":"adj.","gen":"","def":", = Κάνναι (Κάννα, Polyb.), a village in Apulia, north of Canusium, famous for the victory of Hannibal over the Romans"},"canta":{"lemma":"canta","pos":"","gen":"","def":"cano init. cantābĭlis, e, adj. canto, worthy to be sung, Cassiod. Var. 2, 40; id. 8, 9"},"canteci":{"lemma":"Canteci","pos":"","gen":"","def":", a people in Sarmatia Asiatica, near Palus Maeotis, Plin. 6, 7, 7, § 22. cantērĭātus (canth-), a, um, adj. canterius, supporied by props, underpropped: vineae, Col. 5, 4, 1. cantērīnus (canth-), a"},"canthus":{"lemma":"canthus","pos":"","gen":"-wheel","def":", = κάνθος; lit. the iron ring around a carriage-wheel, the tire, Quint. 1, 5, 88, where it is considered as barbarian (African or Spanish).—Hence, Meton. (pars pro toto), a wheel, Pers. 5, 71."},"cantillo":{"lemma":"cantillo","pos":"","gen":"-class","def":"dim. a. , to sing low, to hum (post-class.; perh. only in App.), App. M. 4, p. 146; id. Flor. 1, p. 342, 8; 3, p. 388, 13 al. cantĭo, ōnis, f. cano, lit. a singing, playing"},"canto":{"lemma":"canto","pos":"v.","gen":"","def":"n. and a. , freq. in form, but mostly agrees in meaning with cano. Neutr., to produce melodious sounds (by the voice or an instrument), to sound, sing, play (class. in prose and poetry"},"cantor":{"lemma":"cantor","pos":"","gen":"","def":"cano, a singer, poet. In gen.: omnibus hoc vitium est cantoribus, Hor. S. 1, 3, 1; so id. ib. 1, 3, 129"},"cantrix":{"lemma":"cantrix","pos":"adv.","gen":"","def":"cantor, a female singer, a songstress, Plaut. Trin. 2, 1, 23"},"cantus":{"lemma":"cantus","pos":"","gen":"-nantur","def":"id., the production of melodious sound, a musical utterance or expression, either with voice or instrument"},"canua":{"lemma":"canua","pos":"","gen":"","def":"canifera. Cănŭlēius, a, um, the name of a Roman gens. Thus, C. Canuleius, a tribune of the people. Acc. to a law proposed by him (Canuleium plebiscitum, Cic. Rep. 2, 37, 63) A.U.C. 310"},"capnion":{"lemma":"capnion","pos":"","gen":"","def":"capnos. capnĭŏs, ii, f., = κάπνιος (sc. ἄμπελος), a species of wine, so called from the dark or smoky color of the grapes, Plin. 14, 3, 4, § 39. capnītes, ae, v. capnias, II. A. capnītis, ĭdis, f."},"capra":{"lemma":"capra","pos":"","gen":"-goat","def":"caper, a she-goat, Cato ap. Charis. p. 79 P.; Varr. R. R. 2, 3, 1 sq.; Col. 7, 6 sq.; Plin. 8, 50, 76, § 200"},"capsa":{"lemma":"capsa","pos":"","gen":"","def":"capio; Fr. caisse; Engl. case, a repository, box, esp. for books, bookcase, satchel, * Cic. Div. in Caecil. 16, 51; Hor. S. 1, 4, 22; 1, 10, 63; id. Ep. 2, 1, 268; Juv. 10, 117"},"capsella":{"lemma":"capsella","pos":"","gen":"","def":"dim. id., a small box or coffer, Petr. 67, 9; Dig. 33, 7, 12, § 1"},"capsus":{"lemma":"capsus","pos":"","gen":"-body","def":"id.. A wagon-body, coach-body, Vitr. 10, 14; Fest. s. v. ploxinum, p. 230 Müll.: cf. Isid. Orig. 20, 12, 3. — An enclosure for animals, a pen, Vell. 1, 16, 2."},"capta":{"lemma":"capta","pos":"","gen":"","def":"1. capio fin. captābĭlis, e, adj. capto, that can take: res contrariorum, Boëth. Categ. 1, p. 144. captātĭo, ōnis, f. id., a reaching after or catching at something (rare): verborum"},"capto":{"lemma":"capto","pos":"","gen":"","def":"freq. act. . Prop., to strive to seize, lay hold of a thing with zeal, longing, etc., to catch at, snatch, chase, etc.: (syn. aucupor, venor): Tantalus a labris sitiens fugientia captat Flumina"},"captor":{"lemma":"captor","pos":"","gen":"","def":"capio, he who catches (animals), a hunter, huntsman, Poët. Anth. Lat. 5, 162, 8."},"captrix":{"lemma":"captrix","pos":"","gen":"","def":"captor, she that takes, catches; trop., she that despoils: virium captrices, Cael. Aur. Acut. 2, 39, 226. captūra, ae, f (post-Aug.). A taking, catching (of animals)"},"captus":{"lemma":"captus","pos":"","gen":"-class","def":"capio. A taking, seizing"},"car":{"lemma":"Car","pos":"","gen":"","def":"Caria, I. B. 1. cārăbus, i, m., = κάραβος, a kind of sea-crab, acc. to Beckmann: Cancer cursor, Linn."},"carbas":{"lemma":"Carbas","pos":"","gen":"-northeast","def":", the east-northeast wind, Vitr. 1, 6, 10. carbăsĕus (accessory form carbă-sĭnĕus, Varr. ap. Non. p. 541, 21; and carbăsĭnus, Plin. 19, 1, 6, § 23; App. M. 8, p. 214"},"carbo":{"lemma":"carbo","pos":"","gen":"","def":"Sanscr. c)ra, coquere; cf. cremo, a coal, charcoal (dead or burning); of dead coals, Cato, R. R. 38 fin.; Plaut. Truc. 5, 12; Ter. Ad. 5, 3, 63"},"carda":{"lemma":"Carda","pos":"","gen":"","def":"Cardea. Cardăces, um, m., = Κάρδακες [carda (Persian), strong, warlike, acc. to Strabo, 15, 3], a class of Persian soldiers"},"cardo":{"lemma":"cardo","pos":"","gen":"","def":"cf. κράδη, a swing; κραδαίνω, to swing, wave; Sanscr. kurd, a spring, a leap; old Germ. hrad, lively, and Germ. reit in bereit, ready (f., Gracch. ap. Prisc. p. 683 P.; Graius ap. Non. p. 202, 20"},"carisa":{"lemma":"carisa","pos":"","gen":"","def":", an artful woman, Paul. ex Fest. p. 44 Müll. căristĭa, v. charistia. cārĭtas, ātis, f. carus. Prop., dearness, costliness, high price, etc. (opp. vilitas): annonae, Cic. Verr. 2, 3, 18, § 47"},"carmen":{"lemma":"carmen","pos":"","gen":"-men","def":"(old form cas-men, Varr. L. L. p. 86 Bip.) [Sanscr. çasto declaim, praise; cf.: camilla, censeo], a tune, song; poem, verse; an oracular response, a prophecy"},"carmenta":{"lemma":"Carmenta","pos":"","gen":"","def":"Carmentis. Carmentālĭa, ĭum, -is, e, and Car-mentārĭi, v. Carmentis."},"carmentis":{"lemma":"Carmentis","pos":"","gen":"-ment","def":"1, 7, 8 Weissenb. ad loc."},"carmo":{"lemma":"Carmo","pos":"","gen":"","def":", a city of Hispania Baetica, now Carmona, Liv. 33, 21, 8 (acc. to Cod. Bamb.); Auct. B. Alex. 57.—Carmonenses, its inhabitants, Caes. B. C. 2, 19."},"carna":{"lemma":"Carna","pos":"","gen":"","def":"cf. Cardea, a goddess, previously called Crane, guardian of doorhinges (i. e. of domestic life) and the life of man, Ov F. 6, 101 sq."},"carni":{"lemma":"Carni","pos":"","gen":"","def":", a Celtic people in Upper Italy, east of Aquileia, extending to Cärnthen, now Krain, Mel. 2, 4, 2; Plin. 3, 18, 22, § 127; Inscr. Orell. 4040"},"carnis":{"lemma":"carnis","pos":"","gen":"","def":"2. caro. carnĭvŏrus, a, um, adj. 2. caro-voro; of animals, feeding on flesh, carnivorous. perh. only Plin. 9, 24, 40, § 78"},"carnuntum":{"lemma":"Carnuntum","pos":"","gen":"","def":", an old Celtic town of Upper Pannonia, on the Danube (now near Haimburg), Vell. 2, 109, 5; Plin. 4, 12, 25, § 80"},"carpentum":{"lemma":"carpentum","pos":"","gen":"-wheeled","def":", a two-wheeled, covered carriage, coach, or chariot, esp. used in town and by women, Prop. 4 (5), 8, 23; Ov. F. 1, 619; Liv. 5, 25, 9; 1, 48, 6; 34, 3, 9; Tac. A. 12, 42; Juv. 8, 147 al."},"carpi":{"lemma":"Carpi","pos":"","gen":"","def":", a people on the Danube, in Dacia, Eutr. 9, 25; Vop. Aur. 30"},"carpistes":{"lemma":"carpistes","pos":"adv.","gen":"","def":"καρπιστής, one of the Aeons of Valentinus, i. q. horos, Tert. adv. Val. 9."},"carpo":{"lemma":"carpo","pos":"","gen":"","def":": rapio, ἁρπάζω, καρπος; Engl. grab, grip, grasp. Lit., of plants, flowers, fruits, etc., to pick, pluck, pluck off, cull, crop, gather (class.; in prose and poetry, esp. in the latter very freq."},"carptim":{"lemma":"carptim","pos":"adv.","gen":"","def":"carptus, carpo (in the ante-Aug. per. very rare"},"carptor":{"lemma":"carptor","pos":"","gen":"","def":"carpo, a carver of food, Juv. 9, 110; cf. scissor. carptūra, ae, f. id.; of bees, a sucking or gathering from flowers, Varr. R. R. 3, 16, 26. carptus, a, um, Part., from carpo."},"carpus":{"lemma":"Carpus","pos":"","gen":"","def":"carpo, the name of a carver: qui obsonium carpit Carpus vocatur. Itaque quotiescunque dicit Carpe, eodem verbo et vocat et imperat, Petr. 36 fin."},"carrus":{"lemma":"carrus","pos":"","gen":"-wheeled","def":"(carrum, i, n., Auct. B. Hisp. 6; cf. Non. p. 195, 26, and Isid. Orig. 20, 12, 1), a kind of two-wheeled wagon for transporting burdens, Varr. and Sisenn. ap. Non. p. 195, 26 sq.; Caes. B. G. 1, 3"},"cartallus":{"lemma":"cartallus","pos":"","gen":"","def":", = κάρταλλος, a basket, Vulg. Deut. 26, 2; id. Jer. 6, 9. Cartēĭa, ae, f., = Καρτηία. A very ancient seaport town in Hispania Baetica, now near Rocadillo, Mel. 2, 6, 9; Plin. 3, 1, 3, § 7"},"carthaea":{"lemma":"Carthaea","pos":"","gen":"","def":", = Καρθαία, a town on the south coast of the Cycladic island Ceos or Cea, now Poles, Plin. 4, 12, 20, § 62.— Hence, Carthēus and Carthēĭus, a, um, Carthoean, of Carthoea: arva, Ov. M. 10"},"casca":{"lemma":"Casca","pos":"","gen":"","def":", a Roman cognomen in the gens Servilia, Cic. Att. 13, 44, 3; 16, 15, 3; id. Phil. 13, 15, 31; 2, 11, 27; Suet. Caes. 82"},"cascus":{"lemma":"cascus","pos":"adj.","gen":"-fashioned","def":"cf. canus, old: cascum significat vetus: ejus origo Sabina quae usque radices in Oscam linguam egit, Varr. L. L. 7, § 28"},"cassander":{"lemma":"Cassander","pos":"","gen":"","def":", = Κάσσανδρος. A son of Antipater, and king of Macedonia after the death of Alexander the Great, Just. 15, 1 sq.; Curt. 10, 10, 9; Cic. Off. 2, 14, 48"},"cassi":{"lemma":"Cassi","pos":"","gen":"","def":", a tribe of Britain, now Herts, Caes. B. G. 5, 21."},"cassia":{"lemma":"cassia","pos":"","gen":"","def":"casia. Cassĭānus, a, um, v. Cassius, B. cassĭcŭlus, i, m. dim. casses, a small net, a cobweb, Hier. Ruf. 3, 6"},"cassila":{"lemma":"cassila","pos":"","gen":"","def":"1. cassis. Cassĭŏdōrus, i, m., Magnus Aurelius, a learned Roman, minister under Theodoric, king of the Ostrogoths, and author of several works in Latin"},"cassis":{"lemma":"cassis","pos":"","gen":"","def":"casses. cassīta, ae, f [1. cassis, like galerita from galerus], the crested or tufted lark: Alauda cristata, Linn."},"cassiuellaunus":{"lemma":"Cassivellaunus","pos":"","gen":"","def":", a British chief, defeated by Coesar, Caes. B. G. 5, 11; 5, 18."},"casso":{"lemma":"casso","pos":"v.","gen":"","def":"a. cassus (late Lat.). In gen., to bring to naught, destroy, trop., Sid. Ep. 1 fin.— In the Lat. of the jurists, to annul, make null or void, = abrogo, Cod. Th. 11, 1, 3 al. casso (caso), avi, atum"},"cassus":{"lemma":"cassus","pos":"adj.","gen":"-sum","def":", empty, void, hollow. Prop. (syn.: inanis, vacuus; mostly poet.). Absol.: nux, Plaut. Ps. 1, 3, 137"},"castana":{"lemma":"Castana","pos":"","gen":"","def":", a town in Magnesia, Plin. 4, 9, 16, § 32; cf. Mel. 2, 3, 1. castănĕa, ae, f., = κάστανον. The chestnut-tree, Col. 4, 33; 5, 10, 14; Pall. Febr. 25, 33; id. Nov. 7, 17; Plin. 16, 40, 78, § 212"},"castellum":{"lemma":"castellum","pos":"","gen":"","def":"dim. castrum, a castle, fort, citadel, fortress, stronghold, Sisenn. ap. Non. p. 514, 7; Caes. B. G. 2, 30; id. B. C. 3, 36; Cic. Phil. 5, 4, 9; id. Caecin. 7, 20; Sall. J. 54, 6; Nep. Milt. 2, 1"},"castor":{"lemma":"castor","pos":"","gen":"","def":", = κάστωρ, the castor, beaver; pure Lat. fiber: Castor fiber, Linn.; Plin. 32, 3, 13, § 26; cf. id. 8, 30, 47, § 109; Cic. ap. Isid. Orig. 12, 2, 21; Ov. Nux. 166"},"castra":{"lemma":"castra","pos":"","gen":"","def":"castrum. castră-mētor, āri, 1, v. n., to pitch a camp, Jornand. 4, 54 al. Castrānus, a, um, adj., of Castrum Inui (v. castrum, I.): rura, Mart. 4, 60. castrātĭo, ōnis, f. castro. An emasculating"},"castrensis":{"lemma":"castrensis","pos":"adj.","gen":"-taining","def":"castra, of or per-taining to the camp, camp-: ratio ac militaris, Cic. Cael. 5, 11: arma, Prop. 3 (4), 9, 19. consilium, Liv. 44, 35, 4: triumphus, id. 7, 36, 8: corona"},"castro":{"lemma":"castro","pos":"v.","gen":"","def":"a. Sanscr. çastra, knife, sword. To deprive of generative power (both of male and female), to emasculate, castrate, geld: hircum, Plaut. Merc. 2, 2, 1 and 4: agnum, Varr. R. R. 2, 2, 18: gallos"},"castrum":{"lemma":"castrum","pos":"adj.","gen":"-coast","def":"kindred with casa, q. v.. In sing., any fortified place; a castle, fort, fortress (more rare than castellum): ei Grunium dederat in Phrygiā castrum, etc., Nep. Alcib. 9, 3; Liv. 32. 29, 4"},"castum":{"lemma":"castum","pos":"","gen":"","def":"2. castus init."},"castus":{"lemma":"castus","pos":"adj.","gen":"-tus","def":"i. e. cas-tus, partic., kindr. to Sanscr. çludh, to cleanse; Gr. καθ-αρός; Germ. keusch, heiter; cf. the opp. in-ces-tus, impure, Bopp, Gloss. 351, 6"},"catiuolcus":{"lemma":"Cativolcus","pos":"","gen":"","def":", king of the Eburones, Caes. B. G. 5, 26; 6, 31."},"catlaster":{"lemma":"catlaster","pos":"","gen":"","def":"contr. for catulaster from catulus; cf. Charis. p. 65 P.; Prisc. p. 618 ib. and 628 ib., a boy, lad, stripling: catulaster βούπαις, πάλληξ, Gloss. Philox."},"catta":{"lemma":"catta","pos":"","gen":"","def":", an unknown species of animal (acc. to Gloss. Vet. = αἴλουρος; cf. the Germ. Kater, Katze, cat), Mart. 13, 69, 1."},"catti":{"lemma":"Catti","pos":"","gen":"","def":"Chatti. cătŭla, ae, v. catulus. Cătŭlārĭa Porta, one of the gates of Rome, so called because dogs were sacrificed near it, Paul. ex Fest. p. 45 Müll."},"cauci":{"lemma":"Cauci","pos":"","gen":"","def":"Chauci. caucŭla, ae, f. dim. from the unus. cauca, v. caucus, a small dish, App. M. 5, 20, p. 62 Min. Vit. Debr. caucŭlātor, ōris, m., a reckoner, ψηφιστής, Gloss. Lat. ."},"caucus":{"lemma":"caucus","pos":"adv.","gen":"","def":", = καῦκα, a drinkingvessel, Hier. adv. Jov. 2, 14. cauda (also cōda, like codex, plostrum, etc., Varr. ap. Non. p. 86, 19; id. R. R. 2, 7, 5; Petr. 44, 12; Fest. p. 178, 29"},"caudex":{"lemma":"Caudex","pos":"","gen":"","def":", a Roman cognomen: App. Claudius Caudex, consul A. U. C. 490, B. C. 264, Sen. Brev. Vit. 13, 4"},"caudium":{"lemma":"Caudium","pos":"adj.","gen":"","def":", a small but ancient city of Samnium, near Benevento, celebrated for the narrow mountain pass (the Furculae Caudinae) where the Roman army was shut in by the Samnites, Liv. 9, 2, 1 sq."},"caulias":{"lemma":"caulias","pos":"","gen":"","def":", = καυλίας, taken or derived from the stalk: sucus, opp. to rhizias (from the root), Plin. 19, 3, 15, § 43. caulĭcŭlātus, a, um, adj. cauliculus, furnished with or having a stalk: rami"},"cauma":{"lemma":"cauma","pos":"","gen":"","def":", = καῦμα, the heat, Vulg. Job, 30, 30. Caunus or -ŏs, i, f., = Καῦνος, a very ancient town on the coast of Caria, now Kaiguez, Mel. 1, 16, 1; Plin. 5, 28, 29, § 104; Cic. Div. 2, 40, 84"},"cautim":{"lemma":"cautim","pos":"adv.","gen":"","def":"cautus, caveo, cautiously, warily, = caute, perh. only Non. p. 512, 11 and 12"},"cautor":{"lemma":"cautor","pos":"","gen":"","def":"caveo. * One who is on his guard or is wary, Plaut. Capt. 2, 2, 6.— One who is surety or bail for any one, Cic. Sest. 7, 15. cautrōma, ătis, n. cauter, a wound made by branding (late Lat.)"},"cautus":{"lemma":"cautus","pos":"","gen":"","def":"caveo, P. a. căvaedĭum, v. cavus, I. B. căvāmen, ĭnis, n. cavo. A hollowing out: temonis, Amm. 23, 4, 2.— A cavern, hollow, Sol. 9, § 9. căvannus, i, m., = κικκάβη, the nightowl, Anthol. Lat. 5, 134"},"celetrum":{"lemma":"Celetrum","pos":"","gen":"","def":", a town of Macedonia, now Castoria, Liv. 31, 40, 1. cĕleuma, v. celeusma. Cĕlĕus, ĕi, m., = Κελεός, a king in Eleusis, father of Triptolemus. He or his son was taught agriculture by Ceres"},"cella":{"lemma":"cella","pos":"","gen":"-cul","def":"cf. celo, oc-cul-o, clam, v. Varr. L. L. 5, 33, 45"},"cello":{"lemma":"cello","pos":"v.","gen":"","def":"a., found only in the compounds percello, procello; cf. Gr. κέλλω; Sanscr. kar, to kill; and Lat.: celer, celox."},"celmis":{"lemma":"Celmis","pos":"","gen":"","def":", = Κέλμις, one of the Dactyli or Corybantes, priests of Cybele"},"celsus":{"lemma":"celsus","pos":"adj.","gen":"-ceres","def":"P. a., of obsolete 2. cello, found in antecello, excello, etc., to rise high, tower; root kar-, in κάρη, κάρηνον, κόρυς; cerebrum, crista, pro-ceres"},"celtae":{"lemma":"Celtae","pos":"adj.","gen":"","def":", = Κελταί, a great parent - stock of people in the north of Europe, the Celts; among the Romans, in a more restricted sense, the inhabitants of Middle Gaul, Caes. B. G. 1, 1; Liv. 5, 34, 1"},"celtis":{"lemma":"celtis","pos":"","gen":"","def":", an African species of lotus, Plin. 13, 17, 32, § 104. cēmŏs, i, m., = κημός, an unknown plant, Plin. 27, 8, 35, § 57. cēna (not coena, caena; old form caesna"},"cenchrltis":{"lemma":"cenchrltis","pos":"","gen":"","def":", = κεγχρῖτις, a millet stone, a kind of precious stone now unknown, Plin. 37, 11, 73, § 188 Sillig N. cr. Cenchrĭus (-chrĕus), ii, m., = Κέγχριος, a river of Ionia near Ephesus, Tac. A. 3"},"censor":{"lemma":"censor","pos":"","gen":"","def":"1. censeo; cf. also Umbr. censtur"},"censum":{"lemma":"censum","pos":"","gen":"","def":"1. censeo, = 2. census, II. c., wealth, riches, Cic. ap. Non. p. 202, 23 (IV. 2, p. 456 Orell.). censūra, ae, f. censor. The office of censor, censorship, Liv. 4, 8, 2; 4, 24, 3 sq.; 9, 34, 16 sq."},"census":{"lemma":"census","pos":"","gen":"","def":"1. censeo. A registering and rating of Roman citizens, property, etc., a census; cf. Liv. 1, 42, 5"},"centaurion":{"lemma":"centaurion","pos":"","gen":"","def":"centaureum."},"centauris":{"lemma":"centauris","pos":"","gen":"","def":", = κενταυρίς, a species of centaureum, Plin. 25, 6, 32, § 69. Centaurŏmăchĭa, ae, f., a fictitious name of a part of Thessaly, Plaut. Curc. 3, 75."},"centaurus":{"lemma":"Centaurus","pos":"","gen":"-head","def":", = Κένταυρος, a Centaur; the Centaurs were wild people in the mountains of Thessaly, who fought on horseback"},"cento":{"lemma":"cento","pos":"","gen":"-covering","def":"κέντρων, a garment of several bits or pieces sewed together, a rag-covering, patchwork, etc., Cato ap. Fest. s. v. prohibere, p. 234 Müll.; id. R. R. 2, 3; 10, 5; Lucil. ap. Non. p. 176, 1"},"centrum":{"lemma":"centrum","pos":"","gen":"","def":", = κέντρον (a prickle, sharp point). Centrum circini, the stationary foot of the compasses, around which the other is carried in making a circle, Vitr. 3, 1"},"centumuir":{"lemma":"centumvir","pos":"","gen":"","def":"centumviri. centumvĭrālis, e, adj. centumviri, of or pertaining to the centumviri: judicium, Cic. Caecin. 18, 53; id. de Or. 1, 39, 177; Quint. 11, 1, 78"},"centussis":{"lemma":"centussis","pos":"","gen":"-as","def":"centum-as, a hundred asses, Varr. L. L. 5, § 170; 9, § 81"},"ceos":{"lemma":"Ceos","pos":"","gen":"","def":"Cea. cēpa, v. caepa. cēpaea, ae. f., = κηπαία, a plant similar to the portulacca, the portulacca-leaved sedum: Sedum cepaea, Linn."},"cepolindrum":{"lemma":"cepolindrum","pos":"","gen":"","def":", a kind of condiment, Plaut. Ps. 3, 2, 43. cēpŏnĭdes, um, f., a precious stone now unknown, Plin. 37, 10, 56, § 156. cēpŏs Aphrŏdītēs, = κῆπος?̓Αφροδίτης, hortus Veneris, a plant"},"cercinium":{"lemma":"Cercinium","pos":"","gen":"","def":", a town of Thessaly, Liv. 31, 41, 1 and 3. cercītis, ĭdis, f., = κερκῖτις, a species of olive-tree, Col. 5, 8, 3."},"cercius":{"lemma":"Cercius","pos":"","gen":"","def":"Circius."},"cerco":{"lemma":"Cerco","pos":"","gen":"","def":", a Roman cognomen, Liv. 42, 6 init."},"cercolips":{"lemma":"cercolips","pos":"","gen":"","def":"corcholopis. cercŏpĭthēcus, i, m., = κερκοπίθηκος, a monkey with a tail, Varr. ap. Non. p. 201, 26; Plin. 8, 21, 30, § 72; Mart. 14, 202; 14, 128"},"cercyo":{"lemma":"Cercyo","pos":"adj.","gen":"-us","def":", = Κερκυών, a celebrated robber in Attica, conquered and slain by Theseus at Eleusis, Ov. M. 7, 439; Hyg. Fab. 187"},"cerdiciates":{"lemma":"Cerdiciates","pos":"","gen":"","def":", a people of Liguria, Liv. 32, 29, 7."},"cerdo":{"lemma":"cerdo","pos":"","gen":"","def":", = κέρδων , a handicraftsman, Juv. 4, 153; 8, 182: sutor, a cobbler, Mart. 3, 59; cf. id. 3, 16.— A proper name, esp. of slaves, Dig. 38, 1, 42; Inscr. Orell. 4161. Cĕrĕālis (Cĕrĭālis"},"cereuisia":{"lemma":"cerevisia","pos":"","gen":"","def":"cervisia. cerĭa or cerea, ae, f., a Spanish drink, prepared from corn, = celia and cerevisia, Plin. 22, 25, 82, § 164. cērĭfĭco, āvi, 1 cera - facio, lit., to make wax"},"cerno":{"lemma":"cerno","pos":"v.","gen":"-clause","def":"pass. cretus is apparently used only once: cineris bene creti, Pall. 12, 22, 3; but freq. in the compounds of cerno"},"cerostrota":{"lemma":"cerostrota","pos":"","gen":"","def":"celostratus and cestrotus. cērōsus, a, um, adj. cera, full of wax: mel, Plin. 32, 3, 13, § 27. cērōtārium, ii, v. ceratum. cērōtum, i, v. ceratum. Cerretāni, ōrum, m."},"cerrones":{"lemma":"cerrones","pos":"","gen":"","def":"gerrones."},"cerrus":{"lemma":"cerrus","pos":"","gen":"","def":", a kind of oak, Turkey oak, Col. 7, 9, 6; Plin. 16, 5, 6, § 17; 16, 6, 8, § 19; Vitr. 2, 8; Pall. 1, 9, 3"},"certim":{"lemma":"certim","pos":"adv.","gen":"","def":"certus, analog. to certatim, from certatus, certainly: scire, Jul. Val. Rer. Gest. Alex. M. 1, 31. certĭōro, āvi, ātum, 1, v. a. certior, = certiorem facere, to inform, apprise"},"certo":{"lemma":"certo","pos":"","gen":"","def":"freq. a. cerno, to decide something by a contest (cf. cerno, II. C. b.)"},"certor":{"lemma":"certor","pos":"v.","gen":"","def":"dep. n. , to strive, struggle, contend, Hyg. Fab. 273; Vulg. Ecclus. 11, 9. certus, a, um orig. P. a. from cerno"},"cerua":{"lemma":"cerva","pos":"","gen":"","def":"cervus, a hind, Plin. 11, 37, 45, § 123 sq.; Ov. M. 6, 636; 12, 34.— Poet., for deer in gen., Ter. Phorm. prol. 7; Cat. 63, 72; Verg. A. 4, 69; Hor. C. 1, 1, 27; 3, 5, 32; Ov. M. 7, 546; 11, 772"},"ceruesia":{"lemma":"cervesia","pos":"","gen":"","def":"cervisia. cervīcal (cervīcāle, Cassiod. Orth. p. 2302 P.), ālis, n. cervix, a pillow or bolster, = pulvinus; sing., Mart. 14, 146; Juv. 6, 353; Petr. 56, 8; plur., Plin. Ep. 6, 16, 16; Petr. 32, 1"},"ceruisia":{"lemma":"cervisia","pos":"","gen":"-sia","def":"Gallic, beer, Plin. 22, 25, 82, § 164; Dig. 33, 6, 9; Isid. Orig. 20, 3, 17; Edict. Diocl. 2, 11."},"ceruix":{"lemma":"cervix","pos":"","gen":"-vix","def":"plur. cervicum, Cic. Or. 18, 59; Plin. 23, 2, 33, § 68: cervicium, acc. to Charis. p. 100), f. cer-vix"},"cespes":{"lemma":"cespes","pos":"","gen":"-sposus","def":"caespes, etc. cessātĭo, ōnis, f. cesso. A tarrying, delaying: non datur cessatio, Plaut. Poen. 4, 2, 103.—Hence, Inactivity, idling, cessation, omission, idleness: furtum cessationis quaerere"},"cessio":{"lemma":"cessio","pos":"","gen":"","def":"1. cedo; only in jurid. lang. A giving up, surrendering: abalienatio est ejus rei, quae mancipi est, aut traditio alteri nexo aut in jure cessio, Cic. Top. 5, 28; Dig. 42, 3 tit.; Gai Inst. 3, 78"},"cesso":{"lemma":"cesso","pos":"","gen":"","def":"freq. n. and a. ; lit., to stand back very much; hence, to be remiss in any thing, to delay, loiter, or, in gen., to cease from, stop, give over (indicating a blamable remissness"},"cestron":{"lemma":"cestron","pos":"","gen":"","def":"cestrum."},"cestros":{"lemma":"cestros","pos":"","gen":"","def":", = κέστρος, the plant betony: Betonica officinalis, Linn."},"cetra":{"lemma":"cetra","pos":"","gen":"","def":"caetra, etc."},"cette":{"lemma":"cette","pos":"","gen":"","def":"2. cedo. cētus, i, m. (acc. to the Gr. cētŏs, n., Plin. 32, 1, 4, § 10; and hence common in the plur. cētē = κήτη, Verg. A. 5, 822; Plin. 9, 24, 40, § 78; 9, 50, 74, § 157"},"ceu":{"lemma":"ceu","pos":"adv.","gen":"-ve","def":"contr. from ce-ve, like neu and seu, from neve and sive, a particle of equality or comparison, as, like as, just as (in the ante-Aug. per., peculiar to more elevated poetry"},"ceutrones":{"lemma":"Ceutrones","pos":"","gen":"","def":", a Gallic tribe, Caes. B. G. 5, 39. cēva or ceua, ae, f. Low Germ. Keue, a kind of small cow, Col. 6, 24, 5. Cĕvenna (also Cĕbenna and Gĕ-benna), ae, f., a mountain in Gallia, now Cevennes"},"chaere":{"lemma":"chaere","pos":"interj.","gen":"","def":", = χαῖρε, hail! Pers. prol. 8. Chaerĕa, ae, m. (Gr. Χαιρέας), a Roman cognomen, Ter. Eun. 2, 3, 17 al.; Cic. Rosc. Com. 1, 1"},"chalcanthum":{"lemma":"chalcanthum","pos":"","gen":"-water","def":", = χάλκανθον , copperas-water; pure Lat. atramentum sutorium, Plin. 34, 12, 32, § 123."},"chalcaspis":{"lemma":"chalcaspis","pos":"adj.","gen":"","def":", = χάλκασπις, having a brazen shield, Liv. 44, 41, 2 Weissenb."},"chalcis":{"lemma":"chalcis","pos":"","gen":"-colored","def":", = χαλκίς. A fish of the herring kind, Col. 8, 17, 12; Plin. 9, 47, 71, § 154; 9, 51, 74, § 162.— A lizard with copper-colored spots on its back, Plin. 32, 3, 13, § 30; 32, 5, 17, § 46."},"chalcus":{"lemma":"chalcus","pos":"","gen":"","def":", = χαλκός, a copper coin, the tenth (acc. to Gr. authors, the sixth or eighth) part of an obolus, Plin. 21, 34, 109, § 185."},"chaldaei":{"lemma":"Chaldaei","pos":"adj.","gen":"-d","def":", = Χαλδαῖοι, the Chaldoeans, a people of Assyria, distinguished, in an early age, for their knowledge of astronomy and astrology. Of the nation or people, Plin. 6, 28, 32, § 105"},"cham":{"lemma":"Cham","pos":"","gen":"","def":"indecl., a son of Noah, Ham, Lact. 2, 13, 5"},"chara":{"lemma":"chara","pos":"","gen":"","def":", a root unknown to us; perh. wild cabbage, Caes. B. C. 3, 48. chărăcātus, a, um, adj., χάραξ, provided with stakes, propped up: vineae, Col. 5, 4, 1"},"charisticum":{"lemma":"charisticum","pos":"","gen":"","def":"chartiaticum. Chărĭtes, um, f., = Χάριτες, the Charites or Graces (pure Lat. Gratiae), usu. three, Aglaia, Euphrosyne, and Thalia (cf., however, Lidd. and Scott under the word), Ov. F. 5, 219"},"charta":{"lemma":"charta","pos":"","gen":"","def":", Lucil. ap. Non. p. 196, 19). f., = ό χάρτης (cf. the letter A), a leaf of the Egyptian papyrus, paper, Plin. 13, 11, 21, § 68 sqq.; Lucr. 6, 112; 6, 114; Cic. Att. 5, 4, 4"},"chartus":{"lemma":"chartus","pos":"","gen":"","def":"charta init. Chărybdis, is, f., = Χάρυβδις, a dangerous whirlpool between Italy and Sicily, opposite to Scylla, now Calofaro; personified, a monstrous female being, Mel. 2, 7, 14"},"chasma":{"lemma":"chasma","pos":"","gen":"","def":", = χάσμα, an opening of the earth, a chasm, abyss, Sen. Q. N. 6, 9, 2; Dig. 4, 4, 11; 50, 15, 4"},"chersos":{"lemma":"chersos","pos":"","gen":"","def":"χέρσος, dry land, a kind of toad: feminea, Mart. 14, 88. chersȳdros, i, m., = χέρσυδρος, an amphibious serpent, Cels. 5, 27, 8; Luc. 9, 711"},"chesippus":{"lemma":"Chesippus","pos":"","gen":"","def":", a contemptuous name given by Zeno to Chrysippus, Cic. N. D. 1, 34, 93. chīlĭarchēs, ae, or chīlĭarchus, i, m., = χιλιάρχης or χιλίαρχος, a commander of 1000 soldiers, a chiliarch, Curt. 5. 2"},"chius":{"lemma":"Chius","pos":"","gen":"","def":"Chios. chlămyda, ae, v. chlamys. chlămydātus, a, um, adj. chlamys, dressed in a military cloak, Plaut. Ps. 4, 2, 8; 4, 6, 39; id. Rud. 2, 2, 9 al.; * Cic. Rab. Post. 10, 27"},"chlora":{"lemma":"chlora","pos":"","gen":"","def":", a medicament, Veg. 6, 28, 3. chlōreus (dissyl.), ei, m., = χλωρεύς, a greenish bird, Plin. 10, 74, 95, § 203. chlōrĭōn, ōnis, m., = χλωρίων, a yellow bird, the yellow thrush"},"chlorus":{"lemma":"Chlorus","pos":"","gen":"","def":"A river of Cilicia, Plin. 5, 27, 22, § 91.— A cognomen of Sex. Pompeius, Cic. Verr. 2, 2, 8, § 23. Chŏaspes (Chŏaspis, Isid. Orig. 13, 21, 15), is, m., = Χοάσπης. A river in Susiana"},"choerogryllus":{"lemma":"choerogryllus","pos":"","gen":"","def":", = χοιρόγρυλλος, a kind of hare, Vulg. Lev. 11, 5; id. Deut. 14, 7. chŏĭcus, a, um, adj., = χοϊκός. of earth or clay: homo, Tert. adv. Val. 24; id. Anim. 40; id. Res Carn. 49."},"cholas":{"lemma":"cholas","pos":"","gen":"","def":", a species of emerald, Plin. 37, 5, 18, § 73. chŏlĕra, ae, f., = χολέρα, the jaundice, Cels. 2, 13; 4, 11 al.; Plin. 20, 22, 93, § 252; 24, 13, 73, § 120; in plur., Plin. 20, 12, 48, § 122"},"chondris":{"lemma":"chondris","pos":"","gen":"","def":", a plant, a kind of horehound, resembling marjoram: Marrubium pseudodictamnus, Linn.; Plin. 25, 8, 53, § 92"},"chorda":{"lemma":"chorda","pos":"","gen":"","def":", = χορδή. * An intestine, as food, Petr. 66, 7 (al. leg. cord.).— Far more freq., Catgut, a string (of a musical instrument), Cic. de Or. 3, 57, 214; id. N. D. 2, 59, 149 fin.; Lucr. 2, 412; 2, 505"},"chordapsus":{"lemma":"chordapsus","pos":"","gen":"","def":", = χόρδαψος, a disease of the intestines, Cael. Aur. Acut. 3, 17, 144"},"chordus":{"lemma":"Chordus","pos":"","gen":"","def":", a Roman cognomen; esp.: H. Cremutius Chordus, an historian of the times of Augustus and Tiberius, Quint. 1, 4, 25; Tac. A. 4, 34; Suet. Aug. 35; id. Calig. 16"},"chors":{"lemma":"chors","pos":"","gen":"","def":"cohors. chortĭnus, a, um, adj., = χόρτινος, of or from grass: oleum, Plin. 15, 7, 7, § 30. chŏrus, i, m., = χορός [cf. Lidd. and Scott under χορός]. A dance in a ring, a choral dance, a dance"},"chreston":{"lemma":"chreston","pos":"","gen":"","def":", = χρηστόν (useful), a name by which the plant cichorium was sometimes called, Plin. 20, 8, 30, § 74."},"chrestus":{"lemma":"Chrestus","pos":"","gen":"","def":"A mutilated form for Christus, Lact. 4, 7, 5; hence, Chrestiani, instead of Christiani, was used by many; cf. Tert. Apol. 3 fin.— A Jew at Rome under the emperor Claudius, Suet. Claud. 15"},"chrisma":{"lemma":"chrisma","pos":"adv.","gen":"","def":", = χρίσμα, in eccl. Lat., an anointing, unction, Tert. Bapt. 7; id. adv. Jud. 13; Prud. Cath. 6, 128"},"christus":{"lemma":"Christus","pos":"","gen":"","def":", = Χριστός (the Anointed, Heb. ; cf. Lact. 4, 7, 7), Christ, Tac. A. 15, 44 Rupert. ad loc.; Plin. Ep. 10, 97"},"chydaeus":{"lemma":"chydaeus","pos":"adj.","gen":"","def":", = χυδαῖος (abundant; hence), common: dactyli, a kind of palms, Plin. 13, 4, 9, § 46"},"cia":{"lemma":"Cia","pos":"","gen":"","def":"Cea. Cĭāni, ōrum, m., the inhabitants of Cios, a town in Bithynia, Liv. 31, 31, 4"},"ciccus":{"lemma":"ciccus","pos":"","gen":"","def":", = κίκκος, the thin membrane surrounding the grains of a pomegranate; hence for something unimportant, worthless, a trifle, bagatelle, Varr. L. L. 7, § 91"},"cignus":{"lemma":"cignus","pos":"","gen":"","def":", a measure, = 8 scrupuli, Plin. Val. 2, 30 and 31."},"cilibantum":{"lemma":"cilibantum","pos":"","gen":"","def":", a round cupboard, Varr. L. L. 5, § 121 Müll."},"cilla":{"lemma":"Cilla","pos":"","gen":"","def":", = Κίλλα, a town in Troas, distinguished for the worship of Apollo, Plin. 5, 30, 32, § 122; Sen. Troad. 227"},"cillo":{"lemma":"cillo","pos":"","gen":"","def":"1. cillo, = cinaedus, Pseudo ic. in Sall. 6, 18. Cilnĭus, a, um, adj. pure Etrusc. Cfelne or Cfenle, a designation of a very distinguished Etruscan gens, from which Moecenas originated"},"cilo":{"lemma":"cilo","pos":"","gen":"","def":", having a prominent forehead pressed in upon the sides, Fest. p. 43, 10; cf. Charis. 1, p. 78 P."},"cimber":{"lemma":"Cimber","pos":"","gen":"","def":"Cimbri."},"cimbri":{"lemma":"Cimbri","pos":"adj.","gen":"","def":", = Κίμβροι [Cimbri linguā Gallicā latrones dicuntur, Fest. p. 43, 7], a people of Northern Germany (in Holstein, Silesia, and Jutland)"},"cincia":{"lemma":"Cincia","pos":"","gen":"","def":"Cincius, IV. cincinnālis, e, adj. cincinnus, curled: herba, a plant, also called polytrichon, App. Herb. 51. cincinnātŭlus, a, um, adj. dim. , with curled hair: pueri, Hier. Ep. 130"},"cincinnus":{"lemma":"cincinnus","pos":"","gen":"","def":"m. kindr. with Gr. κίκιννος and Lat. cirrus; Sanscr. cicura, crinis, Bopp, Gloss. 124 a, curled hair, a lock or curl of hair, Plaut. Truc. 2, 2, 32; Varr. R. R. 1, 31, 4"},"cinctia":{"lemma":"Cinctia","pos":"","gen":"","def":"Cinxia. cinctĭcŭlus, i, m. dim. 2. cinctus, a little girdle, Plaut. Bacch. 3, 3, 28."},"cinctor":{"lemma":"cinctor","pos":"","gen":"","def":", = ζώστης, Gloss. Gr. Lat. cinctōrĭum, ii, n. 2. cinctus, a swordbelt, = balteus, Mel. 2, 1, 13.— In gen., a girdle (late Lat.); trop.: et erit... fides cinctorium renum ejus, Vulg. Isa. 11, 5."},"cinctum":{"lemma":"cinctum","pos":"","gen":"","def":", v. 2. cinctus. cinctūra, ae, f. 2. cinctus, cingo, a nncture, a girdle (very rare), * Suet. Caes. 45; * Quint 11, 3, 139. cinctus, a, um, Part., from cingo."},"cinctus":{"lemma":"cinctus","pos":"","gen":"-class","def":"(post-class. access. form cinctum, i, n., Scrib. Comp. 163, Isid. Orig. 19, 33, Pophyr. ad Hor. A. P. 50) . Abstr., a girding (rare): cottidiani cinctus, Plin. 28, 6, 17, § 64"},"cinga":{"lemma":"Cinga","pos":"","gen":"","def":", a small river in Hispania Tarraconensis, in the territory of the Ilergetes, now Cinca, Caes B C. 1, 48"},"cingilia":{"lemma":"Cingilia","pos":"","gen":"","def":", a town of the Vestini on the Adriatic Sea, Liv 8, 29, 13."},"cingillum":{"lemma":"cingillum","pos":"","gen":"","def":"dim. cingulum, a small girdle, Petr 67, 4; Not. Tir. p 158 Grut.; cf.: cingillus, στρόφιον, ζώνιον, Gloss."},"cingo":{"lemma":"cingo","pos":"v.","gen":"","def":"a. cf. Gr κυλλός, κυρτός"},"cinithii":{"lemma":"Cinithii","pos":"","gen":"","def":", a people of Africa, Tac. A. 2, 52. Cinium (Civium), ii, n., a town of the island of Majorca, now Sinau, Plin. 3, 5, 11, § 77."},"cinna":{"lemma":"Cinna","pos":"adj.","gen":"","def":", a family name of the gentes Cornelia and Helvia. L. Cornelius Cinna, consul A.U.C. 667-670; a confederate of C. Marius in the Roman civil war with Sylla, Vell. 2, 20 sq.; Flor. 3, 21"},"cinnus":{"lemma":"cinnus","pos":"","gen":"-grain","def":"kindr. with κυκεών, κόγχος, a mixed drink of spelt-grain and wine, Arn. 5, 174"},"circa":{"lemma":"Circa","pos":"","gen":"","def":"Circe."},"circaea":{"lemma":"circaea","pos":"","gen":"","def":", = κιρκαία, a plant used as a charm, Plin. 27, 8, 38, § 60. circaeum (-on), i, n., = κιρκαῖον, the plant also called mandragoras, Plin. 25, 13, 94, § 147."},"circaeus":{"lemma":"Circaeus","pos":"","gen":"","def":"Circe, II. circāmoerĭum, ii, n. circa-moerus, for murus; cf. pomerium, the space about a wall, on both sides of a wall: pomerium, verbi vim solam intuentes, postmoerium interpretantur esse"},"circellus":{"lemma":"circellus","pos":"","gen":"","def":"dim. circulus, a small ring, Apic. 2, 5, Schol Juv. 6, 379."},"circen":{"lemma":"circen","pos":"","gen":"","def":"circinus, a circle, a circular course: solis, a year, Poët. in Anth. Lat. 4, 274 (Meyer, n. 1373)."},"circensis":{"lemma":"Circensis","pos":"","gen":"","def":"Circus, II. b. circĕs, itis, m. circum-ire, a circle (ante- and post-class.): ut parvi circuli Anuli, sic magni dicebantur circites Ani, Varr L. L. 6, § 8 Müll."},"circlus":{"lemma":"circlus","pos":"","gen":"","def":"circulus init."},"circo":{"lemma":"circo","pos":"v.","gen":"","def":"a. circus. = circumeo. To go about, traverse: montem, Gromat. Vet. p. 326, 17"},"circum-cingo":{"lemma":"circum-cingo","pos":"v.","gen":"-cingo","def":"a., to enclose around, surround: quā Mons Apenninus regiones Italiae Etruriaeque circumcingit, Vitr. 2, 6, 5: eum zonā gloriae, Vulg. Ecclus. 45, 9: PORTICVS, Inscr. Orell. 4043.—In part. pres."},"circum-claudo":{"lemma":"circum-claudo","pos":"v.","gen":"-claudo","def":"a. (postclass. collat. form of circumcludo), to shut in: farinā circumclaudendus locus, Cael. Aur. Tard. 4, 7, 103. circum-clūdo, si, sum, 3, v. a. claudo, to shut in"},"circum-curro":{"lemma":"circum-curro","pos":"v.","gen":"-curro","def":"n., to run round or about (not ante-Aug.), Vitr. 4, 6: circumcurrens linea, the periphery, Quint. 1, 10, 41.—* Trop.: eam artem (rhetoricen) circumcurrentem vocaverunt. quod in omni materiā diceret"},"circum-curso":{"lemma":"circum-curso","pos":"","gen":"-curso","def":"freq. a. and n., to run round about, to run about in, at, or near something (ante- and post-class.; in Cic. Fam. 7, 1, 5, more recent editt. read concursare)"},"circum-do":{"lemma":"circum-do","pos":"v.","gen":"-do","def":"a., lit. to put, set, or place around, i. e. both to wrap around (e. g. a mantle). and also to enclose (e. g. a town with a wall"},"circum-fingo":{"lemma":"circum-fingo","pos":"v.","gen":"-fingo","def":"a., to form around: carnem alicui, Tert. Anim. 23. circum-fīnĭo, īre, v. a., to complete a circle, to bring to an end: annum, Sol. 3. circum-fīrmo, āre, v. a., to fasten round: vitem, Col. 4, 17, 7."},"circum-flagro":{"lemma":"circum-flagro","pos":"v.","gen":"-flagro","def":"n., to blaze or scorch all around: per immensum circumflagrantibus Austris, Avien. Arat. 274."},"circum-flecto":{"lemma":"circum-flecto","pos":"v.","gen":"-flecto","def":"a., to bend or turn about (Verg. and post-class. writers); prop. of the charioteer in the circus; hence, transf.' longos cursus, Verg. A. 5, 131"},"circum-fundo":{"lemma":"circum-fundo","pos":"v.","gen":"-fundo","def":"a., lit. to pour out around, i.e. as in circumdo, either with the acc. of that which is poured, to pour around"},"circum-gesto":{"lemma":"circum-gesto","pos":"","gen":"-gesto","def":"freq. a., to bear or carry around' epistulam, * Cic. Q. Fr. 1, 2, 2, § 6"},"circum-hisco":{"lemma":"circum-hisco","pos":"","gen":"-hisco","def":"n, to stare about with open mouth, Arn. 5, p 175 dub. (al. circumsciscere) circum -hŭmātus, a, um, Part , buried around: corpora, Amm 22, 12, 8. circum-ĭcĭo or circum-jĭcĭo (access. form circum-jăcĭo"},"circum-lambo":{"lemma":"circum-lambo","pos":"v.","gen":"-lambo","def":"a., to lick around ora, Plin. 11, 37, 65, § 171 circum-lăquĕo, āre, v. a., to wind around, in tmesis cassem, Grat. Cyn 29. circumlātĭcĭus or -tĭus, a, um, adj. circumlatus, that may be carried around"},"circum-lustro":{"lemma":"circum-lustro","pos":"v.","gen":"-lustro","def":"a., to light all around; in tmesis: mundi templum, Lucr 5, 1437.— Trop., to travel over or through: populos provinciae, Cod. Th. 4, 8, 5. circum-lŭvĭo, ōnis, f."},"circum-mingo":{"lemma":"circum-mingo","pos":"v.","gen":"-mingo","def":"a., to make water around something; aliquem, Petr. 57, 3: vestimenta, id. 62, 6."},"circum-mitto":{"lemma":"circum-mitto","pos":"v.","gen":"-mitto","def":"a., to send around: legationes in omnes partes, Caes. B. G. 7, 63; id. B. C. 3, 55: praecones, id B. G. 5, 51"},"circum-necto":{"lemma":"circum-necto","pos":"v.","gen":"-necto","def":", nexum, ĕre, v. a., to wrap or bind around, surround, envelop (late Lat.): elephanti flammis conjectis undique circumnexi, Amm. 19, 7, 7: tenuis membrana illa perlucens, quā circumnectitur alvus"},"circum-plaudo":{"lemma":"circum-plaudo","pos":"v.","gen":"-plaudo","def":"a., to applaud or greet on all sides by clapping the hands, Ov. Tr. 4, 2, 49. circumplecto, ĕre (act. collat. form of circumplector"},"circum-plector":{"lemma":"circum-plector","pos":"v.","gen":"-plector","def":"dep. a., to clasp around, embrace, to surround, encompass (class. in prose and poetry): conjunctiones motu undique, Cic. Univ. 7 fin.: domini patrimonium quasi thesaurum draco, id. Phil. 13, 5"},"circum-pulso":{"lemma":"circum-pulso","pos":"v.","gen":"-pulso","def":"a., to strike or beat around; of sounds: aures, to din, Stat. Th. 6, 228."},"circum-pungo":{"lemma":"circum-pungo","pos":"v.","gen":"-pungo","def":"a., to prick or puncture around: clavum pedis, Cels. 5, 28, 14 (cf.: clavi circum scarificati, Plin. 22, 23, 49, § 101)."},"circum-purgo":{"lemma":"circum-purgo","pos":"v.","gen":"-purgo","def":"a., to cleanse or purify around: dentem, Cels. 7, 12, 1"},"circum-scindo":{"lemma":"circum-scindo","pos":"v.","gen":"-scindo","def":"a., to rend, strip, or tear off around: aliquem et spoliare, Liv. 2, 55, 5. circum-scrībo, psi, ptum, 3, v. a. Prop., to draw a line around, to circumscribe, enclose in a circle (in good prose"},"circum-signo":{"lemma":"circum-signo","pos":"v.","gen":"-signo","def":"a., to mark around: gemmam, Col. 5, 11, 19; id. Arb. 26, 8"},"circum-specto":{"lemma":"circum-specto","pos":"","gen":"-specto","def":"freq. a., to look about with attention, precaution, desire, etc.; to cast a look around, to search around"},"circum-stagno":{"lemma":"circum-stagno","pos":"v.","gen":"-stagno","def":"n., to be poured forth all around: lacrimae, Tert. Pud. 22. circumstantĭa, ae, f. circumsto (post-Aug. and rare). A standing round, a surrounding: hostium, Gell. 3, 7, 5: aquae, aëris, Sen. Q. N. 2"},"circum-sto":{"lemma":"circum-sto","pos":"v.","gen":"-sto","def":"n. and a. (the perf. and pluperf. having the same form with those of circumsisto, and a similar meaning, it is sometimes doubtful to which verb a form belongs), to stand around in a circle"},"circum-stringo":{"lemma":"circum-stringo","pos":"v.","gen":"-stringo","def":", strictum, 3, v. a. (post-class.). * To bind about, to put on: aliquid alicui rei: habitus cervicibus circumstrictus, Tert. Pall. 1.— To tie around, to surround"},"circum-tergeo":{"lemma":"circum-tergeo","pos":"v.","gen":"-tergeo","def":"a., to wipe around, Cato, R. R. 76, 2. circum-termĭno, āre, 1, v. a., to bound or limit round about, Isid. Orig. 7, 8, 39. circum-tĕro, ĕre, v. a., to rub around, poet. for, to stand close around"},"circum-tollo":{"lemma":"circum-tollo","pos":"v.","gen":"-tollo","def":"a., to remove on every side: corticem, Cael. Aur. Acut. 3, 4, 42."},"circum-tondeo":{"lemma":"circum-tondeo","pos":"","gen":"-tondeo","def":"circumtonsus. circum-tŏno, ui, 1, v. a., to thunder around"},"circum-uallo":{"lemma":"circum-vallo","pos":"v.","gen":"-vallo","def":"a., to surround with a wall, to circumvallate"},"circum-uecto":{"lemma":"circum-vecto","pos":"","gen":"-vecto","def":"freq. a., to carry around: Penates, Sil. 3, 291.—Hence, Esp., mid., to ride or sail around (rare): Ligurum oram, Liv. 41, 17, 7"},"circum-uerro":{"lemma":"circum-verro","pos":"","gen":"-verro","def":"circumversus. circumversĭo, ōnis, f. circumverto, a turning round, moving around, revolving (post-Aug. and rare): manus (in gesturing), * Quint. 11, 3, 105 Spald.: cursus annui, Amm. 26, 1"},"circum-uoluo":{"lemma":"circum-volvo","pos":"v.","gen":"-volvo","def":", vŏlūtum, 3, v. a., only with se or mid., to roll one's self around, to roll round, revolve, wind, or twine around (prob. not ante-Aug.): aliquid or alicui rei: magnum sol circumvolvitur annum"},"circumactus":{"lemma":"circumactus","pos":"","gen":"","def":"circumago, a moving or turning round (post-Aug.): assiduus caeli, Sen. Q. N. 7, 2, 2; Censor. de Die Nat. 23: corporis, Plin. 8, 30, 44, § 105"},"circumcirco":{"lemma":"circumcirco","pos":"v.","gen":"","def":"n., = circumeo, to go round: regiones, Amm. 31, 2, 23 Eyssenh."},"circumculco":{"lemma":"circumculco","pos":"","gen":"","def":"circumcalco. circum-cŭmŭlo, āre, 1, v. a., to heap or pile up around: exanimes circumcumulantur acervi, Stat. Th. 10, 655."},"circumductor":{"lemma":"circumductor","pos":"adv.","gen":"","def":"id., one who leads about, converts another, Tert. adv. Val. 10."},"circumductum":{"lemma":"circumductum","pos":"","gen":"","def":"circumduco, II. B.; in rhet., a period, Quint. 9, 4, 22. circumductus, a, um, Part., from circumduco."},"circumductus":{"lemma":"circumductus","pos":"","gen":"","def":"circumduco. The circumference of a figure, Quint. 1, 10, 43.—* Motion in a circle, a revolution: orbium, Macr. Somn. Scip. 2, 1, 5. circŭm-ĕo or circŭĕŏ (v. circum, III."},"circumflexus":{"lemma":"circumflexus","pos":"","gen":"","def":"circumflecto, a bending round, a vault, arch: mundi, Plin. 2, 1, 1, § 1: caeli, id. 6, 34, 39, § 212.— A winding, circuit: qui (Tanais) per sinuosos labitur circumflexus, Amm. 22, 8, 27. circum -flo"},"circumfossor":{"lemma":"circumfossor","pos":"","gen":"","def":"circumfodio, one who digs around something, Plin. 17, 24, 37, § 227. circumfossūra, ae, f. id., a digging round, Plin. 17, 26, 39, § 247. circum-fractus, a, um, Part. , broken off around: turbo"},"circumgressus":{"lemma":"circumgressus","pos":"","gen":"","def":"circumgredior (perh. only in Amm.). * Abstr., a going about' rapidi, Amm. 22, 2, 3.— * Concr., the compass, circuit of a thing' amplissimi palus Maeotis, Amm. 22, 8, 30. circumhăbĭtātor = περίοικος"},"circumiectus":{"lemma":"circumjectus","pos":"","gen":"","def":"circumicio, a casting around, a surrounding, encompassing (rare but class.): (aether) qui terram tenero circumjectu amplectitur, with soft embrace, Cic. poet N. D. 2, 25"},"circumplexus":{"lemma":"circumplexus","pos":"","gen":"","def":"circumplector, an encompassing, embracing, or folding around; only in abl. sing., Plin. 8, 11, 11, § 32"},"circumscriptor":{"lemma":"circumscriptor","pos":"adv.","gen":"","def":"circumscribo. * (Acc. to circumscribo, II. C.) A defrauder, deceiver, cheat, * Cic. Cat. 2, 4, 7; * Juv. 15, 136; Sen. Exc. Contr. 6, 3"},"circumspector":{"lemma":"circumspector","pos":"","gen":"-seeing","def":"circumspicio, a watcher, watchman, spy (late Lat.): septem circumspectores sedentes in excelso ad speculandum, Vulg. Ecclus. 37, 18: Deus, i. e. all-seeing, id. ib. 7, 12."},"circumspectus":{"lemma":"circumspectus","pos":"","gen":"","def":"circumspicio, P. a."},"circumuentor":{"lemma":"circumventor","pos":"","gen":"","def":"id., a deceiver, defrauder, Lampr. Alex. Sev. 66. circumventōrĭus, a, um, adj. circumventor, deceitful, fraudulent: obsequia, Aug. Conf. 3, 3. circumventus, a, um, Part., from circumvenio."},"circus":{"lemma":"circus","pos":"adj.","gen":"-course","def":", = κίρκος [kindr. with κρίκος; Dor. κίρκος, and κορώνη"},"cirrus":{"lemma":"cirrus","pos":"","gen":"","def":"(used mostly in plur.), a (natural) lock, curl, ringlet, or tuft of hair (rare): cirri, Varr. ap. Non. p. 94, 21"},"cirta":{"lemma":"Cirta","pos":"","gen":"-ses","def":", = Κίρτα, an important town in Numidia, now Constantine, Mel. 1, 6, 1; Plin. 5, 3, 2, § 22; Sall. J. 21, 2; 26, 1; 101, 1; 102, 1"},"cis":{"lemma":"cis","pos":"prep.","gen":"-ce","def":"pronom. stem ki-, whence -ce; Gr. ἐ-κεῖ; cf.: hic, sic, etc. (far more rare than the kindr. citra), on this side (opp. uls, ultra, and trans; cf. Varr. L. L. 5, § 83 Müll.; Liv. 5, 35, 4"},"cisseus":{"lemma":"Cisseus","pos":"","gen":"","def":", = Κισσεύς. A king of Thrace; acc. to a later myth, father of Hecuba, Verg. A. 5, 537; Hyg. Fab. 91; 911; who is on this account called Cissēïs, Verg. A. 7, 320 Serv."},"cissis":{"lemma":"Cissis","pos":"","gen":"","def":", a town in Hispania Tarraconensis, Liv. 21, 60, 7 sq. Alschefski ad loc. cissītis, is, f., = κισσῖτις, a precious stone of the color of ivy-leaves, Plin. 37, 11, 73, § 188. cissŏs, i, f."},"cista":{"lemma":"cista","pos":"","gen":"","def":", = κίστη, a wooden box or basket, often woven of slips or twigs, used for keeping money, clothes, books, fruit, etc. In gen., Plin. 15, 17, 18, § 60; 16, 40, 77, § 209; Cic. Verr. 2, 3, 85, § 197"},"cistella":{"lemma":"cistella","pos":"","gen":"","def":"dim. cista, a small chest or box, Plaut. Cist. 3, 7; 4, 1, 3 sq.; id. Rud. 4, 4, 65 sq.; Ter. Eun. 4, 6, 15"},"cisterna":{"lemma":"cisterna","pos":"","gen":"","def":"cista, a subterranean reservoir for water, a cistern, Varr. R. R. 1, 11, 2; Col. 1, 5, 2; Sen. Ep. 86, 3; Plin. 31, 3, 21, § 31; 36, 23, 52, § 173; Mart. 3, 56, 1"},"cisthos":{"lemma":"cisthos","pos":"","gen":"","def":", = κίσθος (usu. κίστος), a shrubby plant with red blossoms, Plin. 24, 10, 48, § 81. Cis-tĭbĕris, e, adj., = cis Tiberim, on this side of the Tiber: quinqueviri, Dig. 1, 2, 2, § 33: magistratus"},"claeon":{"lemma":"Claeon","pos":"","gen":"","def":", = Κλαίων (wailing), a fountain in Phrygia, Plin. 31, 2, 16, § 19. clăgălōpes, is, f., a species of eagle, = pygargus, Schol. Juv. 11, 138. clam (old access. form callim, or, acc. to Cod. Gu. 1"},"clango":{"lemma":"clango","pos":"v.","gen":"-class","def":", ĕre, 3, v. n. kindred with crocio, glocio; cf. clamo and κλάζω, to clang, to sound, resound (rare"},"clangor":{"lemma":"clangor","pos":"","gen":"","def":"clango, a sound, clang, noise (mostly poet. and in Aug. prose). Of wind instruments: tubarum, Verg. A. 2, 313; cf. id. ib. 8, 526; 11, 192; Luc. 1, 237; Sil. 2, 19; Stat. Th. 3, 651; Flor. 4, 2, 67"},"claterna":{"lemma":"Claterna","pos":"","gen":"","def":", a fortress in Gallia Cisalpina, near Bononia, on the river Guaderna, Cic. Fam. 12, 5, 2; id. Phil. 8, 2, 6"},"claudaster":{"lemma":"claudaster","pos":"","gen":"","def":", a little lame, Gloss."},"claudeo":{"lemma":"claudeo","pos":"v.","gen":"","def":", sum, ĕre, v. n. claudus, ground form of the more common claudico, to limp or halt, to be lame, to falter (mostly trop.). Claudeo: an ubi vos sitis, ibi consilium claudeat"},"claudo":{"lemma":"claudo","pos":"","gen":"","def":"claudeo. claudus (clūdus, Plaut. Ps. 2, 2, 64; and clōdus, Arat. Act. Apost. 266), a, um, adj. root klu-; v. claudo"},"clausala":{"lemma":"Clausala","pos":"","gen":"","def":", a river of Illyria, now the Khiri or Drinossi, Liv. 44, 31, 3 (al. Clausula). claustra (clostra, Cato, R. R. 13, 3; 135, 2), ōrum, n. (in sing.: claustrum, i, rare, Caes. Germ. Arat. 197"},"claustrum":{"lemma":"claustrum","pos":"","gen":"","def":"claustra init. clausŭla, ae. f. claudo. A close, conclusion, end (cf. claudo, I. B.; in good prose"},"clausum":{"lemma":"clausum","pos":"","gen":"","def":"claudo fin. clausūra or clūsūra, ae, f. claudo. * (Cf. claustra, I. A.) A lock, bar, bolt, Inscr. Orell. 2510.— (Cf. claustra, II. B.) A castle, fort (late Lat.), Cod. Just. 1, 27, 2, § 4"},"clausus":{"lemma":"Clausus","pos":"","gen":"","def":", a Sabine proper name: Attus Clausus, ancestor of the gens Claudia, Liv. 2, 16, 4; 10, 8, 6; Verg. A. 7, 707; Tac. A. 4, 9 al. clāva, ae, f. root cel- of percello"},"claxendix":{"lemma":"claxendix","pos":"","gen":"","def":"clacendix. Clāzŏmĕnae, ārum, f., = Κλαζομεναί, a town on the coast of Ionia, upon a peninsula of the Bay of Smyrna, now Kelisman or Vourla, Mel. 1, 17, 3; Plin. 5, 29, 31, § 117"},"clepsydra":{"lemma":"clepsydra","pos":"","gen":"-glasses","def":", = κλεψύδρα, an instrument for measuring time by water, similar to our sand-glasses, a water-clock, clepsydra, Sen. Ep. 24, 19; Veg. Mil. 3, 8; App. M. 3, p. 130, 19"},"clitae":{"lemma":"Clitae","pos":"","gen":"","def":", a town of Macedonia, Liv. 44, 11, 4."},"cliuius":{"lemma":"clivius","pos":"adj.","gen":"","def":": auspicia, which forbid any thing to be done, Paul. ex Fest. p. 64, 10 Müll.: avis, Plin. 10, 14, 17, § 57. clīvōsus, a, um, adj. clivus, hilly, full of hills"},"clostrum":{"lemma":"clostrum","pos":"","gen":"","def":"claustrum. Clōthō (apparently used only in nom. and acc.), = Κλωθώ, the spinner, among the three Parcoe, Ov. F. 6, 757; id. Ib. 241"},"clura":{"lemma":"clura","pos":"","gen":"","def":", = πίθηκος, an ape, Vet. Gloss. Labb. (Gr. κολούρα).—Hence, clūrīnus, a, um, adj. clura, of or pertaining to apes: pecus, Plaut. Truc. 2, 2, 14; Arn. 3, p. 110"},"cluster":{"lemma":"cluster","pos":"","gen":"","def":"clyster. clūsūra, ae, v. clausura. clūsus, a, um, v. claudo, P. a. Clŭtŏmestōrĭdysarchĭdes, ae, m., a comically formed name, Plaut. Mil. 1, 1"},"clysmus":{"lemma":"clysmus","pos":"","gen":"","def":", = κλυσμός, a clyster (late Lat. for clyster), Scrib. Comp. 155; 194"},"clytus":{"lemma":"Clytus","pos":"","gen":"","def":"Son of Aegyptus, Hyg. Fab. 170.— A companion of Phineus, Ov. M. 5, 87.— A proetor of the Acarnanians, Liv. 36, 11, 8 sq."},"cnaeus":{"lemma":"Cnaeus","pos":"","gen":"","def":"Gneus. cnasonas acus, quibus mulieres caput scalpunt, Paul. ex Fest. p. 52, 17 Müll. cnēcus (cnīcus), i, m., = κνῆκος, safflower: Carthamus tinctorius, Linn.; Plin. 21, 15, 53, § 90"},"coa":{"lemma":"Coa","pos":"","gen":"","def":"Cos, II. Cŏa, ae, f., a fictitious nickname of Clodia [from coeo"},"coccum":{"lemma":"coccum","pos":"","gen":"","def":", = κὀκκος (a berry, and specif.), The berry that grows upon the scarlet oak (Quercus coccifera, Linn."},"coccyx":{"lemma":"coccyx","pos":"","gen":"","def":", = κόκκυξ, a cuckoo, Plin. 10, 9, 11, § 25 sq. cocētum, i, n. perh. from κυκεών, a kind of food prepared from honey and poppies, Tert. adv. Val. 12"},"cochlis":{"lemma":"cochlis","pos":"","gen":"-shell","def":", = κοχλίς, a precious stone like a snail-shell in form, Plin. 37, 12, 74, § 194."},"cochloe":{"lemma":"cochloe","pos":"","gen":"-fishes","def":", = κόχλοι, a kind of shell-fishes with spiral shells, Plin. 32, 11, 53, § 147 Sillig N. cr. cocĭātor, ōris, m., = μεταβόλος, cocio, a broker, Gloss. Vet. (prob. for cocĭōnātor). cŏcĭbĭlis"},"cocta":{"lemma":"cocta","pos":"","gen":"","def":", v. coquo, I. A. fin. coctăna, v. cottana. coctĭlĭcĭus, a, um coctilis, of or pertaining to dried wood: taberna, in which dry wood is sold, Capit. Pert. 3"},"coctor":{"lemma":"coctor","pos":"","gen":"","def":"id. (more rare than coquus), a cook, Petr. 95, 8: calcis, a limeburner, Edict. Diocl. p. 19; Cod. Th. 14, 6, 1. coctūra, ae, f. id., a cooking; a melting"},"codomannus":{"lemma":"Codomannus","pos":"","gen":"","def":", cognomen of the last Persian king Darius, Just. 10, 3"},"coel":{"lemma":"coel","pos":"","gen":"","def":"caelum. Coela (ōrum, n.), Euboeae, Κοῖλα τῆς Εὐβοίας, a deeply-indented maritime region in Euboea, Liv. 31, 47, 1; Val. Max. 1, 8, 10"},"coeles":{"lemma":"coeles","pos":"","gen":"","def":"cael-. coelĭăcus, a, um, adj., = κοιλιακός. Relating to the abdomen or to the stomach: dolor, pain in the stomach, Cato, R. R. 125 (in Cels. 4, 12, written as Greek).— Subst.: coelĭăca, ae"},"coena":{"lemma":"coena","pos":"","gen":"","def":"cena. coenācŭlārius, coenācŭlum, v. cenac-. coenātĭcus, coenātio, etc., v. cen-. coenĭto, coeno, v. cen-. coenŏbīta, ae, m. coenobium, a cloister-brother, a monk, Hier. Ep. 22, n. 34 al."},"coenon":{"lemma":"coenon","pos":"","gen":"","def":", = κοινόν, a kind of eyesalve, Inscr. Orell. 4234. coenōsĭtas, coenōsus, v. caen-. coenŭla, coenŭlentus, v. cen-."},"coenum":{"lemma":"coenum","pos":"","gen":"","def":"caenum. cŏ-ĕo, īvi or ii (e. g. coierunt, Caes. B. G. 6, 22: coiere, Lucr. 6, 452; Prop. 3 (4), 24, 18; Ov. M. 4, 83 al.: cŏĭisse, Verg. A. 12, 709: coisse, Prop. 3 (4), 15, 8. Ov. F. 6, 94"},"coepto":{"lemma":"coepto","pos":"","gen":"","def":"freq. a. and n. coepio (mostly poet., and in Tac."},"coeptum":{"lemma":"coeptum","pos":"","gen":"","def":"coepio, I. B. fin. coeptus, a, um, Part., from coepio."},"coeptus":{"lemma":"coeptus","pos":"","gen":"","def":"coepio, a beginning, undertaking (perh. only in the foll. exs.): primos suos quasi coeptus appetendi fuisse, ut, etc., * Cic. Fin. 4, 15, 41 Madv (cf.: coeptat appetere, id. ib. 5, 9"},"coero":{"lemma":"coero","pos":"","gen":"","def":"curo. cŏ-erro, āre, v. n., to go or wander about together, Dig. 1, 15, 3, § 3. coerŭla, coerŭlĕus, etc., v. caer-."},"coetus":{"lemma":"coetus","pos":"","gen":"","def":"2. coitus. Coeus (dissyl. Coe-us), i, m., = Κοῖος, a Titan, father of Latona, Verg. G. 1, 279 Serv.; id. A. 4, 179; Ov. M. 6, 185; 6, 366; Prop. 3 (4), 9, 48; Val. Fl. 3, 224"},"cognoscenter":{"lemma":"cognoscenter","pos":"adv.","gen":"","def":", v. cognosco, P. a. 1. cognoscĭbĭlis, e, adj. cognosco, recognizable, discernible (late Lat.), Boëth. Arist. Anal. Post. 1, 541.—Adv.: cogno-scĭbĭlĭter"},"cohum":{"lemma":"cohum","pos":"","gen":"-beam","def":", the strap by which the plough-beam was fastened to the yoke; so called, acc. to Paul. ex Fest. p. 39, 4, a cohibendo"},"coiro":{"lemma":"coiro","pos":"","gen":"","def":"curo. cŏĭtĭo, ōnis, f. coëo. * A coming or meeting together, a meeting: prima coitio est acerrima, Ter. Phorm. 2, 2, 32.— Esp. A uniting, banding together. In gen. (rare): societatis, Dig. 17, 2"},"colchi":{"lemma":"Colchi","pos":"","gen":"","def":"Colchis, II. B. fin. Colchĭs, ĭdis (ĭdŏs, Val. Fl. 2, 423; 5, 202), f., = Κολχίς, a province in Asia, east of the Black Sea, celebrated on account of the golden fleece and Medea; now Mingrelia"},"collum":{"lemma":"collum","pos":"","gen":"-class","def":"(ante-class. access. form collus, i, m., Naev., Cato, Lucil., Att., Caecil., Varr. ap. Non. p. 200, 14 sq.; Plaut. Capt. 2, 2, 107; 4, 3, 2"},"collus":{"lemma":"collus","pos":"","gen":"","def":"collum. collūsĭo (conl-), ōnis, f. colludo, II., a secret, deceptive understanding, collusion, * Cic. Verr. 2, 3, 13, § 33: inter raptae patrem et raptorem, Sen. Contr. 2, 11, 22: per collusionem"},"collybista":{"lemma":"collybista","pos":"","gen":"-changer","def":", = κολλυβιστής, a money-changer, banker, Hier. in Matt. 21, 12. collybus (collŭbus), i, m., = κόλλυβος [prob. of Phoenicio-Semitic origin, kindr. with the Heb. , to change]"},"colpa":{"lemma":"colpa","pos":"","gen":"","def":"culpa. cŏlŭber, bri, m. akin to celer, a serpent, snake (poet.), Verg. G. 2, 320; 3, 418; id. A. 2, 471 (an imitation of Hom. Il. 22, 93: ὡς δὲ δράκων, κ.τ.λ.); Ov. M. 4, 620; 11, 775"},"com-mando":{"lemma":"com-mando","pos":"v.","gen":"-mando","def":", sum, ĕre, v. a., to chew (late Lat.): frondes myrti, Ser. Samm. 36, 684: radix commansa, Marc. Emp. 8. commandūcātĭo, ōnis, f. commanduco, a chewing, mastication (late Lat.): olivarum"},"com-martyr":{"lemma":"com-martyr","pos":"","gen":"-martyr","def":", a fellow-martyr, companion in martyrdom, Tert. Anim. 55. com-mascŭlo, āre, v. a. masculus, to make manly, firm, courageous, to invigorate, embolden (post-class.): animum, App. M. 2, p. 124"},"com-mingo":{"lemma":"com-mingo","pos":"v.","gen":"-mingo","def":"a., to pollute, defile: lectum potus (by vomiting), * Hor. S. 1, 3, 90: suavia comminxit spurcā salivā tuā, Cat. 78, 8"},"com-mulco":{"lemma":"com-mulco","pos":"v.","gen":"-mulco","def":"a., to beat violently, App. M. 8, p. 214, 30. commūnālis, e, adj. commune, belonging to the community: loca, Aggen. p. 41 Goes."},"com-mundo":{"lemma":"com-mundo","pos":"v.","gen":"-mundo","def":", ātum, 1, v. a., to cleanse, purify wholly (very rare): vasa eluere et commundare, Col. 12, 18, 3: mulier ornata, sed non commundata, Dig. 34, 2, 25, § 10"},"com-palpo":{"lemma":"com-palpo","pos":"v.","gen":"-palpo","def":"a., to stroke, caress, Aug. Serm. Temp. 214. com-par (conp-), păris, adj. (abl. compari, Liv. 36, 44, 7: compare, Ov. Am. 3, 5, 38; id. A. A. 3, 359"},"com-pastor":{"lemma":"com-pastor","pos":"","gen":"-pastor","def":", a fellow-herdsman, Hyg. Fab. 187. compastus, a, um, Part., from compasco. com-pătĭor, passus, 3, v. dep. (late Lat.). To suffer with one, Tert. adv. Prax. 29"},"com-pauper":{"lemma":"com-pauper","pos":"","gen":"-pauper","def":", a companion in poverty, fellow-pauper (late Lat.), Aug. Serm. 25 ex 50 homil. c. 3. com-păvesco, ĕre, v. inch. n., to be thoroughly terrified, to be very much afraid: animus, Gell. 1, 23, 9"},"com-pecco":{"lemma":"com-pecco","pos":"v.","gen":"-pecco","def":"n., to err or commit a fault together (late Lat.), Cael. Aur. Acut. 2, 12"},"com-pendo":{"lemma":"com-pendo","pos":"v.","gen":"-pendo","def":"a., to weigh, balance together: compendium, quod, cum compenditur, una fit, Varr. L. L. 5, § 183 Müll. compensātĭo (conp-), ōnis, f. compenso, a weighing, balancing of several things together. Prop."},"com-pernis":{"lemma":"com-pernis","pos":"adj.","gen":"-pernis","def":"perna, with the knees bent inwards, knock-kneed, Lucil. ap. Non. p. 26, 3; Plaut. Fragm. ap. Fest. p. 375, 20 Müll."},"com-pingo":{"lemma":"com-pingo","pos":"v.","gen":"-pingo","def":"a., to paint over; only trop.: Aristarchi ineptiae, quibus aliena carmina compinxit, disguised, covered, Sen. Ep. 88, 39."},"com-pinguesco":{"lemma":"com-pinguesco","pos":"","gen":"-pinguesco","def":"inch. n., to thicken to a solid substance, Tert. Anim. 25. compĭtālāris, e, v. compitalis. compĭtālĭcĭus or -tĭus, a, um, adj. compitalis, of or belonging to the compitalia: dies, Cic. Att. 7, 7"},"com-planto":{"lemma":"com-planto","pos":"v.","gen":"-planto","def":", ātum, 1, v. a., to plant together (late Lat.); only trop., Vulg. Rom. 6, 5; Ambros. Abrah. 2, 11, 80 fin.: virtutibus, id. Ep. 42 fin. com-plătōnĭcus, i, m., a fellow-Platonist, Sid. Ep. 4, 11."},"com-plaudo":{"lemma":"com-plaudo","pos":"v.","gen":"-plaudo","def":"n., to applaud together, Paul. Nol. 18, 8."},"com-possessor":{"lemma":"com-possessor","pos":"","gen":"-possessor","def":", a jointpossessor, Tert. Idol. 14. compostūra, ae, v. compositura."},"com-praes":{"lemma":"com-praes","pos":"","gen":"-praes","def":", a joint-surety, Paul. ex Fest. p. 39, 10 Müll."},"com-pransor":{"lemma":"com-pransor","pos":"","gen":"-pransor","def":", a companion in a banquet, a boon companion, Cic. Phil. 2, 39, 101. comprĕcātĭo, ōnis, f. comprecor, a common or public imploring of a deity: sollennis deorum, Liv. 39, 15, 2"},"com-presbyter":{"lemma":"com-presbyter","pos":"","gen":"-presbyter","def":", a fellowpresbyter, Aug. Ep. 228. compressē, adv."},"com-pugno":{"lemma":"com-pugno","pos":"v.","gen":"-pugno","def":"n. To fight or contend together (post-class.), Gell. 12, 5, 3; 14, 5, 4; 14, 5 fin."},"com-purgo":{"lemma":"com-purgo","pos":"v.","gen":"-purgo","def":"a., to purify completely: visum, Plin. 20, 13, 50, § 127. compŭtābĭlis, e, adj. computo, that may be computed, computable: impendium, Plin. 19, 8, 41, § 139. compŭtātĭo, ōnis, f. id., a computing"},"combustum":{"lemma":"combustum","pos":"","gen":"","def":", v comburo, I. B. combustūra, ae, f , a burning (post-class.), Apic. 4, 4, § 179; Vulg. Lev. 13, 28"},"cominius":{"lemma":"Cominius","pos":"","gen":"","def":", a Roman proper name, Cic. Clu. 36, 99; id. Brut 78, 271; Cic. Verr. 2, 4, 10, § 24."},"comma":{"lemma":"comma","pos":"","gen":"","def":", = κόμμα. In gram. A division of a period (in Cic. Or. 62, 211; 66, 223; Quint. 9, 4, 22, written as Greek; pure Lat. incisum), Quint. 1, 8, 6"},"commensus":{"lemma":"commensus","pos":"","gen":"","def":"commetior, a due proportion or measure, symmetry (a word of Vitr., as transl. of the Gr. συμμετρία), Vitr. 1, 3, 2; 6 praef."},"commento":{"lemma":"commento","pos":"","gen":"","def":"act., collat. form of 1. commentor, q. v. (cf. Prisc. p. 797 P.), to delineate, sketch"},"commentor":{"lemma":"commentor","pos":"","gen":"","def":"freq. dep. . Prop., to consider thoroughly, meditate, think over, study, deliberate, weigh, prepare one's self mentally, etc. (class.). Ingen. Absol.: ut cito commentatus est"},"commentum":{"lemma":"commentum","pos":"","gen":"","def":"comminiscor fin. commentus, a, um, Part., from comminiscor. com-mĕo (conm-), āvi, ātum, 1, v. n., to go and come, pass to and fro: remeare redire, ut commeare ultro citroque ire"},"commis":{"lemma":"commis","pos":"","gen":"","def":"gummi. com-miscĕo (con-m-), miscui, mixtum, or mistum, 2, v. a., to mix or mingle together, to intermingle (class.). Lit., constr. with cum, with abl., with in or inter"},"commissor":{"lemma":"commissor","pos":"","gen":"","def":"committo, II. B. 4., a perpetrator, Ennod. 1, 4. commissōrĭus, a, um, adj. committo"},"commissum":{"lemma":"commissum","pos":"","gen":"","def":", v. committo fin. commissūra, ae, f. committo. Prop., a joining or connecting together"},"commixtim":{"lemma":"commixtim","pos":"","gen":"","def":"commistim. commixtĭo (-mist-), ōnis, f. commisceo, a mixing, mingling (post-class.), Marc. Emp. 8; cf. Vet. Gloss.: commixtio χύμα."},"commixtum":{"lemma":"commixtum","pos":"","gen":"","def":", v. commisceo fin. commixtūra (-mist-), ae. f. commisceo, a mixing, mingling, Cato, R. R. 157, 1 dub. commixtus, a, um, Part., from commisceo. commōbĭlis, e, adj. commoveo, easily moving"},"commoris":{"lemma":"Commoris","pos":"","gen":"","def":", a fortress in Cilicia, near Mount Amanus, Cic. Fam. 15, 4, 9. commŏro, āre, v. commoror. com-mŏror (conm-), ātus, 1, v. dep. n. and a. (act. access. form ‡ commŏro, āre"},"compactum":{"lemma":"compactum","pos":"","gen":"","def":", v. compaciscor, II. compactūra, ae, f. compingo, a joining together; only concr., a joint, Vitr. 4, 7, 4."},"compactus":{"lemma":"compactus","pos":"","gen":"","def":"compingo."},"comperco":{"lemma":"comperco","pos":"","gen":"","def":"comparco. com-pĕrēgrīnus, i, m., a fellowstranger, Sid. Ep. 7, 17 fin. compĕrendĭnātĭo, ōnis, f. comperendino, a deferring of the time (of trial) to the third day or later (post-Aug.), Sen. Ep. 97, 5"},"compertus":{"lemma":"compertus","pos":"","gen":"","def":"comperio."},"compes":{"lemma":"compes","pos":"","gen":"","def":"q. compos, acc, to Prisc. 1, p. 553. compesco, pescui (pescitum, Prisc. p. 887 P.), 3, v. a. compes, to fasten together, to confine, hold in check, to repress, curb"},"complecto":{"lemma":"complecto","pos":"","gen":"","def":"complector fin. complector (conp-), plexus, 3, v. dep. (in signif. mostly coinciding with amplector), prop., to entwine around a person or thing (cf. amplector"},"complex":{"lemma":"complex","pos":"adj.","gen":"","def":"complico, closely connected with one, confederate, participant (late Lat.): dii consentes et complices, i. e. agreeing, Arn. 3, p. 123 (v. consentes).— With gen., Cod. Th. 6, 4, 21; Ambros. Off. 3, 4"},"complexo":{"lemma":"complexo","pos":"","gen":"-class","def":"freq. a. complecto = complector, to encompass, embrace closely, clasp around (post-class. and rare), Coripp. 1, 104: artissime complexatum aliquem recipere, App. M. 10, p. 249, 18."},"complexor":{"lemma":"complexor","pos":"","gen":"","def":"freq. a., to embrace closely (late Lat.): eos, Vulg. Marc. 10, 16. complexus, a, um, Part., from complector. complexus (con-), ūs, m. complector, a surrounding, encompassing, encircling, embracing"},"compostus":{"lemma":"compostus","pos":"","gen":"","def":"compono init. com-pōtātĭo, ōnis, f., a drinking together, as transl. of the Gr. συμπόσιον (perh. only in Cic.), Cic. Sen. 13, 45"},"comprendo":{"lemma":"comprendo","pos":"","gen":"","def":"comprehendo."},"compresso":{"lemma":"compresso","pos":"","gen":"","def":", ātum, 1, v. freq. a. id., to press, oppress (late Lat.), Tert. contr. Gnost. 3"},"compressus":{"lemma":"compressus","pos":"","gen":"","def":"comprimo, a pressing together, compression (only in abl. sing.). In gen.: semen tepefactum vapore et compressu suo diffindit (terra), * Cic. Sen. 15, 51: pennarum, Plin. 11, 28, 34, § 98. — Esp."},"comptor":{"lemma":"comptor","pos":"","gen":"","def":"1. como, one who adorns; only trop.: fabricarum, Cassiod. Var. 4, 51. comptŭlus, a, um, adj. dim. , luxuriously decked: juvenes, Hier. Ep. 128, n. 4."},"comptus":{"lemma":"comptus","pos":"","gen":"","def":"1. como, P. a."},"compulso":{"lemma":"compulso","pos":"","gen":"-class","def":"freq. . To press or strike violently (post-class. and rare), App. M. 7, p. 197, 16.— To contend or fight together, Tert. Apol. 20; cf. compulsatio."},"compulsor":{"lemma":"compulsor","pos":"","gen":"","def":"id. (late Lat.). Lit., a driver (of cattle), Pall. Jun. 2, 3. — Transf., one who asks or forces to a payment, an exacter of money, Amm. 22, 6, 1; Cod. Th. 8, 10, 3 and 4"},"compulsus":{"lemma":"compulsus","pos":"","gen":"","def":"compello, a (hostile) striking together, App. M. 8, p. 203, 6. Compulterĭa, ae, f., a little town in Samnium, Liv. 23, 39, 6, 24, 20, 5. compunctĭo, ōnis, f. compungo. Lit., a puncture: ligni"},"comtus":{"lemma":"comtus","pos":"","gen":"","def":"1. como, P. a."},"con-callesco":{"lemma":"con-callesco","pos":"","gen":"-callesco","def":"inch. ; lit., to become hard or callous"},"con-candesco":{"lemma":"con-candesco","pos":"conj.","gen":"-candesco","def":"inch. n., to glow, be inflamed, Manil. 1, 874 ex conj. (Codd. excanduit). Concăni, ōrum, m., = Κωγκανοί, a savage people of Cantabria in Hispania Tarraconensis"},"con-carno":{"lemma":"con-carno","pos":"v.","gen":"-carno","def":"a., to unite or clothe with flesh, to incarnate (post-class. and very rare), Tert. Carn. Christ. 20"},"con-cerno":{"lemma":"con-cerno","pos":"v.","gen":"-cerno","def":"a., to mix, mingle together (as in a sieve, in order to separate by sifting): carni, Aug. Conf. 5, 10 fin."},"con-cerpo":{"lemma":"con-cerpo","pos":"v.","gen":"-cerpo","def":"a. carpo, to pluck, pull, or tear in pieces, to rend (rare). Prop.: epistulas, Cic. Att. 10, 12, 3: librum, Liv. 38, 55, 11; cf. Gell. 4, 18, 12"},"con-certo":{"lemma":"con-certo","pos":"v.","gen":"-certo","def":"a., to contend with any one zealously or warmly (rare but class."},"con-cingo":{"lemma":"con-cingo","pos":"v.","gen":"-cingo","def":"a., to gird, surround completely, Theod. Prisc. 4, 1. concinnātĭcĭus or -tĭus, a, um, adj. concinno, skilfully prepared: mensula, App. M. 2, p. 119. concinnātĭo, ōnis"},"con-cinnus":{"lemma":"con-cinnus","pos":"adj.","gen":"-cinnus","def":"etym. dub.; acc. to Non. p. 43, 21, and p. 59, 30, from cinnus, fitly, skilfully put together or joined, well adjusted, beautiful (class."},"con-crasso":{"lemma":"con-crasso","pos":"v.","gen":"-crasso","def":"a., to thicken, make thick: liquida, Cael. Aur. Tard. 4, 3, 62. con-crĕātus, a, um, adj., created together (eccl. Lat.): diabolus sanctis angelis, Claud. Mam. Stat. Anim. 3, 7"},"con-cresco":{"lemma":"con-cresco","pos":"v.","gen":"-cresco","def":"perf. sync. concresse, Ov. M. 7, 416), v. n., to grow together; hence with the prevailing idea of uniting, and generally of soft or liquid substances which thicken"},"con-crispo":{"lemma":"con-crispo","pos":"v.","gen":"-crispo","def":", ātum, 1, v. a. (very rare, and only in part. pres. and perf.). To curl, to give a curling, undulatory motion to: concrispati cincinni, Vitr. 4, 1, 7: umores (se) concrispantes, id. 8, 1"},"con-crispus":{"lemma":"con-crispus","pos":"adj.","gen":"-crispus","def":", curled (late Lat.), Isid. Orig. 19, 22, 20. con-crŭcĭfīgo, āre, v. a., to crucify together: aliquem alicui, Sid. Ep. 6, 1"},"con-culco":{"lemma":"con-culco","pos":"v.","gen":"-culco","def":"a. calco, to tread under foot, to crush or bruise by treading. * Prop.: vinaceos in dolia picata, Cato, R. R. 25.—More freq., Trop. (cf. calco, I. B.). To tread down, trample upon in a hostile manner"},"con-cumbo":{"lemma":"con-cumbo","pos":"v.","gen":"-cumbo","def":"n. Lit., to lie together, lie in numbers (very rare): Evandri profugae concubuere boves, Prop. 4 (5), 1"},"con-curro":{"lemma":"con-curro","pos":"v.","gen":"-curro","def":"redupl. concucurrit, Flor. 4, 2, 33 Duker N. cr.: concucurrisse, Cato ap. Prisc. p. 901 P., and Suet. Caes. 15"},"con-curso":{"lemma":"con-curso","pos":"","gen":"-curso","def":"freq. n. and a. To come violently together, to rush together, clash: concursare, coire et dissultare vicissim (semina), Lucr. 3, 396.—Far more freq. and class., To go to and fro, run about"},"con-curuo":{"lemma":"con-curvo","pos":"v.","gen":"-curvo","def":"a., to curve, bend, Laber. ap. Macr. S. 2, 7 (Com. Rel. v. 118 Rib.). concussĭbĭlis, e, adj. concutio, that can be shaken, Tert. adv. Marc. 1, 25. concussĭo, ōnis, f. id. (post-Aug.), a shaking"},"con-demno":{"lemma":"con-demno","pos":"v.","gen":"-demno","def":"a. damno. To sentence, condemn, convict (in good prose; rare in the poets). In judicial proceedings (opp. absolvo)"},"con-densus":{"lemma":"con-densus","pos":"adj.","gen":"-densus","def":", very dense, close, thick (mostly poet.; most freq. in Lucr.; not in Cic.): condensa contextaque magis (corpora), Lucr. 4, 57: condensa atque arta nubila, id. 6, 466"},"con-depso":{"lemma":"con-depso","pos":"v.","gen":"-depso","def":"a., to knead together (ante-class.), Cato, R. R. 40, 2; so id. ib. 76, 2"},"con-dignus":{"lemma":"con-dignus","pos":"adj.","gen":"-dignus","def":", wholly deserving, very worthy (very rare"},"con-disco":{"lemma":"con-disco","pos":"v.","gen":"-disco","def":"a. * To learn with or in company with one: ex his, qui mihi Athenis condidicere, App. Flor. 3, n. 18, p. 362, 8.— To learn carefully, eagerly, or well"},"con-do":{"lemma":"con-do","pos":"v.","gen":"-do","def":"a. con- = cum, and 2. do, lit., to bring, lay or put together (very freq. in all periods and species of composition). With the access. idea of uniting, to put or join together into a whole, to form"},"con-doctor":{"lemma":"con-doctor","pos":"","gen":"-doctor","def":", a fellow-teacher (eccl. Lat.), Aug. Conf. 1, 9 fin. condoctus, a, um, Part. and P. a., v. condoceo. con-dŏlĕo, ēre, v. n., to feel severe pain, to suffer greatly (eccl. Lat.). Universum corpus"},"con-dormisco":{"lemma":"con-dormisco","pos":"","gen":"-dormisco","def":"inch. , to go entirely to sleep, to fall asleep; only in Plaut. Curc. 2, 3, 81; id. Rud. 2, 7, 13; id. Mil. 3, 2, 13"},"con-dulco":{"lemma":"con-dulco","pos":"v.","gen":"-dulco","def":"a., to sweeten, Vulg. Ecclus. 27, 26; 40, 18. condŭlus, i, m., v. condylus. condūplĭcātĭo, ōnis, f. conduplico, a doubling (very rare)"},"con-fermento":{"lemma":"con-fermento","pos":"v.","gen":"-fermento","def":"a., to leaven, ferment through and through, Tert. adv. Val. 31. confĕro, contŭli, collātum (conl-), conferre, v. a. To bring, bear, or carry together, to collect"},"con-festim":{"lemma":"con-festim","pos":"adv.","gen":"-festim","def":"kindr. with festinus, festino, from fero, immediately, speedily, without delay, forthwith (class. in prose and poetry): abi ad thensaurum jam confestim clanculum, Plaut. Trin. 3, 3"},"con-findo":{"lemma":"con-findo","pos":"v.","gen":"-findo","def":"a., to cleave asunder, divide: tellurem ferro, Tib. 4, 1, 173."},"con-fingo":{"lemma":"con-fingo","pos":"v.","gen":"-fingo","def":"a., to form, fashion, fabricate (class., esp. in a trop. signif.). Prop.: nidos, Plin. 10, 32, 47, § 91: favos et ceras, id. 11, 5, 4, § 11: verbum, Varr. L. L. 5, § 7 Müll."},"con-firmo":{"lemma":"con-firmo","pos":"v.","gen":"-firmo","def":"a., to make firm, establish, strengthen, confirm (class., esp. in prose). In gen. (prop. and trop.): stipites confirmare et stabilire, Caes. B. G. 7, 73: ali hōc vires nervosque confirmari putant"},"con-flaccesco":{"lemma":"con-flaccesco","pos":"","gen":"-flaccesco","def":"inch. n., to grow quite languid: fluctus conflaccescunt, subside, Gell. 2, 30, 2. conflāges (-flōges, -frāges), places exposed on all sides to the winds, Paul. ex Fest. p. 40, 10 Muuml;ll."},"con-flammo":{"lemma":"con-flammo","pos":"v.","gen":"-flammo","def":"a., to inflame, Cael. Aur. Tard. 4, 7, 98. conflātĭlis, e, adj. conflo, II., cast, molten (late Lat.): Juppiter, Prud. στεφ. 10, 295"},"con-flo":{"lemma":"con-flo","pos":"v.","gen":"-flo","def":"a., to blow together, to blow up, stir up. Of fire, to kindle, light. Prop.: ignem, Plaut. Rud. 3, 4, 59"},"con-formo":{"lemma":"con-formo","pos":"v.","gen":"-formo","def":"a., to form, fashion, shape symmetrically or skilfully (several times in Cic."},"con-fultus":{"lemma":"con-fultus","pos":"adj.","gen":"-fultus","def":"fulcio, pressed together ( = confertus, conglomeratus): corpora, Lucr. 2, 98 Lachm. N. cr."},"con-fundo":{"lemma":"con-fundo","pos":"v.","gen":"-fundo","def":"a. To pour, mingle, or mix together (class. in prose and poetry). Prop.: unā multa jura (cocos), Plaut. Most. 1, 3, 120"},"con-gaudeo":{"lemma":"con-gaudeo","pos":"v.","gen":"-gaudeo","def":"n., to rejoice with one (eccl. Lat.): alicui, Tert. adv. Gnost. c. 13"},"con-gesto":{"lemma":"con-gesto","pos":"v.","gen":"-gesto","def":"a., to bring or carry together, Aug. de Pecc. Merit. 1, 28"},"con-glisco":{"lemma":"con-glisco","pos":"v.","gen":"-glisco","def":"n., to be kindled up, i. e. to become illustrious, Plaut. Trin. 3, 2, 52. conglŏbātim, adv. conglobo, in heaps, in a mass (late Lat.), Aug. Conf. 7, 7 fin. conglŏbātĭo, ōnis, f. id., a heaping"},"con-graeco":{"lemma":"con-graeco","pos":"v.","gen":"-graeco","def":"a. graecor, āri, to lavish on banquets like the Greeks, to squander in luxury: aurum, Plaut. Bacch. 4, 4, 91. congrātŭlātĭo, ōnis, f. congratulor, a wishing of joy; congratulation, Val. Max. 9, 3, 5"},"con-grex":{"lemma":"con-grex","pos":"adj.","gen":"-grex","def":"(post-class.). Of the same herd or flock: equinis armentis, App. M. 7, p. 194, 41: aves, Sol. 2 dub. (al. congregatae).—Hence, In gen., collected in flocks or multitudes: catervas"},"con-nascor":{"lemma":"con-nascor","pos":"v.","gen":"-nascor","def":"dep, to be born at the same time, to be born with (late Lat.): ET (QVI) CONNATVS FVERIT DE CONIVGE MEA, Inscr. Orell. 5013.— Transf., to arise together with: laus nobilitatis connascitur"},"con-necto":{"lemma":"con-necto","pos":"","gen":"-necto","def":"conecto. connexĭo, connexīvus, connex-us, etc., v. conex-. connītor, connīvĕo, etc., v. coni-. connūbĭālis, connūbĭum, con-nūbĭālĭter, v. conub-. connūdātus, a, um, Part. , wholly naked, Plin. 28, 7"},"con-quasso":{"lemma":"con-quasso","pos":"v.","gen":"-quasso","def":", ātum, 1, v. a. To shake severely (several times in Lucr. and Cic., elsewh. very rare"},"con-scendo":{"lemma":"con-scendo","pos":"v.","gen":"-scendo","def":"a. and n. . In gen., to mount, to ascend (in prose rare before the Aug. per.) Lit. With acc.: currum, Lucr. 6, 47; Prop. 2 (3), 18, 13; Ov. Tr. 3, 8, 1; Curt. 5, 10, 12: montes, * Cat. 64, 126"},"con-scindo":{"lemma":"con-scindo","pos":"v.","gen":"-scindo","def":"a., to tear or rend to pieces (very rare). Lit: pallulam, Plaut. Truc. 1, 1, 32: vestem, Ter. Eun. 5, 1, 4: epistulam, Cic. Fam. 7, 18, 4: ipsam capillo for illius capillum, Ter. Eun. 4, 3"},"con-scisco":{"lemma":"con-scisco","pos":"v.","gen":"-scisco","def":"a. Publicists' t. t., to approve of, decree, determine or resolve upon something in common: populi jussa vetita quom suffragio consciscentur, Cic. Leg. 3, 3"},"con-sector":{"lemma":"con-sector","pos":"v.","gen":"-sector","def":"dep., to follow, pursue, strive after eagerly, both in a good and bad sense. Lit., to attend eagerly or continually"},"con-seruo":{"lemma":"con-servo","pos":"v.","gen":"-servo","def":"perf. conservasse more usu. than conservavisse, acc. to Quint. 1, 6, 21), v. a., to retain, keep something in existence, to hold up, maintain, to preserve, leave unhurt or safe (class."},"con-seruus":{"lemma":"con-servus","pos":"","gen":"-servus","def":", a fellow-slave, a companion in servitude, Plaut. Capt. 2, 1, 52; id. Mil. 2, 1, 67; Ter. Ad. 3, 3, 71; Cic. Clu. 64, 179; id. Fam. 12, 3, 2; Hor. S. 1, 8, 9; 2, 7, 80; Tac. Agr. 31"},"con-signo":{"lemma":"con-signo","pos":"v.","gen":"-signo","def":"a. To furnish with a seal, to affix, put one's seal to, to seal, to sign, subscribe (in good prose). Prop.: tabellas, Plaut. Curc. 2, 3, 90"},"con-sisto":{"lemma":"con-sisto","pos":"v.","gen":"-sisto","def":"n., to place one's self anywhere, to stand still, stand, halt, stop, make a stop (very freq. and class. in prose and poetry). Lit. In gen.: jam hunc non ausim praeterire, quin consistam et conloquar"},"con-sors":{"lemma":"con-sors","pos":"adj.","gen":"-sors","def":"m. and f. Sharing property with one (as brother, sister, relative), living in community of goods, partaking of in common: consortes, ad quos eadem sors, Varr. L. L. 6, § 65 Müll."},"con-splendesco":{"lemma":"con-splendesco","pos":"v.","gen":"-splendesco","def":"n., to shine very much: tecta, Jul. Val. Rer. Gest. Alex. M. 3, 66. con-spŏlĭo, āvi, 1, v. a., to rob (late Lat.), Hier. Ep. 98, 21 fin. conspŏlĭum, ii, n., a kind of sacrificial cake, acc. to Arn. 7"},"con-sponsor":{"lemma":"con-sponsor","pos":"","gen":"-sponsor","def":"A joint surety, Cic. Fam. 6, 18, 2"},"con-spurco":{"lemma":"con-spurco","pos":"v.","gen":"-spurco","def":", ātum, 1, v. a., to defile, pollute (rare): omnia taetro sapore, * Lucr. 6, 22: (juvenem) per vim, Suet. Ner. 35; Col. 8, 3 fin."},"con-stagno":{"lemma":"con-stagno","pos":"v.","gen":"-stagno","def":"n., of fluids, = congelo, to cause to stand, to congeal, Fronto, p. 2198 P. constans, antis, Part. and P. a., from consto."},"con-sterno":{"lemma":"con-sterno","pos":"v.","gen":"-sterno","def":"a. To strew over, cover by strewing, bestrew, to thatch, floor, pave, spread, cover (class. in prose and poetry). With abl.: tabernacula caespitibus, Caes. B. C. 3, 96: cubilia gallinarum paleis"},"con-sto":{"lemma":"con-sto","pos":"v.","gen":"-sto","def":"Clem. 1, 19, 3; Plin. 18, 5, 6, § 30; Luc. 2, 17; Mart. 10, 41, 5"},"con-stringo":{"lemma":"con-stringo","pos":"v.","gen":"-stringo","def":"a., to draw together, bind together, to bind, tie up (class. in prose and poetry). Lit. In gen.: vineam alligato recte, dum ne nimium constringas, Cato, R. R. 33, 1: sarcinam, Plaut. Trin. 3, 2"},"con-surgo":{"lemma":"con-surgo","pos":"v.","gen":"-surgo","def":"n., to raise one's self, to rise (esp. of a multitude), to rise up together, stand up"},"con-technor":{"lemma":"con-technor","pos":"v.","gen":"-technor","def":"dep. techna, to devise plots, contrive tricks: vide modo ne illic sit contechnatus quipiam, Plaut. Ps. 4, 6, 34. contectus, a, um, Part., v. contego. con-tĕgo, xi, ctum, 3, v. a., to cover"},"con-tendo":{"lemma":"con-tendo","pos":"v.","gen":"-tendo","def":"a. and n., to stretch, stretch out vigorously, to draw tight, strain. Lit. (rare and mostly poet.): arcum, Verg. A. 12, 815; Ov. M. 6, 286; id. R. Am. 435: tormenta, Sisen. ap. Non. p. 258, 27"},"con-terno":{"lemma":"con-terno","pos":"v.","gen":"-terno","def":"a. terni, to put three things together, to make threefold (late Lat.), Hyg. Lim. p. 191 Goes.—Hence, P. a.: conternans, ntis, three years old: vitula conternans, Hier. in Isa. 5, 15, 5. con-tĕro"},"con-testor":{"lemma":"con-testor","pos":"v.","gen":"-testor","def":"dep., to take or call to witness. Prop. In gen.: deos hominesque, Cic. Verr. 2, 4, 29, § 67"},"con-texo":{"lemma":"con-texo","pos":"v.","gen":"-texo","def":"a. and n. Act., to weave, entwine, braid, join together"},"con-tigno":{"lemma":"con-tigno","pos":"v.","gen":"-tigno","def":", ātum, 1, v. a. tignum, to join together with beams, to furnish with beams, joists, or rafters (rare), Caes. B. C. 2, 15; Vitr. 1, 5; Plin. 9, 3, 2, § 7."},"con-tingo":{"lemma":"con-tingo","pos":"v.","gen":"-tingo","def":"a. and n. tango, to touch on all sides. to touch, take hold of, seize (very freq. in all periods and species of composition). Lit. In gen.: facile cibum terrestrem rostris, Cic. N. D. 2, 47"},"con-tollo":{"lemma":"con-tollo","pos":"v.","gen":"-tollo","def":"a., to bring together: contollam gradum, will go to meet him ( = contra tollam, Wagn. ad loc.), Plaut. Aul. 5, 6 (ap. Non. p. 82, 1). con-tŏnat, v. impers."},"con-tristo":{"lemma":"con-tristo","pos":"v.","gen":"-tristo","def":"a. tristis, to make sad or sorrowful, to sadden, afflict (except in Caelius, perh. not ante-Aug.). Lit.: contristavit haec sententia Balbum, Cael. ap. Cic. Fam. 8, 9"},"con-trunco":{"lemma":"con-trunco","pos":"v.","gen":"-trunco","def":"a., to cut down or to pieces (ante- and post-class. and very rare): filios, Plaut. Bacch. 4, 9, 51"},"con-tundo":{"lemma":"con-tundo","pos":"v.","gen":"-tundo","def":"21, 27, 101, § 174; 28, 16, 62, § 221 al.), 3 (perf. contūdit, Enn. ap. Prisc. p. 891 P., or Ann. v. 482 Vahl."},"con-turbo":{"lemma":"con-turbo","pos":"v.","gen":"-turbo","def":"a., to throw into disorder or confusion, to confuse, derange, disorder, confound (rare, but class. in prose and poetry; most freq. in Lucr. and Cic."},"con-turmo":{"lemma":"con-turmo","pos":"v.","gen":"-turmo","def":"a., to arrange in squadrons (turmae). se, Amm. 16, 12, 37."},"con-uallo":{"lemma":"con-vallo","pos":"v.","gen":"-vallo","def":"a.; lit., to surround with an intrenchment"},"con-uector":{"lemma":"con-vector","pos":"","gen":"-vector","def":", he who goes with one (on board ship, etc.), a fellow-passenger (very rare), * Cic. Att. 10, 17, 1"},"con-uergo":{"lemma":"con-vergo","pos":"v.","gen":"-vergo","def":"n., to incline together (late Lat.): punctus quo cuncta convergunt, Isid. Orig. 3, 12, 1. converrĭtor, ōris, m. converro, one who sweeps together, Cat. ap. App. Mag. p. 277, 13. con-verro (or -vorro)"},"con-uerso":{"lemma":"con-verso","pos":"","gen":"-verso","def":"freq. * Act., to turn round: animus se ipse conversans, * Cic. Univ. 8 med.—More freq., In medial form conversor, ātus, 1 (post-Aug.; a favorite word of Seneca"},"con-uescor":{"lemma":"con-vescor","pos":"v.","gen":"-vescor","def":"dep., to eat with one (eccl. Lat.), Aug. Ep. 18 al. con-vestĭo, īvi, ītum, 4 (arch. inf. pass. convestirier, Poët. ap. Cic. Tusc. 1, 28, 69), v. a., to clothe, cover with clothing (rare"},"con-uexo":{"lemma":"con-vexo","pos":"v.","gen":"-vexo","def":"a., to press or squeeze together (post-class., and perh. only in the foll. exs.): (multitudo) me male miseram convexavit, Soror Appii Caeci in Gell. 10, 6, 2: animal, Veg. Art. Vet. 3, 18, 6: membra"},"con-uinco":{"lemma":"con-vinco","pos":"v.","gen":"-vinco","def":"a., to overcome, conquer"},"con-uoluo":{"lemma":"con-volvo","pos":"v.","gen":"-volvo","def":"a., to roll together, roll up, roll round (first freq. in the post-Aug. per., esp. in Pliny the elder). Lit.: ignis semina convolvunt venti, Lucr. 6, 200 sq.: se sol, Cic. Div. 1, 23"},"concapit":{"lemma":"concapit","pos":"","gen":"","def":"Tab. in a passage in Fest. p. 365 Müll.; cf. Dirks. Uebersicht, etc., p. 433 sq. con-captīvus, i, m., a fellow-captive, Hier. Ep. 119"},"concentor":{"lemma":"concentor","pos":"","gen":"","def":"id., one who sings with others in a chorus (late Lat.), συνῳδός, Gloss. Isid. 7, 12, 28. con-centŭrĭo, āre, v. a.; lit., to assemble by centuries"},"concentus":{"lemma":"concentus","pos":"","gen":"","def":"concino, sounds blending harmoniously together, symphony, harmony, harmonious music (class.). Prop. In gen.: ille sonus...qui acuta cum gravibus temperans varios aequabiliter concentus efficit"},"concepto":{"lemma":"concepto","pos":"","gen":"","def":"freq. a. id. (late Lat.). To conceive, become pregnant, Arn. 4, p. 141.— To conceive in mind: majora, Amm. 31, 10, 5."},"conceptum":{"lemma":"conceptum","pos":"","gen":"","def":", v. concipio, I. B. fin., and II. B. fin. conceptus, a, um, Part., from concipio."},"conceptus":{"lemma":"conceptus","pos":"","gen":"","def":"concipio. A collecting, gathering: (Tiberis) novenorum conceptu dierum navigabilis, after the water had been stopped nine days, Plin. 3, 5, 9, § 53.— Concr., a collection"},"concertor":{"lemma":"concertor","pos":"v.","gen":"","def":"dep.; collat. form of concerto, q. v. (late Lat.), Vulg. Sap. 15, 9"},"concessus":{"lemma":"concessus","pos":"","gen":"","def":"concedo, a permitting, conceding, concession, permission, leave (in good prose, but used only in abl. sing.): Caesaris concessu, Caes. B. G. 7, 20: datur concessu omnium huic aliquis ludus aetati"},"concha":{"lemma":"concha","pos":"","gen":"-fish","def":", = κόγχη. A bivālve shell-fish, mussel, Plaut. Rud. 2, 1, 8; 2, 1, 15; Lucr. 2, 374; Verg. G. 2, 348; Plin. 9, 33, 52, § 102: legere, Cic. de Or. 2, 6, 22"},"conchis":{"lemma":"conchis","pos":"","gen":"","def":", = κόγχος, a kind of bean boiled with the pods, Mart. 13, 7; Juv. 3, 293; 14, 131"},"concinno":{"lemma":"concinno","pos":"v.","gen":"","def":"a. id., to join fitly together, to order, arrange appropriately, to set right, adjust: concinnare est apte componere, Paul. ex Fest. p. 38, 1 Müll. (cf. compono, II. B."},"conclausus":{"lemma":"conclausus","pos":"","gen":"","def":"concludo init. conclāvātae dicebantur, quae sub eādem erant clave, Paul. ex Fest. p. 58, 1 Müll. conclāve, is (gen. plur. heterocl. conclaviorum, Vitr. 6, 3, 8: conclavium, id. 7, 9)"},"concordis":{"lemma":"concordis","pos":"","gen":"","def":"concors init. concordĭtas, ātis, f. concors, = concordia, concord, Pac. ap. Non. 88, 20 (Trag. Rel. v. 188 Rib.). concordĭter, adv., v. concors fin."},"concordo":{"lemma":"concordo","pos":"v.","gen":"","def":"n. and a. . Neutr., to agree together, to be united, be of one mind, to harmonize (rare but class.). Of persons: concordare cum aliquo, * Ter. Phorm. 2, 3"},"concursus":{"lemma":"concursus","pos":"","gen":"","def":"concurro. A running or flocking together, a concourse, assembly: fit concursus per vias, Plaut. Ep. 2, 2, 27"},"concussor":{"lemma":"concussor","pos":"","gen":"","def":"id., one who extorts money by threats (late Lat.), Tert. Fuga in Persec. 12 sq. concussūra, ae, f. id., = concussio, II., the extorting of money by threats (late Lat.), Tert. ad Scap. 13. concussus"},"concussus":{"lemma":"concussus","pos":"","gen":"","def":"concutio, a shaking, concussion; only in abl. sing. in Lucr. 6, 290; 6, 547 (in Plin. 35, 16, 55, § 193, the better read. is concussis"},"conductor":{"lemma":"conductor","pos":"","gen":"","def":"conduco, one who hires a thing, a lessee, farmer, tenant, a contractor (rare, and mostly absol.): (histrionum), Plaut. As. prol. 3: (pecoris), Cato, R. R. 150, 2: (agri), Caes. B. C. 3, 21"},"conductrix":{"lemma":"conductrix","pos":"","gen":"","def":"conductor, she who hires or rents a thing, Cod. Just. 3, 3, 10; 4, 65, 24; 5, 12, 18. conductus, a, um, Part., and con-ductum, i, n., v. conduco, I. B. 2. a. fin."},"conductus":{"lemma":"conductus","pos":"","gen":"","def":"conduco, a contraction: oculorum, Cael. Aur. Acut. 2, 15, 95."},"condurdum":{"lemma":"condurdum","pos":"","gen":"","def":", a plant: Saponaria vaccaria, Linn.; Plin. 26, 5, 14, § 26. con-dūro, āre, v. a., to harden, to make very hard: ferrum, Lucr. 6, 969."},"condus":{"lemma":"condus","pos":"","gen":"","def":"condo, one who lays up (provisions), opp. promus, Plaut. Ps. 2, 2, 14. condylōma, ătis, n., = κονδύλωμα, a swelling in the parts about the anus, Cels. 6, 18, 8; 7, 30, 2; Scrib. Comp. 224 and 225 al."},"confector":{"lemma":"confector","pos":"","gen":"","def":"id.. A maker, preparer, finisher (rare): coriorum, i. e. a tanner, Firm. Math. 3, 9, 7: purpurae, i. e. a dyer, Vop. Aur. 29: negotiorum, Cic. Verr. 2, 2, 44, § 108: totius belli, id. Fam. 10, 20"},"confectrix":{"lemma":"confectrix","pos":"","gen":"","def":"confector, II., that which destroys, a destroyer: vetustas, Lact. 7, 11, 5 (after a passage of Cicero). confectūra, ae, f. conficio, a making, preparing (post-Aug. and rare): mellis, Col. 9, 14"},"confertim":{"lemma":"confertim","pos":"adv.","gen":"","def":"confertus, A. 2., in a compact body, closely; in milit. lang., of marches, battles, etc. (very rare): sese recipere, Sall. J. 50, 5: et pugnant et cedunt, Liv. 31, 43, 3"},"conferua":{"lemma":"conferva","pos":"","gen":"","def":"conferveo, a kind of water plant (so called on account of its healing power), Plin. 27, 8, 45, § 69 (in App. Herb. 59 called consolida). confervē-făcĭo, ĕre, v. a. id."},"conferuesco":{"lemma":"confervesco","pos":"","gen":"","def":"ferveo, and Prisc. p. 866 P.), 3, v. inch. n. , to begin to boil, to become heated, grow hot (perh. not ante-Aug.). In gen. Prop.: aër conclusus versando confervescit, Vitr. 5, 3"},"confessor":{"lemma":"confessor","pos":"","gen":"","def":"confiteor (only in eccl. Lat.; opp. negator), a confessor of Christianity, a martyr, Lact. Mort. Pers. 35; Sid. Ep. 7, 17 al. confessōrĭus, a, um, adj. confessor"},"confexim":{"lemma":"confexim","pos":"","gen":"","def":"conficio init. con-fībŭla, ae, f., a wooden double cramp, clincher: ligneae, Cato, R. R. 12. confĭcĭens, entis, v. conficio, P. a. confĭcĭo, fēci, fectum, 3 (perf. subj. confexim, Plaut. Truc. 4, 4"},"conficto":{"lemma":"conficto","pos":"","gen":"","def":"freq. a. id., to counterfeit, feign, Naev. ap. Varr. L. L. 7, § 107 Müll."},"confictor":{"lemma":"confictor","pos":"","gen":"","def":"id., he who fabricates a thing, a fabricator (late Lat.): falsi, Paul. Nol. 21, 4. confictus, a, um, Part., from confingo, and from configo. con-fĭdejussor, ōris, m., a joint-surety (jurid. Lat.)"},"confisco":{"lemma":"confisco","pos":"v.","gen":"","def":", ātum, 1, v. a. fiscus (post-Aug.). To lay up in a chest: quam (summam) et confiscatam semper repositamque habuerat, Suet. Aug. 101.— Trop.: felices pauperes, qui totam animam in confiscato habent"},"confit":{"lemma":"confit","pos":"","gen":"","def":"conficio init. confĭtĕor, fessus, 2 (arch. inf. confiterier, Plaut. Cist. 1, 3, 22), v. dep. fateor, to acknowledge, confess, own, avow (an error, mistake, or a fact previously denied or doubted"},"conflicto":{"lemma":"conflicto","pos":"","gen":"","def":"freq. a. id.. In gen., to strike together violently; hence, trop., mid., to fight with, contend or struggle with (rare): qui cum ingeniis conflictatur ejusmodi, Ter. And. 1, 1, 66"},"conflictus":{"lemma":"conflictus","pos":"","gen":"","def":"confligo, a striking together (rare, and mostly in the abl. sing.). In gen. Prop.: conflictu atque tritu lapidum elici ignem, Cic. N. D. 2, 9, 25: nubium, id. Div. 2, 19, 44: corporum (in conflict)"},"confoedustus":{"lemma":"confoedustus","pos":"adj.","gen":"-foedus","def":"con-foedus"},"conformis":{"lemma":"conformis","pos":"adj.","gen":"","def":"forma, similar, like (late Lat.), Sid. Ep. 4, 12.—With gen.: conformes fieri imaginis Filii sui, Vulg. Rom. 8, 29."},"conforto":{"lemma":"conforto","pos":"v.","gen":"","def":"a. fortis, to strengthen much (late Lat."},"confringo":{"lemma":"confringo","pos":"v.","gen":"","def":"a. frango, to break in pieces (class. in prose and poetry). Prop.: hirneam, Cato, R. R. 81: pultando pedibus paene confregi hasce ambas (fores), Plaut. Most. 2, 2, 25: fores caedendo, Liv. 26, 46"},"confrixo":{"lemma":"confrixo","pos":"v.","gen":"","def":"a. frigo, to roast or fry with something: aliquid cum oleo, Theod. Prisc. 1, 6. confŭga, ae, comm. confugio, one who takes refuge somewhere, a refugee (late Lat.), Cod. Just. 1, 12, 6 al. confŭgēla"},"congestim":{"lemma":"congestim","pos":"adv.","gen":"","def":"id., heaped together, in heaps: congestim et acervatim jacere, App. Mag. p. 296, 40. congestĭo, ōnis, f. id., lit. a bringing together"},"congressor":{"lemma":"congressor","pos":"","gen":"","def":"id., one who meets or assembles with, Ambros. Ep. 27, 16. congressus, a, um, Part., from congredior."},"congressus":{"lemma":"congressus","pos":"","gen":"","def":"congredior, a coming or going together, in a friendly or hostile manner (class. in prose and poetry). A friendly meeting, a social assembly, conference, conversation"},"congrus":{"lemma":"congrus","pos":"","gen":"","def":"conger. congrŭus, a, um, adj. congruo, II., agreeing, fit, suitable"},"coniecto":{"lemma":"conjecto","pos":"","gen":"-class","def":"freq. a. conicio (ante-class."},"coniector":{"lemma":"conjector","pos":"","gen":"","def":"conicio, I. B. 1., he who interprets, explains, or divines something, an interpreter. In gen.: conjectore Oedipo orationi opus est, Plaut. Poen. 1, 3, 34.— In partic., a diviner"},"coniectrix":{"lemma":"conjectrix","pos":"","gen":"","def":"conjector, a female soothsayer or interpreter of dreams, Plaut. Mil. 3, 1, 99. conjectūra, ae, f. conicio, I. B. 2., a putting together of facts or indications"},"coniectus":{"lemma":"conjectus","pos":"","gen":"","def":"conicio (rare but class."},"conitum":{"lemma":"conitum","pos":"","gen":"","def":"coniptum. cōnīum, ii, n., = κώνειον, hemlock (pure Lat. cicuta), Ambros. Hexaem. 3, 9. cōnīventĭa, ae, f. coniveo, II. B., connivance (post-class. and rare): Ciceronis"},"coniunctim":{"lemma":"conjunctim","pos":"adv.","gen":"","def":"conjungo, unitedly, in common, jointly, together (rare): ratio habetur hujus omnis pecuniae, Caes. B. G. 6, 19: referri de eā re, S. C. ap. Cic. Fam. 8, 8, 5: petere auxilium, Nep. Att. 10, 5: legare"},"coniunctrix":{"lemma":"conjunctrix","pos":"","gen":"","def":"conjunctor, conjungo, that which joins or unites together (late Lat.): voluntas, Aug. Trin. 11, 10. conjunctus, a, um, Part. and P. a., from conjungo."},"coniunctus":{"lemma":"conjunctus","pos":"","gen":"","def":"conjungo, a connection, conjunction, only in abl. sing., Varr. L. L. 10, § 24 Müll."},"coniux":{"lemma":"conjux","pos":"","gen":"","def":"conjunx. conl-. Words thus beginning, v. under coll-. conm-. Words thus beginning, v. under comm-."},"connus":{"lemma":"Connus","pos":"","gen":"-player","def":", a Greek lute-player, who taught Socrates music, Cic. Fam. 9, 22, 3. Cŏnōn, ōnis (Gr. acc. Conona, Just. 6, 1), m., = Κόνων. A renowned general of the Athenians, whose life was written by Nepos"},"conp-":{"lemma":"conp-","pos":"","gen":"","def":"comp-. con-quādro, āvi, ātum, 1, v. a. and n. (very rare). Act., to make square: aurum, Varr. ap. Non. p. 131, 14: perticas (just before: dolare in quadrum), Col. 8, 3, 7.— Neutr."},"conquaero":{"lemma":"conquaero","pos":"","gen":"","def":"conquiro."},"conquaestor":{"lemma":"conquaestor","pos":"","gen":"","def":"conquisitor. conquassātĭo, ōnis, f. conquasso, a severe shaking, a shattering: conquassatio et perturbatio totius valetudinis corporis, Cic. Tusc. 4, 13, 29."},"conquestus":{"lemma":"conquestus","pos":"","gen":"","def":"conqueror, a violent complaint (very rare, and only in abl. sing.), Liv. 8, 7, 22; Sil. 10, 291"},"conquistor":{"lemma":"conquistor","pos":"","gen":"","def":"conquisitor. conr. Words thus beginning, v. under corr."},"consabrum":{"lemma":"Consabrum","pos":"adj.","gen":"-saburensis","def":", a town of Hispania Tarraconensis, south of Toletum, now Consuegra, Itin. Anton. p. 446.—Hence, Con-saburensis, e, adj., of Consabrum, Inscr. Grut. 402, 5"},"consaep-":{"lemma":"consaep-","pos":"","gen":"","def":"consep-. con-saepĭo (-sēpĭo), no perf., saeptum (consiptum, Enn. ap. Paul. ex Fest. p. 62, 10 Müll."},"consaeptum":{"lemma":"consaeptum","pos":"","gen":"","def":", v. consaepio, II. B."},"consaeptus":{"lemma":"consaeptus","pos":"","gen":"","def":"consaepio, a hedging in, fencing round, Curt. 9, 1, 32 Zumpt (al. in conspectu). consălūtātĭo, ōnis, f. consaluto, a greeting, esp. of several, a mutual salutation (rare"},"conscensus":{"lemma":"conscensus","pos":"","gen":"","def":"conscendo, an ascending, mounting (eccl. Lat.), Hilar. Trin. 1, 20"},"conscriptor":{"lemma":"conscriptor","pos":"","gen":"-class","def":"id. (post-class.), a composer, writer, author, Quint. Decl. 277; Arn. 1, p. 33 sq.; Aug. Ep. 18. conscriptus, a, um, Part., from conscribo. con-sĕco, cŭi, ctum, 1, v. a. (rare"},"consecto":{"lemma":"consecto","pos":"","gen":"","def":"consector fin."},"consensus":{"lemma":"consensus","pos":"adv.","gen":"","def":"consentio, agreement, accordance, unanimity, concord (class."},"consentes":{"lemma":"consentes","pos":"adj.","gen":"","def":"[etym. dub.; prob. for consentientes; v Corss. Nachtr. 281"},"conserua":{"lemma":"conserva","pos":"","gen":"-slave","def":"conservus, a (female) fellow-slave. Prop., Plaut. Cas. 1, 20; id. Mil. 4, 8, 30; Ter. Eun. 2, 3, 75; Varr. R. R. 1, 17, 5 al."},"consessor":{"lemma":"consessor","pos":"","gen":"","def":"consido, one who sits near or by a person or thing, an assessor (several times in Cic.; elsewh. rare); in a court of justice, Cic. Fin. 2, 19, 62; at a feast, id. Fl. 11, 24; id. Phil. 5, 5, 13"},"consessus":{"lemma":"consessus","pos":"","gen":"-class","def":"consido. Abstr., a sitting together or with (only post-class.): communis ei, Lampr. Alex. Sev. 4: consessum alicui offerre, the permission to sit with one, id. ib. 18"},"consiptum":{"lemma":"consiptum","pos":"","gen":"","def":"consaepio init. consistĭo, ōnis, f. consisto, a standing still (late Lat.): loci, in a place, Gell. 16, 5, 10; Macr. S. 6, 8, 20."},"conspector":{"lemma":"conspector","pos":"","gen":"","def":"id., he who sees or beholds; an inspector, beholder (eccl. Lat.): cordis Deus, Tert. Or. 13; id. Cult. Fem. 2, 13. conspectus, a, um, Part. and P. a., from conspicio."},"conspectus":{"lemma":"conspectus","pos":"","gen":"","def":"conspicio, a seeing, looking at, a look, sight, view, the range or reach of sight, the power of sceing (freq., and class. in prose and poetry). Lit.: casurusne in conspectum videatur animus"},"constans":{"lemma":"Constans","pos":"","gen":"","def":", a Roman proper name, Aur. Vict. Epit. 41; Eutr. 10, 9."},"constanter":{"lemma":"constanter","pos":"adv.","gen":"","def":", v. consto, P. a. fin. constantĭa, ae, f. 1. constans. A firm standing, steadiness, firmness, immutability, unchangeableness, constancy, perseverance (in good prose"},"constantia":{"lemma":"Constantia","pos":"","gen":"","def":", a Roman proper name, Lact. Mort. Pers. 15, 1, 6"},"constat":{"lemma":"constat","pos":"","gen":"","def":"consto. con-stellātĭo, ōnis, f. stella, a collection of stars supposed to exert an influence upon human affairs, a constellation (late Lat.), Amm. 29, 2, 27; Capitol. Gord. 20"},"consterno":{"lemma":"consterno","pos":"v.","gen":"","def":"a. strengthened collat. form of 1. consterno, acc. to II.. To stretch upon the ground, to overcome: pecorum in modum consternatos (Gallos) caedunt fugantque, Liv. 38, 17, 7.—Far more freq."},"constricto":{"lemma":"constricto","pos":"adv.","gen":"","def":"freq. , to draw together"},"consulto":{"lemma":"consulto","pos":"v.","gen":"-clause","def":"freq. a. consulo. To reflect, consider maturely, to consult, take counsel, deliberate. In gen. (class.). With acc.: quid illaec illic in consilio duae secreto consultant? Plaut. Bacch. 5, 2"},"consultor":{"lemma":"consultor","pos":"","gen":"","def":"consulo. * One who maturely considers, reflects, takes counsel upon a thing, etc., Afran. ap. Non. p. 5, 6, 8 (Com. Rel. v. 332 Rib.).— One who gives counsel, a counsellor"},"consultrix":{"lemma":"consultrix","pos":"","gen":"","def":"1. consultor, she who has a care for, provides: consultrix et provida utilitatum opportunitatumque omnium natura, Cic. N. D. 2, 22, 58."},"consultum":{"lemma":"consultum","pos":"","gen":"","def":", v. consulo, P. a., 2."},"consultus":{"lemma":"consultus","pos":"","gen":"","def":"consulo, P. a., 1."},"consumptor":{"lemma":"consumptor","pos":"","gen":"","def":"id., a consumer, destroyer (very rare): omnium ignis (connected with confector), * Cic. N. D. 2, 15, 41.—Of fire, Ambros. in Luc. 7, § 132.—Of the wasters of their property, spendthrifts"},"consumptrix":{"lemma":"consumptrix","pos":"","gen":"","def":"consumptor, she who wastes, consumes (late Lat.): terra omnium corporum, Serv. ad Verg. A. 6, 395. consumptus, a, um, Part., from consumo. con-sŭo, sŭi, sūtum, 3, v. a. To sew, stitch"},"consus":{"lemma":"Consus","pos":"","gen":"","def":"perh. from condo, a very ancient deity of Italy, a god of the earth and of agriculture, giver of fertility"},"contactus":{"lemma":"contactus","pos":"","gen":"","def":"1. contingo (except once in Sall., perh. not ante-Aug.), a touching, touch, contact. In gen., Verg. A. 3, 227; Ov. M. 4, 52; 11, 111; Col. 11, 3, 50; Plin. 8, 15, 16, § 40; 33, 7, 40, § 122"},"contanter":{"lemma":"contanter","pos":"adv.","gen":"","def":", v. cunctor, P. a., 1. fin. contārĭi, ōrum, m. contus, a kind of soldiers armed with pikes, pike-bearers, κοντοφόροι, Inscr. Grut. 40, 2 and 3. contātio, ōnis, f., v. cunctatio. contātus, a, um"},"contemnenter":{"lemma":"contemnenter","pos":"adv.","gen":"","def":", in a contemptuous manner, Non. p. 515, 33. contemnĭ-fĭcus, a, um, adj. contemno-facio, despising, contemptuous, scornful, Lucil. ap. Non. p. 88, 29. con-temno (also contempno"},"contemplo":{"lemma":"contemplo","pos":"v.","gen":"-class","def":"a. (anteand post-class.; collat. form of contemplor), to survey, behold, observe, consider, contemplate, etc."},"contentus":{"lemma":"contentus","pos":"","gen":"","def":"contendo, P. a."},"contextim":{"lemma":"contextim","pos":"adv.","gen":"","def":"contexo, in a connected manner, connectedly (very rare): luto nidificantes paene contextim, * Plin. 10, 53, 74, § 147"},"contextor":{"lemma":"contextor","pos":"","gen":"","def":"id., one who puts a writing together, a composer, author: codicis, Cod. Th. 1, 1, 6, § 2. contextus, a, um, Part. and P. a., from contexo."},"contextus":{"lemma":"contextus","pos":"","gen":"","def":"contexo, a joining or putting together, a connection (class."},"contignum":{"lemma":"contignum","pos":"","gen":"","def":"contigno, a structure of beams"},"contor":{"lemma":"contor","pos":"","gen":"","def":"cunctor init. con-torquĕo, torsi, tortum (also -torsum, acc. to Prisc. 9, p. 871 P.), 2, v. a., to turn, twist, twirl, swing, whirl or brandish, etc. (class. in prose and poetry). Lit. Of weapons"},"contortor":{"lemma":"contortor","pos":"","gen":"","def":"contorqueo, a wrester, perverter: legum, Ter. Phorm. 2, 3, 27. contortŭlus, a, um, adj. dim. , somewhat complicated or intricate: contortulis quibusdam ac minutis conclusiunculis, Cic. Tusc. 2, 18"},"contracto":{"lemma":"contracto","pos":"","gen":"","def":"contrecto."},"contractor":{"lemma":"contractor","pos":"","gen":"","def":"contraho, I. B. 2., one who makes a contract, a contractor, Cod. Just. 5, 5, 8"},"contractus":{"lemma":"contractus","pos":"","gen":"","def":"contraho. * A drawing together: acinorum, a shrinking, wrinkling, Varr. R. R. 1, 68.— Trop. An entering upon or transacting of an affair: rei, * Quint. 4, 2, 49.— Jurid. t. t. (not in Cic.)"},"contrascriptor":{"lemma":"contrascriptor","pos":"","gen":"","def":"contrascribo, a comptroller, = ἀντιγραφεύς: RATIONIS SVMMI CHORAGI, Inscr. Grut. 579, 10; Inscr. Orell. 3209. contrā-vĕnĭo, īre, v. n., to oppose (late Lat.)"},"contunsum":{"lemma":"contunsum","pos":"","gen":"","def":", v. contundo, I. B. contunsus, a, um, Part., v. contundo init. contŭo, v contueor init. contŭŏli ŏcŭli sunt in angustum coacti conniventibus palpebris"},"contus":{"lemma":"contus","pos":"","gen":"","def":", = κοντός, a pole, pike (perh. not ante-Aug.), as an implement of a boat or ship, Verg. A. 5, 208; 6, 302; Tac. A. 14, 5; Suet. Calig. 32; as a weapon, Verg. A. 9, 510; Tac. A. 6, 35"},"conuecto":{"lemma":"convecto","pos":"","gen":"","def":"freq. a. id., to bear, carry, or bring together in abundance (very rare): recentes praedas, Verg. A. 7, 749"},"conuector":{"lemma":"convector","pos":"","gen":"","def":"conveho, one who carries or brings together; hence, Convector, the deity who presided over the gathering in of grain, Fab. Pict. ap. Serv. ad Verg. G. 1, 21."},"conuento":{"lemma":"convento","pos":"","gen":"","def":"freq. n. , to meet often, Sol. 27, § 7."},"conuentum":{"lemma":"conventum","pos":"","gen":"","def":", v. convenio, P. a., 2. conventus, a, um, Part. of convenio. conventus, ūs (CONVENTVVS, C. I. L. II. p. 2416), m. convenio. (Acc. to convenio, I.) A meeting"},"conuersim":{"lemma":"conversim","pos":"adv.","gen":"","def":"converto, conversely (late Lat.), Mart. Cap. 5, § 491; Firm. Math. 2, 32. conversĭo, ōnis, f. id., a turning round, revolving, revolution (class.). Lit. In gen.: caeli, Cic. Div. 2, 42, 89"},"conuersus":{"lemma":"conversus","pos":"","gen":"","def":"converto, a turning or twisting round, Macr. S. 7, 9, § 4. convertĭbĭlis (convers-), e, adj. id., changeable (post-class.): propositiones, App. Dogm. Plat. 3, p. 33"},"conuexus":{"lemma":"convexus","pos":"adj.","gen":"","def":"conveho, vaulted, arched, rounded, convex, concave. Prop.: convexum id est ex omni parte declinatum, qualis est natura caeli, quod ex omni parte ad terram versus declinatum est, Paul. ex Fest. p. 58"},"conuictor":{"lemma":"convictor","pos":"","gen":"","def":"id., he who lives with one, a table companion, messmate, familiar friend, Cic. Fil. ap. Cic. Fam. 16, 21, 5; Hor. S. 1, 4, 96; 1, 6, 47; Plin. Ep. 2, 6, 4; Sen. Ep. 7, 5; id. Ira, 3, 8, 2"},"conuictus":{"lemma":"convictus","pos":"","gen":"","def":"convivo, a living together, intimacy, social intercourse. In gen. (syn.: societas, consuetudo): convictus humanus et societas, Cic. Off. 3, 5, 21; Lucceius ap. Cic. Fam. 5, 14, 3; Col. 1, 8, 5"},"cops":{"lemma":"cops","pos":"adj.","gen":"","def":", v. 1. copis."},"copta":{"lemma":"copta","pos":"","gen":"-t","def":", = κόπτη, a kind of cake made of pounded materials, Mart. 14, 68.— The same, or a similar kind, called cop-tŏplăcenta, Petr. 40, 4"},"corcillum":{"lemma":"corcillum","pos":"","gen":"","def":"dim. corculum, a little heart: corcillum est quod homines facit, cetera quisquilia omnia, Petr. 75. corcŏdīlus, v. crocodilus. Corcŭlum, i, n. dim. cor, a little heart, Plaut. Most. 4, 2, 70"},"corcus":{"lemma":"corcus","pos":"","gen":"","def":"m., a disease of the chest, Marc. Emp. 21 dub. Corcȳra (y, Avien. Perieg. 663), ae, f., = Κέρκυρα. An island in the Ionian Sea, opposite Epirus"},"corda":{"lemma":"corda","pos":"","gen":"","def":"chorda. cordātē, adv., v. cordatus fin. cordātus, a, um, adj. cor, II. B., wise, prudent, judicious, sagacious (mostly anteand post-class.): egregie cordatus homo, Enn. ap. Cic. Tusc. 1, 9"},"cordax":{"lemma":"cordax","pos":"","gen":"","def":", = κόρδαξ, the extravagant dance of Grecian comedy, distinguished by lively movement and wanton gesture, and by the rope which was kept passing through the hands of the dancers"},"cordus":{"lemma":"cordus","pos":"","gen":"","def":"chordus."},"cormasa":{"lemma":"Cormasa","pos":"","gen":"","def":", = Κύρμασα, a town in Pisidia, Liv. 38, 15, 7. Cornēlĭus, a, subst., a designation of a Roman gens celebrated as embracing the most distinguished Roman men and women (the patrician Scipios, Sulla"},"cornesco":{"lemma":"cornesco","pos":"","gen":"","def":"inch. n. , to become like horn, grow horny, turn to horn, Plin. 11, 49, 109, § 261. cornētum, i, n. 1. cornus, a grove of cornel-trees, Varr. L. L. 5, § 152 Müll."},"cornix":{"lemma":"cornix","pos":"","gen":"","def":"kindred with corvus and κορώνη, a crow, Lucr. 5, 1083: rauca, id. 6, 753: garrula, Ov. M. 2, 548: loquax, id. F. 2, 89; Plin. 10, 12, 14, § 30 al.; renowned as being long lived, Lucr. 5, 1083"},"cornum":{"lemma":"cornum","pos":"","gen":"","def":"1. cornus, the cornelcherry, Verg. G. 2, 34; id. A. 3, 649; Hor. Ep. 1, 16, 9; Ov. M. 1, 105; 8, 665; 13, 816; Col. 12, 10, 3.—* = 1. cornus, II., Ov. M. 8, 408."},"cornus":{"lemma":"cornus","pos":"","gen":"-tree","def":"(cornus, ūs, f., Sil. 4, 552; Stat. Th. 7, 647), a cornel cherry-tree: Cornus mascula, Linn.; Plin. 16, 25, 42, § 103 sq.; Verg. G. 2, 448"},"corpus":{"lemma":"corpus","pos":"part.","gen":"","def":"cf. Sanscr. kar-, to make; Lat. creo, any object composed of materials perceptible by the senses, body, substance (opp. anima and animus"},"correpto":{"lemma":"correpto","pos":"v.","gen":"","def":"n. freq. , to creep (late Lat.): rursum matris in alvum, Juvenc. 2, 192. correptor (conr-), ōris, m. corripio, a reprover, censurer (cf. correptio, I. B.)"},"cors":{"lemma":"cors","pos":"","gen":"","def":", v. cohors."},"corsae":{"lemma":"corsae","pos":"","gen":"","def":", = κόρσαι"},"corsus":{"lemma":"Corsus","pos":"","gen":"","def":"Corsica, II. A."},"cortex":{"lemma":"cortex","pos":"","gen":"-tree","def":"and rar. f. (cf. Quint. 1, 5, 35) [Sanscr. kart, to cut, split; Gr. κείρω"},"cortuosa":{"lemma":"Cortuosa","pos":"","gen":"","def":", a town of Etruria, Liv. 6, 4, 9. Cortȳnia (Gort-), ae, f., a town of Crete, Varr. R. R. 1, 7, 6"},"coruus":{"lemma":"corvus","pos":"part.","gen":"-ram","def":"root kar-, kal-, to sound; cf.: καλέω, κόραξ, etc., a raven, Plin. 10, 43, 60, § 121 sq.; acc. to the fable, orig. white, changed to a black bird in punishment for treachery, Ov. M. 2, 541 sq."},"corysidia":{"lemma":"corysidia","pos":"","gen":"","def":", another name of the plant Minyas, Plin. 24, 17, 100, § 157 (corinthia, Sillig). Cŏrythus, i, m., = Κόρυθος. An ancient town in Etruria, so named from its mythical founder, later called Cortona"},"cosmoe":{"lemma":"Cosmoe","pos":"","gen":"","def":", = Κόσμοι, a high council of the Cretans, answering to the Lacedaemonian Ephori, Cic. Rep. 2, 33, 58 fin. Moser N. cr. cosmōgrăphĭa, ae, f., = κοσμογραφία, a description of the universe"},"cosmus":{"lemma":"Cosmus","pos":"adj.","gen":"","def":", a celebrated maker of, and dealer in unguents at Rome, Juv. 8, 86; Mart. 11, 8, 9; 1, 89, 2; 14, 110, 1.—Hence, Cosmĭānus, a, um, adj., named or derived from Cosmus: ampullae, Mart. 3, 82, 26"},"cossim":{"lemma":"cossim","pos":"adv.","gen":"","def":", v. cessim. Cossinius, a, a Roman gentile name, Cic. Balb. 23, 53 al."},"cossus":{"lemma":"cossus","pos":"","gen":"","def":", a kind of larva under the bark of trees, Plin. 11, 33, 38, § 113; 17, 24, 37, § 220; 30, 13, 39, § 115."},"costa":{"lemma":"costa","pos":"","gen":"","def":", a rib, Cels. 8, 1; Plin. 11, 37, 82, § 207; Plaut. Ps. 1, 2, 4; Lucr. 5, 1297; Verg. G. 1, 273; id. A. 1, 211; Ov. H. 9, 111; Stat. Th. 2, 9"},"costum":{"lemma":"costum","pos":"","gen":"","def":"(access. form, like the Greek, costŏs, i, f., Luc. 9, 917), = κόστος, an Oriental aromatic plant: Costus Arabicus, Linn.; Plin. 12, 12, 25, § 41; Ov. M. 10, 308; Hor. C. 3, 1, 44 al."},"cotta":{"lemma":"Cotta","pos":"","gen":"","def":", v. Aurelius. cottăbus, i, m., = κότταβος (a social sport consisting in dashing a liquid upon a brazen vessel; v. Lidd. and Scott under κότταβος"},"cotton":{"lemma":"Cotton","pos":"","gen":"","def":", a town of Aeolis, in Asia Minor, Liv. 37, 21, 5. Cottus or Cŏtus, i, m., v. Cotys. cŏtŭla (cŏtyla), ae, f., = κοτύλη, a small vessel, as a measure, equal to a hemina or half a sextarius"},"coturnium":{"lemma":"coturnium","pos":"","gen":"","def":"q. cuturnium, q. v. cōturnix (ō, * Lucr. 4, 641; ŏ, Ov. Am. 2, 6, 27; Juv. 12, 97), īcis, f. a sono vocis, Paul. ex Fest. p. 37, 4 Müll., a quail, Plin. 10, 23, 33, § 64 sq.; Plaut. Capt. 5, 4, 6"},"coxa":{"lemma":"coxa","pos":"","gen":"-bone","def":", the hip. Prop, Cels. 4, 22, 1; 8, 1 fin.; 8, 10, 5; Cael. Aur. Tard. 4, 3, 38"},"coxim":{"lemma":"coxim","pos":"adv.","gen":"","def":"coxa; cf.: cessim, cossim, on the hips (late Lat.): insidens, App. M. 3, p. 129, 19."},"coxo":{"lemma":"coxo","pos":"","gen":"","def":"coxa, hobbling, Non. p. 25, 18. crābātus = grabatus, q. v. Crabra (ae) aqua, an aqueduct or water conduit that extended from Tusculum to the Tiber, Cic. Agr. 3, 2, 9; id. Fam. 16, 18, 3"},"cracca":{"lemma":"cracca","pos":"","gen":"","def":", a kind of pulse, perh. wild vetch, Plin. 18, 16, 41, § 142. crăcens, entis kindr. with gracilis"},"crantor":{"lemma":"Crantor","pos":"","gen":"-bearer","def":", = Κράντωρ. In fable, the armor-bearer of Peleus, slain by the centaur Demoleon, Ov. M. 12, 367.— A distinguished Grecian philosopher of the old Academic school, Cic. Ac. 1, 9, 34; 2, 44, 135"},"crassesco":{"lemma":"crassesco","pos":"","gen":"","def":"inch., to grow thick, to thicken, grow dense or hard, grow large or fat (post-Aug."},"crasso":{"lemma":"crasso","pos":"v.","gen":"","def":", ātum, 1, v. a. crassus, to make thick, thicken, condense (postclass.): pili crassantur in setas, App. M. 3, p. 139, 39: crassatus aër, Amm. 19, 4, 6; 19, 4, 8"},"crassus":{"lemma":"crassus","pos":"adj.","gen":"","def":"Sanscr. kart-, to spin; cf.: crates, cartilago, etc."},"crena":{"lemma":"crena","pos":"","gen":"","def":", corrupted word, Plin. 11, 37, 68, § 180; Sillig ad h. 1."},"crepae":{"lemma":"crepae","pos":"","gen":"-goats","def":"q. caprae, she-goats, acc. to Paul. ex Fest. p. 48, 16 Müll. crĕpātūra, ae, f. crepo, a fissure, crack (late Lat.): parietum, Schol. Juv. 3, 196. crĕpax, ācis, adj. id., sounding, creaking: mola"},"cres":{"lemma":"Cres","pos":"","gen":"","def":"Creta, II. A. crescentĭa, ae, f. cresco, an increase, augmentation: dierum (opp. brevitates), Vitr. 9, 9, 7."},"cresco":{"lemma":"cresco","pos":"conj.","gen":"","def":"perf. sync. cresse, Lucr. 3, 683), v. inch. n. . Orig., of things not previously in existence, to come forth, grow, to arise, spring, be born, become visible, appear (so mostly poet.) Lit.: cetera"},"crispo":{"lemma":"crispo","pos":"v.","gen":"","def":", ātum, 1, v. a. and n. id.. Act., to curl, crisp, crimp (poet. or in post-Aug. prose). Prop.: capillum, Plin. 29, 4, 26, § 82: feminae cincinnos, Maec. ap. Sen. Ep. 114"},"crispus":{"lemma":"crispus","pos":"adj.","gen":"","def":"kindred with crinis, crista; cf. cresco. Originally of the hair, curled, crisped, crimped: cincinni, Plaut. Truc. 2, 2, 32; cf. coma, Sil. 16, 120"},"crisso":{"lemma":"crisso","pos":"","gen":"","def":"criso."},"crista":{"lemma":"crista","pos":"","gen":"-ceres","def":"cf. cer- in cerebrum, pro-ceres, = cel- in excello. Prop., a tuft on the head of animals; most freq. of the comb of a cock, Varr. R. R. 3, 9, 4 and 5; Plin. 10, 56, 77, § 156; Juv. 13, 233 al."},"critognatus":{"lemma":"Critognatus","pos":"","gen":"","def":", a chief of the Arverni, Caes. B. G. 7, 77. Crĭtŏlāus, i, m. A peripatetic philosopher, who was sent with Carneades and the Stoic Diogenes as an ambassador to Rome, Cic. de Or. 1, 11, 45; 2, 37, 155"},"crocallis":{"lemma":"crocallis","pos":"","gen":"","def":", an unknown, cherryshaped precious stone, Plin. 37, 10, 56, § 154. crocātĭo, ōnis, f. crocio, the croaking of ravens, Paul. ex Fest. p. 53, 3. crŏcātus, a, um, adj. crocus, saffronyellow: semen"},"crodunum":{"lemma":"Crodunum","pos":"","gen":"","def":", a place in Gallia Narbonensis, now Gourdan, Cic. Font. 5, 9."},"croesus":{"lemma":"Croesus","pos":"adj.","gen":"","def":", = Κροῖσος, a king of Lydia, celebrated for his riches, Cic. Div. 1, 19, 37; id. Fin. 2, 27, 87; Hor. Ep. 1, 11, 2; Just. 1, 7, 2 sqq."},"crosmis":{"lemma":"crosmis","pos":"","gen":"","def":", a kind of sage, App. Herb. 101. crŏtălĭa, ōrum, n., = κροτάλια, a rattling ear-pendant, composed of several pearls, Petr. 67"},"cruppellarii":{"lemma":"cruppellarii","pos":"","gen":"","def":"Celtic, harnessed combatants among the Gauls, Tac. A. 3, 43. crūrālis, e, adj. crus, of or belonging to the legs, crural: fasciae, Petr. 40, 5"},"crusma":{"lemma":"crusma","pos":"","gen":"","def":", = κροῦσμα, a musical piece or tune played upon a stringed instrument, Mart. 6, 71, 1"},"crusta":{"lemma":"crusta","pos":"","gen":"-work","def":"cf. crudus, the hard surface of a body, the rind, shell, crust, bark, etc. In gen.: luti, Lucr. 6, 626"},"crusto":{"lemma":"crusto","pos":"v.","gen":"-work","def":"a. crusta, to cover with a rind, shell, incrustation, plaster-work, embossed figures, etc. (post-Aug.): mala gypso, Plin. 15, 17, 18, § 64: domum marmoribus, to incrust, Luc. 10, 114"},"crustum":{"lemma":"crustum","pos":"","gen":"","def":"access. form to crusta, pastry, any thing baked, Hor. Ep. 1, 1, 78; Verg. A. 7, 115; Inscr. Grut. 173, 4; 373, 8. Crustŭmĕrĭa, ae, f. (Liv. 2, 19, 2; 3, 42, 3)"},"crux":{"lemma":"crux","pos":"","gen":"","def":"(m., Enn. ap. Non. p. 195, 13"},"crypta":{"lemma":"crypta","pos":"","gen":"","def":", = κρύπτη, a concealed, subterrunean passage, a vault, cavern, cave, grotto, pit, Varr. ap. Non. p. 169, 11; Suet. Calig. 58"},"crystallum":{"lemma":"crystallum","pos":"","gen":"-crystal","def":"(analog. to the Gr. crystallus, i, m., Sol. 15 fin.), = κρύσταλλος. Ice, Auct. Priap. 63, 6.— A crystal, mountain- or rock-crystal, Plin. 37, 2, 9, § 23; Sen. Q. N. 3, 25, 12; Plin. 36, 26, 66, § 192"},"cuballa":{"lemma":"Cuballa","pos":"","gen":"","def":", a town in Gallograecia, Liv. 38, 18, 5. cŭbātĭo, ōnis, f. cubo, a lying down, Varr. L. L. 8, § 54 Müll. cŭbātor, ōris, m. cubo, he who lies down, Paul. Nol. Ep. 21, 4. cŭbĭcŭlārĭus, a"},"cucus":{"lemma":"cucus","pos":"","gen":"","def":", a daw: interea Cucus, si in ludum iret, potuisset fieri ut probe litteras sciret, Plaut. Pers. 2, 1, 6. cucutĭum, ii, n. cf. cucullus, a kind of hood, Treb. Poll. Claud. 17, 6. cūdo, ĕre, v. a."},"cuferion":{"lemma":"cuferion","pos":"","gen":"-bleed","def":", the nose-bleed, a disease of horses, Veg. Art. Vet. 3, 37. cuicuimŏdi (ante-class. quoiquoi mŏdi) , euphon. form for cujuscujusmodi (very rare in MSS., but vouched for by the ancient grammarians"},"cui":{"lemma":"qui","pos":"conj.","gen":"-clause","def":"quei; gen. quojus; dat. quoi, and in inscrr. QVOEI, QVOIEI, and QVEI; abl. qui; plur. ques or queis; fem. QVAI; neutr. qua","form_of":"qui"},"cuius":{"lemma":"qui","pos":"conj.","gen":"-clause","def":"quei; gen. quojus; dat. quoi, and in inscrr. QVOEI, QVOIEI, and QVEI; abl. qui; plur. ques or queis; fem. QVAI; neutr. qua","form_of":"qui"},"culex":{"lemma":"culex","pos":"","gen":"","def":"culix. cŭlĭcellus, i, m. dim. 1. culex, a little gnat: amasio Tullae, i. e. buzzing round her, Ser. ap. Diom. p. 513 P. cŭlĭcŭlārĕ, is, n. id., a fly-net (late Lat."},"culix":{"lemma":"culix","pos":"","gen":"","def":", an unknown plant, Plin. 19, 5, 23, § 68.—Also culex, Pall. Mart. 9, 8. cullĕāris (cūl-), e, adj. culleus, II. A., of the measure of a culleus: labrum, Cato, R. R. 154: dolia, Vitr. 6"},"culminia":{"lemma":"Culminia","pos":"","gen":"","def":"Colminiana. culmōsus, a, um, adj. culmus, stalklike, poet.: fratres, sprung from the dragonteeth, Sid. Carm. 6, 72."},"culmus":{"lemma":"culmus","pos":"","gen":"","def":"kindr. with culmen, a stalk, stem, esp. of grain, straw, Varr. R. R. 1, 48, 3 (Cod. Vindob. culmen); Cic. Sen. 15, 51; Verg. G. 1, 111"},"culpa":{"lemma":"culpa","pos":"","gen":"","def":"kindr. in root with scelus; cf. Sanscr. skhal-, errare, crime, fault, blame, failure, defect (as a state worthy of punishment; on the contr. delictum, peccatum, etc., as punishable acts"},"culpo":{"lemma":"culpo","pos":"v.","gen":"-tus","def":"a. culpa. To reproach or blame a person or thing as wrong or faulty, to censure, reprove, disapprove, condemn (syn.: reprehendo, vitupero; opp. laudo, probo, etc.; rare; mostly post-Aug."},"cultellus":{"lemma":"cultellus","pos":"","gen":"","def":"dim. culter, a small knife. Prop., Varr. R. R. 1, 69, 2; id. Fragm. ap. Non. p. 195, 18; Hor. Ep. 1, 7, 51; Plin. 12, 25, 54, § 115 al.— Lignei, wooden pegs or pins, Vitr. 7, 3."},"culter":{"lemma":"culter","pos":"","gen":"-cello","def":"kindr. with Sanscr. kar, to wound, kill; cf. per-cello, clades. Orig. a plough-coulter, ploughshare, Plin. 18, 18, 48, § 171 sq.— In gen., a knife; so a vintner's knife, Col. 4, 25, 2; 12, 45, 4"},"cultor":{"lemma":"cultor","pos":"","gen":"-dresser","def":"id.. Prop., one who bestows care or labor upon a thing, an elaborator, cultivator, etc.: agrorum, Liv. 2, 34, 11; 4, 25, 4: agri, id. 40, 29, 3"},"cultrix":{"lemma":"cultrix","pos":"","gen":"","def":"cultor. Prop., she who labors at or cares for a thing: earum rerum quas terra gignit ... augendarum et alendarum quandam cultricem esse, quae sit scientia atque ars agricolarum, Cic. Fin. 5, 14"},"cultus":{"lemma":"cultus","pos":"","gen":"","def":"1. colo. Prop., a laboring at, labor, care, cultivation, culture (rare): quod est tam asperum saxetum, in quo agricolarum cultus non elaboret? Cic. Agr. 2, 25, 66: agricolae, id. Leg. 1, 1"},"cumba":{"lemma":"cumba","pos":"","gen":"","def":"cymba. cŭmĕra, ae, f. (cŭmĕrum, i, n., Varr. L. L. 7, § 34 Müll.; Paul. ex Fest. p. 50, 7 ib.) , a chest, box, or basket, to keep grain in, Hor. S. 1, 1, 53 Acro; id. Ep. 1, 7, 30"},"cunctim":{"lemma":"cunctim","pos":"adv.","gen":"","def":"cunctus, all together, in a body, collectively, for conjunctim (very rare, perh. only in App.): cunctim et coacervatim (opp.: singulatim ac discretim), App. Flor. 9, p. 347, 6"},"cuncto":{"lemma":"cuncto","pos":"v.","gen":"-class","def":"n. (ante-class. collat. form of cunctor), to delay, hesitate, Enn. ap. Non. p. 469, 27 (Com. Rel. v. 3 Vahl.): cunctas? intus alii festinant, Plaut. Cas. 4, 2, 13: cunctant subferre laborem"},"cunnus":{"lemma":"cunnus","pos":"","gen":"","def":"cf. Sanscr. çushi, ditch; Gr. κυσός, the female pudenda. Prop., Mart. 1, 90, 7; 3, 72, 6; 3, 81, 4"},"cuprum":{"lemma":"cuprum","pos":"n. n.","gen":"-i","def":"copper (named from Cyprus); bronze"},"curiatius":{"lemma":"Curiatius","pos":"","gen":"","def":", a Roman proper name: Curiatius Maternus, v. Maternus. cūrĭātus, a, um, adj. curia, of or pertaining to the curiae: comitia"},"curidius":{"lemma":"Curidius","pos":"","gen":"","def":", a Roman proper name, Cic. Verr. 2, 4, 20, § 44. Cūrietae, ārum, m., the inhabitants of Curieta, an island on the coast of Illyria, now Veglia, Plin. 3, 21, 25, § 139.—Hence, Cūrietĭcus, a, um, adj."},"currax":{"lemma":"currax","pos":"adj.","gen":"-class","def":"curro, running fast, quick, swift (post-class. and rare): servus, Dig. 21, 1, 18.—Poet.: laquei, which are bound on the feet of running animals, Grat. Cyn. 89. currĭcŭlum, i, n. id., a running"},"currus":{"lemma":"currus","pos":"","gen":"-chariot","def":"curro, a chariot, car, wain. Lit. In gen., Poët. ap. Varr. L. L. 5, § 153 Müll.; Cic. Att. 13, 21, 3; Lucr. 3, 642; Cic. Div. 2, 70, 144; Verg. A. 5, 819; id. G. 3, 359"},"cursim":{"lemma":"cursim","pos":"adv.","gen":"","def":"id., quickly, swiftly, hastily, speedily (class.): currere, Plaut. Ps. 1, 3, 124"},"cursito":{"lemma":"cursito","pos":"","gen":"","def":"freq. n. , to run about, run hither and thither (rare). In gen.: sursum deorsum, * Ter. Eun. 2, 2, 47; cf.: huc et illuc, Hor. C. 4, 11, 10"},"curso":{"lemma":"curso","pos":"","gen":"","def":"freq. n. , to run hither and thither, to and fro (rare but class.): ultro et citro, Cic. Rosc. Am. 22, 60: huc illuc, id. Att. 9, 9, 2; Tac. A. 15, 50"},"cursor":{"lemma":"cursor","pos":"","gen":"-race","def":"id., a runner, and partic., A runner in a race, racer, Lucr. 2, 78; Cic. Tusc. 2, 23, 56; id. Div. 2, 70, 144"},"cursus":{"lemma":"cursus","pos":"","gen":"","def":"id., a running (on foot, on a horse, chariot, ship, etc.), a course, way, march, passage, voyage, journey, etc. (very freq.). Lit. Of living beings: ingressus, cursus, accubitio, etc., Cic. N. D. 1"},"curto":{"lemma":"curto","pos":"v.","gen":"","def":"a. curtus, to shorten, diminish (not ante-Aug., and very rare): aliquid, Cels. 7, 9: radices, Pall. Feb. 10, 3.— Trop., to diminish: rem, Pers. 6, 34"},"curuesco":{"lemma":"curvesco","pos":"v.","gen":"","def":"n., to be crooked, curved, to make a curve (late Lat.): mare curvescens, Amm. 22, 8, 5; Ambros. in Luc. 9, 9; id. de Isaac et An. 7, 60"},"curuo":{"lemma":"curvo","pos":"v.","gen":"","def":"a. id., to crook, bend, bow, curve (not ante-Aug."},"curuor":{"lemma":"curvor","pos":"","gen":"","def":"curvus, crookedness, perh. only in Varr. L. L. 5, § 104, and 7, § 25 Müll. curvus (-vŏs), a, um, adj. root kar-, whence κορώνη; cf.: circus, varus, crooked, curved, bent (opp. rectus"},"cusinius":{"lemma":"Cusinius","pos":"","gen":"","def":", a Roman proper name, Cic. Att. 12, 38, 4"},"cuspis":{"lemma":"cuspis","pos":"","gen":"","def":"etym. dub., a point, the pointed end of any thing (freq., esp. in the poets). Prop.: asserum, * Caes. B. C. 2, 2: vomeris, Plin. 18, 18, 48, § 172. acuta contorum, Verg. A. 5, 208: acuta teli"},"custos":{"lemma":"custos","pos":"","gen":"-guard","def":"root sku-, to cover, hide, etc."},"cusus":{"lemma":"Cusus","pos":"","gen":"","def":", a small river in Germania, now prob. the Waag, Tac. A. 2, 63 fin. cŭtīcŭla, ae, f. dim. cutis, the skin, Juv. 11, 203; Pers. 4, 18"},"cutina":{"lemma":"Cutina","pos":"","gen":"","def":", a city of the Vestini, Liv. 8, 29, 13. cŭtĭo, ōnis, m., a small insect, milleped, Marc. Emp. 8. cŭtis, is (acc. cutem, App. Mag. p. 306, 14), f. kindr. with κύτος; Sanscr. gudh"},"cybaeus":{"lemma":"cybaeus","pos":"adj.","gen":"-ship","def":"κύπη, κυβή, cupa, pertaining to a kind of merchantship: navis maxima, Cic. Verr. 2, 5, 17, § 44.—Absol.: cybaea, ae, f., a transport or merchant-ship, Cic. Verr. 2, 4, 8, § 17. Cybĕlē or Cybēbē, ēs"},"cybistra":{"lemma":"Cybistra","pos":"","gen":"","def":", a town of Cappadocia, Cic. Fam. 15, 2, 2 and 4; id. Att. 5, 18, 1 al. cybĭum or -ĭon, ii, n., = κύβιον. A tunny-fish, Varr. L. L. 5, § 77 Müll.; Mart. 11, 27, 3"},"cylindrus":{"lemma":"cylindrus","pos":"","gen":"","def":", = κύλινδρος, a cylinder. Prop., Cic. N. D. 1, 10, 24; id. Fat. 19, 41.— Meton. A cylindrical stone for levelling the ground, a roller, etc., Cato, R. R. 129; Verg. G. 1, 178; Plin. 19, 8, 46, § 158"},"cymindis":{"lemma":"cymindis","pos":"","gen":"","def":", v. cybindis. Cymīnē, ēs, f., a town in Thessaly, Liv. 32, 13, 10. cymīnum, i, v. cuminum. Cȳmŏdŏcē, ēs, or Cȳmŏdŏcēa, ae, f., a Nereid, Verg. A. 5, 826; 10, 225"},"cyna":{"lemma":"cyna","pos":"","gen":"","def":", a tree in Arabia that produced cotton: Bombax ceiba, Linn.; Plin. 12, 11, 22, § 39. cynăcantha, ae, f., = κυνάκανθα, dog-thorn, dog-rose; perh. Rosa canina, Linn."},"cynismus":{"lemma":"cynismus","pos":"","gen":"","def":", = κυνισμός, Cynical philosophy or conduct, Cassiod. Hist. Eccl. 7, 2. cynŏcardămon, i, n., = κυνοκάρδαμον, a kind of nasturtium, App. Herb. 20. cynŏcauma, ătis, n., = κυνόκαυμα"},"cynops":{"lemma":"cynops","pos":"","gen":"-eye","def":", = κύνωψ, a plant, dog's-eye, Plin. 21, 17, 61, § 101. cynorrŏdon (-rhŏd-), i, n., and -da, ae, f., = κυνόρροδον. The dog-rose: Rosa canina, Linn. Form -oda, Plin. 8, 41, 63, § 152"},"cynospastos":{"lemma":"cynospastos","pos":"","gen":"","def":"cynosbatos, II. fin. Cynossēma, ātis, n., = κυνὸς σῆμα, a promontory of the Thracian Chersonese where Hecuba was buried, Plin. 4, 11, 18, § 49; Mel. 2, 2, 7; Sol. 10, 22; Mart. Cap. 6, § 658"},"cynthus":{"lemma":"Cynthus","pos":"adj.","gen":"","def":", = Κύνθος, a mountain of Delos, celebrated as the birthplace of Apollo and Diana, now Montecintio, Plin. 4, 12, 22, § 66; Ov. M. 2, 221"},"cypassis":{"lemma":"Cypassis","pos":"","gen":"","def":", the mistress of the poet Ovid, Ov. Am. 2, 7, 17 sq. cypēris, ĭdos, f., = κυπειρίς, the root of the plant cyperos, Plin. 21, 18, 70, § 117. cypērŏs, i, m. (cypērum, i, n., Varr. R. R. 3, 16, 13)"},"cytae":{"lemma":"Cytae","pos":"adj.","gen":"-taeus","def":", = Κυταία, a town in Colchis, the birthplace of Medea, Plin. 4, 12, 26, § 86.— Hence, Cytaeaeus, a, um, adj., Cytaean"},"cytis":{"lemma":"Cytis","pos":"","gen":"","def":", an island at the entrance of the Arabian Gulf, producing chrysolite; now Perim, Plin. 6, 29, 34, § 170."},"d":{"lemma":"D","pos":"","gen":"-la","def":"indecl., sometimes f. sc. littera), the flat dental mute, corresponding in character and sound to the English d and the Greek Δ, was the fourth letter of the Latin alphabet"},"dabar":{"lemma":"Dabar","pos":"","gen":"","def":", a Numidian, a relative of Masinissa and an intimate friend of Bocchus, Sall. J. 108 and 109."},"dabla":{"lemma":"dabla","pos":"","gen":"","def":"Arab. word, a kind of Arabian palm, which bears a delicious fruit, Plin. 13, 4, 7, § 34. Dāci, ōrum, m., Δακοί, the Dacians, a famous warlike people"},"dactyli":{"lemma":"Dactyli","pos":"","gen":"","def":", v. dactylus, no. VII. dactylĭcus, a, um, adj., = δακτυλικός, dactylic: numerus, Cic. Or. 57: pes, Prud. στεφ. 3, 209: metra, Serv. Centim. p. 1820 P."},"dactylis":{"lemma":"dactylis","pos":"","gen":"","def":", a kind of grape; cf. the following, no. II."},"dactylus":{"lemma":"dactylus","pos":"","gen":"-lis","def":", = δάκτυλος (a finger, hence meton.). A sort of muscle: \"ab humanorum unguium similitudine appellati,\" Plin. 9, 61, 87, § 184.— A kind of grape, Col. 3, 2, 1"},"daemon":{"lemma":"daemon","pos":"","gen":"-class","def":", = δαίμων, a spirit, genius, lar (post-class.). In gen.: App. de Deo Socr. p. 49, 5: bonus = ἀγαθοδαίμων, in astrology, the last but one of the twelve celestial signs, Firm. Math. 2, 19: melior"},"dagnades":{"lemma":"dagnades","pos":"","gen":"","def":", a kind of birds in Egypt, Paul. ex Fest. p. 68, 15 Müll. Dăhae (less correctly written Daae, v. Bramb. s. v.), ārum, m., Δάαι, a Scythian tribe beyond the Caspian Sea, Mel. 1, 2, 5"},"dalion":{"lemma":"Dalion","pos":"","gen":"","def":"A physician, Plin. 20, 17, 73, § 191.— An historian, id. 6, 30, 35, § 194."},"daliuus":{"lemma":"dalivus","pos":"","gen":"","def":"; acc. to some, = supinus; acc. to others, = stultus or insanus, Paul. ex Fest. 68, 1 Müll. Dalmătae or Delmătae (so very often in the best MSS. and inscrr., and on coins; cf. Vel. Long. p. 2233"},"dampno":{"lemma":"dampno","pos":"","gen":"","def":"damno init. dāmŭla (damm-), ae, f. dim. damma, a little fallow-deer, App. M. 8, p. 202, 26; Vulg. Isa. 13, 14. dane = dasne, Plaut. Trin. 2, 4, 22"},"dant":{"lemma":"do","pos":"","gen":"","def":"(form of do)"},"daphnis":{"lemma":"Daphnis","pos":"","gen":"","def":", Δάφνις. A son of Mercury, a beautiful young shepherd in Sicily, the inventor of pastoral songs, and hence a favorite of Pan, Ov. M. 4, 277.—Acc. usu. Daphnim, Verg. E. 2, 26; 5, 20"},"dassaresii":{"lemma":"Dassaresii","pos":"","gen":"-ses","def":", a people of Illyria, Liv. 27, 32; 45, 26; Mel. 2, 3, 11; Plin. 3, 23, 26, § 145 al. dăsypūs, ŏdis, com., = δασύπους (rough-foot), a sort of rabbit, Plin. 8, 55, 81, § 219"},"dat":{"lemma":"do","pos":"","gen":"","def":"(form of do)"},"daulis":{"lemma":"Daulis","pos":"adj.","gen":"","def":", Δαυλίς, a city of Phocis, situated on an eminence, and celebrated as the scene of the fable of Tereus, Progne, and Philomela, Liv. 32, 18"},"daunus":{"lemma":"Daunus","pos":"adj.","gen":"-in","def":", Δαῦνος, a fabulous king over a part of Apulia (whence it obtained the appellation Daunia), father (or ancestor) of Turnus, and father-in-law of Diomedes, Verg. A. 10, 616; 688; 12, 22 al."},"decem-scalmus":{"lemma":"decem-scalmus","pos":"adj.","gen":"-scalmus","def":"scalmus, lit. ten-thowled, i. e. having ten oars: actuariola, Cic. Att. 16, 3, 6"},"dedit":{"lemma":"do","pos":"","gen":"","def":"(form of do)"},"deico":{"lemma":"deico","pos":"","gen":"","def":"2. dīco. Dēïdămīa, ae, f., Δηϊδάμεια. Daughter of Lycomedes, king of Scyros, and mother of Pyrrhus by Achilles, Hyg. Fab. 97; Prop. 2, 9, 16; Ov. A. A. 1, 704"},"dein":{"lemma":"dein","pos":"","gen":"","def":"deinde. dĕin-ceps (dissyl., Hor. S. 2, 8, 80; but trisyl. Prud. Cath. 7, 136. Cf. dehinc and deinde), adj. and adv. capio. Prop., taking place next or after, v. Corss. Ausspr. 2, 591"},"delta":{"lemma":"delta","pos":"","gen":"","def":"or indecl. n., = δέλτα, the fourth letter of the Greek alphabet, delta, Δ: non formam at vocem deltae gero Romuleum D, Aus. Idyll. de lit. monos. 14"},"dens":{"lemma":"dens","pos":"","gen":"-teeth","def":"plur. usually dentium, but dentum is approved by Varr. L. L. 7, 38, 67), m. root in Sanscr. dantas, Gr. ὀδούς, Goth. tunthus, Germ. Zahn, and Engl. tooth"},"denseo":{"lemma":"denseo","pos":"","gen":"","def":"denso. densĭtas, ātis, f. densus, thickness, density (perh. not ante-Aug.). Lit.: limus spissatur et in densitatem coit, Plin. 35, 15, 51, § 178: chartae, id. 13, 12, 24, § 78: umoris, id. 11, 3, 2"},"densus":{"lemma":"densus","pos":"adj.","gen":"-dark","def":"kindred with δασύς, δαυλός (i. e. δασυλός)"},"denter":{"lemma":"Denter","pos":"","gen":"","def":"id., the surname of M. Livius (consul 452 A. U. C.), Liv. 10, 1 and 9. Denthēlēthi, ōrum, m. Δανθηλῆται, = Denseletae q. v., Liv. 39, 53, 12 al. Denthelĭăthēs, is, adj. Δενθάλιοι"},"depso":{"lemma":"depso","pos":"v.","gen":"","def":"a., = δεψέω, to knead. Prop.: id ubi excoxeris, depsito bene, Cato, R. R. 90"},"deraemestae":{"lemma":"Deraemestae","pos":"","gen":"","def":", a people in Dalmatia, Plin. 3, 22, 26, § 143."},"derangae":{"lemma":"Derangae","pos":"","gen":"","def":", a people of India, Plin. 6, 20, 23, § 76. Derbē, es, f., = Δέρβη, a fortified city of Lycaonia, residence of Cicero's friend, the tyrant Antipater"},"dexippus":{"lemma":"Dexippus","pos":"","gen":"","def":"Δέξιππος, a Greek proper name, Cic. Fam. 14, 3, 3. Dexĭus, ĭi, m., a Roman proper name, Cic. Fam. 7, 23, 4."},"dexo":{"lemma":"Dexo","pos":"","gen":"","def":", Δεξων, a Greek proper name, Cic. Verr. 2, 5, 42 al."},"dextans":{"lemma":"dextans","pos":"","gen":"","def":"contr. from de and sextans: as dempto sextante, Varr. L. L. 5, § 172 Müll., ten twelfths of any thing (mostly post-Aug.; Cic. writes instead: pars dimidia et tertia, Fam. 13, 29, 4"},"dextella":{"lemma":"dextella","pos":"","gen":"","def":"dim. dextra, a little right hand: Quintus filius illius, ut scribis, est dextella, Cic. Att. 14, 20, 5. dexter, tĕra, tĕrum, and more freq. tra, trum (dat. plur. fem.: dextrabus manibus"},"di":{"lemma":"di","pos":"","gen":"","def":"Nom. plur., from deus, q. v.— Arch. gen., from dies, q. v. dĭĭambus, i, m., = διΐαμβος, a double iambus: ˘¯˘¯, Don. p. 1739 P."},"di-sperno":{"lemma":"di-sperno","pos":"v.","gen":"-sperno","def":"a., to despise: jussa, Juvenc. 2, 257. dispersē and dispersim, advv., v. dispergo fin. dispersĭo, ōnis, f. dispergo, a scattering, dispersion. In gen. Act.: exercitus, Isid. 18, 2, 7: populi, gentis"},"di-sterno":{"lemma":"di-sterno","pos":"v.","gen":"-sterno","def":"a., to spread out: lectum, i. e. to make, prepare, App. M. 10, p. 256, 7.—Impers.: extra limen pueris distratum fuerat, id. ib. 2, p. 121, 25. dis-tĕro, trīvi, trītum, 3, v. a."},"di-stinguo":{"lemma":"di-stinguo","pos":"v.","gen":"-stinguo","def":"a. root in Sanscr. tegami, to be sharp; Gr. στίζω, στίγμα; Lat. stimulus stilus, in-stigare, etc.. —Prop., to separate by points"},"di-sto":{"lemma":"di-sto","pos":"v.","gen":"-sto","def":"distiti, only Boëth. in Porphyr. 4, p. 89), v. n., to stand apart, to be separate, distant (freq. and class.). Lit. (cf. absum), absol.: quantum summa labra (fossae) distabant, Caes. B. G. 7, 72, 1"},"di-stringo":{"lemma":"di-stringo","pos":"v.","gen":"-stringo","def":"a. To draw asunder, to stretch out (very rarely): radiis rotarum districti pendent, * Verg. A. 6, 616.—Poet.: (canum) rabies districta, i. e. showing the teeth, Lucr. 5, 1064"},"dicis":{"lemma":"dicis","pos":"","gen":"","def":", in the phrase dicis causa or gratia, orig. a jurid. t. t., meaning for the sake of judicial form"},"dicit":{"lemma":"dico","pos":"","gen":"","def":"(form of dico)"},"dictaeus":{"lemma":"Dictaeus","pos":"","gen":"","def":"Dicte, no. II. A. dictāmen, inis, n. dicto, late Lat. for dictum, praescriptum, praeceptum."},"dictamnum":{"lemma":"dictamnum","pos":"","gen":"-us","def":"Dicte, no. II. B. dictāta, ōrum, n., lessons, exercises, etc., v. dicto fin. dictātĭo, ōnis, f. dicto, a dictating, dictation (late Lat.), Dig. 29, 1, 4 al. dictātĭuncŭla, ae, f. dim. dictatio"},"dicto":{"lemma":"dicto","pos":"","gen":"","def":"freq. a. 2. dico, to say often"},"dictor":{"lemma":"dictor","pos":"","gen":"","def":"2. dico, one who says something, a speaker (late Lat.), Aug. Doctr. Chr. 4, 19 al."},"dictum":{"lemma":"dictum","pos":"","gen":"","def":", v. 2. dico, II. dictŭrĭo, īre, v. desid. a., to long to say or tell (late Lat.): fortiter a se facta semper dicturiunt, Macr. S. 7, 2, 7; 2, 3, 16. dictus, a, um, Part., from 2. dico."},"dictus":{"lemma":"dictus","pos":"","gen":"","def":"2. dico, a saying, speech, Aur. Vict. epit. 14."},"dictynna":{"lemma":"Dictynna","pos":"","gen":"-n","def":", Δίκτυννα. The nymph Britomartis, so called because, when pursued by Minos, she sprang into a net (δίκτυον; cf. Callim. Hymn. Dian. 189 sq.), Verg. Cir. 304.— An appellation of Diana, Ov. M. 2, 441"},"dictys":{"lemma":"Dictys","pos":"","gen":"","def":", Δίκτυς. A mariner changed by Bacchus into a dolphin, Ov. M. 3, 615.— A centaur, slain at the wedding of Pirithoüs, Ov. M. 12, 334 sq.— A fisherman on the island of Seriphos"},"dicunt":{"lemma":"dico","pos":"","gen":"","def":"(form of dico)"},"dif-findo":{"lemma":"dif-findo","pos":"v.","gen":"-findo","def":"a., to cleave asunder, to divide (rare but class.). Lit.: vitem mediam per medullam, Cato R. R. 41, 2: malos, Enn. ap. Non. 114, 7 (Ann. v. 389 ed. Vahl., where the read. is, as in Non."},"dif-fingo":{"lemma":"dif-fingo","pos":"v.","gen":"-fingo","def":"a., to form differently, to remodel, to make anew (very rare"},"dif-flo":{"lemma":"dif-flo","pos":"v.","gen":"-flo","def":"a., to blow apart, disperse by blowing: flatu disturbare, Non. 97, 10 (ante- and post-class.): pars difflatur vento, Lucil. ap. Non. 97, 12: legiones spiritu, Plaut. Mil. 1, 1, 17: nubila (nimbi)"},"dif-fundo":{"lemma":"dif-fundo","pos":"v.","gen":"-fundo","def":"a., to spread by pouring, to pour out, pour forth (very freq. and class.). Lit.: (glacies) liquefacta se diffunderet, Cic. N. D. 2, 10: sanguis per venas in omne corpus diffunditur, id. ib. 2, 55"},"diffors":{"lemma":"diffors","pos":"adj.","gen":"-rtis","def":"dis-fors: oratio, a kind of defence, by which the act charged is admitted, but justified, Jul. Victor, Art. Rhet. 3, 3"},"dignanter":{"lemma":"dignanter","pos":"adv.","gen":"","def":", courteously, etc., v. dignor fin. dignātĭo, ōnis, f. dignor, a considering worthy (mostly post-Aug."},"digno":{"lemma":"digno","pos":"v.","gen":"","def":"a. dignus, to deem worthy: quis caelestes dignet decorare hostiis, Pac. ap. Non. 98, 15; so with inf., id. ib. 470, 20; ap. Serv. Verg. A. 11, 169; and in Diomed. p. 395 P."},"dignor":{"lemma":"dignor","pos":"v.","gen":"-class","def":"dep. a. , to deem worthy or deserving (mostly poet. and in post-Aug. prose). Aliquem aliqua re: haud equidem tali me dignor honore, Verg. A. 1, 335; so, aliquem honore, Ov. M. 1, 194; 3, 521"},"dignus":{"lemma":"dignus","pos":"adj.","gen":"-nus","def":"i. e. DIC-nus; root in Sanscr. daç-as, fame; Gr. δοκέω, δόξα"},"dingua":{"lemma":"dingua","pos":"","gen":"","def":", v. lingua. Dīno or Dīnōn, ōnis, m., = Δείνων, a Greek historian of the time of Philip of Macedonia, Cic. Div. 1, 23, 46; Nep. Con. 5"},"diphryges":{"lemma":"diphryges","pos":"","gen":"","def":", = διφρυγές, τό, a kind of slag formed in furnaces when copper is melted, Plin. 34, 13, 37, § 135; Cels. 5, 7, 22; Scrib. Comp. 227 and 247."},"diphthongus":{"lemma":"diphthongus","pos":"","gen":"","def":", = δίφθογγος, a diphthong, Mart. Cap. 3, § 277"},"dipsas":{"lemma":"dipsas","pos":"","gen":"","def":", = διψάς, a kind of serpent whose bite causes violent thirst, the Coluber Vipera, Linn.; Plin. 23, 8, 80, § 152; Mart. 3, 44, 7; Luc. 9, 610; 718; Sil. 3, 313; Vulg. Deut. 8, 15."},"diptycha":{"lemma":"diptycha","pos":"","gen":"-tablet","def":", = δίπτυχα. A writing-tablet of two leaves (late Lat.), Cod. Theod. 15, 9, 1"},"dirca":{"lemma":"Dirca","pos":"","gen":"","def":"Dirce init. Dircē, ēs (acc. Dircam, Plaut. Ps. 1, 2, 65), f., = Δίρκη. A fountain N. W. of Thebes, in Boeotia, Plin. 4, 7, 12, § 25; Ov. M. 2, 239"},"dircenna":{"lemma":"Dircenna","pos":"","gen":"","def":", a fountain in Spain, near Bilbilis, Mart. 1, 50, 17. dircĭon, ii, n., a plant also known as Apollinaris herba, a kind of solanum, Ap. Herb. 23. dīrectā (sc. viā), perpendicularly, see dirigo"},"dis-cerno":{"lemma":"dis-cerno","pos":"v.","gen":"-cerno","def":"a., to separate, set apart. Lit., to separate, part, divide (freq. since the Aug. per.): equas, ne inter se pugnare possint, Varr. R. R. 2, 7, 10: ordines (preceded by senatus a populo secretus)"},"dis-cerpo":{"lemma":"dis-cerpo","pos":"v.","gen":"-cerpo","def":"a. carpo, to pluck or tear in pieces, to rend, to mangle (class.). Lit.: animus nec secerni nec dividi nec discerpi nec distrahi potest, Cic. Tusc. 1, 29, 71"},"dis-cingo":{"lemma":"dis-cingo","pos":"v.","gen":"-cingo","def":"a., to ungird, deprive of the girdle. Lit.: discinctā tunicā fugiendum est, Hor. S. 1, 2, 132; Vell. 2, 41 fin."},"dis-concinnus":{"lemma":"dis-concinnus","pos":"adj.","gen":"-concinnus","def":", unsuitable, ill-matched: oculos (opp. concinnos), Fronto de Or. 2. dis-condūco, ĕre, v. n., not to be profitable or conducive, to be injurious, prejudicial: nil disconducit huic rei, Plaut. Trin. 4"},"dis-cors":{"lemma":"dis-cors","pos":"adj.","gen":"-cors","def":"f. discordis, Pompon. ap. Prisc. p. 726 Com., v. 164 Rib.), adj. cor, discordant, disagreeing, inharmonious, at variance"},"dis-cresco":{"lemma":"dis-cresco","pos":"v.","gen":"-cresco","def":"n., to grow broad, grow out, Lact. de Mort. Pers. 33, 10. discrētim, adv., separately, v. discerno fin. discrētĭo, ōnis"},"dis-cumbo":{"lemma":"dis-cumbo","pos":"v.","gen":"-cumbo","def":"n., to lie down. More freq., to recline at table for the purpose of eating (cf. accumbo—so esp. freq. since the Aug. per.): discubuimus omnes praeter illam, Cic. Att. 5, 1, 4; Lucr. 3, 912"},"dis-curro":{"lemma":"dis-curro","pos":"v.","gen":"-curro","def":"discucurri, Liv. 25, 25, 9; Sen. Contr. 4, 2; Suet. Calig. 32: discurrisse, Curt. 4, 15, 5; oftener curri, Liv. 34, 37; 3, 7, 32; Sen. Ep. 90, 36"},"dis-iicio":{"lemma":"dis-jicio","pos":"","gen":"-jicio","def":"disicio. disjŭgātĭo and disjŭgo, v. dijug. disjunctē, adv., separately, distinctly, etc., v. disjungo, P. a. fin. a."},"dis-par":{"lemma":"dis-par","pos":"adj.","gen":"-par","def":", unlike, dissimilar, different, unequal (freq. and class."},"dis-pello":{"lemma":"dis-pello","pos":"v.","gen":"-pello","def":"a., to drive asunder, to scatter, disperse (rare but class.). Lit.: dispulsa suo de coetu materiaï Copia, Lucr. 1, 1017: pecudes dispulsae, Cic. Att. 7, 7, 7: ater quos aequore turbo Dispulerat"},"dis-pendo":{"lemma":"dis-pendo","pos":"v.","gen":"-pendo","def":"a., to weigh out (ante- and post-class.): in dispendendo, Varr. L. L. 5, § 183 Müll.: panis dispensus, i. e. dispensed, distributed, Prud. ap. Symm. 1, 584."},"dis-penso":{"lemma":"dis-penso","pos":"","gen":"-penso","def":"freq. a. Orig. of money, to distribute by weight, to disburse, pay out (for syn. cf.: partior, impertio, distribuo, divido): ducentos nummos (sc. inter milites), Plaut. Bacch. 4, 9, 47.— In gen."},"dis-perdo":{"lemma":"dis-perdo","pos":"v.","gen":"-perdo","def":"a., to destroy, spoil, ruin (rare but class.): bibe, es, disperde rem, Plaut. Cas. 2, 3, 32"},"dis-pungo":{"lemma":"dis-pungo","pos":"v.","gen":"-pungo","def":"a. In postAug. mercant. lang., to check off the debits and credits of an account"},"dis-serpo":{"lemma":"dis-serpo","pos":"v.","gen":"-serpo","def":"n., to creep about, to spread imperceptibly: late disserpunt tremores, Lucr. 6, 547. dissertātĭo, ōnis, f. disserto, a spoken dissertation, discourse, disquisition (not a written treatise"},"dis-sors":{"lemma":"dis-sors","pos":"adj.","gen":"-sors","def":"(opp. consors), of a different fate, separate, apart, not shared: ab omni milite dissors Gloria, undivided, unshared, Ov. Am. 2, 12, 11: dissortemque utero fetum tulit, id. M. 8, 133 (Heins."},"dis-suesco":{"lemma":"dis-suesco","pos":"v.","gen":"-suesco","def":"n., to disuse, to become disused or unaccustomed to (late Lat.), Alcim. Avit. 4, 46. dis-suētūdo, dinis, f., a becoming unaccustomed, disusing, Ambros. de Cain et Abel. 2, 6"},"dis-tectus":{"lemma":"dis-tectus","pos":"adj.","gen":"-tectus","def":"dis and tego, uncovered, Alcim. Avit. 4, 408. di-stĕgus, a, um, adj. δίστεγος, of two stories, having two apartments: armarium, Inscr. Orell. 4549.—Subst.: distĕ-gum, i, n. (sc. armarium)"},"dis-texo":{"lemma":"dis-texo","pos":"v.","gen":"-texo","def":"a., to unravel, ravel out, Sid. C. 15, 161. distĭchus, a, um, adj., = δίστιχος, consisting of two rows. Adj.: hordeum, Col. 2, 9, 16.— Subst. ‡ distĭ-chum, i, n."},"dis-trunco":{"lemma":"dis-trunco","pos":"v.","gen":"-trunco","def":"a., to cut to pieces, cut up: ego te hic agnum faciam, et medium distruncabo, Plaut. Truc. 2, 7, 53. disturbātĭo, ōnis, f. disturbo, destruction. * Prop.: Corinthi, Cic. Off. 3, 11, 46.— Trop."},"dis-turbo":{"lemma":"dis-turbo","pos":"v.","gen":"-turbo","def":"a., to drive asunder, to separate by violence, to throw into disorder, disturb. Lit. In gen. (rarely): vidistis contionem gladiis disturbari, Cic. Mil. 33 fin.: sortes, id. Div. 1"},"discepto":{"lemma":"discepto","pos":"v.","gen":"","def":"a. dis and capio. Jurid. t. t. (lit., to seize hold of and separate; hence, to stop the dispute), to decide, determine, judge a controversy, = dijudicare (cf.: dissero, disputo"},"discernenter":{"lemma":"discernenter","pos":"adv.","gen":"","def":", with a distinction, etc."},"discessus":{"lemma":"discessus","pos":"","gen":"","def":"discedo. A going asunder, separation, opening (very rare): caeli, i. e. lightning, Cic. Div. 2, 28, 60: est interitus quasi discessus et secretio ac diremptus earum partium"},"disco":{"lemma":"disco","pos":"v.","gen":"","def":"fut.: sic disciturum, etc., App. ap. Prisc. p. 887 P.), v. a. from the root da-, Gr. δεδαώς, δαῆναι"},"discordis":{"lemma":"discordis","pos":"","gen":"","def":"discors init. discordĭtas, ātis, f. discors, disunion, discord, Pac. ap. Non. 97, 1. discordĭum, i, n. discors, discord, dissension.—Plur.: publica discordia, Calp. Ecl. 1, 57."},"discordo":{"lemma":"discordo","pos":"v.","gen":"","def":"n. id., to be at variance, to differ, to quarrel (rare but class.). Lit.: discordare inter se, Ter. And. 3, 3, 43: cupiditates in animis dissident atque discordant, Cic. Fin. 1, 13"},"discursim":{"lemma":"discursim","pos":"adv.","gen":"","def":"discurro, by running or going about, Macr. S. 7, 1, 1 (dub.)"},"discurso":{"lemma":"discurso","pos":"","gen":"","def":"freq. a. and n. id.. Neutr., to run about, hasten up and down (post - Aug. and rare): multum in agendo discursantem, salientem, etc.... non agere dixit (Domitius Afer) sed satagere, Quint. 6, 3, 54"},"discursor":{"lemma":"discursor","pos":"","gen":"","def":"id., one who runs about, (Pseud.) Augustin. ad Frat. Erem. Serm. 5. discursus, a, um, Part., from discurro."},"discursus":{"lemma":"discursus","pos":"","gen":"-class","def":"discurro. A running to and fro, a running about (mostly post-class.): magno clamore discursuque passim fugae se mandant, Hirt. B. G. 8, 29, 2; Liv. 25, 25; Quint. 1, 12, 10; Plin. Ep. 1, 9, 7"},"discus":{"lemma":"discus","pos":"","gen":"","def":", = δίσκος. A quoit, an implement for exercise in ancient gymnastics, Stat. Th. 6, 646 sq.; Prop. 3, 14, 10 (4, 13, 10 M.); Hor. C. 1, 8, 11; id. S. 2, 2, 13; id. A. P. 380"},"discussor":{"lemma":"discussor","pos":"","gen":"","def":"id., an examiner (late Lat.). In gen., Macr. Somn. Scip. 1, 21, 8.— In partic., in the later period of the empire, one who revised the accounts of the public revenue in the provinces, an auditor"},"discussus":{"lemma":"discussus","pos":"","gen":"","def":"discutio, a dashing, agitating: (lupus) si haesit in hamo, tumultuoso discussu laxat volnera, Plin. 32, 2, 5, § 13. dis-cŭtĭo, cussi, cussum, 3, v. a. quatio, to strike asunder, dash to pieces"},"disiecto":{"lemma":"disjecto","pos":"","gen":"","def":"freq. a. disicio, to hurl hither and thither, to scatter, disperse: disjectare solet magnum mare transtra, cavernas, etc., Lucr. 2, 553; id. ib. 562; 3, 501: conspiratas gentes, Amm. 16, 3"},"disiectus":{"lemma":"disjectus","pos":"","gen":"","def":"disicio, a casting asunder, scattering, Lucr. 3, 928."},"disiunctim":{"lemma":"disjunctim","pos":"adv.","gen":"","def":", separately, etc., v. disjungo, P. a. fin. b. disjunctĭo or dījunctio, ōnis, f. disjungo, a separation (a Ciceron. word). In gen.: in tanta disjunctione meorum, tanta acerbitate, Cic. Sest. 21, 47"},"dispargo":{"lemma":"dispargo","pos":"","gen":"","def":"dispergo. dis-părĭlis, e, adj., dissimilar, different (very rare): pabulum, Varr. R. R. 2, 11, 4: formae, id. L. L. 9, § 40 Müll.: aspiratio terrarum, * Cic. Div. 1, 36, 79: vites, Col. 3, 2"},"dispecto":{"lemma":"dispecto","pos":"","gen":"","def":"freq. a. id., to consider, contemplate, examine: momenta, Arn. 1, p. 13."},"dispector":{"lemma":"dispector","pos":"","gen":"","def":"id., one who considers, examines, a searcher (eccl. Lat.): cordis Deus, Tert. Anim. 15: alienarum sententiarum, id. ad Uxor. 2, 8. dispectus, a, um, Part., from dispicio."},"dispectus":{"lemma":"dispectus","pos":"","gen":"","def":"dispicio, regard, consideration, examination, Sen. de Ira, 2, 9, 2; id. Ep. 94 med."},"dispenno":{"lemma":"dispenno","pos":"","gen":"","def":"dispando. dispensātĭo, ōnis, f. dispenso. Economical management, charge, direction, superintendence. Lit.: aerarii, Cic. Vatin. 15, 36.— Transf.: annonae, Liv. 10, 11"},"dispessus":{"lemma":"dispessus","pos":"","gen":"","def":"dispando. dispestus, a, um, Part., from dispesco. di-spĭcĭo, spexi, spectum, 3, v. n. and a., to see through all parts (cf. Lachm. ad Lucr. vol. 2, p. 236 and 237), to see with an effort"},"dispunctor":{"lemma":"dispunctor","pos":"adv.","gen":"","def":"id., an examiner, investigator: meritorum (with judex), Tert. adv. Marc. 4, 17. dispunctus, a, um, Part., from dispungo."},"disrumpo":{"lemma":"disrumpo","pos":"","gen":"","def":"dirumpo. dissaepīmentum (-sēp-), i, n. dissaepio, that which separates, a partition, Fest. p. 166, 12 Müll. dis-saepĭo (less correctly dis-sēpio), psi, ptum, 4, v. a., to part off by a boundary"},"dissaeptum":{"lemma":"dissaeptum","pos":"","gen":"","def":"id., a barrier, partition: saxea domorum, Lucr. 6, 951"},"dissensus":{"lemma":"dissensus","pos":"","gen":"","def":"dissentio, dissension, disagreement, discord (poet. and in post-Aug. prose), Verg. A. 11, 455; Stat. Th. 10, 558; Dig. 17, 2, 65, § 3"},"dissentior":{"lemma":"dissentior","pos":"v.","gen":"","def":"dep., v. dissentio fin. dissēpărātĭo, ōnis, f. disseparo, a parting, separation (late Lat.), Auct. Decl. in Catil. 31. dis-sēpăro, āre, 1, v. a., to part, divide (late Lat.)"},"disserto":{"lemma":"disserto","pos":"","gen":"-class","def":"freq. a. dissero, to discuss, argue, debate a thing"},"dissertus":{"lemma":"dissertus","pos":"","gen":"","def":"2. dissero init. dissĭcio, v. disicio. dissĭdentĭa, ae, f. dissideo, diversity, contrariety: rerum, Plin. 29, 4, 23, § 75. dis-sĭdĕo, ēdi, essum, 2, v. n. sedeo, to sit apart, to be remote from"},"dissiptum":{"lemma":"dissiptum","pos":"","gen":"","def":"dissaepio. dissĭtus, a, um, Part., from 1. dissero. dis-sĭtus, a, um, adj., lying apart, remote (an Appuleian word), opp. assitus, App. Flor. init. p. 340: femora, i. q. divaricata, id. M. 7, p. 198"},"dissulto":{"lemma":"dissulto","pos":"","gen":"","def":"freq. n. , to leap apart, to fly in pieces, burst asunder (poet., and in post-Aug. prose): dissultant ripae, Verg. A. 8, 240: tanti crepitus, id. ib. 12, 923: ferrum utrimque, Plin. 37, 4, 15"},"distenno":{"lemma":"distenno","pos":"","gen":"","def":"distendo init."},"distensus":{"lemma":"distensus","pos":"","gen":"","def":"distendo init. distentĭo, ōnis, f. distendo, a stretching out, distention (very rare), Cels. 2, 4; 8, 4"},"distentus":{"lemma":"distentus","pos":"","gen":"","def":"distendo, a swelling out, distention: subflatae cutis distentu, Plin. 8, 38, 57, § 138. distermĭnātĭo, ōnis, f., a separation, division, Simplic. p. 83 Goes. distermĭnātor, ōris, m. distermino"},"distillo":{"lemma":"distillo","pos":"","gen":"","def":"destillo. di-stĭmŭlo, āre, v. a., to goad through; transf.: bona, i. e. to run through, waste, consume, Plaut. Bacch. 1, 1, 30."},"distincte":{"lemma":"distincte","pos":"adv.","gen":"","def":", distinctly, clearly"},"distinctor":{"lemma":"distinctor","pos":"","gen":"","def":"id., one who distinguishes (late Lat.): justorum injustorumque (judices), Amm. 22, 3; 18, 1, 2; Aug. in Joann. 20, 12. distinctus, a, um, Part. and P. a., from distinguo."},"distinctus":{"lemma":"distinctus","pos":"","gen":"","def":"distinguo, a distinguishing, distinction; object., a difference (post-Aug. and very rare): distinctu pinnarum, * Tac. A. 6, 28"},"distractor":{"lemma":"distractor","pos":"","gen":"-changer","def":"id. I.. One who worries, a tormenter: improbus (i. e. Achilles), Anthol. Lat. 1, 93, 1.— A retailer, Cod. Th. 11, 1, 4: argenti, i. e. a money-changer, id. Just. 8, 14, 27"},"distractus":{"lemma":"distractus","pos":"","gen":"","def":"distraho, dissolution of a contract, opp. to contractus, Just. Inst. 3, 27, § 6. dis-trăho, xi, ctum, 3, v. a. To pull asunder, tear in pieces, to separate forcibly"},"diuitenses":{"lemma":"Divitenses","pos":"","gen":"","def":", the inhabitants of the town Divitia (the mod. Deutz), opposite to Cologne, Amm. 26, 7; 27, 1"},"diurna":{"lemma":"diurna","pos":"","gen":"","def":"diurnus. dĭurnālis, e, adj. diurna, = ἡμερούσιος, diurnal (hence, It. giornale"},"dius":{"lemma":"dius","pos":"adv.","gen":"","def":", v. diu init. dĭuscŭle, adv. diu, a little while, Aug. Trinit. 11, 2. dĭūtĭne, adv., v. the foll. fin. dĭūtĭnus, a, um, adj. diu, of long duration, lasting, long (rare but class."},"dixit":{"lemma":"dico","pos":"","gen":"","def":"(form of dico)"},"docte":{"lemma":"docte","pos":"adv.","gen":"","def":", v. doceo, P. a. fin. doctĭcănus, a, um, adj. doctus-cano, singing skilfully: sensus, Mart. Cap. 2, § 122. doctĭfĭcus, a, um, adj. doctus-facio, making learned: Ardor (i. e. Pallas)"},"doctor":{"lemma":"doctor","pos":"","gen":"","def":"doceo, a teacher, instructor, Cic. de Or. 1, 6, 23; 3, 15, 57; id. Div. 1, 3, 6; id. Or. 33, 117; Quint. 2, 2, 2; Hor. C. 4, 6, 25; id. S. 1, 1, 26"},"doctrix":{"lemma":"doctrix","pos":"","gen":"","def":"doctor, she who instructs, an instructress, teacher: (sapientia) doctrix est disciplinae Dei, Vulg. Sap. 8, 4; August. de Mor. Eccl. Cath. 16; Serv. Verg. A. 12, 159"},"dogma":{"lemma":"dogma","pos":"","gen":"","def":"(also fem.: Pythagoream dogmam doctus, Laber. ap. Prisc. p. 679 fin. P.), = δόγμα, a philosophic tenet, doctrine, dogma, Cic. Ac. 2, 43, 133; id. Fin. 2, 32, 105; Mart. 1, 9; Juv. 13, 121"},"domnus":{"lemma":"domnus","pos":"","gen":"","def":"dominus init. dŏmo, ui, ĭtum (also dŏmāvi, Poëta ap. Charis. p. 252 P.; cf. Flor. 3, 22, 6: domata, Petr. 74, 14), 1, v. a. Sanscr. root dam-, dām - yāmi, to be tame; Gr. δαμνηι, δάμαρ, δαμάλης, δμώς"},"dorceus":{"lemma":"Dorceus","pos":"","gen":"","def":", Δορκεύς (qs. gazellecatcher), the name of one of Actaeon's hounds, Ov. M. 3, 210"},"dormisco":{"lemma":"dormisco","pos":"","gen":"","def":"inch. , to fall asleep, Prisc. 824 P. dormītātĭo, ōnis, f. dormito, sleep (eccl. Lat.), Vulg. Psa. 131, 4; id. Prov. 23, 21; Hil. in Psa. 118, 4, 7"},"dorso":{"lemma":"Dorso","pos":"","gen":"","def":", a Roman surname, Liv. 5, 46; 7, 28 al. dorsŭālis, e, adj. dorsum, of or on the back, dorsal (post-class): notae equi, App. M. 11, p. 266, 32; cf.: crustae ferarum, Amm. 22, 15"},"dorsum":{"lemma":"dorsum","pos":"","gen":"","def":"(masc. dorsus, Plaut. Mil. 2, 4, 44; quoted ap. Non. 203, 6) , the back (in class. prose, only of beasts of burden; poet. and later also of men; cf.: tergum, tergus). Prop., Plaut. l. l."},"draucus":{"lemma":"draucus","pos":"","gen":"","def":", a sodomite, Mart. 9, 27, 10; id. 1, 96, 12; cf.: draucus, καταπύγων, Gloss. Philox. Draus or Dravus, i, m., the river Drave in Hungary, Plin. 3, 25, 28, § 147; Flor. 4, 12, 8."},"drenso":{"lemma":"drenso","pos":"v.","gen":"","def":"n., expresses the note of the swan, Auct. Philom. 23. Drĕpăna, ōrum, n., = Δρέπανα, a town on the western coast of Sicily, now Trapani, Cato acc. to Serv. Verg. A. 3, 707, Plin. 3, 8, 14, § 90"},"drungus":{"lemma":"drungus","pos":"","gen":"","def":", a body of soldiers, a troop (late Lat.), Veg. Mil. 3, 16; Vop. Prob. 19. druppa or drūpa (sc.) oliva = δρύππα (v. Lidd. and Scott under δρυπεπής), an over-ripe, wrinkled olive, Plin. 15, 1, 2, § 6"},"dryas":{"lemma":"Dryas","pos":"","gen":"","def":", = Δρύας. The father of Lycurgus king of Thrace, Hyg. Fab. 132; Serv. Verg. A. 3, 14.—Hence, Dryantīdes, ae, m., i. e. Lycurgus, Ov. Ib. 347"},"dryops":{"lemma":"Dryops","pos":"","gen":"","def":"One of the Dryopes, a people of Epirus, Ov. Ib. 490; usu. plur.: Dryŏpes, um, the Dryopians, Plin. 4 praef."},"dua":{"lemma":"dua","pos":"","gen":"","def":"duo. dŭālis, e, adj. duo, that contains two: numerus (nasi), i. e. the dual number, duality, Lact. Opif. D. 10, 9.—In gram. lang.: numerus, the dual, Quint. 1, 5, 42 al. dŭālĭtas, ātis, f."},"ductim":{"lemma":"ductim","pos":"adv.","gen":"","def":"id., by drawing (very rare): major pars operis in vinea ductim, potius quam caesim faciendaest (for which, shortly after: ductu falcis, non ictu), Col. 4, 25, 2: invergere in me liquores"},"ducto":{"lemma":"ducto","pos":"","gen":"","def":"freq. a. id., to lead or draw, conduct (very freq. in Plaut.; elsewh. perh. only in Ter., Sall., and once in Tac."},"ductor":{"lemma":"ductor","pos":"","gen":"","def":"id., a leader, commander, chief, general (class.; a favorite word of Vergil, used by him more than 20 times; cf.: dux, imperator, princeps, praetor, praefectus, etc.): exercitus, * Cic. Tusc. 1, 37"},"ductrix":{"lemma":"ductrix","pos":"","gen":"","def":"ductor, a female chief, a general: Penthesilea, Dar. Phryg. 36. ductus, a, um, Part., from duco."},"ductus":{"lemma":"ductus","pos":"","gen":"","def":"duco, a leading, conducting (class.). Lit. In gen.: aquarum, Cic. Off. 2, 4, 14; id. Leg. 2, 1, 2; cf. the work of Frontinus: De aquaeductibus"},"duidens":{"lemma":"duidens","pos":"","gen":"","def":"bidens, II. b. Dŭīlĭus or Dŭillĭus, v. Duellius. dŭim, v. do init. dŭis, verb., v. do init.— Num., v. bis init. dŭītae, ārum, m. duo, heretics who believed in two gods, Prud. Hamart. praef. 37."},"dulce":{"lemma":"dulce","pos":"adv.","gen":"","def":", sweetly, pleasantly, v. dulcis, fin. . dulcēdo, ĭnis, f. dulcis, sweetness. Lit., a sweet taste (rare): radix amara cum quadam dulcedine, Plin. 25, 6, 30, § 66"},"dulcesco":{"lemma":"dulcesco","pos":"","gen":"","def":"inch. n. , to become sweet, Cic. de Sen. 15, 53; Plin. 3, 18, 22, § 127; 31, 7, 41, § 70"},"dulco":{"lemma":"dulco","pos":"v.","gen":"","def":"a. id., to sweeten (late Lat.), Sid. Ep. 5, 4; id. Carm. 2, 105."},"dulcor":{"lemma":"dulcor","pos":"adv.","gen":"","def":"id., sweetness (cf. the opp. amaror; late Lat.), Tert. adv. Marc. 1. 6; 3, 5; Vulg. Sirach, 11, 3 al. dulcōro, āre, 1, v. a. dulcor, to sweeten (late Lat.): amaritudinem, Hier. Ep. 22, 9"},"duntaxat":{"lemma":"duntaxat","pos":"","gen":"","def":"dumtaxat. dŭŏ, ae, ŏ (acc. masc. duo as freq. as duos; cf. ambo. Passages with duo, Att. ap. Charis. p. 101 P.; Plaut. Ep. 2, 2, 4; 3, 2, 37; id. Most. 3, 2, 89; 147; 148; id. Ps. 1, 3, 99; 4, 2, 43"},"duonus":{"lemma":"duonus","pos":"","gen":"","def":"bonus init. dŭŏvir, vĭri, and usu. plur. dŭŏvĭri (less correctly dŭumvĭri, Zumpt, Gram. § 124; Krebs, Antibarb. p. 391; in MSS. and Inscr. usu. II. vir, II. viri"},"duris":{"lemma":"Duris","pos":"","gen":"","def":", a Greek author, of Samos, Cic. Att. 6, 1, 18"},"duronius":{"lemma":"Duronius","pos":"","gen":"","def":", a Roman proper name, Cic. de Or. 2, 68, 274 al. dūrus, a, um, adj. etym. dub."},"dux":{"lemma":"dux","pos":"","gen":"-in","def":"duco, a leader, conductor, guide (for syn. cf.: imperator, ductor, tyrannus, rex, princeps, praetor, auctor). In gen.: illis non ducem locorum, non exploratorem fuisse, Liv. 9, 5, 7"},"dyas":{"lemma":"dyas","pos":"","gen":"","def":", = δυάς, the number two, Macr. Somn. Scip. 1, 6, 18; 1, 12, 5; Aug. Conf. 4, 15."},"dymas":{"lemma":"Dymas","pos":"adj.","gen":"-mantis","def":", = Δύμας, the father of Hecuba, Ov. M. 11, 761; Serv. Verg. A. 7, 320; Hyg. Fab. 91; 111.—Hence, Dy-mantis, ĭdis, adj., of Dymas: proles, i. e. Hecuba"},"dynastes":{"lemma":"dynastes","pos":"","gen":"","def":", = δυνάστης, a ruler, prince (partic. of a small country), Cic. Phil. 11, 12 fin.; Caes. B. C. 3, 3, 2; Nep. Dat. 2"},"dyraspes":{"lemma":"Dyraspes","pos":"","gen":"","def":", a river in Scythia, Ov. Pont. 4, 10, 53. Dyrrăchĭum (Dyrrh-), ii, n., = Δυρράχιον, a famous sea-coast town of Grecian Illyria, the landing-place of those coming from Italy"},"dyspnoea":{"lemma":"dyspnoea","pos":"","gen":"","def":", = δύσπνοια, a difficulty of breathing, Plin. 23, 4, 47, § 92"},"ea":{"lemma":"is","pos":"pron.","gen":"-class","def":"eis, C. I. L. 1, 198; n. it, ib. 5, 875 al., and freq. in MSS. of Plaut.), gen. ējus (old form eiius, C. I. L. 3, 1365 et saep.; v. Prisc. 1, 4, 18, p. 545; also etius, ib. 2, 1276 al.","form_of":"is"},"eam":{"lemma":"is","pos":"pron.","gen":"-class","def":"eis, C. I. L. 1, 198; n. it, ib. 5, 875 al., and freq. in MSS. of Plaut.), gen. ējus (old form eiius, C. I. L. 3, 1365 et saep.; v. Prisc. 1, 4, 18, p. 545; also etius, ib. 2, 1276 al.","form_of":"is"},"eas":{"lemma":"is","pos":"pron.","gen":"-class","def":"eis, C. I. L. 1, 198; n. it, ib. 5, 875 al., and freq. in MSS. of Plaut.), gen. ējus (old form eiius, C. I. L. 3, 1365 et saep.; v. Prisc. 1, 4, 18, p. 545; also etius, ib. 2, 1276 al.","form_of":"is"},"ebromagus":{"lemma":"Ebromagus","pos":"","gen":"","def":", a city in the province of Gaul, now Bram, Cic. Font. 5, 9 Halm (Kayser, Cobiamachus, § 19). ĕbŭlīnus, a, um, adj. ebulum, of elder-wood, Plin. Val. 1, 64. ē-bullĭo, īre, 4 (and post-class. ēbullo"},"ecca":{"lemma":"ecca","pos":"","gen":"","def":"ecce, II. D. ecce, adv. demonstr. [perh. from locat. form of pronom. stem i, with demonstr. ending -ce"},"eccentros":{"lemma":"eccentros","pos":"adj.","gen":"","def":", = ἔκκεντρος, out of the centre, eccentric: terra, Mart. Cap. 8, § 849 al. eccĕre or ĕcĕre, interj. ecce and abl. of res, see there in fact! lo in truth! Corss. Aussp. 2, 858, 1028"},"eccheuma":{"lemma":"eccheuma","pos":"","gen":"","def":", = ἔκχευμα, a pouring out, Plaut. Poen. 3, 3, 88."},"eccillam":{"lemma":"eccillam","pos":"","gen":"","def":"ecce, II. D. ecclēsĭa (ēcclĕsĭa, Sedul. 5, 358; Venant. Carm. 3, 6, 24; and ĕclĕsĭa, Paul. Nol. Carm. 15, 117"},"eccum":{"lemma":"eccum","pos":"","gen":"","def":"ecce, II. D. ecdĭcus, i, m., = ἐκδικός, i. q. cognitor or defensor civitatis, a syndic, solicitor of a community (esp. in Asia Minor), Cic. Fam. 13, 56, 1 and 3"},"ecquando":{"lemma":"ecquando","pos":"adv.","gen":"","def":"interrog. , ever, at any time"},"ecqui":{"lemma":"ecqui","pos":"adj.","gen":"","def":"Zumpt ad Cic. Verr. 2, 4, 11, § 25, and v. aliqui), ecquod (gen. is not in use), pron. interr. adj. , Is there any one who? Any? in impassioned interrogation, i. q. num qui"},"ecquisnam":{"lemma":"ecquisnam","pos":"","gen":"","def":"ecquis, I. fin."},"ecquo":{"lemma":"ecquo","pos":"adv.","gen":"","def":", v. ecquis, II. C. ecrāgīno, āre, 1, v. n., = ἐκραγῆναι, to break forth, Petr. 61, 9. ecstăsis, is, f., = ἔκστασις, a being beside one's self, ecstasy, trance, rapture (eccl. Lat.)"},"ecthlipsis":{"lemma":"ecthlipsis","pos":"","gen":"","def":", = ἔκθλιψις, gram. t. t., ecthlipsis, the elision of a final m with its vowel before an initial vowel, Diom. 2, p. 436"},"ectypus":{"lemma":"ectypus","pos":"adj.","gen":"","def":", = ἔκτυπος, engraved in relief, embossed, Plin. 35, 12, 43, § 152; 37, 10, 63, § 173"},"edessa":{"lemma":"Edessa","pos":"adj.","gen":"-place","def":", = Ἔδεσσα. A city of Macedonia, the burial-place of the kings, Liv. 45, 29"},"ef-findo":{"lemma":"ef-findo","pos":"v.","gen":"-findo","def":"a., to divide, cleave: fluctus rectos, Manil. 4, 283. ef-fingo, finxi, fictum, 3, v. a., orig., to work out by pressing = fingendo exprimere, ἐκμάσσειν (v. fingo).—Hence, To form"},"ef-firmo":{"lemma":"ef-firmo","pos":"v.","gen":"-firmo","def":"a., to strengthen, encourage, Att. ap. Non. 256, 18. efflāgĭtātĭo, ōnis, f. efflagito, an urgent demand, pressing request (very rare), * Cic. Fam. 5, 19, 2"},"ef-flammans":{"lemma":"ef-flammans","pos":"adj.","gen":"-flammans","def":"flammo, emitting flames, flaming, blazing: stellae, Mart. Cap. 2, § 207. ef-flĕo, ēvi, 2, v. a., to weep out, exhaust by weeping: oculos, Quint. decl. 6, 4. efflicte and efflictim, advv., v. effligo."},"ef-flo":{"lemma":"ef-flo","pos":"v.","gen":"-flo","def":"a. and n., to blow or breathe out (mostly poet. and post-Aug. prose). Act. In gen.: (Sol) suos efflavit ignes, Lucr. 5, 652"},"ef-for":{"lemma":"ef-for","pos":"v.","gen":"-for","def":"dep. a. (defect. In use only: effor, Cav. ap. Diom. p. 375 P.: effaris, App. M. 7, 25, p. 199, 6: effatur, Verg. A. 10, 523 al.: effamini, Arn. 7, 41: effantur, App. Mund. prooem. p. 56, 22: effabor"},"ef-fringo":{"lemma":"ef-fringo","pos":"v.","gen":"-fringo","def":"a. and n. Act., to break off, to break open: effringere quam aperire putant robustius, Quint. 2, 12, 1 (class.): cardines foribus, Plaut. Am. 4, 2, 6; id. As. 2, 3, 8"},"ef-frondesco":{"lemma":"ef-frondesco","pos":"","gen":"-frondesco","def":"inch. n., to put forth leaves, be covered with foliage, Vop. Prob. 19, 3."},"ef-frons":{"lemma":"ef-frons","pos":"adj.","gen":"-frons","def":"(putting forth the forehead, i. e. trop.), barefaced, shameless: consilium, Vop. Num. 13. ef-frŭtĭco, āre, v. a. and n. (late Lat.). * Act., to put forth, produce, transf."},"effecte":{"lemma":"effecte","pos":"adv.","gen":"","def":", in fact, really"},"effector":{"lemma":"effector","pos":"","gen":"","def":"id., an effecter, producer, author (a Ciceronian word), Cic. Univ. 5 fin.; id. Div. 2, 26; id. de Or. 1, 33, 150 (quoted in Quint. 10, 3, 1"},"effectrix":{"lemma":"effectrix","pos":"","gen":"","def":"id., she who effects, produces, causes; perh. only Cic. Fin. 2, 17, 55; id. Univ. 10, 32. effectus, a, um, Part. and P. a., from efficio."},"effectus":{"lemma":"effectus","pos":"","gen":"","def":"efficio, a doing, effecting. In gen., execution, accomplishment, performance: ad effectum consiliorum pervenire, Planc. ap. Cic. Fam. 10, 8, 4: operis, Liv. 21, 7: ad effectum aliquid adducere"},"efflicto":{"lemma":"efflicto","pos":"","gen":"","def":"freq. a. effligo, to strike dead, Plaut. Stich. 4, 2, 26. ef-flīgo, xi, ctum, 3, v. a., to strike dead, to kill, destroy (very rare): qui filium misit ad effligendum Pompeium, Cic. Att. 9, 19"},"effoecundo":{"lemma":"effoecundo","pos":"","gen":"","def":"effecundo. effoemĭno, v. effemino. effoetus and effoeto, v. effet-."},"effractor":{"lemma":"effractor","pos":"","gen":"","def":"effringo, a housebreaker, burglar (jurid. Lat.), Dig. 1, 15, 3; 47, 17, 1"},"egesta":{"lemma":"Egesta","pos":"","gen":"","def":", the Greek name of Segesta (sc. Ἔγεστα), Fest. p. 340, 5 Müll. ĕgestas, ātis, f. egeo, indigence, extreme poverty, necessity, want (very freq. and class."},"eglecopala":{"lemma":"eglecopala","pos":"","gen":"","def":", a Gallic name for blue marl, Plin. 17, 8, 4, § 46. Egnātĭa, ae, f. A city and harbor on the coast of Appulia, now Torre d' Agnazzo or Monopoli, Plin. 2, 107, 111, § 240"},"ei":{"lemma":"ei","pos":"interj.","gen":"","def":", oh! etc., Plaut. Cas. 3, 6, 7"},"eis":{"lemma":"is","pos":"pron.","gen":"-class","def":"eis, C. I. L. 1, 198; n. it, ib. 5, 875 al., and freq. in MSS. of Plaut.), gen. ējus (old form eiius, C. I. L. 3, 1365 et saep.; v. Prisc. 1, 4, 18, p. 545; also etius, ib. 2, 1276 al.","form_of":"is"},"eius":{"lemma":"is","pos":"pron.","gen":"-class","def":"eis, C. I. L. 1, 198; n. it, ib. 5, 875 al., and freq. in MSS. of Plaut.), gen. ējus (old form eiius, C. I. L. 3, 1365 et saep.; v. Prisc. 1, 4, 18, p. 545; also etius, ib. 2, 1276 al.","form_of":"is"},"elaea":{"lemma":"Elaea","pos":"","gen":"","def":", = Ἐλαία, a city of Aeolis, Mel. 1, 8, 1; Plin. 5, 30, 32, § 121"},"elagabalus":{"lemma":"Elagabalus","pos":"","gen":"","def":"Heliogabalus. ē-lambo, ĕre, 3, v. a., to lick away, remove by licking: mox ut elambente matris lingua detersa sint (animalia), Mar. Vict. Art. Metr. 4, 2, 5. ē-lāmentābĭlis, e, adj."},"elephanticus":{"lemma":"elephanticus","pos":"","gen":"","def":"preced. art. fin. Elĕphantīne, ēs, f., = Ἐλεφαντίνη, a small but very fertile island of the Nile, in the Thebaid, with a city of the same name, now Jezyret-Assuan, Mel. 1, 9, 2; 9"},"elius":{"lemma":"Elius","pos":"","gen":"","def":"Elis, II. B. ēlix, ĭcis, m. elicio, a channel for diverting a stream: elix, ἀναπνοὴ ὀχετοῦ, Gloss.; usually in plur., v. elices. ēlixātūra, ae, f. elixo, a thorough boiling"},"ellops":{"lemma":"ellops","pos":"","gen":"","def":", v. helops."},"ellum":{"lemma":"ellum","pos":"","gen":"","def":"ecce. ellychnĭum, ii, n., = ἐλλύχνιον, a lamp-wick, Plin. 23, 4, 41, § 84; 28, 11, 47, § 168; Vitr. 8, 1"},"elops":{"lemma":"elops","pos":"","gen":"","def":", v. helops. ēlŏquens, entis, Part. and P. a., from eloquor. ēlŏquenter, adv., eloquently, v. eloquor, P. a. fin. ēlŏquentĭa, ae, f. eloquor, a being eloquent, eloquence, Cic. Part. 23, 79"},"elysii":{"lemma":"Elysii","pos":"","gen":"","def":"A people of Eastern Germany, between the Oder and the Vistula, Tac. G. 43.— The Elysian Fields, v. the foll. II. Ēlysĭum, ii, n., = Ἠλύσιον, the abode of the blest, Elysium, Verg. A. 5, 735 Serv."},"em":{"lemma":"em","pos":"","gen":"","def":"q. eum, v. is init."},"embamma":{"lemma":"embamma","pos":"","gen":"","def":", = ἔμβαμμα, a sauce, Col. 12, 57 fin.; Plin. 20, 14, 53, § 147"},"emphragma":{"lemma":"emphragma","pos":"","gen":"","def":", = ἔμφραγμα, a stoppage, obstruction, Veg. Vet. 2, 12 and 19 (1, 40; 47 Bip.)."},"emphyteusis":{"lemma":"emphyteusis","pos":"","gen":"-farm","def":", = ἐμφύτευσις (lit., an implanting), in jurid. lang., a permanent tenure of land upon condition of cultivating it properly, and paying a stipulated rent, a sort of fee-farm or copyhold, Cod. Just. 4"},"emphyteuta":{"lemma":"emphyteuta","pos":"adj.","gen":"-t","def":", = ἐμφυτεύτης, the lessee in the tenure of emphyteusis, Cod. Just. 4, 66, 1 sq.; called also emphyteu-tĭcārĭus, ib. 11, 62, 1"},"emplastro":{"lemma":"emplastro","pos":"v.","gen":"","def":", ātum, 1, v. a., in horticult. lang., to inoculate by inserting a bit of the bark with the eye, to scutcheongraft, to bud, Col. 5, 11, 10; 11, 2, 37; Pall. Mai. 6; id. Nov. 7, 7."},"emplastrum":{"lemma":"emplastrum","pos":"","gen":"","def":"(or emplastra, ae, f., Gell. 16, 7 fin.), = ἔμπλαστρον. In medic. lang., a plaster. Prop., Cels. 5, 17; 19; Cato, R. R. 39, 2; Plin. 21, 4, 10, § 15"},"emplecton":{"lemma":"emplecton","pos":"","gen":"-work","def":", = ἔμπλεκτον (lit., interwoven), rubble-work, a sort of masonry in which the space between two walls is filled with broken stones and mortar, Plin. 36, 22, 51, § 171 (Vitr. 2, 8, 7"},"empylus":{"lemma":"Empylus","pos":"","gen":"","def":", =Ἔμπυλος, a rhetorician of Rhodes, Cic. ap. Quint. 10, 6, 4. empyrĭus (-rĕus), a, um, adj., = ἐμπύριος, fiery: mundi sublimitates, August. Civ. D. 10, 27. ē-mūgĭo, īre, v. a., to bellow out"},"emussitata":{"lemma":"emussitata","pos":"","gen":"","def":"amussito. ēmūtātĭo, ōnis, f. emuto, a change, alteration (with novitas), Quint. 8, 6, 51. ē-mūto, no perf., ātum, 1, v. a., to change, alter (perh. only in the foll. passages"},"encanthis":{"lemma":"encanthis","pos":"","gen":"","def":", = ἐγκανθίς, a swelling of the eyelid, Cels. 7, 7, 5. encardĭa, ae, f., = ἐγκαρδία, an unknown precious stone, with the figure of a heart on it, Plin. 37, 10, 58, § 159."},"encarpa":{"lemma":"encarpa","pos":"","gen":"","def":", = ἔγκαρπα, an architect. ornament, festoons of fruit, Vitr. 4, 1, 7. encăthisma, ătis, n., = ἐγκάθισμα, a sitting bath, Cael. Aur. Acut. 3, 18; id. Tard. 5, 4, 69"},"encomma":{"lemma":"encomma","pos":"","gen":"","def":", v. incomma. Encrătītae, ārum, m., = Ἐγκρατῖται (\"the Continent\"), a sect of Gnostics, Cod. Th. 16, 19, 1"},"enna":{"lemma":"Enna","pos":"","gen":"","def":"Henn-. Ennăĕtēris, ĭdis, f., = ἐνναετηρίς, a period of nine years, Censor. 18, 4. ennam, etiamne, Paul. ex Fest. p. 76, 2. Ennĕacrūnos, v. Callirrhoe. ennĕădĕcăĕtēris, rĭdis, f., = ἐννεακαιδεκαετηρίς"},"ennoea":{"lemma":"ennoea","pos":"adv.","gen":"","def":", = ἔννοια, an idea, notion, one of the aeons of Valentinus, Tert. adv. Val. 7. ennŏēmătĭcus, a, um, adj., = ἐννοηματικός, intellectual, notional"},"enrythmos":{"lemma":"enrythmos","pos":"adj.","gen":"","def":", = ἔνρυθμος, rhythmical, in harmony: tempora, Mart. Cap. 9, § 972; cf. § 970."},"ens":{"lemma":"ens","pos":"","gen":"","def":"sum, a thing"},"ensis":{"lemma":"ensis","pos":"","gen":"","def":"Sanscr. root as-, asyati, hurl; asi, sword, a sword, brand. Prop. (almost exclusively in the poets; synon. with gladius, acc. to Quint. 10, 1, 11"},"entella":{"lemma":"Entella","pos":"adj.","gen":"","def":", = Ἔντελλα, a city in the interior of Sicily, now Rocca d' Entella, Sil. 14, 204.—Hence, Entellīni, ōrum, m., the inhabitants of Entella, Plin. 3, 8, 14, § 91.—In sing., Entellinus, Cic. Verr. 2, 3"},"entellus":{"lemma":"Entellus","pos":"","gen":"","def":", a Sicilian hero, famous as a pugilist, Verg. A. 5, 387 sq. entĕrŏcēle, ēs, f., = ἐντεροκήλη, a rupture, hernia, Plin. 26, 13, 83, § 134; Mart. 10, 56"},"eon":{"lemma":"eon","pos":"","gen":"","def":", an unknown tree, Plin. 13, 22, 39, § 119. ĕōpse, v. ipse init. Ēōs (only in nom.), f., = Ἠώς, the dawn (pure Lat. Aurora), Ov. F. 3, 877; 4, 389"},"eos":{"lemma":"is","pos":"pron.","gen":"-class","def":"eis, C. I. L. 1, 198; n. it, ib. 5, 875 al., and freq. in MSS. of Plaut.), gen. ējus (old form eiius, C. I. L. 3, 1365 et saep.; v. Prisc. 1, 4, 18, p. 545; also etius, ib. 2, 1276 al.","form_of":"is"},"ephi":{"lemma":"ephi","pos":"","gen":"","def":"indecl., a Hebrew measure, used for grain, oil, etc."},"ephod":{"lemma":"ephod","pos":"","gen":"","def":"indecl., part of the clothing of the Hebrew priest, Vulg. Exod. 25, 7 al. ĕphŏrus, i (nom. plur. ephoroe = ἔφοροι, Val. Max. 1, 41, ext. 8), m., = ἔφορος"},"epicactis":{"lemma":"epicactis","pos":"","gen":"","def":"epipactis. ĕpĭcēdīon or -īum, ii, n., = ἐπικήδειον, a funeral song, dirge, Stat. S. 2 praef."},"epolonus":{"lemma":"epolonus","pos":"","gen":"","def":"epulo init. ĕpomphălĭon, ĭi, n., = ἐπομφάλιον, a plaster for the uterus, Fulg. Myth. 2, 5 fin. Epŏna, ae, f. from equus; cf. Gr. ἵππος"},"erant":{"lemma":"sum","pos":"","gen":"","def":"(form of sum)"},"erat":{"lemma":"sum","pos":"","gen":"","def":"(form of sum)"},"erembi":{"lemma":"Erembi","pos":"","gen":"","def":", = Ἐρεμβοί, the Troglodytes in Africa, Avien. Descr. Orb. 271"},"ericinium":{"lemma":"Ericinium","pos":"","gen":"","def":", a city of Thessaly, in Perrhaebia, Liv. 36, 13; 39, 25 fin. ērĭcīnus, a, um, adj. ericius, of the hedgehog: caro, August. cont. Faust. 30, 1"},"erindes":{"lemma":"Erindes","pos":"","gen":"","def":", a river between Media and Hyrcanea, Tac. A. 11, 10. ĕrīnĕos, i, f., = ἐριϝεός, a plant, perh. the Campanula Rapunculus, Linn., Plin. 23, 7, 65, § 131. Ērinna, ae, f., = Ἤριϝϝα"},"eris":{"lemma":"Eris","pos":"","gen":"","def":", = Ἔρις, the goddess of strife, Hyg. F. 92. Erĭsichthon, v. Erysichthon. ĕrisma, ae, f., and ĕrisma, ătis, n., = ἔρεισμα, a buttress, Front. Aquaed. 18"},"eriza":{"lemma":"Eriza","pos":"adj.","gen":"","def":", = Ἔριζα, a town of Magna Phrygia, Liv. 38, 14, 1.—Hence, Erizēnus, a, um, adj., of Eriza: regio, Plin. 10, 43, 60, § 124. ernĕum, i, n., a cake baked in an earthen pot, Cato R. R. 81. ēro"},"eros":{"lemma":"Eros","pos":"","gen":"","def":", = Ἔρως. Love as a person; Lat. Amor, Cupido, Nemes. Ecl. 4 lem.— In gen., a common name of Roman slaves or freedmen, Cic. Fam. 12, 26; id. Att. 10, 15; 15, 15; 20"},"errantia":{"lemma":"errantia","pos":"","gen":"","def":"id., a wandering: animi, Att. ap. Non. 204, 13 (Rib. Fragm. Trag. p. 196). errātĭcus, a, um, adj. id., wandering to and fro, wandering about, roving"},"erro":{"lemma":"erro","pos":"v.","gen":"-o","def":"n. and a. [root er-, to go; desiderative forms, ἔρχομαι (ἐρσκ-); and Lat. (ers-o) erro, to seek to reach; hence, to wander; cf. Germ. irren"},"error":{"lemma":"error","pos":"","gen":"","def":"id., a wandering. In gen., a wandering, straying or strolling about (rare and mostly poet.). Lit.: ad quos Ceres in illo errore venisse dicitur, Cic. Verr. 2, 4, 49"},"erucius":{"lemma":"Erucius","pos":"","gen":"","def":", a Roman proper name, Cic. Rosc. Am. 13 al. ēructātĭo, ōnis, f. eructo, a casting or throwing upward (post-class. and rare): altera (exhalatio) arida est atque animae similis"},"erycus":{"lemma":"Erycus","pos":"","gen":"","def":", v. Eryx."},"erymanthus":{"lemma":"Erymanthus","pos":"adj.","gen":"","def":", = Ἐρύμανθος. A chain of mountains in Arcadia, on the borders of Elis, where Hercules slew the boar named after the place, Ov. H. 9, 87; id. M. 5, 608"},"esca":{"lemma":"esca","pos":"","gen":"","def":"sing. escas, Liv. Andron. ap. Prisc. p. 679 P.), f. for edca, v. esco, and edo; cf. Varr. L. L. 6, § 84 Müll., food, both of men and beasts (class."},"escit":{"lemma":"escit","pos":"","gen":"","def":"sum init."},"esco":{"lemma":"esco","pos":"v.","gen":"","def":"a. for edsco, from edo, Corss. Ausspr. 2, 257, to eat: escandi gratia, Sol. 40 fin. escŭlentus, a, um, adj. id., fit for eating, good to eat, eatable, edible, esculent"},"escunt":{"lemma":"escunt","pos":"","gen":"","def":"sum init. ēsĭto, āvi, ātum, 1, v. freq. a. 1. edo, to be wont to eat, to eat (ante- and post-class.): brassicam, Cato R. R. 157, 10 (cited in Plin. 20, 9, 33, § 83; Plaut. Capt. 1, 2, 85"},"esse":{"lemma":"sum","pos":"","gen":"","def":"(form of sum)"},"esset":{"lemma":"sum","pos":"","gen":"","def":"(form of sum)"},"est":{"lemma":"sum","pos":"","gen":"","def":"(form of sum)"},"estrix":{"lemma":"estrix","pos":"","gen":"","def":"esor, a female glutton or gormandizer, Plaut. Cas. 4, 1, 20. ēstur, for editur, v. 1. ĕdo init. Esubĭi, ōrum, m. a Gallic tribe west of the Sequana, Caes. B. G. 3, 7 fin."},"et-si":{"lemma":"et-si","pos":"conj.","gen":"-si","def":", like etiamsi, a concessive conditional particle, though, although, albeit. Prop. With indic.: gaudeo, etsi nihil scio, quod gaudeam, Plaut. Capt. 4, 2, 62: etsi scio ego, Philumena"},"eu":{"lemma":"eu","pos":"interj.","gen":"","def":", = εὖ, well! well done! bravo! an exclamation of joy or approbation, Plaut. Most. 1, 4, 26; Ter. Phorm. 3, 1, 14; Plaut. Mil. 4, 4, 10; Ter. Eun. 1, 2, 74"},"euan":{"lemma":"Euan","pos":"","gen":"","def":"Euhan. Euander (Gr. nom. -drus, Verg. A. 8, 100, 185 al.; voc. -dre, id. ib. 11, 55. Less correctly, Evander), dri, m., = Εὔανδρος. Son of Carmenta (v. Carmentis), born at Pallantium, in Arcadia"},"euax":{"lemma":"euax","pos":"interj.","gen":"","def":"only Plautine, expressive of delight at some tidings or event, hail! joy! good! Plaut. Bacch. 2, 3, 13; 4, 4, 72; Cassiod. 4, 4, 13."},"euboea":{"lemma":"Euboea","pos":"adj.","gen":"","def":", = Εὔβοια, an island in the Aegean Sea, separated from Boeotia by Euripus, now Negroponte, Mel. 2, 7, 9; Plin. 4, 12, 21, § 63"},"euchadia":{"lemma":"Euchadia","pos":"","gen":"","def":", a Greek proper name, Cic. Pis. 36, 89. euchăris, is, adj., = εὔχαρις, agreeable, grateful, Vulg. Sir. 6, 5. euchăristĭa, ae, f., = εὐχαριστία. A thanksgiving"},"eudaemon":{"lemma":"Eudaemon","pos":"","gen":"","def":", = Εὐδαίμων (fortunate), the Greek appellation of the southern part of Arabia (Arabia Felix), Mel. 3, 8, 6; Plin. 6, 27, 31, § 138; Sol. 33, 4; and of its inhabitants, Vop. Aurel. 33"},"eudoxus":{"lemma":"Eudoxus","pos":"","gen":"","def":", = Εὔδοξος, a Greek astrologer, a disciple of Plato, Cic. Div. 2, 42, 87; id. Rep. 1, 14 al. Euēnus (-nos, also Ēvēnus), i, m., = Εὔηνος, a king of Etolia, father of Marpessa"},"euias":{"lemma":"Euias","pos":"","gen":"","def":"Euhius."},"eum":{"lemma":"is","pos":"pron.","gen":"-class","def":"eis, C. I. L. 1, 198; n. it, ib. 5, 875 al., and freq. in MSS. of Plaut.), gen. ējus (old form eiius, C. I. L. 3, 1365 et saep.; v. Prisc. 1, 4, 18, p. 545; also etius, ib. 2, 1276 al.","form_of":"is"},"eumaeus":{"lemma":"Eumaeus","pos":"","gen":"","def":", = Εὔμαιος, the swineherd of Ulysses in Homer, Varr. R. R. 2, 4, 1"},"eumitres":{"lemma":"eumitres","pos":"","gen":"","def":", an unknown precious stone, Plin. 37, 10, 58, § 160."},"eumolpus":{"lemma":"Eumolpus","pos":"","gen":"","def":", = Εὔμολπος, a fabulous Thracian singer and priest of Ceres, who brought the Eleusinian mysteries and the culture of the vine to Attica, Plin. 7, 56, 57, § 199.—His descendant of the same name"},"euonymos":{"lemma":"evonymos","pos":"","gen":"","def":", v. euonymos. ē-vulgo (evolgo), āvi, ātum, 1, v. a., to bring out among the people, to publish, divulge (not ante-Aug., and very rare): civile jus repositum in penetralibus pontificum evulgavit"},"euphorbus":{"lemma":"Euphorbus","pos":"","gen":"","def":", = Εὔφορβος. Son of Panthus, a brave Trojan, whose soul Pythagoras asserted had descended to himself, through the process of transmigration, Ov. M. 15, 161"},"euplia":{"lemma":"euplia","pos":"","gen":"","def":", an unknown plant, Plin. 25, 10, 81, § 130. euplŏcămus, i, m., = εὐπλόκαμος, having beautiful locks, Lucil. ap. Non. 35, 31. Eupŏlĕmus, i, m., = Εὐπόλεμος, a Greek proper name, Cic. Verr. 2, 4"},"eurus":{"lemma":"eurus","pos":"","gen":"","def":", = εὖρος, the southeast wind (pure Lat. Vulturnus), Col. 11, 2, 65; 5, 5, 15; Sen. Q. N. 5, 16; Plin. 2, 47, 46, § 119; Gell. 2, 22, 7 sq.; Vitr. 1, 6; Hor. C 1, 28, 25"},"eurymus":{"lemma":"Eurymus","pos":"","gen":"","def":", = Εὔρυμος, a seer, father of the seer Telemus, Hyg. Fab. 125 and 128.—Whence, Eurymĭdes, ae, m., the surname of Telemus, Ov. M. 13, 771. Eurynŏme, ēs, f., = Εὐρυνόμη, daughter of Oceanus and Tethys"},"eurypylus":{"lemma":"Eurypylus","pos":"adj.","gen":"-lis","def":", = Εὐρύπυλος. Son of Hercules and king of the island of Cos, Ov. M. 7, 363.—Hence, Eurypy-lis, ĭdis, f., adj., Eurypylan, poet. i. q. Coan: textura, Prop. 4 (5), 5, 23.— Son of Euaemon of Thessaly"},"eurytus":{"lemma":"Eurytus","pos":"","gen":"","def":", = Εὔρυτος. King of Oechalia and father of Iole, Ov. M. 9, 356.—Whence Iole is called Eurytis, ĭdis, f., Ov. M. 9, 395"},"euterpe":{"lemma":"Euterpe","pos":"","gen":"","def":", = Εὐτέρπη, the muse of music, Hor. C. 1, 1, 33; Aus. Idyll. 20, 4."},"euthalos":{"lemma":"euthalos","pos":"","gen":"","def":", a kind of laurel, also called daphnoides, Plin. 15, 30, 39, § 132 (al. eupetalos). euthĕriston, i, n., = εὐθέριστον, a balsam-tree, Plin. 12, 25, 54, § 114. euthīa, ae, f., = εὐθεῖα"},"euthygrammum":{"lemma":"euthygrammum","pos":"","gen":"","def":", = εὐθύγραμμον, an architect's rule, Vitr. 1, 1. Eutrăpĕlus, i, m., = Εὐτράπελος (witty), a surname given to P. Volumnius, a friend of Marc Antony, Cic. Att. 15, 8, 1"},"ex-albesco":{"lemma":"ex-albesco","pos":"","gen":"-albesco","def":"inch. n., to become white. Lit. (very rarely), Gell. 12, 1, 12.—More freq., Trop., to grow white, turn pale from fright, etc., Enn. ap. Cic. de Or. 3, 58, 218; and in Fin. 5, 11, 31"},"ex-albo":{"lemma":"ex-albo","pos":"v.","gen":"-albo","def":", ātum, 1, v. a. albus, to make white, Tert. adv. Marc. 4, 10"},"ex-alto":{"lemma":"ex-alto","pos":"v.","gen":"-alto","def":"a. altus (postAug."},"ex-amplexor":{"lemma":"ex-amplexor","pos":"v.","gen":"-amplexor","def":"dep. a., to clasp, embrace, Auct. Her. 4, 52 fin. ex-ămurco, āre, v. a. amurca.Prop., to cleanse from dregs.—Transf., to deprive of moisture, to dry, App. M. 4, p. 149, 14. ex-ămussim, adv. amussis"},"ex-apto":{"lemma":"ex-apto","pos":"v.","gen":"-apto","def":"a., to fit, adjust: Deo coronas, App. M. 11, p. 271, 19."},"ex-aptus":{"lemma":"ex-aptus","pos":"adj.","gen":"-aptus","def":", fastened (very rare): exaptum pendere onus ingens, Lucil. ap. Non. 235, 7; cf.: ex quo orbe pendeant exapta catenis tintinabula, Varr. ap. Plin. 36, 13, 19, § 92"},"ex-ardesco":{"lemma":"ex-ardesco","pos":"","gen":"-ardesco","def":"inch. n., qs. to blaze out, i. e. to kindle, take fire (class.; esp. freq. in the trop. sense and in Cic."},"ex-areno":{"lemma":"ex-areno","pos":"","gen":"-areno","def":"exhareno. ex-āresco, rŭi, 3, v. inch. n., to dry up, become completely dry (rare, but class.). Lit.: vestimenta uvida, Plaut. Rud. 2, 7, 20: frumentum, Varr. R. R. 1, 32: silva omnis radicitus"},"ex-armo":{"lemma":"ex-armo","pos":"v.","gen":"-armo","def":"a., to deprive of arms, to disarm (post-Aug.). Lit.: cohortes, Tac. H. 2, 76 fin.: dextras, Luc. 5, 356: Medos, id. 8, 387; Col. 7, 3, 5"},"ex-ballisto":{"lemma":"ex-ballisto","pos":"v.","gen":"-ballisto","def":"a. ballista, a comically formed word, to put an end to, to finish or conquer with the ballista: Ballionem exballistabo lepide, Plaut. Ps. 2, 1, 10. exbĭbo, ĕre, = ebibo, to drink out"},"ex-caeco":{"lemma":"ex-caeco","pos":"v.","gen":"-caeco","def":"a., to blind, make blind (rare). Lit.: num ergo is excaecat nos aut orbat sensibus? etc., * Cic. Ac. 2, 23, 74; Plin. 20, 18, 76, § 200"},"ex-caldo":{"lemma":"ex-caldo","pos":"v.","gen":"-caldo","def":"a. caldus, to wash or bathe in warm water (late Lat.), Marc. Empir. 26"},"ex-cerno":{"lemma":"ex-cerno","pos":"v.","gen":"-cerno","def":"a., to sift out, to separate (perh. not ante-Aug.). In gen.: furfures a farina, Col. 8, 4, 1: frumenta, i. e. to cleanse, id. 2, 20, 5"},"ex-cerpo":{"lemma":"ex-cerpo","pos":"v.","gen":"-cerpo","def":"a. carpo, to pick or take out. * Lit.: semina pomis, Hor. S. 2, 3, 272.— Trop. (class.). To pick out, choose, select, gather: non solum ex malis eligere minima oportere, sed etiam excerpere ex ipsis"},"ex-condo":{"lemma":"ex-condo","pos":"v.","gen":"-condo","def":"a., to form, exhibit (post-class.): aliquem, Tert. adv. Marc. 5, 18. ex-congrŭus, a, um, adj., not agreeing, not harmonious: laus, Symm. Or. pro Syn. 5 ed. Mai. ex-consŭlāris, is, m."},"ex-cornis":{"lemma":"ex-cornis","pos":"adj.","gen":"-cornis","def":"cornu, without horns: bestia, Tert. Pall. 5."},"ex-cors":{"lemma":"ex-cors","pos":"adj.","gen":"-cors","def":"cor, the heart, as the seat of intelligence; v. cor, without intelligence, without understanding, senseless, silly, stupid (class."},"ex-creo":{"lemma":"ex-creo","pos":"","gen":"-creo","def":"exscreo. excrescentĭa, ium, n., v. excresco, B. 2."},"ex-cresco":{"lemma":"ex-cresco","pos":"","gen":"-cresco","def":"inch. n., to grow out or forth, to grow up, rise up (not ante-Aug.). Lit. In gen.: quae si satis excreverint (palmae), Col. 4, 21, 3: abies, larix, palma in longitudinem, Plin. 16, 30, 54"},"ex-erro":{"lemma":"ex-erro","pos":"v.","gen":"-erro","def":"n., to wander away (post-Aug. and very rare). Lit.: dexterque exerrat Arion (equus), Stat. Th. 6, 444; Anthol. Lat. 5, 172, 1; 6, 17, 22.— Trop., to deviate, err: a via veritatis, Cypr. Ep. 1, 12"},"ex-herbo":{"lemma":"ex-herbo","pos":"v.","gen":"-herbo","def":"a. herba, to free from grass or woods: locum, Col. 11, 3, 11: salicem, id. 4, 31, 2. exhērēdātĭo, ōnis, f. exheredo, a disinheriting, Quint. 7, 1, 53"},"ex-hinc":{"lemma":"ex-hinc","pos":"adv.","gen":"-hinc","def":", hereupon, after this, then (post-class. and very rare, for exinde, exin), App. M. 11, p. 269, 19. exhŏnōrātio, ōnis, f. exhonoro, a dishonoring, Aug. Civ. D. 5, 18, 2. ex-hŏnōro, āre, v. a."},"ex-hortor":{"lemma":"ex-hortor","pos":"v.","gen":"-hortor","def":"dep. a. (act.: exhortavit, Petr. 76, 10"},"ex-ignesco":{"lemma":"ex-ignesco","pos":"","gen":"-ignesco","def":"inch. n., to become ignited, turn to fire: mundus tum exignescere, tum exaquescere videtur, Censor. de Die Nat. 18. ex-ĭgo, ēgi, actum, 3, v. a. ago, to drive out or forth, to thrust out"},"ex-lex":{"lemma":"ex-lex","pos":"adj.","gen":"-lex","def":", beyond the law, bound by no law, lawless (only nom. and acc.; rare but class.): postremo quaero, parebis legibus an non? anne exlex solus vives? Varr. ap. Non. 10, 19; cf. Lucil. ib. 22"},"ex-opto":{"lemma":"ex-opto","pos":"v.","gen":"-opto","def":"a., to wish or desire greatly, to long for a thing (class.). With acc.: quae majori parti pulcherrima videntur, ea maxime exoptant, Cic. Off. 1, 32, 118: Samnitium adventum, Liv. 9, 25"},"ex-orno":{"lemma":"ex-orno","pos":"v.","gen":"-orno","def":"a., to fit out, equip, furnish, supply with any thing. In gen. (rare"},"ex-pallesco":{"lemma":"ex-pallesco","pos":"","gen":"-pallesco","def":"inch. n., to grow or turn very pale (perh. occurring only in the perf.): viden' ut expalluit! Plaut. Curc. 2, 3, 32; Ov. M. 6, 602; Plin. Ep. 1, 5, 13"},"ex-palmo":{"lemma":"ex-palmo","pos":"v.","gen":"-palmo","def":"a., to slap, box, strike, ῥαπίζω, ex-palmo, Gloss.: manibus, August. in Psa. 56, 13."},"ex-pando":{"lemma":"ex-pando","pos":"v.","gen":"-pando","def":"2, 103, 106, § 228; 9, 33, 52, § 103; 31, 6, 37, § 70; the latter, Caecil. ap. Gell. 15, 15, 2"},"ex-partus":{"lemma":"ex-partus","pos":"adj.","gen":"-partus","def":"pario, of female animals, past bearing: pecudes, Varr. R. R, 2, 5, 7, p. 181 Bip. expassus, a, um, Part., from expando. expatare in locum patentem se dare, sive in spatium se conferre"},"ex-pello":{"lemma":"ex-pello","pos":"v.","gen":"-pello","def":"a., to drive out or away, thrust out or away, to eject, expel (class.). Lit.: haec tanta virtus ex hac urbe expelletur, exterminabitur, proicietur? Cic. Mil. 37, 101: me ex re publica, id. Fam. 6, 6"},"ex-pers":{"lemma":"ex-pers","pos":"adj.","gen":"-pers","def":"pars, having no part in, not sharing in, not privy to. Prop. (rare but class.).—Constr. with gen.: ne expers partis esset de nostris bonis, Ter. Heaut. 4, 1"},"ex-pingo":{"lemma":"ex-pingo","pos":"v.","gen":"-pingo","def":"a., to paint, depict"},"ex-pinso":{"lemma":"ex-pinso","pos":"v.","gen":"-pinso","def":"a., to bruise to pieces, grind: far, Cato, R. R. 2, 4. ex-pĭo, āvi, ātum, 1, v. a., to make satisfaction, amends, atonement for a crime or a criminal; to purify any thing defiled with crime"},"ex-piscor":{"lemma":"ex-piscor","pos":"v.","gen":"-piscor","def":"dep. a. (lit., to fish out; hence, trop.), to search out, find out (perh. only vulg."},"ex-planto":{"lemma":"ex-planto","pos":"v.","gen":"-planto","def":"a., to pull up, root out a plant (post-Aug.): pampinos, Col. 4, 14, 1; cf. id. 4, 29, 11; 11, 2, 38 al."},"ex-porto":{"lemma":"ex-porto","pos":"v.","gen":"-porto","def":"a., to bear or carry out, to bring out, convey away, export (class.): per mare e Phoenice Europam (Juppiter), Varr. R. R. 2, 5, 5: aurum quotannis ex Italia Hierosolymam, Cic. Fl. 28"},"ex-posco":{"lemma":"ex-posco","pos":"v.","gen":"-posco","def":"a., to ask earnestly, to beg, request, to entreat, implore (rare but class.). In gen.: quam (misericordiam) ipse non implorat, ego autem repugnante hoc et imploro et exposco, * Cic. Mil. 34"},"ex-pugno":{"lemma":"ex-pugno","pos":"v.","gen":"-pugno","def":"fut. expugnassere, Plaut. Am. 1, 1, 55), v. a., to take by assault, to storm, capture, reduce, subdue (freq. and class."},"ex-pungo":{"lemma":"ex-pungo","pos":"v.","gen":"-pungo","def":"a. * Lit., to prick out: nates jam diu sunt saepe expunctae, Plaut. Pers. 5, 2, 67.— Hence, Transf. To strike out, cross out, blot out, erase from a list by points (set above or below). Lit."},"ex-purgo":{"lemma":"ex-purgo","pos":"v.","gen":"-purgo","def":"a., to purge, cleanse, purify (class.). Lit.: dolabella quicquid emortuum est (trunci aut vitis), Col. 4, 24, 5: capisterio quicquid exteretur, id. 2, 9, 1: lepras, psoras, lichenas, lentigines"},"ex-scalpo":{"lemma":"ex-scalpo","pos":"v.","gen":"-scalpo","def":"a., to cut out, shape. —Trop., to frame, prepare, of a passage in verse: hunc locum nostra poetica scabies coepit exscalpare, Auson. Idyl. 11 praef."},"ex-tergeo":{"lemma":"ex-tergeo","pos":"v.","gen":"-tergeo","def":"extergere, Vulg. Johan. 13, 5; praes. extergimus, id. Luc. 10, 11: extergunt, id. Baruch, 6, 12"},"ex-texo":{"lemma":"ex-texo","pos":"v.","gen":"-texo","def":"a.—Lit., to unweave; hence trop., to plunder, cheat of one's money: extexam ego illum pulcre jam, Plaut. Bacch. 2, 3, 5."},"ex-tollo":{"lemma":"ex-tollo","pos":"v.","gen":"-tollo","def":"exsustulissent, Sen. Contr. 1, 6, 4), v. a., to lift out or up, to raise up, elevate (class."},"ex-torpesco":{"lemma":"ex-torpesco","pos":"","gen":"-torpesco","def":"inch. n., to grow numb or torpid, Venat. Vit. Mart. 1, 240. ex-torquĕo, si, tum, 2, v. a., to twist out, wrench out, wrest away (class.). Lit. In gen.: ferrum e manibus, Cic. Cat. 2, 1, 2"},"ex-tundo":{"lemma":"ex-tundo","pos":"v.","gen":"-tundo","def":"a., to beat out, strike out, force out (mostly poet. and post-Aug.; not in Cic. or Caes.). Lit.: calcibus frontem extudit, Phaedr. 1, 21, 9"},"ex-turbo":{"lemma":"ex-turbo","pos":"v.","gen":"-turbo","def":"a., to drive or thrust out, to drive away, thrust away (class."},"ex-undo":{"lemma":"ex-undo","pos":"v.","gen":"-undo","def":"n. and a. Neutr., to flow out or over, to overflow (poet. and in post-Aug. prose). Lit.: fons, Plin. 2, 103, 106, § 229: per quos (rivos) exundat piscina, Col. 8, 17, 6: trunco cruor exundat"},"ex-ungo":{"lemma":"ex-ungo","pos":"v.","gen":"-ungo","def":", unctum, 3, v. a., to anoint (a Plautinian word): eluas tu an exungare, ciccum non interduim, Plaut. Rud. 2, 7, 22: exunctum, elutum in balineis, spent on ointments, id. Trin. 2, 4, 5."},"ex-unguis":{"lemma":"ex-unguis","pos":"adj.","gen":"-unguis","def":", without claws (postclass.): exunguis et excornis bestia (muraena), Tert. Pall. 5. ex-ungŭlo, āvi, 1, v. n., to lose the hoof, Veg. Vet. 2, 57 fin. ex-ŭo, ŭi, ūtum, 3, v. a. ex and root av-"},"exacte":{"lemma":"exacte","pos":"adv.","gen":"","def":", exactly, precisely, accurately, v. exigo, P. a. fin. exactĭo, ōnis, f. exigo. * A driving out, expelling: (regum), Cic. de Or. 1, 9"},"exactor":{"lemma":"exactor","pos":"","gen":"-out","def":"id.; cf. also exactio. * A driver-out, expeller: regum (Junii Valeriique), Liv. 9, 17, 11.— A demander, exactor (cf.: redemptor, manceps, magister"},"exactrix":{"lemma":"exactrix","pos":"","gen":"","def":"exactor, she who demands: rescriptorum, Aug. Ep. 135. exactus, a, um, Part. and P. a., from exigo."},"exactus":{"lemma":"exactus","pos":"","gen":"","def":"exigo, a sending off or away: mercis, i. e. disposal, sale, Quint. Decl. 12, 19. ex-ăcŭo, ŭi, ūtum, 3, v. a., to make very sharp, to sharpen, make pointed (class.). Lit.: ferramenta cote, Plin. 28, 4"},"exanguis":{"lemma":"exanguis","pos":"","gen":"","def":"exsanguis. ex-ănĭmābĭlĭter, adv. exanimo, half dead with fear or horror, Nov. ap. Non. 376, 12. ex-ănĭmālis, e, adj. pass. (perh. only in Plaut.), lifeless, dead: ni illum exanimalem faxo"},"exantlo":{"lemma":"exantlo","pos":"","gen":"","def":"exanclo. ex-ăpĕrĭo, īre, v. a., to open wide, throw open (very rare): exapertae repente delubri fores, et audita major humana vox, Tac. H. 5, 13: implicatissimam nodositatem, to undo, unloose"},"exarchus":{"lemma":"exarchus","pos":"","gen":"","def":", = ἔξαρχος, a superintendent, overseer: monasteriorum, Just. Nov. 133, 4. ex-ardĕo, ēre, 2, v. a. (eccl. Lat.). Prop., to burn: ignis, Vulg. Sir. 16, 7; cf. ib. 28, 14"},"excandesco":{"lemma":"excandesco","pos":"","gen":"","def":"inch. n., to grow hot, to take fire, kindle, to glow (class.). Lit.: cum bitumen et sulphur additum est, excandescet, Cato R. R. 95"},"excellenter":{"lemma":"excellenter","pos":"adv.","gen":"","def":", excellently; v. excello, P. a. 1. fin."},"excellentia":{"lemma":"excellentia","pos":"","gen":"-eminence","def":"excello, P. a. 1., superiority, excellence, perfection (abstr. and rel.): magna cum excellentia praestantiaque animantium reliquarum, Cic. Off. 1, 28"},"excepto":{"lemma":"excepto","pos":"","gen":"","def":"freq. a. excipio, to take out, to take up, catch (very rare): barbatulos nullos exceptans de piscina, * Cic. Par. 5, 2, 38"},"exceptor":{"lemma":"exceptor","pos":"","gen":"-hand","def":"id., one who catches up any thing said, i. e. who writes it down, an amanuensis, short-hand writer, scribe (post-Aug.). In gen., Dig. 19, 2, 19 fin."},"excessus":{"lemma":"excessus","pos":"","gen":"-possession","def":"excedo, I. A. 2. and B. 2.. A departure. In gen.: excessus ejus, Vell. 1, 15, 1.—Esp., a departure from life: in his esse et excessum e vita et in vita mansionem, Cic. Fin. 3, 18, 60"},"excultor":{"lemma":"excultor","pos":"","gen":"-class","def":"1. excolo, a cultivator, rearer (post-class.): florum, Tert. Monog. 16: tyrannicae crudelitatis, Cassiod. Hist. Eccl. 2, 22. excultus, a, um, Part., from 1. excolo. ex-cŭnĕātus, a, um, adj. cuneus"},"excurso":{"lemma":"excurso","pos":"v.","gen":"","def":"n. freq. of excurro, to break forth repeatedly, to make frequent sallies or incursions: ubi plures innumeris videt excursare latebris, Stat. Th. 2, 550."},"excursor":{"lemma":"excursor","pos":"","gen":"","def":"excurro, I. A. b.. A skirmisher, scout, spy: paratissimus pro nobis, Val. Max. 7, 3, 7: istius excursor et emissarius, Cic. Verr. 2, 2, 8, § 22.— Transf.: excursores venti habentur"},"excursus":{"lemma":"excursus","pos":"","gen":"","def":"excurro, a running out or forth (rare; not in Cic.; cf. excursio). Lit.: excursusque breves tentant (apes), excursions, Verg. G. 4, 194: avium, Sol. 20, 3"},"excusse":{"lemma":"excusse","pos":"adv.","gen":"","def":", v. excutio, P. a. fin. excussĭo, ōnis, f. excutio, a shaking down: oleae, Vulg. Isa. 17, 6. excussōrĭus, a, um, adj. id., that serves for shaking out: cribra e lino, bolting-sieves, Plin. 18, 11"},"excussus":{"lemma":"excussus","pos":"","gen":"","def":"excutio, a beating out, beating, Prud. στεφ. 5, 226. excūsus, a, um, Part., from excudo. ex-cŭtĭo, cussi, cussum, 3 (archaic perf. subj. excussit, for excusserit, Plaut. Bacch. 4, 2, 16)"},"exdemeticus":{"lemma":"Exdemeticus","pos":"","gen":"","def":", the title of a satire by Varro, Gell. 19, 8, 17. exdīco, ĕre, v. edico init. ex-dorsŭo or -dorso, āre, v. a. dorsum; lit., to deprive of the back"},"exemplo":{"lemma":"exemplo","pos":"v.","gen":"","def":"a. id., to adduce as an example, August. Ep. 149."},"exemplum":{"lemma":"exemplum","pos":"","gen":"","def":"eximo, orig., what is taken out as a sample (cf. eximius, from eximo), a sample. Prop. (cf. exemplar, specimen): purpurae, tritici, Auct. Her. 4, 6, 9.—Hence, Transf. An imitation, image"},"exemptor":{"lemma":"exemptor","pos":"","gen":"","def":"id., one who takes out any thing, esp. stone, a quarryman, Plin. 36, 15, 24, § 125. exemptus, a, um, Part., from eximo."},"exemptus":{"lemma":"exemptus","pos":"","gen":"","def":"eximo, a taking out or away: cuneorum (opp. adjectus), Vitr. 9, 8, 6. exĕnĭa, ōrum, n. collat. form of xenia, with e prosth.; cf. xenium"},"exertus":{"lemma":"exertus","pos":"","gen":"","def":"exsertus under exsero. exēsor, ōris, m. exedo, that which eats away any thing: murorum (aestus), i. e. an underminer, Lucr. 4, 220"},"exhaeresimus":{"lemma":"exhaeresimus","pos":"","gen":"","def":"exaeresimus. exhālātĭo, ōnis, f. exhalo, an exhalation, vapor (class.): exhalationes terrae, Cic. Tusc. 1, 19, 43; Sen. Q. N. 2, 10; Plin. 31, 3, 27, § 44"},"exhalatio":{"lemma":"exhalatio","pos":"n. f.","gen":"-onis","def":"an exhalation, vapour, effluvium rising from the earth"},"exhorresco":{"lemma":"exhorresco","pos":"","gen":"","def":"inch. n. and a. . Neutr., to tremble or shudder exceedingly, to be terrified (class.): non possum non exhorrescere, si quid intra cutem subest vulneris, Planc. ap. Cic. Fam. 10, 18"},"exim":{"lemma":"exim","pos":"","gen":"","def":"exinde init. exĭmĭē, adv., v. eximius fin. exĭmĭĕtas, ātis, f. eximius, excellence, eminence (late Lat.), Symm. Ep. 3, 3; Aug. Ep. 32, 231"},"exin":{"lemma":"exin","pos":"adv.","gen":"","def":", v. exinde. ex-ĭnānĭo, īvi or ĭi, ītum, 4, v. a., to empty, make empty (rare but class.): Siciliam provinciam C. Verres per triennium depopulatus esse, Siculorum civitates vastasse, domos exinanisse"},"existo":{"lemma":"existo","pos":"","gen":"","def":"exsisto. exĭtĭābĭlis, e, adj. exitium, destructive, fatal, deadly (rare but class.): exitiabilem illi faciam diem, Plaut. Ep. 4, 2, 36: bellum suis civibus, * Cic. Att. 10, 4, 3"},"exoluo":{"lemma":"exolvo","pos":"","gen":"","def":"exsolvo. exōmĭdes sunt comici vestitus exsertis humeris, Fest. p. 81 Müll.; cf. Gell. 7, 12, 3 (= ἐξωμίς). exŏmŏlŏgēsis, is, f., = ἐξομολόγησις, a confession (eccl. Lat.), Tert. Poen. 9"},"exorcismus":{"lemma":"exorcismus","pos":"","gen":"","def":", = ἐξορκισμός, an exorcism (post - class.): exorcismis fugare daemones, Tert. Cor. Mil. 11."},"exorcista":{"lemma":"exorcista","pos":"","gen":"-class","def":", = ἐξορκιστής, an exorcist (post-class.), Cod. Just. 1, 3, 6; Firm. Math. 3, 5; 9 fin."},"exormiston":{"lemma":"exormiston","pos":"","gen":"","def":", = ἐξορμιστόν, a fish, perh. a kind of muraena, Cassiod. Var. 12, 14. exornātĭo, ōnis, f. exorno, an adorning, decorating, embellishing. Lit.: quae ad lavationem, quae ad exornationem pertinerent"},"exors":{"lemma":"exors","pos":"","gen":"","def":"exsors. exorsus, a, um, Part., from exordior."},"exorsus":{"lemma":"exorsus","pos":"","gen":"","def":"exordior, a beginning, commencement: orationis, Cic. de Imp. Pomp. 4, 11. exortīvus, a, um, adj. 2. exortus. Of or belonging to the rising of the heavenly bodies, ascendant (post-Aug.): mensura"},"exortus":{"lemma":"exortus","pos":"","gen":"","def":"exorior, a coming forth, rising: solis, Auct. Her. 3, 22, 36; Suet. Aug. 5"},"exossis":{"lemma":"exossis","pos":"adj.","gen":"-class","def":"ex-ŏs, without bones, boneless (post-class.). Lit.: cum sit (lepus marinus) cetera exossis, App. Mag. p. 300, 13.— Transf. Pliant, limber, supple, yielding: exossis plane et enervis, App. Mag. p. 322"},"exosso":{"lemma":"exosso","pos":"v.","gen":"","def":"a. id., to deprive of the bones, to bone: mirum ni hic me quasi muraenam exossare cogitat, Plaut. Am. 1, 1, 163: congrum, Ter. Ad. 3, 3, 24"},"expalpo":{"lemma":"expalpo","pos":"v.","gen":"-class","def":"a., and expalpor, āri, v. dep. a., to obtain by coaxing or flattery (ante-class.): exora, blandire, expalpa, Plaut. Poen. 1, 2, 144: si quid expalpare possim ab illo, Pompon. ap. Non. 104"},"expalpor":{"lemma":"expalpor","pos":"","gen":"","def":"expalpo."},"expensa":{"lemma":"expensa","pos":"","gen":"-class","def":"(sc. pecunia) , a disbursement, expense (post-class.): neque tempus neque finem expensarum habet, Dig. 27, 10, 1: non indecores aeraria lassant expensae, Claud. II. Cons. Stil. 145. expensē, adv."},"expenso":{"lemma":"expenso","pos":"","gen":"-class","def":"freq. a. id.. To pay out, pay (ante- and post-class.): argentum accepto, expenso, Plaut. Ps. 2, 2, 31: nummos, Dig. 40, 5, 41, § 10.—* To equalize"},"expensum":{"lemma":"expensum","pos":"","gen":"","def":", v. expendo, I. B. 2. expensus, a, um, Part., from expendo. expergē-făcĭo, fēci, factum, 3, v. a. expergo, to awaken, rouse. Lit.: expergefactus e somno, Suet. Calig. 6; 38"},"expergisco":{"lemma":"expergisco","pos":"","gen":"","def":"expergiscor init."},"expergiscor":{"lemma":"expergiscor","pos":"v.","gen":"","def":"praes. expergiscier, Plaut. As. 2, 1, 1), v. dep. (act. form in the imperf. subj. expergisceret, Pompon. ap. Non. 473, 6), n. expergo, to be awakened, to awake (class.). Lit.: si dormis"},"expergo":{"lemma":"expergo","pos":"v.","gen":"-class","def":"a., to awaken, rouse up (cf. Paul. ex Fest. p. 80 Müll."},"explaudo":{"lemma":"explaudo","pos":"","gen":"","def":"explodo. explēmentum, i, n. expleo, that which fills up. Lit., of food, a filling, stuffing: inanimentis explementum quaerito, Plaut. Stich. 1, 3, 19: cacumina arborum explementum esse ventris"},"explendesco":{"lemma":"explendesco","pos":"","gen":"","def":"exsplendesco. ex-plĕo, ēvi, ētum, 2 (archaic form explenunt, for explent, acc. to Fest. p. 80; cf.: solinunt, nequinunt, danunt, for solent, nequeunt, dant; v. do, redeo and soleo init."},"expressim":{"lemma":"expressim","pos":"adv.","gen":"","def":"expressus, from exprimo, expressly, clearly, distinctly (postclass.), Dig. 46, 3, 98"},"expressor":{"lemma":"expressor","pos":"","gen":"-class","def":"exprimo, one who presses out or brings forth (post-class.); trop.: veritatis (with integrator), Tert. Apol. 46. expressus, a, um, Part. and P. a., from exprimo."},"expressus":{"lemma":"expressus","pos":"","gen":"","def":"exprimo, a forcing apparatus for raising water, Vitr. 8, 7; cf. expressio, II. A. exprētus, a, um perh. for exspretus, from ex-sperno"},"expugnax":{"lemma":"expugnax","pos":"adj.","gen":"","def":"id., victorious, controlling, effectual: sive expugnacior herba est, Ov. M. 14, 21."},"expulsim":{"lemma":"expulsim","pos":"adv.","gen":"","def":"expulsus, from expello, by driving out or away from one's self: pilā expulsim ludere, Varr. ap. Non. 104, 29. expulsĭo, ōnis, f. expello, a driving out, expulsion: expulsiones vicinorum, Cic. Par. 6"},"expulso":{"lemma":"expulso","pos":"","gen":"","def":"freq. a. id., to drive out, to expel (post-Aug. and very rare): si me (i. e. pilam) nobilibus scis expulsare sinistris, Sum tua, to drive from one's self, drive back, Mart. 14, 46, 1"},"expulsor":{"lemma":"expulsor","pos":"","gen":"","def":"id., a driver out, expeller (very rare but class.): iste bonorum possessor, expulsor, ereptor, * Cic. Quint. 8, 30: tyranni, Nep. Dion. 10, 2. expulsus, a, um, Part., from expello."},"expultrix":{"lemma":"expultrix","pos":"","gen":"","def":"expello, she that drives out or expels: philosophia, expultrix vitiorum, Cic. Tusc. 5, 2, 5. ex-pūmĭco, āre, v. a., to rub off with pumice-stone"},"expunctor":{"lemma":"expunctor","pos":"","gen":"-out","def":"expungo, a blotter-out, obliterator (post-class.), Tert. Or. 1."},"expunctrix":{"lemma":"expunctrix","pos":"","gen":"","def":"id., she who blots out: meritorum, Jul. ap. August. cont. Sec. Resp. Jul. 1, 37. expunctus, a, um, Part., from expungo."},"exquaero":{"lemma":"exquaero","pos":"","gen":"","def":"exquiro init. Exquĭlĭae, ārum, and its derivatives, v. Esquiliae. ex-quīro (in Plautus also exquaero, Bacch. 4, 4, 70 al.), sīvi, sītum, 3, v. a., to search out diligently, to seek for"},"exsanguesco":{"lemma":"exsanguesco","pos":"","gen":"","def":"inch. , to become pale, grow faint or feeble: (mens) ad omnia exsanguescens dubia, Jul. ap. August. cont. Sec. Resp. Jul. 6, 14. exsanguĭnātus (exang-), a, um, adj. exsanguis, deprived of blood"},"exscendo":{"lemma":"exscendo","pos":"","gen":"","def":"escendo. exscensĭo (excens-), ōnis, f. escendo, II.; cf. ex, IV. B. 2., a debarkation, landing; usu. with facere (repeatedly in Liv.; elsewh. rare"},"exspargo":{"lemma":"exspargo","pos":"","gen":"","def":"exspergo. ex-spătĭor (exp-), ātus, 1, v. dep. n., to wander from the course, go out of the way; to spread out, extend"},"exsurrectio":{"lemma":"exsurrectio","pos":"","gen":"","def":"exsurgo, an arising, Vulg. 4 Esdr. 16, 71. exsuscĭtātĭo (exusc-), ōnis, f. exsuscito, an awakening, arousing, as a fig. of speech, Auct. Her. 4, 42, 55"},"exta":{"lemma":"exta","pos":"","gen":"","def":"plur. extūm, Pac. ap. Cic. Or. 46, 155.—Also EXTAE, ārum, Inscr. Fratr. Arv. ap. Marin. Tab. 41, 19; Tab. 42, 12; Tab. 43, 22), n. sup. form for ecista (exista); cf.: exterus, extra"},"extantia":{"lemma":"extantia","pos":"","gen":"","def":", v. exstantia. extāris, e, adj. exta, of or belonging to the entrails (very rare): aula (i. e. olla), for cooking entrails, Plaut. Rud. 1, 2, 47."},"extasis":{"lemma":"extasis","pos":"","gen":"","def":"exstasis. extemplō (original uncontracted form extempŭlo, Plaut. Aul. 1, 2, 15; id. Cist. 1, 1, 98; 2, 3, 30; id. Bacch. 4, 9, 44; id. Mil. 2, 5, 51"},"extensor":{"lemma":"extensor","pos":"","gen":"","def":"extendo, he who stretches (i. e. upon the rack), a torturer, Ambros. de Jac. et Vit. Beat. 2, 10, 44. extensus, a, um, Part., from extendo. extentē, adv., widely"},"extento":{"lemma":"extento","pos":"","gen":"-class","def":"freq. a. id., to stretch out, extend (ante- and post-class.). Lit.: nervos, Lucr. 3, 490: humeros angustos, Amm. 22, 14.— Trop.: vires alieno ostio, i. e. to exert, try, Plaut. Bacch. 4, 2"},"extentus":{"lemma":"extentus","pos":"","gen":"","def":"extendo, a stretching out, extending, extent: laterum, Sil. 4, 619. extĕnŭātĭo, ōnis, f. extenuo, a thinning, rarefaction. Lit.: vitium, Plin. 17, 26, 39, § 246"},"externo":{"lemma":"externo","pos":"","gen":"","def":"exsterno."},"externus":{"lemma":"externus","pos":"adj.","gen":"","def":"exter, outward, external (class.). In gen.: nec enim ille externus et adventicius habendus est tepor, sed ex intimis maris partibus agitatione excitatus, Cic. N. D. 2, 10"},"extersus":{"lemma":"extersus","pos":"","gen":"","def":"extergeo, a rubbing dry, a rubbing down: linteum extersui, Plaut. Curc. 4, 4, 20. extĕrus, a, um, v. exter."},"extillo":{"lemma":"extillo","pos":"","gen":"","def":"exstillo. ex-tĭmesco, mŭi, 3, v. inch. n. and a., to be greatly afraid of, to fear greatly"},"extirpo":{"lemma":"extirpo","pos":"","gen":"","def":"exstirpo. extispex, ĭcis (also post-class. ‡ extispicus, i, Inscr. Orell. 2302), m. exta-specio, one who prophesies by inspecting the entrails of animals, a diviner, soothsayer (syn.: augur, auspex"},"exto":{"lemma":"exto","pos":"","gen":"","def":"exsto. extollentĭa, ae, f. extollo, pride (late Lat.): oculorum, Vulg. Sirach, 23, 5."},"extorris":{"lemma":"extorris","pos":"adj.","gen":"","def":"ex and terra, driven out of the country, exiled, banished (class.; syn.: exsul, profugus, fugitivus, transfuga, desertor): hinc extorres profugerunt, * Cic. Verr. 2, 3, 51, § 120"},"extortor":{"lemma":"extortor","pos":"","gen":"","def":"id. I. B. 2., an extorter: bonorum, Ter. Ph. 2, 3, 27; Cypr. Ep. 14, 1. extortus, a, um, Part., from extorqueo. extrā (old form EXTRAD repeatedly in the S. C. de Bacchan."},"extrilidus":{"lemma":"extrilidus","pos":"adj.","gen":"","def":", unterrified, dauntless: hominem conspicimus impavidum et extrilidum, Gell. 19, 1, 6 Hertz. (al. extimidum). extrin-sĕcus, adv. ‡ extrim as an adverbial form of exter, from without"},"extro":{"lemma":"extro","pos":"v.","gen":"","def":"a. extra, analog. to intro, āre, to go out from, to quit: simul limen intrabo, illi extrabunt ilico, Afran. ap. Non. 104, 21 (Rib. Com. Fragm. p. 165). extrorsŭs, adv. extra + versus"},"exuccus":{"lemma":"exuccus","pos":"","gen":"","def":"exsuc-. exūdo, āre, v. exsudo. exūgo, ĕre, v. exsugo."},"exul":{"lemma":"exul","pos":"","gen":"","def":"exsul. exulcĕrātĭo, ōnis, f. exulcero, a soreness, festering, exulceration (post-Aug.). Lit.: si nulla exulceratio est, Cels. 4, 22.—In plur.: vesicarum, Plin. 20, 3, 8, § 17.—* Trop.: verebar"},"exulto":{"lemma":"exulto","pos":"","gen":"","def":"exsulto. ex-ŭlŭlo, āvi, ātum, 1, v. n. and a. (poet.). Neutr., to howl or cry out, to howl violently: nactusque silentia ruris Exululat, Ov. M. 1, 233"},"exurgo":{"lemma":"exurgo","pos":"","gen":"","def":"exsurgo. ex-ūro, ussi, ustum, 3, v. a., to burn out, burn up, consume (class.; syn.: incendo, accendo, inflammo, cremo). Lit.: illic oculos exuram lampadibus ardentibus, Plaut. Men. 5, 2, 86"},"fabullus":{"lemma":"Fabullus","pos":"","gen":"","def":", a friend of Catullus, Plin. N. H. praef. § 1. fābŭlo, āre, v. fabulor. fābŭlor, ātus (archaic inf. praes. fabularier, Plaut. Am. 1, 1, 46; id. Most. 3, 1, 77; id. Ps. 1, 1, 60; id. Trin. 2, 4, 60"},"facit":{"lemma":"facio","pos":"","gen":"","def":"(form of facio)"},"faciunt":{"lemma":"facio","pos":"","gen":"","def":"(form of facio)"},"facteon":{"lemma":"facteon","pos":"","gen":"","def":"facio fin. * 2. factīcĭōsus = πολυμήχανος, Gloss. Philox. factīcĭus (-tĭus), a, um, adj. facio, made by art, artificial, factitious (postAug.). In gen.: sal, Plin. 31, 7, 39, § 81: colores, id. 31, 7"},"facto":{"lemma":"facto","pos":"","gen":"","def":"freq. a. facio, to make, do, perform: operis quicquam, Plaut. Truc. 5, 1, 23; false reading for facio; cf. Plaut. Merc. prol. 95 Ritschl."},"factor":{"lemma":"factor","pos":"","gen":"-presser","def":"id., a maker, doer, performer, perpetrator (ante- and postclass.). In gen.: cuparum doliorumque, Pall. 1, 6: qui praepositum suum non praetexit, cum posset, in pari causa factori habendus est"},"factum":{"lemma":"factum","pos":"","gen":"","def":", v. facio fin. factūra, ae, f. facio, a making, manufacture, formation, = ποίησις (post-Aug. and very rare). Prop.: in nostro orbe aliubi vena bonitatem hanc praestat, aliubi factura, Plin. 34, 14"},"factus":{"lemma":"factus","pos":"","gen":"","def":"(also factum, i, n., Varr. R. R. 1, 24, 3"},"faenilis":{"lemma":"faenilis","pos":"adj.","gen":"","def":", = fenebris, Not. Tir. p. 68. faenĭsĕca (fēn-, foen-), ae, v. faenisex. faenĭ-secta (fēn-, foen-), ōrum, n. faenum, I.; seco, mown hay, Varr. L. L. 5, § 136 Müll. N. cr."},"faex":{"lemma":"faex","pos":"","gen":"","def":"plur.: faecum, acc. to Charis. p. 114 P.), f. etym. dub., grounds, sediment, lees, dregs of liquids (cf. sentina). Lit.: omnis mundi quasi limus subsedit funditus ut faex, Lucr. 5"},"falcastrum":{"lemma":"falcastrum","pos":"","gen":"-hook","def":"id., an agricultural instrument, a bush-hook: a similitudine falcis vocatum. Est autem ferramentum curvum cum manubrio longo ad densitatem veprium succidendam, Isid. Orig. 20, 14, 5. falcātus, a, um"},"falco":{"lemma":"falco","pos":"","gen":"","def":"v. flecto, = φάλκων, a falcon. Lit., Serv. Verg. A. 10, 146; Isid. Orig. 12, 7, 57 al.— Transf.: falcones dicuntur, quorum digiti pollices in pedibus intro sunt curvati, Paul. ex Fest. p. 88, 8 Müll."},"falcula":{"lemma":"Falcula","pos":"","gen":"","def":", a Roman surname, Cic. Caecin. 10, 28"},"falla":{"lemma":"falla","pos":"","gen":"","def":"fallo, = fallacia, an artifice, trick, Nov. ap. Non. 109, 20. fallācĭa, ae (abl. also fallacie, App. M. 5, p. 171), f. fallax, deceit, trick, artifice, stratagem, craft, intrigue (class."},"fallax":{"lemma":"fallax","pos":"adj.","gen":"","def":"plur. fallacium, Cic. Lael. 25, 91 al.; but fallacum, Cat. 30, 4), adj. fallo, deceitful, deceptive, fallacious (class.; esp. freq. in Cic."},"fallo":{"lemma":"fallo","pos":"v.","gen":"-clause","def":"praes. pass. fallier, Pers. 3, 50; perf. pass. fefellitus sum, Petr. Fragm. 61, MSS.), v. a. Sanscr. sphal, sphul, to waver"},"false":{"lemma":"false","pos":"adv.","gen":"","def":", v. fallo, P. a. fin. 2. falsĭdĭcentia, ae, f. falsidicus, habitual falsehood (opp. veridicentia), Jul. Val. Rer. Gest. Alex. M. 2, 1. falsĭdĭcus, a, um, adj. falsus-dico, speaking falsely"},"falso":{"lemma":"falso","pos":"v.","gen":"","def":"a. id., to falsify (late Lat.): pondera aut mensuras, Dig. 48, 10, 32 fin.: scripturas divinas, Ambros. de Fide, 2, 15, 135: liber falsatus ab haereticis, Hier. in Ruf. 2, 5 al.—Hence, falsātus, a"},"falx":{"lemma":"falx","pos":"","gen":"-hook","def":"perh. akin to flecto, a sickle, reaping-hook, a pruning-hook, scythe. Prop., Cato, R. R. 10, 3; 11, 4; Varr. R. R. 1, 22, 5; Cic. Tusc. 5, 23, 65; id. Mil. 33, 91; Verg. G. 1, 348: Ov. F. 4, 914"},"famel":{"lemma":"famel","pos":"","gen":"","def":"famulus init. fămēlĭcē, adv., v. famelicus fin. fămēlĭco, āvi, 1, v. a. famelicus, to make hungry, cause to famish: non famelicas sed reficis, Pseud. August. ad Fratr. Erem. Serm. 10. fămēlĭcōsus"},"famex":{"lemma":"famex","pos":"","gen":"","def":", a bruise, contusion, Col. 6, 12, 2 Schneid. N cr.; Veg. Vet. 4, 19"},"fanester":{"lemma":"Fanester","pos":"","gen":"","def":"2. fanum. fānĭtālis, e, adj. 1. fanum, pertaining to a temple, Inscr. Guarin. Comment. XII. p. 28. Fannĭus, a, the name of a Roman gens: 1. C. Fannius Strabo, son-in-law of Laelius"},"fanum":{"lemma":"Fanum","pos":"","gen":"","def":", a city in Umbria, on the Adriatic Sea, with a celebrated temple of Fortuna, now Fano, Caes. B. C. 1, 11 fin.; called also Fanum Fortunae, Plin. 3, 14, 19, § 113; Tac. H. 3, 50"},"far":{"lemma":"far","pos":"","gen":"","def":"akin with frico, q. v., a sort of grain, spelt, Gr. ζέα, Triticum spelta, Linn. Prop., the earliest food of the Romans, both roasted and ground into meal, Cato, R. R. 2, 4; Varr. R. R. 1, 63; 1, 2, 6"},"farfugium":{"lemma":"farfugium","pos":"","gen":"","def":", v. 1. farfarus. fărīna, ae, f. far, ground corn, meal, flour. Prop., Plin. 18, 9, 20, § 88; Varr. R. R. 2, 5, 17; Plin. 20, 13, 51, § 139"},"farnus":{"lemma":"farnus","pos":"","gen":"-tree","def":"perh. for franus, contr. from fraxinus, an ash, ash-tree, Vitr. 7, 1 dub. (al. fraxinus)"},"fartim":{"lemma":"fartim","pos":"adv.","gen":"-class","def":"id., by stuffing or cramming"},"fartor":{"lemma":"fartor","pos":"","gen":"","def":"id.. A stuffer, fattener of fowls, poulterer: pinguem quoque facere gallinam quamquam fartoris non rustici sit officium, Col. 8, 7, 1; Inscr. Grut. 580, 15"},"fartum":{"lemma":"fartum","pos":"","gen":"","def":", v. farcio fin. fartūra (also farctūra), ae, f. farcio. A cramming, fattening of fowls, Varr. R. R. 3, 8, 3; Col. 8, 9, 1"},"fascis":{"lemma":"fascis","pos":"","gen":"","def":"cf. φάκελος, fascia, but v fido, a bundle of wood, twigs, straw, reeds, etc. A fagot, fascine"},"fasti":{"lemma":"fasti","pos":"","gen":"","def":", v. 1. fastus. fastīdĭbĭlis, e, adj. fastidio; act., nauseous, loathsome, disagreeable (postclass. and very rare): judicia, Tert. Anim. 33 fin. fastīdĭenter, adv., disdainfully, scornfully"},"fastus":{"lemma":"fastus","pos":"adj.","gen":"-day","def":"perh. root ΦΑ, φάσκω, φημί, fari; lit., in which it is allowed to speak, fasti dies; and more commonly absol.: fasti, ōrum, m. (acc. to the 4th decl. acc. fastus, Varr. ap. Prisc. p. 711 P."},"fatantur":{"lemma":"fatantur","pos":"","gen":"","def":"fator. fătĕor, fassus, 2 (archaic inf. praes. faterier, Hor. Ep. 2, 2, 148), v. dep. a. , to confess, own, grant, acknowledge. Prop. (freq. and class.; syn.: confiteor, profiteor)"},"fatuellus":{"lemma":"Fatuellus","pos":"","gen":"","def":", v. 2. Fatuus. fătŭĭna rŏsa, another name for the paeonia, App. Herb. 64. fătŭĭtas, ātis, f. 1. fatuus, foolishness, folly, silliness, fatuity (very rare), Cic. Inv. 2, 32, 99; id. Att. 11, 25, 2"},"fauna":{"lemma":"Fauna","pos":"","gen":"","def":", the prophesying sister of Faunus, called also Bona Dea, Macr. S. 1, 12; Lact. 1, 22, 9"},"faunus":{"lemma":"Faunus","pos":"adj.","gen":"","def":"faveo, a mythic son of Picus, grandson of Saturn, and father of Latinus, king of Latium"},"fausta":{"lemma":"Fausta","pos":"","gen":"","def":"2. Faustus. faustē, adv., luckily, favorably, v. 1. faustus fin. Faustĭānus, a, um, v. 2. Faustus. Faustīna, ae, f. The wife of the emperor Antoninus Pius, Capit. Anton. Pius"},"faustus":{"lemma":"faustus","pos":"adj.","gen":"","def":"for favostus, from faveo; lit., favorable; hence, of favorable or fortunate omen, fortunate, favorable, auspicious, prosperous, lucky (rare but class."},"fautrix":{"lemma":"fautrix","pos":"","gen":"","def":"fautor, a patroness, protectress (class.). With gen.: amicitiae non modo fautrices fidelissimae, sed etiam effectrices sunt voluptatum tam amicis quam sibi, Cic. Fin. 1, 20, 67: regio fautrix suorum"},"faux":{"lemma":"faux","pos":"","gen":"","def":"fauces. făvĕa, ae, f. faveo, a favorite female slave (= παιδίσκη, Gloss.), Plaut. Mil. 3, 1, 200. făventĭa, ae, f. id., a being favorable"},"fax":{"lemma":"fax","pos":"","gen":"-thorn","def":"sing. ‡ faces, acc. to Paul. ex Fest. p. 87, 9 Müll.; gen. plur.: facum, acc. to Charis. p. 113 P., but without example), f. root bhā, to shine"},"faxim":{"lemma":"faxim","pos":"","gen":"","def":"facio init. Febrārĭus, v. Februarius."},"febresco":{"lemma":"febresco","pos":"","gen":"","def":"inch. n. , to catch a fever (late Lat.), Sol. 19 med. febrĭbĭlis, e, adj. id., that easily produces fever (late Lat.), Cael. Aur. Tard. 4, 8 med. fēbrīcĭto, āvi, 1, v. n. id., to be ill of a fever"},"februatus":{"lemma":"Februatus","pos":"","gen":"","def":"februum and februo."},"februlis":{"lemma":"Februlis","pos":"","gen":"","def":"februum. febrŭo, no perf., ātum, 1, v. a. februum, to purify, expiate (ante-class.): in eorum sacris liba cum sint facta, inicere solent farris semina ac dicere, se ea februare, id est pura facere"},"fecit":{"lemma":"facio","pos":"","gen":"","def":"(form of facio)"},"fel":{"lemma":"fel","pos":"","gen":"-bladder","def":"Gr. χόλος, gall; cf. Germ. Galle; Engl. gall, the gall-bladder, gall, bile (cf. bilis): jecur a dextra parte sub praecordiis: ex inferiore parte ei fel inhaeret, Cels. 4, 1"},"fellebris":{"lemma":"fellebris","pos":"adj.","gen":"","def":"id., sucking, Sol. 2 med. dub. fellĕus, a, um, adj. fel, of gall, full of gall, like gall: sudores, Plin. 26, 12, 76, § 124: urina, Cael. Aur. Tard. 3, 6. fellĭco (fellĭto), āre, v. a. fello"},"fello":{"lemma":"fello","pos":"v.","gen":"-class","def":"a., to suck (ante-class. and poet.). Lit.: lac humanum, Varr. ap. Non. 113, 14: lupam, id. ib. 242, 33.— Transf. obsc., Mart. 2, 50, 1 al."},"fendo":{"lemma":"fendo","pos":"","gen":"","def":"defendo, fustis, the primitive word of the compounds defendo, offendo, infensus, and infestus"},"fenni":{"lemma":"Fenni","pos":"","gen":"","def":", a tribe in the north and northeastern parts of Europe, not of the Germani, called Φίννοι by Ptolemy, probably the Finns, Tac. G. 46"},"feratrina":{"lemma":"feratrina","pos":"","gen":"","def":"63, 26, compared as to its form with moletrina, but without an explanation of its meaning. fĕrax, ācis, adj. fero, fruit-bearing, fruitful, fertile (rare but class.). Lit. —Absol.: terrae, * Lucr. 2"},"ferbui":{"lemma":"ferbui","pos":"","gen":"","def":"ferveo init."},"ferctum":{"lemma":"ferctum","pos":"","gen":"","def":", v. fertum. fercŭlum (or uncontr. fĕrĭcŭlum, Sen. Ep. 90, 15"},"ferentum":{"lemma":"Ferentum","pos":"","gen":"","def":"Forentum. fereŏla vītis, a sort of vine, Col. 3, 2, 28. Fĕrētrĭus, ii, m. ferio"},"fermentesco":{"lemma":"fermentesco","pos":"","gen":"","def":"inch. n. (lit., to ferment, to rise in fermenting"},"fermentum":{"lemma":"fermentum","pos":"","gen":"","def":"contr. for fervimentum, from fervo, ferveo, that which causes fermentation, leaven, yeast, ferment. Lit., Plin. 18, 11, 26, § 102; 18, 7, 12, § 68: panis sine fermento, unleavened bread, Cels. 2, 24"},"ferrea":{"lemma":"ferrea","pos":"","gen":"","def":", v. ferreus, I. ferrĕus, a, um, adj. ferrum, made of iron, iron. Lit.: Britanni utuntur aut aere aut taleis ferreis ... pro nummo, Caes. B. G. 5, 12, 4: vomer, Lucr. 1, 314: ensis, id. 5"},"ferrum":{"lemma":"ferrum","pos":"n. n.","gen":"-i","def":"iron; any iron implement: sword, ploughshare, chisel"},"fertor":{"lemma":"fertor","pos":"","gen":"","def":"fero, one who bears, not in use"},"fertus":{"lemma":"fertus","pos":"adj.","gen":"","def":"fero; cf. fertilis, fertile, productive: pini, Avien. Or. Mar. 556"},"feruenter":{"lemma":"ferventer","pos":"adv.","gen":"","def":", v. ferveo, P. a. fin. fervĕo, bŭi, 2, or fervo, vi, 3 (the latter form ante-and post-class., Plaut. Pseud. 3, 2, 51; Lucr. 2, 41 al.; poet. in class. per., e.g. Verg. G. 1, 456; id. A. 8, 677"},"feruesco":{"lemma":"fervesco","pos":"","gen":"-class","def":"inch. n. , to become boiling hot, to begin to boil, begin to glow, to grow hot. Lit. (ante-class. and post-Aug.): possent seriae fervescere, Plaut. Capt. 4, 4, 9: fervescens materia, Plin. 33, 6, 35"},"feruo":{"lemma":"fervo","pos":"","gen":"","def":"ferveo."},"feruor":{"lemma":"fervor","pos":"","gen":"","def":"ferveo, a boiling or raging heat, a violent heat, a raging, boiling, fermenting (class.; syn.: ardor, tepor, calor, aestus). Lit.: pollens fervore corusco, Lucr. 6, 237"},"festra":{"lemma":"festra","pos":"","gen":"","def":", v. fenestra. festūca, ae, f., a stalk, stem, straw. Lit. In gen.: qui homo in pratis per fenisecta festucas corradit, Varr. L. L. 5, § 136; Col. 8, 15, 6; Plin. 10, 41, 57, § 116"},"festus":{"lemma":"festus","pos":"adj.","gen":"-iae","def":"Sanscr. bhas, shine; lengthened from bha-; Gr. φα-, φαίνω, v. for"},"fibla":{"lemma":"fibla","pos":"","gen":"","def":"fibula init. fībra, ae, f. acc. to Doed. Syn. 3, p. 22, kindr. with filum (cf. the Eng. string in both senses), a fibre, filament, in a plant, in a part of an animal's body"},"fictor":{"lemma":"fictor","pos":"","gen":"-cakes","def":"fingo, one who makes images of clay, wood, wax, etc., an imagemaker, statuary. (Syn.: pictor, scalptor, sculptor, plastes, statuarius.) Lit. In gen.: deos ea facie novimus"},"fictrix":{"lemma":"fictrix","pos":"","gen":"","def":"id., she that forms or fashions: ejus universae materiae fictrix et moderatrix divina est providentia, Cic. N. D. 3, 39, 92"},"figmen":{"lemma":"figmen","pos":"","gen":"-class","def":"FIG, fingo, formation, figure, image (post-class.), Prud. Apoth. 798; 1035: figminis figura, Mart. Cap. 3, § 222."},"figmentum":{"lemma":"figmentum","pos":"","gen":"-class","def":"id. (post-class.), formation (cf. fictio). In gen. In abstr.: verborum, the forming of new words, Gell. 20, 9, 1.— In concr., a figure, image: animalis, Gell. 5, 12, 12: figmento deae caelitus lapso"},"findo":{"lemma":"findo","pos":"v.","gen":"","def":"a. root Sanscr. bhid-, to cleave; Germ. beissen; Engl. bite, to cleave, split, part, separate, divide (class."},"fingo":{"lemma":"fingo","pos":"v.","gen":"-clause","def":"a. Sanscr. dih-, dēhmi, smear; Gr. θιγ, θιγγάνω, touch; whence figulus, figura, etc."},"fircus":{"lemma":"fircus","pos":"","gen":"","def":", v. hircus init. firmāmen, ĭnis, n. firmo, poet. for firmamentum, a prop, support: trunci, Ov. M. 10, 491; Sen. Herc. Fur. 1251. firmāmentum, i, n. id., a strengthening, support, prop (class."},"firmo":{"lemma":"firmo","pos":"v.","gen":"-clauses","def":"a. firmus, to make firm or fast, to strengthen, fortify, support (freq. and class.). Lit.: lacertos, Lucr. 6, 397: corpora juvenum firmari labore voluerunt, Cic. Tusc. 2, 15, 36: corpora cibo"},"firmum":{"lemma":"Firmum","pos":"adj.","gen":"-port","def":", a fortified sea-port of Picenum, now Fermo, Mel. 2, 4, 6; Vell. 1, 14, 8"},"firmus":{"lemma":"firmus","pos":"adj.","gen":"-mi","def":"Sanscr. dhar-, dharā-mi, hold, support; Gr. θρᾶ-, θρή-σασθαι, to sit down, θρῆνυς, θρόνος"},"fiscella":{"lemma":"fiscella","pos":"","gen":"-forms","def":"(also fiscellus, i, m., Col. 12, 38, 6, v. fiscellus), dim. fiscina, a small basket for fruit, cheese-forms, etc., woven of slender twigs, rushes, etc. (syn.: fscina, qualus, canistrum, calathus"},"fiscellus":{"lemma":"fiscellus","pos":"","gen":"","def":"dim. fiscina."},"fiscus":{"lemma":"fiscus","pos":"","gen":"-basket","def":", a basket or frail woven of slender twigs, rushes, etc. (like fiscina, fiscella, q. v.); used, For olives in the oilpress, Col. 12, 52, 22"},"fissum":{"lemma":"fissum","pos":"","gen":"","def":", v. findo fin. fissūra, ae, f. findo"},"fistella":{"lemma":"fistella","pos":"","gen":"","def":"dim. fistula, a little pipe, Pelagon. Art. Vet. 24. fistūca, ae, f., an instrument for ramming down, a rammer, beetle, Caes. B. G. 4, 17, 4; Cato, R. R. 28, 2"},"flaccus":{"lemma":"flaccus","pos":"adj.","gen":"-eared","def":"etym. dub., flabby, hanging down. Lit.: auriculae, Varr. R. R. 2, 9, 4.— Transf., of persons, flap-eared: ecquos deos paetulos esse arbitramur? ecquos silos, flaccos, frontones, capitones"},"flamma":{"lemma":"flamma","pos":"","gen":"-color","def":"sing. flammaï, Lucr. 1, 725; 900; 5, 1099), f. for flagma, v. flagro"},"flammesco":{"lemma":"flammesco","pos":"","gen":"","def":"inch. n. , to become inflamed: flammescere caelum, Lucr. 6, 669. flammĕus, a, um, adj. id., flaming, fiery. Lit.: sunt stellae naturā flammeae, Cic. N. D. 2, 46, 118"},"flammo":{"lemma":"flammo","pos":"v.","gen":"-colored","def":"n. and a. . Neutr., to flame, blaze, burn (poet. and perh. only in the part. pres.): super raros feni flammantis acervos Traicit immundos ebria turba pedes (in the purifications at the Palilia)"},"flamomenses":{"lemma":"Flamomenses","pos":"","gen":"","def":", a people of Italy, Plin. 3, 19, 23, § 130. flātĭlis, e, adj. flo, produced by blowing, blown (post-class.): sonitus, Amm. 30, 1: laminae, i. e. founded, cast, Arn. 6, 201: virus, blown in"},"flauissae":{"lemma":"flavissae","pos":"","gen":"","def":"112, 29, for favissae, v. h. v.). Flāvĭus, a, the name of a Roman gens: gens Flavia, Suet. Vesp. 1"},"flegma":{"lemma":"flegma","pos":"","gen":"","def":", v. phlegma. flēmĭna, um, n. (=φλεγμονη), a bloody swelling or congestion of blood about the ankles"},"flexo":{"lemma":"flexo","pos":"","gen":"","def":"freq. a. flexus, from flecto, to bend, curve: vineam, Cato, R. R. 49 fin. flexuntes"},"flexus":{"lemma":"flexus","pos":"","gen":"","def":"flecto, a bending, turning, winding (class.; in sing. and plur.). Lit.: aures duros et quasi corneolos habent introitus, multisque cum flexibus, Cic. N. D. 2, 57, 144"},"flictus":{"lemma":"flictus","pos":"","gen":"","def":"fligo, a striking, dashing together, collision (poet.): armamentūm stridor, flictus navium, Pac. ap. Serv. Verg. A. 9, 667 (Trag. Rel. v. 335 ed. Rib.): tum scuta cavaeque Dant sonitum flictu galeae"},"flo":{"lemma":"flo","pos":"v.","gen":"-glorying","def":"n. and a. [root fla-; Gr. ἐκ-φλαίνω, to stream forth; φλασμός, vain-glorying; hence, Lat. flatus, flabrum, etc., flos, flōreo, Flōra; Germ. blasen, blähen"},"flocces":{"lemma":"flocces","pos":"","gen":"-class","def":", dregs or less of wine (ante-class.): flocces audierat prisca voce significare vini faecem e vinaceis expressam, sicuti fraces ex oleis, idque apud Caecilium in Polumenis legerat, Gell. 11, 7"},"floccus":{"lemma":"floccus","pos":"","gen":"-class","def":", a lock or flock (of wool, on clothes, in fruits, etc.). Lit.: ne qui flocci intereant, Varr. R. R. 2, 11, 8: pomis substrati flocci, id. ib. 1, 59, 3: in veste floccos legere fimbriasve diducere"},"floscellus":{"lemma":"floscellus","pos":"","gen":"","def":"dim. flos, a floweret: ad solis cursum floscelli se vertunt, App. Herb. 49. floscŭle, adv. flosculus, bloomingly: corpus floscule vividum, Cael. Aur. Acut. 1, 6, 50. floscŭlus, i, m. (collat. form"},"flouios":{"lemma":"flovios","pos":"","gen":"","def":"fluvius init. fluctĭcŏla, ae, adj. fluctus-colo, living in waves: nurus, Sid. Carm. 10, 1. fluctĭ-cŏlor, ōris, adj. fluctus, seacolored: profunditas hyacinthi, Mart. Cap. 1, § 67. fluctĭcŭlus, i"},"flustra":{"lemma":"flustra","pos":"","gen":"","def":"id., the usual quiet state of the sea, a calm (ante- and postclass.): flustra, motus maris sine tempestate fluctuantis. Naevius in bello Poenico quod ait: honorariae honestae stabant in flustris"},"fluxe":{"lemma":"fluxe","pos":"adv.","gen":"","def":", v. fluo, P. a., B. fin. fluxĭlis, e, adj. fluxus, fr. fluo, fluid (post-class.): fusile et fluxile liquoris est qualitas, fluidity, Tert. adv. Val. 24. fluxĭo, ōnis, f. fluo"},"fluxus":{"lemma":"fluxus","pos":"","gen":"","def":"fluo, P. a., B."},"foecunde":{"lemma":"foecunde","pos":"","gen":"","def":"fec-. foedē, adv., v. 1. foedus fin. foedĕrāticus, a, um, adj. 2. foedus, pertaining to a league or to the allied, Just. Nov. 147, 2, and 148, 2. foedĕro, āvi, ātum, 1, v. a. 2. foedus"},"foedo":{"lemma":"foedo","pos":"v.","gen":"","def":"a. id., to make foul, filthy, hideous"},"foedus":{"lemma":"foedus","pos":"adj.","gen":"-clause","def":"Sanscr. dhūmas, smoke; cf.: fumus, fīmus, feteo, foul, filthy, loathsome, ugly, unseemly, detestable, abominable, horrible (class."},"foen":{"lemma":"foen","pos":"","gen":"","def":"fen. foetĕo, v. feteo."},"foetesco":{"lemma":"foetesco","pos":"","gen":"","def":"fetesco. foetĭdus, v. fetidus."},"foetor":{"lemma":"foetor","pos":"","gen":"","def":"fetor. foetŭlentus, v. fetulentus."},"foetus":{"lemma":"foetus","pos":"","gen":"","def":"fetus. foetūtīna, v. fetutina. Fōlĭa, ae, f., the name of a witch of Ariminum, Hor. Epod. 5, 42. fŏlĭācĕus, a, um, adj. folium, leafy, like leaves: semen, Plin. 19, 3, 15, § 42"},"follis":{"lemma":"follis","pos":"adv.","gen":"-ball","def":"cf. flo. Lit. A pair of bellows: formae, quas vos effici sine follibus et sine incudibus non putatis, Cic. N. D. 1, 20, 54; cf.: folle fabrili flando accenderunt, Liv. 38, 7, 12; Verg. G. 4, 171"},"fons":{"lemma":"fons","pos":"","gen":"-source","def":"root in Gr. χέϝω, χεύσω, to pour, χύμα, χοή, etc.; Lat. fundo, futtilis. Fons, i. e. stem font, for fovont = χεϝοντ-; cf. Varr. L. L. 5, § 123 Müll."},"for":{"lemma":"for","pos":"part.","gen":"-mi","def":"defect. (the forms in use are fatur, fantur, fabor, fabitur; part. perf. fatus; perf. fatus sum or eram; imper. fare, poet.; inf. fari; and parag. farier, Verg. A. 11, 242; gerund. fandi, fando"},"forceps":{"lemma":"forceps","pos":"","gen":"-mas","def":"plur. forcipium, Lucil. ap. Charis. p. 74), m. and f. (m., Cels. 7, 12; 8, 4; f., Ov. M. 12, 277) [root in Sanscr. ghar-mas, glow, warmth; Gr. θερ-, θέρμη, θέρος"},"forctis":{"lemma":"forctis","pos":"","gen":"","def":"fortis init. Forcŭlus, i, m. contr. from Foriculus, from 1. foris, a deity who presides over the doors, Tert. Idol. 15; Coron. Mil. 13; Aug. Civ. D. 4, 8 fin."},"forda":{"lemma":"forda","pos":"","gen":"","def":", v. fordus. fordĭcīdĭa (archaic form ‡ hordĭ-cīdia, Paul. ex Fest. p. 102 Müll., v. the foll. art.), ōrum, n. forda + caedo, the sacrifice of a cow that is with calf"},"fordus":{"lemma":"fordus","pos":"adj.","gen":"","def":"in the foll.), adj. fero, with young, pregnant: fordicidia a fordis bubus: bos forda quae fert in ventre, etc., Varr. L. L. 6, § 15 Müll."},"forfex":{"lemma":"forfex","pos":"","gen":"-facio","def":"forus-facio, a pair of shears or scissors: forfices sunt quibus incidimus: forcipes quibus aliquid firmum tenemus, Serv. ad Verg. A. 8, 453: vitiosa grana (in uva), forficibus amputant, Col. 12, 44"},"forma":{"lemma":"forma","pos":"","gen":"-i","def":"Sanscr. dhar-, dhar-āmi, bear; dhar-i-man, figure; Gr. θρα- in θρῆνυς, θρόνος"},"formaster":{"lemma":"formaster","pos":"","gen":"","def":"forma, one who beautifies or adorns himself, a coxcomb, dandy: aut luculentaster aut formaster frigidus, Tit. ap. Fest. s. v. OBSTRVDANT, p. 193 Müll. formātĭo, ōnis, f. formo, a shaping, forming"},"formella":{"lemma":"formella","pos":"","gen":"","def":"dim. forma, a little form or mould for baking in (late Lat.): in formella piscem formare, Apic. 9, 13"},"formus":{"lemma":"formus","pos":"adj.","gen":"-veo","def":"ferv-veo; Sanscr. ghar-mas, glow, warmth; Gr. θερμός, θέρος; Lat. ferveo, fornus, fornax; O. H. Germ. waram"},"fornax":{"lemma":"fornax","pos":"","gen":"","def":"cf.: fornus and furnus, Gr. πῦρ, a furnace, oven, kiln (cf. also: caminus, clibanus, focus): in ardentibus fornacibus, Cic. N. D. 1, 37, 103: calcaria, Cato, R. R. 38"},"fornix":{"lemma":"fornix","pos":"","gen":"","def":", an arch or vault (cf.: camera, testudo, tholus, lacunar). Lit.: Democritus invenisse dicitur fornicem, ut lapidum curvatura paulatim inclinatorum medio saxo alligaretur"},"fornus":{"lemma":"fornus","pos":"","gen":"","def":"furnus init. fŏro, āvi, ātum, 1, v. a. root bhar-, Zend. bar-, cut, bore; Gr. φαρ-, φάρος, plough; cf. φάραγξ, φάρυγξ; Germ. bohren; Angl.-Sax. borian"},"foroiuliensis":{"lemma":"Forojuliensis","pos":"","gen":"","def":"Forum Julii, under forum fin."},"forpex":{"lemma":"forpex","pos":"","gen":"-tongs","def":"corrupted from forfex, fire-tongs, Cato, R. R. 10, 3; 11, 5; Suet. Aug. 75; Sid. Epith. 15, 184."},"fors":{"lemma":"fors","pos":"","gen":"-class","def":"fero, to bring, whence fortuna, v. Georg Curtius Gr. Etym. p. 300 sq., chance, hap, luck, hazard. Subst. As an appellative noun (used only in the nom. and abl."},"fors-an":{"lemma":"fors-an","pos":"adv.","gen":"-an","def":"ellipt. for fors sit an"},"forsit":{"lemma":"forsit","pos":"adv.","gen":"","def":"contr. from fors sit; cf. fors, II. A., perhaps, Hor. S. 1, 6, 49 (quoted Prisc. p. 1015 P.). forsĭtan, adv. contr. from fors sit an; v. fors, A."},"fortassis":{"lemma":"fortassis","pos":"adv.","gen":"","def":", v. fortasse init."},"fortax":{"lemma":"fortax","pos":"","gen":"","def":", = φόρταξ (bearer), the basis on which a furnace rests, Cato, R. R. 38, 1. fortē, adv., v. fors, II. B."},"fortesco":{"lemma":"fortesco","pos":"","gen":"","def":"inch. n. , to become brave: item notavimus, quod fortescere posuit (Laevius) pro fortem fieri, Gell. 19, 7, 8. fortĭcŭlus, a, um, adj. dim. , somewhat bold, brave"},"fosi":{"lemma":"Fosi","pos":"","gen":"","def":", a Germanic tribe, a branch of the Cheruscans, near the modern Celle, Tac. G. 36."},"fossa":{"lemma":"fossa","pos":"n. f.","gen":"-ae","def":"a ditch, trench, channel, pit; an excavation, mine trench"},"fosso":{"lemma":"fosso","pos":"","gen":"-and","def":"freq. a. fodio, to dig, pierce (ante-and post-class.): corpora telis, Enn. ap. Varr. L. L. 7, § 100 (Ann. v. 569 ed. Vahl.).—Hence, fossātum, i, n., a ditch, fosse, Pall. Sept. 13; Capitol. Gord. 28"},"fossor":{"lemma":"fossor","pos":"part.","gen":"-digger","def":"id., a digger, delver, ditcher. Lit. In gen. (poet. and in post-Aug. prose): et labefacta movens robustus jugera fossor, Verg. G. 2, 264: squalidus in magna compede fossor, Juv. 11, 80"},"fostia":{"lemma":"fostia","pos":"","gen":"","def":"hostia init."},"fostis":{"lemma":"fostis","pos":"","gen":"","def":"hostis init. fōtus, a, um, Part., from foveo. fōtus, ūs, m. foveo, a warming, fomenting (post-Aug., rare except in abl.). Lit., Amm. 21, 2, 3: solis, Lact. 1, 12"},"fractor":{"lemma":"fractor","pos":"","gen":"-class","def":"id., a breaker, breaker in pieces (post-class.): ferularum, Sid. Ep. 3, 13. fractūra, ae, f. frango, a breach, fracture, cleft: ad luxum aut ad fracturam alliga, Cato"},"fraglo":{"lemma":"fraglo","pos":"","gen":"","def":"fragro init."},"fragmen":{"lemma":"fragmen","pos":"","gen":"","def":"FRAG, frango. * A fracture: percussit subito deceptum fragmine pectus, Val. Fl. 3, 477.— Mostly in plur.: fragmina, um, pieces broken off, fragments, ruins"},"fragmentum":{"lemma":"fragmentum","pos":"","gen":"","def":"FRAG, frango, a piece broken off, a piece, remnant, fragment (class.; mostly in plur."},"franci":{"lemma":"Franci","pos":"adj.","gen":"","def":", the Franks, a Germanic confederacy on the Rhine, Claud. I. Laud. Stil. 189; 227; II. Laud. Stil. 243"},"frango":{"lemma":"frango","pos":"v.","gen":"","def":"a. root in Gr. FPAT, ῥήγνυμι, ῥῆγμα, ῥωγαλέος; Goth. Brikkan; Irish brissim; Germ. brechen; Engl. break"},"fraus":{"lemma":"fraus","pos":"","gen":"-ti","def":"plur. fraudium, Cic. Off. 3, 18, 75; id. Pis. 19, 44; Dig. 9, 2, 23, § 4 al.: fraudum, Tac. A. 6, 21; Gell. 14, 2, 6; Claud. Laud. Stil. 2, 214; archaic form dat. sing. frudi, Lucr. 6, 187 Lachm."},"fraussus":{"lemma":"fraussus","pos":"","gen":"","def":"fraudo init."},"frax":{"lemma":"frax","pos":"","gen":"","def":"fraces init. fraxāre, vigiliam circuire, Paul. ex Fest. p. 91 Müll. fraxĭnĕus, a, um, adj. 1. fraxinus, of ash-wood, ashen: sudes, Verg. G. 2, 359: trabes, id. A. 6, 181: frons, Col. 6, 3, 6: hasta"},"frendesco":{"lemma":"frendesco","pos":"","gen":"","def":"inch. , to begin to gnash with the teeth: crudelitate doloris, Fulg. Serm. 11. frendo and frendeo, frendui, frēsum and fressum (v. infra), 2 and 3, v. n. and a. [cf. Gr. χρεμ-ίζω, to neigh, χρόμη"},"frendor":{"lemma":"frendor","pos":"","gen":"-class","def":"frendo, a gnashing (post-class.): dentium in Gehenna, Tert. Res. Carn. 35 fin."},"frictrix":{"lemma":"frictrix","pos":"","gen":"-class","def":"id., she that rubs (cf. frico fin.; post-class.), Tert. Pall. 4 fin.; id. Res. Carn. 16; cf. tribas. frictūra, ae, f. id., a rubbing, in mal. part., App. M. Fragm. p. 717 Oud."},"frictus":{"lemma":"frictus","pos":"","gen":"","def":"Rubbed, Part. of frico.— Roasted, Part. of frigo."},"fridum":{"lemma":"fridum","pos":"","gen":"","def":"frigidus, A. 2. C."},"frigdaria":{"lemma":"frigdaria","pos":"","gen":"","def":"frigidarius."},"frigdor":{"lemma":"frigdor","pos":"","gen":"","def":"frigor. frīgēdo, ĭnis, f. frigeo, cold, Varr. ap. Non. 139, 11, and 206, 21. frīgĕ-facto, āre, v. a. frigeo + facio, to make cold, to cool: os nunc frigefactas, Plaut. Poen. 3, 5, 15"},"fritilla":{"lemma":"fritilla","pos":"","gen":"","def":"fitilla. frĭtillus, i, m., a box from which the dice were thrown, a dice-box, Mart. 14, 1, 3; 4, 14, 8; Juv. 14, 5"},"frixo":{"lemma":"frixo","pos":"","gen":"","def":"freq. , to roast thoroughly, Cael. Aur. Acut. 1, 11, 77. frixōrĭum, ii, n. id., a frying-pan, Plin. Val. 2, 7"},"fronto":{"lemma":"fronto","pos":"","gen":"","def":"amplif. , one who has a broad forehead: ecquos naevum habere? ecquos silos, flaccos, frontones, capitones? Cic. N. D. 1, 29, 80.—Hence,"},"fros":{"lemma":"fros","pos":"","gen":"","def":"1. frons init. fructēta, ōrum, n., a later form for frutecta, bushes, thickets: arbusta, fructeta scholastici vocabant, Serv. Verg. E. 1, 40. fructĭfer, ĕra, ĕrum, adj. fructus + fero, fruit-bearing"},"fruns":{"lemma":"fruns","pos":"","gen":"","def":"1. frons init. frŭor, fructus (perf. fruitus est, Dig. 7, 4, 29: fruiti sumus, Sen. Ep. 93, 7: fructus sum, Vell. 2, 104, 3; Lucr. 3, 940; v. Neue, Formenl. 2, 562"},"frus":{"lemma":"frus","pos":"","gen":"","def":"1. frons. Frŭsĭno, ōnis, m., a city of the Hernici, in Latium, situated on the Via Latina, now Frosinone, Liv. 27, 37"},"frustillum":{"lemma":"frustillum","pos":"","gen":"-class","def":"dim. frustum, a small piece, little bit (ante-class.): parvula, Arn. 7, 231: ignea, id. 2, 84."},"frusto":{"lemma":"frusto","pos":"v.","gen":"","def":"a., to break to pieces: cum Punicae praedae omnibus promontoriis insulisque frustarentur et fluitarent, etc."},"frustro":{"lemma":"frustro","pos":"","gen":"","def":"the foll. art."},"frustror":{"lemma":"frustror","pos":"v.","gen":"-stro","def":"dep."},"frustum":{"lemma":"frustum","pos":"","gen":"","def":", a piece, bit (syn.: fragmentum, segmentum). Lit., of food (class.): frusto panis conduci potest, vel uti taceat, vel uti loquatur, Cato ap. Gell. 1, 15, 10: necesse est"},"frutinal":{"lemma":"Frutinal","pos":"","gen":"","def":"the foll. art. Frūtis, is (Etrusc. form Fruti"},"fu":{"lemma":"fu","pos":"interj.","gen":"","def":", v. fue."},"fuat":{"lemma":"fuat","pos":"","gen":"","def":"1. sum init. fūcātē, adv., v. fuco, P. a. fin. fūcātus, a, um, Part. and P. a., from fuco. fūcĭlis falsa: dicta autem quasi fucata, Paul. ex Fest. p. 92 Müll. N. cr. fūcĭnus, a, um, adj. 1. fucus"},"fuit":{"lemma":"sum","pos":"","gen":"","def":"(form of sum)"},"fulcrum":{"lemma":"fulcrum","pos":"","gen":"-couch","def":"fulcio, the post or foot of a couch (a bed or an eating-couch), a bedpost: eburnum, Prop. 2, 13, 21 (3, 5, 5 M.); Ov. P. 3, 3, 14"},"fulgenter":{"lemma":"fulgenter","pos":"adv.","gen":"","def":", v. fulgeo, P. a. fin. Fulgentĭus, ii, m., Fabius Planciades Fulgentius, a Roman mythographer and grammarian in the beginning of the sixth century of the Christian era. fulgeo, fulsi"},"fulgesco":{"lemma":"fulgesco","pos":"","gen":"","def":"inch. n. , to flash, to glitter: solis radiatione fulgescere, Firm. Astr. 1, 4 fin. fulgētra, ae, v. the foll. art. fulgētrum, i (fem. plur. acc. fulgetras, Plin. 28, 2, 5"},"fulgo":{"lemma":"fulgo","pos":"","gen":"","def":"fulgeo init."},"fulgor":{"lemma":"fulgor","pos":"","gen":"","def":"fulgeo, lightning, a flash of lightning (mostly poet. for fulgur): fulgorem quoque cernimus ante Quam tonitrum accipimus, Lucr. 6, 170 Lachm. N. cr.; so ib. 217; Verg. A. 8, 524"},"fullo":{"lemma":"fullo","pos":"part.","gen":"-fuller","def":"A fuller, cloth-fuller, Plaut. Aul. 3, 5, 34; Plin. 28, 6, 18, § 66; Mart. 6, 93, 1; Dig. 12, 7, 2; Gai. Inst. 3, 143"},"fulmenta":{"lemma":"fulmenta","pos":"","gen":"-class","def":"contr. from fulcimenta, from fulcio (ante-class.), a prop, support of a building, Cato, R. R. 14, 1.— In partic., the heel of a shoe, Lucil. ap. Non. 206, 26; Plaut. Trin. 3, 2, 94."},"fulmentum":{"lemma":"fulmentum","pos":"","gen":"","def":"n. contr. from fulcimentum, from fulcio, a prop, support. In gen., Vitr. 5, 1 fin.: porticus fulmentis Aquitanicis superba, i. e. columns, Sid. Ep. 2, 10 in Carm.— In partic., a bedpost: Cels. 2"},"fultor":{"lemma":"fultor","pos":"","gen":"","def":"fulcio, a supporter, support, prop (late lat.)"},"fuluaster":{"lemma":"fulvaster","pos":"adj.","gen":"-class","def":"fulvus, yellowish (post-class.): radix, App. Herb. 109. Fulvĭus, a, name of a Roman gens, Cic. Planc. 8, 20. So esp., M. Fulvius Flaccus, a friend of C. Gracchus, who lost his life with him"},"fuluia":{"lemma":"Fulvia","pos":"","gen":"","def":"Fulvius."},"fuluus":{"lemma":"fulvus","pos":"adj.","gen":"-colored","def":"v. fulgeo, deep yellow, reddish yellow, gold-colored, tawny (mostly poet.): corpora leonum, Lucr. 5, 902"},"funda":{"lemma":"funda","pos":"","gen":"-stone","def":"Sanscr. spandē, itch; Gr. σφαδάζω, to move convulsively; σφοδρός, σφεδανός, impassioned; σφενδόνη"},"fundi":{"lemma":"Fundi","pos":"adj.","gen":"-coast","def":", a sea-coast town of Latium, on the Appian Way, between Formiae and Tarracina, now Fondi, Mel. 2, 4, 9; Cic. Att. 14, 6, 1; Liv. 41, 27; Hor. S. 1, 5, 34; Suet. Tib. 5; id. Galb. 4"},"fundo":{"lemma":"fundo","pos":"v.","gen":"","def":"a. fundus, to lay the bottom, keel, foundation of a thing, to found (syn.: condo, exstruo, etc.). Lit. (perh. only poet.): haec carina satis probe fundata et bene statuta est, i. e. is laid"},"fundus":{"lemma":"fundus","pos":"","gen":"-nas","def":"Sanscr. budh-nas, ground; Gr. πυθμήν, πύνδαξ; O. H. Germ. Bodam; Germ. Boden"},"fungus":{"lemma":"fungus","pos":"","gen":"-pated","def":"for sfungus, kindred to σφόγγος, σπόγγος, the initial s suppressed as in fallo, fides, nurus, etc."},"fuo":{"lemma":"fuo","pos":"","gen":"","def":"sum init. fūr, fūris, comm. root fer-, v. fero"},"fura":{"lemma":"Fura","pos":"","gen":"","def":", name of a goddess, otherwise unknown, Mart. Cap. 2, § 164 (al. Furia). fūrācĭtas, ātis, f. furax, inclination to steal, thievish disposition, thievishness (very rare): auri argentique, Plin. 10, 29"},"furca":{"lemma":"furca","pos":"","gen":"-ig","def":"Sanscr. bhur-ig, shears; cf. Lat. forceps, forfex; also Gr. φάρος, plough; Lat. forāre; Engl. bore, Georg Curtius Gr. Etym. p. 299; but Corss. refers furca to root dhar-,=fero, as a prop. support"},"furcilla":{"lemma":"furcilla","pos":"","gen":"","def":"dim. furca, a little fork: herba subsecari falcibus debet et, quoad perarescat, furcillis versari, Varr. R. R. 1, 49, 1; 1, 8, 6"},"furcillo":{"lemma":"furcillo","pos":"v.","gen":"","def":"a. id., to support (qs. by a crotch).—Trop.: tu inventus vero, meam qui furcilles fidem! Plaut. Ps. 2, 2, 36. furcōsus, a, um, adj. furca, full of forks or points: thyrsi leontopodii"},"furtim":{"lemma":"furtim","pos":"adv.","gen":"","def":"fur; hence, like a thief, i. e., by stealth, secretly, privily (rare but class."},"furtum":{"lemma":"furtum","pos":"adv.","gen":"","def":"fur, theft, robbery (class. and freq."},"furuus":{"lemma":"furvus","pos":"adj.","gen":"","def":"akin with fuscus, dark, dusky, gloomy, swarthy, black: veteres Romani furvum atrum appellaverunt, Gell. 1, 18, 4; cf.: furvum nigrum vel atrum, Paul. ex Fest. p. 84 Müll."},"fusco":{"lemma":"fusco","pos":"v.","gen":"","def":"a. and n. id.. Act., to make dark, swarthy, dusky, to blacken, darken (poet.). Lit.: fuscentur corpora campo, Ov. A. A. 1, 513: cutem pingui olivo, Stat. Th. 6"},"fuscus":{"lemma":"fuscus","pos":"adj.","gen":"-scus","def":"for fur-scus; cf. furvus, v. Georg Curtius Gr. Etym. p. 304, dark, swarthy, dusky, tawny (class."},"fusterna":{"lemma":"fusterna","pos":"","gen":"","def":"contr. from fusterina, sc. pars, from fustis, the upper part, knotty part of a fir - tree, Plin. 16, 39, 76, § 196"},"gabba":{"lemma":"Gabba","pos":"","gen":"","def":", in full Apicius Gabba, a famous wit of the time of Tiberius, Juv. 5, 4; Mart. 1, 41, 16. Găbĭi, ōrum, m. Sanscr. gambhas, mouth; Gr. γαμφή, jaw; cf. Saxon camb"},"gaesum":{"lemma":"gaesum","pos":"","gen":"","def":"Celtic, a long, heavy javelin of the Gauls; Gr. γαισός or γαῖσον (syn.: dolo, sarissa, sparus, lancea), Caes. B. G. 3, 4, 1; Liv. 8, 8, 5; 9, 36, 6; 26, 6, 5; Varr. ap. Non. 555, 13; Verg. A. 8, 662"},"gala":{"lemma":"Gala","pos":"","gen":"","def":", the father of Masinissa, Liv. 24, 48. gălactītes, ae, m., and gălactītis, ĭdis, f., = γαλακτίτης and γαλακτῖτις, a precious stone of a milk-white color, otherwise unknown, milk-stone, Plin. 37, 10"},"galba":{"lemma":"galba","pos":"","gen":"-borer","def":"Gallic, perh. kindr. with the Germ. gelb (yellow) or Kalb (calf). A small worm, the ash-borer, or the larva of the ash-spinner, Bombyx aesculi, Linn. acc. to Suet. Galb. 3.— In the Gallic"},"galbus":{"lemma":"galbus","pos":"","gen":"","def":"calvus fin. gălĕa, ae, f. kindred to Sancr. jal, to cover; cf. celare, a helmet (usually of leather), head-piece, morion (cf. cudo"},"galion":{"lemma":"galion","pos":"","gen":"","def":"galeopsis."},"galla":{"lemma":"galla","pos":"","gen":"-apple","def":"Oak-apple, gall-nut, Plin. 16, 6, 9, § 26; 24, 4, 5, § 9; Col. 9, 13, 7; Mart. Cap. 3, § 225.—Plur., Col. 6, 7, 2. —In a pun with Galla, a female Gaul"},"galli":{"lemma":"Galli","pos":"adj.","gen":"-nut","def":", the Gallic nation, the Gauls, both beyond the Rhine and in Upper Italy"},"gallia":{"lemma":"Gallia","pos":"","gen":"","def":"1. Galli, II. A."},"galliambus":{"lemma":"galliambus","pos":"","gen":"","def":"3. Gallus, II. A., a song of the priests of Cybele, Diom. p. 513 P.; Mart. 2, 86, 5"},"gallidraga":{"lemma":"gallidraga","pos":"","gen":"","def":", the hairy teasel, Dipsacus pilosus, Linn.; Plin. 27, 10, 62, § 89. gallīna, ae, f. 1. gallus, a hen. Lit., Varr. R. R. 3, 9, 1; Col. 8, 2, 1; Plaut. Ps. 1, 1, 27 sq.; Cic. de Sen. 16, 56"},"gallus":{"lemma":"gallus","pos":"","gen":"-cock","def":"kindr. to Sanscr. grī, cry; Gr. γῆρυς, speech; Lat. garrio, garrulus; Engl. call, a cock, dunghill-cock, Varr. R. R. 2, 10, 4; 3, 9, 3; Cic. Div. 2, 26, 56 sq.; Juv. 13, 233; Hor. S. 1, 1, 10"},"gamba":{"lemma":"gamba","pos":"","gen":"","def":"perh. from κάμπη, a bending, a hoof (late Lat.), Veg. Vet. 1, 56 fin."},"gamma":{"lemma":"gamma","pos":"","gen":"","def":", = γάμμα, the Greek letter Γ, gamma. Lit., Aus. Idyll. de Lit. 12, 21.— Transf., in the agrimensores, the rectangular shape of a field, Auct. de Limit. p. 278 and 309 Goes. gammărus, i"},"gangaba":{"lemma":"gangaba","pos":"","gen":"","def":"Persian, a porter (= bajulus), Curt. 3, 13, 6. Gangărĭdae (Garg-), ārum, m., = Γαγγαρίδαι, an Indian people near the Ganges, in the modern Bengal, Plin. 6, 18, 22, § 65; Curt. 9, 2, 2; Verg. G. 3, 27"},"ganges":{"lemma":"Ganges","pos":"adj.","gen":"-hunter","def":", = Γάγγης, the river Ganges, in India, Mel. 3, 7, 5 sq.; Plin. 6, 17, 21, § 60 sq.; Cic. Rep. 6, 20; Verg. G. 2, 137; Ov. Tr. 5, 3, 23; id. M. 2, 249"},"gangraena":{"lemma":"gangraena","pos":"","gen":"","def":", = γάγγραινα, a cancerous, eating ulcer on the body, a gangrene. Lit., Cels. 5, 26, 34; Lucil. ap. Non. 117, 22"},"ganta":{"lemma":"ganta","pos":"","gen":"","def":"old Germ.; the mod. Gans, a goose: (anseres) e Germania laudatissimi. Candidi ibi, verum minores, gantae vocantur, Plin. 10, 22, 27, § 54"},"gargaridio":{"lemma":"gargaridio","pos":"","gen":"","def":"gargarizo init. gargărisma (-ismum, Cael. Aur. Tard. 2, 7, 99), ătis, n., = γαργάρισμα, a gargle, Theod. Prisc. 1, 10, 15"},"gassinades":{"lemma":"gassinades","pos":"","gen":"","def":"(lapis), a Median precious stone, Plin. 37, 10, 59, § 163."},"gaster":{"lemma":"gaster","pos":"","gen":"-bellied","def":", = γαστήρ, the belly (pure Lat. venter). Lit.: inflatio secundum gastera, Cael. Aur. Tard. 3, 8.— Transf., a big-bellied vessel, Petr. 70; 79; Marc. Emp. 8 med."},"gates":{"lemma":"Gates","pos":"","gen":"","def":"Garites."},"gau":{"lemma":"gau","pos":"","gen":"","def":"gaudium init. gaudĕbundus, a, um, v. gaudibundus. gaudens, entis, Part. and P. a., from gaudeo. gaudĕo, gāvīsus, 2 (archaic perf. gavisi, Liv. Andron. and Cass. Hem. ap. Prisc. p. 868 P.)"},"gaulus":{"lemma":"gaulus","pos":"","gen":"","def":"Sanscr. gōlas, a waterpot"},"gaurelios":{"lemma":"Gaurelios","pos":"","gen":"","def":"31, 45."},"gaurus":{"lemma":"Gaurus","pos":"adj.","gen":"-nus","def":", a mountain in Campania, famous for its wine, now Monte Barbaro, Plin. 14, 6, 8, § 64; Flor. 1, 16, 5"},"gemma":{"lemma":"gemma","pos":"","gen":"-vessel","def":"cf. Gr. γέμω, to be full; Lat. gumia; lit. a fulness, swelling. The ancients supposed the original meaning to be a precious stone, Quint. 8, 6, 6; cf. Cic. Or. 24, 81"},"gemmasco":{"lemma":"gemmasco","pos":"","gen":"","def":"inch. n. , to begin to bud, Col. 5, 10, 12; Arb. 22, 1; Plin. 17, 15, 25, § 116. gemmātus, a, um, adj. gemma"},"gemmesco":{"lemma":"gemmesco","pos":"","gen":"","def":"inch. n. , to become a gem, Plin. 37, 10, 57, § 158. gemmĕus, a, um, adj. id., of precious stones, set or adorned with precious stones. Lit.: mittit etiam trullam gemmeam rogatum, Cic. Verr. 2, 4, 27"},"gemmo":{"lemma":"gemmo","pos":"v.","gen":"","def":"n. and a. . (Acc. to gemma, I.) To put forth buds, to bud or gem: id fit antequam gemmare Aut florere quid incipit, Varr. R. R. 1, 40, 4"},"gens":{"lemma":"gens","pos":"","gen":"","def":"root GEN, gigno, that which belongs together by birth or descent, a race or clan, embracing several families united together by a common name and by certain religious rites"},"genucilius":{"lemma":"Genucilius","pos":"","gen":"","def":", a Roman proper name, Cic. Fam. 13, 53, 1. gĕnŭīnus, a, um, adj. geno, gigno, innate, native, natural. Lit. (rare but class.): genuinae domesticaeque virtutes, * Cic. Rep. 2, 15"},"germen":{"lemma":"germen","pos":"","gen":"-as","def":"Sanscr. root grabh-, grah-, to conceive; garbh-as, child"},"gerrae":{"lemma":"gerrae","pos":"","gen":"","def":", = γέρρα, orig. wattled twigs"},"gerres":{"lemma":"gerres","pos":"","gen":"","def":", an inferior salted seafish, Plin. 32, 11, 53, § 148 Sill. (al. girres), Mart. 12, 32, 15; 3, 77, 7"},"gessius":{"lemma":"Gessius","pos":"","gen":"","def":", a Roman family name, Tac. H. 5, 10."},"gesta":{"lemma":"gesta","pos":"","gen":"","def":"gero, II. B. 3., deeds, acts (rare for res gestae): obscuriora sunt ejus gesta, Nep. Timoth. 4, 6; id. Hann. 13, 3; Sisenn. ap. Gell. 12, 15, 2"},"gesto":{"lemma":"gesto","pos":"","gen":"","def":"freq. a. and n. gero. Act., to bear, to carry, to have; to wear, wield (mostly poet. and in postAug. prose"},"gestor":{"lemma":"gestor","pos":"","gen":"-bearer","def":"id.. * A tale-bearer, tattler: homines qui gestant quique auscultant crimina, Si meo arbitratu liceat, omnes pendeant, Gestores linguis, auditores auribus, Plaut. Ps. 1, 5, 12.—* A manager"},"gibba":{"lemma":"gibba","pos":"","gen":"","def":"1. gibbus, II. B."},"gibber":{"lemma":"gibber","pos":"adj.","gen":"-backed","def":"like gibbus; kindr. to Sanscr. kubya, hunch-backed"},"gibbus":{"lemma":"gibbus","pos":"adj.","gen":"-like","def":"cf. κύπτω, κυφός, bent, bowed, crooked"},"gignentia":{"lemma":"gignentia","pos":"","gen":"","def":", see gigno fin. gigno, gĕnŭi, gĕnĭtum, 3 (archaic primary form of the pres. gĕno, ĕre: genit, Varr. R. R. 2, 2, 19: genunt, Varr. ap. Prisc. p. 898 P.: genat, Varr. R. R. 1, 31, 4: genitur"},"gilbus":{"lemma":"gilbus","pos":"","gen":"","def":"gilvus."},"gillo":{"lemma":"gillo","pos":"","gen":"-vessel","def":", a cooling-vessel, cooler for liquids, Poët. in Anthol. Lat. 2, p. 369 and 406 Burm.; cf. βαυκάλιον gillo, Gloss. Philox."},"gindes":{"lemma":"Gindes","pos":"","gen":"","def":"Gyndes. gingĭdĭon, ii, n., = γιγγίδιον, a small Syrian plant; acc. to Sprengel, the French carrot, Daucus gingidium, Linn."},"ginnus":{"lemma":"ginnus","pos":"","gen":"","def":"hinnus. git (also gith and gicti, acc. to Charis. p. 106 P.), indecl. n., a planc, called also melanthion and melanspermon, Roman coriander, Nigella sativa, Linn.; Plin. 20, 17, 71, § 182 sq."},"glamae":{"lemma":"glamae","pos":"","gen":"","def":"gramiae. glandārĭus, a, um, adj. glans, of or belonging to acorns or mast: silva, producing acorns, Cato, R. R. 1, 7"},"glando":{"lemma":"glando","pos":"","gen":"","def":"id., in late Latin for glans, an acorn, Avien. Perieg. 285; 1189. glandŭlae, ārum, f. dim. id.; lit., a little acorn"},"glanis":{"lemma":"glanis","pos":"","gen":"","def":", = γλάνις and γλάνος, a kind of shad, Plin. 9, 43, 67, § 145; 32, 10, 45, § 128; 32, 11, 53, § 148."},"glans":{"lemma":"glans","pos":"","gen":"-shaped","def":"kindr. with βάλανος, an acorn, and, in gen., any acorn-shaped fruit, beechnut, chestnut, etc. Lit.: bubus glandem prandio depromere, Plaut. Truc. 3, 1, 2; Cato, R. R. 54; 60; Col. 6, 3"},"glanus":{"lemma":"glanus","pos":"","gen":"","def":"glanis. glārĕa, ae, f., gravel (cf. arena, sabulum, suburra, rudus): eo loco pulvis, non glarea injecta est, Cic. Q. Fr. 3, 2, 2, § 4"},"glastum":{"lemma":"glastum","pos":"","gen":"","def":", the herb woad, used in dyeing blue, usually called Isatis tinctoria, Linn.; Plin. 22, 1, 2, § 2."},"glauce":{"lemma":"Glauce","pos":"","gen":"","def":", = Γλαύκη. The mother of the third Diana, Cic. N. D. 3, 23, 58.— Another name of Creüsa, wife of Jason, Hyg. F. 25.— An Amazon, Hyg. F. 163. glaucēum, i, n., = γλαύκειον, a bluish-colored plant"},"glauciscus":{"lemma":"glauciscus","pos":"","gen":"-colored","def":", = γλαυκίσκος, a bluish-colored fish, otherwise unknown, Plin. 32, 10, 46, § 129"},"glaucus":{"lemma":"Glaucus","pos":"","gen":"-god","def":", = Γλαῦκος, a Greek proper name. A son of Sisyphus, devoured by his own horses, Verg. G. 3, 267.— The commander of the Lycians in the Trojan war, a friend of Diomede, Hor. S. 1, 7"},"glaux":{"lemma":"glaux","pos":"","gen":"","def":", = γλαύξ, a plant, called also eugalacton, Plin. 27, 9, 58, § 82. glēba, and its derivv., v. glaeba, etc. glēchon, ōnis, m., = γλήχων, pennyroyal: pulegium, App. Herb. 92. glēchōnītes, is, m."},"glis":{"lemma":"glis","pos":"","gen":"","def":"perh. kindred with γαλέη, a dormouse: Sciurus glis, Linn.; Glis esculentus, Blumenb.; a delicacy with the Romans, Varr. R. R. 3, 15; Plin. 8, 57, 82, § 223 sq.; Mart. 13, 59; Apic. 8, 9; Petr. 31"},"glisco":{"lemma":"glisco","pos":"v.","gen":"","def":"n. perh. kindred with cresco, Paul. ex Fest. s. h. v. p. 98 Müll.; cf. Doed. Syn. 1, p. 21, to grow up, swell up, spread, blaze up, burst out (mostly poet. and in post-Aug. prose"},"glos":{"lemma":"glos","pos":"","gen":"-in","def":"Gr. γάλοως, Att. γάλως, a husband's sister, sister-in-law. Lit., Dig. 38, 10, 4, § 6; Paul. ex Fest. p. 98 Müll.; Charis. p. 27"},"glossa":{"lemma":"glossa","pos":"","gen":"","def":", = γλῶσσα, an obsolete or foreign word that requires explanation"},"glottis":{"lemma":"glottis","pos":"","gen":"","def":", = γλωττίς, a little bird, Plin. 10, 23, 33, § 66. glūbo, ĕre, v. a. and n. Gr. γλύφω"},"glus":{"lemma":"glus","pos":"","gen":"","def":"Gr. γλοιός, sticky oil; γλία, slime, gluten, glue; for the usual gluten, Aus. Idyll. monos. per interr. 12, 10"},"glyssomarga":{"lemma":"glyssomarga","pos":"","gen":"","def":"glisomarga."},"gnaeus":{"lemma":"Gnaeus","pos":"","gen":"","def":"Gneus. gnaphălĭon, ii, n., = γναφάλιον, the herb cudweed, cotton-grass, Plin. 27, 10, 61, § 88. gnarigavit significat apud Livium (Andron.) narravit, Paul. ex Fest. p. 95 Müll. N. cr. . gnārĭtas"},"gnosco":{"lemma":"gnosco","pos":"","gen":"","def":"nosco init. gnostĭcē, es, f., = γνωστική, insight, the power of perceiving, Fulg. Myth. 3, 10. Gnostĭci, ōrum, m., = Γνωστικοί, the Gnostics"},"gomphi":{"lemma":"Gomphi","pos":"","gen":"","def":", = Γόμφοι, a town of Thessaly on the Penēus, now Kalabaki, Plin. 4, 8, 15, § 29 sq.; Caes. B. C. 3, 80, 1: Liv. 31, 41; 32, 14"},"gomphus":{"lemma":"gomphus","pos":"","gen":"","def":", = γόμφος, a nail, peg, Tert. Mag. 12; Stat. S. 4, 3, 48."},"gonger":{"lemma":"gonger","pos":"","gen":"","def":"conger."},"gongylis":{"lemma":"gongylis","pos":"","gen":"","def":", = γογγυλίς, a rape, turnip, Col. poët. 10, 421."},"goniaea":{"lemma":"goniaea","pos":"","gen":"","def":", a precious stone, otherwise unknown, Plin. 37, 10, 59, § 164."},"gonni":{"lemma":"Gonni","pos":"","gen":"","def":", a town of Thessaly near the Vale of Tempe, now Lycóstomo, Liv. 33, 10; 36, 10.—Also in the sing.: Gonnus, i, m., Liv. 42, 54; 67; 44, 6."},"gonnocondylum":{"lemma":"Gonnocondylum","pos":"","gen":"","def":", a town of Thessaly, Liv. 39, 25 fin. gŏnorrhoea, ae, f., = γονόρροια, a seminal flux, gonorrhoea, Firm. Math. 3, 7, 8."},"gordaei":{"lemma":"Gordaei","pos":"","gen":"","def":"Gordueni. Gordĭānus, i, m., a Roman proper name"},"gorge":{"lemma":"Gorge","pos":"","gen":"","def":", a daughter of Oeneus, and sister of Meleager and Dejanira, who was changed into a bird, Ov. M. 8, 543; Hyg. Fab. 174"},"gortyn":{"lemma":"Gortyn","pos":"","gen":"","def":"the foll. art. Gortȳna, ae, and Gortȳne, ēs (also Cortȳnia, ae, Varr. R. R. 1, 7, 6"},"gracchus":{"lemma":"Gracchus","pos":"adj.","gen":"-nus","def":", a Roman family name in the gens Sempronia"},"gracillo":{"lemma":"gracillo","pos":"v.","gen":"","def":"n., to cackle or cluck as a hen: cucurrire solet gallus, gallina gracillat, Auct. Carm. Philom. 25. grăcĭlus, a, um, v. gracilis init. grācŭlus (gracc-), i, m. from its note gra gra, Quint. 1, 6, 37"},"graea":{"lemma":"Graea","pos":"","gen":"","def":", = Γραῖα, an ancient town in Boeotia, near Oropus (mentioned by Hom. Il. 2, 498), Stat. Th. 7, 332."},"graeae":{"lemma":"Graeae","pos":"","gen":"-haired","def":", = Γραῖαι (old women), daughters of Phorcus (hence Phorcydes) and Ceto, sisters and guardians of the Gorgons, gray-haired from their birth, having but one eye and one tooth among them"},"graece":{"lemma":"Graece","pos":"adv.","gen":"","def":", v. Graeci, II. A. fin. 1."},"graeci":{"lemma":"Graeci","pos":"adj.","gen":"-cus","def":", = Γραικοί, the Grecians, Greeks: contendunt Graecos, Graios memorare solent sos, Enn. ap. Fest. p. 301 Müll. (Ann. v. 358 Vahl.): eos septem, quos Graeci sapientes nominaverunt, Cic. Rep. 1"},"graecia":{"lemma":"Graecia","pos":"","gen":"","def":"Graeci, II. B. Graecĭgĕna, ae, m. Graecus-gigno"},"graecor":{"lemma":"graecor","pos":"v.","gen":"","def":"dep. n. , to imitate the Greeks, live in the Greek manner: si Romana fatigat Militia assuetum Graecari, Hor. S. 2, 2, 11"},"graecus":{"lemma":"Graecus","pos":"","gen":"","def":"Graeci, II. A."},"grallae":{"lemma":"grallae","pos":"","gen":"","def":"contr. from an obsolete dim., gradula, from gradus; cf. rallum, from rado, stilts, Varr. ap. Non. 115, 21 sq."},"gramma":{"lemma":"gramma","pos":"","gen":"-class","def":", = γραμμή, a line in writing, a stroke of the pen (post-class.), Macr. Somn. Scip. 1, 5; App. Herb. 108."},"grandaeuus":{"lemma":"grandaevus","pos":"adj.","gen":"","def":"grandisaevum, in years, old, aged (poet. and in post-Aug. prose): Nereus, Verg. G. 4, 392: Alethes, id. A. 1, 121: Emathion, Ov. M. 5, 99: pater, id. ib. 8, 519: patres, id. ib. 7, 160: senes"},"grandesco":{"lemma":"grandesco","pos":"","gen":"","def":"inch. n. , to become great, to grow (poet. and in postAug. prose): quicque sua de materia grandescere alique (preceded by crescere), Lucr. 1, 191; cf. id. 2, 1122"},"grandis":{"lemma":"grandis","pos":"adj.","gen":"-grown","def":"cf. gradus; also Germ. gross; Engl. great, full-grown, large, great, full, abundant (class.; most freq. of things"},"grando":{"lemma":"grando","pos":"","gen":"-uni","def":"(masc., Varr. ap. Non. 208, 11) [Sanscr. hrād-uni, storm; Gr. χάλαζα for χαλαδ-ια], hail, a hail-storm. Lit., Plaut. Most. 1, 2, 58; id. Merc. 5, 2, 19; Cic. N. D. 3, 35, 86; Liv. 28, 37, 7"},"grannus":{"lemma":"Grannus","pos":"","gen":"","def":"Ers. and Trel. grian, the sun, a surname of Apollo in several Germanic, Dacian, and Scottish inscriptions, Inscr. Orell. 1997 sq. (cf. Grynēus). grānōsus, a, um, adj. granum"},"grassor":{"lemma":"grassor","pos":"v.","gen":"-class","def":"pres. grassarier, Prud. Ham. 651; act. collat. form grassabamus, App. M. 7, 7), v. dep. n. and a. , to go, go about (not in Cic. and Caes."},"gressus":{"lemma":"gressus","pos":"","gen":"-class","def":"gradior, a stepping, going, step, course, way. Lit. (poet. and post-class.; cf.: gradus, passus, incessus, ingressus): tendere gressum ad moenia, Verg. A. 1, 410; so in sing., id. ib. 6, 389"},"grex":{"lemma":"grex","pos":"","gen":"","def":"(fem., Lucil. ap. Charis. p. 72 P.; Lucr. 2, 662; Inscr. ap. Maff. Mus. Veron. 127, 4) [Sanscr. root jar-, come together"},"grinnes":{"lemma":"Grinnes","pos":"","gen":"","def":", a place in Gallia Belgica, near the modern Druten or Warich and Bochstein, Tac. H. 5, 20. grīphus, i, m., = γρῖφος (a net"},"groco":{"lemma":"groco","pos":"v.","gen":"","def":"n., to croak as a raven, Apul. de Deo Soc. prol. p. 366, 19 (Hild. crocare). grōma or grūma, ae, f. A surveyor's pole or measuring-rod, acc. to Paul. ex Fest. s. v. p. 72 Müll. and Non. 63, 6.— Hence"},"gromphaena":{"lemma":"gromphaena","pos":"","gen":"","def":", a kind of amaranth: Amaranthus tricolor, Linn.; Plin. 26, 7, 23, § 40. gromphēna, ae, f., a Sardinian bird of the crane species, Plin. 30, 15, 52, § 146."},"grosa":{"lemma":"grosa","pos":"","gen":"","def":", a tool of a silversmith, Arn. 6, 14."},"grosphus":{"lemma":"grosphus","pos":"","gen":"","def":", = γρόσφος, the point of a javelin, Arn. 6, 200. Grosphus, a Roman surname, Hor. C. 2, 16 lemm. grossĭtūdo, ĭnis, f. 2. grossus, thickness=crassitudo (late Lat.), Vulg. Jer. 52, 21; 3, Reg. 7, 26"},"grossus":{"lemma":"grossus","pos":"","gen":"","def":"and f., an unripe fig, Cato, R. R. 94; Cels. 5, 12; Plin. 23, 7, 63, § 125; 17, 27, 43, § 254."},"gruis":{"lemma":"gruis","pos":"","gen":"","def":"grus. grullus εἶδος πλοίου, Gloss. Philox. grūma and grūmātĭcus, v. grom-."},"grumentum":{"lemma":"Grumentum","pos":"","gen":"","def":", a town of Lucania, near the modern Saponara, Liv. 23, 37, 10; 27, 41, 1 sq."},"grus":{"lemma":"grus","pos":"","gen":"-ram","def":"sing. gruis, Phaedr. 1, 8, 7), f. (m., Hor. S. 2, 8, 87) , a crane, Plin. 10, 23, 30, § 60; Cic. N. D. 2, 49, 125; Mart. 13, 75; Cels. 2, 18; Lucr. 4, 181"},"gry":{"lemma":"gry","pos":"","gen":"","def":"indecl., = γρῦ, the least trifle: ne gry quidem ferre hinc potes, Plaut. Most. 3, 1, 67 Weise (recent edd. write γρῦ)."},"gryllo":{"lemma":"gryllo","pos":"v.","gen":"","def":"n. gryllus, the note of the cricket, to chirp: et gryllus gryllat, Auct. Carm. de Philom. 62. gryllus (also grillus), i, m., = γρύλλος. A cricket or grasshopper, Plin. 29, 6, 39, § 138.— Transf."},"gryllus":{"lemma":"Gryllus","pos":"","gen":"","def":", =Γρύλλος, a Greek proper name. A son of Xenophon, who fell in the battle at Mantinea, and was celebrated by Aristotle in a monogram entitled Γρύλλος, Quint. 2, 17, 14.— A Roman proper name, Mart. 1"},"gummus":{"lemma":"gummus","pos":"","gen":"","def":", = gummi, Gargil. Mart. de Pom. 16. gurdōnĭcus, a, um, adj. gurdus, doltish, stupid: homo, Sulp. Sev. Dial. 1, 26."},"gurdus":{"lemma":"gurdus","pos":"","gen":"","def":"Spanish, a dolt, jolterhead, numskull: gurdos, quos pro stolidis accipit vulgus, ex Hispania duxisse originem audivi, Quint. 1, 5, 57; cf.: gurdus lentus, inutilis, Gloss. Isid."},"gurges":{"lemma":"gurges","pos":"","gen":"","def":"v. gula"},"gusto":{"lemma":"gusto","pos":"v.","gen":"","def":"a. gustus, to taste, to take a little of any thing (freq. and class."},"gustum":{"lemma":"gustum","pos":"","gen":"","def":", v. gustus, I. 2. a."},"gustus":{"lemma":"gustus","pos":"","gen":"","def":"kindred with Sanscr. ǵush, to be fond of; Gr. γεύω, γεύομαι, γεῦσις, taste, a tasting of food, a partaking slightly or eating a little of any thing (mostly post-Aug.; not in Cic."},"gutta":{"lemma":"gutta","pos":"","gen":"-class","def":"sing. guttaiï, Lucr. 6, 614), f. etym. dub., a drop of a fluid (cf.: stilla, stiria). Lit.: numerus quem in cadentibus guttis, quod intervallis distinguitur, notare possumus, Cic. de Or. 3, 48"},"guttur":{"lemma":"guttur","pos":"","gen":"-class","def":"(ante-class.; also m. in acc. sing. gutturem, Plaut. Mil. 3, 2, 22; id. Aul. 2, 4, 25"},"gylippus":{"lemma":"Gylippus","pos":"","gen":"","def":", = Γύλιππος. An Arcadian, who came to Italia with Evander, Verg. A. 12, 272.— A famous Spartan general in the Peloponnesian war, Just. 4, 4; Tib. 4, 1, 199."},"gymnas":{"lemma":"gymnas","pos":"","gen":"","def":", = γυμνάς, wrestling, the exercise of wrestling (in post-Aug. poetry): Herculeā turpatus gymnade, Stat. Th. 4, 106; id. S. 4, 2, 47"},"gypso":{"lemma":"gypso","pos":"v.","gen":"","def":"a. id., to cover or coat with gypsum, to plaster: opercula, Col. 12, 39, 2: vas, id. ib. 43.—Poet.: gypsati pedes, the feet of a prisoner marked with gypsum"},"gypsoplastes":{"lemma":"gypsoplastes","pos":"","gen":"","def":", = γυψοπλάστης, a worker in gypsum or stucco, Cassiod. Varr. 7, 5."},"gypsum":{"lemma":"gypsum","pos":"","gen":"","def":", = γύψος, white lime plaster, gypsum. Lit., Plin. 36, 24, 59, § 182; 14, 19, 24, § 120; 20, 9, 39, § 98; Col. 12, 20, 8"},"gyrton":{"lemma":"Gyrton","pos":"","gen":"","def":", a town of Thessaly, between Pharsalia and Larissa, now the village Tatári, Liv. 36, 10; 42, 54; Plin. 4, 9, 16, § 32"},"habent":{"lemma":"habeo","pos":"","gen":"","def":"(form of habeo)"},"habet":{"lemma":"habeo","pos":"","gen":"","def":"(form of habeo)"},"habuit":{"lemma":"habeo","pos":"","gen":"","def":"(form of habeo)"},"hadrosphaerum":{"lemma":"hadrosphaerum","pos":"","gen":"","def":", = ἁδρόσφαιρον, a kind of spikenard with large leaves, Plin. 12, 12, 26, § 44. Hadrūmētum (Adrūm-), i, n. (also Hadrumetus, i, f., Mart. Cap. 6, § 670), = Ἁδρούμητος, a city of Africa propria"},"hae":{"lemma":"hae","pos":"","gen":"","def":"hic. Haedĭlĭa, ae, f., prob. a mountain near the Sabine villa of Horace, Hor. C. 1, 17, 9 (so the Codd.; Bentley conjectured haeduleae, from haedulea, a little kid"},"haec":{"lemma":"hic","pos":"","gen":"","def":"(form of hic)"},"haedui":{"lemma":"Haedui","pos":"","gen":"","def":"Aedui. haedŭlĕa, v. Haedilia. haedŭlus (hoed-), i, m. dim. haedus, a little kid: pinguissimus, Juv. 11, 66. haedus (less correctly hoedus, and archaic aedus or ēdus"},"haemon":{"lemma":"Haemon","pos":"","gen":"","def":", = Αἵμων, a son of Creon, king of Thebes, the lover of Antigone, Prop. 2, 8, 21; Ov. Tr. 2, 402; id. Ib. 563; Hyg. Fab. 72. Haemŏnĭa (Aemŏnia), ae, f., a poetical name of Thessaly, Ov. M. 1, 568"},"haemorrhousa":{"lemma":"haemorrhousa","pos":"","gen":"","def":", = αἱμορροῦσα, she that has a hemorrhage, eccl. (cf. Vulg. Matt. 9, 20). haemostăsis, is, f., = αἱμόστασις, a plant that stops the flow of blood, App. Herb. 59. Haemus (Aemus) or Haemos, i, m."},"haeres":{"lemma":"haeres","pos":"","gen":"","def":"heres."},"haeresco":{"lemma":"haeresco","pos":"","gen":"","def":"inch. n. , to stick, adhere (Lucretian): primordia in terris, Lucr. 2, 477; 4, 742. haerĕsĭarcha, ae, m., = αἱρεσιάρχης, a leader of a sect, heresiarch (eccl. Lat.), Sid. Ep. 7, 6"},"hahae":{"lemma":"hahae","pos":"","gen":"","def":"ha."},"halaesa":{"lemma":"Halaesa","pos":"","gen":"-laesus","def":"Halesa, etc. hălăgŏra, as, f. ἅλσ-ἀγορά, the saltmarket, Plaut. Poen. 5, 5, 34 dub. halapanta significat omnia mentientem, Paul. ex Fest. p. 101, 18 Müll. (perh. the same word as halophanta"},"hales":{"lemma":"Hales","pos":"","gen":"","def":", a small river in Lucania near Velia, now Halente, Cic. Fam. 7, 20, 1"},"hallex":{"lemma":"hallex","pos":"","gen":"","def":"allex. hallūcĭnor, āri, and its derivatives, v. aluc-."},"hallus":{"lemma":"hallus","pos":"","gen":"","def":"allus. halmyrĭdĭon, ii, n., = ἁλμυρίδιον (saltish), a kind of cabbage, Plin. 19, 8, 41, § 142."},"halmyrrhax":{"lemma":"halmyrrhax","pos":"","gen":"","def":", = ἁλμύρραξ, a kind of saltpetre, Plin. 31, 10, 46, § 106. hālo, āvi, ātum, 1, v. n. and a., to breathe (poet."},"halter":{"lemma":"halter","pos":"","gen":"-bells","def":", = ἁλτήρ, in gymnastics, leaden weights held in the hands in leaping exercises, to add to the impetus of the body, the dumb-bells of modern gymnastics, Mart. 14, 49, 1"},"halus":{"lemma":"Halus","pos":"","gen":"","def":", a small place in Assyria, near Artemita, only mentioned by Tac. A. 6, 41. halyaeĕtos, v. hali."},"halyattes":{"lemma":"Halyattes","pos":"","gen":"","def":"Alyattes. Hălys, yos, m., = Ἅλυς. A river in Asia Minor, flowing between Paphlagonia and Cappadocia, now Kisil-Irmak: secundum Halyn, Mel. 1, 19, 9; Plin. 6, 2, 2, § 6"},"hamae":{"lemma":"Hamae","pos":"","gen":"","def":", a place in Campania, near Cumoe, mentioned only by Liv. 23, 35, 3. hămarthrītis, is, f. ἅμα-ἀρθρῖτις, the general gout, Cael. Aur. Tard. 5, 2, 28. Hămartĭgĕnīa, ae, f., = Ἁμαρτιγένεια"},"hanc":{"lemma":"hic","pos":"","gen":"","def":"(form of hic)"},"hapsus":{"lemma":"hapsus","pos":"","gen":"","def":", = ἅψος (a binding together; hence), a lock of wool used in bandaging: lanae, Cels. 4, 6, 9; 7, 26, 5. hăra, ae, f., a pen or coop for animals: anserum, a goose-pen, Varr. R. R. 3, 10, 3 sq."},"harpa":{"lemma":"harpa","pos":"","gen":"","def":", = ἅρπη (a sickle, transf.), a harp (late Lat.), Ven. Carm. 7, 8, 63. harpactĭcon, false read. in Plin. 35, 15, 50, § 176"},"harpastum":{"lemma":"harpastum","pos":"","gen":"-ball","def":", = ἁρπαστόν, a hand-ball: sive harpasta manu pulverulenta rapis, Mart. 4, 19, 6; 7, 67, 4."},"harpax":{"lemma":"harpax","pos":"adj.","gen":"","def":", = ἅρπαξ, drawing to itself, rapacious.—Lit., of amber and brimstone: in Syria feminas verticillos inde (i. e. ex electro) facere et vocari harpaga, quia folia paleasque et vestium fimbrias rapiat"},"has":{"lemma":"hic","pos":"","gen":"","def":"(form of hic)"},"haustus":{"lemma":"haustus","pos":"","gen":"","def":"haurio, a drawing. Lit.: aqua, quae non sit haustus profundi, Col. 1, 5, 1: puteus in tenues plantas facili diffunditur haustu, Juv. 3, 227"},"haut":{"lemma":"haut","pos":"","gen":"","def":"haud. have and haveo, v. 2. aveo. Hĕautontīmōrūmĕnos, i, m., = Ἑαυτὸν τιμωρούμενος, The Self-tormentor, the title of a comedy of Terence, Ter. Heaut. prol. 5 (= Ipse se puniens, Cic. Tusc. 3, 27"},"hebria":{"lemma":"hebria","pos":"","gen":"-vessel","def":", a wine-vessel, Charis. p. 63 P. Hĕbrus, i, m., = Ἕβρος. The principal river in Thrace, which rises in Mount Hoemus, and flows into the Aegean Sea, now the Maritza, Mel. 2, 2, 2; 8; Verg. E. 10, 65"},"hector":{"lemma":"Hector","pos":"adj.","gen":"","def":"ap. Cic. Tusc. 2, 17, 39 = Trag. v. 25 Vahl.; id. ap. Varr. L. L. 10, § 70 Müll. = Trag. v. 130 Vahl.; acc. Hectorem, id. ap. Cic. Tusc. 1, 44, 105 = Trag. v. 129 Vahl."},"heia":{"lemma":"heia","pos":"interj.","gen":"","def":", v. eia."},"heic":{"lemma":"heic","pos":"adv.","gen":"","def":", v. hic, III. 2 init. Hēïus, i, m. (Ἥϊος), a Greek proper name, Cic. Verr. 2, 5, 18, 47 al. helcĭārĭus, ii, m. helcium, one who draws small vessels up the stream, Mart. 4, 64, 22"},"helcium":{"lemma":"helcium","pos":"","gen":"-collar","def":", = ἕλκιον, that with which a load is drawn, a yoke, horse-collar, App. M. 8, p. 222 and 227."},"helcysma":{"lemma":"helcysma","pos":"","gen":"-dross","def":", = ἕλκυσμα, the dross of molten silver, silver-dross, Plin. 33, 6, 35, § 105. Hĕlĕna, ae, or Hĕlĕnē, ēs, f., = Ἑλένη. Daughter of Jupiler and Leda, sister of Castor and Pollux and of Clytemnestra"},"helia":{"lemma":"Helia","pos":"","gen":"","def":"Velia. Hēlĭăcus, a, um, adj., = Ἡλιακός, relating to Helios (the sun): Heliaca tradere, to offer sacrifices to Helios, Inscr. Orell. 2343. Hēlĭădĕs, um, f., = Ἡλιάδες"},"hellas":{"lemma":"Hellas","pos":"","gen":"-land","def":", = Ἑλλάς. Hellas, the main-land of Greece, Mel. 2, 3, 3 sq."},"hellespontus":{"lemma":"Hellespontus","pos":"adj.","gen":"-lespont","def":", = Ἑλλήσποντος, the Sea of Helle, the Hellespont, so named after Helle, who was drowned in it, the modern Dardanelles, Mel. 1, 1, 5; 1, 3, 1; Plin. 4, 11, 18, § 49; 4, 12, 24, § 75; 4, 13, 27, § 92"},"hellusii":{"lemma":"Hellusii","pos":"","gen":"","def":", a German tribe, mentioned only by Tac. G. 46. hĕlops (also ĕlops and ellops), ŏpis, m., = ἔλλοψ, a very savory sea-fish, perh. the sword-fish"},"helus":{"lemma":"helus","pos":"","gen":"","def":"holus init. helvacea genus ornamenti Lydii, dictum a colore boum, qui est inter rufum et album appellaturque helvus, Paul. ex Fest. p. 99 Müll. N. cr. Helvecōnes, um, m., a northern Germanic tribe"},"heluus":{"lemma":"helvus","pos":"adj.","gen":"","def":"perh. a weakened form of gilvus, yellow, light bay: color vaccarum, Varr. R. R. 2, 5, 9"},"hemo":{"lemma":"hemo","pos":"","gen":"","def":"homo init. hendĕcăsyllăbi, ōrum, m., = ἑνδεκασύλλαβοι, verses of eleven syllables, Cat. 12, 10; Plin. Ep. 4, 14, 8; 7, 4, 1"},"henna":{"lemma":"Henna","pos":"adj.","gen":"-nenses","def":", = Ἕννα, a city of great antiquity in the centre of Sicily, with a famous temple of Ceres: it was from here that Pluto carried off Proserpine; now Castro Giovanni, Mel. 2, 7, 16"},"heptas":{"lemma":"heptas","pos":"","gen":"","def":", = ἑπτάς, the number seven, Mart. Cap. 2, § 108; 7, § 738 (in Macr. Somn. Scip. 1, 6, written as Greek). heptăsēmos, on, adj., = ἑπτάσημος"},"herbans":{"lemma":"herbans","pos":"adj.","gen":"","def":"herba, producing grass or herbage, full of grass: prata, App. M. 7, p. 194 Oud. N. cr. (al. herbentia). herbārĭa, ae, f. (sc. ars) , the knowledge of plants"},"herbens":{"lemma":"herbens","pos":"","gen":"","def":"herbans."},"herbesco":{"lemma":"herbesco","pos":"","gen":"","def":"inch. n. , to grow into green stalks or blades: elicere herbescentem viriditatem, Cic. de Sen. 15, 51: campi semper herbescunt, Amm. 31, 2, 19. Herbessus (Herbēsus), i, f., a town of Sicily, Liv. 24"},"herbo":{"lemma":"herbo","pos":"","gen":"","def":"herbans. herbōsus, a, um, adj. id.. Full of grass or herbs, grassy: campus, Hor. C. 3, 18, 9: Palatia, Tib. 2, 5, 25: Apidanus, Prop. 1, 3, 6: flumen, Verg. G. 2, 199: pascua, Ov. M. 2, 689: moretum"},"hercle":{"lemma":"hercle","pos":"","gen":"","def":"Hercules, I. B. herctum or erctum, i, n. HORCTUM et FORCTUM pro bono dicebant, Paul. ex Fest. p. 102 Müll.; perh. kindr. with heres. In the old jurid. lang., an inheritance, estate, patrimony"},"hermaeum":{"lemma":"Hermaeum","pos":"","gen":"","def":"Hermes, II. Hermăgŏras and Hermăgŏra (the latter is the Ciceron. form acc. to Quint. 1, 5, 61), ae, m., = Ἑρμαγόρας. A celebrated Greek rhetorician of Rhodes, Cic. Brut. 78, 271; id. Inv. 1, 6, 8"},"hermarchus":{"lemma":"Hermarchus","pos":"","gen":"","def":"Of Mitylene, a disciple of Epicurus, Cic. Fin. 2, 30, 96; id. N. D. 1, 33, 93"},"hermippus":{"lemma":"Hermippus","pos":"","gen":"","def":", = Ἕρμιππος, a Greek proper name, Cic. Fl. 19 sq.; id. Q. Fr. 1, 2, 2, § 4 al. Hermŏdōrus, i, m. An Ephesian prince, Cic. Tusc. 5, 36, 105"},"hermus":{"lemma":"Hermus","pos":"","gen":"","def":", = Ἕρμος, an auriferous river in Aeolis, now Sarabat, Mel. 1, 17, 3; Plin. 5, 29, 31, § 119; Verg. G. 2, 137"},"herpes":{"lemma":"herpes","pos":"","gen":"","def":", = ἕρπης. A cutaneous eruption that creeps and spreads, Plin. 26, 14, 87, § 145"},"herpyllum":{"lemma":"herpyllum","pos":"","gen":"","def":", = ἕρπυλλον, a climbing evergreen plant, also called sisymbrium, creeping thyme, App. Herb. 105"},"hertha":{"lemma":"Hertha","pos":"","gen":"","def":"Nerthus. Hĕrŭli (Erŭli), ōrum, m., the Herulians, the people of Northern Germany who penetrated into Italy and dissolved the western Roman Empire, Amm. 23, 1, 3; Paul. Diac. Longob. 1, 1"},"heruum":{"lemma":"hervum","pos":"","gen":"","def":", v. ervum. Hēsĭŏdus, i, m., = Ἡσίοδος, the Greek poet Hesiod, Gell. 3, 11; 17, 21, 3; Vell. 1, 7, 1; Quint. 10, 1, 52; 5, 11, 19; Cic. N. D. 1, 14, 36"},"hesternus":{"lemma":"hesternus","pos":"adj.","gen":"","def":"hes, whence heri, analog. with hodiernus, of yesterday, yesterday's: disputatio hesterni et hodierni diei, Cic. de Or. 3, 21, 81"},"hesus":{"lemma":"Hesus","pos":"","gen":"","def":", v. Esus. hĕtaerĭa, ae, f., = ἑταιρία, a (religious) brotherhood, fraternity, Traj. ap. Plin. Ep. 10, 43, 1"},"hexas":{"lemma":"hexas","pos":"","gen":"","def":", = ἑξάς, the number six, Mart. Cap. 2, § 108 al. hexastĭchus, a, um, adj., = ἑξάστιχος, of six lines or rows: hordeum, perh. our long-eared barley, Hordeum caeleste, Linn."},"hexastylos":{"lemma":"hexastylos","pos":"adj.","gen":"","def":", = ἑξάστυλος, having six columns, Vitr. 3, 2, 7. hexēcontălĭthos, i, m., = ἑξηκοντάλιθος (sixty-colored stone), a precious stone, otherwise unknown, Plin. 37, 10, 60, § 167"},"hice":{"lemma":"hice","pos":"","gen":"","def":"hic, I. B. Hĭcĕtāon, ŏnis, m., = Ἱκετάων, son of Laomedon king of Troy, App. de Deo Socr. p. 152, 9.—Hence, Hĭcĕtāŏnĭus, a um, of Hicetāon: Thymoetes, i. e. his son, Verg. A. 10, 123. Hĭcĕtas, ae, m."},"hicine":{"lemma":"hicine","pos":"","gen":"","def":"hic, I. B."},"hillae":{"lemma":"hillae","pos":"part.","gen":"","def":"dim. hira, the smaller and anterior intestines of animals (other than men and sheep). Lit.: ab hoc ventriculo lactes in homine et ove, per quas labitur cibus, in ceteris hillae"},"hinc":{"lemma":"hinc","pos":"adv.","gen":"","def":"for hince, locative form from hic, from this place. hence. In space: Imus huc: illuc hinc: cum illuc ventum est, ire illinc lubet, Enn. ap. Gell. 19, 10"},"hinna":{"lemma":"hinna","pos":"","gen":"","def":"hinnus, I. hinnībĭlis, e, adj. hinnio, that neighs, neighing (post-class.): quod hinnibile est, equus est, App. Dogm. Plat. 3, p. 30: exscreatus, Cael. Aur. Tard. 5, 10, 119. hinnĭbundus, a, um"},"hinnus":{"lemma":"hinnus","pos":"","gen":"-ass","def":", = ἵννος, a mule (from a stallion and a she-ass"},"hipparchus":{"lemma":"Hipparchus","pos":"","gen":"","def":", = Ἵππαρχος. A son of Pisistratus tyrant of Athens, and brother of Hippias, killed by Harmodius and Aristogiton, Gell. 17, 21, 7.— A celebrated astronomer of Nicoea, Cic. Att. 2, 6, 1"},"hippias":{"lemma":"Hippias","pos":"","gen":"","def":", = Ἱππίας. A son of Pisistratus tyrant of Athens, and brother of Hipparchus, after whose assassination he fled to the Persians; he fell in the battle of Marathon, Cic. Att. 9, 10, 3"},"hippius":{"lemma":"Hippius","pos":"","gen":"","def":", a Roman proper name, Cic. Fam. 13, 76. ‡ Hippius, id est equester, Neptunus dictus est, etc., Paul. ex Fest. p. 101 Müll. ."},"hippo":{"lemma":"Hippo","pos":"adj.","gen":"","def":", = Ἱππών, the name of several cities. A city of Numidia, also with the surname of regius, Gr. Ἱππὼν βασιλικός, afterwards a bishop's see, now Bonah, Mel. 1, 7, 1; Liv. 29, 3, 7"},"hippus":{"lemma":"hippus","pos":"","gen":"-fish","def":", = ἵππος, a sea-fish, otherwise unknown, Plin. 32, 11, 53, § 149. hir or ir, indecl. n. from χείρ, like heres from χῆρος, and hiems from χεῖμα, χειμών, a hand: quibu' vinum Defusum e pleno siet"},"hirco":{"lemma":"hirco","pos":"v.","gen":"","def":"n., to howl, of the sound of the lynx, Auct. Carm. de Philom. 51. hircōsus, a, um, adj. hircus, that smells like a goat, goatish: senex, Plaut. Merc. 3, 3, 14: gens centurionum, Pers. 3, 77: subulcus"},"hirpex":{"lemma":"hirpex","pos":"","gen":"","def":"irpex."},"hirpi":{"lemma":"Hirpi","pos":"","gen":"","def":", a very ancient Sabine family near Rome, in the territory of the Falisci, Plin. 7, 2, 2, § 19"},"hirquitallus":{"lemma":"hirquitallus","pos":"","gen":"","def":"the preced. art."},"hirquus":{"lemma":"hirquus","pos":"","gen":"","def":"hircus. hirrĭo (irrio), īre, v. n., of dogs, to snarl: hirrire = garrire, quod genus vocis est canis rabiosae, Paul. ex Fest. p. 101 Müll. N. cr."},"hirtus":{"lemma":"hirtus","pos":"adj.","gen":"","def":", rough, hairy, shaggy, = δασύς (mostly post-Aug."},"his":{"lemma":"hic","pos":"","gen":"","def":"(form of hic)"},"hisco":{"lemma":"hisco","pos":"","gen":"","def":"inch. n. and a. . Neutr., to open, gape, yawn. In gen.: tellus, ait, hisce, Ov. M. 1, 546"},"hispellum":{"lemma":"Hispellum","pos":"","gen":"","def":", a city of Umbria, at the foot of the Apennines, now Spello, Plin. 3, 14, 19, § 113; Sil. 8, 458"},"hispo":{"lemma":"Hispo","pos":"","gen":"","def":", a Roman surname, Cic. Fam. 13, 65; 14, 1; Juv. 2, 50."},"hispulla":{"lemma":"Hispulla","pos":"","gen":"","def":", the name of a woman, Juv. 6, 74; 12, 11; Plin. Ep. 4, 19 tit."},"hister":{"lemma":"Hister","pos":"adv.","gen":"","def":", = Ἴστρος, the lower part of the Danube (the upper part, Danubius). Prop. In gen.: Ponticum simul et Hadriaticum mare et Histrum amnem et Alpes conspici posse, Liv. 40"},"histon":{"lemma":"histon","pos":"","gen":"-room","def":", = ἱστών, the place where a loom stands, a weaving-room: habere institutos histonas, Varr. R. R. 1, 2, 21. histŏrĭa, ae, f., = ἱστορία, a narrative of past events, history (syn.: annales"},"histrio":{"lemma":"histrio","pos":"","gen":"-player","def":"Etrusc. prim. form HISTER, Liv. 7, 2, 6; Val. Max. 2, 4, 4"},"histrix":{"lemma":"histrix","pos":"","gen":"","def":"hystrix. hĭulcē, adv., v. hiulcus fin. hĭulco, no perf., ātum, 1, v. a. hiulcus, to cause to gape or split open, to break into chinks: cum gravis exustos aestus hiulcat agros, Cat. 68"},"hoc":{"lemma":"hoc","pos":"adv.","gen":"","def":", v. huc. hŏdĭē, adv. contr. from hoc die, on this day, to-day. Lit.: quem quidem negat Eros hodie: cras mane putat, Cic. Att. 13, 30, 2; so opp. cras, Ov. R. Am. 94"},"hoedus":{"lemma":"hoedus","pos":"","gen":"","def":", v. haed. holcē, ēs, f., = ὁλκή, a drachma: holceque a drachma non re sed nomine differt, Fann. de Pond. 19."},"holcus":{"lemma":"holcus","pos":"","gen":"","def":", = όλκός, a sort of grain, mouse - barley, Hordeum murinum, Linn."},"holusatrum":{"lemma":"holusatrum","pos":"","gen":"","def":"1. holus, II. hŏluscŭlum, i, n. dim. holus, a small herb or vegetable, a little cabbage (class.), Cic. Att. 6, 1, 13; Hor. S. 2, 6, 64; Juv. 11, 79"},"horconia":{"lemma":"horconia","pos":"","gen":"","def":", a sort of wine in Campania, Plin. 14, 2, 4, § 35. horctum et forctum pro bono dicebant, Paul. ex Fest. p. 102 Müll.: cf. fortis init."},"horda":{"lemma":"horda","pos":"","gen":"","def":", archaic i. q. forda, a cow that is with calf: quae sterilis est vacca, taura appellata"},"hordicidia":{"lemma":"hordicidia","pos":"","gen":"","def":"‡ fordicidia."},"hordus":{"lemma":"hordus","pos":"","gen":"","def":"fordus."},"horesti":{"lemma":"Horesti","pos":"","gen":"","def":", a tribe in North Britain, in the modern Stirling, or the north part of Lanark, Tac. Agr. 38 (al. Boresti). hŏrĭa (oria), ae, f., a small vessel, a fishing-smack (cf.: celox, catascopium, prosumia"},"horno":{"lemma":"horno","pos":"adv.","gen":"","def":", v. hornus fin. hornōtĭnus, a, um, adj. hornus, of this year, this year's: nuces, Cato, R. R. 17, 2: frumentum, Cic. Verr. 2, 3, 18, § 45: virgae, Col. 5, 6 fin. hornus, a, um"},"horresco":{"lemma":"horresco","pos":"","gen":"","def":"inch. n. and a. , to rise on end, stand erect, to bristle up, grow rough. Lit. (mostly poet."},"horror":{"lemma":"horror","pos":"","gen":"-fit","def":"horreo, a standing on end, standing erect, bristling. Lit. (only poet. and very rare): comarum, Luc. 5, 154; Val. Fl. 1, 229: pontus non horrore tremit, i. e. was not ruffled, agitated, Luc. 5, 446"},"horsum":{"lemma":"horsum","pos":"adv.","gen":"-class","def":"contr. from hoc = huc and vorsum, hitherwards, hither, this way (ante-class.): pergunt, Ter. Hec. 3, 4, 36: horsum se capessit, Plaut. Rud. 1, 2, 83"},"hortensis":{"lemma":"hortensis","pos":"adj.","gen":"","def":"hortus, of or belonging to a garden, garden-: lira, Col. 9, 4, 4: DII, Inscr. Orell. 1626: IOVIS, Inscr. ap. Marin. Fratr. Arv. p. 390. hortensĭus, a, um, adj. id., of or belonging to a garden"},"hortor":{"lemma":"hortor","pos":"v.","gen":"-clause","def":"pres. hortarier, Plaut. Merc. 4, 2, 5), v. dep. for horitor, v. horior, to urge one strongly to do a thing, to incite, instigate, encourage, cheer, exhort (freq. and class."},"hortus":{"lemma":"hortus","pos":"","gen":"-hors","def":"cf.: heres, co-hors; χόρτος, an enclosure for plants"},"hos":{"lemma":"hic","pos":"","gen":"","def":"(form of hic)"},"hostio":{"lemma":"hostio","pos":"v.","gen":"-class","def":"a., to make even, return like for like, to recompense, requite: hostire (ab antiquis) ponebatur pro aequare. Fest. s. v. status dies, p. 314 Müll."},"hostus":{"lemma":"hostus","pos":"","gen":"-tree","def":"perh. a rustic term for haustus, the yield of an olive-tree, Cato, R. R. 6, 2; Varr. R. R. 1, 24, 2."},"hucusque":{"lemma":"hucusque","pos":"adv.","gen":"","def":", v. huc, I. D. and II. D."},"hui":{"lemma":"hui","pos":"interj.","gen":"","def":", an exclamation of astonishment or admiration, hah! ho! oh! hui, homunculi quanti estis, Plaut. Rud. 1, 2, 65: hui, dixti pulchre! Ter. Phorm. 2, 1, 72: triginta? hui, percara est! id. ib. 3, 3"},"huic":{"lemma":"hic","pos":"","gen":"","def":"(form of hic)"},"huius":{"lemma":"hic","pos":"","gen":"","def":"(form of hic)"},"hulcus":{"lemma":"hulcus","pos":"","gen":"","def":"ulcus. hūmānātus, a, um, v. humano. hūmānē, adv., v. humanus fin. hūmānĭtas, ātis, f. humanus, human nature, humanity, in a good sense"},"hunc":{"lemma":"hic","pos":"","gen":"","def":"(form of hic)"},"hyaena":{"lemma":"hyaena","pos":"","gen":"","def":", = ὕαινα, a hyena, Plin. 8, 30, 44, § 105"},"hyantes":{"lemma":"Hyantes","pos":"adj.","gen":"-t","def":", = Ὕαντες, the Hyantes, an old name of the Boeotians, Plin. 4, 7, 12, § 26.— Derivv. Hyan-tēus, a, um, adj., of or belonging to the Hyantes (Boeotians), Hyantean, Boeotian: Iolāus, Ov. M. 8"},"hyas":{"lemma":"Hyas","pos":"","gen":"","def":", v. Hyades. Hybla, ae, and Hyblē, ēs, f., =Ὕβλη, a mountain of Sicily abounding in flowers and bees, with a city of the same name, Plin. 11, 13, 13, § 32; Verg. E. 7, 37; Ov. Tr. 5, 13, 22"},"hybrida":{"lemma":"hybrida","pos":"","gen":"","def":"hibrida."},"hydaspes":{"lemma":"Hydaspes","pos":"adj.","gen":"","def":", = Ὑδάσπης. A river of India, a tributary of the Indus, now Jeloum, Mel. 3, 7, 6; Plin. 6, 20, 23, § 71; Curt. 4, 5, 3; 8, 12, 8; Verg. G. 4, 211; Hor. C. 1, 22, 8"},"hydrargyrus":{"lemma":"hydrargyrus","pos":"","gen":"","def":", = ὑδράργυρος, quicksilver artificially prepared, Plin. 33, 8, 41, § 123; 33, 3, 20, § 64."},"hydraula":{"lemma":"hydraula","pos":"","gen":"-am","def":", = ὑδραύλης, one who plays on the waterorgan, Suet. Ner. 54; Petr. 36"},"hydraulus":{"lemma":"hydraulus","pos":"","gen":"-organ","def":", = ὕδραυλος, a water-organ, Cic. Tusc. 3, 18, 43"},"hydreuma":{"lemma":"hydreuma","pos":"","gen":"-place","def":", = ὕδρευμα, a resting-place for caravans, where they get water, a watering - place, Plin. 6, 23, 26, § 103 (al. hydreum). hydrĕus, a, um, adj. hydrus, of or belonging to the water - serpent: germen"},"hydrops":{"lemma":"hydrops","pos":"","gen":"","def":", = ὕδρωψ, the dropsy, Cels. 3, 21; Hor. C. 2, 2, 13"},"hydruntum":{"lemma":"Hydruntum","pos":"","gen":"","def":"2. Hydrus. hydrus or -os, i, m., = ὕδρος, a water-serpent, serpent (cf.: chelydrus, chersydrus, anguis, serpens). Lit., Plin. 29, 4, 22, § 72; Verg. G. 4, 458; id. A. 7, 753"},"hyes":{"lemma":"Hyes","pos":"","gen":"","def":", = Ὕης, one of the first three Dioscuri, Cic. N. D. 3, 21, 53 (acc. to Lobeck's conject.)."},"hyettus":{"lemma":"Hyettus","pos":"","gen":"","def":", = Ὑηττός, a city of Boeotia, north of lake Copais, near the modern Strobiki, Plin. 36, 16, 25, § 128. Hygēa or Hygīa (Hygĭeia), ae, f., = Ὑγεία, daughter of Aesculapius, and goddess of health"},"hygra":{"lemma":"hygra","pos":"","gen":"-salve","def":", = ὑγρά (liquid), a kind of eye-salve, Scrib. Comp. 37."},"hygremplastrum":{"lemma":"hygremplastrum","pos":"","gen":"","def":", = ὑγρέμπλαστρον, a wet plaster, Plin. 34, 15, 46, § 155. hygrŏphŏbĭa, ae, f., = ὑγροφοβία, a dread of liquids, as water, wine, etc., Cael. Aur. Acut. 3, 9, 98."},"hylactor":{"lemma":"Hylactor","pos":"","gen":"","def":", name of a hound of Actoeon, Ov. M. 3, 224; Hyg. Fab. 181. Hȳlaeus, i, m., = Ὑλαῖος (v. Chandler, Gr. Accent. § 239). A centaur who offered violence to Atalanta, Ov. A. A. 2, 191"},"hylas":{"lemma":"Hylas","pos":"","gen":"","def":", = Ὕλας, a beautiful youth of Oechalia (or Argos), companion of Hercules in the Argonautic expedition, who was carried off by the nymphs, and long sought for by Hercules in vain, Prop. 1, 20, 6"},"hymnio":{"lemma":"hymnio","pos":"v.","gen":"-class","def":"a. hymnus, to sing hymns (post-class.): hymnite matres pro receptis parvulis, Prud. στεφ. 1, 118."},"hymnis":{"lemma":"Hymnis","pos":"","gen":"","def":", a comedy of Coecilius Statius, Cic. Fin. 2, 7, 22. hymnĭsŏnus, a, um, adj. hymnussonus, singing hymns, singing praises (post-class.): chori, Paul. Nol. Carm. 28, 230; 22, 200"},"hymnus":{"lemma":"hymnus","pos":"","gen":"","def":", = ὕμνος, a song of praise, a hymn: hymnus cantus est cum laude Dei, Aug. Enarr. in Psa. 148, 17; Ambros. Expos. Psa. 118, prol. § 3; Lucil. ap. Non. 330, 9; Prud. Cath. 37 praef."},"hyophthalmos":{"lemma":"hyophthalmos","pos":"","gen":"","def":", = ὑόφθαλμος (swine's eye), a plant, called also Aster Atticus, App. Herb. 60. hyoscyămĭnus, a, um, adj., =ὑοσκυάμινος, made of henbane, henbane-: oleum, Plin. 23, 4, 49, § 94. hyoscyămus, i, m."},"hypaepa":{"lemma":"Hypaepa","pos":"","gen":"-paep","def":", = Ὕπαιπα, a small town in Lydia, now Beréki, Ov. M. 6, 13; 11, 152; Petr. 133.—Hence, Hy-paepēni, ōrum, m., its inhabitants, Plin. 5, 29, 31, § 120"},"hyperthyrum":{"lemma":"hyperthyrum","pos":"","gen":"-way","def":", = ὑπέρθυρον, the lintel of a door-way, Vitr. 4, 6 dub. (al. hypothyrum). Hyphăsis, v. Hypasis. hyphĕar, ăris, n., = ὕφεαρ, the mistletoe, Plin. 16, 44, 93, § 245 sq."},"hypoglossa":{"lemma":"hypoglossa","pos":"","gen":"","def":", = ὑπόγλωσσον, a kind of butcher's broom or ruscus: Ruscus hypoglossum, Linn."},"hypotrimma":{"lemma":"hypotrimma","pos":"","gen":"","def":", = ὑπότριμμα, a sauce made of all sorts of condiments, Apic. 1, 33, § 34."},"hypsa":{"lemma":"Hypsa","pos":"","gen":"","def":", a river in Sicily, now Belici, Plin. 3, 8, 14, § 90; Sil. 14, 228."},"hypsaeus":{"lemma":"Hypsaeus","pos":"","gen":"","def":", a surname of P. Plautius, Cic. Att. 3, 8, 3. Hypseus (dissyll.), ei, m., one who was present at the nuptials of Perseus, Ov. M. 5, 98. Hypsicrătes, is, m., a grammarian, Gell. 16, 12. Hypsĭpylē, ēs"},"hystaspes":{"lemma":"Hystaspes","pos":"","gen":"","def":", = Ὑστάσπης, father of the Persian king Darius I., Plin. 6, 27, 31, § 133; Just. 1, 10, 6; Nep. Milt. 3; Reg. 1. hystĕrĭcus, a, um, adj., = ὑστερικός, hysterical, Mart. 11, 71, 1"},"iacchus":{"lemma":"Iacchus","pos":"","gen":"","def":", = Ἴακχος. A poetic and mystical appellation of Bacchus, Verg. E. 7, 61; id. G. 1, 166; Cic. Leg. 2, 14, 34; Cat. 64, 251"},"iacea":{"lemma":"jacea","pos":"","gen":"-rack","def":", a wooden hay-rack: cratis, quae jacea vocatur a vulgo, Veg. Vet. 1, 56, 5 (dub. al jacca). jăcĕo, cŭi, cĭtum (fut. part. jaci-turus, Stat. Th. 7, 777), 2, v. n. intr. of jacio"},"iactanter":{"lemma":"jactanter","pos":"adv.","gen":"","def":", v. jacto fin. jactantĭa, ae, f. jacto, a boasting, bragging; display, ostentation (post-Aug.): sui, Tac. A. 2, 46: militaris, id. Agr. 25: frivola in parvis, Quint. 1, 6, 20"},"iactus":{"lemma":"jactus","pos":"","gen":"-throw","def":"jacio, a throwing, casting, hurling; a throw, cast. Lit. In gen.: jactus fulminum, Cic. Cat. 3, 8, 18"},"iaera":{"lemma":"Iaera","pos":"","gen":"-nymph","def":", = Ἴαιρα, the name of a sea-nymph or Nereid, Hom. Il. 18, 42; but Lat. only as the name of an Oread or woodnymph: sylvestris, Verg. A. 9, 673"},"iam":{"lemma":"jam","pos":"adv.","gen":"-dem","def":"for diam, collat. form of diem, cf. pri-dem, du-dum, Corss. Ausspr. I. p. 213; II. p. 850; but acc. to Georg Curtius Gr. Etym. 398, 620"},"iana":{"lemma":"Jana","pos":"adv.","gen":"-goddess","def":", for Diana, the moon-goddess, Varr. R. R. 1, 37, 3; Macr. S. 1, 9"},"iarartes":{"lemma":"Iarartes","pos":"","gen":"","def":", = Ἰαξάρτης, a river of Central Asia, now Syr-Daria (i. e. Yellow River), Mel. 3, 5, 6"},"iarba":{"lemma":"Iarba","pos":"","gen":"-ta","def":", a king of Mauritania, Ov. F. 3, 552 sq.; Verg. A. 4, 36; Juv. 5, 45.—Hence, Iarbī-ta, ae, m., a Mauritanian, Hor. Ep. 1, 19, 15"},"iaxartes":{"lemma":"Jaxartes","pos":"","gen":"","def":", a river of Sogdiana, now Sir or Sihoon, Mel. 3, 5, 6"},"iber":{"lemma":"Iber","pos":"","gen":"","def":"Hiberes. Ibēres, v. Hiberes. ĭbēris, idis, f., = ἰβηρίς, a kind of cress, Plin. 25, 8, 49, § 87"},"ibus":{"lemma":"ibus","pos":"","gen":"","def":"is init. Ībycus, i, m., = Ἴβυκος. A Greek lyric poet of Rhegium, celebrated on account of the cranes which he called upon as witnesses of his murder, Cic. Tusc. 4, 33, 71; Stat. S. 5, 3, 152"},"iccirco":{"lemma":"iccirco","pos":"","gen":"","def":"idcirco. Iccĭus, ĭi, m., a Roman proper name, Cic. Phil. 3, 10. 26"},"ichneumon":{"lemma":"ichneumon","pos":"","gen":"-fly","def":", = ἰχνεύμων. An animal which tracks the crocodile and destroys its eggs; the Egyptian rat or ichneumon, Plin. 8, 24, 35, § 88; 8, 25, 37, § 90 sq.; Cic. N. D. 1, 36, 101; Mart. 7, 87, 5"},"ictis":{"lemma":"ictis","pos":"","gen":"","def":", = ἴκτις, a kind of weasel, Plin. 29, 4, 16, § 50: nunc ictim tenes, Plaut. Capt. 1, 2, 81. ictus, a, um, Part., from ico."},"ictus":{"lemma":"ictus","pos":"part.","gen":"","def":"sing. icti, Quadrig. ap. Gell. 9, 13, 17), m. ico, a blow, stroke, stab, thrust, bite, sting (freq. and class.). Lit. In gen.: a bestiis ictus, morsus, impetus, Cic. Off. 2, 6"},"idmon":{"lemma":"Idmon","pos":"adj.","gen":"","def":", = Ἴδμων. The father of Arachne, a native of Colophon, Ov. M. 6, 8.— Deriv.: Idmŏnĭus, a, um, adj., of or related to Idmon, Idmonian: Arachne, Ov. M. 6, 133.— A prophet in Argos"},"iento":{"lemma":"jento","pos":"v.","gen":"","def":"n. contr. for jejunito from jejunus, to breakfast: quod pulli jentent, Varr. ap. Non. 126, 14; Afran. ib."},"ignem":{"lemma":"ignis","pos":"n. m.","gen":"-is","def":"fire, flame; a firebrand; ardour, passion; lightning","form_of":"ignis"},"ignesco":{"lemma":"ignesco","pos":"","gen":"","def":"inch. n. (in pass. ignescitur, Laber. ap. Non. 481, 7"},"igni":{"lemma":"ignis","pos":"n. m.","gen":"-is","def":"fire, flame; a firebrand; ardour, passion; lightning","form_of":"ignis"},"ignis":{"lemma":"ignis","pos":"n. m.","gen":"-is","def":"fire, flame; a firebrand; ardour, passion; lightning"},"iis":{"lemma":"is","pos":"pron.","gen":"-class","def":"eis, C. I. L. 1, 198; n. it, ib. 5, 875 al., and freq. in MSS. of Plaut.), gen. ējus (old form eiius, C. I. L. 3, 1365 et saep.; v. Prisc. 1, 4, 18, p. 545; also etius, ib. 2, 1276 al.","form_of":"is"},"ilerda":{"lemma":"Ilerda","pos":"","gen":"","def":", a city in Hispania Tarraconensis, on the Sicoris, now Lerida, Caes. B. C. 1, 41 sq.; Hor. Ep. 1, 20, 13; Luc. 4, 144"},"iliberi":{"lemma":"Iliberi","pos":"","gen":"","def":"Illiberi. īlĭcet, adv. i, root of īre, and licet; cf. scilicet and videlicet; lit., one may go"},"ilios":{"lemma":"Ilios","pos":"","gen":"","def":", v. Ilium. īlĭōsus, i, m. 1. ilia, one who suffers with the colic, Plin. 20, 4, 13, § 26."},"ilipa":{"lemma":"Ilipa","pos":"","gen":"","def":", a city of Hispania Boetica, upon the right bank of the Boetis (Guadalquiver), its ruins near Peñaflor, Plin. 3, 1, 3, § 11"},"ilium":{"lemma":"ilium","pos":"","gen":"","def":"ile."},"ilius":{"lemma":"Ilius","pos":"","gen":"","def":"Ilium, II. A."},"illa":{"lemma":"illa","pos":"adv.","gen":"","def":", v. ille fin. illăbĕfactus (inl-), a, um, adj. in-labefactus, unshaken, unbroken, unimpaired (poet.): vincula, Ov. P. 4, 8, 10: concordia, id. ib. 4, 12, 30. illābor (inl-), psus, 3, v. dep. n."},"illac":{"lemma":"illac","pos":"adv.","gen":"","def":", v. 1. illic fin. illăcĕrābĭlis (inl-), e, adj. in-lacerabilis, that cannot be torn: spolium, Sil. 5, 138. illăcessītus (inl-), a, um, adj. inlacessitus, unprovoked"},"illautus":{"lemma":"illautus","pos":"","gen":"","def":"illotus. ille (old orthog., olle), a, ud (ollus, a, um, Enn. ap. Varr. L. L. 7, § 42 Müll.; Verg. A. 5, 197"},"illi":{"lemma":"illi","pos":"adv.","gen":"","def":", v. 2. illic init. illībābĭlis (inl-), e, adj. in-libo, incapable of diminution: sapientia, Lact. 2, 7, 33. illībātus (inl-), a, um, adj. in-libo, undiminished, unimpaired, uninjured"},"illicine":{"lemma":"illicine","pos":"","gen":"","def":"1. illic, I. B. illĭcĭo (inl-), lexi, lectum, 3 (inf. perf. sync. illexe, Att. ap. Cic. N. D. 3, 27, 68; Fragm. Trag. v. 205 Rib."},"illico":{"lemma":"illico","pos":"","gen":"","def":"ilico. illīdo (inl-), si, sum, 3, v. a. in-laedo, to strike or dash against or upon, to beat against, to strike, dash or beat in any direction. Lit. (mostly poet., not in Cic. prose"},"illim":{"lemma":"illim","pos":"adv.","gen":"","def":", v. ille fin. 3. illīmātus (inl-), a, um, adj. in-limus, fastened or attached by means of rich earth: frondes, Col. 9, 7, 4 Schneid. N. cr. illīmis (inl-), e, adj. id., without mud or slime: fons"},"illinc":{"lemma":"illinc","pos":"adv.","gen":"-ce","def":"for illim-ce, from that place, thence. Lit.: jube illos illinc abscedere, Plaut. Most. 2, 2, 36: illinc venire, id. Men. 2, 3, 61: se illinc subducet, Ter. Eun. 4, 1"},"illix":{"lemma":"illix","pos":"","gen":"","def":"2. illex."},"illo":{"lemma":"illo","pos":"adv.","gen":"","def":", v. ille fin. illoc. Neutr. pron., v. illic.— Adv., v. illic fin. illŏcābĭlis (inl-), e, adj. in-loco, that cannot (on account of her poverty) be disposed of in marriage: virginem habeo grandem"},"illuc":{"lemma":"illuc","pos":"adv.","gen":"","def":", v. 1. illic, II. B. illūcĕo (inl-), ēre, v. n. in-luceo, to shine in or on, to light up, illuminate, give light (very rare): pix atra tuo capiti illuceat, Plaut. Capt. 3, 4"},"illuo":{"lemma":"illuo","pos":"","gen":"","def":"3, 5, 10, § 74, and Dig. 10, 2, 16, § 3."},"illurgauonenses":{"lemma":"Illurgavonenses","pos":"","gen":"","def":"Ilergavonenses. Illŭrĭcus, adj., and Illŭrĭi, orum, v. Illyr. illūsĭo (inl-), ōnis, f. illudo, a mocking, jeering; irony, a figure of speech, = derisio, insultatio, Cic. de Or. 3, 53, 202"},"ilua":{"lemma":"Ilva","pos":"","gen":"","def":", the modern Island of Elba, in the Mediterranean Sea, Mel. 2, 7, 19; Plin 3, 6, 12, § 81; 34, 14, 41, § 142; Liv. 30, 39, 2, Verg. A. 10, 173"},"iluro":{"lemma":"Iluro","pos":"","gen":"","def":", a town in Hispania Tarraconensis, the modern Maltaeo, Plin. 3, 3, 4, § 22.—Hence, Ilurensis, is, m., an inhabitant of Iluro, Inscr. Grut. 406, 9. Īlus, i, m., = Ἶλος. A son of Tros"},"im":{"lemma":"im","pos":"","gen":"","def":"q. eum, v. is init. Imăchărensis or Imăcărensis, e, adj., of Imachăra, a city in the northeastern part of Sicily, now perh. Traina: Leontes, Cic. Verr. 2, 5, 7, § 15: ager, id. ib. 3, 18"},"imbrex":{"lemma":"imbrex","pos":"","gen":"-tile","def":"(less freq. m., Plin. 17, 14, 24, § 114; Arn. 3, 107) , a hollow tile, gutter-tile, pantile (used in roofs for the purpose of leading off the rain"},"immendo":{"lemma":"immendo","pos":"v.","gen":"-mendum","def":"a. in-mendum, to involve in a fault, implicate: quos non emendamus, sed nos potius immendamus, Aug. Cont. Mendac, 3, 6. immensĭtas (inm-), ātis, f. immensus, immeasurableness"},"immistus":{"lemma":"immistus","pos":"","gen":"","def":"immixtus. immīte, adv., v. immitis fin. immītĭgābĭlis (inm-), e, adj. inmitigo, that cannot be softened or allayed, immitigable (post-class.): ardor, Cael. Aur. Tard. 4, 3, 33. immītis (inm-), e"},"immoenis":{"lemma":"immoenis","pos":"","gen":"","def":"immunis. immŏlātīcĭus (inm-) or -tĭus, a, um, adj. immolo, of or for a sacrifice (late Lat.): caro, Aug. Ep. 154"},"immundo":{"lemma":"immundo","pos":"v.","gen":"","def":"a. id., to defile, render unclean (late Lat.): albentes pulvere canes, Dracont. Carm. 8, 589. immundus (inm-), a, um, adj. inmundus, unclean, impure, dirty, filthy, foul (syn.: spurcus, obscenus"},"impaene":{"lemma":"impaene","pos":"","gen":"","def":"impunis, II. impaenĭtendus (inp-), a, um, adj. 2. in-paenitet, not to be repented of: pauperies, App. M. 11, p. 271. impaenĭtens (inp-), entis, adj. 2. inpaenitens, not repenting"},"imparcenter":{"lemma":"imparcenter","pos":"adv.","gen":"-parcus","def":"in-parcus, relentlessly, unsparingly: cuncta perdit, Hilar. in Job, 1, 76: Samson in mortem tradidit, id. ib. p. 90. impārentem non parentem hoc est obedientem"},"implexus":{"lemma":"implexus","pos":"","gen":"","def":"implecto, an entwining, infolding, embrace (post-Aug. and only in the abl. sing.): polypus cavernam cancellato bracchiorum implexu claudit, Plin. 9, 51, 74"},"impoene":{"lemma":"impoene","pos":"","gen":"","def":"impune, II. impoenĭtens, etc., v. impaenitens, etc. impŏlītē (inp-), adv., v. impolitus fin. impŏlītĭa (inp-), ae, f. impolitus, want of neatness, carelessness"},"in-candesco":{"lemma":"in-candesco","pos":"","gen":"-candesco","def":"inch. n., to become warm or hot, to glow, to kindle (poet. and in post-Aug. prose): volat illud (plumbum) et incandescit eundo, Ov. M. 2, 728: vetus accensis incanduit ignibus ara, id. ib. 12"},"in-canto":{"lemma":"in-canto","pos":"v.","gen":"-canto","def":"a. and n. * To sing in, with dat.: passer incantans saepiculae (i. e. in saepicula), App. M. 8, p. 210, 26. — In partic. To say over, mutter"},"in-cassus":{"lemma":"in-cassus","pos":"adj.","gen":"-cassus","def":", vain: non incassa futura temptamina, Sulp. Sev. Dial. 3, 10, 3. incastē, v. incestus fin. in-castīgātus, a, um, adj., unpunished, unreproved: nec me dimittes incastigatum, Hor. Ep. 1, 10"},"in-cautus":{"lemma":"in-cautus","pos":"adj.","gen":"-cautus","def":"Act., incautious, heedless, improvident, inconsiderate (class.; syn. improvidus): ut in ipsum incautum atque etiam imparatum incideret, Caes. B. G. 6, 30, 2"},"in-cerno":{"lemma":"in-cerno","pos":"v.","gen":"-cerno","def":"a., to sift upon a thing, to cover or bestrew with sifting; to sift, scatter with a sieve: terram cribro, Cato, R. R. 48, 2"},"in-circum":{"lemma":"in-circum","pos":"prep.","gen":"-circum","def":", round about: quod incircum cum locum aquae frigidae et caldae multae, Varr. L. L. 5, § 25 Müll.; cf. Hand, Turs. ad h. v. in-circumcīsus, a, um, adj., uncircumcised (eccl. Lat.), Tert. adv. Jud. 2"},"in-circumscriptus":{"lemma":"in-circumscriptus","pos":"adj.","gen":"-circumscriptus","def":", unlimited, infinite (eccl. Lat.): dominus, Prud. Apoth. 863. incīsē, adv., v. incīdo fin. C. 2. incīsim, adv. incisus, from 2. incīdo"},"in-cognosco":{"lemma":"in-cognosco","pos":"","gen":"-cognosco","def":"inch. n., to learn, find out a thing: ut incognosceret, quisnam esset, App. Flor. p. 362, 22 (dub. al. ut inde cognosceret). incŏhāmenta (incho-), ōrum, n. incoho, first principles, rudiments"},"in-compertus":{"lemma":"in-compertus","pos":"adj.","gen":"-compertus","def":", of which one has no information, unknown (not anteAug.): inter cetera vetustate incomperta hoc quoque in incerto positum, Liv. 4, 23, 3: ne quid incompertum deferret, id. 10, 40, 10"},"in-concessus":{"lemma":"in-concessus","pos":"adj.","gen":"-concessus","def":", not allowed, impossible (not ante-Aug. and rare): hymenaei, unlawful, forbidden, Verg. A. 1, 651"},"in-concinnus":{"lemma":"in-concinnus","pos":"adj.","gen":"-concinnus","def":", inelegant, awkward, absurd (rare but class.): qui in aliquo genere inconcinnus aut multus est, is ineptus dicitur, * Cic. de Or. 2, 4, 17: personamque feret non inconcinnus utramque, Hor. Ep. 1, 17"},"in-concussus":{"lemma":"in-concussus","pos":"adj.","gen":"-concussus","def":", unshaken, undisturbed, firm, constant, unchanged (post-Aug.). Lit.: caelestia sidera, Luc. 2, 268; so, vestigia, id. 2, 248.— Trop.: inconcussus ipse et immotus, Plin. Pan. 82, 2"},"in-confectus":{"lemma":"in-confectus","pos":"adj.","gen":"-confectus","def":", not wrought out, undigested (late Lat.), Hier. Ep. 119, no. 1"},"in-connexus":{"lemma":"in-connexus","pos":"","gen":"-connexus","def":"inconexus. inconnīvus (better incōnīvus), a, um, adj. 2. in-coniveo, that does not close the eyes, sleepless (Appuleian"},"in-conscriptus":{"lemma":"in-conscriptus","pos":"adj.","gen":"-conscriptus","def":", not arranged (late Lat.): incondita, id est inconscripta, Serv. ad Verg. E. 2, 4. in-consentānĕus, a, um, adj., unsuitable, unfit (late Lat.), Mart. Cap. 3, § 228 al. in-consĕquens, tis, adj."},"in-conspectus":{"lemma":"in-conspectus","pos":"adj.","gen":"-conspectus","def":", indiscreet, imprudent (post-class.): inconspectum aliquid temere dicere, Gell. 17, 21, 1. in-conspĭcŭus, a, um, adj., not conspicuous, not remarkable ( = inglorius, ignobilis"},"in-constans":{"lemma":"in-constans","pos":"adj.","gen":"-constans","def":", inconstant, changeable, fickle, capricious, inconsistent (class.). Of persons: mihi ridicule es visus esse inconstans, qui eundem et laederes, et laudares, Cic. Rosc. Com. 6"},"in-consultus":{"lemma":"in-consultus","pos":"adj.","gen":"-consultus","def":"Not consulted, unasked (so perh. not in Cic.): inconsulto senatu, Liv. 36, 36, 2; so, inconsulto se, Suet. Tib. 52: me inconsulto, Amm. 17, 5, 12; 27, 2 fin.; Ambros. Ep. 6, 43; Plin. Ep. 10, 107, 2"},"in-consumptus":{"lemma":"in-consumptus","pos":"adj.","gen":"-consumptus","def":", unconsumed, undiminished (Ovidian): pars turis, Ov. M. 7, 592: jecur, id. P. 1, 2, 41: juventa, id. M. 4, 17. inconsūtĭlis, e, adj. 2. in-consuo, not sewed together, without seam: tunica"},"in-contentus":{"lemma":"in-contentus","pos":"adj.","gen":"-contentus","def":", unstretched: fides, out of tune Cic. Fin. 4, 27, 75. incontĭgŭus, a, um, adj. 2. in-contingo, that cannot be touched (eccl. Lat.): Deus omni est incontiguus tactu, Arn. 7, p. 267. in-contĭnens, tis"},"in-correctus":{"lemma":"in-correctus","pos":"adj.","gen":"-correctus","def":", uncorrected, unimproved: opus, Ov. Tr. 3, 14, 23. in-corrĭgĭbĭlis, e, adj., not to be corrected or cured (post-Aug."},"in-crasso":{"lemma":"in-crasso","pos":"v.","gen":"-crasso","def":"a., to make thick or stout (post-class.; used mostly in the part.), Tert. adv. Psych. 6.—Hence, in-crassātus, a, um, P. a., made stout, fattened, Tert. adv. Marc. 3, 6"},"in-crebresco":{"lemma":"in-crebresco","pos":"v.","gen":"-crebresco","def":"n., to become frequent or strong, to increase, gain ground, prevail, spread (= crebrior fieri, augeri, crescere; class.): mores deteriores, Plaut. Merc. 5, 1, 9: ventus, Cic. Fam. 7, 20, 3"},"in-cresco":{"lemma":"in-cresco","pos":"v.","gen":"-cresco","def":"n., to grow in or upon any thing (perh. not ante-Aug.). Lit.: non taedia animalium capillis increscunt, do not grow in the hair, Plin. 28, 11, 46, § 163. — In gen., to grow"},"in-crusto":{"lemma":"in-crusto","pos":"v.","gen":"-crusto","def":"a., to cover with a coat or rind, to incrust (mostly anteand post-class.): ollam sapā et farre, Varr. R. R. 3, 14, 5: tota maceria levi lapide aut tectoria intrinsecus incrustetur, id. ib. 15"},"in-culco":{"lemma":"in-culco","pos":"v.","gen":"-culco","def":"a. in-calco, to tread in, tread down (class., esp. in the trop. signif.). Lit., to tread down, ram down: aliquid, Col. 2, 20, 1: semen obrutum pavicula, id. 11, 3, 34.— Trop. To stuff, press"},"in-cultus":{"lemma":"in-cultus","pos":"adj.","gen":"-cultus","def":", untilled, uncultivated (class.). Lit.: ager, Cic. Rosc. Com. 12, 33: via, with silvestris, neglected, id. Brut. 72, 259: quid incultius oppidis? id. Prov. Cons. 12"},"in-cunctans":{"lemma":"in-cunctans","pos":"adj.","gen":"-cunctans","def":", not delaying, unhesitating (eccl. Lat.): fides, Paul. Petr. Vit. S. Mart. 5, 233.—Adv.: in-cunctan-ter (incont-), without delay, unhesitatingly (post-class.)"},"in-curuo":{"lemma":"in-curvo","pos":"v.","gen":"-curvo","def":"a., to bend, bow, crook, curve (in Cic. only once in part. pass."},"in-curuus":{"lemma":"in-curvus","pos":"adj.","gen":"-curvus","def":", bent, bowed, crooked, curved (opp. recurvus, pandus"},"in-cussor":{"lemma":"in-cussor","pos":"","gen":"-cussor","def":"id., one who strikes, Paul. Petr. Vit. S. Mart. 5, 285. incussus, a, um, Part., from incutio."},"in-deflexus":{"lemma":"in-deflexus","pos":"adj.","gen":"-deflexus","def":", unbent, unchanged (post-Aug.): maturitas, Plin. Pan. 4, 7: cursus, App. de Deo Socr. p. 42, 16: saevitia, Amm. 27, 9. in-dējectus, a, um, adj., not thrown down: domus, Ov. M. 1, 289. in-dēlassātus"},"in-descriptus":{"lemma":"in-descriptus","pos":"adj.","gen":"-descriptus","def":", not divided (post-Aug.): vites, Col. 3, 21, 4: agri, Sid. Carm. 2, 412. in-dēsertus, a, um, adj., not deserted, unforsaken: regna, Ov. Am. 2, 9, 52. in-dēsĕs, ĭdis, adj., not inactive"},"in-despectus":{"lemma":"in-despectus","pos":"adj.","gen":"-despectus","def":", that one cannot look down into, unfathomable (postAug.): Tartara, Luc. 6, 748."},"in-destrictus":{"lemma":"in-destrictus","pos":"adj.","gen":"-destrictus","def":", untouched, uninjured, unhurt: abibo, Ov. M. 12, 92 (al. indistrictus). indētermĭnābĭlis, e, adj. 2. in-determino, that cannot be defined, indeterminable (late Lat.): quaestiones"},"in-dictus":{"lemma":"in-dictus","pos":"adj.","gen":"-dictus","def":"Not said, unsaid (class.): quod dictum, indictum'st: quod modo erat ratum, irritum est, Ter. Phorm. 5, 7, 58: quae tum cecinerit, ea se nec, ut indicta sint, revocare posse, Liv. 5, 15"},"in-dignor":{"lemma":"in-dignor","pos":"v.","gen":"-dignor","def":"indignarier for indignari, Lucr. 3, 870), v. dep. a. , to consider as unworthy or improper, to be angry or displeased at, to be indignant (syn. stomachor). In gen. (class.). With acc.: se ipsum"},"in-dignus":{"lemma":"in-dignus","pos":"adj.","gen":"-dignus","def":", unworthy, undeserving (class.). Of persons. In gen., unworthy. Absol.: divitias quivis quamvis indignus, habere potest, Cic. Tusc. 5, 16, 46: indignissimi candidati, Liv. 4, 57"},"in-discissus":{"lemma":"in-discissus","pos":"adj.","gen":"-discissus","def":", not cut to pieces, undivided (late Lat.): tunica Domini, Hier. Ep. 15, 1."},"in-disco":{"lemma":"in-disco","pos":"v.","gen":"-disco","def":"a., to learn thoroughly: magna res est posse indiscere, Schol. Juv. 6, 474. in-discrētē and in-discrētim, advv., v. indiscretus, a, um, fin. in-discrētĭo, ōnis, f., lack of discernment, indiscretion"},"in-discussus":{"lemma":"in-discussus","pos":"adj.","gen":"-discussus","def":"id., not discussed, not considered (late Lat.), Claud. Mam. Stat. Anim. 3, 11"},"in-distanter":{"lemma":"in-distanter","pos":"adv.","gen":"-distanter","def":"2. in-disto (late Lat.). Uninterruptedly: syllaba uno spiritu indistanter profertur, Prisc. p. 565 P. — Without distinction, without exception (post-class.), Amm. 27, 9, 41"},"in-distinctus":{"lemma":"in-distinctus","pos":"adj.","gen":"-distinctus","def":"(post-Aug.). Not properly distinguished, confused: neque inordinata, neque indistincta, Quint. 8, 2, 23"},"in-do":{"lemma":"in-do","pos":"v.","gen":"-do","def":"a. in-, 2. do, to put, set, or place into or upon (mostly anteclass. and post-Aug.). Lit. With in and acc.: coronam in focum, Cato, R. R. 143, 2: in urnam, id. ib. 143, 23: ignem in aram"},"in-doctus":{"lemma":"in-doctus","pos":"adj.","gen":"-doctus","def":", untaught, unlearned, uninstructed, ignorant, unskilful. Of persons (class.): homo, Auct. Her. 4, 46, 59: (Juventius) nec indoctus, et magna cum juris civilis intellegentia, Cic. Brut. 48"},"in-dulceo":{"lemma":"in-dulceo","pos":"v.","gen":"-dulceo","def":"n. in-dulcis, to become very sweet, Gloss. Philox. in-dulcĭtas, false read. for dulcitas, Caecil. ap. Non. 96, 29; v. Com. Rel. p. 60 Rib."},"in-dulco":{"lemma":"in-dulco","pos":"v.","gen":"-dulco","def":"a., to make sweet, to sweeten (late Lat.). Lit.: aquam amaram, Tert. adv. Jud. 13"},"in-faeco":{"lemma":"in-faeco","pos":"v.","gen":"-faeco","def":"a. in-faex, to pollute: animam concretione carnis (late Lat.), Tert. Anim. 53 fin. in-fallĭbĭlĭter, adv. 2. in-fallo, infallibly (late Lat.), Aug. Praedest. Sanct. 15, 2. in-falsātus, a, um, adj."},"in-fandus":{"lemma":"in-fandus","pos":"adj.","gen":"-fandus","def":", unspeakable, unutterable, unheard of, unnatural, shocking, abominable (class.): res crudelis, infanda, Cic. de Or. 2, 79, 322: impurum atque infandum corpus, id. Sest. 55, 117: epulae"},"in-faustus":{"lemma":"in-faustus","pos":"adj.","gen":"-faustus","def":", unfortunate, unpropitious (poet. and post-Aug.): infaustas exurite puppes, Verg. A. 5, 635: nomen, id. ib. 7, 717: auspicium, id. ib. 11, 347: gradus, Ov. M. 3, 36: dies, Tac. H. 2, 91: castra"},"in-fermentum":{"lemma":"in-fermentum","pos":"","gen":"-fermentum","def":", unleavened bread, Gloss. Philox. infernālis, e, adj. infernus, nether, lower, belonging to the lower regions, infernal (post-class.): nox, Alcim. Avit. 2, 290: Juppiter, i. e. Pluto"},"in-feruesco":{"lemma":"in-fervesco","pos":"","gen":"-fervesco","def":"inch. n., to boil down, to boil, to grow hot, be heated: fabae tertia pars ut infervescat, Cato, R. R. 90: mulsum quod inferbuit, Cels. 2, 30: hoc ubi inferbuit, Hor. S. 2, 4"},"in-festus":{"lemma":"in-festus","pos":"adj.","gen":"-festus","def":"2. in-festus for fenstus, from fendo; whence defendo, infensus, made unsafe, disturbed, molested, infested; unquiet, unsafe (class."},"in-findo":{"lemma":"in-findo","pos":"v.","gen":"-findo","def":"a., to cut into, to cleave (poet.): telluri sulcos, Verg. E. 4, 33"},"in-firmo":{"lemma":"in-firmo","pos":"v.","gen":"-firmo","def":"a., to establish in, fix, or confirm in (late Lat.), Cael. Aur. Acut. 3, 4, 36. in-firmus, a, um (post-class. infir-mis, e, Amm. 20, 6), adj., not strong, weak, feeble. Lit.: viribus infirmis"},"in-fit":{"lemma":"in-fit","pos":"","gen":"-fit","def":"def. (infĭunt, Mart. Cap. 2, § 220: infe ἄρξαι, Gloss.: infĭo, Varr. ap. Prisc. 8 fin.), he (she, it), begins: infit me percontarier, Plaut. As. 2, 2, 76: laudare formam virginis"},"in-flammo":{"lemma":"in-flammo","pos":"v.","gen":"-flammo","def":"a., to set on fire, light up, kindle (syn. incendere). Lit.: taedas ignibus, Cic. Verr. 2, 4, 48"},"in-flecto":{"lemma":"in-flecto","pos":"v.","gen":"-flecto","def":"a., to bend, bow, curve. Lit.: cum ferrum se inflexisset, Caes. B. G. 1, 25: bacillum, Cic. Div. 1, 17: capillum leniter, Suet. Aug. 79. —Mid.: sinus ad urbem inflectitur, bends itself, curves round"},"in-flexus":{"lemma":"in-flexus","pos":"adj.","gen":"-flexus","def":"; gram. t. t., not declined, not inflected, Mart. Cap. 3, § 305."},"in-flo":{"lemma":"in-flo","pos":"v.","gen":"-flo","def":"a., to blow into or upon any thing, to inflate. Lit. In gen.: age, jam infla buccas, Plaut. Stich. 5, 5, 26: ex ore in os palumbi inflare aquam, Cato, R. R. 90: tumidoque inflatur carbasus Austro"},"in-foecundus":{"lemma":"in-foecundus","pos":"","gen":"-foecundus","def":"infecundus. in-foedĕrātus, a, um, adj., not leagued together, not allied (late Lat.): reges, Tert. Praeser. 12. in-formābĭlis, e, adj., insusceptible of form"},"in-formo":{"lemma":"in-formo","pos":"v.","gen":"-formo","def":"a., to give form to a thing, to shape, form, mould, fashion. Lit. (mostly poet.): clipeum, Verg. A. 8, 447: aream, Col. 11, 3, 13: effigiem, Sil. 17, 525: Martem cerā, Poët. ap. Plin. Ep. 9"},"in-fractus":{"lemma":"in-fractus","pos":"adj.","gen":"-fractus","def":", unbroken, unweakened (late Lat.): animi, Symm. Ep. 1, 3: infractus hoc spectaculo, Hier. Vit. Pauli."},"in-frendo":{"lemma":"in-frendo","pos":"","gen":"-frendo","def":"infrendeo. infrēnis, e, and infrēnus, a, um (infraen-), adj. 2. in - frenum, without a bridle, unbridled (poet. and post-class.). Lit.: infrenis equus, Verg. A. 10, 750: Numidae infreni"},"in-fringo":{"lemma":"in-fringo","pos":"v.","gen":"-fringo","def":"a. infrango, to break off, to break, bruise, crack. Lit.: infractis omnibus hastis, Liv. 40, 40, 7: ut si quis violas riguove papavera in horto Liliaque infringat, Ov. M. 10"},"in-frons":{"lemma":"in-frons","pos":"adj.","gen":"-frons","def":", without foliage, treeless, Ov. P. 4, 10, 31. in-frontātē, adv., impudently, Fulg. de Prisc. Serm. no. 22. infructĭfĕrus, a, um, adj., bearing no fruit (eccl. Lat.)"},"in-fundo":{"lemma":"in-fundo","pos":"v.","gen":"-fundo","def":"a., to pour in, upon, or into (syn. invergere). Lit.: aliquid in aliquod vas, Cic. Tusc. 1, 25, 61: vinum reticulo aut cribro, Sen. Ben. 7, 19: aliquid in nares, Plin. 20, 17, 69"},"in-fusco":{"lemma":"in-fusco","pos":"v.","gen":"-fusco","def":"a., to make dark or dusky, to darken, obscure. Lit.: humida fulmina non urunt sed infuscant, Plin. 2, 51, 52, § 137: aquā infuscatā atramento, id. 9, 29, 45, § 84"},"in-fuscus":{"lemma":"in-fuscus","pos":"adj.","gen":"-fuscus","def":", dusky, dark brown, blackish: apes infusci coloris, Col. 9, 3, 1"},"in-gemmesco":{"lemma":"in-gemmesco","pos":"","gen":"-gemmesco","def":"inch. n., to become a jewel, Isid. 16, 14, 7. in-gĕmo, ŭi, 3, v. a. and n., to groan or sigh over a thing"},"in-gesto":{"lemma":"in-gesto","pos":"v.","gen":"-gesto","def":"a., to bear: votum, a dub. read. in App. M. 11, p. 264, 37, where now intextas; v. Hildebr. ad h. l. ingestus, a, um, Part., from ingero."},"in-gigno":{"lemma":"in-gigno","pos":"v.","gen":"-gigno","def":"a., to instil by birth or nature, to implant, engender. Lit.: herbasque nocentes rupibus ingenuit tellus, Luc. 6, 439: vites ingenita sterilitate, Col. 3, 7"},"in-grandesco":{"lemma":"in-grandesco","pos":"","gen":"-grandesco","def":"inch. n., to grow big, increase (post-Aug.): asinus, Col. 3, 6, 3: sata, id. 2, 10, 15: porrum, si jam ingranduit, id. 11, 3, 17. ingrātē, adv., v. ingratus fin. ingrātĭa, ae"},"in-gusto":{"lemma":"in-gusto","pos":"v.","gen":"-gusto","def":"a., to give to taste (late Lat.): Jovi sanguinem humanum, Tert. adv. Gnost. 7. Ingyaeŏnes (v. Ingaevones), um, m., a German tribe, Plin. 4, 14, 28, § 99. ĭn-hăbĭlis, e, adj., that cannot be managed"},"in-hisco":{"lemma":"in-hisco","pos":"v.","gen":"-hisco","def":"n., i. q. inhio: inhisco ἐπιχαίνω, Gloss. Philox. ĭnhŏnestāmentum, i, n. inhonesto, dishonor, disgrace, shame (ante- and postclass.): pueritia tua adulescentiae tuae inhonestamentum fuit"},"in-iunctus":{"lemma":"in-junctus","pos":"adj.","gen":"-junctus","def":"2. in-jungo, not joined, not united (late Lat.): fideles, Tert. adv. Ux. 2, 2."},"in-iungo":{"lemma":"in-jungo","pos":"v.","gen":"-jungo","def":"a., to join into something. Lit. To join or fasten into: tignos in asseres, Liv. 44, 5, 4: arborem scrobi, to set or plant into, Pall. Febr. 10, 1"},"in-iussus":{"lemma":"in-jussus","pos":"adj.","gen":"-jussus","def":"2. in-jubeo, unbidden, voluntary, of one's own accord. Lit.: ut numquam inducant animum cantare rogati, injussi numquam desistant, Hor. S. 1, 3, 3: puer, Luc. 7"},"in-iustus":{"lemma":"in-justus","pos":"adj.","gen":"-justus","def":", that is contrary to right and justice, unjust, wrongful, unreasonable, excessive, oppressive, severe. In gen., unsuitable, oppressive, excessive (rare): onus ( = immodicum), Cic. Or. 10, 35: faenus"},"in-nascor":{"lemma":"in-nascor","pos":"v.","gen":"-nascor","def":"dep., to be born in, to grow or spring up in a place. Lit.: neglectis urenda filix innascitur agris, Hor. S. 1, 3, 37: Fauni velut innati triviis, id. A. P. 245: innata rupibus altis robora, Ov. H. 7"},"in-no":{"lemma":"in-no","pos":"v.","gen":"-no","def":"n., to swim or float in or upon. Lit. Partim submersae, partim fluitantes et innantes beluae, Cic. N. D. 2, 39, 100: innare contextis ratibus, Amm. 14, 2, 10: innabant pariter fluctusque secabant"},"in-nuptus":{"lemma":"in-nuptus","pos":"adj.","gen":"-nuptus","def":"2. in-nubo, unmarried. Lit. Adj.: pueri innuptaeque puellae, Verg. G. 4, 476: Minerva, virginal, virgin-, id. A. 2, 31: manus, the Amazons, Sil. 2, 75.— Subst.: innupta, ae, f., an unmarried woman"},"in-rectus":{"lemma":"in-rectus","pos":"adj.","gen":"-rectus","def":", not straight, crooked: vulpinari dictum ab inrecto, seu intorto vulpium cursu, Non. 46, 24. in-saepĭo, īre, saeptus, 4, v. a., to hedge in, enclose: ingenti muro, Sen. Ben. 4, 19, 1."},"in-saeptus":{"lemma":"in-saeptus","pos":"adj.","gen":"-saeptus","def":", not hedged in, not enclosed, Paul. ex Fest. 95, 111 Müll. in-saevĭo, īre, 4, v. n., to fall into a passion, Ambros. de Jos. Patr. 3, 11"},"in-sanctus":{"lemma":"in-sanctus","pos":"adj.","gen":"-sanctus","def":", unholy: insanctus, ο μὴ ἅγιος, Gloss. Gr. Lat. insānē, adv., v. insanus fin. insānĭa, ae, f. insanus, unsoundness of mind. As a disease, madness, insanity, Cels. 3, 18"},"in-scriptus":{"lemma":"in-scriptus","pos":"adj.","gen":"-scriptus","def":"Unwritten: unde et illa divisio est, alia esse scripta, alia inscripta, Quint. 3, 6, 36"},"in-sectus":{"lemma":"in-sectus","pos":"adj.","gen":"-sectus","def":"2. in-seco, for non sectus, Paul. ex Fest. p. 111 Müll. in-sĕcundus, a, um, adj., not following, unyielding, uncomplying: secundus, insecundus, Not. Tir. 95. insĕcūtĭo, ōnis, f. insequor"},"in-segnis":{"lemma":"in-segnis","pos":"adj.","gen":"-segnis","def":", inactive, indolent: insegnis, ἀδρανής, Gloss. Philox. in-sĕmĕl, adv., at once, Flor. prooem. § 3; id. 2, 20, 1"},"in-septus":{"lemma":"in-septus","pos":"","gen":"-septus","def":"insaeptus. in-sĕpultus, a, um, adj. 2. in-sepultus, unburied (class.): acervi civium, Cic. Cat. 4, 6, 11: membra, Hor. Epod. 5, 99: insepultos projecit, Liv. 29, 9, 10. — Transf."},"in-serpo":{"lemma":"in-serpo","pos":"v.","gen":"-serpo","def":"n., to crcep on or over any thing; only trop."},"in-seruo":{"lemma":"in-servo","pos":"v.","gen":"-servo","def":"a. To attend to, observe (a favorite word of Statius): gemit, inservante noverca, Liber, Stat. Th. 10, 886: volucres, id. ib. 8, 194: fata, id. ib. 6"},"in-sessus":{"lemma":"in-sessus","pos":"adj.","gen":"-sessus","def":"2. in-sedeo, unsettled, without a permanent dwelling: gentes, Sic. Fl. de Cond. Agr. p. 3."},"in-signo":{"lemma":"in-signo","pos":"v.","gen":"-signo","def":"a., to engrave: insigno, ἐγχαράσσω, Gloss. Philox. insĭlĭa, ĭum, n. plur. , the treadle of a weaver's loom, Lucr. 5, 1353. insĭlĭo, ŭi (insilivi, Liv. 8, 9, 9: insilii, Claud. ap. Ruf. 1, 349"},"in-sisto":{"lemma":"in-sisto","pos":"v.","gen":"-sisto","def":"n., to set foot upon, to stand, tread, or press upon"},"in-somnis":{"lemma":"in-somnis","pos":"adj.","gen":"-somnis","def":"2. in-somnus, sleepless (poet. and in post-Aug. prose). Of living beings, Hor. C. 3, 7, 8: juventus, Pers. 3, 54: insomnes magis, quam pervigiles, Tac. A. 1, 65: draco, Ov. M. 9"},"in-sons":{"lemma":"in-sons","pos":"adj.","gen":"-sons","def":"Guiltless, innocent"},"in-sordesco":{"lemma":"in-sordesco","pos":"","gen":"-sordesco","def":"inch. n., to become dirty or foul (post-class.), Sid. Ep. 5, 13.— Esp., to become gloomy, to darken, Sid. Ep. 2, 2"},"in-splendesco":{"lemma":"in-splendesco","pos":"","gen":"-splendesco","def":"inch. n., to shine into, illuminate: insplendesco, ἐνλάμπω, Gloss. Philox. in-spŏlĭātus, a, um, adj., not plundered (poet. and in post-Aug. prose): occi sus est non praedae gratiā"},"in-spurco":{"lemma":"in-spurco","pos":"v.","gen":"-spurco","def":"a., to defile: utrum illum pecunia purum effecit, an ipse pecuniam inspurcavit, Sen. Ep. 87, 16. in-spūto, āvi, ātum, 1, v. a. freq. , to spit upon: ain' eum mihi esse morbum"},"in-stagno":{"lemma":"in-stagno","pos":"v.","gen":"-stagno","def":"n., to overflow, Not. Tir. p. 183. instans, P. a., v. insto fin."},"in-stauro":{"lemma":"in-stauro","pos":"v.","gen":"-stauro","def":"a. staurus, obs., = Gr. σταυρός, a paling, stake; cf. Sanscr. sthavaras, firm; root stare, ἵστημι, to renew, repeat, celebrate anew; to repair, restore; to erect, make (syn.: renovo, integro"},"in-sterno":{"lemma":"in-sterno","pos":"v.","gen":"-sterno","def":"a. To cover, cover over: instrata cubilia fronde, Lucr. 5, 987; so, instratos ostro, Verg. A. 7, 277"},"in-stinguo":{"lemma":"in-stinguo","pos":"v.","gen":"-stinguo","def":"a., to instigate, incite, impel (class. only in the part. pass.): Christus intus instinxerat, Tert. Anim. 26 (Gell. 17, 20, 7, read instrinxit).— Part. pass.: instinctus, a, um, instigated"},"in-stringo":{"lemma":"in-stringo","pos":"v.","gen":"-stringo","def":"a. To bind, girdle, fasten, chain (rare"},"in-subiectus":{"lemma":"in-subjectus","pos":"adj.","gen":"-subjectus","def":", unsubjected, unsubdued, Prud. Ham. 699. Insŭbres, v. Insuber. insubsĭdĭātus, a, um, adj. 2. in-subsidior, unsupported, Vulg. Esdr. 3, 9, 11. in-substantīvus, a, um, adj., unsubstantial"},"in-suesco":{"lemma":"in-suesco","pos":"v.","gen":"-suesco","def":"n. and a. (insuerat, Tac. A. 4, 57), to accustom, habituate (not in Cic. or Caes.). Neutr., to accustom or habituate one's self, to become accustomed to a thing"},"in-sufflo":{"lemma":"in-sufflo","pos":"v.","gen":"-sufflo","def":"a., to blow or breathe into or upon (post-class.): insufflavit in faciem ejus flatum vitae, Tert. Res. Carn. 5"},"in-sulco":{"lemma":"in-sulco","pos":"v.","gen":"-sulco","def":"a., to furrow, make furrows: sulcat, insulcat, Not. Tir. p. 155. insŭlensis, e, adj. insula, of or belonging to an island, insular (late Lat.): ab insulense ad continentem, Sol. 54 dub. insŭlōsus, a"},"in-sum":{"lemma":"in-sum","pos":"v.","gen":"-sum","def":"n., to be in or upon. Lit.: meo patri torulus inerit aureus sub petaso, Plaut. Am. prol. 144: nummi octingenti aurei in marsupio infuerunt, id. Rud. 5, 2, 26: nec digitis anulus ullus inest, Ov. F 4"},"in-surgo":{"lemma":"in-surgo","pos":"v.","gen":"-surgo","def":"n. To rise upon, to rise up or to: insurgite remis, rise on your oars, i. e. ply your oars vigorously, Verg. A. 3, 560; 3, 207; 5, 189"},"in-susceptus":{"lemma":"in-susceptus","pos":"adj.","gen":"-susceptus","def":", not taken upon one's self: vota, Albin. 1, 197. in-suspĭcābĭlis, e, adj., not thought of, unexpected (eccl. Lat.)"},"in-tactus":{"lemma":"in-tactus","pos":"adj.","gen":"-tactus","def":", untouched, uninjured, intact. Lit.: cervix juvencae, not broken to the yoke, Verg. G. 4, 540: grex, id. A. 6, 38: boves, Hor. Epod. 9, 22: nix, Liv. 21, 36: exercitus integer intactusque, id. 10"},"in-tardo":{"lemma":"in-tardo","pos":"v.","gen":"-tardo","def":"n. and a., to stay, abide (late Lat.): intardans atque perseverans, Cael. Aur. Acut. 1, 4, 43"},"in-tectus":{"lemma":"in-tectus","pos":"adj.","gen":"-tectus","def":", uncovered, unclad. Lit.: nuda, intecta corpora, Sall. H. 1, 59: semiruta moenia, domūs intectae, unroofed, id. ib. 2, 21: cetera intecti, with no other covering, Tac. G. 17: dux prope intectus"},"in-testis":{"lemma":"in-testis","pos":"adj.","gen":"-testis","def":"2. in-, 2. testis, without testicles, emasculated, Arn. 5, 160 (cf. Salmas ad Tert. Pall. 3)."},"in-texo":{"lemma":"in-texo","pos":"v.","gen":"-texo","def":"a., to weave into, to inweave, interweave"},"in-tollo":{"lemma":"in-tollo","pos":"v.","gen":"-tollo","def":"a., to raise (post-class.): clamores absonos, App. M. 8, p. 213, 27. in-tondĕo, tondi, tonsum, 2, v. a., to clip off: fibrarum summas partes, Col. 11, 3, 31. in-tŏno, ŭi (āvi), 1, v. n."},"in-tundo":{"lemma":"in-tundo","pos":"v.","gen":"-tundo","def":"a., to bruise, pound (post-class.), Scrib. Comp. 71. intŭor, tŭi, v. intueor init. in-turbātus, a, um, adj., undisturbed, calm (post-Aug.): sedit inturbatus, interritus, Plin. Pan. 64, 2. in-turbĭdus"},"in-turgesco":{"lemma":"in-turgesco","pos":"v.","gen":"-turgesco","def":"n. inch., to swell up (post-class.), Veg. Vet. 1, 56, 19."},"in-uergo":{"lemma":"in-vergo","pos":"v.","gen":"-vergo","def":"a., to incline or turn to, to pour upon (poet."},"in-uersor":{"lemma":"in-versor","pos":"v.","gen":"-versor","def":"dep., to be among, to be occupied about (ante-class.): quīs inversamur, Lucil. ap. Lact. 6, 5, 2 (perh. quīs in versamur)."},"in-uerto":{"lemma":"in-verto","pos":"v.","gen":"-verto","def":"a., to turn upside down, turn about, to upset, invert (class.). Lit.: pingue solum Fortes invertant tauri, to turn up, plough up, Verg. G. 1, 64: campum, id. ib. 3, 161: Boreas invertit ornos"},"in-uestis":{"lemma":"in-vestis","pos":"adj.","gen":"-vestis","def":"2. in, unclothed (postclass.). In gen.: homo nudus et investis, Tert. Pall. 3.— In partic. Without a beard, beardless: puer, App. M. 5, p. 171; id. Mag. p. 336: pueri et puellae, Macr. S. 3, 8"},"in-uictus":{"lemma":"in-victus","pos":"adj.","gen":"-victus","def":"2. in, unconquered, unsubdued, not vanquished; hence unconquerable, invincible"},"in-uisco":{"lemma":"in-visco","pos":"v.","gen":"-visco","def":"a. viscum, to ensnare, capture with birdlime (late Lat.), Fulg. Serm. 69. ‡ in-visco, 1, v. a. id., to besmear with birdlime, Not. Tir. p. 160. invīsē, adv., v. 2, invisus fin. in-vīsĭbĭlis, e, adj."},"in-uoluo":{"lemma":"in-volvo","pos":"v.","gen":"-volvo","def":"a., to roll to or upon any thing. Lit.: Ossae frondosum involvere Olympum, Verg. G, 1, 282: montes, Ov. M. 12, 507: silvas, armenta secum, to sweep away with it, Verg. A. 12"},"inadc-":{"lemma":"inadc-","pos":"","gen":"","def":"inacc-."},"inadf-":{"lemma":"inadf-","pos":"","gen":"","def":"inaff-. ĭnădĭbĭlis, e, adj. 2. in-, 1. adeo, unapproachable, inaccessible: lacus vestigio inspectoris, Sid. Ep. 2, 2 med.: terra, Cassiod. Hist. Eccl. 11, 18."},"inadp-":{"lemma":"inadp-","pos":"","gen":"","def":"inapp-."},"inads-":{"lemma":"inads-","pos":"","gen":"","def":"inass-."},"inadsc-":{"lemma":"inadsc-","pos":"","gen":"","def":"inasc"},"inadt-":{"lemma":"inadt-","pos":"","gen":"","def":"inatt-. ĭn-ădūlābĭlis, e, adj., inaccessible to flattery: judex (with incorruptus), Gell. 14, 4, 3. ĭn-ădustus, a, um, adj., not burned, unburned, unsinged (very rare): corpus, Ov. H. 12, 93: fratres"},"inb-":{"lemma":"inb-","pos":"","gen":"","def":"imb-. in-caedŭus (incīdŭus, Stat. Th. 6, 9?*!0), a, um, adj., not cut or felled, uncut, unhewn (poet. and in post-class. prose): lucus, Ov. F. 2, 435: silva, id. Am. 3, 1, 1"},"incallo":{"lemma":"incallo","pos":"v.","gen":"-callum","def":"a. in-callum, to render callous (late Lat.): carnem indurat et incallat, Veg. Vet. 2, 27."},"incarno":{"lemma":"incarno","pos":"v.","gen":"-caro","def":"a. in-caro, orig., to make flesh; hence, in pass.: in-carnārī, ātus, to be made flesh, become incarnate (eccl. Lat.), Claud. Mam. Stat. An. 1, 12; Salv. adv. Avar. 3, 2; Cassiod. Hist. Eccl. 2, 9 al."},"incassum":{"lemma":"incassum","pos":"","gen":"","def":"cassus, II."},"incendo":{"lemma":"incendo","pos":"v.","gen":"-candeo","def":"subj. incensit = incenderit, sicut incepsit = inceperit, Paul. ex Fest. p. 107 Müll.), v. a. in-candeo; cf.: accendo and succendo, to set fire to, to kindle, burn (freq. and class."},"incensio":{"lemma":"incensio","pos":"","gen":"","def":"incendo, a setting on fire, burning (rare but class.): Capitolii, Cic. Cat. 3, 4, 9: incensione urbem liberavi, id. Sull. 11, 33: turis, Arn. 7, 234. incensĭtus, a, um, adj. 2. in-censeo"},"incensor":{"lemma":"incensor","pos":"","gen":"-class","def":"incendo, one who kindles or sets fire to (post-class.). Lit.: messium, Dig. 48, 19, 16, § 9; Paul. Sent. 5, 20"},"incensum":{"lemma":"incensum","pos":"adv.","gen":"","def":"id.. A setting fire to, lighting (eccl. Lat.): hora incensi, Ambros. de Virg. 3.— Concr., incense: incenso imposito, Inscr. Fratr. Arv. ap. Marin. p. 639; Sulp. Sev. Chron. 1, 47, 4"},"incensus":{"lemma":"incensus","pos":"adj.","gen":"-census","def":"2. in-census, not estimated, not assessed, unregistered"},"incentor":{"lemma":"incentor","pos":"","gen":"-class","def":"id., one who sets the tune or begins to sing, a precentor, singer (post-class.). Lit.: carminis, Paul. Nol. Carm. 15, 32: incentore canam Phoebo Musisque magistris, Avien. Perieg. 895"},"incepto":{"lemma":"incepto","pos":"","gen":"-class","def":"freq. a. id., to begin, undertake, attempt (ante- and post-class.): inceptas facinus facere, Plaut. Curc. 1, 1, 23"},"inceptor":{"lemma":"inceptor","pos":"","gen":"","def":"id., a beginner (anteand post - class.): o mearum voluptatum omnium inventor, inceptor, perfector! Ter. Eun. 5, 8, 4: carminis, Avien. Arat. init."},"inceptum":{"lemma":"inceptum","pos":"","gen":"","def":", v. incipio fin. inceptus, a, um, Part., from incipio."},"inceptus":{"lemma":"inceptus","pos":"","gen":"","def":"incipio, a beginning, undertaking (rare): foedum inceptu, foedum exitu, Liv. praef. 10: magno in omnia inceptu veneram, Sen. Ep. 108, 15: eriles, Val. Fl. 6, 124. incernĭcŭlum, i, n. incerno, a sieve"},"incerto":{"lemma":"incerto","pos":"adv.","gen":"","def":", v. incertus fin."},"incertum":{"lemma":"incertum","pos":"","gen":"","def":", v. incertus, II. 2."},"incertus":{"lemma":"incertus","pos":"adj.","gen":"-clause","def":"plur. incertūm, Pac. ap. Non. 495, 27), adj. 2. incertus"},"incessans":{"lemma":"incessans","pos":"adj.","gen":"-cessans","def":"2. in-cessans, incessant (post-class.): virtus, Cassiod. Complex. Act. Apost. 11.— Adv.: incessan-ter, incessantly: inhaerere, Cod. Just. 11, 42, 10 fin.: legebat auctores antiquos, Sid. Ep. 8"},"incessus":{"lemma":"incessus","pos":"","gen":"","def":"incedo, a going, walking, pace, gait. Lit. In gen. (class.): status, incessus, sessio, accubitio, vultus, oculi, manuum motus teneant illud decorum, Cic. Off. 1, 35, 128"},"incesto":{"lemma":"incesto","pos":"v.","gen":"","def":"a. incestus, to pollute, defile (poet. and in post-Aug. prose). In gen.: totamque incestat funere classem, Verg. A. 6, 150: aras, Stat. S. 5, 5, 4: diem (Furiae), id. Th. 11, 120"},"incestum":{"lemma":"incestum","pos":"","gen":"","def":"1. incestus, II. B. incestŭōsus, a, um, adj. 2. incestus, incestuous, lewd, Hilar. in Psa. 130, 3."},"incestus":{"lemma":"incestus","pos":"adj.","gen":"-castus","def":"2. in-castus, unclean (in a moral and religious sense), impure, polluted, defiled, sinful"},"incingo":{"lemma":"incingo","pos":"v.","gen":"-cingo","def":"a. in-cingo, to enclose with a girdle; hence, to gird, gird about, surround (mostly poet. and in postAug. prose; not used by Cic. in prose"},"inclango":{"lemma":"inclango","pos":"v.","gen":"","def":"n. (late Lat.), Jul. ap. Aug. cont. Sec. VI. 28. in-clāresco, rŭi, 3, v. inch. n. Lit., to become clear or light (late Lat.): ubi primum dies inclaruit, Amm. 25, 1, 1. — Trop."},"inclytus":{"lemma":"inclytus","pos":"","gen":"","def":"inclutus. in-cŏactus, a, um, adj., not compelled, voluntary (post-Aug. and rare): omne honestum injussum incoactumque est, Sen. Ep. 66 med. (false read. for incohata, Val. Max. 4, 7). incoctĭlis, e"},"incoctus":{"lemma":"incoctus","pos":"adj.","gen":"-coquo","def":"2. in-coquo, uncooked, raw (ante-class. and rare): incoctum non expromet, bene coctum dabit, Plaut. Mil. 2, 2, 53: collyrae facite ut madeant et colyphia: incocta ne mihi detis, id. Pers. 1, 3"},"incoercitus":{"lemma":"incoercitus","pos":"adj.","gen":"-co","def":"2. in-coërceo, unrestrained: incoercitos affectus, Jul. ap. Aug. C. Saec. Jul. 4, 41. in-cōgĭtābĭlis, e, adj. Act., thoughtless, inconsiderate (ante- and post - class.): nunc demum scio"},"incompos":{"lemma":"incompos","pos":"adj.","gen":"-compos","def":"2. in-compos, not having control over (late Lat.): incompotem mentis hominem, Polem. Physiog. p. 125. incompŏsĭtē, adv., v. incompositus fin. in-compŏsĭtus, a, um, adj. Not compounded, simple"},"inconsultus":{"lemma":"inconsultus","pos":"","gen":"-consulo","def":"2. in-consulo, the not advising with another (anteclass."},"inconuulsus":{"lemma":"inconvulsus","pos":"adj.","gen":"-convello","def":"2. in-convello, undestroyed (late Lat.): inconvulsa a se vectigalium pensione, i. e. while they are not relieved from the obligation of paying taxes, Fragm. Cod. Th. 5, 13, 14"},"incoxo":{"lemma":"incoxo","pos":"v.","gen":"-coxa","def":"n. in-coxa, to bend down, to cower or squat down, Pomp. ap. Non. 39, 9 (Com. Fragm. v. 97 Rib.). incrassātus, a, um, Part. and P. a., from incrasso."},"incrispo":{"lemma":"incrispo","pos":"v.","gen":"-crispus","def":"a. in-crispus, to crisp or curl (al. incrustare), Tert. Idol. 8. in-crŭcĭo, āre, v. a., to torture greatly, Not. Tir. p. 109. in-crūdesco, ĕre, v. inch. n., to become very raw"},"incumba":{"lemma":"incumba","pos":"","gen":"","def":"incumbo, archit. t. t., the impost or chaptrel of a pillar that bears the weight of an arch, Vitr. 6, 11."},"incumbo":{"lemma":"incumbo","pos":"v.","gen":"-class","def":"n. 1. incubo, to lay one's self upon, to lean or recline upon a thing (cf. ingruo; class., partic. in the trop. sense). Lit., constr. with in, ad, super, or dat."},"incursax":{"lemma":"incursax","pos":"adj.","gen":"","def":"id., that makes frequent inroads: Massagetae, Sid. Ep. 8, 12."},"incursim":{"lemma":"incursim","pos":"adv.","gen":"","def":"incurro, rapidly, quickly, Caecil. ap. Non. 127, 20 (Com. Fragm. v. 46 Rib.). incursĭo, ōnis, f. id., a running against, onset, assault, attack (class.). In gen.: atomorum, Cic. N. D. 1, 41"},"incurso":{"lemma":"incurso","pos":"","gen":"","def":"freq. n. and a. , to run to or against, to dash or strike against, to assault, attack (class.). Lit. With in: jam in vos incursabimus, Plaut. Bacch. 5, 2, 29: in agmen Romanum, Liv. 36, 14"},"incursus":{"lemma":"incursus","pos":"","gen":"","def":"incurro, a running against, an assault, attack (class.). Lit.: ceterorum tela atque incursus refugit, Cic. Caecin. 8, 22: equitum incursus sustinere, Caes. B. C. 1, 71"},"incuruisco":{"lemma":"incurvisco","pos":"","gen":"","def":"incurvesco."},"incussus":{"lemma":"incussus","pos":"","gen":"","def":"incutio, a striking or dashing against, a shock (rare, and only in abl. sing.): armorum, Tac. H. 4, 23: arietis, Sen. Const. Sap. 6: silicis, Prud. Cathem. 5, 7. in-custōdītus, a, um, adj. Pass. Lit."},"indalbo":{"lemma":"indalbo","pos":"","gen":"","def":"inalbo. indaudĭo, v. inaudio."},"inde":{"lemma":"inde","pos":"adv.","gen":"-im","def":"i-im, locative from is, and de = die"},"indemnis":{"lemma":"indemnis","pos":"adj.","gen":"-damnum","def":"2. in-damnum, unhurt, uninjured (post-Aug.): illaesus et indemnis evasit, Sen. Ep. 9; id. Const. Sap. 5; Amm. 26, 6; Dig. 50, 8, 9, § 4 sq."},"indeprensus":{"lemma":"indeprensus","pos":"adj.","gen":"","def":"id., unobserved, undiscovered (poet.): (with irremeabilis) error, Verg. A. 5, 591: vestigia, Stat. Th. 6, 565: retinacula, Prud. Hamart. 141. indeptāre consequi, Paul. ex Fest. p. 106 Müll. indeptus"},"index":{"lemma":"index","pos":"","gen":"-finger","def":"1. indico, he who (that which) points out, a pointer, indicator (class.). Lit. Of things. Of the forefinger, index-finger. With digitus: indice monstraret digito, Hor. S. 2, 8, 26"},"indi":{"lemma":"Indi","pos":"","gen":"","def":", v. Indus. Indĭa, ae, f., India, a country extending from the Indus to China, Cic. Tusc. 5, 27, 77 sq.; Cat. 43, 6"},"indignanter":{"lemma":"indignanter","pos":"adv.","gen":"","def":", v. indignor fin. indignātĭo, ōnis, f. indignor, displeasure, indignation, disdain. Lit. In gen.: sive indignatione et dolore vinculorum, Hirt. B. G. 8, 44, 2 (Kraner, indignitate"},"indisiunctim":{"lemma":"indisjunctim","pos":"adv.","gen":"-disjunctus","def":"2. in-disjunctus, i. e. not separated in time, immediately (late Lat.), Claud. Mam. Stat. Anim. 1, 12. in-dispensātus, a, um, adj. 2. in-dispenso, not properly distributed"},"indistrictus":{"lemma":"indistrictus","pos":"","gen":"","def":"indestrictus. indĭtus, a, um, P. a., from indo. indīvĭdŭĭtas, ātis, f. individuus, indivisibility (eccl. Lat.): animae, Tert. Anim. 51: matrimonii, id. Monog. 5. in-dīvĭdŭus, a, um"},"indormis":{"lemma":"indormis","pos":"adj.","gen":"-dormio","def":"2. in-dormio, i. q. insomnis, sleepless, Gloss. Philox. in-dōtātus, a, um, adj., unportioned, portionless (class. only in the trop. signif.). Lit.: virgo, Ter. Ad. 4, 7, 11; id. Phorm. 1, 2, 70"},"indu-gredior":{"lemma":"indu-gredior","pos":"","gen":"-gredior","def":"ingredior and in init."},"inductor":{"lemma":"inductor","pos":"","gen":"","def":"id., one who stirs up or rouses one, a chastiser, scourger: acerrimi, Plaut. As. 3, 2, 6. inductōrĭum, i, n. id., a covering: facere inductorium, Plin. Val. 1, 3. inductōrĭus, a, um, adj. id."},"inductrix":{"lemma":"inductrix","pos":"","gen":"","def":"id., she that misleads or deceives, App. Flor. 23 fin. al. inductūra, ae, f. id., a covering, coating (late Lat.), Cael. Aur. Acut. 3, 17, 148. inductus, a, um, Part. and P. a., from induco."},"inductus":{"lemma":"inductus","pos":"","gen":"","def":"(only in abl. sing.) , an inducement, persuasion (rare but class.): hujus persuasu et inductu, Cic. Fragm. ap. Quint. 5, 10, 69: inductu alieno facere aliquid, at another's persuasion, Auct. Her. 2"},"indulgenter":{"lemma":"indulgenter","pos":"adv.","gen":"","def":", v. indulgeo fin. indulgentĭa, ae, f. indulgens, indulgence, gentleness, complaisance, tenderness, fondness (class.). Of persons: quid est dignius"},"indultor":{"lemma":"indultor","pos":"adv.","gen":"","def":"id., a favorer (late Lat.): legis, Tert. adv. Marc. 4, 9."},"indultum":{"lemma":"indultum","pos":"","gen":"-class","def":"id., indulgence, permission, grace, favor (post-class.): legis, Cod. Th. 4, 15, 1: principis, id. ib. 3, 10, 1. indultus, a, um, Part., from indulgeo."},"indultus":{"lemma":"indultus","pos":"","gen":"","def":"indulgeo, leave, permission (late Lat.): indultu clementiae tuae scribere, Sid. Ep. 1, 11. indūmentum, i, n. induo, a garment (post-class.). Lit.: indumenta induere, Gell. 16, 19, 12: oris, a mask"},"indus":{"lemma":"Indus","pos":"adj.","gen":"","def":", = Ἰνδός, of or belonging to India, Indian (as an adj. almost exclusively poet.): ebur, Verg. A. 12, 67: dens, ivory, Cat. 64, 48: belua, i. e. elephas, Ov. Tr. 4, 6, 7: conchae, pearls, Prop. 1, 8"},"infanto":{"lemma":"infanto","pos":"v.","gen":"","def":"a. id., to nourish or feed as an infant (late Lat.), Tert. adv. Marc. 1, 14. infantŭla, ae, f. dim. id., a little girl (post-class.), App. M. 10, p. 252, 15"},"infector":{"lemma":"infector","pos":"","gen":"","def":"id., a dyer (class.): eum infector moratur, Cic. Fam. 2, 16, 7: lanarum, Plin. 20, 7, 25, § 59.— Adj., dyeing: infector ille sucus, Plin. 11, 3, 2, § 8. infectōrĭus, a, um, adj. id."},"infectrix":{"lemma":"infectrix","pos":"","gen":"","def":"id., one that infects (eccl. Lat.), Jul. ap. Aug. c. Sec. Resp. Jul. II. 105."},"infectus":{"lemma":"infectus","pos":"adj.","gen":"-factus","def":"2. in-factus. Not made or done, unwrought, unmade, undone, unperformed, unfinished (class.): ubi cognovit, opera quae facta infectaque sient, Cato, R. R. 2, 1: ea, quae sunt facta, infecta refert"},"infenso":{"lemma":"infenso","pos":"v.","gen":"","def":"a. and n. infensus, to treat in a hostile manner, to ravage, destroy (Tacitean)."},"infensus":{"lemma":"infensus","pos":"adj.","gen":"-fendo","def":"2. in-fendo, hostile, inimical, enraged (class."},"infer":{"lemma":"infer","pos":"","gen":"","def":"inferus init. in-fĕrax, ācis, adj., unfruitful (late Lat.): silvae, Hier. Homil. ex Orig. 2. infercĭo, v. infarcio. infĕri, ōrum, v. inferus, I. B. infĕrĭae, ārum, f. plur."},"infernas":{"lemma":"infernas","pos":"adj.","gen":"","def":"infernus, of or from the lower country, lowland (rare): abies, Plin. 16, 39, 76, § 197"},"infernus":{"lemma":"infernus","pos":"adj.","gen":"","def":"infer, lower, that which lies beneath (mostly poet. and postAug.). In gen.: hic sese infernis de partibus erigit Hydra, from beneath, Cic. poët. N. D. 2, 44, 114: superi infernique Di, Liv. 24, 38"},"infertor":{"lemma":"infertor","pos":"","gen":"","def":"(infero), one who serves up dishes, a waiter, steward, παραθέτης, Gloss. Philox.; Schol. Juv. 5, 83"},"infesto":{"lemma":"infesto","pos":"v.","gen":"","def":"a. infestus, to attack, trouble, molest, disturb, infest (mostly post-Aug.). Lit.: Scylla latus dextrum, laevum Charybdis infestant, Ov. M. 13, 730: eas insulas infestari beluis, Plin. 6, 32, 37"},"infirmis":{"lemma":"infirmis","pos":"adj.","gen":"","def":", v. infirmus init. infirmĭtas, ātis, f. infirmus, want of strength"},"infirmo":{"lemma":"infirmo","pos":"v.","gen":"","def":"a. and n. infirmus. Act., to deprive of strength, to weaken, enfeeble. Lit.: legiones, Tac. A. 15, 10: munimenta madore, Sall. Fragm. ap. Non. 138, 6: hominem, Cels. 2, 12.— Trop. To invalidate"},"inflammanter":{"lemma":"inflammanter","pos":"adv.","gen":"","def":", v. inflammo fin. inflammātĭo, ōnis, f. inflammo, a kindling, setting on fire, conflagration. Lit. (post-class.): portarum"},"inflexus":{"lemma":"inflexus","pos":"","gen":"","def":"inflecto, a bending, curving, inflecting (post-Aug.). Lit.: vicorum, Juv. 3, 237: adire inflexibus flexuosis, Arn. 2, 57.— Trop.: vocem inflexu modulationis torquere, Sen. Brev. Vit. 12, 3. inflictĭo"},"inflictus":{"lemma":"inflictus","pos":"","gen":"","def":"infligo, a striking on or against: labiorum et dentium, Arn. 3, 111. in-flīgo, ixi, ictum, 3, v. a., to strike a thing on or against (syn.: incutere, illidere). Lit.: alicui securim, Cic. Planc. 29"},"influxus":{"lemma":"influxus","pos":"","gen":"","def":"id., a flowing in (late Lat.); trop.: stellarum, influence, Firm. Math. 1, 1. in-fŏdĭo, fōdi, fossum, 3, v. a., to dig in or up, make by digging"},"informis":{"lemma":"informis","pos":"adj.","gen":"-forma","def":"2. in-forma, that has no form or not a proper form, unformed, shapeless. Lit.: cum res muta aut informis fit loquens et formata, Auct. Her. 4, 53, 66: alveus, Liv. 21, 26, 9: caro, Plin. 7, 15, 13"},"infraeno":{"lemma":"infraeno","pos":"","gen":"","def":"infreno. infrā-fŏrānus, a, um, adj. forum, that is under the Forum: COLLEGIUM, Inscr. ap. Le-Vita AA. BB. 26, 3. in-frăgĭlis, e, adj., that cannot be broken to pieces. Lit.: adamas"},"infrendis":{"lemma":"infrendis","pos":"adj.","gen":"-frendo","def":"2. in-frendo, that cannot gnash (late Lat.): infantes sine dentibus infrendes dicuntur, Lact. ad Stat. Th. 5, 663."},"ingauni":{"lemma":"Ingauni","pos":"","gen":"-g","def":", a people of Liguria, on the sea - coast, at the foot of the Maritime Alps, Liv. 28, 46; 30, 19.—Hence, Album Ingaunum, their capital city, Varr. R. R. 3, 9, 17; Plin. 3, 5, 7, § 48"},"ingens":{"lemma":"ingens","pos":"adj.","gen":"-genus","def":"2. in-genus, gens, that goes beyond its kind or species, qs. uncouth, monstrous, of immoderate size, vast, huge, prodigious, enormous"},"ingestus":{"lemma":"ingestus","pos":"","gen":"","def":"ingero, a presenting with, bestowment (late Lat.): immortalitatis, Tert. Res. Carn. 42."},"ingressus":{"lemma":"ingressus","pos":"","gen":"","def":"id., a going into, entering, an entrance. Lit.: Antonii in castra, Vell. 2, 63, 2: turba ad ingressum tuum te consalutavit, Plin. Pan. 5, 4"},"inguen":{"lemma":"inguen","pos":"","gen":"-na","def":"(also late Lat. inguĭ-na, ae, f., Isid. 4, 6, 19), the front part of the body between the hips. Lit. The groin.— Sing., Cels. 7, 20: lentum destillat ab inguine virus, Verg. G. 3, 281"},"iniecto":{"lemma":"injecto","pos":"","gen":"","def":"freq. a. id., to lay on, apply (poet.): dextram, Stat. Th. 9, 133; Sil. 3, 183; Luc. 3, 611. injectus, a, um, Part., from inicio."},"iniectus":{"lemma":"injectus","pos":"","gen":"","def":"inicio, a throwing or casting on or over. Lit.: opprimere senem injectu multae vestis, Tac. A. 6, 50; so Plin. 8, 16, 21, § 54; 8, 17, 21, § 60: pulveris, id. 11, 17, 18, § 58"},"inlex":{"lemma":"inlex","pos":"","gen":"","def":"illex. in-lĭcĭtātor, ōris, m., a buyer, purchaser, Paul. ex Fest. p. 113, 14. inlĭcĭum, v. illicium. inlittĕrātus, v. illitteratus. inlūdĭa, v. illudia."},"inneruis":{"lemma":"innervis","pos":"adj.","gen":"-nervus","def":"2. in-nervus, enervated (late Lat.): marcidus et innervis animus, Sid. Ep. 1, 6. innexus, a, um, Part., from innecto. in-nexus, ūs, a false reading in App. M. p. 115, instead of in nexu. innīsus, a"},"innixus":{"lemma":"innixus","pos":"","gen":"","def":"innitor init."},"inp-":{"lemma":"inp-","pos":"","gen":"","def":"imp-. inpraesentĭārum, v. impr-. in-prīmis, v. primus, II. B. in-quaesītus, a, um, adj., i. q. inquisitus, sought for, Tert. adv. Marc. 5"},"insaeptio":{"lemma":"insaeptio","pos":"","gen":"","def":"insaepio, a defined surface, facet, Sen. Q. N. 1, 7, 3. insaeptus, Part. of insaepio."},"inscalp-":{"lemma":"inscalp-","pos":"","gen":"","def":"insculp-. inscalptĭo, v. insculptio."},"inscendo":{"lemma":"inscendo","pos":"v.","gen":"-scando","def":"n. and a. , to step into or upon, to climb up, mount, ascend. Lit.: cum inscenderet in rogum ardentem, Cic. Div. 1, 23, 47: supra pilam inscendat, Cato, R. R. 127, 2: quadrigas Jovis, Plaut. Am. 1, 1"},"inscensus":{"lemma":"inscensus","pos":"","gen":"","def":"inscendo, a mounting, i. e. covering: equarum, App. M. 7, p. 194, 17. inscĭē, adv., v. inscius fin. in-scĭens, entis, adj., unknowing. Without knowledge, unaware: si peccavi, insciens feci"},"inscriptum":{"lemma":"inscriptum","pos":"","gen":"","def":"inscribo, I. B. fin. inscriptūra, ae, f. inscribo, an inscription (al. in scriptura), Tert. adv. Val. 30. inscriptus, a, um, Part., from inscribo."},"insecta":{"lemma":"insecta","pos":"","gen":"","def":"1. inseco fin."},"insectanter":{"lemma":"insectanter","pos":"adv.","gen":"","def":"insector, harshly, bitterly (with graviter): vituperari, Gell. 19, 3, 1. in-sectātĭo, ōnis, f. id., a pursuing, pursuit (class., but not in Cic. or Caes.). Lit.: hostis, Liv. 21, 47, 2.— Trop."},"insecto":{"lemma":"insecto","pos":"v.","gen":"","def":"a., a rare form for insector, to pursue (ante- and postclass.): nos insectabit lapidibus, Plaut. Capt. 3, 4, 61.— Hence, pass.: insectatus, pursued, Auct. B. Afr. 71, 4."},"insector":{"lemma":"insector","pos":"v.","gen":"","def":"dep. a. freq. , to pursue (class.). Lit.: impios agitant insectanturque furiae, Cic. Leg. 1, 14, 40"},"insectum":{"lemma":"insectum","pos":"","gen":"","def":", v. 1. inseco fin. in-sectūra, ae, f. [1. inseco), an incision, Sen. Q. N. 1, 7. insectus, a, um, Part., from 1. inseco."},"inserta":{"lemma":"inserta","pos":"","gen":"","def":"2. insero, an ornament (very rare): frugalitas inserta est rumoris boni, Macr. S. 2, 7. insertātĭo, ōnis, f. inserto, an inserting, Cael. Aur. Tard. 1, 1, 43. insertīcĭus, a, um, adj. 2. insero"},"inserto":{"lemma":"inserto","pos":"v.","gen":"","def":"a. freq. , to put into, insert"},"insessor":{"lemma":"insessor","pos":"","gen":"","def":"id., a besetter, occupant (very rare); of a ship, Jul. Val. Res Gest. Alex. 1, 1: viarum, a waylayer, Symm. Ep. 2, 48"},"insexit":{"lemma":"insexit","pos":"","gen":"","def":"2. inseco. insībĭlātor, m. insibilo, one that breathes in by hissing (late Lat.): venenorum insibilator serpens, Aug. in Joh. 8, 6. in-sībĭlo, 1, v. n. and a., to hiss, whistle"},"insigne":{"lemma":"insigne","pos":"","gen":"","def":"insignis, a mark, sign, signal"},"insignis":{"lemma":"insignis","pos":"adj.","gen":"-signum","def":"in-signum, distinguished by a mark"},"insochi":{"lemma":"Insochi","pos":"","gen":"","def":", a people of Armenia, Tac. A. 13, 37 (dub."},"inspargo":{"lemma":"inspargo","pos":"","gen":"","def":"inspergo. in-spătĭor, āri, v. dep. n., to walk about in a place: inspatiantem (al. exspatiantem), Prud. Apoth. 130. in-spĕcĭātus, a, um, adj., unshapen: substantia informis et inspeciata (late Lat.)"},"inspecto":{"lemma":"inspecto","pos":"part.","gen":"","def":"freq. a. inspicio, to look at, observe, view (class. only in part. pres.): aliquid, Plaut. Poen. 3, 3, 69: nescio quis inspectavit per impluvium, id. Mil. 2, 2, 18: me inspectante, before my eyes"},"inspector":{"lemma":"inspector","pos":"","gen":"","def":"id.. A viewer, observer (post-Aug.), Sen. Ben. 1, 9, 3.— An inspector, examiner (late Lat.), Dig. 13, 6, 10; Cod. Th. 11, 1, 31; Mos. et Rom. Leg. Coll. 15, 1, 2 al."},"inspectrix":{"lemma":"inspectrix","pos":"","gen":"","def":"inspector, she that inspects or examines (late Lat.), Ambros. Ep. 5. inspectus, a, um, Part., from inspicio."},"inspectus":{"lemma":"inspectus","pos":"","gen":"","def":"inspicio. A looking at, inspection, an examination (postAug.): jecoris, Amm. 22, 1, 25.— Contemplation: animus liber ad inspectum, oculis inspectu minacibus, App. M. 10, p. 254, 26: universi"},"inspergo":{"lemma":"inspergo","pos":"v.","gen":"-spargo","def":"18, 11, 29, § 115; and insparsus, id. 26, 14, 87, § 140), 3, v. a. in-spargo, to sprinkle or scatter into or upon"},"inspersus":{"lemma":"inspersus","pos":"","gen":"-class","def":"inspergo, a sprinkling upon, inspersion (post-class.; only in abl. sing.), App. M. 7, p. 197, 35; id. ib. 9, p. 231, 5. inspĭcĭo, spexi, spectum, 3, v. a. inspecio, to look into; to look at, inspect"},"instanter":{"lemma":"instanter","pos":"adv.","gen":"","def":", v. insto fin. instantĭa, ae, f. insto. Lit., a being near or close upon, hence presence: futura quorum consequenti tempore vera erit instantia, ea vera dicimus, Cic. Fat. 12"},"instar":{"lemma":"instar","pos":"","gen":"-class","def":"indecl. perh. in and root sta-"},"instillo":{"lemma":"instillo","pos":"v.","gen":"","def":"a., to pour in by drops, to drop in, to instil (class.). Lit.: haec quoque, nisi tamquam lumini, oleum instilles, extinguuntur senectute, Cic. de Sen. 11: (oleum) caulibus. Hor. S. 2, 2"},"instinctor":{"lemma":"instinctor","pos":"","gen":"","def":"instinguo, an instigator (post-Aug.): sceleris, Tac. H. 1, 22: belli, id. ib. 4, 68; Amm. 21, 12; 30, 1. instinctus, a, um, Part., from instinguo."},"instinctus":{"lemma":"instinctus","pos":"","gen":"","def":"instinguo, instigation, impulse (class.; mostly in abl. sing.): oracula, quae instinctu divino afflatuque funduntur, inspiration, Cic. Div. 1, 18, 34; id. ib. 1, 6 fin."},"instructor":{"lemma":"instructor","pos":"","gen":"","def":"instruo, a preparer: convivii, Cic. post Red. in Sen. 6, 15. instructūra, ae, f. id.. Lit., a building in, enclosure, barrier, Gromat. Vet. p. 347, 8.—Plur., Gromat. Vet. p. 255, 25"},"instructus":{"lemma":"instructus","pos":"","gen":"","def":"instruo, arrangement, preparation (syn. apparatus): oratio eodem est instructu ornatuque comitata, Cic. de Or. 3, 6, 23. instrūmentum, i, n. id., an implement of any kind, a utensil, tool"},"insulsus":{"lemma":"insulsus","pos":"adj.","gen":"-salsus","def":"2. in-salsus, unsalted, insipid. Lit.: amurcā insulsā perfundunt sulcos, Col. 2, 9: gula, that longs for tasteless things, Cic. Att. 13, 31, 4. — Comp.: cibus insulsior, Hier. Ep. 22"},"insulto":{"lemma":"insulto","pos":"v.","gen":"","def":"n. and a. , to spring or leap at or upon a thing, to leap, bound, jump, spring. Lit.: fores calcibus, Ter. Eun. 2, 2, 54: floribus, Verg. G. 4, 11: sub armis Insultare solo, id. ib. 3, 116: busto"},"insultus":{"lemma":"insultus","pos":"","gen":"","def":"id., a scoffing, reviling, insult (eccl. Lat.): insultus et saevae jurgia turbae, Poët. ap. Lact. Carm. de Pass. Chr. 30. insŭlŭla, ae, f., false reading for insula, Cic. Verr. 2, 3, 37, § 85 Lamb."},"insumptum":{"lemma":"insumptum","pos":"","gen":"","def":"id., expense: sumptus, insumptum, Not. Tir. 68. in-sŭo, ŭi, ūtum. 3, v. a., to sew in or into, to sew up in. With acc.: aliquem in culleum, Cic. Rosc. Am. 25, 70"},"intellector":{"lemma":"intellector","pos":"","gen":"","def":"id, one who understands, Aug. Doctr. Christ. 2, 13. intellectŭālis, e, adj. 2. intellectus, of or relating to the understanding, intellectual, App. Dogm. Plat. p. 3, 1"},"intellectus":{"lemma":"intellectus","pos":"","gen":"","def":"intellego, a perceiving, discerning. Lit., perception, discernment by the senses: saporum, Plin. 11, 37, 65, § 174: acrimoniae, id. 19, 8, 54, § 171: nec est intellectus ullus in odore vel sapore"},"intempestus":{"lemma":"intempestus","pos":"adj.","gen":"-tempus","def":"2. in-tempus, unseasonable. Lit.: intempesta nox, the dead of night, Cic. Phil. 1, 3; id. Pis. 38; Cic. Verr. 2, 4, 43, § 94; Verg. A. 3, 587; id. G. 1, 247 al.; cf. Varr. L. L. 6, § 7"},"intento":{"lemma":"intento","pos":"v.","gen":"","def":"a. id., to stretch out or extend towards any thing. Lit.: haec sica intentata nobis est, Cic. Mil. 14: manus, Tac. A. 1, 27: alicui manus, Auct. B. Hisp. 22: cum voces cum manus intentarent, raise"},"intentus":{"lemma":"intentus","pos":"","gen":"","def":"intendo, a stretching out, extending: palmarum, Cic. Sest. 55, 117. in-tĕpĕo, ŭi, 2, v. n., to be lukewarm: et lacus aestivis intepet Umber aquis, Prop. 4 (5), 1, 124. Lernaea palus, Stat. Th. 2"},"inter":{"lemma":"inter","pos":"adv.","gen":"-makers","def":", and prep. with acc. [kindred to in, intra; Sanscr. antar; Goth. undar; Germ. unter"},"inter-aptus":{"lemma":"inter-aptus","pos":"","gen":"-aptus","def":"q. interjunctus, joined together; in tmesi: quae memorare queam inter singillariter apta, Lucr. 6, 1067"},"inter-caelestis":{"lemma":"inter-caelestis","pos":"adj.","gen":"-caelestis","def":", between heaven and earth, Claud. Mam. Stat. An. 2, 12. intercălāris, e, adj. intercalo, of or for insertion, that is to be or is inserted, intercalary: dies, an intercalary day, Plin. 2, 8, 6, § 35"},"inter-culco":{"lemma":"inter-culco","pos":"v.","gen":"-culco","def":"a. calco, to tread between: ita distantes ut interculcari possint vinacea (al. intercalcari), Col. 12, 43, 10."},"inter-cultus":{"lemma":"inter-cultus","pos":"adj.","gen":"-cultus","def":", cultivated, tilled between: fines, Sic. Fl. Cond. Agr. p. 7."},"inter-curro":{"lemma":"inter-curro","pos":"v.","gen":"-curro","def":"n. and a. (tmesis in Lucr. 5, 1374: inter plaga currere). Neutr., to run between. Lit. In gen.: latitudine intercurrentis freti, Plin. 3, 11, 16, § 100.— In partic."},"inter-curso":{"lemma":"inter-curso","pos":"v.","gen":"-curso","def":"n. freq. (tmesis: inter enim cursant, Lucr. 3, 262), to run between. Lit.: intercursantibus barbaris, Liv. 21, 35, 1.— Transf., to be or lie between"},"inter-cus":{"lemma":"inter-cus","pos":"adj.","gen":"-cus","def":"cutis, under the skin, intercutaneous. Esp., as med. t. t.: aqua intercus, the dropsy, Plaut. Men. 5, 4, 3: medicamentum alicui dare ad aquam intercutem, Cic. Off. 3, 24, 42: morbus aquae intercutis"},"inter-ductus":{"lemma":"inter-ductus","pos":"","gen":"-ductus","def":", interpunctuation, Cic. Or. 68, 228."},"inter-dum":{"lemma":"inter-dum","pos":"adv.","gen":"-dum","def":", sometimes, occasionally, now and then, = nonnumquam: interdum fio Juppiter, quando lubet, Plaut. Am. 3, 1, 4: interdum cursus est in oratione incitatior, interdum moderata ingressio"},"inter-for":{"lemma":"inter-for","pos":"v.","gen":"-for","def":"dep. n. and a. (interfari, interfatur, interfatus are the forms in common use), to speak between, to interrupt in speaking (syn. interpello): priusquam ille postulatum perageret, interfatur Appius"},"inter-fringo":{"lemma":"inter-fringo","pos":"v.","gen":"-fringo","def":"a. frango, to break to pieces (ante-class. and post-Aug.): si quid ventus interfregerit, Cato, R. R. 44; Plin. 17, 18, 30, § 127. inter-fŭgĭo, fŭgĕre, v. n., to flee between or into"},"inter-fundo":{"lemma":"inter-fundo","pos":"v.","gen":"-fundo","def":"a. 2. fundo, to pour between"},"inter-iungo":{"lemma":"inter-jungo","pos":"v.","gen":"-jungo","def":"a. and n. To join together, join, unite: dextrae interjunctae, Liv. 22, 30, 6 (cf. interaptus): interjunctus (equus) equis, harnessed among, Stat. Th. 6, 308. — To unyoke. Lit.: lassos equos, Mart. 3"},"inter-mestris":{"lemma":"inter-mestris","pos":"adj.","gen":"-mestris","def":"mensis, between two months: a mensibus intermestris dictus, Varr. L. L. 6, 2, § 10 Müll.: luna, the new moon, Cat. R. R. 37"},"inter-mitto":{"lemma":"inter-mitto","pos":"v.","gen":"-mitto","def":"a. and n. Act. To leave off, intermit, omit, neglect"},"inter-nascor":{"lemma":"inter-nascor","pos":"v.","gen":"-nascor","def":"dep., to grow between or among: internascentes herbae, Plin. 18, 16, 43, § 146: virgulta internata, Liv. 28, 2: internatum corpus, Plin. 17, 27, 42, § 251. inter-nătĭdus, a, um, adj. internates"},"inter-necto":{"lemma":"inter-necto","pos":"v.","gen":"-necto","def":"a., to bind together, bind up (poet.): ut fibula crinem Auro internectat, Verg. A. 7, 816: plagas, to bind up, Stat. Th. 8, 168. inter-nīdĭfĭco, 1, v. n., to build a nest among, Plin. 10, 33, 49"},"inter-nosco":{"lemma":"inter-nosco","pos":"v.","gen":"-nosco","def":"a., to distinguish between, to tell apart, to discern, distinguish (class.): fortuna dignum atque indignum nequit internoscere, Pac. ap. Auct. Her. 2, 23, 36 (Trag. Rel. v. 371 Rib.): gemini duo"},"inter-pello":{"lemma":"inter-pello","pos":"v.","gen":"-pello","def":"a., to interrupt by speaking, to disturb, molest, etc. (syn. obloquor"},"inter-pungo":{"lemma":"inter-pungo","pos":"v.","gen":"-pungo","def":"a., to place points between words, to point, punctuate: cum scribimus, interpungere consuevimus, Sen. Ep. 40.—Hence, inter-punctus, a, um, P. a."},"inter-purgo":{"lemma":"inter-purgo","pos":"v.","gen":"-purgo","def":"a., to cleanse here and there: ficus, Plin. 18, 26, 65, § 243. inter-pŭto, 1, v. a., to prune here and there: ficos, Cato, R. R. 50: oleam, Varr. R. R. 1, 30: rosas, Col. Arb. 30. inter-quĕror"},"inter-regnum":{"lemma":"inter-regnum","pos":"","gen":"-regnum","def":", the time between the death of one king and the election of another, an interregnum: populus flagitare regem non destitit"},"inter-rex":{"lemma":"inter-rex","pos":"","gen":"-rex","def":", one who held the regal office between the death of one king and the election of another; a regent, interrex, Liv. 1, 17"},"inter-scalptus":{"lemma":"inter-scalptus","pos":"adj.","gen":"-scalptus","def":", engraved in the middle, ornamented with carved work in the middle (late Lat.): columnae, Jul. Val. Res Gest. Alex. M. 3, 58. inter-scăpĭlĭum, i, n. scapula"},"inter-scindo":{"lemma":"inter-scindo","pos":"v.","gen":"-scindo","def":"a., to tear asunder, break down; to separate, interrupt (class.). Lit.: pontem, Caes. B. G. 2, 9"},"inter-sisto":{"lemma":"inter-sisto","pos":"v.","gen":"-sisto","def":"n., to stand still in the middle; trop., to stop in the midst, to make a pause in speaking (perhaps only in Quint.)"},"inter-sterno":{"lemma":"inter-sterno","pos":"v.","gen":"-sterno","def":"a., to strew or lay between or among (perh. only in part. pass.): bitumine interstrato, Just. 1, 2, 7: assulis interstratis, Plin. 29, 2, 9, § 34. interstĕs, stĭtis, adj. intersto"},"inter-sto":{"lemma":"inter-sto","pos":"v.","gen":"-sto","def":"n. and a., to stand or be between or in the midst of (post-class.): tempus interstat, Amm. 22, 11, 3"},"inter-stringo":{"lemma":"inter-stringo","pos":"v.","gen":"-stringo","def":"a., to squeeze tight (poet.): alicui gulam, to throttle, strangle, Plaut. Aul. 4, 4, 32. inter-strŭo, struxi, structum, 3, v. a., to join together"},"inter-texo":{"lemma":"inter-texo","pos":"v.","gen":"-texo","def":"a. Lit., to intertwine, interweave, intersperse: flores hederis intertexti, Ov. M. 6, 128: vestis intertexta notis, Quint. 8, 5, 28: chlamys auro intertexta, Verg. A. 8, 167.— Transf., to interweave"},"inter-tortus":{"lemma":"inter-tortus","pos":"adj.","gen":"-tortus","def":", wound between, intertwisted: intertorto pectore, Petr. 124 dub. inter-trăho, traxi, tractum, 3, v. a., to take away, withdraw from: illi animam omnem intertraxero, Plaut. Am. 2, 2"},"inter-turbo":{"lemma":"inter-turbo","pos":"v.","gen":"-turbo","def":"a., to produce disquietude or confusion, to cause a disturbance (ante- and post-class.): ne interturba, Plaut. Bacch. 4, 4, 81; Amm. 18, 2, 5; 26, 4; 31, 12 (but not Ter. And. 4, 1, 39"},"inter-uallo":{"lemma":"inter-vallo","pos":"v.","gen":"-vallo","def":"a. vallum, to take or assume at intervals (post-class.): intervallando potestates assiduas, Amm. 27, 11. — Hence, intervallātus, a, um, P. a., separated, having intervals: febris, intermittent fever"},"intercalco":{"lemma":"intercalco","pos":"","gen":"","def":"interculco. inter-călo, āvi, ātum, 1, v. a., lit., to proclaim that something has been intercalated, to insert, intercalate a day or month (syn.: interpono, intericio)"},"interceptor":{"lemma":"interceptor","pos":"","gen":"","def":"id., an intercepter, usurper, embezzler: praedae, Liv. 4, 50, 1: litis alienae, id. 3, 72, 4: donativi, Tac. H. 3, 10: divini beneficii, one who renders void, Val. Max. 9, 11, 4. interceptus, a, um"},"interceptus":{"lemma":"interceptus","pos":"","gen":"","def":"intercipio, a taking away, Fulg. Myth. 3, 10. intercessĭo, ōnis, f. intercedo, a coming between, intervention. Lit.: testium, Gell. 14, 2, 7.— Transf. An interposition"},"intercessor":{"lemma":"intercessor","pos":"","gen":"","def":"id., one who intervenes. A mediator in money matters, a surety: utinam semper esses tribunus: intercessorem non quaereres, Cic. Fam. 7, 27, 1"},"intercessus":{"lemma":"intercessus","pos":"","gen":"","def":"id., an intervention"},"intercursus":{"lemma":"intercursus","pos":"","gen":"","def":"intercurro, only abl. sing., a running between, intervention, interposition (rare, except in Liv.): periculum intercursu tum primum pubescentis filii propulsatum, Liv. 21, 46"},"intercussus":{"lemma":"intercussus","pos":"","gen":"-quatio","def":"inter-quatio, a striking between: luminis, a flashing between, Sen. Q. N. 3, 27. intercŭtītus, a, um, adj. intercus, greatly abused, dishonored, Paul. ex Fest. p. 113 Müll."},"interdictor":{"lemma":"interdictor","pos":"adv.","gen":"","def":"id., a forbidder, interdicter: delicti, Tert. adv. Marc. 2, 9. interdictōrĭus, a um, adj. interdictor, prohibitory, interdictory, Salv. contr. Avar. 3 med. p. 130 Rittersh."},"interdictum":{"lemma":"interdictum","pos":"","gen":"","def":"interdico. In gen., a prohibition: nequeone ego ted interdictis facere mansuetem meis? Plaut. As. 3, 1, 1: deorum, Cic. Pis. 21, 48.— In partic., as a legal t. t., a provisional decree of the praetor"},"interdictus":{"lemma":"interdictus","pos":"","gen":"","def":", = interdictum, Jul. ap. Aug. contr. Sec. Resp. Jul. 6, 20. Interdidĭum, i, n., a place in Alexandria, Jul. Val. Res Gest. Alex. M. 1, 30 Mai. inter-dĭgĭtālĭa, ĭum, n. plur. , excrescences (warts"},"interfector":{"lemma":"interfector","pos":"","gen":"","def":"id., a slayer, murderer. Lit.: alicujus, Cic. Mil. 27, 72; id. Phil. 1, 14, 35; Nep. Att. 8, 3; Tac. A. 1, 9; 12, 48; 14, 44; Liv. 24, 7, 7"},"interfectrix":{"lemma":"interfectrix","pos":"","gen":"","def":"interfector, a murderess (post-Aug.): nepotis, Tac. A. 3, 17"},"interiectus":{"lemma":"interjectus","pos":"","gen":"","def":"interjacio, a throwing or placing between, interposition"},"intermissus":{"lemma":"intermissus","pos":"","gen":"","def":"intermitto, for intermissio, an intermission, interruption: garrulus sine intermissu cantus, incessant, Plin. 10, 29, 43, § 81."},"internas":{"lemma":"internas","pos":"","gen":"","def":"supernas, inward, inner, Fronto ad Amic. 1, 17."},"internus":{"lemma":"internus","pos":"adj.","gen":"-class","def":"in"},"interpunctum":{"lemma":"interpunctum","pos":"","gen":"","def":"id., i. q. interpunctio, a separating of words by points, interpunctuation: interpuncta verborum, Cic. de Or. 3, 46, 181. interpunctus, a, um, P. a., v. interpungo fin."},"interruptor":{"lemma":"interruptor","pos":"","gen":"","def":"id., an interrupter, spoiler: interruptor, διαφθορεύς, Gloss. Philox. interruptus, a, um, P. a., v. interrumpo fin. inter-saepĭo, saepsi, saeptum, 4, v. a. To fence about, hedge in, stop up, enclose"},"intersaeptum":{"lemma":"intersaeptum","pos":"","gen":"","def":"intersaepio, the midriff, diaphragm: intersaeptum, διάφραγμα, Gloss. Philox. — In gen., a boundary: regnorum, Aus. Grat. Act. § 82. intersaeptus, a, um, Part., from intersaepio. inter-scalmĭum, i"},"interuentor":{"lemma":"interventor","pos":"","gen":"","def":"id.. One who comes in, a visitor: vacuus ab interventoribus dies, Cic. Fat. 1, 2.— A surety, bondsman: si filius fidejussor, vel quasi interventor acceptus sit, Dig. 15, 1, 3.— An intercessor"},"interuentus":{"lemma":"interventus","pos":"","gen":"","def":"id., a coming up, appearance, coming between, intervention. Lit. Of persons: interventus alicujus, Cic. Part. 8, 30: Caleni et Calvenae, id. Att. 16, 11, 1: Pomptini, id. Cat. 3, 3, 6: hominum"},"interuersor":{"lemma":"interversor","pos":"","gen":"","def":"freq. , to turn hither and thither (post-Aug.): interversando, Plin. 9, 50, 74, § 157."},"interuorto":{"lemma":"intervorto","pos":"","gen":"","def":"interverto. intervulsus, a, um, Part., from intervello. in-testābĭlis, e, adj., that is incapable, by reason of misconduct"},"intextus":{"lemma":"intextus","pos":"","gen":"","def":"intexo, an interweaving, joining together, Plin. 2, 8, 6, § 30 (but in Quint. 8, 4, 8, contextu is the true reading). in-thrŏnizo, 1, v. a. thronus, to enthrone, Cassiod. Hist. Eccl. 12"},"intinctus":{"lemma":"intinctus","pos":"","gen":"","def":"intingo, a dipping in; concr., a sauce or pickle in which meat, etc., is dipped, Plin. 20, 7, 26, § 65; 20, 9, 33, § 81"},"intonsus":{"lemma":"intonsus","pos":"adj.","gen":"-tondeo","def":"2. in-tondeo, unshorn. Lit.: scindens dolore identidem intonsam comam, Acc. ap. Cic. Tusc. 3, 26: capilli, Hor. Epod. 15, 9: crinis, Tib. 1, 4,38: Cynthius, Hor. C. 1, 21, 2: deus, Ov. Tr. 3, 1, 60"},"intus":{"lemma":"intus","pos":"adv.","gen":"-tus","def":"1. in and the abl. termination -tus; Sanscr. -tas"},"intybus":{"lemma":"intybus","pos":"","gen":"","def":"intibus. ĭn-ūber, ūbēris, adj., not full, ill-fed, ill-conditioned, poor: ostreae, Gell. 20, 8, 3. ĭn-ūdo, āre, v. a., to wet, moisten: manus labris, Paul. Nol. Carm. 18, 418. ĭnŭla, ae, f. ἑλένιον"},"inuector":{"lemma":"invector","pos":"","gen":"-class","def":"inveho, one who brings in, an importer (post-class.): lanati pecoris, Symm. Ep. 10, 27."},"inuectrix":{"lemma":"invectrix","pos":"","gen":"-class","def":"invector, she that brings in or introduces (post-class.): mali, Ambros. Ep. 63, 3. invectus, a, um, Part. and P. a., v. inveho."},"inuectus":{"lemma":"invectus","pos":"","gen":"","def":"inveho, a bringing in (post-Aug.), only in abl. sing.: terrae invectu, Plin. 4, 1, 2, § 5"},"inuentor":{"lemma":"inventor","pos":"","gen":"","def":"invenio, one that finds out, a contriver, author, discoverer, inventor (class.): o mearum voluptatum omnium Inventor, inceptor, perfector, Ter. Eun. 5, 9, 5: Aristaeus, qui olivae dicitur inventor"},"inuentrix":{"lemma":"inventrix","pos":"","gen":"","def":"inventor, she that finds out or invents, an inventress (class.): omnium doctrinarum inventrices Athenae, Cic. de Or. 1, 4, 13: belli, id. N. D. 3, 21, 53: carminis hujus, Ov. F. 6, 709."},"inuentum":{"lemma":"inventum","pos":"","gen":"","def":"invenio, a device, contrivance, invention (class.): ut te omnes di cum istoc invento atque incepto perduint, Ter. Heaut. 4, 6, 7: inventa Zenonis, Cic. Mur. 29, 61: inventum medicina meum est"},"inuentus":{"lemma":"inventus","pos":"","gen":"","def":", only in abl. sing. , an invention (for inventio), Plin. 17, 21, 35, § 162. invĕnustē, adv., v. invenustus fin. in-vĕnustus, a, um, adj. Not elegant or graceful, ungraceful, not beautiful"},"inuersum":{"lemma":"inversum","pos":"adv.","gen":"","def":", v. inverto fin. inversūra, ae, f. inverto, a turn, curve: aditus sine inversuris, Vitr. 5, 3, 5. inversus, a, um, Part. and P. a., v. inverto fin. invertĭbĭlĭtas, ātis, f. 2. in-verto"},"inuictrix":{"lemma":"invictrix","pos":"adj.","gen":"-class","def":", adj. invictus, unconquerable (post-class.): invictricis Fortunae filius, Inscr. ap. Grut. 1065, 6."},"inuinctus":{"lemma":"invinctus","pos":"adj.","gen":"-vincio","def":"1. in-vincio, fettered (post-class.): aliquem invinctum habere (al. in vinculis), Dig. 48, 15, 6, § 2. invīnĭus, a, um, adj. 2. in-vinum, that abstains from wine (post-class.), App. M. 11, p. 268"},"inuolgo":{"lemma":"involgo","pos":"","gen":"","def":"invulgo. invŏlĭto, āvi, ātum, 1, v. n. freq. , to fly over a place. Lit., with dat.: nec minus involitat terris, Prud. 13, 100. — Transf., of inanim. things"},"iol":{"lemma":"Iol","pos":"","gen":"","def":", the former name of the city of Caesarea in Numidia, now Ser-Sel, Plin. 5, 2, 1, § 20"},"iollas":{"lemma":"Iollas","pos":"","gen":"","def":"A Trojan, Verg. A. 11, 640.— A shepherd, Verg. E. 2, 57; 3, 76. — A Greek writer on medicine, Plin. 34, 10, 22, § 104 al. ĭon, ĭi, n. ἴον. A kind of violet, Plin. 21, 11, 38, § 64"},"ios":{"lemma":"Ios","pos":"","gen":"","def":", = Ἴος, a small island of the Sporades, in the Aegean Sea, now Nio, Mel. 2, 7, 11"},"ipra":{"lemma":"Ipra","pos":"","gen":"","def":"the foll. art."},"iprasturgi":{"lemma":"Iprasturgi","pos":"","gen":"","def":"3, 1, 3, § 10 (Jahn reads Ipra, Isturgi). ipse (ipsus, Cato, R. R. 70; 71; Plaut. Ps. 4, 7, 43; id. Trin. 2, 2, 40; 3, 1, 10 et saep.; Ter. And. 3, 2, 15; id. Eun. 3, 4, 8, id. Hec. 3, 5, 5"},"ir":{"lemma":"ir","pos":"","gen":"","def":"hir. īra, ae (gen. iraï for irae, Lucr. 3, 303), f. kindred to Sanscr. īr, tremere, commoveri; cf.: ir-ya, vigorous; iras-yati, to be angry"},"ircus":{"lemma":"ircus","pos":"","gen":"","def":"hircus. īrēnācĕus, i, m., a hedgehog (al. erinaceus, herinaceus), Plin. 8, 37, 56, § 133; 10, 63, 83, § 174; 30, 8, 21, § 65"},"iresiae":{"lemma":"Iresiae","pos":"","gen":"","def":", a city of Thessaly, Liv. 32, 13, 9. īrī and īrĭer, v. 1. eo. Irĭātes, ium, m., the inhabitants of Julia Iria, in Liguria, near Dertona (now Voghierro), Liv. 31, 10 (cf. Plin. 3, 5, 7"},"irpus":{"lemma":"irpus","pos":"","gen":"","def":"Sabine, a wolf: (lupus) quem irpum dicunt Samnites, Paul. ex Fest. p. 106 Müll."},"irraucus":{"lemma":"irraucus","pos":"adj.","gen":"","def":"id., hoarse: vox, Plin. Val. 1, 2. irrĕcĭtābĭlĭter, adv. 2. in-recito, unutterably, unspeakably, Venant. Carm. 3, 9, 49. irrĕcōgĭtātĭo (inr-), ōnis, f. 2. inrecogitatio, inconsiderateness"},"irruptus":{"lemma":"irruptus","pos":"","gen":"","def":"id., an irruption (late Lat.), Fab. Claud. Gord. Fulg. Aet. Mund. 11, p. 141. irruptus (inr-), a, um, Part., from irrumpo. irruptus (inr-), a, um, adj. 2. in-rumpo, unbroken, unsevered: copula"},"is":{"lemma":"is","pos":"pron.","gen":"-class","def":"eis, C. I. L. 1, 198; n. it, ib. 5, 875 al., and freq. in MSS. of Plaut.), gen. ējus (old form eiius, C. I. L. 3, 1365 et saep.; v. Prisc. 1, 4, 18, p. 545; also etius, ib. 2, 1276 al."},"isacia":{"lemma":"Isacia","pos":"","gen":"","def":", an island opposite Velia (v. Oenotrides), Plin. 3, 7, 13, § 85. Īsaeus, i, m., = Ἰσαῖος. A Grecian orator of Chalcis, instructor of Demosthenes, Quint. 12, 10"},"isauri":{"lemma":"Isauri","pos":"adj.","gen":"-r","def":", an Asiatic tribe between Pamphylia, Lycaonia, and Cilicia, Isaurians, Liv. Epit. 93; Mel. 1, 2; Amm. 14, 2, 1; also, of their country, Cic. Fam. 15, 2, 1"},"isaurus":{"lemma":"Isaurus","pos":"","gen":"","def":", a river in Picenum, now Foglia, Luc. 2, 406."},"ischaemon":{"lemma":"ischaemon","pos":"","gen":"","def":", = ἴσχαιμον, a kind of styptic herb, Plin. 25, 8, 45, § 83; 26, 12, 82, § 131. ischĭa, ōrum, n., = ἰσχία, the hipjoints, the hips (Lat. coxae), Gell. 4, 13, 1"},"isiondensis":{"lemma":"Isiondensis","pos":"adj.","gen":"","def":", of or belonging to the city of Isionda (in the southwest of Pisidia), Isiondian, Liv. 38, 15 dub. Īsis, is, and ĭdis. f., = Ἶσις, the Egyptian goddess Isis, Cic. N. D. 3, 19, 47; Ov. M. 9, 772"},"issa":{"lemma":"Issa","pos":"adj.","gen":"","def":", = Ἴσσα, an island in the Adriatic Sea, near Illyria, with a town of the same name, now Lissa, Plin. 3, 26, 30, § 152; Caes. B. C. 3, 9"},"issus":{"lemma":"issus","pos":"adj.","gen":"","def":", a childish form of ipse, used with little children as a term of endearment: ISSA HAVE, Inscr. ap. Fabr. p. 45, n. 255.—Issa, the name of a pet slut, Mart. 1, 109.—Also dim.: ‡ issŭlus, a, um"},"istaec":{"lemma":"istaec","pos":"","gen":"","def":"istic. Istaevŏnes, um, m. (al. Istyaeŏnes), an ancient people of Germany bordering on the Rhine, Tac. G. 2; Plin. 4, 14, 28, § 100."},"iste":{"lemma":"iste","pos":"pron.","gen":"-ta","def":"istīus (the poets often make the penult of the gen. short: istĭus, Verg. A. 12, 648: istius, dissyl., Plaut. Most. 3, 2, 59"},"ister":{"lemma":"Ister","pos":"","gen":"","def":"Hister. Isthmus or -os, i, m., = Ἰσθμός, a strip of land between two seas, an isthmus, Mel. 1, 18; 2, 2.— Esp., the Isthmus of Corinth, where the Isthmian games were celebrated, Caes. B. C. 3, 55, 2"},"isti":{"lemma":"isti","pos":"adv.","gen":"","def":", v. istic init. istic (not isthic), aec, oc, and uc, pron. demonstr. [for iste-ce"},"istim":{"lemma":"istim","pos":"adv.","gen":"","def":"iste, thither, to that place (very rare): nolite, hospites, ad me adire! ilico istim! Enn. ap. Cic. Tusc. 3, 12, 26 (Enn. Trag. v. 404 Vahl., and Trag. Rel. v. 303 Rib., isti"},"istinc":{"lemma":"istinc","pos":"adv.","gen":"-ce","def":"istim-ce"},"istoc":{"lemma":"istoc","pos":"adv.","gen":"","def":"istic, thither, that way, yonder: quemquam istoc ad vos intromittere, Plaut. Truc. 4, 2, 6: accede illuc: nimium istoc abisti, Ter. Ad. 2, 1, 15; v. also istic."},"istorsum":{"lemma":"istorsum","pos":"adv.","gen":"-versum","def":"isto-versum, thitherwards: concede hinc a foribus paululum istorsum, sodes, Ter. Phorm. 5, 1, 14; id. Heaut. 3, 3, 27. Istri (Histri), ōrum, m., the inhabitants of Istria, the Istrians, Liv. 41, 11"},"istuc":{"lemma":"istuc","pos":"adv.","gen":"","def":"isto- (iste) ce, thither, esp. in reference to the place where the party addressed is: concedite istuc, Plaut. As. 3, 3, 56: istuc eo quantum potest, id. Merc. 4, 1, 25: jam istuc ego revortar"},"isturgi":{"lemma":"Isturgi","pos":"","gen":"","def":"Iprasturgi. Istyaeŏnes, um, m., a German tribe, Plin. 4, 14, 28, § 100 (Jan.). ĭta, adv. pronom. stem i-; cf. is; Sanscr. itthā"},"itis":{"lemma":"itis","pos":"","gen":"","def":", a Tuscan word meaning day, from which Idus is derived, Macr. S. 1, 15. ĭtĭto, āre, v. freq. n. , to go: exsequias ititant, Naev. ap. Calp. Pis."},"itylus":{"lemma":"Itylus","pos":"","gen":"","def":", = Ἴτυλος, the son of Ze thus, Cat. 65, 13 (where Itylus is confounded with Itys). Itȳraeus, a, um, v. Ituraeus."},"itys":{"lemma":"Itys","pos":"","gen":"","def":", = Ἴτυς. Son of Tereus and Progne; he was killed by his mother and served up to his father for food"},"iuerna":{"lemma":"Iverna","pos":"","gen":"","def":"Hibernia. ixĭa, ae, f., = ἰξία, the chameleon plant, Plin. 22, 18, 21, § 45. Ixīon, ŏnis, m., = Ἰξίων, the son of Phlegyas (acc. to others, of Antion or of Jupiter), king of the Lapithae in Thessaly"},"iugo":{"lemma":"jugo","pos":"v.","gen":"","def":"n., to utter the note of the kite (milvus), Varr. ap. Non. 179, 2"},"iuliacum":{"lemma":"Juliacum","pos":"","gen":"","def":", a city of Gallia Belgica, now Juliers, Amm. 17, 4. Jūlĭānus, a, um, adj. Julius, of or belonging to Julius Caesar, Julian: vectigalia, i. e. which were introduced by Julius Caesar"},"iunctim":{"lemma":"junctim","pos":"adv.","gen":"","def":", v. jungo fin."},"iunctio":{"lemma":"junctio","pos":"","gen":"","def":"jungo, a joining, uniting, union, Cic. Tusc. 1, 29, 71."},"iunctor":{"lemma":"junctor","pos":"","gen":"","def":"id., a harnesser, Dig. 50, 16, 203 fin. junctūra, ae, f. id., a joining, uniting"},"iunctus":{"lemma":"junctus","pos":"","gen":"-class","def":"jungo, a joining (ante-class.): Carinarum, Varr. L. L. 5, § 47, Müll."},"iuncus":{"lemma":"juncus","pos":"","gen":"","def":", a rush. Lit.: murteta juncis circumvincire, Plaut. Rud. 3, 4, 27: palustres, Ov. M. 8, 336: acutā cuspide junci, id. ib. 4, 299.— A twig resembling a rush, Plin. 26, 8, 46, § 72."},"iungo":{"lemma":"jungo","pos":"v.","gen":"-tus","def":"a. Sanscr. jug, junagmi, to unite; juk, joined; Goth. juk; O. H. Germ. joh, joch"},"iurgor":{"lemma":"jurgor","pos":"","gen":"","def":"jurgo. jūrĭdĭcātus, ūs, m. juridicus, a judgeship, jurisdiction, Inscr. Orell. 3117. jūrĭdĭcĭālis, e, adj. id., relating to right or justice (class.): juridicialis constitutio est"},"iuscellum":{"lemma":"juscellum","pos":"","gen":"","def":"dim. jusculum, broth, soup (late Lat.), Theod. Prisc. 2, 13; plur., Ven. Carm. 6, 10, 18"},"iussum":{"lemma":"jussum","pos":"","gen":"","def":"jubeo, an order, command; a law (class.; mostly in plur.; the abl. sing. is supplied by jussu"},"iusta":{"lemma":"justa","pos":"","gen":"","def":"justus, B. 2. justē, adv., v. justus fin. justĭfĭcātĭo, ōnis, f. justifico, justification (late Lat.), Salv. Avar. 3, 2"},"iustus":{"lemma":"justus","pos":"adj.","gen":"-sta","def":"2. jus, just, upright, righteous. Lit.: justus et bonus vir, Cic. Off. 2, 12, 42: digna esse justo homine, eoque quem virum bonum dicimus, id. ib. 1, 10, 31: in amicitia parum justus, id. Lael. 20"},"iuxtim":{"lemma":"juxtim","pos":"adv.","gen":"","def":"and prep. juxta, next to, close by. Adv.: in sedes collocat se regias Clytaemnestra juxtim, Liv. Andron. ap. Non. 127, 32 (Trag. Rel. p. 2 Rib.): assidebat juxtim, Suet. Tib. 33.— In partic."},"ixor":{"lemma":"Ixor","pos":"","gen":"","def":", a river in Gaetulia, Plin. 5, 1, 1, § 13. ĭynx, iyngis, f., = ἴυγξ, the wryneck, a bird made use of in conjurations and charms"},"izi":{"lemma":"Izi","pos":"","gen":"","def":", a people of India, Plin. 6, 17, 21, § 64 Jan. (al. Izzi). J J, j, a consonant which, although originally represented by the same character as the vowel i"},"kalo":{"lemma":"Kalo","pos":"","gen":"","def":"calo. Karthāgo, v. Carthago. Koppa (Coppa), n. indecl., = κόππα, a letter of the original Greek alphabet, in which it stood between π and ρ"},"labda":{"lemma":"labda","pos":"","gen":"-class","def":"indecl., = λάμβδα, the Greek letter Λ; supinum, i. e. an inverted V, Mart. Cap. 9, § 943. † labda, ae, m., = λάβδα, a voluptuary, i. q. irrumator (ante- and post-class.), Varr. ap. Non. 70, 11"},"labro":{"lemma":"Labro","pos":"","gen":"","def":", prob. a seaport in Etruria, where stands the modern Livorno (Leghorn), Cic. Q. Fr. 2, 6, 2. lābros or -us, = λάβρος (greedy). A fish, otherwise unknown, Plin. 32, 11, 54, § 152 (Jahn"},"laburnum":{"lemma":"laburnum","pos":"","gen":"-leaved","def":", the broad-leaved beantrefoil: Cytisus laburnum, Linn.; Plin. 16, 18, 31, § 76; 17, 22, 35, § 174. lăbyrinthus, i, m., = λαβύρινθος, a labyrinth, a building with many winding passages"},"lac":{"lemma":"lac","pos":"","gen":"-white","def":"lacte, Enn. ap. Non. 483, 2; Plaut. Mil. 2, 2, 85; id. Bacch. 5, 2, 16 Ritschl N. cr. al.; and lact, Aus. Idyll. 12; Mart. Cap. 3, § 307; masc. acc. lactem, App. M. 8, p. 214 fin.; 215 init."},"lacca":{"lemma":"lacca","pos":"","gen":"-cattle","def":"A swelling on the shinbone of draught-cattle, Veg. Vet. 1, 27, 4; 3, 18.— A plant, otherwise unknown, App. Herb. 3 fin."},"laccar":{"lemma":"laccar","pos":"","gen":"","def":", a plant, Plin. Val. 2, 17. Lăcĕdaemōn (nom. Lăcĕdaemo, Cic. Leg. 2, 15, 39"},"lacta":{"lemma":"lacta","pos":"","gen":"","def":", a kind of cassia, Plin. 12, 19, 43, § 97; al. lada. lactānĕus, a, um, adj. lac, milk-like, milky: color, Th. Prisc. 4, 2. lactans, P. and P. a., of lacto, q. v."},"lactans":{"lemma":"Lactans","pos":"","gen":"","def":"lac, the god of milky growth in corn: Lactantem deum esse qui se infundit segetibus, et eas facit lactescere, Varr. ap. Sen. Verg. G. 1, 315. Lactantĭus, ii, m., with the surname Firmianus"},"lacte":{"lemma":"lacte","pos":"","gen":"","def":"lac init. lactĕo, ēre (used almost exclusively in the part. pres.), v. a. lac. To suck milk, to be a suckling: Romulus parvus atque lactens, uberibus lupinis inhians, Cic. Cat. 3, 8, 19"},"lacteris":{"lemma":"lacteris","pos":"","gen":"","def":", a plant, App. Herb. 111. lactes, ium (in sing. lactis, is, only, acc. to Prisc. p. 686, erroneously on account of lactis agninas), f. root lag-; Gr. λαγαρός"},"lactesco":{"lemma":"lactesco","pos":"","gen":"","def":"inch. n. . * To turn to milk: omnis fere cibus matrum lactescere incipit, Cic. N. D. 2, 51, 128"},"lactis":{"lemma":"lactis","pos":"","gen":"","def":"lactes. lactĭto, 1, v. freq. a. 1. lacto, to give suck, to suckle (poet.), Ps.-Mart. 7, 102, 3."},"lacto":{"lemma":"lacto","pos":"v.","gen":"","def":"pres.), 1, v. a. and n. lac. To contain milk, to have milk, to give suck: ubera lactantia, Ov. M. 6, 342; 7, 321"},"lacturnus":{"lemma":"Lacturnus","pos":"","gen":"","def":"the preced. art. lăcŭlātus, a, um, adj. lacus, four-cornered, checkered: vestis, woven in square compartments or checks, with inwoven or embroidered pictures (v. lacus, V.), Isid. Orig. 19, 22"},"laeca":{"lemma":"Laeca","pos":"","gen":"","def":", a Roman surname"},"laedo":{"lemma":"laedo","pos":"v.","gen":"","def":"a. perh. for lavido, root lu-"},"laelaps":{"lemma":"Laelaps","pos":"","gen":"","def":"λαίλαψ, hurricane, name of a dog, Ov. M. 3, 211"},"laena":{"lemma":"laena","pos":"","gen":"","def":", = χλαίνη, a lined upper garment, a cloak, mantle: laena vestimenti genus habitu duplicis. Quidam appellatam existimant Tusce, quidam Graece, quam χλανίδα dicunt"},"laenas":{"lemma":"Laenas","pos":"","gen":"","def":"Popilius. laeŏtŏmus, i, f., = λαιότομος, the chord of a segment of a circle, Vitr. 9, 8, 6 Schneid. N. cr. (al. lacotomus). Lāërtes, ae (nom. Laërta, Sen. Troad. 699"},"laeta":{"lemma":"laeta","pos":"","gen":"","def":"2. laetus. laetābĭlis, e, adj. laetor, joyful, glad, gladsome (class.): quid habet ista res aut laetabile, aut gloriosum? Cic. Tusc. 1, 21, 49: nihil laetabile, id. ib. 4, 17, 37: factum, Ov. M. 9"},"laetanter":{"lemma":"laetanter","pos":"adv.","gen":"","def":", v. laetor fin. laetātĭo, ōnis, f. laetor, rejoicing, exultation, joy (for the usual laetitia): diutina, Caes. B. G. 5, 52 fin. laetē, adv., v. 1. laetus fin. laetĭcŭlōsus, a, um, adj. laetor"},"laetisco":{"lemma":"laetisco","pos":"v.","gen":"","def":"n. inch. , to rejoice, Sisenn. ap. Non. 133, 2. laetĭtĭa, ae, f. id., joy, esp. unrestrained joyfulness, gladness, pleasure, delight (cf.: gaudium"},"laeto":{"lemma":"laeto","pos":"v.","gen":"-class","def":"a. id., to make joyful, to delight, cheer, gladden. Lit. (ante- and post-class.): oculos specie laetavisti optabili, Liv. Andron. ap. Non. 132, 32: te ut triplici laetarem bono"},"laetor":{"lemma":"laetor","pos":"v.","gen":"","def":"dep. n. , to rejoice, feel joy, be joyful or glad at any thing (syn. gaudeo)"},"laetus":{"lemma":"laetus","pos":"adj.","gen":"","def":"Sanscr. root prī-, to cheer; prētis, joy, love; cf. Gr. πραΰς, πρᾷος; Germ. Friede, Freude"},"laeua":{"lemma":"laeva","pos":"","gen":"","def":", the left hand, v. laevus, I. B. 1. laevātus, v. levatus. laevē, adv. v. laevus fin. Laevi (Lēvi), ōrum, m., the Laevi, an ancient people of Liguria, between the Po and the Ticinus, Liv. 33, 37, 6"},"laeuis":{"lemma":"laevis","pos":"","gen":"","def":"1. levis, etc. Laevĭus, ii, m., a Roman poet of the ante-clussical period, Gell. 2, 24, 8; 19, 9, 7"},"laeuus":{"lemma":"laevus","pos":"adj.","gen":"","def":"cf. Gr. λαιός, left, on the left side (mostly poet.; syn.: sinister, scaevus). Lit.: ut idem nunc sit laevus"},"lago":{"lemma":"lago","pos":"","gen":"","def":", a plant, otherwise called schite"},"lagos":{"lemma":"Lagos","pos":"","gen":"","def":", a city in Great Phrygia, Liv. 38, 15, 2. lăguncŭla, ae, f. dim. lagena, a small flask, small bottle, Col. 12, 38, 6; 8; Plin. Ep. 2, 6, 2; 1, 6, 3: novae, Vulg. Job, 32, 19; id. Jer. 13, 12"},"lallo":{"lemma":"lallo","pos":"v.","gen":"","def":"n., to sing lalla or lullaby, to sing as a nurse to a child: iratus mammae, lallare recusas, will not let yourself be sung to sleep, Pers. 3, 17; Hier. Ep. 14, 3: lallare βαβάζειν, Gloss. Philox."},"lallum":{"lemma":"lallum","pos":"","gen":"-class","def":", or lallus, i, m. lallo, a singing lalla or lullaby (post-class.), Aus. Ep. 16, 91. lāma, ae, f. (cf.: lacus, lacer). A slough, bog, fen: lacuna id est aquae collectio, quam alii lamam, alii lustrum"},"lambo":{"lemma":"lambo","pos":"v.","gen":"","def":"lambuerunt, Vulg. Jud. 7, 7 al.), 3, v. a. root lap-; Gr. λάπτω, λαφύσσω; Lat. labrum, labium; Germ. Löffel, spoon; Eng. lip, to lick, lap; to touch (class."},"lambrus":{"lemma":"Lambrus","pos":"","gen":"","def":", a small river in northern Italy, a tributary of the Po, Plin. 3, 19, 23, § 131 al. lāmella, ae, f. dim. lamina, a small plate of metal, Vitr. 7, 3: paucae lamellae argenti, a few small silver coins"},"lamna":{"lemma":"lamna","pos":"","gen":"","def":"lamina init. lamnŭla, ae, f. dim. lamina for lamella, a little plate of metal (eccl. Lat.): triumphi laurea lamnulis ornatur, Tert. Coron. Mil. 12 dub. (al. lamnis). lampābĭlis, e, adj. lampo"},"lampadio":{"lemma":"Lampadio","pos":"","gen":"","def":", the name of a slave, Plaut. Cist. 2, 3, 50. Lampădiscus, i, m., the name of a slave, Plaut. Cist. 2, 3, 2. lampădo, ōnis, m., i. q. bulbus, Theod. Prisc. de Diaeta, 9. lampăs"},"lampo":{"lemma":"lampo","pos":"v.","gen":"","def":"n. lampas, to shine (eccl. Lat.); only trop. of eloquence, Cassiod. Inst. Div. Litt. 21."},"lampon":{"lemma":"Lampon","pos":"","gen":"","def":", = Λάμπων, the name of a horse, Sil. 16, 334. Lamprĭdĭus, ii, m. Aelius, a Roman historiographer, one of the Scriptores Historiae Augustae, Vopisc. Prob. 2 fin."},"lampus":{"lemma":"Lampus","pos":"","gen":"","def":"One of Actaeon's hounds, Hyg. Fab. 181.— One of the four horses of the sun, Fulg. Myth. 1, 11. lampȳris, ĭdis, f., = λαμπυρίς, a glowworm, Plin. 11, 28, 34, § 98. Lămus, i, m."},"lances":{"lemma":"lances","pos":"","gen":"","def":"lanx. Lancĭa, ae, f., a city of Hispania Tarraconensis, now Castro, Flor. 4, 12"},"langa":{"lemma":"langa","pos":"","gen":"","def":"Celtic, a kind of lizard, from whose urine the stone called langurium (lyncurium) was said to be produced, Plin. 37, 2, 11, § 34. Langŏbardi, ōrum, m., a people of northern Germany, west of the Elbe"},"languesco":{"lemma":"languesco","pos":"","gen":"","def":"inch. n. , to become faint, weak, languid (class."},"languor":{"lemma":"languor","pos":"","gen":"","def":"langueo, faintness, feebleness, weariness, sluggishness, languor, lassitude. Lit. In gen. (class."},"lanx":{"lemma":"lanx","pos":"","gen":"","def":"cf. λέκος, λεκάνη, a plate, platter, charger, dish (class."},"lapis":{"lemma":"lapis","pos":"n. m.","gen":"-idis","def":"a stone, rock; a milestone; gemstone; marble"},"lappa":{"lemma":"lappa","pos":"","gen":"","def":", a bur, Verg. G. 1, 153; Ov. P. 2, 1, 14; Plin. 18, 17, 44, § 153; 21, 17, 64, § 104 al.— Lappa, ae, m., a Roman surname"},"lapso":{"lemma":"lapso","pos":"","gen":"-class","def":"freq. n. , to slip, slide, stumble, fall. Lit. (poet. and in postAug. prose): (Priamum) in multo lapsantem sanguine nati, Verg. A. 2, 551: sanguine suo et lubrico paludum lapsantes (equi), Tac. A. 1"},"lapsus":{"lemma":"lapsus","pos":"","gen":"","def":"1. labor, a falling, fall"},"lardum":{"lemma":"lardum","pos":"","gen":"","def":"laridum. Lārentĭa (Lārentīna, Lact. 1, 20 init.), ae, f. (also called Acca Larentia), acc. to the myth, the wife of Faustulus, and mother of the twelve Arval Brothers"},"larga":{"lemma":"Larga","pos":"","gen":"","def":", the name of a woman of bad repute, Juv. 14, 25. largē, adv., v. 1. largus fin. A. Largĭānus, a, um, v. 2. Largus. largĭfĭcus, a, um, adj. largus-facio, bountiful, Lucr. 2"},"largus":{"lemma":"largus","pos":"adj.","gen":"-class","def":"perh. for lasgus; Sanscr. root lash, desire; Gr. λᾶ- in λιλαίομαι, λῆμα"},"lars":{"lemma":"Lars","pos":"","gen":"","def":"1. Lar. Lartidĭus, i, m., prop. name, an imitator of Ulysses, Cic. Att. 7, 1, 9. Lărunda, ae, v. Lara. lărus (lăros), i, m., = λάρος, a ravenous sea-bird, perh. the mew, Vulg. Lev. 11, 16"},"laruo":{"lemma":"larvo","pos":"v.","gen":"-class","def":", ātum (part. ante-class. larŭātus), 1, v. a. larva, to bewitch, enchant (ante- and post-class., and used almost exclusively in the part. perf.): artus larvari, Firm. Math. 3"},"larymna":{"lemma":"Larymna","pos":"","gen":"","def":", the name of a small town in Boeotia, Mel. 2, 3"},"lassesco":{"lemma":"lassesco","pos":"","gen":"","def":"inch. n. , to become tired, to grow weary (post-Aug.): ne lassescat fortuna, Plin. 7, 40, 41, § 130"},"lasso":{"lemma":"lasso","pos":"v.","gen":"","def":"a. lassus, to render faint or languid, to tire, weary, fatigue, to deprive of vigor (syn.: fatigo, languefacio"},"lassus":{"lemma":"lassus","pos":"adj.","gen":"","def":"etym. dub.; acc. to Bopp, Gloss. 112, 6, for glassus from glasnus; kindred to Sanscr. glasnu, fessus, defessus, lassus; but more prob. collat. form of laxus"},"lastaurus":{"lemma":"lastaurus","pos":"","gen":"","def":", = λάσταυρος, a lewd person, debauchee, Suet. Gramm. 15. latăcē, ēs, f., a magic herb, Plin. 26, 4, 9, § 18. lātē, adv., v. 1. latus fin. lătēbra, ae, f. lateo, a hiding-place, lurking-hole, covert"},"lathyris":{"lemma":"lathyris","pos":"","gen":"-thyr","def":"(collat. form, lā-thyr, Ser. Samm. 1099), = λαθυρίς, a plant, a kind of wolf's-milk, Plin. 27, 11, 71, § 95."},"lathyros":{"lemma":"lathyros","pos":"","gen":"","def":", = λάθυρος, a plant, also called leontopodion, App. Herb. 7. Lătĭālis, e; Lătĭālĭter, Lătĭar, āris; Lătĭāris, e"},"latmus":{"lemma":"Latmus","pos":"adj.","gen":"","def":", = Λάτμος, a mountain in Caria, at the mouth of the Maeander, where Luna (Selene) kissed the sleeping Endymion, Cic. Tusc. 1, 38, 92; Mel. 1, 17"},"latobius":{"lemma":"Latobius","pos":"","gen":"","def":", an almost unknown deity, Inscr. Orell. 2019."},"latobrigi":{"lemma":"Latobrigi","pos":"","gen":"","def":", a Gallic people, neighbors of the Helvetians, situated probably on the Rhine, Caes. B. G. 1, 5"},"laudo":{"lemma":"laudo","pos":"v.","gen":"-gen","def":"a. laus, to praise, laud, commend, extol, eulogize, approve (cf.: celebro, praed co). Lit. In gen.: omnes mortales sese laudarier optant, Enn. ap. Aug. Trin. 13"},"laurentum":{"lemma":"Laurentum","pos":"adj.","gen":"-rent","def":", a maritime town in Latium, between Ostia and Lavinium, now Torre Paterno, Mel. 2, 4, 9.—Hence, Laurens, entis, adj. Of or belonging to Laurentum, Laurentian: Laurens Thybris, Verg. A. 5, 797: arva"},"laurus":{"lemma":"laurus","pos":"","gen":"-tree","def":"laurūs, Plin. 15, 30, 39, § 132; 14, 16, 19, § 112; Col. 6, 7, 3 codd.; abl. lauru, Hor. C. 2, 7, 19; but lauro, id. ib. 3, 30, 16; nom. plur. laurus, Verg. A. 3, 91"},"laus":{"lemma":"laus","pos":"","gen":"","def":"plur. laudium, Sid. Carm. 23, 32), f. for claus, from clavid, kindred to cluo and the Greek κλέϝος, praise, commendation, glory, fame, renown, esteem (cf.: gloria, praeconium"},"lausus":{"lemma":"Lausus","pos":"","gen":"","def":"Son of Numitor and brother of Rhea Silvia, Ov. F. 4, 55.— The son of Mezentius, whom Aeneas slew, Verg. A. 7, 649; 10, 790. lautē, adv., v. lavo fin. lautĭa (in Plutarch λαύτεια, Quaest. Rom. 45"},"laxo":{"lemma":"laxo","pos":"v.","gen":"","def":"a. (rarely n."},"laxus":{"lemma":"laxus","pos":"adj.","gen":"","def":"cf. languidus, languor, lactes, wide, loose, open; spacious, roomy"},"lecto":{"lemma":"lecto","pos":"","gen":"","def":"freq. , = lectito, Vet. Schol. Hor. S. 1, 6, 122; cf. Charis. 142 P. Lecton (Lectum), i, n., = Λέκτον, a promontory on the coast of Troy, now C. Baba, Liv. 37, 37; Plin. 5, 32, 32, § 123"},"lector":{"lemma":"lector","pos":"adv.","gen":"","def":"2. lego, one who reads. Lit. In gen., a reader: cum enim Brutus duos lectores excitasset, et alteri orationem legendam dedisset, etc., Cic. de Or. 2, 55"},"lectrix":{"lemma":"lectrix","pos":"","gen":"","def":"lector, a female reader, Inscr. ap. Fabr. p. 311, n. 347; cf. Cledon. p. 1893 P."},"lectus":{"lemma":"lectus","pos":"","gen":"-bed","def":"(nom. lectum, i, n., Dig. 32, 1, 52, § 9; 34, 2, 19, § 8; lectus, ūs, Plaut. Am. 1, 3, 15; al. lecti; Sen. Ep. 95, 72 Haas; Cornif. ap. Prisc. 711 P.) [Gr. λέχος, ἄλοχος, λόχος, λόχμη; Lat. lectica"},"lembus":{"lemma":"lembus","pos":"","gen":"","def":", = λέμβος, a small fastsailing vessel with a sharp prow, a pinnace, yacht, cutter: lembus genus navicellae velocissimae, quod et dromonis nomine appellamus, Fulg. Exp. Serm. 564, 6"},"lemma":{"lemma":"lemma","pos":"","gen":"-tales","def":", = λῆμμα, a subject for consideration or explanation, a theme, matter, subject, contents (not ante-Aug."},"lemniscus":{"lemma":"lemniscus","pos":"","gen":"-bast","def":", = λημνίσκος. A pendent (purple?) ribbon, fastened to a victor's crown, at first of linden-bast or wool"},"lenis":{"lemma":"lenis","pos":"","gen":"","def":", a kind of vessel, Afran. and Laber. ap. Non. 544, 31. lēnĭtas, ātis, f. 1. lenis, softness, smoothness, gentleness, mildness. Lit.: vini, opp. asperitas, Plin. 14, 19, 24, § 120: lini, id. 13, 12"},"lens":{"lemma":"lens","pos":"","gen":"","def":", a louse's egg, a nit: lendes tolluntur adipe canino, Plin. 29, 6, 35, § 111; Ser. Samm. 5, 72."},"lentesco":{"lemma":"lentesco","pos":"","gen":"","def":"inch. n. , to become viscous or sticky"},"lentiscus":{"lemma":"lentiscus","pos":"","gen":"-oil","def":", lentiscum, i, n., the mastic - tree, Pistacia lentiscus, Linn. Lit.: viridis semperque gravata Lentiscus, Cic. poët. Div. 1, 9, 15.— Transf. Mastic-oil, Cato, R. R. 7, 4; Varr. R. R. 1, 60"},"lento":{"lemma":"lento","pos":"v.","gen":"","def":"a. id., to make flexible, to bend (poet. and in postclass. prose). Lit.: arcus lentare et fundere glandes, i. e. to draw a bow, Stat. Achill. 1, 436"},"lentor":{"lemma":"lentor","pos":"","gen":"","def":"lentus, pliancy, flexibility; toughness, stickiness, viscosity (Plinian"},"lentus":{"lemma":"lentus","pos":"adj.","gen":"","def":"cf. lenis, pliant, flexible, tough, tenacious, sticky, viscous (syn.: flexilis, tardus, serus). Lit.: viburna, Verg. E. 1, 26: vitis, id. ib. 3, 38: genistae, id. G. 2, 12: rami, id. ib. 4"},"lepta":{"lemma":"Lepta","pos":"","gen":"","def":"λεπτός, weak, a Roman surname: Q. Lepta, praefectus fabrūm, Cic. Fam. 3, 7, 4"},"lerna":{"lemma":"Lerna","pos":"adj.","gen":"","def":", = Λέρνη, a forest and marsh near Argos, through which flowed a stream of the same name"},"lesbus":{"lemma":"Lesbus","pos":"","gen":"","def":"Lesbos. lessus, acc. um (only in acc. sing.), m., a wailing, cry, funeral lamentation: mulieres genas ne radunto, neve lessum funeris ergo habento, Cic. Leg. 2, 23, 59"},"letus":{"lemma":"Letus","pos":"","gen":"","def":", a mountain in Liguria, Liv. 41, 18"},"leuca":{"lemma":"Leuca","pos":"","gen":"","def":", a town in Calabria, near the Iapygian promontory, now S. Maria di Leuca: secretaque littora Leucae, Luc. 5, 376. leucăcantha, ae, f., and leucă-canthos, i, m., = λευκάκανθα. The white thorn"},"leucanthes":{"lemma":"leucanthes","pos":"","gen":"","def":", = λευκανθές, the herb pellitory, Plin. 21, 30, 104, § 176."},"leucanthus":{"lemma":"leucanthus","pos":"","gen":"","def":", = λεύκανθος, a plant, otherwise unknown, App. Herb. 92."},"leucargillos":{"lemma":"leucargillos","pos":"","gen":"","def":", = λευκάργιλλος, white clay, Plin. 17, 7, 4, § 42."},"leucas":{"lemma":"Leucas","pos":"adj.","gen":"","def":", = Λευκάς. For Leucadia, v. h. v.— The capital of the island Leucadia; v. Leucadia, B.— The promontory Leucata"},"leucaspis":{"lemma":"Leucaspis","pos":"","gen":"","def":", one of the companions of Aeneas, Verg. A. 6, 334. Leucāta, ae, and Leucātē, ēs, f. (Leucāte, is, n., Serv. Verg. A. 3, 279.— Leucātes, ae, m., Claud. B. G. 185.— Leucas, ădis, f., Ov. H. 15, 172"},"leuci":{"lemma":"Leuci","pos":"","gen":"","def":", = Λεῦκοι, a people of Gallia Belgica, adjacent to the Lingones, whence, perh., the mod. Liège, Caes. B. G. 1, 40, 10; Plin. 4, 17, 31, § 106"},"leucippus":{"lemma":"Leucippus","pos":"","gen":"","def":", = Λεύκιππος. The father of Phoebe and Hilaira, who were carried off by Castor and Pollux, Ov. F. 5, 709.—Hence, Leucippis, ĭdis, f., a daughter of Leucippus, Prop. 1, 2, 15: te rapuit Theseus"},"leucophthalmos":{"lemma":"leucophthalmos","pos":"","gen":"","def":", = λευκόφθαλμος (white eye), a precious stone, Plin. 37, 10, 62, § 171. leucōpis, ĭdis, f., = λευκῶπις, a plant, called also artemisia, App. Herb. 10. leucŏpoecĭlos, i, m."},"leucos":{"lemma":"leucos","pos":"adj.","gen":"","def":", = λευκός, white, Plin. 10, 60, 79, § 164. Leucŏsĭa, ae, f., = Λευκοσία, a small island off the coast of Lucania, near Paestum, now Licosa: Leucosiamque petit, tepidique rosaria Paesti, Ov. M. 15"},"leuctra":{"lemma":"Leuctra","pos":"adj.","gen":"","def":"(Leuctrae, ārum. f., Sol. 7), = Λεῦκτρα. A small town in Baeotia, where Epaminondas defeated the Spartans, now the village of Leuca, with the ruins of Eremo-Castro (cf. Mann. Griechenland, p. 238)"},"leucus":{"lemma":"Leucus","pos":"","gen":"","def":"Leuci."},"leudus":{"lemma":"leudus","pos":"","gen":"","def":"(Germ. Lied, Laut), a German song, Ven. Fort. 7, 8, 69."},"leuga":{"lemma":"leuga","pos":"","gen":"","def":"leuca. lĕuncŭlus, i, m. dim. leo, a small lion, Vulg. 3 Reg. 10, 20; id. 1 Par. 28, 17. lēus, a, um, adj., = λεῖος, smooth: brassica lea, Plin. 20, 9, 33, § 79."},"leuson":{"lemma":"leuson","pos":"","gen":"","def":", = λοῦσσον, the inner part of the wood of the fir: (hoc lignum, proximum medullae) in abiete leuson Graeci vocant, Plin. 16, 39, 73, § 187. lĕvābĭlis, e, adj. levo, that can be lightened: motus"},"lex":{"lemma":"lex","pos":"","gen":"-class","def":"perh. Sanscr. root lag-, lig-, to fasten; Lat. ligo, to bind, oblige"},"liceo":{"lemma":"liceo","pos":"","gen":"","def":"licet. lĭcĕor, lĭcĭtus, 2, v. dep. n. and a. , to bid on goods at an auction (class.). Absol.: licetur Aebutius, Cic. Caecin. 6, 16: liciti sunt usque adeo, quoad, etc., Cic. Verr. 2, 3, 33"},"lignor":{"lemma":"lignor","pos":"v.","gen":"","def":"dep. lignum, to fetch or procure wood, to collect wood: num lignatum mittimur? Plaut. Capt. 3, 4, 125 (dub."},"lignum":{"lemma":"lignum","pos":"","gen":"-tablet","def":"prob. root leg-, v. 2. lĕgo"},"limbus":{"lemma":"limbus","pos":"","gen":"","def":", a border that surrounds any thing, a hem, welt, edge, selvage, fringe; a belt, band, girdle. Lit.: Sidoniam picto chlamydem circumdata limbo, Verg. A. 4, 137"},"limia":{"lemma":"Limia","pos":"","gen":"","def":"Limaeas."},"limici":{"lemma":"Limici","pos":"","gen":"","def":"plur., a people of Hispania Tarraconensis, Plin. 3, 3, 4, § 28. līmĭcŏla, ae, m. limus-colo, a dweller in the mud: ostreae, Aus. Ep. 7, 36. līmĭgĕnus, a, um, adj. limus-gigno"},"limma":{"lemma":"limma","pos":"","gen":"","def":", = λεῖμμα (a remainder; hence), a semitone, Macr. Somn. Scip. 2, 1, § 23."},"limnaea":{"lemma":"Limnaea","pos":"","gen":"","def":", = Λιμναία, a town of Thessaly, now Kortikhi, Liv. 36, 13 fin. Limnātis, ĭdis, f., = Λιμνᾶτις (that lives in marshes), a surname of Diana: templum Dianae Limnatidis, Tac. A. 4"},"linctus":{"lemma":"linctus","pos":"","gen":"","def":"lingo, a licking: nectaris, Lucr. 6, 971 (v. Lachm. ad h. l.), Plin. 31, 9, 45, § 104"},"linguax":{"lemma":"linguax","pos":"adj.","gen":"","def":"id., loquacious, Gell. 1, 15, 20. lingŭla, v. ligula. lingŭlāca, ae lingula. Comm., a gossip, chatterbox: ea (uxor) lingulaca est nobis: numquam tacet, Plaut. Cas. 2, 8, 62: lingulacae obtrectatores"},"linquo":{"lemma":"linquo","pos":"v.","gen":"","def":"lictus, Capitol. M. Aurel. 7 dub.), v. a. Gr. λιπ- in λείπω, λοιπός"},"linter":{"lemma":"linter","pos":"","gen":"-ter","def":"lintris, Sid. Carm. 5, 283), f. (m., Tib. 2, 5, 34) [old form lunter for plun-ter; root πλύνω, to wash; cf. pluvia; hence] Lit., a wash-tub"},"linternum":{"lemma":"Linternum","pos":"","gen":"","def":"Liternum. lintĕum, i, n. linum, a linen cloth. Lit.: linteum cape atque exterge tibi manus, Plaut. Most. 1, 3, 110: uncto linteo, id. Bacch. 3, 3, 42: linteum extersui, id. Curc. 4, 4"},"lintris":{"lemma":"lintris","pos":"","gen":"","def":"linter init. līnum, i, n. Gr. λίνον; Goth. lein; Germ. Leinwand; Engl. linen, flax. Lit.: reticulum, tenuissimo lino, Cic. Verr. 2, 5, 11, § 27: urit lini campum seges, Verg. G. 1, 77"},"lippesco":{"lemma":"lippesco","pos":"v.","gen":"-eyed","def":"n., to become blear-eyed (eccl. Lat.), Hier. in Sophon. 3, 49. lippĭdus, γλαμώδης (i. q. lippus), Gloss. Gr. Lat. lippĭo, īvi, ītum, 4, v. n. lippus, to haw watery or inflamed eyes"},"lippus":{"lemma":"lippus","pos":"adj.","gen":"-eyed","def":"Sanscr. lip, to smear; Gr. λίπα, λίπος, fat; ἄλειφα, salve"},"lips":{"lemma":"Lips","pos":"","gen":"","def":"Libs. lĭquābĭlis, e, adj. liquo, that may be melted or dissolved (post-class.): cera, App. Mag. 293, 3: saxum, i. e. the pillar of salt into which Lot's wife was turned, Prud. Ham. 744. lĭquāmen"},"liquor":{"lemma":"liquor","pos":"n. m.","gen":"-oris","def":"a liquid, fluid; water; a flowing, liquidity"},"lissus":{"lemma":"Lissus","pos":"","gen":"","def":", and Lissum, i, n., = Λισσός, a city in southern Dalmatia, on the borders of Macedonia, now Alessio, Caes. B. C. 3, 26, 4; Plin. 3, 22, 26, § 144; Liv. 43, 20"},"littus":{"lemma":"littus","pos":"","gen":"","def":"litus. Litubĭum, i, n., a town in Liguria, Liv. 32, 29. lĭtūra, ae, f. lino, a smearing, anointing. In gen.: solem etiam et pluviam arcet ejusmodi litura, Col. 4, 24, 6.— In partic. Lit."},"lix":{"lemma":"lix","pos":"","gen":"","def":", ashes, lye: lix est cinis vel umor cineri admixtus: nam etiamnum id genus lixivium vocatur, Non. 62, 11."},"lixa":{"lemma":"lixa","pos":"","gen":"-followers","def":"perh. linquo, a sutler: non lixa sequebatur, Liv. 39, 1: lixae modo sine insignibus, sine lictoribus, profectum, id. 21, 63: lixarum in modum negotiari, id. 5, 8: lixae ac negotiatores, Tac. A. 2"},"lixio":{"lemma":"lixio","pos":"","gen":"-follower","def":"id., a sutler, camp-follower: lixiones aquarum portitores, Gloss. Isid. lixīvĭus, a, um, adj. lix, made into lye: cinere lixivio abluere, lye-ashes, Plin. 28, 18, 75, § 244.— Subst.: lixīvĭa, ae, f."},"lixus":{"lemma":"Lixus","pos":"","gen":"","def":", = Λίξος, a river in Mauritania, with a city of the same name, now Wady al-Khos, Mel. 3, 10, 6; Plin. 5, 1, 1, § 9; Sil. 3, 258"},"locutius":{"lemma":"Locutius","pos":"","gen":"","def":"Aius. lŏcūtor (lŏquūtor), ōris, m. loquor, one who speaks, a speaker (post-class.). In gen.: rudis locutor exotici sermonis, App. M. 1, p. 102.— In partic., a talker, prater"},"loebasius":{"lemma":"Loebasius","pos":"","gen":"","def":"2. Liber init. loebertas and ‡ loebesum, v. 1. liber init. loedŏrĭa, ae, f., = λοιδορία, open reviling, gross abuse: loedoria exprobratio ad directam contumeliam, Macr. S. 7"},"longaeuus":{"lemma":"longaevus","pos":"adj.","gen":"-aevum","def":"longus-aevum, of great age, aged, ancient (poet.): parens, Verg. A. 3, 169"},"longinquus":{"lemma":"longinquus","pos":"adj.","gen":"-fetched","def":"longus, long, extensive. Lit., in space. In gen. (rare): linea, Plin. 9, 17, 26, § 59: aequora, Claud. Rapt. Pros. 3, 363: amnes, Tac. A. 1, 9.— In partic. Far removed, far off, remote"},"longisco":{"lemma":"longisco","pos":"v.","gen":"","def":"n. inch. , to become long (perh. languisco = languidum fieri, frangi, to become faint, weak, languid), Enn. ap. Non. 134, 19 (Ann. v. 480 Vahl.). longĭter, adv., v. longus fin. B. longĭtĭa (longĭcĭa)"},"longum":{"lemma":"longum","pos":"adv.","gen":"","def":", v. longus fin. C. Longuntĭca, ae, f., a city in Hispania Tarraconensis, Liv. 22, 20, 6. longŭrĭo, ōnis, m. longus, a tall fellow, a long-shanks, Varr. ap. Non. 131, 29. longŭrĭus, ii, m. id."},"lopadusa":{"lemma":"Lopadusa","pos":"","gen":"","def":", an island on the coast of Africa, Plin. 5, 7, 7, § 42.—The same as Lepadusē, Plin. 3, 9, 15, § 92 Jan. (al. Lepidose). lŏpas, v. lepas. lŏquācĭtas, ātis, f. loquax, talkativeness, loquacity"},"luceium":{"lemma":"Luceium","pos":"","gen":"","def":", a castle or fortress in Galatia, Cic. Deiot. 6"},"lucta":{"lemma":"lucta","pos":"","gen":"-match","def":"root lug-"},"lucto":{"lemma":"lucto","pos":"","gen":"","def":"the foll. init."},"luctor":{"lemma":"luctor","pos":"v.","gen":"-beams","def":"gen. plur. luctantūm, Prop. 4 (5), 22, 9; act. collat. form: viri validis viribus luctant, Enn. ap. Non. 472, 8: plurimum luctavimus, Plaut. ap. Non. 468, 32"},"luctus":{"lemma":"luctus","pos":"","gen":"","def":"lucti, Att. ap. Non. 485, 30 and 32), m. lugeo, sorrow, mourning, grief, affliction, distress, lamentation, esp. over the loss of something dear to one. Lit.: filius luctu perditus, Cic. Rosc. Am. 8"},"lumbellus":{"lemma":"lumbellus","pos":"","gen":"","def":"dim. id., a little loin, Apic. 7, 1, § 259. lumbĭfrăgĭum, i, n. lumbus-frango, a breaking of the loins, Plaut. Am. 1, 1, 298. lumbrīcōsus, a, um, adj. lumbricus, full of intestinal worms"},"lumbus":{"lemma":"lumbus","pos":"","gen":"","def":", a loin. Lit.: At Edepol nos (velimus) tibi in lumbos linguam atque oculos in solum (decidisse), Plaut. Poen. 3, 1, 68: exporgi meliust lumbos, id. Ps. prol. 24 (1)"},"lunchus":{"lemma":"lunchus","pos":"","gen":"","def":"lonchus. Lūnensis, e, adj., v. 2, Luna, II. lūno, āvi, ātum, 1, v. a. 1. luna, to bend like a half-moon or crescent, to crook like a sickle (rare in the verb. finit."},"lurco":{"lemma":"lurco","pos":"v.","gen":"","def":"a., and lurcor, āri, v. dep. n. [perh. lura, to have a stomach of leather], to eat voraciously, to devour: lurcare est cum aviditate cibum sumere, Non. 10, 31: lardum, Pomp. ap. Non. 11"},"luscus":{"lemma":"luscus","pos":"adj.","gen":"-eyed","def":"root luc of lux; with fundamental idea to glimmer"},"lustro":{"lemma":"lustro","pos":"v.","gen":"","def":"a. 2. lustrum, to purify by means of a propitiatory offering (syn.: procuro, expio). Lit.: agrum lustrare sic oportet. Impera suovetaurilia circumagi, etc., Cato"},"lustrum":{"lemma":"lustrum","pos":"","gen":"-repute","def":"1. luo, lavo"},"luxo":{"lemma":"luxo","pos":"v.","gen":"","def":"a. Gr. λοξός, slanting, akin to obliquus, limus, licinus, to put out of joint, to dislocate. Lit.: luxatum si quod est, sanum faciet, Cato, R. R. 157: luxata in locum reponere, Sen. Ep. 104"},"luxor":{"lemma":"luxor","pos":"v.","gen":"","def":"dep. luxus, to riot, revel, live luxuriously: luxantur a luxu dictum, id est luxuriantur, Paul. ex Fest. p. 120 Müll."},"luxus":{"lemma":"luxus","pos":"adj.","gen":"","def":"= Gr. λοξός; v. luxo, dislocated: luxum si quod est, Cato, R. R. 160: luxo pede, Sall. Fragm. ap. Prob. p. 1476 P. (Hist. 5, 2)"},"lyaeus":{"lemma":"Lyaeus","pos":"adj.","gen":"","def":", = Λυαῖος, Lyaeus, the relaxer, unbender, deliverer from care. A surname of Bacchus: patri Lyaeo, Verg. A. 4, 58: corniger Lyaeus, Ov. Am. 3, 15, 17; id. M. 4, 11; 8, 274; 11, 68"},"lycaeus":{"lemma":"Lycaeus","pos":"adj.","gen":"","def":", = Λυκαῖος, a mountain in Arcadia (now Dhiaforti), where Jupiter and Pan were worshipped, Plin. 4, 6, 10, § 21; Verg. G. 4, 539; Ov. M. 1, 217; Aug. Civ. Dei, 18, 17"},"lycambes":{"lemma":"Lycambes","pos":"adj.","gen":"","def":", = Λυκάμβης, a Theban who promised his daughter to Archilochus, and afterwards refused her"},"lycapsos":{"lemma":"lycapsos","pos":"","gen":"","def":", = λύκαψος, alkanet, Plin. 27, 11, 73, § 97 (al. lycopsis). Lycaūnŭs, i, m., the name of a warrior, Sil. 4, 203. Lycē, ēs, f., = Λύκη, the name of a woman, Hor. C. 4, 13, 1. Lycēum"},"lychnis":{"lemma":"lychnis","pos":"adj.","gen":"","def":"f., = λυχνίς, lightgiving, shining. Lit.: lychnides puellae, girls with lamps, Fulg. Myth. prooem. 1.— Subst.: lychnis, ĭdis, f. A kind of rose of a fiery red, Plin. 21, 4, 10, § 18.— Lychnis agria"},"lycisca":{"lemma":"Lycisca","pos":"","gen":"","def":"The name of a bitch, Verg. E. 3, 18; Ov. M. 3, 220.— A vile woman, Juv. 6, 122."},"lyciscus":{"lemma":"lyciscus","pos":"","gen":"","def":", = λυκίσκος, a wolfdog: lycisci dicuntur canes nati ex lupis et canibus, cum inter se forte miscentur, Isid. Orig. 12, 2.— Lyciscus, the name of a beautiful boy, Hor. Epod. 11"},"lyco":{"lemma":"Lyco","pos":"","gen":"","def":", a Peripatetic philosopher, a follower of Strato of Lampsacus, Cic. Tusc. 3, 32, 78. Lycŏmēdes, is, m., = Λυκομήδης, a king of the Isle of Scyros"},"lycophthalmos":{"lemma":"lycophthalmos","pos":"","gen":"-eye","def":", = λυκόφθαλμος (wolf's-eye), a precious stone, Plin. 37, 11, 72, § 187"},"lycormas":{"lemma":"Lycormas","pos":"","gen":"","def":", = Λυκόρμας, a river of Aetolia, Ov. M. 2, 245; afterwards called Chrysorrhoas, Hyg. Fab. 242."},"lycortas":{"lemma":"Lycortas","pos":"","gen":"","def":", = Λυκόρτας, a general (strategos, στρατηγός) of the Achaean League, Liv. 39, 35; 36."},"lycos":{"lemma":"lycos","pos":"","gen":"","def":", = λύκος, a kind of spider: araneus, et maxume qui lycos vocatur, Plin. 30, 6, 17, § 52"},"lycurgus":{"lemma":"Lycurgus","pos":"","gen":"-curg","def":", = Λυκοῦργος. Son of Dryas, king of the Edones, who prohibited the worship of Bacchus to his subjects, and ordered all the vines to be destroyed, Ov. M. 4, 22; Prop. 4, 16, 23; Stat. Th. 4, 386"},"lygdos":{"lemma":"lygdos","pos":"","gen":"","def":", = λύγδος, a white stone, = lygdinus lapis: candida, Mart. 6, 13, 3: vacua, id. 6, 42, 21."},"lygii":{"lemma":"Lygii","pos":"","gen":"","def":"Ligii. Lygmon, Müller's reading for Lucmo, Prop. 5, 1, 29."},"lygos":{"lemma":"lygos","pos":"","gen":"","def":", = λύγος, a plant, the chaste tree, agnus castus, Abraham's balm (in late Lat. vitex), Plin. 24, 9, 38, § 59."},"lympha":{"lemma":"lympha","pos":"","gen":"","def":"νύμφη, water; esp. clear river or spring water (poet.): lymphae puteales, Lucr. 6, 1178: fluviali spargere lympha, Verg. A. 4, 635"},"lympho":{"lemma":"lympho","pos":"v.","gen":"","def":"a. and n. lympha. To water, dilute with water: admixto vino lymphato, id est, aqua temperato, Cael. Aur. Tard. 4, 3, 68.— To drive out of one's senses, to distract with fear, to make mad: urbem"},"lymphor":{"lemma":"lymphor","pos":"","gen":"","def":"id., water: impermixtum lymphorem, Lucil. ap. Non. 212, 4. Lyncaestē, ēs, f., one of Actaeon's hounds, Hyg. Fab. 181."},"lyncestae":{"lemma":"Lyncestae","pos":"adj.","gen":"-western","def":", = Λυγκησταί, a people in the south-western part of Macedonia, Liv. 45, 30, 6; Plin. 4, 10, 17, § 35.— Hence, Lyncestĭus, a, um, adj., Lyncestian: amnis, Ov. M. 15, 329"},"lynx":{"lemma":"lynx","pos":"","gen":"-skin","def":", = λύγξ, a lynx: lynces Bacchi variae (Bacchus was drawn by a team of lynxes), Verg. G. 3, 264: maculosae tegmine lyncis, id. A. 1, 323: lyncibus ad caelum vecta Ariadna tuis, Prop. 3, 15, 8 (4, 16"},"lyo":{"lemma":"lyo","pos":"v.","gen":"","def":"a. λύω, to make liquid, to liquefy: ptisanam, Apic. 4, 4: pulpa lyata, id. 5, 1."},"lyra":{"lemma":"lyra","pos":"","gen":"","def":", = λύρα, a lute, lyre, a stringed instrument resembling the cithara, fabled to have been invented by Mercury and presented to Apollo, Hyg. Astr. 2, 7: curvae lyrae parens, Hor. C. 1, 10"},"lyristes":{"lemma":"lyristes","pos":"","gen":"","def":", = λυριστής, a luteplayer, lyrist: audisses lectorem, vel lyristen, Plin. Ep. 1, 15, 2; 9, 17, 3; 9, 36, 4"},"lyron":{"lemma":"lyron","pos":"","gen":"","def":", = λύρον, a plant, also called alisma, Plin. 25, 10, 77, § 124."},"lysander":{"lemma":"Lysander","pos":"","gen":"","def":", = Λύσανδρος. A celebrated Spartan general, conqueror of the Athenians, Cic. Off. 1, 22, 76; 1, 30, 109; Nep. Lys.— An ephor in Sparta, banished for injustice, Cic. Off. 2, 23, 80."},"lysas":{"lemma":"lysas","pos":"","gen":"","def":", a plant, also called artemisia, App. Herb. 10. Lysĭăcus, a, um, v. Lysias, I. B. Lysĭădes, ae, m., = Λυσιάδης, an Athenian, son of the philosopher Phaedrus, Cic. Phil. 5, 5, 13. Lysĭas, ae, m."},"lysis":{"lemma":"lysis","pos":"","gen":"","def":", = λύσις. A loosening, rupture: trabes frangunt suā lysi structuras, Vitr. 6, 11.— A talon, ogee, Vitr. 3, 4, 5; 5, 6, 6. Lȳsis, is, m., a small river in Asia Minor, Liv. 38, 15, 3."},"lystra":{"lemma":"Lystra","pos":"","gen":"-west","def":", or ōrum, n., a city in Lycaonia, north-west of Iconium, Vulg. Act. 14, 8; 14, 21.—Hence, Lystrēni, ōrum, m., the inhabitants of Lystra, Lystrenes, Plin. 5, 32, 42, § 147."},"lytra":{"lemma":"lytra","pos":"","gen":"","def":"lutra. lytrōtes, ae, m., = λυτρωτής, one of the aeons of Valentinus, Tert. adv. Val. 9. lytrum, false read. for lustra; v. 2. lustrum, II. E."},"lytta":{"lemma":"lytta","pos":"","gen":"","def":", = λύττα, a worm under a dog's tongue, said to cause madness, Plin. 29, 5, 32, § 100. M M, m, the twelfth letter of the Latin alphabet (J not being distinguished from I in the class. period)"},"m":{"lemma":"m","pos":"","gen":"","def":"Dat. from ego.— Voc. from meus; v. h. vv. Mĭa Chărĭtōn = Χαρίτων μία, one of the Graces, Lucr. 4, 1162; v. Charites. mīca, ae, f. root smic-; Gr. σμικρός, μικρός; cf. micula"},"macae":{"lemma":"Macae","pos":"","gen":"-eastern","def":", a people in the north-eastern part of Arabia Felix, Prisc. Peri. 887."},"maccis":{"lemma":"maccis","pos":"","gen":"","def":", a fictitious spice, Plaut. Ps. 3, 2, 43 (al. macis). Maccius, a, name of a Roman gens. —Hence, T. Maccius Plautus, the celebrated Roman comic poet; v. Plautus."},"maccus":{"lemma":"maccus","pos":"","gen":"","def":"cf. Sanscr. mūkas, dumb; Gr. μῶκος, mockery; also Μῶμος, a buffoon, punchinello, macaroni, in the Atellane plays: in Atellana Oscae personae inducuntur, ut maccus, Diom. p. 488 P."},"macella":{"lemma":"Macella","pos":"","gen":"","def":", = Μάκελλα, a town in Sicily, on the Crimisus, Liv. 26, 21. măcellārĭus, a, um, adj. macellum, of or belonging to the meat-market or provision-market: taberna, Val. Max. 3, 4"},"machabaeus":{"lemma":"Machabaeus","pos":"","gen":"","def":", a surname of Judas, Vulg. 1 Macc. 1, 2 et saep.—Hence, Machabaei, ōrum, m., the Maccabees, Aug. Civ. Dei, 18, 36"},"machetum":{"lemma":"machetum","pos":"","gen":"","def":", a kind of rose, Plin. 21, 4, 10, § 19. māchilla, ae, f. dim. machina, a little machine: e machillā sustuli, Petr. 74, 13 dub. (al. e machina illam sustuli). Machĭmus, i, m., = Μάχιμος"},"machlyes":{"lemma":"Machlyes","pos":"","gen":"","def":", a fabled people of Africa: supra Nasamonas confinesque illis Machlyas androgynos esse utriusque naturae, Plin. 7, 2, 2, § 15. Măchŏrōnes, um, m., a people of Pontus, Plin. 6, 4, 4, § 11. macĭa, ae"},"macria":{"lemma":"Macria","pos":"","gen":"","def":", a small island near Euboea, Plin. 2, 88, 90, § 204. macrĭcŭlus, a, um, adj. dim. , lean, Varr. L. L. 8, 40, § 79 Müll. Mācrīnus, i, m., the name of a man. A friend of the poet Persius, Pers. 2"},"macto":{"lemma":"macto","pos":"","gen":"","def":"subj. mactassint, Enn., Afran., and Pompon. ap. Non. 342, 12 sq.), v. freq. a. macto, kindr. to Sanscr. makh, mah; intens. māmahyata, to slaughter, sacrifice; maha, victim"},"mactus":{"lemma":"mactus","pos":"adj.","gen":"","def":"root μακ, in μάκαρ, blessed"},"madaura":{"lemma":"Madaura","pos":"","gen":"","def":", and Madauri, ōrum, m., a city in Numidia, now Ayedrah, Aug. Conf. 2, 3."},"madaurensis":{"lemma":"Madaurensis","pos":"adj.","gen":"","def":", of or belonging to the city of Madaura (on the borders of Numidia and Gaetulia, not the city mentioned in the preced. art.), Madauran: Appuleius Madaurensis, Aug. Ep. 49.—Hence, subst.: Madaurensis"},"madena":{"lemma":"Madena","pos":"","gen":"","def":", a district of Great Armenia, between the rivers Cyrus and Araxes, Eutr. 8, 3; Sex. Ruf. Brev. 16 al. mădens, entis, P. a., v. madeo fin. mădĕo, ŭi, ēre, v. n. Gr. μαδάω, to drip"},"maea":{"lemma":"maea","pos":"","gen":"-crab","def":", a kind of sea-crab, Plin. 9, 31, 51, § 97. Maeander (Maeandros or Mae-andrus), dri, m., = Μαιανδρος, a river, proverbial for its winding course, which rises in Great Phrygia"},"maeles":{"lemma":"maeles","pos":"","gen":"","def":"1. meles. Maelĭānus (Mēl-), v. Maelius. maelĭum, ii, v. mellum. Maelĭus, a, the name of a Roman gens, of which the most celebrated member is Sp. Maelius, who"},"maenas":{"lemma":"Maenas","pos":"","gen":"","def":", v. Maenades. Maenĭus, a, the name of a Roman gens: C. Maenius, consul A. U. C. 416, Liv. 8, 13, 1.—Hence, Maenĭus, a, um, adj., of or belonging to a Maenius, Maenian: Maenia lex"},"maeon":{"lemma":"Maeon","pos":"","gen":"","def":", = Μαιών. A Theban, a priest of Apollo, Stat. Th. 2, 693; 4, 598.— A Lydian"},"maera":{"lemma":"Maera","pos":"","gen":"","def":", = Μαῖρα. The name of a woman who was changed into a dog, Ov. M. 7, 362; 13, 406"},"magis":{"lemma":"magis","pos":"adv.","gen":"","def":", v. magnus fin. măgis, ĭdis, or măgĭda, ae, f., = μαγίς. A dish, platter, plate: magidam et longulam alterum a magnitudine, alterum a latitudine finxerunt, Varr. L. L. 5"},"magma":{"lemma":"magma","pos":"","gen":"","def":", = μάγμα, the dregs of an unguent: faecem unguenti magma appellant, Plin. 13, 2, 3, § 19"},"magmentum":{"lemma":"magmentum","pos":"","gen":"","def":"contr. from magimentum, from root mag; cf. mactare and mactus.—In relig. lang., that which magnifies or glorifies, an offering, sacrifice, Inscr. Orell. 2489; 2490; Inscr. Grut. 23, 12; 229, 1"},"magnes":{"lemma":"magnes","pos":"adj.","gen":"","def":", = μάγνης, with or without lapis, a magnet, loadstone: (lapis), quem magneta vocant patrio de nomine Grai Magnetum quia sit patriis in finibus ortus, Lucr. 6, 908"},"magnus":{"lemma":"Magnus","pos":"","gen":"","def":", a Roman surname, e. g. Cn. Pompeius Magnus; v. Pompeius. Māgo and Māgon, ōnis, m., Μάγων. A Carthaginian, the brother of Hannibal, Nep. Hann. 7, 4; 8, 2; Liv. 21, 47; 4, 6; Aur. Vict. Vir. Ill. 49"},"maguntia":{"lemma":"Maguntia","pos":"","gen":"","def":"Magontiacum. măgus, i, m., and măga, ae, f., = μάγος. In the masc., a Magian, a learned man and magician among the Persians: ei magos dixisse, quod genus sapientum et doctorum habebatur in Persis"},"maharbal":{"lemma":"Maharbal","pos":"","gen":"","def":", a Carthaginian officer under Hannibal, Liv. 21, 12; 45; 22, 6; 46; 51."},"maia":{"lemma":"maia","pos":"","gen":"","def":", = μαῖα, a large kind of crab, Plin. 9, 31, 51, § 97; al. maea. Māia, Māja (written by Cicero Majja, like ejjus, pejjus, etc."},"malacha":{"lemma":"malacha","pos":"","gen":"","def":", v. maldacon. mălăchē and mŏlŏchē, ēs, f., = μαλάχη and μολόχη, a kind of mallows (v. malva). Form malache, Varr. L. L. 5, 21, § 103 Müll.; Plin. 20, 21, 84, § 222"},"malfactum":{"lemma":"malfactum","pos":"","gen":"","def":"malefactum. Mālĭăcus Sĭnus, a gulf south of Thessaly, now Gulf of Zeitouni, Mel. 2, 3, 6; Plin. 4, 7, 12, § 27"},"mallo":{"lemma":"mallo","pos":"","gen":"-class","def":", = μαλλός. The stem of onions (post-class.): mallonem caeparum, id est calamos siccos, unde fasces dependent, Veg. Vet. 2, 60; 1, 63.— A kind of tumor on the knees in animals, Veg. Vet. 2, 48, 1."},"malloea":{"lemma":"Malloea","pos":"","gen":"","def":", a city in Thessaly, Liv. 32, 41, 5; 36, 10, 5."},"mallon":{"lemma":"mallon","pos":"","gen":"","def":", the Boeotian name for the plant Nymphaea, Plin. 25, 7, 37, § 75 (al. madon). Mallos and us, i, f., = Μαλλός, a city in Cilicia, Mel. 1, 13, 1"},"mallus":{"lemma":"mallus","pos":"","gen":"","def":", = μαλλός, a lock of wool, Cato, R. R. 157. mallŭvĭae, ārum, f. manus - lavo, water for washing the hands, Paul. ex Fest. p. 161 Müll."},"maltha":{"lemma":"maltha","pos":"","gen":"","def":", = μάλθα, a kind of thick, fatty petroleum from Samosata, fossil tar, the flame of which could be extinguished only with earth, Plin. 2, 104, 108, § 235.— Transf."},"maltho":{"lemma":"maltho","pos":"v.","gen":"","def":"a. id., to cement, to varnish (post-Aug.), Plin. 36, 24, 58, § 181, Schol. Juv, 5, 48 Cramer. Malūgĭnensis, is, m., a Roman surname in the gens Cornelia, e. g. M. Cornelius Maluginensis, Liv. 4"},"malua":{"lemma":"malva","pos":"","gen":"","def":"μαλάχη, mallows: in magnis laudibus malva est utraque, et sativa"},"malundrum":{"lemma":"malundrum","pos":"","gen":"","def":", a plant, otherwise unknown, Plin. 26, 7, 24, § 40. mălus, a, um, adj. Sanscr. mala, dirt; Gr. μέλας, black; cf. macula"},"mammaea":{"lemma":"Mammaea","pos":"adj.","gen":"","def":", the mother of the emperor Alexander Severus, Lampr. Alex. Sev. 3, 1.—Hence, Mammaeānus, a, um, adj., of or belonging to Mammaea, Mammaean, Lampr. Alex. Sev. 57, 7. mammālis, e, adj. mamma"},"mammilla":{"lemma":"mammilla","pos":"","gen":"","def":"mamilla."},"mammo":{"lemma":"mammo","pos":"v.","gen":"","def":"n. mamma, to give suck (late Lat.): vae tunc praegnantibus et mammantibus, S. S. Marc. 13, 17, ap. Aug. in Psa. 95, 14. mammōnas, or mammōna, ae, or mammon, nos, m., = μαμμωνᾶς , riches"},"mammothreptus":{"lemma":"mammothreptus","pos":"","gen":"","def":", = μαμμόθρεπτος, nourished by a nurse, Aug. in Psa. Conc. 30. mammŭla, ae, f. dim. mamma, a little breast or teat. Lit., Varr. R. R. 2, 3, 2"},"manceps":{"lemma":"manceps","pos":"","gen":"-capio","def":"manus-capio, a purchaser of any thing at a public auction, a renter, farmer, contractor, etc. (syn.: redemtor, exactor). Lit.: manceps dicitur, qui quid a populo emit conducitve"},"mancus":{"lemma":"mancus","pos":"adj.","gen":"","def":"Sanscr. man-āk, little"},"mando":{"lemma":"mando","pos":"v.","gen":"-clause","def":"a. manusdo, to commit to one's charge, to enjoin, commission, order, command (syn.: praecipio, edico)"},"mandra":{"lemma":"mandra","pos":"","gen":"-board","def":", = μάνδρα, a stall or pen for cattle, etc. (poet.). Lit.: mulorum, Mart. 5, 22, 7.— Transf. A herd of cattle: stantis convicia mandrae, abuse from the herd penned up or stopped"},"mango":{"lemma":"mango","pos":"","gen":"","def":"μάγγανον, a dealer, monger in slaves or wares, to which he tries to give an appearance of greater value, by adorning them (post-Aug.): mangones quicquid est quod displiceat"},"manna":{"lemma":"manna","pos":"","gen":"","def":", = μάννα, a grain, a vegetable juice hardened into grains, Plin. 12, 14, 32, § 62: manna una turis, id. 29, 6, 38, § 119: croci, Veg. Vet. 2, 39. †† manna, man, manhu, neutr. indecl., and manna, ae"},"mansor":{"lemma":"mansor","pos":"","gen":"","def":"maneo, a sojourner, indweller, guest (late Lat.): faciat (Deus nos) tanto mansore capaces, Sedul. 5, 294. mansōrĭus, a, um, adj. mansor, abiding"},"mansus":{"lemma":"mansus","pos":"","gen":"","def":"Part., from 2. mando.— Part., from maneo. mantēle (mantīle), is, n., and mantēlĭum (mantīlĭum), ii, n. manus and tela, properly a cloth for the hand, a towel, napkin. Lit.: mantelium"},"manto":{"lemma":"manto","pos":"","gen":"-class","def":"freq. n. and a. . Neutr., to stay, remain, wait (ante-class.): in eādem mantat malitiā, Caecil. ap. Non. 505, 27 (Com. Rel. v. 87 Rib.): manta, Plaut. Ps. 1, 3, 49"},"mantum":{"lemma":"mantum","pos":"","gen":"","def":", a Spanish cloak: mantum Hispani vocant, quod manus tegat tantum: est enim breve amictum, Isid. Orig. 19, 24, 15."},"manturna":{"lemma":"Manturna","pos":"","gen":"","def":"maneo, the goddess of matrimony, who was invoked to render the marriage lasting, Aug. Civ. Dei, 6, 9."},"mantus":{"lemma":"Mantus","pos":"","gen":"-world","def":", the Etruscan Pluto, the god of the under-world, Serv. Verg. A. 10, 199. mănŭa, ae, f. manus, a handful: manuae feni, Schol. Juv. 8, 154: manua, δράγμα, Gloss. mănŭālis, e, adj. 1. manus"},"mappa":{"lemma":"mappa","pos":"","gen":"-napkin","def":"Punic, Quint. 1, 5, 57, a napkin, table-napkin; a towel. Lit.: Varius mappa compescere risum Vix poterat, Hor. S. 2, 8, 63: laticlavia, Petr. 32"},"maracanda":{"lemma":"Maracanda","pos":"","gen":"","def":", the capital of Sogdiana, now Samarcand, Curt. 7, 6, 16"},"marcellus":{"lemma":"Marcellus","pos":"adj.","gen":"","def":"dim. of Marcus, a Roman family name in the plebeian gens Claudia: inter Marcellos et Claudios patricios, Cic. de Or. 1, 39, 176: generosior Marcellis, Juv. 2, 145.— Esp., M. Claudius Marcellus"},"marcens":{"lemma":"marcens","pos":"","gen":"","def":"marceo, P. a. marcĕo, ēre, v. n. Sanscr. root mar, die; Gr. μαραίνω, μαρασμός"},"marcesco":{"lemma":"marcesco","pos":"","gen":"","def":"inch. n. , to wither, pine away, droop, decay (not in Cic. or Caes.). Lit.: fagus et cerrus celeriter marcescunt, Plin. 16, 40, 79, § 218: quae spectatissime florent, celerrime marcescunt, id. 21, 1"},"marcor":{"lemma":"marcor","pos":"","gen":"","def":"marceo, a withering: segetum, Sen. Q. N. 3, 27, 4.—Hence, Transf. Decay, rottenness (not anteAug.): panni marcor, a rotten rag, Plin. 22, 22, 46, § 94.— Faintness, languor, indolence: marcor"},"marcus":{"lemma":"marcus","pos":"","gen":"","def":"cf. Sanscr. mar, mrid, to break, crush, a large hammer, Isid. Orig. 19, 7, 2, v. 1. marculus."},"mardi":{"lemma":"Mardi","pos":"","gen":"","def":", a plundering race dwelling in the highlands between Media, Susiana, and Persis, near the Hyrcanians, Plin. 6, 5, 5, § 16; 6, 16, 18, § 47; Tac. A. 14, 23; Curt. 4, 12, 7; 5, 6, 17"},"marga":{"lemma":"marga","pos":"","gen":"","def":", a kind of earth, marl, Plin. 17, 6, 4, § 42. Margānĭa, ae, f., a city in Margiana, Curt. 7, 10, 15 Foss. (al. Margianam). margărĭdes, um, f., = μαργαρίδες, a round kind of date"},"margo":{"lemma":"margo","pos":"","gen":"-dishes","def":"and f. (cf. Prisc. p. 684 P.), an edge, brink, border, margin (class., but not in Cic. or Caes.): flumen marginibus lapideis, Varr. R. R. 3, 5, 9: conchae, Plin. 9, 36, 61, § 130: ulceris, id. 30, 13"},"margum":{"lemma":"Margum","pos":"","gen":"","def":", a city in Upper Moesia, on the Margis, Eutr. 9, 13. Mărīa, ae, f., a female proper name. Mary, the mother of Jesus (eccl. Lat.), Vulg. Matt. 2, 11: Marĭa, Prud. Psych. 88; id. Apoth. 643"},"maricas":{"lemma":"Maricas","pos":"","gen":"","def":", = Μαρικᾶς, a title of a comedy of Eupolis, directed against Hyperbolus, Quint. 1, 10, 18 Spald."},"mariccus":{"lemma":"Mariccus","pos":"","gen":"","def":", a Boian, who stirred up a revolt against Vitellius, Tac. H. 2, 61. mărīnus, a, um, adj. mare, of or belonging to the sea, sea-, marine (class.): marini terrenique umores, Cic. N. D. 2, 16"},"marium":{"lemma":"Marium","pos":"","gen":"","def":", and Mareum, = Μα·ριον, an ancient town of Cyprus, Plin. 5, 31, 35, § 130. Mărĭus, i, m., the name of a Roman gens. The most celebrated is C. Marius, the conqueror of Jugurtha"},"marnas":{"lemma":"Marnas","pos":"","gen":"","def":"Syrian, a deity worshipped at Gaza, in Palestine, Hier. Isa. 7, 17, 2; id. Vit. Hilar. 14. Măro, ōnis, m. from root smar-, to be thoughtful"},"maron":{"lemma":"maron","pos":"","gen":"","def":"marum. Mărōnēa or Mărōnīa, ae, f., = Μαρώνεια. A town of Thrace, on the Schoeneus, famous for its wine, now Marona, Mel. 2, 2, 8; Liv. 31, 16, 3"},"marra":{"lemma":"marra","pos":"","gen":"-hook","def":"etym. unknown, a sort of hoe for tearing up weeds, a weeding-hook, = ligo (post-Aug.). Lit.: tu penitus latis eradere viscera marris Ne dubita, Col. 10, 72; id. 10, 89; Plin. 17, 21, 35, § 159"},"marsi":{"lemma":"Marsi","pos":"adj.","gen":"-charmers","def":"A people in Latium, on the Lacus Fucinus, celebrated as wizards and snake-charmers; in the Social War the most zealous enemies of the Romans, Plin. 7, 2, 2, § 15; 3, 12, 17, § 106; Caes. B. C. 1, 15"},"marsigni":{"lemma":"Marsigni","pos":"","gen":"","def":", a people of Germany, a part of the Suevi, Tac. G. 43. Marspedis sive sine r littera maspedis in precatione solitaurilium quid significet"},"marsus":{"lemma":"Marsus","pos":"","gen":"","def":"Marsi, I. B. 1."},"marsyas":{"lemma":"Marsyas","pos":"","gen":"","def":", the name of several rivers. A river in Greater Phrygia, which flows into the Maeander, now Tschinar Tchai, Ov. M. 6, 400; Liv. 38, 13, 6.— The name of two rivers in Syria, Plin. 5, 23, 19, § 81"},"martes":{"lemma":"martes","pos":"","gen":"","def":", a marten: captā marte, Mart. 10, 37, 18 dub. (al. mele or maele). Martĭālis, e, v. Mars, IV. B. Martĭālis, is, m., M. Valerius Martialis, a native of Bilbilis, in Spain"},"martyr":{"lemma":"martyr","pos":"","gen":"","def":", = μάρτυρ, a witness; esp. one who by his death bears witness to the truth of the Christian religion, a martyr (eccl. Lat.): salvete flores Marty rum, Prud. Cath. 12, 125"},"marucca":{"lemma":"Marucca","pos":"","gen":"","def":", a town in Batica, Plin. 3, 1, 3, § 12. Mărullus, i, m., a Roman surname, e. g. C. Epidius Marullus, Val. Max. 5, 7, 2. —In fem.: Mărulla, ae, Mart. 10, 55, 1. mărum and măron, i, n., = μάρον"},"marus":{"lemma":"Marus","pos":"","gen":"","def":", a river in Dacia, now the March or Morana, Tac. A. 2, 63; Plin. 4, 12, 25, § 81. mās, măris (n. mare, rare; gen. plur marium, Cic. Part. Or. 10, 35"},"masada":{"lemma":"Masada","pos":"","gen":"","def":", a fortress in Judaea, now Sebbeh, Plin. 5, 17, 15, § 73. Masaesȳli, ōrum, v. Massaesyli. Masāti, ōrum, m., a people of Mauritania, Plin. 5, 1, 1, § 9. mascarpĭo, ōnis, m. mas-carpo"},"masicitus":{"lemma":"Masicitus","pos":"","gen":"","def":", a mountain in Lycia, Plin. 5, 27, 28, § 100. Măsĭnissa (Măsănīsa, Oros. 4, 18), ae, m., a king of Numidia, grandfather of Jugurtha"},"maspedis":{"lemma":"Maspedis","pos":"","gen":"","def":"Marspedis. maspĕtum, i, n., = μα·σπετον, the leaf of the laserpitium, Plin. 19, 3, 15, § 42. Maspĭter, i. q. Marspiter, v. Mars."},"massa":{"lemma":"massa","pos":"","gen":"","def":", = μάζα, that which adheres together like dough, a lump, mass (poet. and post-Aug.): massa picis, Verg. G. 1, 275: salis, Plin. 31, 7, 39, § 78: lactis coacti, cheese, Ov. M. 8, 666: lactis alligati"},"massala":{"lemma":"Massala","pos":"","gen":"","def":", a town of Arabia Felix, Plin. 6, 28, 32, § 158. Massălĭōtĭcus, a, um, v. Massilia, C. massālis, e, adj. 1. massa, of or belonging to a mass, that constitutes a mass (eccl. Lat.): massalis moles"},"masso":{"lemma":"masso","pos":"v.","gen":"","def":"a., = μάσσω, to chew (late Lat.), Theod. Prisc. 1, 8; 2, 29."},"mastarna":{"lemma":"Mastarna","pos":"","gen":"","def":", an ancient (Tuscan) name of Mons Coelius, Oratio Claudii Aug. ap. Grut. 502."},"mastaurenses":{"lemma":"Mastaurenses","pos":"","gen":"","def":", the inhabitants of the city of Mastaura in Lydia, Plin. 5, 29, 31, § 120. mastĭcātĭo, ōnis, f. mastico, a chewing, mastication (post-class.): cibum masticatione exercere, Cael. Aur. Tard. 4, 3"},"mastix":{"lemma":"mastix","pos":"","gen":"","def":"mastiche fin."},"mastos":{"lemma":"mastos","pos":"","gen":"","def":", = μαστός, a plant good for the breast, Plin. 26, 15, 92, § 163. mastrūca (mastrūga), ae, f. Sardinian"},"masturbor":{"lemma":"masturbor","pos":"v.","gen":"-stupro","def":"dep. perhaps from manus-stupro, to defile one's self (postAug.), Mart. 11, 104, 13; 9, 42, 7"},"masurius":{"lemma":"Masurius","pos":"","gen":"","def":"Massurius. matăra, ae, f., v. materis. matăris, v. materis."},"mataxa":{"lemma":"mataxa","pos":"","gen":"","def":"metaxa. mătella or mătēla, ae, f. dim. matula, a pot, a vessel for liquids. In gen.: matella aquae, Plaut. Fragm. ap. Non. 543, 17; Varr. ib. 19; Cato, R. R. 10"},"matisco":{"lemma":"Matisco","pos":"","gen":"","def":", a city of the Aeduans, in Gallia Lugdunensis, on the Arar, the modern Maçon, Caes. B. G. 7, 90, 7. Mătĭus, a, the name of a Roman gens. So, Cn. Matius, a poet and translator of the Iliad, Gell. 6"},"matrae":{"lemma":"Matrae","pos":"","gen":"","def":"(dat. plur. MATRABVS, for Matris, Inscr. Grut. 29, 1), or Matres, more freq. Matronae, the protecting goddesses of a country, city, or place: MATRIS AVGVSTIS D. D., Inscr. Grut. 90, 1"},"matrimes":{"lemma":"matrimes","pos":"","gen":"","def":"matrimus init. mātrĭmōnĭālis, e, adj. matrimonium, of or belonging to marriage, matrimonial (post-class.): tabulae, Firm. Math. 7, 17: lectulus, Quint. Decl. 1, 13. mātrĭmōnĭum, ii, n. mater, wedlock"},"matta":{"lemma":"matta","pos":"","gen":"","def":", a mat made of rushes, Aug. contr. Faust. 5, 5; Schol. Juv. 5, 8"},"matthaeus":{"lemma":"Matthaeus","pos":"","gen":"","def":", = Ματθαῖος, or Mattheus (eu diph.), St. Matthew the evangelist: publicanus, Vulg. Matt. 10, 3: Mattheus, as a dissyl., Prud. Apoth. 982. Mattĭăcus, a, um, adj."},"mattya":{"lemma":"mattya","pos":"","gen":"","def":"mattea. mătŭla, ae, f., a vessel, pot for liquids (ante- and post-class.). In gen.: continentur mundo muliebri specula, matulae, unguenta, vasa unguentaria, Dig. 34, 2, 25, § 10. As a term of abuse"},"matus":{"lemma":"matus","pos":"","gen":"","def":"mattus. Mātūta, ae, f. root ma- of mane, maturus, q. v.. Matuta, the goddess of the morning or dawn, identical with Aurora, Lucr. 5, 656.— A name of Ino (Gr. Λευκοθέα)"},"maurella":{"lemma":"maurella","pos":"","gen":"","def":", a plant, otherwise unknown, Macer. Cam. 2, 34. Maurētānĭa (Maurīt-), ae, f., v. Mauri, C."},"mauri":{"lemma":"Mauri","pos":"adj.","gen":"-r","def":"(Μαῦροι), the Moors, Mauritanians, the inhabitants of Mauritania: proxime Hispaniam Mauri sunt, Sall. J. 18, 10 sqq.; Plin. 5, 2, 1, § 17; 13, 15, 29, § 91; Liv. 21, 22, 3"},"maxilla":{"lemma":"maxilla","pos":"","gen":"-form","def":"dim. of a ground-form magsula (whence māla; root mag of μάσσω, to knead; μαγεύς. baker, etc."},"mazagae":{"lemma":"Mazagae","pos":"","gen":"","def":", a city in India, Curt. 8, 10, 22. Mazĭces, um, m., = Μάζικες, a people of Numidia, the same with Mazaces, q. v., Amm. 29, 25, 21 sqq. māzŏnŏmus, i, m. (acc. to others, māzŏnŏmon, i, n."},"me":{"lemma":"me","pos":"","gen":"","def":"ego init. mĕābĭlis, e, adj. meo. * Pass., passable, that can be passed through: transitus vel bubus meabilis, Plin. 6, 1, 1, § 2.— * Act., passing through, penetrating: aër per cuncta rerum meabilis"},"mecastor":{"lemma":"mecastor","pos":"","gen":"","def":"Castor. mēchănēma, ătis, n., = μηχάνημα, a piece of mechanism, a trick (post-class.), Sid. Ep. 1, 9. mēchănĭcus, a, um, adj., = μηχανικός, of or belonging to mechanics"},"mechir":{"lemma":"Mechir","pos":"","gen":"","def":", the name of an Egyptian month, answering nearly to the Roman January and a part of February, Plin. 6, 23, 26, § 106. mēcon, ōnis, f., = μήκων, a sort of poppy: tertium genus est tithymalon"},"med":{"lemma":"med","pos":"","gen":"","def":"ego. meddix (medix), icis, m. from the root med-, medeor"},"medipontus":{"lemma":"medipontus","pos":"","gen":"-class","def":", a kind of thick rope (ante-class.): medipontos privos loreos (al. melipontos), Cato, R. R. 3, 5; 12. mĕdĭtābundus, a, um, adj. meditor, earnestly meditating, designing"},"medix":{"lemma":"medix","pos":"","gen":"","def":"meddix. medixtutĭcus, v. meddix. Medobrēga (Medubrīga, Mun-dobrīga), ae, f., a city in Lusitania, now Portalegre, Auct. B. Alex. 48, 4.—Hence, Medubrīgenses, ĭum, m., the inhabitants of Medobrega"},"medullus":{"lemma":"Medullus","pos":"","gen":"","def":", a mountain in Hispania Tarraconensis, Flor. 4, 12, 50; Oros. 6, 21. Mĕdŭlus, a, um, adj., v. Meduli. Mēdus, a, um, v. Medi, II. A. Mēdus, i, m., son of Aegeus and Medea"},"mehe":{"lemma":"mehe","pos":"","gen":"","def":"ego init."},"mehercle":{"lemma":"mehercle","pos":"","gen":"-herc","def":"Hercules. mēio, ĕre, v. n. for migio, kindred with Sanscr. mih, effundere; whence also mingo"},"melae":{"lemma":"Melae","pos":"","gen":"","def":", a town in the Samnite country, Liv. 24, 20"},"meldi":{"lemma":"Meldi","pos":"","gen":"","def":", a people of Gallia Celtica, between the Seine and Marne; their chief town answered to the modern Meaux, Caes. B. G. 5, 5"},"melessi":{"lemma":"Melessi","pos":"","gen":"","def":", a people in Hispania Baetica, Liv. 28, 3. Mĕlĕtē, ēs, f., = Μελέτη. One of the Muses, Cic. N. D. 3, 21, 54.— A Roman surname: PORCIA MELETE, Inscr. Grut. 357, 7.— The name of a plant"},"mella":{"lemma":"mella","pos":"","gen":"-water","def":"mel, perh. for mellea (sc. aqua), honey-water (post-Aug.), Col. 12, 11, 1"},"mellilla":{"lemma":"mellilla","pos":"","gen":"","def":"dim. 2. melinus, a term of endearment, little honey, little sweetheart: mea vita, mea mellilla, Plaut. Cas. 1, 1, 47 dub. mellĭna, ae, v. 2. melinus. mellĭnĭa, ae, f. mel, sweetness, deliciousness"},"mello":{"lemma":"mello","pos":"v.","gen":"","def":"a. id., to make or collect honey, Pall. 7, 7, 1 dub. Mellōna, ae, f. id., the goddess of bees and honey, Aug. Civ. Dei, 4, 24.—Called also Mellōnĭa, Arn. 4, 131. Mellŏproxĭmus, i, m., vox hibr."},"mellum":{"lemma":"mellum","pos":"","gen":"-lus","def":", a dog's collar, Varr. R. R. 2, 9, 15 Schneid. N. cr. (al. melium and maelium).—Also, millus, i: millus collare canum venaticorum"},"melosmos":{"lemma":"melosmos","pos":"","gen":"","def":", a plant, also called polion, App. Herb. 57. mēlōta, ae, or mēlōtē, ōs, f., = μηλωτή, a sheepskin (with the wool on): circumierunt in melotis, in pellibus caprinis, Vulg. Heb. 11, 37"},"meltom":{"lemma":"meltom","pos":"","gen":"","def":"bonus init. Memacēni, ōrum, m., a people of Asia, beyond the Caspian Sea, Curt. 7, 6. membrāna, ae, f. membrum"},"membro":{"lemma":"membro","pos":"v.","gen":"","def":"a. membrum, to form limb by limb, to furnish with limbs: quinque et triginta diebus infans membratur, Censor. de Die Nat. 11"},"membrum":{"lemma":"membrum","pos":"","gen":"-trum","def":"etym. dub.; perh. for mems-trum"},"memnon":{"lemma":"Memnon","pos":"adj.","gen":"-string","def":", = Μεμνων, son of Tithonus and Aurora, and king of the Ethiopians"},"memphis":{"lemma":"Memphis","pos":"adj.","gen":"","def":", = Μεμφις, a city of Middle Egypt, celebrated as the residence of the Egyptian kings, now Metrahenny (fourteen miles south of Cairo), Mel. 1, 9, 9; Plin. 2, 85, 87, § 201; 5, 9, 9, § 50"},"mena":{"lemma":"Mena","pos":"","gen":"","def":", a Roman surname, Inscr. Grut. 241, col. 2. Mĕnaechmi, ōrum, m., = Μέναιχμοι, a comedy of Plautus, so called from the two twin brothers of this name, the leading characters. Mĕnaenĭus or Mĕnaenus, a"},"menda":{"lemma":"menda","pos":"","gen":"","def":"v. mendum, a fault, defect, blemish of the body (poet. and postAug.). Lit.: in toto nusquam corpore menda fuit, Ov. Am. 1, 5, 18: nocte latent mendae, id. A. A. 1, 249.— Transf., a mistake, error"},"mendax":{"lemma":"mendax","pos":"adj.","gen":"-class","def":"mentior, given to lying, mendacious"},"mendico":{"lemma":"mendico","pos":"v.","gen":"-begging","def":"n. and a., and mendīcor, ātus sum (archaio inf. mendicarier, Plaut. Capt. prol. 13), 1, v. dep. id., to beg, ask for alms, go a-begging; to beg for something, solicit, obtain by begging"},"mendum":{"lemma":"mendum","pos":"","gen":"","def":"Sanscr. manāk, a little; mindā, a defect"},"mennis":{"lemma":"Mennis","pos":"","gen":"","def":", a city of Assyria, in Adiabene, Curt. 5, 1, 15. mennonĭa, ae, f., a reading for memnonia, Plin. 37, 10, 63, § 173. Mĕnoeceus, ĕi and ĕos, m., = Μενοικευς, son of the Theban king Creon"},"mens":{"lemma":"mens","pos":"","gen":"","def":"sing. mentis: terra corpus est, at mentis ignis est, Enn. ap. Prisc. p. 764 P.; so too, istic est de sole sumptus; isque totus mentis est, Enn. ap. Varr. L. L. 5, § 59 Müll."},"mensis":{"lemma":"mensis","pos":"","gen":"","def":"plur. regularly mensium; freq. mensum, Plaut. Most. 1, 1, 78; Cic. Phil. 12, 9, 22; id. Verr 2, 74, 182 al.; Caes. B. G. 1, 5, 3; Ov. M. 8, 500; id. F. 5, 187; 424; Liv. 3, 24, 4; 3, 25, 4"},"mensor":{"lemma":"mensor","pos":"","gen":"-measurer","def":"metior, a measurer (post Aug.). In gen.: te maris, et terrae, numeroque carentis arenae Mensorem cohibent, Archyta, Hor. C. 1, 28, 1: frumentarius, a corn-measurer, Paul. Dig. 27, 1"},"mensurnus":{"lemma":"mensurnus","pos":"adj.","gen":"","def":"mensis, monthly (for the more usual menstruus): spatium, * Cic. Inv. 1, 26, 39 (acc. to Prisc. p 595 P.; B. and K. menstrui spatii)"},"mentastrum":{"lemma":"mentastrum","pos":"","gen":"","def":"menta, wild mint, Plin. 19, 8, 47, § 159: silvestre, Col. 11, 3. Mentēsānus, a, um, adj. Of or belonging to the city of Mentesa (Mentissa, Liv. 26, 17) in Hispania Baetica: ordo Mentesanus"},"mentha":{"lemma":"mentha","pos":"","gen":"","def":"menta. mentĭens, entis, Part., from mentior, q. v. mentīgo, ĭnis, f. mentum, a kind of eruption, scab, on lambs (i. q. ostigo, q. v.), Col. 7, 5, 21. mentĭo, ōnis, f. from root man-, men-"},"mentissa":{"lemma":"Mentissa","pos":"","gen":"","def":"Mentesanus. mentītĭo, ōnis, f. mentior, a lying, deception, Auct. Her. 3, 2, 3 dub. mentītus, a, um, Part., v. mentior fin. 2."},"mento":{"lemma":"mento","pos":"","gen":"-chin","def":"amplif. , one who has a long chin, long-chin, Arn. 3, 108."},"mentor":{"lemma":"Mentor","pos":"adj.","gen":"-cup","def":", = Μέντωρ. The famous friend of Odysseus, Cic. Att. 9, 8, 2. — A celebrated artist in embossed work in metal, Cic. Verr. 2, 4, 18, § 38"},"mentum":{"lemma":"mentum","pos":"","gen":"","def":"root men-, min-, to project; cf.: minae, minari, etc., the chin of persons and animals"},"meopte":{"lemma":"meopte","pos":"","gen":"","def":"e. meo ipsius, v. meus. mĕphītĭcus, a, um, adj. mephitis, mephitic, pestilential (post-class.): odor, Sid. Ep. 3, 13. mĕphītis, is, f., a noxious, pestilential exhalation from the ground"},"mepte":{"lemma":"mepte","pos":"","gen":"","def":"e. me ipsum, Plaut. Men. 5, 8, 10. mĕrācē, adv., v. meracus fin. mĕrācŭlus (also sync., meraclus), a, um, adj. dim. , pretty pure"},"merces":{"lemma":"merces","pos":"","gen":"","def":"h. v. mercĭmōnĭum, ii, n. merx, goods, wares, merchandise (ante-class. and postAug.): in vostris mercimoniis Emundis vendundisque, Plaut. Am. prol. 1; id. Most. 3, 3, 9"},"merco":{"lemma":"merco","pos":"","gen":"","def":"mercor fin. mercor, ātus, 1 (archaic form, mercassitur for mercatus fuerit, Inscr. Grut. 512, 20.—Inf. mercarier for mercari, Hor. S. 2, 3, 24), v. dep. n. and a. , to trade, traffic"},"merda":{"lemma":"merda","pos":"","gen":"","def":"etym. dub.; cf. Gr. μορύσσειν, to defile, dung, ordure, excrement: corvorum, Hor. S. 1, 8, 37; Mart. 3, 17, 6; Veg. 2, 8, 4"},"merenda":{"lemma":"Merenda","pos":"","gen":"","def":", a Roman surname: T. Antonius Merenda, a consul, A. U. C. 304, Liv. 3, 35. mĕrendārĭus, ii, m. 1. merenda, one who takes an afternoon luncheon (postAug.), Sen. Contr. 5"},"mergae":{"lemma":"mergae","pos":"","gen":"-pronged","def":"root marg-, to clear away"},"mergo":{"lemma":"mergo","pos":"v.","gen":"-fish","def":"a. cf. Sanscr. madsh-, majan, to dip; Zend, masga, marrow; Germ. Mark; Engl. marrow, to dip, dip in, immerse"},"merso":{"lemma":"merso","pos":"","gen":"","def":"freq. a. id., to dip in, immerse (poet. and in post-Aug. prose). Lit.: balantumque gregem fluvio mersare salubri, Verg. G. 1, 272: balneo infertur, calida aqua mersatur, Tac. A. 15, 69.— Trop."},"merthryx":{"lemma":"merthryx","pos":"","gen":"","def":", a false reading for myrtis, Plin. 26, 11, 68, § 108."},"merto":{"lemma":"merto","pos":"","gen":"","def":"freq. a. mergo, a collat. form of merso, to immerse, overwhelm (anteclass.): mertat pro mersat dicebant, Paul. ex Fest. p. 124 Müll."},"merx":{"lemma":"merx","pos":"","gen":"-class","def":"sing. merces, Sall. Fragm. ap. Charis. p. 27 P.), f. mereo, goods, wares, commodities, merchandise (class.): invendibili merce oportet ultro emptorem adducere: Proba merx facile emptorem reperit"},"messor":{"lemma":"messor","pos":"","gen":"","def":"id., a reaper (class.). Lit., Cic. de Or. 3, 12, 46: durus, Ov. M. 14, 643: feniseca, a mower, Col. 2, 18: dura messorum ilia, Hor. Epod. 3, 4: parce messoribus illis qui saturant urbem, Juv. 8"},"mestria":{"lemma":"Mestria","pos":"","gen":"","def":", a Roman surname, Inscr. Fabr. p. 621, 181. Mestriānus, i, m., a Roman surname, Inscr. Malvas. Marm. Felsin. p. 253. met"},"metalces":{"lemma":"Metalces","pos":"","gen":"","def":", = Μεταλκής, one of the fifty sons of Aegyptus, slain by his wife Cleopatra, Hyg. Fab. 170. metălepsis, is, f., = μετάληψις, in rhetoric"},"metallinensis":{"lemma":"Metallinensis","pos":"adj.","gen":"-sis","def":"Metallinum, of or belonging to the town of Metallinum (in Lusitania), Metallinian: colonia, Plin. 4, 21, 35, § 117. mĕtallum, i, n., = μέταλλον, a mine or quarry, of gold, silver, iron, or stone"},"metallum":{"lemma":"metallum","pos":"n. n.","gen":"-i","def":"a metal; a mine, quarry; metallic ore"},"metina":{"lemma":"Metina","pos":"","gen":"","def":", an island near the coast of Gaul, opposite the mouth of the Rhone, Mart. Cap. 6, § 643. mētĭor, mensus (post-class. metītus, Dig. 32, 1, 52), 4, v. dep. Sanscr. ma, to measure"},"metiscus":{"lemma":"Metiscus","pos":"","gen":"","def":", a charioteer of Turnus, Verg. A. 12, 469. mētītĭo, ōnis, f. metior, = mensura, but not in use"},"micio":{"lemma":"Micio","pos":"","gen":"","def":", name of a man, Ter. Ad. 5, 3, 7. Mĭcipsa, ae, m., son of Masinissa, and king of Numidia, Sall. J. 5 sq."},"microsphaerum":{"lemma":"microsphaerum","pos":"","gen":"-leaved","def":", = μικρόσφαιρον, small-leaved nard, Plin. 12, 12, 26, § 44. mictĭlis, e, adj. mingo, that deserves to be defiled"},"mictus":{"lemma":"mictus","pos":"","gen":"-class","def":"id., a making water, urinating (post-class.): sanguinis mictus, Cael. Aur. Tard. 5, 3, 59"},"midaium":{"lemma":"Midaium","pos":"","gen":"","def":", = Μιδάειον, a city of Phrygia, Plin. 5, 32, 41, § 145.—Hence, subst.: Midaeenses, ium, m., the inhabitants of Midaium, Cic. Fam. 3, 8, 3.—Also called Midaei, orum, m., Plin. 5, 29, 29"},"migma":{"lemma":"migma","pos":"","gen":"","def":", = μίγμα, a mixture, mixed provender, meslin: commistum mig ma, Vulg. Isa. 30, 24. mīgrātĭo, ōnis, f. migro, a removal, a changing of one's habitation"},"mihipte":{"lemma":"mihipte","pos":"","gen":"","def":"q. mihi ipsi, v. ego. Mīlănĭon, ōnis, m., = Μειλανίων, the husband of Atalanta: flēsse Milaniona, Ov. A. A. 2, 188; id. Am. 3, 2, 29"},"millus":{"lemma":"millus","pos":"","gen":"","def":", v. mellum. Mĭlo and Mĭlon, ōnis, m., = Μίλων. A celebrated athlete of Crotona, Cic. Fat. 13, 30; id. Sen. 9, 27; 10, 33; Val. Max. 9, 12, 9 ext.; Vitr. 9 praef. § 2"},"miltos":{"lemma":"miltos","pos":"","gen":"-lead","def":", = μιλτος, red-lead, minium, or native cinnabar, Plin. 33, 7, 38, § 115. milŭa (-va), ae, f. milvus, a she-kite, as a term of abuse, Petr. 75, 6. milŭāgo (-vago), ĭnis, f. id., a kind of fish"},"mimnermus":{"lemma":"Mimnermus","pos":"","gen":"","def":", = Μίμνερμος, a Greek elegiac poet of Colophon, the inventor of the pentameter, Hor. Ep. 1, 6, 65"},"min":{"lemma":"min","pos":"","gen":"","def":"h. v. min', for mihine, v. ego. mĭna (mna, Plin. 35, 10, 36, § 107), ae, f., = μνᾶ. A Greek weight of a hundred Attic drachmas, a mina, Plin. 21, 34, 109, § 185"},"minctus":{"lemma":"minctus","pos":"","gen":"","def":"id. (late Lat.), Cael. Aur. signif 136. mĭnĕo, ēre, false reading for meant, Lucr. 6, 563 and 1193"},"mingo":{"lemma":"mingo","pos":"v.","gen":"","def":"a. root mig, whence also meio"},"mintha":{"lemma":"mintha","pos":"","gen":"","def":", = μίνθη, the Greek name for menta, mint: mentae nomen suavitas odoris apud Graecos mutavit, cum alioqui mintha vocaretur, Plin. 19, 8, 47, § 159. mintrĭo, īre, or mintro, āre, v. n."},"minturnae":{"lemma":"Minturnae","pos":"adj.","gen":"","def":", a city of Latium, on the border of Campania, at the mouth of the Liris, in the neighborhood of which Marius concealed himself from Sylla in a marsh, Plin. 3, 5, 9, § 59; Liv. 9, 25, 3"},"minyanthes":{"lemma":"minyanthes","pos":"","gen":"-leaved","def":", = μινυανθές, a kind of large-leaved clover, Plin. 21, 9, 30, § 54; 21, 21, 88, § 152. Mĭnyas, ae, m., v. Minyae."},"minyas":{"lemma":"minyas","pos":"","gen":"","def":", a plant: idem (Pythagoras) minyada appellat, nomine alio Corinthiam, Plin. 24, 17, 100, § 157. Mĭnȳēĭas, ădis, f., = Μινυηϊάς, the daughter of Minyas, Ov. M. 4, 1. Mĭnyēĭdĕs, f. (Mĭnēĭdĕs)"},"mis":{"lemma":"mis","pos":"","gen":"","def":"meus init. Mīsăgĕnes, is, m., a son of Masinissa, Liv. 42, 29"},"miscillus":{"lemma":"miscillus","pos":"","gen":"","def":"miscellus init."},"miscipulo":{"lemma":"miscipulo","pos":"v.","gen":"","def":"n., to smack: miscipulat, ποππύζει, Gloss. Philox. miscĭtātus, a, um Part. from the unused miscito, v. freq. from misceo, mixed, mingled, Auct. de Limit. p. 267 Goes."},"miscix":{"lemma":"miscix","pos":"adj.","gen":"","def":"misceo, changeable, inconstant: inconstans, Petr. 45, 6 dub. (al. mittix). mĭsellus, a, um, adj. dim. , poor, wretched, unfortunate (rare, and with Cic. only in the epistolary style): homo"},"missa":{"lemma":"missa","pos":"","gen":"","def":"mitto, the mass (eccl. Lat.), Ambros. Ep. 5, 33. missārĭum, i, n., v. missum. mĭssĭbĭlia, ĭum, for missilia, Sid. Ep. 4, 20 missīcĭus or -tĭus, a, um, adj. mitto"},"missor":{"lemma":"missor","pos":"","gen":"","def":"id., one who sends, throws, or shoots, an archer (very rare): hic missore vacans fulgens jacet una sagitta (al.: hic misso revocans), Cic. Arat. 84. Missor, a Roman surname, Inscr. Fabr. 365"},"missum":{"lemma":"missum","pos":"","gen":"-s","def":"id., a prize: ἆθλον, missum, Gloss. Gr. Lat.; also called mis-sārĭum, i, n., Schol. Juv. 8, 227. missus, a, um, Part., from mitto."},"missus":{"lemma":"missus","pos":"","gen":"","def":"mitto, a sending away, a sending, despatching. Lit. missu Caesaris ad Ambiorigem ventitare consueverat, Caes. B. G. 5, 27: duas venisse legiones missu Caesaris, id. ib. 6, 7: Archippi regis missu"},"mistyllus":{"lemma":"Mistyllus","pos":"","gen":"","def":"μιστύλλω, to cut up, the name of a cook, Mart. 1, 51, 1. Misulāni (Mus-), ōrum, m., a people of Numidia, Plin. 5, 4, 4, § 30; called also Musulamii, Tac. A. 2, 52"},"mittix":{"lemma":"mittix","pos":"","gen":"","def":"miscix. mitto, mīsi, missum, 3 (contr. form, misti for misisti, Cat. 14, 14: archaic inf. pass. mittier, Plaut. Capt. 2, 3, 78), v. a. etym. dub."},"mitys":{"lemma":"Mitys","pos":"","gen":"-yos","def":", a river of Macedonia, Liv. 44, 7. mīūrus versus, μίουρος, μείουρος, a hexameter that has at the end an iambus instead of a spondee, Ter. de Metr. p. 2425 P.; Serv. Centim. p. 1824 P."},"mius":{"lemma":"mius","pos":"adj.","gen":"","def":", an old form for meus, Diom. p. 319 P.: v. meus. mixtārĭus, mixtĭo, etc., v. mist-."},"mna":{"lemma":"mna","pos":"","gen":"","def":"mina. Mnasĕas, ae, m., = Μνασἐας, an author who wrote De Re Rustica, Varr. R. R. 1, 1, 9; Col. 1, 1, 9"},"moechillus":{"lemma":"moechillus","pos":"","gen":"","def":"id., an adulterer, paramour: moechilli, facto, v. l. ap. Cat. 113, 2 dub. for mucillam. moechĭmēnĭum, ii, n. id., adultery, Laber. ap. Gell. 16, 7, 2 (also ap. Non. 140, 31)."},"moechisso":{"lemma":"moechisso","pos":"v.","gen":"","def":"a. id., to ravish (anteclass.): aliquam, Plaut. Cas. 5, 4, 6. moechŏ-cĭnaedus, i, m. moechuscinaedus, a man abandoned to lewdness, Lucil. ap. Non. 493, 26."},"moechor":{"lemma":"moechor","pos":"v.","gen":"","def":"dep. moechus, to commit adultery (poet. and late Lat.), Cat. 94, 1; Hor. S. 1, 2, 49; Mart. 6, 91, 2"},"moene":{"lemma":"moene","pos":"","gen":"","def":"moenia init. moenĕra, um, for munera, v. munus. moenĭa, ĭum (gen. plur. moeniōrum for moenium, like anciliorum for ancilium, acc. to Cledon. p. 1898 P."},"moenis":{"lemma":"Moenis","pos":"","gen":"","def":", the River Main, in Germany, Mel. 3, 3, 3.—Called also Moenus, i, Tac. G. 28; Plin. 9, 15, 17, § 45; Amm. 17, 1, 6. moenītus, Part., from moenio, v. munio."},"moenus":{"lemma":"Moenus","pos":"","gen":"","def":"Moenis. † moera (mīra), ae, f., = μοῖρα, a part, a degree, in the astronomical sense (post-class.), Sid. Carm. 15, 66; 14 prooem."},"moera":{"lemma":"Moera","pos":"","gen":"","def":", the name of one of the Fates, Gell. 3, 16, 11. moerens (maerens), entis, P. a., v. maereo fin."},"moereo":{"lemma":"moereo","pos":"","gen":"-ror","def":"maereo and maeror. moerica (merica), vitis, a sort of grape-vine, otherwise unknown, Plin. 14, 2, 6; Col. 3, 2, 27."},"moeris":{"lemma":"Moeris","pos":"","gen":"","def":", = Μοῖρις, Moeris, a king of Egypt in the fifteenth century A. C., who caused the lake which bears his name to be excavated: Moeridis lacus, Plin. 5, 9, 9, § 50.—Hence,"},"moerus":{"lemma":"moerus","pos":"","gen":"","def":"h. v."},"moesa":{"lemma":"Moesa","pos":"","gen":"","def":", the grandmother of Heliogabalus, Lampr. Heliog. 10."},"moesi":{"lemma":"Moesi","pos":"adj.","gen":"","def":", the Moesians, a people in the modern Bulgaria and Servia, Plin. 3, 26, 29, § 149; 4, 11, 18, § 41; Tac. A. 15, 6; Juv. 9, 143"},"molae":{"lemma":"Molae","pos":"","gen":"","def":", in the relig. lang. of the Italic people, perh. the daughters of Mars, the protectresses of mills, Gell. 13, 22. mŏlāris, e, adj. mola, of or belonging to a mill or to grinding"},"mollesco":{"lemma":"mollesco","pos":"","gen":"","def":"inch. n. , to become soft, to soften (poet. and in post-Aug. prose"},"mollis":{"lemma":"mollis","pos":"adj.","gen":"","def":"Gr. μαλακός, ἀμαλός, μῶλυς; cf. βληχρός, perh. Lat. mulier (mollior), easily movable, pliant, flexible, supple; soft, tender, delicate, gentle, mild, pleasant (class."},"molluscus":{"lemma":"molluscus","pos":"adj.","gen":"-sca","def":"mollis. Soft: mollusca nux; and absol.: mollu-sca, ae, f., a kind of soft nut with a thin shell, Plaut. ap. Macr. S. 2, 14"},"momar":{"lemma":"momar","pos":"","gen":"","def":", = μῶμαρ: Siculi stultum appellant, Paul. ex Fest. p. 140 Müll. mōmen, ĭnis, n. for movimen, from moveo. Movement, motion: e salso consurgere momine ponti, i. e. from the salt billows, Lucr. 6, 474"},"monda":{"lemma":"Monda","pos":"","gen":"","def":"Munda, II. fin. mŏnēdŭla, ae, f., a jackdaw, daw, Corvus monedula, Linn.: examina graculorum monedularum, cui soli avi furacitas auri argentique praecipue mira est, Plin. 10, 29, 41, § 77"},"monolium":{"lemma":"monolium","pos":"","gen":"","def":"monolinum. mŏnŏlōris, e, adj. vox hybr. μόνοσ- lorum, with one thong: vestes, having a single stripe of purple, Vop. Aur. 46, 6. mŏnŏmăchĭa, ae, f., = μονομαχία, a single combat"},"monstro":{"lemma":"monstro","pos":"v.","gen":"","def":"Brix ad Plaut. Trin. 2, 2, 61), 1, v. a. like monstrum, from moneo, to show, point out, to indicate, intimate, inform, advise, teach, instruct, tell any thing (in class. prose very rare"},"montanilla":{"lemma":"Montanilla","pos":"","gen":"","def":", a Roman surname, Inscr. Grut. 1146, 9. Montānīnus, i, m., a Roman surname, Inscr. Grut. 713, 2. montānĭōsus, a, um, adj. mons, for montanus, mountainous (post-class.): locus"},"montensis":{"lemma":"montensis","pos":"adj.","gen":"","def":"mons, for montanus, of or belonging to mountains, mountain-: DII, Inscr. Grut. 21, 3. montĭcellus, i, m. dim. id., a small mountain, a mount (post-class.)"},"mopsus":{"lemma":"Mopsus","pos":"","gen":"","def":", = Μόψος. A soothsayer in Argos, Cic. N. D. 2, 3, 7; id. Div. 1, 40, 88; id. Leg. 2, 13, 33.— A soothsayer in Thessaly, Ov. M. 12, 456; Hyg. Fab. 14; 128"},"moracillum":{"lemma":"moracillum","pos":"","gen":"","def":"from moracius, Titin. ap. Paul. ex Fest. p. 139 Müll. moracĭus, a, um, adj. mora, hard: nuces, Titin. ap. Paul. ex Fest. p. 139 Müll. mōrālis, e, adj. mores, of or belonging to manners or morals"},"morbus":{"lemma":"morbus","pos":"","gen":"","def":"Sanscr. mar-, die; Gr. βροτός (for μροτός), μαραίνω"},"mordax":{"lemma":"mordax","pos":"adj.","gen":"","def":"mordeo, biting, given to biting, snappish (poet. and in postAug. prose). Lit.: canis, Plaut. Bacch. 5, 2, 27: equus, Labeo ap. Gell. 4, 2: asinus, App. M. 8, p. 213 init.: Memmius"},"mordex":{"lemma":"mordex","pos":"adj.","gen":"-dex","def":"mordeo, biting, gnawing: asini mordices, v. l., Plaut. Aul. 2, 3, 57 (better mordicus).—As subst.: Mor-dex, ĭcis, m., the biter, i. e. tooth, v. l. ap. App. M. 3, p. 140 (better mordicus"},"moritasgus":{"lemma":"Moritasgus","pos":"","gen":"","def":"A god of the Senones, Inscr. Orell. 2028.— A male proper name among the Senones, Caes. B. G. 5, 54, 2. mŏrĭtŭrĭo, 4, v. n. desid. , to desire to die, Cic. ap. Aug. de Gramm. p. 2006 P."},"mormorion":{"lemma":"mormorion","pos":"","gen":"","def":", a kind of darkbrown rock crystal, Plin. 37, 10, 63, § 173."},"mormyr":{"lemma":"mormyr","pos":"","gen":"","def":", = μορμύρος, a sort of fish in Pontus: pictae mormyres, Ov. Hal. 110"},"morpheus":{"lemma":"Morpheus","pos":"","gen":"","def":", = Μορφεύς, the son of Sleep and god of dreams: excitat Morphea, Ov. M. 11, 634; 647."},"morphnos":{"lemma":"morphnos","pos":"","gen":"","def":", = μορφνός, a kind of eagle that lives near lakes, Plin. 10, 3, 3, § 7."},"morrenas":{"lemma":"Morrenas","pos":"adj.","gen":"","def":"comm., of or belonging to Morrena or Morena (a country of Mysia), Inscr. Grut. 760, 4."},"mors":{"lemma":"mors","pos":"","gen":"","def":"root mor, v. morior (dat. morte, Varr. ap. Gell. 24), death in every form, natural or violent (syn.: letum, nex). Lit.: omnium rerum mors est extremum, Cic. Fam. 6, 21, 1: mors ultima linea rerum est"},"morsum":{"lemma":"morsum","pos":"","gen":"","def":"mordeo, a bit, little piece, e. g. of wool (poet.): lanea morsa, Cat. 64, 316. morsus, a, um, Part., from mordeo. morsus, ūs, m. mordeo, a biting"},"morta":{"lemma":"Morta","pos":"","gen":"","def":", = Μορτή, one of the Fates, Liv. Andron. ap. Gell. 3, 16, 11: tria sunt nomina Parcarum, Nona, Decima, Morta, Caesell. ib. mortālis, e, adj. mors, subject to death, liable to die"},"moschi":{"lemma":"Moschi","pos":"adj.","gen":"","def":", a people between the Black and the Caspian Seas, Mela, 1, 2, 5; 3, 5, 4; Luc. 3, 270; Plin. 6, 4, 4, § 29.— Hence, Moschĭcus, a, um, adj., Moschian, Plin. 5, 27, 27, § 99"},"moschis":{"lemma":"Moschis","pos":"","gen":"","def":", a female proper name, Afran. ap. Non. 318, 5; Inscr. Mur. 477, 5."},"moschus":{"lemma":"Moschus","pos":"","gen":"","def":"A rhetorician of Pergamus, accused of poisoning, Hor. Ep. 1, 5, 9.— A Roman surname, Inscr. Mur. 477, 5. moscilli or moscŭli, ōrum, m. dim. mos"},"mostellum":{"lemma":"mostellum","pos":"","gen":"","def":"Mostellaria. Mostēni, ōrum, m., the inhabitants of Mostena or Mostene, a city of Lydia, Tac. A. 2, 47. Mŏsŭla, ae, v. Mosella. mōtābĭlis, e, adj. moto, moving, that moves: anima, Vulg. Gen. 1"},"mox":{"lemma":"mox","pos":"adv.","gen":"-class","def":"etym. dub.; cf. Sanscr. mankshu, ready, soon, soon, anon, directly, presently"},"moyses":{"lemma":"Moyses","pos":"","gen":"","def":"Moses. Mŏysītĭcus, a, um, adj. Moyses, of or belonging to Moses (post-class.), Venant. Vit. S. Mart. 2, 28."},"mu":{"lemma":"mu","pos":"interj.","gen":"-class","def":", = μῦ, a slight sound made with the closed lips (ante-class.): neque, ut aiunt, mu facere audent, to mutter, make a muttering, Enn. ap. Varr. L. L. 7, § 101 Müll. (Enn. p. 175"},"muchula":{"lemma":"muchula","pos":"","gen":"","def":", the Persian name of the precious stone telicardios, Plin. 37, 10, 68, § 183. Mūcĭa, ae, v. Mucius. Mūcĭānus (Mut-), a, um, v. Mucius. mūcĭdus (mucc-), a, um, adj. mucus. Mouldy"},"mucro":{"lemma":"mucro","pos":"","gen":"","def":", a sharp point or edge; esp., the point of a sword, the sword's point (class."},"mufrius":{"lemma":"mufrius","pos":"","gen":"","def":", a term of abuse: mufrius non magister, Petr. 58 fin. muger dici solet a Castrensium hominibus, quasi mucosus, is, qui talis male ludit, Paul. ex Fest. p. 158, 27 Müll. (cf. Engl. smuggle"},"mulc":{"lemma":"mulc","pos":"","gen":"","def":"37, 10, 68, § 183; al. muchala. mulcātor, ōris, m. mulco, he who handles roughly, Isid. 10, 178"},"mulcta":{"lemma":"mulcta","pos":"","gen":"-t","def":"multa, etc."},"mulctra":{"lemma":"mulctra","pos":"","gen":"-pail","def":"mulgeo, a milkingpail, milk-pail. Lit.: bis venit ad mulctram, Verg. E. 3, 30: e mulctrā recens caseus, Col. 8, 17, 13; cf. mulctrum.— Transf., the milk in a milk-pail, Col. 7, 8, 1"},"mulctrum":{"lemma":"mulctrum","pos":"","gen":"-pail","def":"id., a milking-pail: illic injussae veniunt ad mulctra capellae, Hor. Epod. 16, 49; Val. Fl. 6, 145; Calp. Ecl. 3, 66; 4, 25; 5, 33; 9, 36; Prud. Cath. 3, 66: mea, Nemes. Ecl. 2, 35; cf. mulctra."},"mulctus":{"lemma":"mulctus","pos":"","gen":"-class","def":"(only in abl. sing.) , a milking (ante-class.), Varr. R. R. 2, 11, 2. mulgāre, is, n. mulgeo, a milkingpail: tepidi mulgaria lactis, Valg. ap. Serv and Philarg. ad Verg. G. 3, 177. mulgĕo, si"},"mullo":{"lemma":"mullo","pos":"v.","gen":"","def":"a., to sew; v. mulleus. mullŭlus, i, m. dim. mullus, a little red mullet or barbel: barbatulos mullulos exceptans, Cic. Par. 5, 2, 38 dub. (Orell., mullos)."},"mullus":{"lemma":"mullus","pos":"","gen":"","def":", a kind of fish highly esteemed, the red mullet, barbel, Varr. R. R. 3, 17; Plin. 9, 17, 30, § 64: mulli barbati in piscinis, Cic. Att. 2, 1, 7; Juv. 5, 92"},"mulsa":{"lemma":"mulsa","pos":"","gen":"","def":", v. mulceo, P. a., B. 1. mulsĕus, a, um, adj. mulsum, v. mulceo, sweetened with honey; sweet as honey (post-Aug.): mulsea aqua, honey-water, hydromel, Col. 8, 7, 4"},"mulsum":{"lemma":"mulsum","pos":"","gen":"","def":", v. mulceo, P. a. B. 2. mulsūra, ae, f. mulgeo, a milking, Calp. Ecl. 5, 34. mulsus, a, um, Part. and P. a., v. mulceo fin. multa (mulcta), ae, f. Sabine, acc. to Varr. ap. Gell. 11, 1, 5"},"multa":{"lemma":"multa","pos":"adj.","gen":"","def":"fem., v. multus. multangŭlus (multiang-), a, um, adj. multus-angulus, having many angles, multangular, Lucr. 4, 654: forma, Mart. Cap. 2, § 138. multănĭmis, e, adj. multus-animus"},"multannus":{"lemma":"multannus","pos":"adj.","gen":"","def":"multusannus, of many years, ancient: πολυχρόνιος, multannus, Gloss. Gr. Lat. multātīcĭus (mulct-), or -tĭus, a, um, adj. 1. multa, of or belonging to fines, fine-: pecunia, fine-money, Liv. 10, 23"},"multifructus":{"lemma":"multifructus","pos":"adj.","gen":"","def":"multusfructus, = πολύκαρπος, abounding in fruit, Fulg. Myth. 3, 2"},"multum":{"lemma":"multum","pos":"adv.","gen":"","def":", v. multus fin. multus (old form moltus), a, um; comp. plus"},"mulucha":{"lemma":"Mulucha","pos":"","gen":"","def":"and f. Masc., a river in Africa, between Mauritania and Numidia, now Maluja, Sall. J. 19, 7; 92, 5; 110, 8; Mel. 5, 1, 5"},"mummia":{"lemma":"Mummia","pos":"","gen":"","def":"Mummius. Mummĭus, a, name of a Roman gens. The most celebrated are, L. Mummius Achaicus, the destroyer of Corinth, Cic. Off. 2, 22, 76; Cic. Verr. 2, 1, 21, § 55; 2, 3, 4, § 9"},"munda":{"lemma":"Munda","pos":"","gen":"","def":"A city in Hispania Baetica, taken by Coesar in the war against the son of Pompey, now Monda, Liv. 24, 42, 1; Auct. B. Hisp. 32; Val. Max. 7, 6, 5; Sil. 3, 100"},"mundensis":{"lemma":"Mundensis","pos":"adj.","gen":"","def":"Munda, of or belonging to Munda: duces, Auct. B. Hisp. 36: proelium, Suet. Caes. 56. mundĭālis, e, adj. 2. mundus, worldly, mundane (eccl. Lat.). elementa, Tert. Spect. 9: sordes"},"mundo":{"lemma":"mundo","pos":"v.","gen":"","def":"a. 1. mundus, to make clean, to clean, cleanse (post-Aug."},"mundum":{"lemma":"mundum","pos":"","gen":"","def":"2. mundus init."},"mundus":{"lemma":"mundus","pos":"adj.","gen":"-class","def":"Sanscr. mund, purificari, clean, cleanly, nice, neat, elegant. Lit. (class."},"murcus":{"lemma":"murcus","pos":"","gen":"-class","def":", a coward, who, to escape military service, cuts off his thumb (post-class.), Amm. 15, 12, 3."},"murena":{"lemma":"Murena","pos":"adj.","gen":"-class","def":"(ante-class form Muraena, but without class. authority), a Roman surname in the gens Licinia, Varr. R. R. 3, 3, 10"},"murgiso":{"lemma":"murgiso","pos":"","gen":"","def":", a crafty advocate: murgisonem dixerunt a morā et decisione, Paul. ex Fest. p. 144 Müll. mŭrĭa, ae (collat. form mŭrĭes, ēi. v infra), f. ἁλμυοίς, salt liquor, brine"},"murmillo":{"lemma":"murmillo","pos":"","gen":"","def":"mirmillo."},"murmur":{"lemma":"murmur","pos":"","gen":"-instruments","def":"(m.: murmur fit verus, Varr. ap. Non. 214, 14) [Sanscr. marmara, susurrus, murmur, and the Greek μορμύρω and μυρμύρω], a murmur, murmuring; a humming, roaring, growling, grumbling"},"murocincta":{"lemma":"Murocincta","pos":"","gen":"","def":", a villa of Valentinian in Lower Pannonia, Amm. 30, 10, 4. murra (less correctly myrrha, murrha, v. Bramb. Orthog. p. 107), ae, f., = μύρρα. Prop., the myrrh-tree, an Arabian tree"},"murra":{"lemma":"murra","pos":"","gen":"","def":", = μύρρα and μνρρίς, a plant, called also smyrrhiza, sweet - cicely, Plin. 24, 16, 97, § 154. murra (less correctly murrha, myrrha), ae, f."},"murta":{"lemma":"murta","pos":"","gen":"","def":"myrtus. murtātus and murtĕus, a, um, v. myrt-. murtētum, v. myrtetum. Murtĭus, v. Murcius."},"murtum":{"lemma":"murtum","pos":"","gen":"","def":"myrtum. mūrus (archaic orthogr. moerus, Varr. L. L. 5, 32, § 41 Müll.; Enn. ap. Serv. Verg. G. 1, 18, or Ann. v. 376 Vahl.; Verg. A. 10, 24: moirus, Inscr. Orell. 566), i, m. from root mū-"},"musca":{"lemma":"musca","pos":"","gen":"","def":"Sanscr. makshikà, a fly; Gr. μυῖα, of which musca, μυἱσκα, may be a dim. form; cf. Germ. Mücke"},"muscerda":{"lemma":"muscerda","pos":"","gen":"-dung","def":"id., mouse-dung, Plin. 29, 6, 34, § 106"},"muscus":{"lemma":"muscus","pos":"","gen":"","def":"Moss, Cato, R. R. 6: musco circumlita saxa, Hor. Ep. 1, 10, 7: mollis, Ov. M. 8, 562.— Musk, Hier. in Jov. 2, n. 8. mūseiārĭus and mūsaeārĭus, ii, m., for musivarius"},"musmo":{"lemma":"musmo","pos":"","gen":"","def":"musimo. Mūsōnĭus, i, m., a famous Stoic philosopher of the time of Tiberius, Vespasian, and Titus, teacher of Epictetus, Tac. A. 14, 59; Plin. Ep. 3, 11, 5; Amm. 27, 9, 6"},"musso":{"lemma":"musso","pos":"v.","gen":"","def":"n. and a. (depon. collat. form: discumbimus mussati, Varr. ap. Non. 249, 10) [root mu-, shut; Sanscr. mūkas, dumb; Gr. μυάω, μυώψ; cf. μυστήριον; Lat. mutus], to say in a low tone, to mutter, murmur"},"mussor":{"lemma":"mussor","pos":"v.","gen":"","def":"dep., v. musso, init. mustācē, ēs, f., a kind of laurel, Plin. 15, 30, 39, § 127. mustācĕus, i, m., and mustācĕum, i, n., a must-cake or laurel-cake"},"mustax":{"lemma":"mustax","pos":"","gen":"","def":", a kind of laurel, Plin. 15, 30, 39, § 127. mustēcŭla, ae, f. dim. mustela, a small weasel: velox mustecula dintrit (al. velox mustelaque dintrit), Auct. Carm. Phil. 61. mustēla or mustella, ae"},"mustum":{"lemma":"mustum","pos":"","gen":"","def":"mustus, II. mustŭōsus, a, um, adj. mustum, full of new wine (late Lat.), Cassiod. ap. Ps. 79, s. f."},"mustus":{"lemma":"mustus","pos":"adj.","gen":"-class","def":", young, new, fresh (as adj. only ante-class.): agna, Cato ap. Prisc. 711 P.: vinum, id. R. R. 115.— Subst.: mustum, i, n., new or unfermented wine, must, Cato, R. R. 120: dulce, Verg. G. 1"},"mutgo":{"lemma":"Mutgo","pos":"","gen":"","def":", a king of Tyre, the father of Pygmalion, Just. 18, 4, 3 (in Virgil called Belus, Verg. A. 1, 621). Muthul, a river in Numidia, Sall. J. 48, 3. mŭtĭcus, a, um, adj., for mutilus, curtailed"},"muttum":{"lemma":"muttum","pos":"","gen":"","def":", a mutter, a grunt: muttum, γρῦ, Gloss. Vet.: non audet dicere muttum, Lucil.: proverbialiter dicimus, muttum nullum emiseris, id est, verbum, Cornutus ad Pers. 1, 119. mūtŭārĭus, a, um, adj. mutuus"},"mutucumenses":{"lemma":"Mutucumenses","pos":"","gen":"","def":", the inhabitants of a city in Latium, Plin. 3, 5, 9, § 69 (rejected by Jahn). mūtŭē, adv., v. mutuus fin. B. mūtŭĭter, adv., v. mutuus fin. C. mūtŭĭto, āre, v. a., or mūtŭĭtor, āri"},"mya":{"lemma":"mya","pos":"","gen":"","def":", = μύα, a kind of mussel on the shores of the Thracian Bosporus, Plin. 9, 35, 56, § 115. myăcanthos, i, f., or myăcan-thon, i, n., = ὁ μυάκανθος, τὸ μυάκανθον, a plant, also called corruda, and"},"myax":{"lemma":"myax","pos":"","gen":"","def":", = μύαξ, a kind of mussel, Plin. 32, 9, 30, § 95. Mycălē, ēs, f., = Μυκάλη. A promontory and city in Ionia, opposite the Isle of Samos, Ov. M. 2, 223"},"mycon":{"lemma":"Mycon","pos":"","gen":"","def":"Micon. Mycŏnos or -us, i, f., = Μύκονος, one of the Cyctades, now Mykoni, Mel. 2, 7, 11; Verg. A. 3, 76"},"myiscae":{"lemma":"myiscae","pos":"","gen":"-mussels","def":", = μυἱσκαι, small sca-mussels, Plin. 32, 9, 31, § 98; 32, 11, 53, § 149."},"myiscus":{"lemma":"myiscus","pos":"","gen":"-mussel","def":", a small sea-mussel, Plin. 32, 11, 53, § 149. Mȳlae, ārum (and Mȳlē, ēs, f., Sil. 14, 202), f., = Μύλαι. A city in Sicily, now Milazzo, Plin. 3, 8, 14, § 90; Vell. 2, 79, 4"},"myops":{"lemma":"myops","pos":"adj.","gen":"-sighted","def":", = μυώψ, near-sighted (post-class.), Dig. 21, 1, 10, § 3. myŏsōta, ae, and myŏsōtis, ĭdis, f., = μυοσώτη, μυοσωτίς, mouse-ear, a plant, Plin. 27, 12, 80, § 105. myŏsōton, i, n., = μυόσωτον"},"myotacismus":{"lemma":"myotacismus","pos":"","gen":"-mus","def":"l. for moetacis-mus, the frequent repetition or recurrence of the letter m, Diom. 448 P.; Mart. Cap. 5, § 514"},"myriza":{"lemma":"Myriza","pos":"","gen":"","def":"Myrriza. Myrmēcĕs Scŏpŭli, rocks in the sea, near Smyrna, Plin. 5, 29, 31, § 119. myrmēcĭas, ae, m., = μυρμηκίας, a black precious stone, with protuberances like warts, Plin. 37, 10, 63"},"myrmillo":{"lemma":"myrmillo","pos":"","gen":"","def":"mirmillo. myrmillōnĭca scūta, v. mirmillonicus."},"myro":{"lemma":"Myro","pos":"","gen":"","def":", v. 1. Myron. myrŏbălănum, i, n., = μυροβάλανον, the fruit of a palm-tree from which a balsam was made, the behen-nut; also, the balsam itself, Plin. 12, 21, 46, § 100; 12, 22, 47, § 103"},"myrrha":{"lemma":"myrrha","pos":"","gen":"","def":"1. murra.‡ † myrrha-, etc., v. murra-, etc. myrrhĕus, v. murreus. myrrhĭnus, v. murrinus."},"myrrhis":{"lemma":"myrrhis","pos":"","gen":"","def":"2. murra."},"myrtea":{"lemma":"Myrtea","pos":"","gen":"","def":"Murcia. myrtĕŏlus (murtĕŏlus, myr-tĭŏlus), a, um, adj. dim. , of the color of myrtle-blossoms: myrteolo modo crine viret (al. murceolo, al. murciolo), Col. poët. 10, 237. myrtēta, ae"},"myrtis":{"lemma":"myrtis","pos":"","gen":"","def":", = μυρτίς, a kind of geranium, Plin. 26, 11, 68, § 108. myrtītes, ae, m., = μυρτίτης οἶνος. Myrtle-wine: vinum myrtiten sic facito, Col. 12, 38: vinum myrtiten sic facies, Pall. 2"},"mys":{"lemma":"mys","pos":"","gen":"-mussel","def":", = μῦς, a sea-mussel, Plin. 32, 11, 53, § 149; 9, 35, 56, § 115. Mȳs, Myos, m., = Μῦς, a famous artist in embossed work, Mart. 8, 51, 1; 8, 34, 1; Plin. 33, 12, 55, § 155"},"mystes":{"lemma":"mystes","pos":"","gen":"","def":"mysta. mystĭcē, adv., v. mysticus fin. mystĭcus, a, um, adj., = μυστικός, of or belonging to secret rites or mysteries, mystic, mystical (poet.): mystica sacra Dindymenes, Mart. 8, 81"},"mystrum":{"lemma":"mystrum","pos":"","gen":"","def":", = μύστρον, the fourth part of a cyathus, Rhem. Fan. de Pond. et Mens. 77. mystus, a false read. for Nystrus, Plin. 4, 12, 19, § 53. Mȳsus, a, um, adj., v. Mysia, II. C. mytăcismus, i. q. metacismus"},"myxa":{"lemma":"myxa","pos":"","gen":"-tree","def":", = μύξα. A kind of plum-tree, Plin. 13, 5, 10, § 51.— = rostrum, the curved part of a lamp, nozzle, Mart. 14, 41, 2. myxo or myxon, ōnis, m., = μύξων, a fish, also called bacchus, Plin. 32, 7, 25"},"myxum":{"lemma":"myxum","pos":"","gen":"","def":"myxa, the fruit of the myxa, Pall. 3, 25 fin.; Gargil. Mart. Medic. ex Rom. § 15. N N, n, had its full, pure sound only when it began a syllable"},"nabdalsa":{"lemma":"Nabdalsa","pos":"","gen":"","def":", a distinguished Numidian, a general of Jugurtha, Sall. J. 70, 2. †† nabis, is, f., or nabun Ethiopic, a camelopard, Plin. 8, 18, 27, § 69; Sol. 30."},"nabis":{"lemma":"Nabis","pos":"","gen":"","def":", = Νάβις, a king of Sparta, about 200 B. C., Liv. 29, 12, 14; 31, 25, 3; 34, 24, 6."},"nablia":{"lemma":"nablia","pos":"","gen":"","def":"naulia. nablĭo, ōnis, m., one who plays the nablium (naulium): nablio, ψάλτης, Gloss. Philox. nablĭum or nablum, i, n., a musical instrument of ten or twelve strings, played with both hands"},"nablizo":{"lemma":"nablizo","pos":"v.","gen":"","def":"a., to play the nablium (naulium): nablizo, ψάλλω, Gloss. Philox."},"nabun":{"lemma":"nabun","pos":"","gen":"","def":"1. nabis. nacca (nacta, natta), ae, m., = νάκτης (pure Lat. fullo), a fuller: naccae appellantur vulgo fullones, ut ait Curiatius, quod nauci non sint"},"nacta":{"lemma":"nacta","pos":"","gen":"","def":", v. nacca. nactus, a, um, Part., from nanciscor."},"nae":{"lemma":"nae","pos":"","gen":"","def":"3. ne), particle of assurance, verily, truly. naenĭa, v. nenia. Naevĭa porta, v. 2. Naevius, A. Naevĭānus, v. 2. Naevius, B. naevĭus, a, um, adj. naevus, that has a mole on his body, Arn. 3"},"naeuus":{"lemma":"naevus","pos":"","gen":"","def":"for gnaevus, root gna-, gen-, of genus, gnatus, a mark born with one"},"naharuali":{"lemma":"Naharvali","pos":"","gen":"","def":"Nahanarvali. Nāĭăs, ădis, and more freq. Nāĭs, ĭdis and ĭdos (plur. ĭdas), f., = Ναϊάς and Ναἱς (floating, swimming, that is in the water), a water-nymph, Naiad: illum fontana petebant Numina"},"nana":{"lemma":"Nana","pos":"","gen":"","def":", a nymph, daughter of Sangarius and mother of Atys, Arn. 5, p. 158. nancĭo, īre, v. a., and nancĭor, īri, v. dep. a. , to get, gain, obtain (post-class.): si nanciam populi desiderium"},"nanciscor":{"lemma":"nanciscor","pos":"v.","gen":"-operation","def":"Mai. ad Cic. Rep. 1, 10, 16; Drak. ad Liv. 24, 31; 25, 30; inf. nanciscier, Plaut. As. 2, 2, 59), 3, v. dep. a. [Sanscr. naç, obtain; Gr. ἐνεκ- in ἤνεγκα, etc."},"nanctus":{"lemma":"nanctus","pos":"","gen":"","def":"nanciscor it."},"nanis":{"lemma":"Nanis","pos":"","gen":"","def":"nana, a Roman surname, Inscr. Fabr. p. 48, n. 269. Nannētes, v. Namnetes."},"nanque":{"lemma":"nanque","pos":"","gen":"","def":"namque. nans, nantis, Part. and P. a., v. 1. no. Nantŭātes, um, m., a people in Gallia Narbonensis, at the foot of the Alps, Caes. B. G. 3, 1; 4, 10"},"napurae":{"lemma":"napurae","pos":"","gen":"","def":", straw ropes: nectere ligare significat ... pontifex minor ex stramentis napuras nectito, id est funiculos facito, quibus sues annectantur, Paul. ex Fest. s. v. nectere, p. 165 Müll."},"nar":{"lemma":"Nar","pos":"","gen":"","def":", a river of Illyria, Mela, 2, 3, 13."},"narbo":{"lemma":"Narbo","pos":"adj.","gen":"-b","def":", and (late Lat.) Nar-bōna, ae, f., also with the appellation Marcius (after the consul Q. Marcius Rex, who led a colony thither A. U. C. 636), a city in Gaul"},"narcissus":{"lemma":"narcissus","pos":"","gen":"","def":", = νάρκισσος, the narcissus, Plin. 21, 5, 12, § 25; 21, 19, 75, § 128; Verg. E. 5, 38; id. G. 4, 123; 160."},"nardus":{"lemma":"nardus","pos":"","gen":"-balsam","def":", and nardum, i, n., = νάρδος, nard, Plin. 12, 12, 26, § 42: nardus Gallicus, id. 12, 12, 26, § 46.— Transf., nard-balsam, nard-oil: Assyriāque nardo Potamus uncti, Hor. C. 2, 11"},"nartes":{"lemma":"Nartes","pos":"","gen":"","def":", v. 2, Nar. narthēcĭa or narthēcya, ae, f, = ναρθηκία or ναρθηκύα, a low species of ferula, Plin. 13, 22, 42, § 123. narthēcĭum, ii, n."},"narthex":{"lemma":"narthex","pos":"","gen":"","def":", = ὁ νάρθηξ, the shrub ferula, Plin. 13, 22, 42, § 123. nārus, a, um, v. gnarus init. Nārycĭa, ae, f., the city of Locri, founded in Lower Italy by the Ozolian Locrians (from Narycion), Ov. M. 15"},"nasco":{"lemma":"nasco","pos":"","gen":"","def":"nascor fin. nascor, nātus, nasci (ante-class., and in poets of the class. period also gnatus, v. under P. a. B.; part. fut. nasciturus, Pall. Jun. 7, § 8"},"natiso":{"lemma":"Natiso","pos":"","gen":"","def":", = Νατίσων, a small Italian river near Aquileia, now Natisone, Mel. 2, 4, 3"},"natta":{"lemma":"natta","pos":"","gen":"","def":"nacca. nātu, v. 2. natus. nātŭla, ae, f. dim. nata, a little daughter, Inscr. Gud. 335, 12. nātūra, ae, f. nascor, birth. Lit. (very rare): naturā tu illi pater es, consiliis ego, Ter. Ad. 1, 2, 46"},"nauarchia":{"lemma":"nauarchia","pos":"","gen":"","def":", = ναυαρχία, the command of a vessel, Cod. Th. 13, 5, 20."},"nauarchus":{"lemma":"nauarchus","pos":"","gen":"","def":"(less correctly nav-), = ναύαρχος, the master of a vessel, Cic. Verr. 2, 5, 24, § 60; Tac. A. 15, 51; Inscr. Orell. 3615; 3624"},"nauci":{"lemma":"nauci","pos":"","gen":"","def":"naucum. nauclērĭcus, a, um, adj., = ναυκληρικός, of or belonging to a ship-owner or ship-master: facito uti venias (ornatu) ornatus huc nauclerico, in a skipper's dress, Plaut. Mil. 4, 4"},"naucum":{"lemma":"naucum","pos":"","gen":"","def":", or naucus, i, m. etym. dub."},"nauportum":{"lemma":"Nauportum","pos":"","gen":"-portus","def":", a city in Upper Pannonia, the mod. Laybach, Tac. A. 1, 20; Vell. 2, 110, 4.—Near it is the river Nau-portus, i, m., Plin. 3, 18, 22, § 128."},"naura":{"lemma":"Naura","pos":"","gen":"","def":"Nautaca. nauscit (qs. naviscit), said of a bean, which opens in the shape of a ship, Paul. ex Fest. p. 168 and 169 Müll. nausĕa or nausĭa, ae, f., = ναυσία"},"naustathmos":{"lemma":"Naustathmos","pos":"","gen":"","def":", = Ναύσταθμος, a seaport in Ionia, near Phocaea, Liv. 37, 31 fin. naustĭbŭlum, i, n. navis, a vessel shaped like a ship: naustibulum vocabant antiqui vas alvei simile, videlicet a navis similitudine"},"nausum":{"lemma":"nausum","pos":"","gen":"","def":", a kind of Gallic ship: nauso advehi, Aus. Ep. 22"},"nautes":{"lemma":"Nautes","pos":"","gen":"","def":", the primogenitor of the Nautii (v. h. v.), Verg. A. 5, 704"},"naxa":{"lemma":"naxa","pos":"","gen":"","def":", v. nassa. naxĭum, ii, n., a stone used for polishing marble, which was found on the island of Cyprus and prepared in the city of Naxos, in Crete, Plin. 36, 7, 10, § 54; 37, 8, 32, § 109."},"naxos":{"lemma":"Naxos","pos":"adj.","gen":"","def":", = Νάξος, the isle of Naxos (now Naxia, or Axia), in the Aegean Sea, the largest of the Cyclades, famed for its wines, and for the abandonment there of Ariadne by Theseus, Plin. 4, 12, 22, § 67"},"nebris":{"lemma":"Nebris","pos":"","gen":"","def":", a Roman surname, Inscr. Grut. 476, 8. nebrītis, ĭdis, f., = νεβρῖτις, a precious stone sacred to Bacchus, Plin. 37, 10, 64, § 175. Nebrōdes, is, m., = Νεβρώδη or Νευρώδη, τά"},"nebrundines":{"lemma":"nebrundines","pos":"","gen":"","def":"nefrens."},"nebrus":{"lemma":"Nebrus","pos":"","gen":"","def":", = Νεβρός (fawn), a Roman surname, Inscr. Grut. 476, 8. nĕbŭla, ae, f. like nubes; Sanscr. nabhas; Lat. aër, caelum"},"necdum":{"lemma":"necdum","pos":"","gen":"","def":"neque fin. Nĕcepsus, i (Nĕcepso, ōnis, Jul. Firm. 8), m., a mythic astrologer in Egypt, a disciple of Aesculapius and Anubis, Aus. Ep. 19, 18. necerim, nec eum, Paul. ex Fest. p. 162"},"nechon":{"lemma":"nechon","pos":"","gen":"","def":", a kind of spice with which sweet things were kept from turning, Apic. 1, 14. necnĕ, adv. neque-ne, or not, is used in the second half of a disjunctive interrogation, corresponding to -ne or utrum"},"nectar":{"lemma":"nectar","pos":"","gen":"","def":", = νεκταρ, nectar, the drink of the gods. Lit.: non enim ambrosiā deos aut nectare ... laetari, arbitror, Cic. Tusc. 1, 26, 65; cf. id. N. D. 1, 40, 112; Ov. M. 3, 318; 10, 161; 14, 606"},"necto":{"lemma":"necto","pos":"v.","gen":"","def":"Neue, Formenl. 2, 494 sq.), xum (inf. pass. nectier, Cic. Rep. 2, 34, 59), 3, v. a. with neo, kindr. to Sanscr. nah, ligare, nectere, and Gr. νέω, νήθω, to bind, tie, fasten"},"neglectim":{"lemma":"neglectim","pos":"adv.","gen":"","def":"neglectus, negligently, Poët. ap. Anthol. Lat. 1, p. 637 Burm. neglectĭo, ōnis, f. neglego, a neglecting, neglect: amicorum, Cic. Mur. 4, 9."},"neglector":{"lemma":"neglector","pos":"","gen":"","def":"id., a neglecter, slighter (late Lat.): praeceptorum dei, Aug. Serm. Divers. 45, 9. neglectus, a, um, Part. and P. a., from neglego."},"neglectus":{"lemma":"neglectus","pos":"","gen":"","def":"neglego, a neglecting, neglect (very rare for neglectio, neglegentia): quapropter haec res ne utiquam neglectui mihi est, Ter. Heaut. 2, 3, 116: a somno moventium, Plin. 7, 51, 52, § 171. neglĕgens"},"negumate":{"lemma":"negumate","pos":"","gen":"","def":"nego init."},"nehalennia":{"lemma":"Nehalennia","pos":"","gen":"-goddess","def":", a river-goddess worshipped at the mouth of the Rhine, Inscr. Orell. 2029 sq.; 2775"},"nemetocenna":{"lemma":"Nemetocenna","pos":"","gen":"","def":", a city of Belgic Gaul, in the territory of the Atrebates, the modern Arras, Hirt. B. G. 8, 47"},"nemossus":{"lemma":"Nemossus","pos":"","gen":"","def":", a city of Aquitanian Gaul, the capital of the Arverni, now Clermont, Luc. 1, 419. nempe (often nĕmpĕ in Plaut., e. g. Mil. 906, 922; Trin. 328, 427, etc."},"neopum":{"lemma":"neopum","pos":"","gen":"-oil","def":", olive-oil, Plin. 15, 7, 7, § 26. nĕōtĕrĭcē, adv., v. neotericus. nĕōtĕrĭcus, a, um, adj., = νεωτερικός. New, modern (post-class.): scriptor, Claud. Mamert. de Stat. Anim. 1, 3.— Subst.: nĕōtĕrĭci"},"neptis":{"lemma":"neptis","pos":"","gen":"","def":"(like nepos, orig. comm.; as masc., still found in an inscr.: C. COELIO VERO NEPTI, Inscr. Murat. 692, 2"},"nersae":{"lemma":"Nersae","pos":"","gen":"","def":", an ancient city of the Aequi, Verg. A. 7, 744. Nersĭa, ae, f., an Etruscan goddess, Tert. Apol. 24."},"nerthus":{"lemma":"Nerthus","pos":"","gen":"","def":"nirdu; cf. Sanscr. narakas, underworld; Gr. ἔνεροι, f., a goddess of the ancient Germans, the Earth, Tac. G. 40, 4; v. Orell. ad h. l."},"nertobriga":{"lemma":"Nertobriga","pos":"","gen":"","def":"A city in Hispania Baetica, surnamed Concordia Julia, now Valera la Vieja, Plin. 3, 1, 3, § 14.— A city of Celtiberia, now Almunia, Flor. 2, 17, 10. Nerŭlum, i, n., a fortified city in Lucania"},"nerua":{"lemma":"Nerva","pos":"adj.","gen":"","def":", a Roman family name of the Licinii, Cocceii, and Silii. So M. Cocceius Nerva, the Roman emperor.—Hence, Nervĭus, a, um, adj., of or belonging to the emperor Nerva, Nervian: miles"},"neruus":{"lemma":"nervus","pos":"","gen":"","def":"root snar-; Old Germ. snara, a snare; Gr. νεῦρον"},"nesebis":{"lemma":"Nesebis","pos":"","gen":"","def":"Nisibis. nesi, pro sine positum est in lege dedicationis arae Dianae Aventinensis, Paul. ex Fest. p. 165 Müll. Nēsĭmăchus, i, m., the father of Hippomedon, Hyg. Fab. 70. Nēsiōtae, ārum, m."},"nessus":{"lemma":"Nessus","pos":"adj.","gen":"","def":", = Νέσσος. A river in Thrace, now the Mesto or (Turkish) Karasu, Liv. 45, 29, 6"},"nestis":{"lemma":"nestis","pos":"","gen":"","def":", = νῆστις, the second part of the small intestines; Lat. intestinum jejunum, so called because always found empty: nestide paralysi vitiata, Cael. Aur. Tard. 2, 1, 11"},"nestos":{"lemma":"Nestos","pos":"","gen":"","def":", v. Nessus, I. nētē, ēs, f., = νἠτη (sc. χορδή), the undermost or last string of a musical instrument, i. e. the highest note, Vitr. 5, 4, 5. Nētīnenses, ĭum, v. Netum, A Nētīni, ōrum, v. Netum"},"neu":{"lemma":"neu","pos":"adv.","gen":"","def":", v. neve. neuras (nevras), ădis, f., = νευράς, The plant manicon, which excites the nerves, Plin. 21, 31, 105, § 179.— A plant, called also poterion: poterion, aut ut alii vocant, phrynion"},"neuras":{"lemma":"nevras","pos":"","gen":"","def":"neuras."},"neurospaston":{"lemma":"neurospaston","pos":"","gen":"","def":", = νευρόσπαστον, a figure set in motion by strings, a puppet, marionette, Gell. 14, 1, 23 (by others written as Greek)."},"neurospastos":{"lemma":"neurospastos","pos":"","gen":"-brier","def":", = νευρόσπαστος, the wild-brier, dog-rose, Plin. 24, 14, 74, § 121."},"neuter":{"lemma":"neuter","pos":"adj.","gen":"-uter","def":"neutri, Varr. L. L. 9, § 62, acc. to the MSS.; cf. §§ 55 and 58; Aus. Ep. 50; and by grammarians always in the phrase neutri generis, of the neuter gender, Charis. 13 P.; Diom. 277 P. al."},"nex":{"lemma":"nex","pos":"","gen":"","def":"neco, death (syn.: mors, letum). Lit. A violent death, murder, slaughter (cf.: caedes, occisio): mater terribilem minatur vitae cruciatum et necem, Enn. ap. Cic. de Or. 3, 58"},"nexo":{"lemma":"nexo","pos":"conj.","gen":"-class","def":", acc. to Prisc. 9, 6, 33, p. 860 sq.; 10, 8, 48, p. 904; Diom. 1, p. 366; and in the reading: nexantem nodis seque in sua membra plicantem, Verg. A. 5, 279 Conington"},"nexum":{"lemma":"nexum","pos":"","gen":"","def":"2. nexus, II. nexuōsus, a, um nexus, full of windings, much interlaced, Cassiod. Var. 11, 40 Fig.—Sup.: nexuosissimae quaestionem minutiae, excessively involved or complicated"},"nexus":{"lemma":"nexus","pos":"","gen":"","def":"necto, a tying or binding together, a fastening, joining, an interlacing, entwining, clasping. Lit. (only poet. and in post-Aug. prose): et jam contulerant arto luctantia nexu Pectora pectoribus"},"nicto":{"lemma":"nicto","pos":"v.","gen":"","def":"n., and nictor, ātus, v. dep. n. , to move the eyelids. Lit., to move the eyelids up and down, to wink, blink: plerisque naturale ut nictari (al. nictare) non cessent, Plin. 11, 37, 54, § 144"},"nictus":{"lemma":"nictus","pos":"","gen":"","def":"1. nico, a winking, blinking with the eyes, Caecil. ap. Paul. ex Fest. p. 177 Müll. (but in Ov. M. 3, 460; id. A. A. 1, 138"},"nigir":{"lemma":"Nigir","pos":"","gen":"","def":"Nigris. nīgrans, antis, P. a., v. nigro fin. nīgrēdo, ĭnis, f. niger, blackness, black color (post-class.): capilli corvinā nigredine, App. M. 2, p. 118, 31: nigredo ollae, Vulg. Nah. 2, 10"},"nimbus":{"lemma":"nimbus","pos":"","gen":"-storm","def":"plur. nimbūm, Pac. ap. Trag. Rel. 412 Rib.), m. Sanscr. nabhas, cloud, vapor; Gr. νέφος, νεφέλη"},"ningor":{"lemma":"ningor","pos":"","gen":"","def":"ningo, a fall of snow, App. de Mundo, p. 61, 26. ninguĭdus, a, um, adj. ninguis, full of snow, snowy (post-class.): juga, Aus. Ep. 24, 68: oppida, id. ib. 24, 124: Boreas"},"ninguis":{"lemma":"ninguis","pos":"","gen":"-class","def":"kindr. with nix, snow (ante- and post-class.): albas descendere ningues, Lucr. 6, 736 (but id. 6, 964, the correct read. is nives, v. Lachm. ad h. l.); so according to Lucil. ap. Charis. p. 71 P."},"ninnius":{"lemma":"Ninnius","pos":"","gen":"","def":"23, 8.—So, L. Ninnius Quadratus, a tribune of the people, Cic. Att. 3, 23, 4; id. Sest. 31, 68.— Ninnius Crassus, who translated the Iliad into Latin, Prisc. 865 P."},"niptra":{"lemma":"Niptra","pos":"","gen":"","def":"plur., = Νίπτρα, water for washing, the title of a tragedy of Pacuvius, Cic. Tusc. 2, 21, 48; Gell. 13, 29, 3"},"nix":{"lemma":"nix","pos":"","gen":"","def":"cf. Gr. νίφα (acc.), snow"},"nixus":{"lemma":"nixus","pos":"","gen":"","def":"1. nitor, a pressure (the same as nisus, v. 2, nisus). Lit.: astra se nixu suo conglobata continent, revolution, course, * Cic. N. D. 2, 46, 117. — Transf., a striving, exertion"},"no":{"lemma":"no","pos":"v.","gen":"","def":"n. νέω, to swim, float. Lit.: alter nare cupit: alter pugnare paratu'st, Enn. ap. Paul. ex Fest. p. 166 Müll. (Ann. v. 258 Vahl.): pueris, qui nare discunt, scirpea induitur ratis, Plaut. Aul. 4, 1"},"noctanter":{"lemma":"noctanter","pos":"adv.","gen":"","def":"nox, by night, Cassiod. Hist. Eccl. 6, 31."},"noctesco":{"lemma":"noctesco","pos":"v.","gen":"","def":"n. inch. , to draw towards night, to grow dark: omnia noctescunt, Furius ap. Non. 145, 11"},"noctu":{"lemma":"noctu","pos":"","gen":"","def":"nox. noctŭa, ae, f. nox, a night-owl, an owl, a bird sacred to Minerva: noctua, quod noctu canit ac vigilat, Varr. L. L. 5, § 76 Müll.; Paul. ex Fest. pp. 174 and 175 ib."},"nocturnus":{"lemma":"nocturnus","pos":"adj.","gen":"-time","def":"from the adv. noctu, analog. to diurnus from diu, of or belonging to the night, nocturnal (class.): labores diurnos nocturnosque suscipere, Cic. Sen. 23, 82"},"noctus":{"lemma":"noctus","pos":"","gen":"","def":"nox init. noctūvĭgĭlus (noctīv-), a, um, adj. nox-vigilo, night-watching: Venus, Plaut. Curc. 1, 3, 40. nŏcŭus, a, um, adj. noceo, hurtful, injurious, noxious (very rare), Ov. Hal. 128"},"non-dum":{"lemma":"non-dum","pos":"adv.","gen":"-dum","def":", not yet: nondum sex menses, Plaut. Pers. 1, 3, 57: nondum centum et decem anni sunt, cum, etc., Cic. Off. 2, 21, 75: nondum Voconiā lege latā, id. Rep. 3, 10, 17"},"non-nusquam":{"lemma":"non-nusquam","pos":"adv.","gen":"-nusquam","def":", in some places, Plin. 14, 19, 24, § 120: silices quibusdam in locis rubentes, nonnusquam vero et albi, id. 36, 22, 49, § 168"},"nongentus":{"lemma":"nongentus","pos":"","gen":"","def":", v. nongenti. nongēsĭmus, v. nonigesimus. nōnĭes, adv. nonus, nine times: quinquies, sexies, septies, octies, nonies, decies, Not. Tir. p. 100"},"nonna":{"lemma":"nonna","pos":"","gen":"","def":", v. nonnus. non-nĕ, adv., the interrogative non, expecting an affirmative answer, not? In a direct interrogation: nonne ego hic sto? Plaut. Am. 1, 1, 250: nonne animadvertis? Cic. N. D. 3, 37"},"nonnus":{"lemma":"nonnus","pos":"","gen":"","def":", and nonna, ae, f. A monk; a nun, Hier. Ep. 117, n. 6; id. ib. 22, n. 16.— A tutor, Inscr. Orell. 4670."},"norba":{"lemma":"Norba","pos":"adj.","gen":"","def":", a city of Latium, now called Norma, Liv. 2, 34.— Hence, Norbānus, a, um, adj., of or belonging to Norba, Norban: ager, Liv. 8, 19.—In plur.: Norbāni, ōrum, m., the Norbans, Liv. 8, 1; 27, 10"},"norma":{"lemma":"norma","pos":"","gen":"","def":"for gnorima (cf. Gr. γνώριμος); root, gno-; cf. gnarus, nosco, a square, employed by carpenters, masons, etc., for making right angles (cf. regula). Lit.: anguli ad normam respondentes, Vitr. 7, 3"},"normo":{"lemma":"normo","pos":"v.","gen":"","def":"a. id., to square, to set by the square: basis ad perpendiculum normata, Col. 3, 13, 12. normŭla, ae, f. dim. id., a small square: norma, normula, Not. Tir. p. 119"},"nosmet":{"lemma":"nosmet","pos":"","gen":"","def":"nos fin., and ego. nŏsŏcŏmīum, ii, n., = νοσοκομεῖον, a hospital, infirmary, Cod. Just. 1, 2, 19; 22"},"noster":{"lemma":"noster","pos":"pron.","gen":"-pte","def":"sing. f. nostrāï, Vel. Long. p. 2222 P.; gen. plur. nostrum, Plaut. Men. 1, 2, 25; v. infra.), pron. poss. , our, our own"},"nostos":{"lemma":"Nostos","pos":"","gen":"","def":", = Νόστος (return), name of a Roman slave, Inscr. Fabr. p. 194, n. 41. nŏta, ae, f. nosco, a mark, sign, note (cf.: signum, insigne, indicium): nota alias significat signum"},"nostras":{"lemma":"nostras","pos":"adj.","gen":"","def":"sing. nostratis, Cass. Hem. ap. Prisc. p. 943 P.), adj. noster, of our country, native: arma nostratia, Cato ap. Prisc. p. 943 P.: verba nostratia, Cic. Fam. 2, 11, 1: mirifice capior facetiis"},"notium":{"lemma":"Notium","pos":"","gen":"","def":", a city and promontory near Colophon, in Ionia, Liv. 37, 26; 38, 39; Plin. 5, 29, 31, § 116. nŏtĭus, a, um, adj., = νότιος, southern: notia sidera, Manil. 1, 436"},"notrix":{"lemma":"notrix","pos":"","gen":"","def":"nutrix init. nŏtŭla, ae, f. dim. nota, a little mark, Mart. Cap. 1, § 66. nōtus, a, um, v. nosco fin. Nŏtus and Nŏtos, i, m. Νότος, = auster"},"nouomagus":{"lemma":"Novomagus","pos":"","gen":"","def":"Nivomagus. Nŏvum Cōmum, v. Comum. nŏvus, a, um, adj. Sanscr. navas; Gr. νέος, i. e. νεϝος; cf.: noverca, nuntius, denuo, nuper; Germ. neu"},"noxa":{"lemma":"noxa","pos":"","gen":"-sa","def":"for noc-sa, from noc-eo, like rixa from ringor, hurt, harm, injury, which one does or suffers (v. Döderl. Synon. 2, p. 153 sqq.; not in Cic., but cf. noxia"},"nuba":{"lemma":"Nuba","pos":"","gen":"","def":", v. Nubae fin. Nūbae, ārum, m., = Νοῦβαι, a people of Africa, to the south of Egypt, the Nubians, Sil. 3, 269"},"nubs":{"lemma":"nubs","pos":"","gen":"","def":", v. nubes init. nŭcālis, e, adj. nux, like a nut (postclass.): palmulae nucales, Cael. Aur. Acut. 2, 37. nŭcāmenta, ōrum, n. nux (things in the shape of nuts"},"num":{"lemma":"num","pos":"adv.","gen":"-taking","def":"an acc. m., of which nam is the acc. f., an interrog. particle"},"numella":{"lemma":"numella","pos":"","gen":"","def":", a kind of shackle or fetter, for crimmals, slaves, and cattle: numella genus vinculi, quo quadrupedes deligantur, solet autem ea fieri nervo, aut corio crudo bovis, ut plurimum"},"numellus":{"lemma":"numellus","pos":"","gen":"","def":", v numella fin. nūmen, ĭnis, n. for nuimen, root nu-; Gr. νεύω, nod"},"numquando":{"lemma":"numquando","pos":"num.","gen":"","def":"num. num-quid (nunqu-), adv. interrog. In a direct interrogation, where there is no corresponding term in English: numquid meministi? do you remember? Ter. And. 5, 4, 40: numquid, Gnatho, tu dubitas"},"nunc":{"lemma":"nunc","pos":"adv.","gen":"-ce","def":"Sanscr. nu, nūnam, now; Gr. νύ, νῦν"},"nunc-usque":{"lemma":"nunc-usque","pos":"adv.","gen":"-usque","def":", until now (postclass.), Amm. 14, 2, 13 al. nundĭālis, v. nundinalis. nundĭna, ae, f., v. nundinus, II. Nundĭna, ae, f., v. nundinus, I. nundĭnae, ārum, f., v. nundinus, II."},"nupta":{"lemma":"nupta","pos":"","gen":"","def":", v. nubo. nuptālīcĭus or -tĭus, a, um, adj. nupta, of or belonging to a marriage wedding-, nuptial (only in jurid. Lat.): donum, Dig. 50, 16, 194. nuptĭābĭlis, e, adj. nuptiae, marriageable: nupta"},"nupto":{"lemma":"nupto","pos":"","gen":"-class","def":"freq. n. , to marry wed (post-class.), Tert. Sod. 45. nuptŭla, ae, f. dim. nupta, a young wife, Varr. ap. Non. 357, 2. nuptŭrĭo, īvi, īre, v. desid. n. , to desire to marry (post-Aug.), Mart. 3, 93"},"nuptus":{"lemma":"nuptus","pos":"","gen":"-class","def":"nubo, a covering, veiling, Varr. L. L. 5, § 72 Müll.— Transf., marriage, wedlock (post-class.): nuptumque passa, Stat. S. 5, 1, 45: solenni nuptu filias locabant, Aur. Vict. Vir. Ill. 59. nŭra, ae"},"nusquam":{"lemma":"nusquam","pos":"adv.","gen":"-usquam","def":"ne-usquam, nowhere, in no place. Lit.: nusquam invenio Naucratem, Plaut. Am. 4, 1, 6: fratrem nusquam invenio gentium, Ter. Ad. 4, 2, 1"},"nux":{"lemma":"nux","pos":"","gen":"-tree","def":"plur. nucerum for nucum, Cael. ap. Charis. p. 40 P.), f. etym. dub., a nut. At weddings it was customary to strew nuts on the floor: sparge, marite, nuces, Verg. E. 8, 30"},"nycteus":{"lemma":"Nycteus","pos":"","gen":"","def":", = Νυκτεύς, a son of Hyrieus and the nymph Clonia, and father of Antiopa: Nycteos Antiope, Prop. 3, 15 (4, 14), 12.—Hence, Nyctēis, ĭdis, f., the Nycteide, i. e. Antiopa: Nycteida, Ov. M. 6"},"nyma":{"lemma":"nyma","pos":"","gen":"","def":", a plant, otherwise unknown, Plin. 27, 12, 82, § 106 (al. nigina). nympha, ae, and nymphē, ēs (dat. plur. NYMPHABVS, Inscr. Orell. 1629; NYMFABVS, ib. 1630; NYMPHIS, ib. 1627"},"nymphaea":{"lemma":"nymphaea","pos":"","gen":"-lily","def":", = νυμφαία (Lat.: clava Herculis; cf. Marc. Emp. 33), the water-lily, Plin. 25, 7, 37, § 75; App. Herb. 67."},"nymphaeum":{"lemma":"Nymphaeum","pos":"","gen":"","def":", = Νύμφαιον, a promontory and seaport in Illyria, on the borders of Macedonia, now Capo di Redeni, Caes. B. C. 3, 26, 4; Liv. 42, 36, 8; Plin. 3, 22, 26, § 144; Luc. 5, 720."},"nymphaeus":{"lemma":"Nymphaeus","pos":"","gen":"","def":"A river in Latium, between Circeii and Astura, now Ninfa, Plin. 3, 5, 9, § 57.— A river in Mesopotamia, Amm. 18, 9, 2. nymphālis, is, adj. nympha, of or belonging to a fountain: in aquā nymphali"},"nymphon":{"lemma":"nymphon","pos":"adv.","gen":"","def":", = νυμφών, a bridal chamber, Tert. adv. Val. 32. Nȳsa, ae, f., the nurse of Bacchus: in monte Nysā, a Nysā nutrice, Serv. ad Verg. E. 6, 15; cf. Plin. 5, 18, 16, § 74"},"nyssos":{"lemma":"Nyssos","pos":"","gen":"","def":", f., = Νύσσος, a city in Macedonia, Plin. 4, 10, 17, § 36. Nȳsus, i, m., the tutor of Bacchus, to whom he intrusted Thebes during his expedition to India, Hyg. Fab. 131 and 167. O O, o"},"ob-do":{"lemma":"ob-do","pos":"v.","gen":"-do","def":"a., to put, place, or set one thing before another; to put against"},"ob-dulcesco":{"lemma":"ob-dulcesco","pos":"","gen":"-dulcesco","def":"inch. n., to become sweet: obdulcesco, περιγλυκύνομαι, Gloss. Philox.: in earum familiaritate obdulcuisses mihi, Aug. Conf. 7, 20, 2."},"ob-dulco":{"lemma":"ob-dulco","pos":"v.","gen":"-dulco","def":"a., to sweeten, make sweet (post-class.): aliquid sale, Cael. Aur. Tard. 3, 8, 146"},"ob-languesco":{"lemma":"ob-languesco","pos":"","gen":"-languesco","def":"inch. n., to become feeble or languid, to languish: litterulae meae oblanguerunt, Cic. Fam. 16, 10, 2. oblăquĕātĭo, ōnis, f. oblaqueo, I., a digging or clearing away around trees: ARBORVM"},"ob-lecto":{"lemma":"ob-lecto","pos":"v.","gen":"-lecto","def":"a. 2. lacto, to delight, please, divert, entertain, amuse (class.; most freq. with se and mid.; syn. delecto)"},"ob-longus":{"lemma":"ob-longus","pos":"adj.","gen":"-longus","def":", rather long, longish"},"ob-luctor":{"lemma":"ob-luctor","pos":"v.","gen":"-luctor","def":"dep., to strive or struggle against, to contend with, oppose a person or thing (poet. and in post-Aug. prose). Lit. With dat. of person: soli obluctandum Fabio, to contend with Fabius alone, Sil. 8"},"ob-marcesco":{"lemma":"ob-marcesco","pos":"","gen":"-marcesco","def":"inch. n., to fall away, grow lean: obmarcescebat febris, Lucil. ap. Non. 2, 30."},"ob-quinisco":{"lemma":"ob-quinisco","pos":"","gen":"-quinisco","def":"ocquinisco. ob-rădĭo, āre, v. n., to shine forth (postclass.), Isid. Orig. 16, 18, 2. obraucātus, a, um, Part., from the obsol. obrauco, āre , grown hoarse (post-class.): ea (grus) ubi obraucata est"},"ob-signo":{"lemma":"ob-signo","pos":"v.","gen":"-signo","def":"a., to seal, seal up a will, a letter, etc. (class.). Lit. In gen.: cedo tu ceram ac linum actutum: age obliga, obsigna cito, Plaut. Bacch. 4, 4, 96: cellas, id. Cas. 2, 1, 1: lagenas"},"ob-sisto":{"lemma":"ob-sisto","pos":"v.","gen":"-sisto","def":"n., to set, place, or post one's self before any thing (class."},"ob-sordesco":{"lemma":"ob-sordesco","pos":"","gen":"-sordesco","def":"inch. n., to become dirty, be soiled (ante- and post-class.). Lit.: ne coma fumo obsordescat, Prud. Apoth. 214.— Trop., to wear out, decrease: obsorduit jam haec in me aerumna, i. e. is moderated"},"ob-sterno":{"lemma":"ob-sterno","pos":"v.","gen":"-sterno","def":"a., to strew or cast before, to throw in one's way (postclass.): uxorem puero, App. Mag. p. 335, 31. obstētrīcĭus (opst-) or -tĭus, a, um, adj. obstetrix, of or belonging to a midwife"},"ob-stringo":{"lemma":"ob-stringo","pos":"v.","gen":"-stringo","def":"a. To bind to or about"},"ob-sufflo":{"lemma":"ob-sufflo","pos":"v.","gen":"-sufflo","def":"a., to blow against or at, Auct. Quint. Decl. 7 ob-sum, obfui or offui, obesse (old form of fut. obescet, oberit vel aderit, Paul. ex Fest. p. 188 Müll.), v. n., to be against, be prejudicial to"},"ob-surdesco":{"lemma":"ob-surdesco","pos":"","gen":"-surdesco","def":"inch. n., to become deaf (class.). Lit.: hoc sonitu oppletae aures hominum obsurduerunt, Cic. Rep. 6, 18, 19: si sapiens excaecatur, obsurdescat, etc., Aug. Civ. Dei, 19, 4, 4.— Trop., to be deaf"},"ob-tendo":{"lemma":"ob-tendo","pos":"v.","gen":"-tendo","def":"a. To draw, stretch, spread, or place before (cf. obtego"},"ob-tensus":{"lemma":"ob-tensus","pos":"","gen":"-tensus","def":"obtendo, for obtentus, a pretext, Front. ad Amic. 2, 6 fin. Mai. ob-tentĭo, ōnis, f. id. II., a covering, veiling"},"ob-testor":{"lemma":"ob-testor","pos":"v.","gen":"-testor","def":"dep., to call as a witness to any thing; to protest or assert by a person or thing (syn.: testor, obsecro, supplico"},"ob-texo":{"lemma":"ob-texo","pos":"v.","gen":"-texo","def":"a. (post-Aug.). To weave to or over any thing: papilio fila araneosa alarum lanugine obtexit, Plin. 11, 19, 21, § 65.— To weave over, i. e. to overspread, cover with any thing: caelum obtexitur umbrā"},"ob-torpeo":{"lemma":"ob-torpeo","pos":"v.","gen":"-torpeo","def":"n., to be numb: torpet, intorpet, contorpet, obtorpet, Not. Tir. p. 94."},"ob-torpesco":{"lemma":"ob-torpesco","pos":"","gen":"-torpesco","def":"inch. n., to become numb or stiff"},"ob-trecto":{"lemma":"ob-trecto","pos":"v.","gen":"-trecto","def":"n. and a. , to detract from through envy; to disparage, underrate, decry; to be opposed to; to thwart; to injure a person or thing (class.; syn. detrecto; cf.: aemulo, invideo)"},"ob-trunco":{"lemma":"ob-trunco","pos":"v.","gen":"-trunco","def":"a., to cut off, lop away; to trim, prune. Lit. (post-Aug. and very rare): vitem, Col. 4, 29, 13.— In gen., to cut down, cut to pieces, kill, slay, slaughter (not in Cic. or Caes."},"ob-tundo":{"lemma":"ob-tundo","pos":"v.","gen":"-tundo","def":"a. To strike or beat against, at, or on a thing; to beat, thump, belabor (very rare"},"ob-turbo":{"lemma":"ob-turbo","pos":"v.","gen":"-turbo","def":"a., to stir up, make turbid. Lit.: obturbata proculcatione prius aqua, Plin. 8, 18, 26, § 68. — Trop., to throw into disorder or confusion"},"ob-turgesco":{"lemma":"ob-turgesco","pos":"","gen":"-turgesco","def":"inch. n., to begin to swell, to swell up (very rare; not in Cic.): obturgescit pes, Lucr. 6, 658"},"ob-uallo":{"lemma":"ob-vallo","pos":"v.","gen":"-vallo","def":"a., to surround with a wall or rampart"},"ob-uentus":{"lemma":"ob-ventus","pos":"","gen":"-ventus","def":"id., a meeting (eccl. Lat.), Tert. Anim. 41. ob-verbĕro, 1, v. a., to beat soundly, to bang (post-class.): asinum baculo, App. M. 7, p. 198, 34: aliquem pugnis, id. ib. 9, p. 221"},"ob-uersor":{"lemma":"ob-versor","pos":"v.","gen":"-versor","def":"dep. (act. collat. form obverso, āre, acc. to Prisc. p. 799 P.), to take position opposite or over against, to oppose one's self (class.). Lit.: magnam partem eorum palam Carthagini obversari dici"},"ob-uerto":{"lemma":"ob-verto","pos":"v.","gen":"-verto","def":"a. To turn towards or against, to direct towards any thing (not in Cic. or Caes.): cujus ob os Graii ora obvertebant sua, Poët. ap. Cic. Tusc. 3, 18, 39"},"ob-uoluo":{"lemma":"ob-volvo","pos":"v.","gen":"-volvo","def":"a., to wrap round, muffle up, cover all over (class.; cf. obtego). Lit.: pictor ille vidit, obvolvendum caput Agamemnonis esse, Cic. Or. 22, 74"},"obba":{"lemma":"obba","pos":"","gen":"","def":", a vessel large at the bottom, a beaker, noggin; a decanter: obba poculi genus, quod nunc ubba dicitur. Varro: obbas et Cumanos calices, Non. 146, 8 sq."},"obc-":{"lemma":"obc-","pos":"","gen":"","def":"occ-. ob-densātĭo, ōnis, f., a thickening (post-class.): cutis, Cael. Aur. Tard. 1, 1, 47. obdĭtus, a, um, Part., v. obdo."},"obdormisco":{"lemma":"obdormisco","pos":"","gen":"","def":"inch. n. , to fall asleep (rare but class.): ibidem obdormiscemus, Plaut. Rud. 2, 7, 33"},"obducto":{"lemma":"obducto","pos":"","gen":"","def":"freq. a. id., to lead or conduct in opposition or rivalry to another: nec pol ego patiar ... measque in aedes sic scorta obductarier, Plaut. Merc. 4, 4, 46"},"obf-":{"lemma":"obf-","pos":"","gen":"","def":"off-."},"obg-":{"lemma":"obg-","pos":"","gen":"","def":"ogg-. ŏb-haerĕo, ēre, v. n., to stick fast to a thing: navis obhaerens vado, Suet. Tib. 2: ne qui forte obhaereant ac resistant, Lact. Opif. D. 11. ŏb-haeresco, haesi, 3, v. inch. n., to stick fast"},"obiecto":{"lemma":"objecto","pos":"","gen":"-clause","def":"freq. a. id., to throw before or against, to set against, oppose. Lit. (poet.): (pelagi volucres) Nunc caput objectare fretis, nunc currere in undas, i. e. to dive down, Verg. G. 1"},"obiector":{"lemma":"objector","pos":"","gen":"","def":"obicio, an accuser: falsi criminis objectores, Non. 130, 25. objectus, a, um, Part. and P. a., from obicio."},"obiectus":{"lemma":"objectus","pos":"","gen":"","def":"obicio, a casting before, a putting against, in the way, or opposite, an opposing"},"obiex":{"lemma":"objex","pos":"","gen":"","def":"obex. objurgātĭo, ōnis, f. objurgo, a chiding, reproving, reproof, rebuke, reprehension (class.): objurgatio post turpe factum castigatio"},"oblicus":{"lemma":"oblicus","pos":"","gen":"","def":"obliquus. ob-līdo, si, sum, 3, v. a. laedo. To squeeze together (rare but class.): caelum digitulis duobus oblidere, Cic. Scaur. § 10, p. 261 Orell.: oblisis faucibus, strangled, Tac. A. 5, 9"},"oblucinasse":{"lemma":"oblucinasse","pos":"","gen":"","def":"oblucuviasse. obluctātĭo, ōnis, f. obluctor, a striving or struggling against, vehement opposition (eccl. Lat.): obluctatio virtutis, Arn. 2, 77: flammarum, Mart. Cap. 6, § 647: adversus mala"},"obmentans":{"lemma":"obmentans","pos":"","gen":"","def":"ommento. ob-mĕrĭtus, a, um, Part. , having deserved well of, Rénier, Inscr. Afr. 444 al.: parentes optime obmeritae, id. ib. 966. ob-mōlĭor, ītus, 4, v. dep. (perh. not ante-Aug.). Lit."},"obmusso":{"lemma":"obmusso","pos":"v.","gen":"","def":"a., to whisper against any one"},"obnexus":{"lemma":"obnexus","pos":"adv.","gen":"","def":"obnecto, a connecting, connection (eccl. Lat.), Tert. adv. Marc. 4, 37. ob-nĭger, gra, grum, adj., blackish: radices, Plin. 20, 23, 94, § 253 Sillig. (al. obliquis nigris). obnīsē, adv., v. obnitor"},"obp-":{"lemma":"obp-","pos":"","gen":"","def":"opp-."},"obrepto":{"lemma":"obrepto","pos":"","gen":"","def":"freq. n. , to steal on unawares, to come on imperceptibly (very rare): ne quis obreptaverit, Plaut. Pers. 1, 2, 27: obreptantibus Satyris, Plin. 35, 10, 36, § 109 (but in Cic. Att. 6, 5, 3"},"obscaen-":{"lemma":"obscaen-","pos":"","gen":"","def":"obscen-."},"obscaeuo":{"lemma":"obscaevo","pos":"v.","gen":"-scaeva","def":"n. ob-scaeva, to give or bring a bad omen: metuo, quod illic obscaevavit meae falsae fallaciae, Plaut. As. 2, 1, 18. obscēnē (obscaenē and obscoe-nē), adv., v. obscenus fin. obscēnĭtas (obscaen-"},"obscus":{"lemma":"Obscus","pos":"","gen":"","def":"Osci. obsĕcrātĭo, ōnis, f. obsecro. In gen., a beseeching, imploring, supplication, entreaty (class.): prece et obsecratione humili uti, Cic. Inv. 1, 16, 22"},"obseruanter":{"lemma":"observanter","pos":"adv.","gen":"","def":", v. observo, P. a. fin. observantĭa, ae, f. observo, a remarking, noting, regard, observance. In gen.: temporum observantia, Vell. 2, 1063. — In partic. Observance, attention, respect, regard"},"obsessor":{"lemma":"obsessor","pos":"","gen":"-class","def":"id., one who sits, stays, abides in a place"},"obstrictus":{"lemma":"obstrictus","pos":"","gen":"","def":"obstringo, a binding, clasping: accendat flammam ipso obstrictu (al. affrictu), Sen. Q. N. 5, 14, 4. obstrĭgillātor, ōris, m. obstrigillo, an opposer, blamer (ante-class.), Varr. ap. Non. 492"},"obtectus":{"lemma":"obtectus","pos":"","gen":"","def":"obtego, a covering (late Lat.), Jul. ap. Aug. c. Sec. Resp. Jul. 4, 65. obtectus, a, um, Part., from obtego. ob-tĕgo (collat. form obtĭgo, Plaut. Most. 1, 3, 8), xi, ctum, 3, v. a., to cover over"},"obtentus":{"lemma":"obtentus","pos":"","gen":"","def":"Part., from obtendo.— Part., from obtineo. ob-tentus (opt-), ūs, m. obtendo. A drawing, spreading, or placing before (poet. and post-Aug.). Lit.: obtentu togae, tamquam se amiciens, ne videretur"},"occa":{"lemma":"occa","pos":"","gen":"-class","def":"occo, a harrow (post-class.); occa rastrum, Gloss. Isid.: occa βωλοκόπημα, Gloss. Philox."},"occentus":{"lemma":"occentus","pos":"","gen":"","def":"occino, a singing, a cry (post-Aug.): soricum, Plin. 8, 57, 82, § 223: soricis, Val. Max. 1, 1, 5; Amm. 16, 8, 2."},"occepso":{"lemma":"occepso","pos":"","gen":"","def":"occipio init."},"occepto":{"lemma":"occepto","pos":"","gen":"","def":"subj. occeptassit; v. in the foll.), v. freq. a. occipio, to begin (Plautin.): occeptat insanire, Plaut. Men. 5, 5, 18 and 32.—Absol.: si attigerit sive occeptassit, Plaut. Rud. 3, 4, 70."},"occhi":{"lemma":"occhi","pos":"","gen":"-tree","def":", a kind of tree in Hyrcania, resembling the fig-tree, from which honey flowed in the morning, perh. the manna sainfoin, Hedysarum Alhagi of Linn., Plin. 12, 8, 18, § 34. Occĭa, ae, f."},"occillo":{"lemma":"occillo","pos":"v.","gen":"","def":"a. occo, to break, smash: qui mi advenienti os occillet probe, Plaut. Am. 1, 1, 28 Fleck. (dub."},"occo":{"lemma":"occo","pos":"v.","gen":"","def":"a. root ac, acuo"},"occoepi":{"lemma":"occoepi","pos":"","gen":"","def":"occipio. occŭbĭtus, ūs, m. occumbo, a going down, setting (eccl. Lat.): solis, Hier. Ep. 108, n. 34; Vulg. Gen. 28, 11"},"occurso":{"lemma":"occurso","pos":"","gen":"","def":"freq. n. , to run, go, or come to meet"},"occursor":{"lemma":"occursor","pos":"","gen":"","def":"id., a meeter (late Lat.), Aug. Music. 6, 6. occursōrĭus, a, um, adj. occursor, of or belonging to meeting (post-class.): occursoria potio, a draught taken before a meal, App. M. 9, p. 227, 32."},"occursus":{"lemma":"occursus","pos":"","gen":"","def":"occurro, a meeting, falling in with (not in Cic. or Caes."},"ocris":{"lemma":"ocris","pos":"","gen":"-class","def":", = ὄκρις , a broken, rugged, stony mountain (ante-class.): ocrem antiqui montem confragosum vocabant, ut apud Livium: qui ascendunt altum ocrim; et, celsosque ocrīs arvaque petria"},"octans":{"lemma":"octans","pos":"","gen":"","def":"octo, a measuring instrument, a half quadrant, an octant, Vitr. 10, 11. Octānus, i, m. id., a soldier of the eighth legion, Prisc. 1354 P. octăphŏron, v. octophoron."},"octas":{"lemma":"octas","pos":"","gen":"","def":", = ὀκτάς, the number eight, Mart. Cap. 7, § 740. octăsēmus, a, um, adj., = ὀκτάσημος, t. t. of the metrical art, containing eight times, Mart. Cap. 9, § 985. octă-stȳlos, on, adj., = ὀκτάστυλος"},"octennis":{"lemma":"octennis","pos":"adj.","gen":"-annus","def":"octo-annus, eight years old (post-class.): puer, Amm. 18, 6, 10. octennĭum, ii, n. (octo-annus), a period of eight years: tertio quoque octennio, every twenty-four years, Macr. S. 1, 13"},"octingenti":{"lemma":"octingenti","pos":"adj.","gen":"","def":"plur. octingentūm, Liv. 30, 21, 4), card. num. adj. , eight hundred, Cic. Planc 25, 60: stadia, id. Ac. 2, 25, 81. octingentĭes or -tiens, adv. num. octingenti"},"octo-uir":{"lemma":"octo-vir","pos":"","gen":"-vir","def":", a member of a council of eight (usually written VIII VIR), Inscr. Orell. 3658; 3699; 3963"},"octolophus":{"lemma":"Octolophus","pos":"","gen":"","def":", or Octolophum, i, n., a city in Thessaly, Liv. 31, 36, 6; 31, 40, 9"},"octussis":{"lemma":"octussis","pos":"","gen":"-as","def":"octo-as, eight asses: Quanti emptae? Parvo. Quanti ergo? Octussibus, Hor. S. 2, 3, 156"},"ocymum":{"lemma":"ocymum","pos":"","gen":"","def":"ocinum. ōcyor, ōcyssĭmus, and ōcyus, more correctly ocior, etc. Ōcypĕtē, ēs, f, = ὠκυπέτη, Swift-flier, one of the Harpies, Serv. Verg. A. 3, 209. Ōcypŏtē, ēs, f., = ὠκυπότη, Swift-flier"},"odrysae":{"lemma":"Odrysae","pos":"adj.","gen":"","def":", = Ὀδρύσαι, a people of Thrace, on the Hebrus, now Rumili, Liv. 39, 53"},"oea":{"lemma":"Oea","pos":"adj.","gen":"","def":", a town of Africa, now Tripolis, Mela. 1, 7, 5; Sil. 3, 257; App. Mag. 17. —Hence, Oeensis, e, adj., of or belonging to Oea: civitas Oeensis, Plin. 5, 4, 4, § 27"},"oeclus":{"lemma":"Oeclus","pos":"","gen":"","def":", the name of a Centaur, Ov. M. 12, 450. oecŏnŏmĭa, ae, f., = οἰκονομία, the management of household affairs, domestic economy"},"oecus":{"lemma":"oecus","pos":"","gen":"","def":", = οἶκος, a room in a house; a hall, saloon (only in Vitr. and Plin.): oeci magni, in quibus matresfamiliarum cum lanificis habent sessiones, Vitr. 6, 10; Plin. 36, 25, 60, § 184"},"oestrus":{"lemma":"oestrus","pos":"","gen":"-fly","def":", = οἶστρος. Lit., a gad-fly, horse-fly, breese (pure Lat. asilus): volitans, cui nomen asilo Romanum est, oestrum Graii vertere vocantes, Verg. G. 3, 148: nascuntur in extremis favis apes grandiores"},"oesyma":{"lemma":"Oesyma","pos":"","gen":"","def":", a city in Italy, Liv. 44, 26."},"oesypum":{"lemma":"oesypum","pos":"","gen":"","def":", = οἴσυπος, the greasy sweat and dirt of unwashed wool, Plin. 29, 2, 10, § 35; cf. id. 29, 6, 36, § 112; 30, 4, 10, § 28.—Used as a cosmetic by the Roman ladies, Ov. A. A. 3, 213; id. R. Am. 354."},"oeta":{"lemma":"Oeta","pos":"adj.","gen":"-taeus","def":", = Οἴτη, the mountain range between Thessaly and Aetolia, where Hercules ascended the funeral pile, now Katavothron, Plin. 4, 7, 13, § 28; Liv. 36, 15; Luc. 8, 800; Sen. Herc. Oet. 862"},"oetum":{"lemma":"oetum","pos":"","gen":"","def":", = οἶτον, an Egyptian plant, otherwise unknown, Plin. 21, 15, 52, § 88. ŏfella, ae, f. dim. offa, a bite, bit, mouthful, morsel (post-Aug.). Lit., Juv. 11, 142; Mart. 10, 48, 15; 14, 221, 1"},"offa":{"lemma":"offa","pos":"","gen":"","def":"Lit., a bite, bit, morsel"},"offectus":{"lemma":"offectus","pos":"","gen":"","def":"officio, a bewitching, a charm (poet.), Grat. Cyn. 406. offendĭcŭlum, i, n. 1. offendo, a stumbling-block, obstacle, hinderance"},"offendix":{"lemma":"offendix","pos":"","gen":"","def":"ob, and Sanscr. root bandh, to bind; Goth. binda, a tie"},"offendo":{"lemma":"offendo","pos":"v.","gen":"-fensus","def":"a. and n. obfendo. to hit, thrust, strike, or dash against something (syn.: illido, impingo"},"offensa":{"lemma":"offensa","pos":"","gen":"","def":"1. offendo, like repulsa, from repello, a striking or grating against any thing. Lit. (very rare): donec cerussae similis fiat, nulla dentium offensa, and does not grit against the teeth, Plin. 34"},"offenso":{"lemma":"offenso","pos":"","gen":"","def":"freq. a. 1. offendo, to strike or dash against (not in Cic. or Caes.). Lit.: sponte suā offensando ut semina rerum, Lucr. 2, 1059"},"offensor":{"lemma":"offensor","pos":"","gen":"","def":"id., an offender, injurer (eccl. Lat.): in gratiam suis cum offensoribus redire, Arn. 7, 216. offensus, a, um, Part. and P. a., from 1. offendo."},"offensus":{"lemma":"offensus","pos":"adv.","gen":"-class","def":"1. offendo, a striking against, a shock (poet. and in post-class. prose). Lit., Lucr. 2, 223; 4, 359"},"offex":{"lemma":"offex","pos":"","gen":"","def":"officio, a hinderer: offex, impeditor, qui officit, Gloss. Isid. offĭcĭālis, e, adj. officium, of or belonging to duty, office, or service, official (post-class.). Adj.: libri officiales"},"offla":{"lemma":"offla","pos":"","gen":"","def":"offula. offlecto (obfl-), ĕre, v. a. ob-flecto, to turn about: navem, Plaut. Rud. 4, 3, 74. offōco (obf-; collat. form offuco"},"oglasa":{"lemma":"Oglasa","pos":"","gen":"","def":", an island near Corsica, now Monte Christo, Plin. 3, 6, 12, § 80. Ogulnĭus, ĭi, m., a Roman proper name, Liv. 10, 6"},"oh":{"lemma":"oh","pos":"interj.","gen":"","def":", an expression for the most various emotions of the mind—for surprise, both joyful and painful; for great pleasure or sorrow"},"ohoho":{"lemma":"ohoho","pos":"","gen":"","def":"oh."},"oi":{"lemma":"oi","pos":"interj.","gen":"","def":", an exclamation of complaint, of one weeping: Ph. I intro nunc jam. Do. Oi! ei! Ter. Eun. 4, 4, 47: oi! hui! id. Phorm, 4, 3, 58."},"oica":{"lemma":"oica","pos":"","gen":"","def":", a precious stone, otherwise unknown, Plin. 37, 10, 65, § 176; Isid. Orig. 16, 12, 1."},"oiei":{"lemma":"oiei","pos":"interj.","gen":"","def":", a cry of lamentation, Ter. Eun. 4, 4, 47"},"olca":{"lemma":"olca","pos":"","gen":"","def":"37, 10, 65, § 176"},"olfacto":{"lemma":"olfacto","pos":"","gen":"-class","def":"freq. a. olfacio, to smell at any thing (ante-class. and post-Aug.). Lit.: vestimentum, Plaut. Men. 1, 2, 56: membrana olfactata, Plin. 28, 16, 63, § 225 (al. olefacta): pulei ramum, id. 20, 14, 54"},"olfactrix":{"lemma":"olfactrix","pos":"","gen":"","def":", v. 1. for olfactatrix (q. v.), Plin. 17, 24, 37, § 239. olfactus, a, um, Part., from olfacio."},"olfactus":{"lemma":"olfactus","pos":"","gen":"","def":"olfacio. Lit., a smelling, smell (post-Aug.): thymi, Plin. 21, 21, 89, § 156 (al. olfacto thymo); 32, 3, 13, § 28"},"olipor":{"lemma":"Olipor","pos":"","gen":"","def":"prob. from Auli puer, like Marcipor, Quintipor, a Roman surname, Inscr. Murat. 154, 2. Ŏlĭsīpo and Ŏlysippo (Ulys-), ōnis, m., a city of Lusitania, the modern Lisbon, Plin. 4, 22, 35, § 116"},"olma":{"lemma":"olma","pos":"","gen":"","def":", the plant ebulum, among the Dacians, App. Herb. 91. ŏlo, ĕre, v. oleo init. ŏlŏlygon, ŏnis, m., = ὀλολυγών, the croaking of the male frog, to attract the female, Plin. 11, 37, 65, § 172. ŏlor, ōris"},"onchestus":{"lemma":"Onchestus","pos":"","gen":"","def":", a city of Boeotia; v. Onchestius."},"onco":{"lemma":"onco","pos":"v.","gen":"","def":"n., to bray, like an ass: oncat asellus, Auct. Carm. Philom. 55. oncōma, ătis, n., = ὄγκωμα, a tumor (post-class.), Veg. Vet. 2, 30. ŏnēar, ătis, n. ὄνειαρ, refreshment, a plant"},"onoba":{"lemma":"Onoba","pos":"","gen":"","def":"3, 1, 3, § 10"},"opetis":{"lemma":"opetis","pos":"","gen":"","def":", a plant, called also aristolochia, App. Herb. 19. Ophellĭus, ii, m., a Roman surname, Inscr. Grut. 463, 2. Ŏpheltes, ae, m., = Ὀφέλτης, a proper name. Son of Lycurgus, king of Thrace, Stat. Th. 5"},"oppando":{"lemma":"oppando","pos":"v.","gen":"-pando","def":"a. ob-pando, to spread or stretch out against or before, to spread out (post-class.): aliquid ad flatus helices, Grat. Cyn. 55: cornibus oppansis et summā fronte coruscum (of the cross of Christ)"},"oppansum":{"lemma":"oppansum","pos":"","gen":"","def":", v. oppando fin. oppansus, a, um, Part., from oppando. oppassus, a, um, Part., from oppando. oppecto (obp-), ĕre, v. a. ob-pecto, to comb off"},"oppingo":{"lemma":"oppingo","pos":"","gen":"","def":"oppango. Oppĭus, i, m."},"oppressor":{"lemma":"oppressor","pos":"","gen":"","def":"opprimo, a crusher, destroyer: oppressores dominationis, Brut. ap. Cic. Ep. ad Brut. 1, 16. oppressus (obp-), a, um, Part., from opprimo. oppressus (obp-), ūs, m. opprimo, a pressing down"},"opscus":{"lemma":"Opscus","pos":"","gen":"","def":"Osci. opsōnĭum, v. obsonium. optābĭlis, e, adj. opto, to be wished for, desirable (class.): quae expetenda atque optabilia videntur, Cic. de Or. 1, 51, 221: mihi pax imprimis fuit optabilis"},"orbis":{"lemma":"orbis","pos":"","gen":"-top","def":"orbs, Ven. Carm. 8, 5. —Abl. regul. orbe; but orbi, Lucr. 5, 74: ex orbi, Varr. R. R. 3, 5, 16; Rutil. ap. Charis. p. 112 P.: orbi terrae, in the meaning in the world, Cic. Sest. 30, 66"},"orbo":{"lemma":"orbo","pos":"v.","gen":"","def":"a. orbus, to deprive or bereave of parents, children, or other dear persons; to make fatherless, motherless, childless, etc. (class."},"orbus":{"lemma":"orbus","pos":"adj.","gen":"","def":"kindr. with Gr. ὀρφανός; cf. Fest. p. 183 Müll., bereaved, bereft, of parents or children; parentless, fatherless, childless (class.; cf. pupillus). Lit.: senex, Cic. Par. 5, 2, 39"},"orca":{"lemma":"orca","pos":"","gen":"-bellied","def":"cf. ἄρχα, a kind of whale, an orc, Plin. 9, 6, 5, § 12.— Transf. A large-bellied vessel, a butt, tun (cf.: seria"},"orchis":{"lemma":"orchis","pos":"","gen":"","def":", = ὄρχις A plant, a kind of olive, Col. 5, 8, 4; id. Arb. 17, 3"},"orchus":{"lemma":"Orchus","pos":"","gen":"","def":", = Orcus: Orchi traditus thesauro, Naev. ap. Gell. 1, 24, 2. Orcīnĭānus, a, um, adj. Orcus, of or belonging to Orcus or to the dead (poet.): sponda, i. e. a bier, Mart. 10, 5, 9. Orcīnus, a, um"},"orcus":{"lemma":"Orcus","pos":"","gen":"","def":"kindr. with ἕρκος and the Lat. urgeo: Orcum quem dicimus, ait Verrius ab antiquis dictum uragum, Fest. p. 202 Müll.—Hence, prop., that which impels, constrains, confines. the Lower World"},"ordouices":{"lemma":"Ordovices","pos":"","gen":"","def":", a people of Britain, Tac. A. 12, 33"},"orestilla":{"lemma":"Orestilla","pos":"","gen":"","def":", a female surname in the gens Aurelia; esp. Aurelia Orestilla, wife of Catiline, Sall. C. 15, 2; 35, 3; 6"},"orgessum":{"lemma":"Orgessum","pos":"","gen":"","def":", a castle in Macedonia, Liv. 31, 27. Orgĕtŏrix, ĭgis, m., chief of the Helvetii, Caes. B. G. 1, 2 sq. al. Orgĭa, ōrum, n., = Ὄργια, a nocturnal festival in honor of Bacchus"},"orgus":{"lemma":"Orgus","pos":"","gen":"","def":", a river of Upper Italy, now Orco, Ennod. Carm 1, 38 ŏrĭa, v horia. Ŏrībăsus, i, m., = Ὀρείβασος (mountain-climber), one of Actoeon's hounds, Ov. M. 3, 210. ŏrībăta, ae, m., = ὀρειβάτης"},"oritae":{"lemma":"Oritae","pos":"","gen":"","def":", a nation of Ichthyophagi, on the borders of India, Plin. 7, 2, 2, § 30, id. 6, 23, 25, § 95. ŏrītes, ae, m., or ŏrītis, ĭdis, f., v. oritis. Ōrīthȳīa (quadrisyl.), ae, f., = Ὠρείθυια"},"orminos":{"lemma":"orminos","pos":"","gen":"","def":", wild asparagus, Plin. 20, 10, 43, § 110. ornāmen, ĭnis, n. orno, an old reading for ornamentum, Mart. Cap. 6, § 587. ornāmentārĭus, a, um, adj. ornamentum, adorned with the insignia of an office"},"orno":{"lemma":"orno","pos":"v.","gen":"","def":"ORNAVET, Column. Rostr.; v. infra), v. a. perh. root var-, cover; Sanscr. varna-, color, to fit out, furnish, provide with necessaries; to equip, to get ready, prepare (class."},"ornus":{"lemma":"ornus","pos":"","gen":"-ash","def":", the wild mountain-ash: steriles orni, Verg. G. 2, 111; Hor. C. 3, 27, 58; Plin. 16, 18, 30, § 73; Col. Arbor. 16"},"orphas":{"lemma":"orphas","pos":"","gen":"","def":"l. Ov. Hal. 104 for orphus, q. v. Orpheus (dissyl.), i (Gr. dat. Orphei, Verg. E. 4, 57; Gr. acc. Orphĕă, Verg. E. 6, 30; Ov. P. 3, 3, 41: Orphēā, id. M. 10, 3; voc. Orpheu, Verg. G. 4, 494"},"orphus":{"lemma":"orphus","pos":"","gen":"-fish","def":", = ὀρφός, a sea-fish, the gilt-head, Plin. 32, 11, 54, § 152; Ov. Hal. 104. orrhŏpȳgĭum, ĭi, a false read. for orthopygium, q. v."},"orsa":{"lemma":"orsa","pos":"","gen":"","def":"ordior. Beginnings, commencements, an undertaking, attempt: ut (di) orsis tanti operis successus prosperos darent, Liv. praef. fin.: Orsa juvare, Val. Fl. 1, 21.— In partic., words"},"orses":{"lemma":"Orses","pos":"","gen":"","def":", the name of a Trojan warrior, Verg. A. 10, 748. Orsĭlŏchē, ēs, f., the name of the Tauric Diana, Amm. 22, 8. Orsĭlŏchus, i, m., the name of a Trojan warrior, Verg. A. 11, 636."},"orsinus":{"lemma":"orsinus","pos":"","gen":"","def":"21, 11, 39, § 67.—Perh. an error in the MSS. for orinus, or oreinos; cf. Jan. ad loc. orsōrĭus, a, um, adj. ordior, belonging to a loom: in palo orsorio, S. S. Judic. 16, 13"},"orsus":{"lemma":"orsus","pos":"","gen":"","def":", ordior, a beginning, commencement"},"orthopnoea":{"lemma":"orthopnoea","pos":"","gen":"","def":", = ὀρθόπνοια, difficulty of breathing, asthma, orthopny, Plin. 32, 4, 14, § 37; plur., id. 21, 20, 83, § 142. orthopnŏĭcus, a, um, adj., = ὀρθοπνοϊκός, asthmatic, Plin. 20, 17, 73, § 193"},"orthrus":{"lemma":"Orthrus","pos":"","gen":"","def":", = Ὄρθρος. Geryon's dog, Sil. 13, 845.— A Roman surname, Inscr. Gud. 269, 2. ortīvus, a, um, adj. 2. ortus, of or belonging to rising, rising (post-class.), App. M. 3, p. 141, 23: cardo"},"ortus":{"lemma":"ortus","pos":"","gen":"","def":"orior. A rising of the heavenly bodies (opp. occasus"},"ortyx":{"lemma":"ortyx","pos":"","gen":"","def":", = ὄρτυξ, a plant, Plin. 21, 17, 61, § 101. ōrum, i, v. aurum init. ŏryx, ygis, m., = ὄρυξ, a kind of wild goat or gazelle: Gaetulus oryx, Juv. 11, 140; Mart. 13, 94, 2; Vulg. Deut. 14, 5"},"osca":{"lemma":"Osca","pos":"adj.","gen":"","def":", a town in Hispania Tarraconensis, now Huesca, in Aragon, Vell. 2, 30, 1"},"oscen":{"lemma":"oscen","pos":"","gen":"-cano","def":"(but f. ap. Varr. L. L. 6, 7, 67; Plin. 10, 19, 22, § 43) , a singing-bird, esp. in the auspices"},"oscensis":{"lemma":"Oscensis","pos":"","gen":"","def":"Osca."},"osci":{"lemma":"Osci","pos":"adj.","gen":"","def":", the Oscans, a primitive people of Campania; in more ancient times called also Opici and Opsci (Obsci), Verg. A. 7, 730"},"oscillo":{"lemma":"oscillo","pos":"v.","gen":"","def":"n. 2. oscillum, to swing, swing one's self: oscillum Santra dici ait, quod oscillent, id est inclinent, praecipitesque in os ferantur, Fest. p. 194, 9 and 10 Müll.—Pass.: osculor, Mythogr. Lat. 1"},"oscillum":{"lemma":"oscillum","pos":"","gen":"","def":"dim. 1. os; lit. little mouth"},"oscus":{"lemma":"Oscus","pos":"","gen":"","def":"Osci. Osdrŏēna, ae, f., = Ὀσδροηνή, a country in the western part of Mesopotamia, the modern Diar Mochar, Amm. 14, 3, 2; 14, 8, 7.—Its inhabitants are called Osdrŏēni, ōrum. m., Eutr. 8, 3."},"osi":{"lemma":"Osi","pos":"","gen":"","def":"m., a people of Germany, on the banks of the Danube, Tac. G. 28"},"ossa":{"lemma":"Ossa","pos":"adj.","gen":"","def":"(m., Ov. M. 1, 155), = Ὄσσα, a high mountain in Thessaly, now Kissovo, Mel. 2, 3, 2"},"ossum":{"lemma":"ossum","pos":"","gen":"","def":", v. 2. os. ossŭōsus, a, um, adj. 2. os, full of bones (post-class.): loci, Veg. Vet. 2, 13. ostendo, di, sum, and tum (ostensus, Varr. ap. Prisc. p. 892 P."},"ostensor":{"lemma":"ostensor","pos":"","gen":"","def":"ostendo, a shower, exhibiter (eccl. Lat.), Tert. Apol. 11. ostensus, a, um, Part., from ostendo. ostentābĭlis, e, adj. ostento, worth showing, worth seeing: ostentabilis, ἐπιδεικτικός"},"ostento":{"lemma":"ostento","pos":"","gen":"-clause","def":"pass. ostentarier, Plaut. Most. 1, 3, 129), 1, v. freq. a. ostendo, to present to view, to show, exhibit (class.). In gen.: alicui jugula sua pro capite alicujus, to present, offer, Cic. Att. 1, 16"},"ostentum":{"lemma":"ostentum","pos":"","gen":"","def":", v. ostendo fin. ostentus, a, um, Part. and P. a., from ostendo."},"ostentus":{"lemma":"ostentus","pos":"","gen":"","def":"ostendo. In gen., a showing, exhibiting, display (not in Cic. or Caes.): corpora extra vallum abjecta ostentui, as a public spectacle, Tac. A. 1, 29: atrocitatis, Gell. 20, 1, 48.— In partic. Show"},"ostes":{"lemma":"ostes","pos":"","gen":"","def":", = ὤστης, a kind of earthquake, App. de Mundo, p. 65, 30. Ostĭa, ae, f., and Ostĭa, ōrum, n. ostium"},"ostrum":{"lemma":"ostrum","pos":"","gen":"-snail","def":", = ὄστρεον. Lit., the blood of the sea-snail, purple (cf.: murex, purpura): ostro Perfusae vestes, Verg. A. 5, 111"},"ostrya":{"lemma":"ostrya","pos":"","gen":"","def":", = ὀστρύα, ὄστρυς, a tree with hard wood, perh. the common hornbeam, Plin. 13, 21, 37, § 117. ōsus and ōsūrus, a, um, Partt., v. odi. ŏsyris, is, f., = ὄσυρις, a plant"},"othrys":{"lemma":"Othrys","pos":"adj.","gen":"","def":", = Ὄθρυς, a mountain in Thessaly, now Ierako: Homolen Othrymque nivalem Linquentes, Verg. A. 7, 675"},"oxartes":{"lemma":"Oxartes","pos":"","gen":"","def":", a Persian, the father of Roxana, the wife of Alexander the Great, Curt. 10, 3, 11."},"oxathres":{"lemma":"Oxathres","pos":"","gen":"","def":", brother of the Persian king Darius Codomannus, Curt. 3, 11, 8. oxĭmē, v. ociter, under ocior. Oxĭmum, i, n., a city in Italy, also called Auximum, Liv. 41, 21. Oxiones, um (acc. -as), m."},"oxus":{"lemma":"Oxus","pos":"","gen":"","def":"Oxos. oxybăphus, i, m., = ὀξυβάφον, lit. a vinegar-cup (pure Lat. acetabulum); hence, a liquid measure containing fifteen drachms (post-class.), Rhem. Fan. Ponder. 75"},"oxys":{"lemma":"oxys","pos":"","gen":"-sorrel","def":", = ὀξύς (sharp). Common wood-sorrel, Plin. 27, 12, 89, § 112. — A kind of sharp rush, Plin. 21, 18, 69, § 112. oxysacchărum, i, n., = ὀξυσάκχαρον, vinegar-sugar, a drink made of vinegar and sugar"},"oxyschoenos":{"lemma":"oxyschoenos","pos":"","gen":"","def":", = ὀξύσχοινος, a kind of rush, Plin. 21, 18, 69, § 112. oxytŏnon, i, n., = ὀξύτονον, wild poppy, App. Herb. 53. oxytrĭphyllon, i, n., = ὀξυτρίφυλλον, sharp-leaved trefoil, Plin. 21, 9, 30"},"ozaena":{"lemma":"ozaena","pos":"","gen":"","def":", = ὄζαινα. A kind of polypus: ozaena, dicta a gravi capitis odore, Plin. 9, 30, 48, § 89.— A polypus in the nose: narium ozaenae, Plin. 25, 13, 104, § 165. ozaenītis, ĭdis, f., = ὀζαινῖτις"},"ozogardana":{"lemma":"Ozogardana","pos":"","gen":"","def":", a city of Mesopotamia, Amm. 24, 2, 3. Ozŏmĕnē, ēs, f., the wife of Thaumas and mother of the Harpies, Hyg. Fab. 14."},"ozymum":{"lemma":"ozymum","pos":"","gen":"","def":", v. ocinum. P P, p, the fifteenth letter of the Latin alphabet, the character for which is derived from the ancient form of the Greek II (P or P), as is shown by inscriptions and coins"},"pac-":{"lemma":"pac-","pos":"","gen":"","def":"pag-. pācālis, e, adj. pax, of or belonging to peace, peaceful (poet.): olea, Ov. M. 6, 101: laurus, peaceful, that betokens peace, id. ib. 15, 591: flammae, on the altar of the goddess of peace"},"pacta":{"lemma":"pacta","pos":"","gen":"","def":", v. pactus, under pacisco fin. 1. pactīcĭus or -tĭus, a, um, adj. paciscor, agreed upon, stipulated, Gell. 1, 25, 8. pactĭlis, e, adj. pango, plaited together, wreathed: corona, Plin. 21, 3, 8"},"pactor":{"lemma":"pactor","pos":"","gen":"","def":"paciscor, one who makes a contract, a contractor, negotiator: societatis pactores, Cic. Verr. 2, 5, 21, § 55."},"pactum":{"lemma":"pactum","pos":"","gen":"","def":", v. pacisco fin. Pactŭmējus, i, m., a supposititious son of Canidia, Hor. Epod. 17, 50. pactus, a, um, Part. and P. a., from pacisco. pactus, a, um, Part., from pango."},"pactus":{"lemma":"pactus","pos":"","gen":"","def":", v. pacisco fin. Pactyē, ēs, and Pactya, ae, f., = Πακτύη, a town of Thrace, now Doghan Arslan, Nep. Alc. 7, 4"},"paean":{"lemma":"Paean","pos":"","gen":"","def":", = Παιάν. An appellation of Apollo, as the healing deity: signum Paeanis, Cic. Verr. 2, 4, 57, § 127: Paeana voca, Ov. M. 14, 720; Juv. 6, 172; cf. Fest. p. 222 Müll."},"paeantis":{"lemma":"paeantis","pos":"","gen":"","def":", a precious stone, otherwise unknown, Sol. 9"},"paedor":{"lemma":"paedor","pos":"","gen":"-class","def":"root pu-; Sanscr. pūje, to be rotten, stink; Gr. πύθομαι, πύον"},"paeligni":{"lemma":"Paeligni","pos":"","gen":"","def":"Peligni. paemĭnōsus, a, um, adj. In econom. lang., full of chinks, uneven, rough: area, Varr. R. R. 1, 51 (cited Non. 163, 14). paene (less correctly pēne), adv. etym. dub., nearly, almost"},"paestum":{"lemma":"Paestum","pos":"adj.","gen":"-blowing","def":", a city of Lucania, formerly called Posidonia, celebrated for its twice-blowing roses, now Pesti: biferique rosaria Paesti, Verg. G. 4, 119; cf. Ov. M. 15, 708"},"paetus":{"lemma":"paetus","pos":"adj.","gen":"","def":"etym. dub., having leering eyes, with a cast in the eyes, blinking or winking with the eyes, blinkeyed"},"pagae":{"lemma":"Pagae","pos":"","gen":"-gaei","def":", a city in Megaris, Plin. 4, 7, 11, § 23"},"pagmentum":{"lemma":"pagmentum","pos":"","gen":"","def":"pago, that is joined together (compactio, res compacta): qui sunt ante secundum pagmentum, Vitr. 4, 6 fin. (al. secundum antepagmentum)."},"pago":{"lemma":"pago","pos":"","gen":"","def":"pango init. pagrus (phagr-) or păger (ph-), ri, m., = πάγρος (φάγρος), a fish, otherwise unknown: pagrus fluviatilis, Plin. 32, 10, 38, § 113"},"palaga":{"lemma":"palaga","pos":"","gen":"","def":", an ingot of gold , Plin. 33, 4, 21, § 77 (al. palacra). pălam, adv. and prep. locative form; cf.: clam, perperam, etc.; root pal-, pla-; as in πλατύς, planus; cf. pellis"},"palla":{"lemma":"palla","pos":"","gen":"-player","def":"kindred with pellis; cf. Doed. Syn. 5, p. 211, a long and wide upper garment of the Roman ladies, held together by brooches, a robe, mantle (cf.: stola, peplum, chlamys), Plaut. As. 5, 2, 35"},"pallantis":{"lemma":"Pallantis","pos":"","gen":"","def":"2. Pallas, II. C. Pallantĭus, a, um, v. 2. Pallas, II. D. pallāris, e, adj. palla, of or belonging to the palla: palla, pallaris, Not. Tir. p. 157. Pallăs, ădis and ădos, f."},"pallesco":{"lemma":"pallesco","pos":"","gen":"","def":"inch. n. , to grow or turn pale. Lit.: ut qui timent sanguine ex ore decedente pallescant, Gell. 19, 4, 4: pallescere curis, Prop. 1, 13, 7: nullā pallescere culpā, Hor. Ep. 1, 1"},"pallium":{"lemma":"pallium","pos":"adv.","gen":"","def":", a covering, cover . In gen. A coverlet: et gravius justo pallia pondus habent, Ov. H. 21, 170: onerosa pallia jactat, Juv. 6, 236: tunc queror in toto non sidere pallia lecto, Prop. 5, 3, 31"},"pallor":{"lemma":"pallor","pos":"","gen":"","def":"palleo, pale color, paleness, wanness, pallor. Lit.: pudorem rubor, terrorem pallor et tremor consequitur, Cic. Tusc. 4, 8, 19: albus ora pallor inficit, Hor. Epod. 7, 15: luteus, id. ib. 10, 16"},"palmensis":{"lemma":"palmensis","pos":"adj.","gen":"","def":"1. palma, made from palms: vina, Plin. 14, 6, 8, § 67. palmĕs, ĭtis, m. 1. palma, II. E., a young branch or shoot of a vine, a vinesprig"},"palmo":{"lemma":"palmo","pos":"v.","gen":"-tree","def":", ātum, 1, v. a. 1. palma. To make the print or mark of the palm of one's hand, Quint. Decl. 1, 12"},"palmus":{"lemma":"palmus","pos":"","gen":"","def":"1. palma, the palm of the hand. Lit.: manūs palmum, Vitr. 2, 3: Graeci antiqui doron palmum vocabant: et ideo dora munera, quia manu darentur, Plin. 35, 14, 49, § 171.— Transf."},"palpo":{"lemma":"palpo","pos":"v.","gen":"-por","def":"a., and pal-por, ātus palpus; cf. Gr. ψάλλω, 1, v. dep. a., to stroke, to touch softly, to pat (poet. and in post-Aug. prose"},"palpus":{"lemma":"palpus","pos":"","gen":"","def":"(nom. not in use) , the soft palm of the hand (Plautin.): timidam palpo percutit, Plaut. Am. 1, 3, 28: palpo percutis, id. Merc. 1, 2, 42: mi obtrudere non potes palpum, id. Ps. 4, 1"},"panchaeus":{"lemma":"Panchaeus","pos":"","gen":"","def":"Panchaia, A. Panchāĭa, ae, f., = Παγχαία, a fabulous island in the Erythroean Sea, east of Arabia, rich in precious stones, incense, myrrh, etc.: totaque turiferis Panchaia pinguis arenis, Verg. G. 2"},"panchrus":{"lemma":"panchrus","pos":"","gen":"","def":", = πάγχρους (of all colors), a variegated precious stone, Plin. 37, 10, 66, § 178. Panchrȳsos, on, adj., = πάγχρυσος, all golden: Berenice urbs, quae Panchrysos cognominata est, Plin. 6, 29, 34"},"panda":{"lemma":"Panda","pos":"","gen":"","def":"2. pando, a Roman goddess; acc. to Aelius ap. Non. 44, 7, Ceres"},"pandae":{"lemma":"Pandae","pos":"adj.","gen":"","def":", a people of India: gens sola Indorum regnata feminis, Plin. 6, 20, 23, § 76.—Hence, Pandaeus, a, um, adj., of the Pandoe: gens, Sol. 52. Pandāna, ae, f. 2. pando, one of the oldest gates of Rome"},"pandecter":{"lemma":"pandecter","pos":"","gen":"","def":", = πανδεκτήρ (allcontaining), the title of the fourth book of the work of Apicius. pandectes or -ta, ae, m., = πανδέκτης, a book that contains every thing, a complete repertory, an encyclopedia"},"pando":{"lemma":"pando","pos":"v.","gen":"","def":"a. and n. for spando; root spa-; Sanscr. spha-, spread, grow; Gr. σπάω"},"pandus":{"lemma":"pandus","pos":"adj.","gen":"-backed","def":"2. pando, bent, crooked, curved (mostly poet.; syn.: curvus, uncus): carina, Enn. ap. Vet. Schol. in Stat. Achill. 1, 558 (Ann. v. 560 Vahl.)"},"pangaeus":{"lemma":"Pangaeus","pos":"adj.","gen":"","def":", and Pangaea, ōrum, n., = Πάγγαιον ὄρος, a mountain of Thrace, on the borders of Macedonia, near Philippi, now Pilaf Tepeh: Mons Pangaeus, Plin. 4, 11, 18"},"pango":{"lemma":"pango","pos":"v.","gen":"","def":"Neue, Formenl. 2, 474 sq.), 3, v. a. root pac-; Sanscr. pāca, band, fetter; Gr. πήγνυμι, fix; πάχνη, frost; πάσσαλος, peg, etc.; cf.: pagus, pagina, paciscor; old form paco, pago"},"pannus":{"lemma":"pannus","pos":"","gen":"-out","def":"(neutr. collat. form pannum, i, Nov. ap. Non. 218, 27.—Dat. and abl. plur. pannibus, Enn. ap. Charis. p. 40 P."},"pannychismus":{"lemma":"pannychismus","pos":"","gen":"","def":", = παννυχισμός, a watching all night long, Arn. 5, 173. pannychĭus, a, um, adj., = παννύχιος, that lasts all night: negotium, Marc. Aur. ap. Front. Ep. ad M. Caes. 3, 5 Mai. Pănomphaeus, i, m."},"pansa":{"lemma":"pansa","pos":"adj.","gen":"-footed","def":"pando, broad-footed, splay-foot, Plaut. Merc. 3, 4, 55."},"pantarces":{"lemma":"Pantarces","pos":"","gen":"-helping","def":"πανταρκής, all-helping, a surname of Jupiter"},"panther":{"lemma":"panther","pos":"","gen":"","def":"1. panthera."},"pantheum":{"lemma":"Pantheum","pos":"","gen":"","def":"Pantheon. Panthĭus, ii, m., one of the fifty sons of Aegyptus, Hyg. Fab. 170. Panthŏus and Panthūs, i, m., = Πάνθοος (-ονς), the nephew of Hecuba and father of Euphorbus: Panthus Othryades"},"papo":{"lemma":"papo","pos":"","gen":"","def":"pappo."},"pappa":{"lemma":"pappa","pos":"","gen":"","def":"papa."},"pappas":{"lemma":"pappas","pos":"","gen":"","def":"papas. pappo (papo), āre, v. a., to eat pap, to eat: liberto opus est quod pappet, Plaut. Ep. 5, 2, 62; Pers. 3, 17."},"pappus":{"lemma":"pappus","pos":"","gen":"","def":", = πάππος. An old man, Varr. L. L. 7, § 30 Müll.— A grandfather, Aus. Idyll. 4, 18.— The woolly, hairy seed of certain plants, Lucr. 3, 386 Lachm."},"parca":{"lemma":"Parca","pos":"","gen":"","def":"root πλεκ-; cf. πλέκω, πλοκή"},"parcus":{"lemma":"parcus","pos":"adj.","gen":"-indulgent","def":", = παῦρος , sparing in any thing, esp. in expenditure; in a good and bad sense, frugal, thrifty, economical"},"pardus":{"lemma":"pardus","pos":"","gen":"","def":", = πάρδος, a male panther: nunc varias (pantheras) et pardos, qui mares sunt, appellant in eo omni genere creberrimo in Africā Syriāque, Plin. 8, 17, 23, § 63; 10, 73, 94, § 202; 11, 37, 65, § 172"},"parma":{"lemma":"Parma","pos":"adj.","gen":"-mensis","def":", the city of Parma, in Gallia Cispadana, between Cremona and Placentia, famed for its breed of sheep, Plin. 3, 15, 20, § 115; Cic. Fam. 12, 5, 2; 10, 33, 4"},"parmensis":{"lemma":"Parmensis","pos":"","gen":"","def":"2. Parma, II."},"parmessis":{"lemma":"Parmessis","pos":"","gen":"","def":"Permessis. parmŭla, ae, f. dim. 1. parma, a little, round shield, a small target. Lit.: relictā non bene parmulā, Hor. C. 2, 7, 10"},"parnes":{"lemma":"Parnes","pos":"","gen":"","def":", = Πάρνης, -νηθος, a mountain range in Attica, on the borders of Boeotia, famous for its wine, and abounding in game, the modern Noyia: Parnesque benignus vitibus, Stat. Th. 12, 620"},"parra":{"lemma":"parra","pos":"","gen":"","def":", a bird of ill omen, the common or barn owl"},"parthi":{"lemma":"Parthi","pos":"adj.","gen":"-east","def":", = Πάρθοι, the Parthians, a Scythian people, situated to the north-east of the passes of the Caspian and south of Hyrcania, famed in antiquity as roving warriors and skilful archers, Just. 41, 1, 2"},"parthus":{"lemma":"Parthus","pos":"","gen":"","def":"Parthi, A."},"partim":{"lemma":"partim","pos":"","gen":"","def":"pars fin. partĭo, ōnis, f. pario, a bearing, bringing forth young (ante-and post-class.): horresco misera, mentio quoties fit partionis, Plaut. Truc. 1, 2, 92"},"partor":{"lemma":"partor","pos":"","gen":"","def":"postpartor. partŭālis, e, adj. 2. partus, of or belonging to bearing or birth: sanguis, Tert. adv. Marc. 4, 20. Partŭla, ae, f. id., the goddess who presides over birth, Tert. Anim. 37. partūra, ae"},"partus":{"lemma":"partus","pos":"","gen":"","def":"parti, Pac. ap. Non. 486, 6: partuis, Varr. ib. 8; dat. sing. partu, Prop. 1, 13, 30"},"paruus":{"lemma":"parvus","pos":"adj.","gen":"-and","def":"(usual, irreg. comp. and sup.: mĭnor, mĭnĭmus.—Comp.: volantum parviores, Cael. Aur. Tard. 2, 1, 26.— Sup.: rictus parvissimus, Varr. ap. Non. 456, 10: parvissima corpora, Lucr. 1, 615; 621"},"pascha":{"lemma":"pascha","pos":"adv.","gen":"","def":", and ătis, n., = πάσχα (Hebr. ). The feast of the Passover, Easter: sollennibus Paschae, Tert. ad Uxor. 2, 4: lege dedit pascham, id. in Carm. adv. Marc. 2, 80: pascharum dies, Symm. Ep. 10"},"pasco":{"lemma":"pasco","pos":"v.","gen":"-pas","def":"a. and n. root pa-; Sanscr. gō-pas, herdsman; Gr. πατέομαι; cf. pabulum, pastor, Pales, panis"},"pascor":{"lemma":"pascor","pos":"v.","gen":"","def":"dep., v. pasco, I. B. 4, b., and II. 1. b. pascŭa, ae, v. pascuus, II. B. pascŭālis, e, v. pascalis. pascŭōsus, a, um, adj. pascuum, full of pasture, fit for pasture (late Lat.): herba"},"passer":{"lemma":"passer","pos":"","gen":"","def":"for panser, from pando; cf. anser. Lit., a sparrow, Cic. Fin. 2, 23, 75; cf. Plin. 10, 36, 52, § 107; 10, 38, 54, § 111; 18, 17, 45, § 158; 30, 15, 49, § 141; Cic. Div. 2, 30, 63; 1, 33, 72"},"passernix":{"lemma":"passernix","pos":"","gen":"","def":"36, 22, 47, § 165. passĭbĭlis, e, adj. patior, capable of feeling or suffering, passible (post-class.), Arn. 7, 214; Prud. Apoth. 74; Tert. adv. Prax. 29; Vulg. Act. 26, 23"},"passi":{"lemma":"passi","pos":"adv.","gen":"","def":"adv. passus, from pando (lit., spread or scattered about"},"passum":{"lemma":"passum","pos":"","gen":"","def":", v. 2. pando, P. a., B. 2. b. passus, a, um, Part. and P. a. of 2. pando. passus, a, um, Part. of patior."},"passus":{"lemma":"passus","pos":"","gen":"","def":"from the root pat, a step, pace (cf.: gressus, gradus). Lit.: hinc campos celerl passu permensa parumper, Enn. ap. Non. 378, 20 (Ann. v. 74 Vahl.); Plaut. Bacch. 4, 7, 34; Lucr 4, 827; 877"},"pasta":{"lemma":"pasta","pos":"","gen":"","def":", = πάστη, paste, Marc. Emp. 1. pastĭcus, a, um, adj. pastus, fed, fattened: agnus, Apic. 8, 6. pastillārĭus, ii, m. pastillus, a maker of pastils, Inscr. (Ann. p. Chr. 435) Murat. 527"},"pastillum":{"lemma":"pastillum","pos":"","gen":"","def":"id., a little loaf or roll of bread, Varr. ap. Charis. p. 24 P.; a little round loaf for offering: pastillum in sacris libi genus rotundi, Paul. ex Fest. p. 250 Müll."},"pastillus":{"lemma":"pastillus","pos":"","gen":"","def":"dim. panis, a little loaf or roll: pastillus forma panis parvi utique deminutivum est a pane, Paul. ex Fest. p. 222 Müll.— Transf., medicine in the form of a round ball or cake, a lozenge, troche"},"pastus":{"lemma":"pastus","pos":"","gen":"","def":"pasco, pasture, fodder, food (class"},"pauci":{"lemma":"pauci","pos":"","gen":"","def":"paucus, II. A. paucĭes (or paucĭens), adv. paucus, a few times, seldom, rarely (ante-class.): tuam uxorem pauciens video, Titin. ap. Fest. p. 220 Müll. and ap. Non. 157, 17: in urbem paucies venire"},"paucus":{"lemma":"paucus","pos":"adj.","gen":"","def":"plur. paucūm, Enn. ap. Gell. 12, 4, fin.—Dat. plur. fem. paucabus, Cn. Gellius ap. Charis. p. 39 P.), adj. root pau-; Gr. παύω, to cause to cease, παῦλα, remnant, παῦρος, little"},"pauperasco":{"lemma":"pauperasco","pos":"v.","gen":"","def":"n. inch. , to grow poor (late Lat.), Falg. Rusp. Serm. 5, 6. paupercŭlus, a, um, adj. dim. , poor (not in Cic.): senex, Plaut. Aul. 2, 1, 49: anus, Ter. Heaut. 1, 1, 44: sumus pauperculi"},"paupertas":{"lemma":"paupertas","pos":"","gen":"-paupertatem","def":"pauper, poverty, small means, moderate circumstances (opp. as well to egestas, inopia, penuria, as to abundantia and luxuria, v. Doed. Syn. 3, pp. 111 and 118; class.) Lit.: pecuniaque erat parva"},"pausa":{"lemma":"pausa","pos":"","gen":"-class","def":", = παῦσις [root in παύω, to cause to cease, to stop], a pause, halt, stop, cessation, end (ante- and post-class. for quies, finis, etc.): Neptunus saevus undis asperis pausam dedit"},"pauso":{"lemma":"pauso","pos":"v.","gen":"-class","def":"n. pausa. Lit., to halt, cease, pause (ante- and postclass. for quiesco, interquiesco): cum capitis pausaverit dolor, Cael. Aur. Tard. 1, 1, 16: pausante vomitu, id. Acut. 3, 21"},"pausus":{"lemma":"Pausus","pos":"","gen":"","def":"id., the god of rest, Arn. 1, 15. pauxillātim, adv. pauxillus, = paulatim, by little and little, by degrees, gradually (ante-class.): ad aliquem pauxillatim accedere, Plaut. Ep. 2, 2, 63"},"pauxillisper":{"lemma":"pauxillisper","pos":"adv.","gen":"","def":"id., by little bits, by degrees: plus decem pondo amoris pauxillisper perdidi, Plaut. Truc. 5, 21 (id est per particulas, Non. 156, 2). pauxillĭtas, ātis, f. id., diminutiveness (late Lat.)"},"pauxillo":{"lemma":"pauxillo","pos":"","gen":"","def":"pauxillus. pauxillŭlum, adv., v. pauxillulus. pauxillŭlus (pausill-), a, um, adj. dim. , very little, very small (anteand post-class.): in libello hoc obsignato ad te attuli pauxillulo, Plaut. Ps. 2"},"pauxillum":{"lemma":"pauxillum","pos":"adv.","gen":"","def":", v. pauxillus. pauxillus (pausill-), a, um, adj. dim. , little, small (mostly ante-class.): res, Plaut. Poen. 3, 1, 63: peccatum, Turp. ap. Non. 363, 15 (al. pausillulum): ossa pauxilla atque minuta"},"pax":{"lemma":"pax","pos":"interj.","gen":"-stones","def":"from the root pac, pag, pacisco, pango; whence also pagina, pagus, q. v.: pacem a pactione conditionum putat dictam Sinnius Capito, quae utrique inter se populo sit observanda, Fest. p. 230 Müll."},"paxillus":{"lemma":"paxillus","pos":"","gen":"","def":", = πάσσαλος, a small stake, a peg. Lit., Varr. ap. Non. 153, 9; Col. 4, 16, 3; 8, 8, 3: dodrantales paxilli, Plin. 17, 21, 35, § 154"},"peccanter":{"lemma":"peccanter","pos":"adv.","gen":"","def":", v. pecco, P. a. fin. peccantĭa, ae, f. pecco, sin (postclass.), Tert. adv. Jud. 10. peccātēla, ae, f. id., sin (post-class.), Tert. Anim. 40. peccātĭo, ōnis, f. id., a failing, fault"},"pecco":{"lemma":"pecco","pos":"v.","gen":"","def":"n. and a. [often referred to Sanscr. pāpa, pāpaka, wicked; but better to root pik-, to be angry; cf.: piget, pigeo, and Fick, Vergl. Wört. 632], to miss or mistake any thing"},"pecten":{"lemma":"pecten","pos":"","gen":"-fish","def":"pecto, a comb. Prop., for the hair, Plaut. Capt. 2, 2, 18; Ov. Am. 1, 14, 15: deducit pectine crines, id. M. 4, 311; 12, 409; Petr. 126"},"pectis":{"lemma":"pectis","pos":"","gen":"","def":", a plant, called also consolida and symphyton, App. Herb. 59. pectĭtus, a, um, Part., from pecto."},"pecto":{"lemma":"pecto","pos":"v.","gen":"","def":"Ep. 77), pexum and pectĭtum, 3, v. a. Gr. πέκω, πεκτέω, to comb, shear; πόκος, fleece"},"pectus":{"lemma":"pectus","pos":"","gen":"-heartedness","def":"kindred with the Sanscr. vakshas, pectus, the breast, in men and animals. Lit., the breast, the breastbone: pectus, hoc est ossa praecordiis et vitalibus natura circumdedit, Plin. 11, 37, 82, § 207"},"pegris":{"lemma":"pegris","pos":"","gen":"-mussel","def":", a sea-mussel, Plin. 32, 11, 53, § 150. pējĕrātĭo, ōnis, f. pejero, perjury, Salvian. Gub. Dei, 4, 16. pējĕro, or, in the orig. form, perjūro (Vulg. Lev. 19, 12"},"pelina":{"lemma":"Pelina","pos":"","gen":"","def":", a goddess of the Pelignians, Inscr. Murat. 99, 3; 367, 1."},"pelinnaeus":{"lemma":"Pelinnaeus","pos":"","gen":"","def":", a mountain in Chios, Plin. 5, 31, 38, § 136. Pēlĭon, ii (masc. collat. form Pēlĭos, Plin. 4, 8, 15, § 30: Pelio, scanned as a dissyl. per syniz., Sil. 3, 495), n., = Πήλιον"},"pella":{"lemma":"Pella","pos":"adj.","gen":"","def":", = Πέλλα, a city of remote antiquity in Macedonia, the birthplace of Alexander the Great, now Alaklisi, or Apostolus, Plin. 4, 10, 17, § 34; Liv. 44, 46; 36, 7; 42, 51"},"pellaeus":{"lemma":"Pellaeus","pos":"","gen":"","def":"Pella, II. Pellārĭus, ĭi, m. pellis, one that prepares skins, a furrier (post-class.; cf. Varr. L. L. 8, § 55 Müll.), Firm. Math. 4, 7; cf.: pellarius, πελλοράφος, Gloss. Philox."},"pellax":{"lemma":"pellax","pos":"adj.","gen":"","def":"pellicio, = ποικιλομήτης, seductive, deceitful (poet. and postclass."},"pellex":{"lemma":"pellex","pos":"","gen":"","def":", v. paelex. pellĭcātor, qui pellicit ad fraudem, Paul. ex Fest. p. 204 Müll. pellĭcātus, v. pelicatus. pellĭcĕo, ēre, v. pellicio. pellĭcĕus, a, um, v. pellicius."},"pelliris":{"lemma":"pelliris","pos":"adj.","gen":"","def":"pellis, made of skin: galerus, quia fiebat ex pelle, Paul. ex Fest. p. 204 Müll. pellis, is (abl. sing. pelle; but pelli, Lucr. 6, 1270; App. Mag. 22), f. Gr. πέλλα, πέλας, skin"},"pello":{"lemma":"pello","pos":"v.","gen":"","def":"pulserat, Amm. 30, 5, 19), v. a. kindred with Gr. πάλλω, πέλω, to beat, strike, knock any thing or at any thing; to push, drive, hurl, impel, propel. Lit. In gen. (mostly poet."},"pellos":{"lemma":"pellos","pos":"adj.","gen":"-colored","def":", = πελλός or πέλλος, η, ον, dark-colored, Plin. 10, 60, 79, § 164. pellūcĕo, v. perluceo. pellūcĭdĭtas (perl-), ātis, f. pel lucidus, transparency, pellucidness: vitri, Vitr. 2"},"peltasta":{"lemma":"peltasta","pos":"","gen":"","def":", = πελταστής, a soldier armed with the pelta, a peltast, Liv. 28, 5, 11: cetrati, quos peltastas vocant, id. 31, 36. peltātus, a, um, adj. pelta, armed with the pelta, Ov. Am. 2, 14, 2"},"pemma":{"lemma":"pemma","pos":"","gen":"","def":", = πέμμα, pastry: panis, pemma, lucuns, Varr. ap. Non. 131, 24: vinum, pemma, lucuns, id. 131, 26. pĕnārĭus, a, um, adj. penus, of or for provisions: cella, Cic. Sen. 16, 56"},"pendix":{"lemma":"pendix","pos":"","gen":"","def":"id., perh. i. q. pendigo: A PENDICE CEDRI, Inscr. Grut. 601, 10 and 11."},"pendo":{"lemma":"pendo","pos":"v.","gen":"-class","def":"45, 26 fin.: penderit for pependerit, Paul. Nol. Carm. 14, 122), v. a. and n. etym. dub.; cf. root σφαδ-, σφενδόνη, a sling; Lat. funda.—Lit., to cause to hang down, to suspend"},"pennesco":{"lemma":"pennesco","pos":"v.","gen":"-class","def":"n. inch. , to put forth feathers or wings, to become fledged (post-class.), Cassiod. Var. 1, 38. pennĭfer, ĕra, ĕrum, adj. penna-fero, feathered, winged (post-class. prose): armi, Sid. Carm. 2"},"pennor":{"lemma":"pennor","pos":"v.","gen":"","def":"dep. n. , to put forth wings, become fledged, Dracont. 1, 262. pennŭla, ae, f. dim. id., a little wing (rare but class.): cum pulli pennulis uti possunt, Cic. N. D. 2, 52, 129: tensa, Ven. Carm. 3"},"pennus":{"lemma":"pennus","pos":"adj.","gen":"","def":"pinna, pointed, sharp: pennum antiqui acutum dicebant: unde et avium pennae, quia acutae, Isid. Orig. 19, 19, 11 dub. (al. pinnum)."},"pensa":{"lemma":"pensa","pos":"","gen":"","def":"pendo, a day's provisions, a ration for a day, Edict. Diocl. p. 19. pensābilis, e, adj. penso, reparable (post-class.): damna, Amm. 31, 13, 11. pensātĭo, ōnis, f. id.. Lit., a weighing, weighing out"},"pensim":{"lemma":"pensim","pos":"adv.","gen":"","def":", another reading for pensiculate; v. pensiculo fin. pensĭo, ōnis, f. pendo; lit., a weighing, weighing out; hence, A weight (only in Vitr.), Vitr. 10, 16"},"penso":{"lemma":"penso","pos":"","gen":"","def":"freq. a. pendo, to weigh or weigh out carefully (not freq. till after the Aug. per."},"pensor":{"lemma":"pensor","pos":"","gen":"","def":"id., one who weighs or considers, a weigher, examiner (eccl. Lat.): elementorum, Aug. Conf. 5, 4 fin.; id. Civ. Dei, 15, 27."},"pensum":{"lemma":"pensum","pos":"","gen":"","def":"pendo, P. a. B. pensūra, ae, f. pendo, a weighing, Varr. L. L. 5, § 183 Müll. pensus, a, um, Part. and P. a., from pendo. pentăchordus, a, um, adj., = πεντάχορδος, five-stringed (post-class.)"},"pentas":{"lemma":"pentas","pos":"","gen":"-class","def":", = πεντάς, the number five, five (post-class.), Mart. Cap. 7, §§ 735 and 745. pentăsēmus, a, um, adj., = πεντάσημος, that has five marks or divisions of time (post-class.): pes, Mart. Cap. 9, § 978."},"pentaspaston":{"lemma":"pentaspaston","pos":"","gen":"","def":", = πεντάσπαστον, a tackle with five pulleys, two in the lower block and three in the upper, Vitr. 10, 3."},"pentasphaerus":{"lemma":"pentasphaerus","pos":"adj.","gen":"","def":", = πέντεσφαῖρα, folium, a kind of costly spice, Dig. 39, 4, 16, § 7. pentastĭchoe porticus = πεντάστιχοι, having five rows of columns, Treb. Gall. 18. pentăsyllăbus, a, um, adj., = πεντασύλλαβος"},"pentheus":{"lemma":"Pentheus","pos":"adj.","gen":"","def":", = Πενθεύς, son of Echion and Agave, grandson of Cadmus, and king of Thebes"},"pentri":{"lemma":"Pentri","pos":"","gen":"","def":", a Samnite people, Liv. 9, 31. pĕnu, v. penus init. pĕnŭārĭus, a, um, adj. penus, of or for provisions (post-class. for penarius): cellae, Dig. 33, 9, 3, § 11. pēnŭla, ae, v. paenula. pēnultĭmus, a"},"peplis":{"lemma":"peplis","pos":"","gen":"","def":", = πεπλίς, the name of two plants, one of which was also called porcilaca, Plin. 20, 20, 81, § 210"},"per-bacchor":{"lemma":"per-bacchor","pos":"v.","gen":"-bacchor","def":"dep. a:, to carouse or revel through: multos dies, Cic. Phil. 2, 41, 104: annum suum in re publicā, Ps. -Cic. Decl. in Sall. 3, 10.— Transf., of fire: perbacchata domos incendia"},"per-blandus":{"lemma":"per-blandus","pos":"adj.","gen":"-blandus","def":", very courteous or charming, very engaging, very bland: successor, Cic. Q. Fr. 1, 2, 3: oratio, Liv. 23, 10, 1: adulatio, Juvenc. 1, 705.— Adv.: perblandē, very winningly: aliquem salutare"},"per-caedo":{"lemma":"per-caedo","pos":"v.","gen":"-caedo","def":"a., to cut up completely = ad internecionem caedere (post-class.): exercitum, Flor. 3, 20, 10. (dub."},"per-calleo":{"lemma":"per-calleo","pos":"v.","gen":"-calleo","def":"a., to know or understand well: quinque et viginti gentium linguas, Gell. 17, 17, 2."},"per-callesco":{"lemma":"per-callesco","pos":"","gen":"-callesco","def":"inch. n. and a. * Neutr., to become very hardened, very callous: civitatis patientia percalluerat, Cic. Mil. 28, 76.— Act., to get a good knowledge of"},"per-cautus":{"lemma":"per-cautus","pos":"adj.","gen":"-cautus","def":", very cautious, Cic. Q. Fr. 1, 1, 6, § 18. percēdo, cessi, ĕre, v. a.: cedit, cessit, percedit, percessit, Not. Tir. p. 17. per-cĕlĕber, bris, bre, adj., very famous"},"per-cello":{"lemma":"per-cello","pos":"v.","gen":"-cello","def":"17, 8, 4; 25, 8, 13), v. a. cf.: procella, celer, to beat down, throw down; to overturn, upset (class."},"per-cognosco":{"lemma":"per-cognosco","pos":"v.","gen":"-cognosco","def":"a., to become perfectly acquainted with: aliquem, Plaut. Truc. 1, 2, 50 (Speng. pergnovi).— Hence, percognĭtus, a, um, P. a., well known: lex naturae non ignota, etsi nondum percognita, Plin. 2, 45"},"per-crassus":{"lemma":"per-crassus","pos":"adj.","gen":"-crassus","def":", very thick, Cels. 5, 26, 20. per-crēbesco, bŭi, and per-cre-bresco, brui, 3, v. inch. n., to become very frequent or prevalent, to be spread abroad (class.): cum hoc percrebrescit, Cic. Att. 1, 1"},"per-cresco":{"lemma":"per-cresco","pos":"v.","gen":"-cresco","def":"n., to grow greatly, Ser. Samm. 36, 679. per-crībro, āvi, ātum, 1, v. a., to sift thoroughly, Scrib. Comp. 87: res contusae et percribratae, id. ib. 289. per-crŭcĭo, āre, v. a."},"per-cumbo":{"lemma":"per-cumbo","pos":"v.","gen":"-cumbo","def":"n., mentioned as an unused form, Varr. L. L. 9, § 49 Müll. percunctātĭo, ōnis, v. percontatio. percunctātīvē and percunctātī-vus, v. percontativus. percunctātor, ōris, v. percontator."},"per-curro":{"lemma":"per-curro","pos":"v.","gen":"-curro","def":"a. and n. Act., to run through, hasten through; to pass through, traverse, run over, pass over or along class."},"per-densus":{"lemma":"per-densus","pos":"adj.","gen":"-densus","def":", very compact, very dense (post-Aug.): humus, Col. 3, 12, 2. perdĕo for pereo, v. pereo init."},"per-depso":{"lemma":"per-depso","pos":"v.","gen":"-depso","def":"a., to knead over, to work up, in mal. part., Cat. 74, 3. perdīcālis, e, adj. perdix, of or belonging to partridges, partridge- (postclass.): herba, App. Herb. 81. Perdiccas and Perdicca, ae, m."},"per-dignus":{"lemma":"per-dignus","pos":"adj.","gen":"-dignus","def":", very worthy"},"per-disco":{"lemma":"per-disco","pos":"v.","gen":"-disco","def":"a., to learn thoroughly or completely, to get by heart (rare but class.): omnia jura belli, Cic. Balb. 20, 47: locus de moribus est oratori perdiscendus, id. de Or. 1, 15, 69: hominis speciem pingere"},"per-dormisco":{"lemma":"per-dormisco","pos":"v.","gen":"-dormisco","def":"n. dormio, to sleep on: perdormiscin' tu usque ad lucem? Plaut. Men. 5, 5, 29. per-dūco, xi, ctum, 3 (imper. perduce for perduc, Ser. Samm. 40, 754), v. a., lit., to lead or bring through"},"per-dulcis":{"lemma":"per-dulcis","pos":"adj.","gen":"-dulcis","def":", very sweet"},"per-efflo":{"lemma":"per-efflo","pos":"v.","gen":"-efflo","def":"a., to breathe out entirely, breathe away (post-class.): animam, App. M. 8, p. 207, 23. per-efflŭo, 3, v. n., to flow through.— Trop., to forget, Vulg. Heb. 2"},"per-flo":{"lemma":"per-flo","pos":"v.","gen":"-flo","def":"a. and n., to blow through or over (not in Caes.). Act.: cum venti nubila perflant, Lucr. 6, 132"},"per-formo":{"lemma":"per-formo","pos":"v.","gen":"-formo","def":"a., to form thoroughly, to form (eccl. Lat.): ad malum performantur (al. praeformantur), Tert. Apol. 1. per-fŏro, āvi, ātum, 1 (in tmesi: perque forare, Lucr. 5, 126, 8), v. a., to bore through"},"per-fragrans":{"lemma":"per-fragrans","pos":"adj.","gen":"-fragrans","def":", very fragrant (late Lat.), Fulg. Serm. 27. per-frĕmo, ui, 1, v. n., to roar or snort along (ante-class.): perfremunt delphini, Att. ap. Cic. N. D. 2, 35, 89. per-frĕquens, entis, adj., very crowded"},"per-fundo":{"lemma":"per-fundo","pos":"v.","gen":"-fundo","def":"a., to pour over, to wet, moisten, bedew, besprinkle (class."},"per-fungor":{"lemma":"per-fungor","pos":"v.","gen":"-fungor","def":"dep. n. Lit., to fulfil, perform, discharge (class.). With abl.: munere quodam necessitatis, et gravi opere perfungimur, Cic. Sen. 21, 77: honoribus amplissimis et laboribus maximis, id. Fam. 1, 8"},"per-glisco":{"lemma":"per-glisco","pos":"v.","gen":"-glisco","def":"n., to become quite fat (post-Aug.): gallina pergliscit, Col. 8, 7, 4. per-gnārus, a, um, adj., that has a thorough knowledge of, that is very experienced"},"per-graecor":{"lemma":"per-graecor","pos":"v.","gen":"-graecor","def":"dep. n., to live just like the Greeks, to play the Greek, i. e. to revel, carouse (ante-class.): ut cum solo pergraecetur milite, Plaut. Truc. 1, 1, 69; id. Most. 1, 1, 21"},"per-grandesco":{"lemma":"per-grandesco","pos":"","gen":"-grandesco","def":"inch. n., to grow very large (ante-class.), Att. ap. Non. 115, 9."},"per-grandis":{"lemma":"per-grandis","pos":"adj.","gen":"-grandis","def":", very large, very great (rare but class.): gemma, Cic. Verr. 2, 4, 27, § 62: vectigal, id. Agr. 1, 4, 9: lucrum, Plaut. Pers. 4, 3, 23: pergrandis natu, very old, very aged, Liv. 29, 29, 6: lapis"},"per-gustus":{"lemma":"per-gustus","pos":"","gen":"-gustus","def":", taste (late Lat.): severi, Epist. Jud. Minor. Conv. p. 830, t. 41 Migne. pĕr-haurĭo, si, stum, 4, v. a. Lit., to drain completely, to drink up: calicem uno haustu, App. M. 10, p. 246, 39"},"per-laetus":{"lemma":"per-laetus","pos":"adj.","gen":"-laetus","def":", very joyful or glad, full of joy: supplicatio, Liv. 10, 21. perlapsus, a, um, Part., from perlabor. per-lātē adv., very widely, very extensively: perlate patere, Cic. de Or. 2, 4, 17. per-lătĕo, ŭi"},"per-longinquus":{"lemma":"per-longinquus","pos":"adj.","gen":"-longinquus","def":", lasting very long, Plaut. Bacch. 5, 2, 76."},"per-longus":{"lemma":"per-longus","pos":"adj.","gen":"-longus","def":", very long. Lit.: via, Cic. Att. 5, 20, 8: perlongum. adverb., for a very long time, very long, Aus. Epigr. 1, 7.— Transf., very tedious, Plaut. Trin. 3, 3, 17.—Adv.: perlongē, a very long way off"},"per-lustro":{"lemma":"per-lustro","pos":"v.","gen":"-lustro","def":"a. To go or wander all through, to traverse completely. Lit.: hostium agros, Liv. 8, 36: haec omnia (loca), id. 7, 34: perlustrata armis tota Germania, Vell. 2, 106, 1.— Trop., to view all over"},"per-magnus":{"lemma":"per-magnus","pos":"adj.","gen":"-magnus","def":", very great, very large: accessio, Cic. Fin. 1, 17, 15: vis naturae, id. ib. 2, 7, 18: hereditas, Cic. Verr. 2, 1, 10, § 27: numerus, Caes. B. G. 7, 31.— As subst.: permagnum, i, n."},"per-mingo":{"lemma":"per-mingo","pos":"v.","gen":"-mingo","def":"a. Lit., to make water upon one"},"per-misceo":{"lemma":"per-misceo","pos":"v.","gen":"-misceo","def":"a., to mix or mingle together"},"per-mitto":{"lemma":"per-mitto","pos":"v.","gen":"-mitto","def":"a., to let go through, suffer to pass through. Lit. (very rare): fenestellae permittant columbas ad introitum exitumque, Pall. 1, 24, 1. — Transf., to let go, let loose: equos permittunt in hostem"},"per-moestus":{"lemma":"per-moestus","pos":"","gen":"-moestus","def":"permaestus. permŏlestē, adv., v. permolestus fin. per-mŏlestus, a, um, adj., very troublesome: atque hi non sunt permolesti, Cic. Att. 1, 18, 2.—Adv.: permŏlestē"},"per-mollis":{"lemma":"per-mollis","pos":"adj.","gen":"-mollis","def":", very soft: quod etiam in carminibus est permolle, Quint. 9, 4, 65. per-mŏlo, ĕre, v. a., to grind up. Lit.: piperis grana, Ser. Samm. 19, 334.— Transf., in mal. part.: alienas uxores, Hor. S. 1, 2"},"per-multus":{"lemma":"per-multus","pos":"adj.","gen":"-multus","def":", very much, very many (class.): nescio quantulum attulerit"},"per-mundo":{"lemma":"per-mundo","pos":"v.","gen":"-mundo","def":"a., to cleanse thoroughly, Theod. Prisc. 1, 19; Vulg. Matt. 3, 12."},"per-mundus":{"lemma":"per-mundus","pos":"adj.","gen":"-mundus","def":", very cleanly: volucres, Varr. R. R. 3, 7, 5. per-mūnĭo, īvi or ĭi, ītum, 4, v. a., to fortify completely, to finish fortifying (not in Cic. or Caes.). Lit.: quae munimenta incohaverat, permunit"},"per-narro":{"lemma":"per-narro","pos":"v.","gen":"-narro","def":"a., to narrate completely: pernarro, ἀφηγοῦμαι, Gloss. Philox. per-nāvĭgātus, a, um, Part. , sailed through or over, Plin. 2, 67, 67, § 167. per-nĕcessārĭus, a, um, adj. Very necessary: tempus"},"per-nocto":{"lemma":"per-nocto","pos":"v.","gen":"-nocto","def":"n., to stay all night long, to pass the night (class.). Lit.: foris non est pernoctandum, Varr. R. R. 2, 3: noctem pernoctare perpetem, Plaut. Truc. 2, 2, 22: cum ibi pernoctaret, Cic. Clu. 13"},"per-nosco":{"lemma":"per-nosco","pos":"v.","gen":"-nosco","def":"a. To examine thoroughly: pernoscite, Furtumne factum existimetis, an, etc., Ter. Ad. prol. 12.—Hence, in perf., to have examined or discerned, to know thoroughly"},"per-nox":{"lemma":"per-nox","pos":"adj.","gen":"-nox","def":", continuing through the night, that lasts all night (not ante-Aug.): (bos) jacet pernox instrato cubili, Verg. G. 3, 230: luna pernox erat, was up all night, was at her full, Liv. 5, 28, 10"},"per-paruus":{"lemma":"per-parvus","pos":"adj.","gen":"-parvus","def":", very little, very small: semina, Lucr. 3, 216"},"per-pasco":{"lemma":"per-pasco","pos":"v.","gen":"-pasco","def":"n., to graze, pasture. Lit., Varr. L. L. 5, § 95 Müll.— Transf.: perpascor, ci, 3, v. dep., to lay waste, devastate: fluvius perpascitur agros, Sev. Aetn. 489.—Hence, perpastus, a, um, P. a."},"per-paucus":{"lemma":"per-paucus","pos":"adj.","gen":"-paucus","def":", very little, very few: homines, Ter. Eun. 3, 1, 19"},"per-paulus":{"lemma":"per-paulus","pos":"adj.","gen":"-paulus","def":", very little. As subst.: perpaulum, i, n., a very little: loci, Cic. de Or. 2, 35, 150.— Adv.: per-paulum, a very little indeed: declinare, Cic. Fin. 1, 6, 19."},"per-pauper":{"lemma":"per-pauper","pos":"adj.","gen":"-pauper","def":", very poor: vicinus, Afran. ap. Non. 280, 25 (Com. Rel. p. 157 Rib.): rex, Cic. Att. 6, 3, 5."},"per-pauxillus":{"lemma":"per-pauxillus","pos":"adj.","gen":"-pauxillus","def":", very little"},"per-pello":{"lemma":"per-pello","pos":"v.","gen":"-pello","def":"a., to strike or push violently. Lit. (rare"},"per-pendo":{"lemma":"per-pendo","pos":"v.","gen":"-pendo","def":"a., to weigh carefully or exactly. Lit. (very rare): in librili pendere, Gell. 20, 1, 34.— Trop., to weigh carefully, examine; to ponder, consider (class."},"per-pexus":{"lemma":"per-pexus","pos":"adj.","gen":"-pexus","def":"pecto, wellcombed (post-class.): barba, Firm. Math. 5, 5."},"per-pinguis":{"lemma":"per-pinguis","pos":"adj.","gen":"-pinguis","def":", very rich (postclass.): harenae, Auct. Itin. Alex. M. 45 Mai. per-plăcĕo, ēre, v. n., to please greatly: ecquid placeant, me rogas? immo hercle vero perplacent, Plaut. Most. 3, 3"},"per-plexus":{"lemma":"per-plexus","pos":"adj.","gen":"-plexus","def":"plecto, entangled, involved, intricate, confused (not in Cic. or Caes.). Lit.: figurae, Lucr. 2, 102; cf. id. 2, 459"},"per-porto":{"lemma":"per-porto","pos":"v.","gen":"-porto","def":"a., to carry or transport a thing to a place: praedam Carthaginem, Liv. 28, 46 fin. perpōtātĭo, ōnis, f. perpoto, a continued drinking"},"per-prosper":{"lemma":"per-prosper","pos":"adj.","gen":"-prosper","def":", very favorable, very prosperous: valetudo, very good, excellent, Suet. Claud. 31. per-prūrisco, ĕre, v. inch. n., to itch all over: ubi perpruriscamus usque ex unguiculis, Plaut. Stich. 5, 5, 20"},"per-pugnax":{"lemma":"per-pugnax","pos":"adj.","gen":"-pugnax","def":", very pugnacious: perpugnax in disputando, Cic. de Or. 1, 20, 93; Aug. contr. Acad. 3, 4."},"per-pulcher":{"lemma":"per-pulcher","pos":"adj.","gen":"-pulcher","def":", very beautiful: dona, Ter. Eun. 3, 2, 15."},"per-pulsus":{"lemma":"per-pulsus","pos":"adj.","gen":"-pulsus","def":"pello, greatly smitten: me malis perpulsum, Front. Ep. ad Verum, 9 Mai."},"per-pungo":{"lemma":"per-pungo","pos":"v.","gen":"-pungo","def":"a., to pierce through and through (post-class. and only in part. perf.), Cael. Aur. Acut. 2, 10, 71"},"per-quam":{"lemma":"per-quam","pos":"adv.","gen":"-quam","def":"(also, less correctly, written separately, per quam, v. per fin.), as much as possible, extremely, exceedingly: illorum mores perquam meditate tenes, Plaut. Bacch. 3, 6, 16: perquam indignis modis"},"per-rumpo":{"lemma":"per-rumpo","pos":"v.","gen":"-rumpo","def":"n. and a., to break through. Neutr., to break or rush through, to force one's way through: per medios hostes perrumpunt, Caes. B. G. 6, 39: in vestibulum templi, Liv. 3, 18: in urbem, id. 10"},"per-saepe":{"lemma":"per-saepe","pos":"adv.","gen":"-saepe","def":", very often, very frequently: quod persaepe fit, Cic. Lael. 20, 75: frons, oculi, voltus persaepe mentiuntur, id. Q. Fr. 1, 1, 5, § 15: persaepe velut qui Junonis sacra ferret, Hor. S. 1, 3, 10"},"per-saeuus":{"lemma":"per-saevus","pos":"adj.","gen":"-saevus","def":", very furious: flumina, Mel. 2, 5, 8. Persagădae, v. Pasargadae. persalsē, adv., v. persalsus fin."},"per-salsus":{"lemma":"per-salsus","pos":"adj.","gen":"-salsus","def":", very witty, Cic. de Or. 2, 69, 279.—Hence, adv.: per-salsē, very wittily: gratias agere, Cic. Q. Fr. 2, 15, 3. persălūtātĭo, ōnis, f. persaluto, a saluting of all, assiduous salutation"},"per-sanctus":{"lemma":"per-sanctus","pos":"adj.","gen":"-sanctus","def":", very sacred or holy: CONIVX, Inscr. Afr. ap. Rénier, 4414.—Hence, adv.: per-sanctē, very sacredly or religiously: dejerare, to swear solemnly, Ter. Hec. 5, 2, 5: jurare, Suet. Tib. 10"},"per-scindo":{"lemma":"per-scindo","pos":"v.","gen":"-scindo","def":"a., to rend asunder or in pieces: nubem, Lucr. 6, 138; 180: vestem, Tib. 1, 10, 63: omnia perscindente vento, Liv. 21, 58, 57; Lucr. 6, 111.—Pass., Lucr. 4, 599."},"per-scisco":{"lemma":"per-scisco","pos":"v.","gen":"-scisco","def":"a., to learn thoroughly, become well informed of: causam tumultūs cupidus persciscere, Dict. Cret. 2, 37. perscissus, a, um, Part., from perscindo. per-scītus, a, um, adj., very clever"},"per-segnis":{"lemma":"per-segnis","pos":"adj.","gen":"-segnis","def":", very sluggish or inactive: proelium, Liv. 25, 15, 12. Persēis, ĭdis, f., v. 2. Persa, B. Persēĭus, a, um, v. 2. Persa, A., and 1. Perseus, B. 2. per-sĕnesco, nŭi, 3, v. inch. n."},"per-sentisco":{"lemma":"per-sentisco","pos":"","gen":"-sentisco","def":"intens. a. To perceive clearly, to detect (ante-class.): nunc ne legio persentiscat, clam illuc redeundum'st mihi, Plaut. Am. 1, 3, 28"},"per-serpo":{"lemma":"per-serpo","pos":"v.","gen":"-serpo","def":"n., to creep perpetually, to crawl, Lucil. ap. Charis. p. 100, 31 Keil. per-servĭo, īre, v.n., to serve throughout: alicui, Vop. Prob. 18 dub."},"per-seruo":{"lemma":"per-servo","pos":"v.","gen":"-servo","def":"a., to preserve (post-class.): patientiam, Tert. Pat. 5."},"per-siccus":{"lemma":"per-siccus","pos":"adj.","gen":"-siccus","def":", very dry: oculi, Cels. 3, 6, 23: tempus, Fest. s. v. substillum, pp. 306 and 307 Müll. Persĭcē, adv., v. Persae, II. B. fin. Persĭcē, ēs, f., v. Persae, II. B. 2. Persĭcus, a, um, v. Persae, II. B."},"per-signo":{"lemma":"per-signo","pos":"v.","gen":"-signo","def":"a. (extremely rare; not in Cic. or Caes.). To note down, record: uni dona, Liv. 25, 7, 5.— To mark: notis corpus, Mel. 1, 19, 20"},"per-simplex":{"lemma":"per-simplex","pos":"adj.","gen":"-simplex","def":", very plain or simple: victus, Tac. A. 15, 45 fin."},"per-sisto":{"lemma":"per-sisto","pos":"v.","gen":"-sisto","def":"n., to continue steadfastly, to persist (rare): si perstiteris ad corpus ea referre, Cic. Fin. 2, 33, 107 fin.: in impudentiā, Liv. 38, 14, 11: in luxuriā, Treb. Poll. Gall. 4"},"per-soluo":{"lemma":"per-solvo","pos":"v.","gen":"-solvo","def":"a., to release or discharge completely"},"per-sterno":{"lemma":"per-sterno","pos":"v.","gen":"-sterno","def":"a., to pave all over, to make quite even or level: viam, Liv 10, 47, 4; Vitr. 7, 1, 7."},"per-stringo":{"lemma":"per-stringo","pos":"v.","gen":"-stringo","def":"a. To bind tightly together; to draw together, draw up, contract: vitem, Cato, R. R. 32: stomachus nimio rigore perstrictus, Veg. Vet. 3, 53"},"per-sulco":{"lemma":"per-sulco","pos":"v.","gen":"-sulco","def":", ātum, 1, v. a., to furrow through, to plough up.—Trop.: rugis persulcata genas, Claud. in Ruf. 1, 136. persultātor, ōris, m. persulto, one who leaps or skips about (post-class.): litoris"},"per-sulto":{"lemma":"per-sulto","pos":"v.","gen":"-sulto","def":"a. and n. salto, to leap, skip, or prance about in a place (not in Cic. or Caes.). Lit. Neutr.: in agro, Liv. 34, 20: solo stabili, id. 44, 9: ante vallum, Tac. A. 4, 47: notis vadis, id. H. 5"},"per-tango":{"lemma":"per-tango","pos":"v.","gen":"-tango","def":"a., to touch all over, i. e. to baste well (post-class.): pullum suo sibi jure, Apic. 6, 9"},"per-tendo":{"lemma":"per-tendo","pos":"v.","gen":"-tendo","def":"a., and n.—Prop., to stretch out, extend hence, transf., * Act., to carry out, go on with, perform any thing: video non licere ut coeperam hoc pertendere, Ter. Heaut. 5, 5, 9.— Neutr. Prop."},"per-tento":{"lemma":"per-tento","pos":"v.","gen":"-tento","def":"a., to feel all over"},"per-texo":{"lemma":"per-texo","pos":"v.","gen":"-texo","def":"a. Lit. To weave throughout, weave entirely: palla bysso tenui pertexta, i. e. byssina, App. M. 11, p. 258, 21.— To interweave, i. e. to furnish, decorate, adorn with any thing: Odeum"},"per-tingo":{"lemma":"per-tingo","pos":"v.","gen":"-tingo","def":"a. tango, to stretch out, reach, extend to a certain point (rare; not in Cic."},"per-tristis":{"lemma":"per-tristis","pos":"adj.","gen":"-tristis","def":", very sad or mournful. Lit.: carmen, Cic. poët. Div. 1, 8, 14.— Transf., very austere or morose: patruus, Cic. Cael. 11, 25. pertrītus, a, um, Part., rubbed to pieces"},"per-trux":{"lemma":"per-trux","pos":"adj.","gen":"-trux","def":", very savage or terrible: bestiae, App. M. 5, p. 166, 22. per-tŭmesco, mŭi, 3, v. inch. n., to swell up greatly, Not. Tir. p. 115. per-tŭmĭdus, a, um, adj."},"per-turbo":{"lemma":"per-turbo","pos":"v.","gen":"-turbo","def":"a., to throw into confusion or disorder, to confuse, disturb (cf.: confundo, misceo). Lit.: omnia, Ter. And. 3, 4, 22: provinciam, Cic. Sull. 20, 56: aetatum ordinem, id. Brut. 62"},"per-turpis":{"lemma":"per-turpis","pos":"adj.","gen":"-turpis","def":", very shameful, scandalous, abominable, Cic. Cael. 20, 50 pertūsĭo, ōnis, f. pertundo, a perforation (late Lat.), Ps. Soran. Quu. Medic. 230. pertūsūra, ae, f. id., a thrusting or boring through"},"per-uasto":{"lemma":"per-vasto","pos":"v.","gen":"-vasto","def":"a., to lay waste, devastate: fines, Liv. 6, 4: pervastatis passim agris, id. 8, 19: pervastata Italia, Tac. A. 15, 45: Boii Laevos cum pervastassent, Liv. 33, 37, 6. pervāsus, a, um, Part."},"per-uello":{"lemma":"per-vello","pos":"v.","gen":"-vello","def":"a., to pull or pluck hard; to pull, iwitch any thing. Lit.: nates, Plaut. Pers. 5, 2, 66: aurem, Phaedr. 5, 5, 32"},"per-uoluo":{"lemma":"per-volvo","pos":"v.","gen":"-volvo","def":"a., to roll or tumble about (syn. voluto). Lit.: aliquem in luto, Ter. And. 4, 4, 38.—Mid., to roll one's self, to roll: in suo pervoluta sanguine, weltering, App. M. 8, p. 207, 22.— Transf."},"perca":{"lemma":"perca","pos":"","gen":"","def":", = πέρκη, a kind of fish, a perch, Plin. 9, 16, 24, § 57; cf. id. 32, 9, 34, § 107; 32, 10, 44, § 126; 32, 11, 53, § 145; Ov. Hal. 112; Aus. Idyll. 10, 115."},"percepta":{"lemma":"percepta","pos":"","gen":"","def":"plur., v. percipio, P. a. fin. perceptībĭlis, e percipio. Perceptible, Cassiod. Hist. Eccl. 5, 20.— Participating in any thing, Boëth. Dial. in Porphyr. 1, 20. perceptĭo, ōnis, f. percipio, a taking"},"perceptor":{"lemma":"perceptor","pos":"","gen":"","def":"id., a receiver, imbiber (late Lat.): sapientiae, Aug. Soliloq. 1, 1 fin. perceptus, a, um, Part. and P. a., from percipio."},"percernis":{"lemma":"percernis","pos":"adj.","gen":"-cerno","def":"per-cerno, easily visible, Inscr. Fabr. p. 615, n. 127. per-cīdo, cīdi, cīsum (perf. percecīdi, Flor. 4, 12, 7), 3, v. a. caedo, to beat or cut to pieces, to smash. In gen.: os alicui, Plaut. Pers. 2"},"percingo":{"lemma":"percingo","pos":"","gen":"","def":"l. for praecingere (q. v.), Col. 10, 347"},"percis":{"lemma":"percis","pos":"","gen":"","def":", a false reading for pegris, Plin. 32, 11, 53, § 150. percīsus, a, um, Part., v. percido. per-cĭto, āvi, ātum, 1, v. a., to excite thoroughly, strongly, vehemently (ante-class.)"},"perculsus":{"lemma":"perculsus","pos":"","gen":"","def":"percello, a shock, Tert. Anim. 52."},"percultor":{"lemma":"percultor","pos":"","gen":"","def":"2. percolo, an ardent adorer or reverencer: doctorum, Aur. Vict. Caes. 1, 5. percultus, a, um, Part., from 2. percolo."},"percuncto":{"lemma":"percuncto","pos":"","gen":"","def":"percontor. per-cŭpĭdus, a, um, adj., very partial to, very fond of one.—With gen.: percupidus tui, Cic. Fam. 1, 7, 2. per-cŭpĭo, pĕre, v. a., to wish greatly, desire earnestly"},"percurso":{"lemma":"percurso","pos":"","gen":"","def":"freq. a. and n. id.. Act., to run or range through, ramble over (perh. not ante-Aug.): ripas, Plin. Pan. 12, 11.— Neutr., to range or rove about: finibus nostris, Liv. 23, 42, 10."},"percursor":{"lemma":"percursor","pos":"","gen":"","def":"id., one who runs through: viae, Lact. 6, 7 dub. (al. praecursor). percursus, a, um, Part., from percurro. percussĭbĭlis, e, adj. percutio, penetrating, pervading (post-class.): odor"},"percussor":{"lemma":"percussor","pos":"","gen":"","def":"id., a striker, stabber, shooter. In gen. (post-Aug.): leo vulneratus percussorem novit, Plin. 8, 16, 19, § 51.— In partic., a murderer, assassin, bandit (class."},"percussus":{"lemma":"percussus","pos":"","gen":"","def":"percutio, a beating, striking (poet. and in post-Aug. prose): caducis Percussu crebro saxa cavantur aquis, Ov. P. 2, 7, 40"},"perdix":{"lemma":"perdix","pos":"","gen":"","def":", = πέρδιξ, a partridge, Plin. 10, 33, 51, § 100; Mart. 3, 37, 15: perdicas Boeotios, Varr. ap. Non. 218, 18: picta, Mart. 3, 58, 15; Vulg. Jer. 17, 11."},"perducto":{"lemma":"perducto","pos":"","gen":"","def":"freq. a. perduco, to lead, conduct to or over a place (Plautin. in the double sense of perductor, q. v.): quicquid est, errabo potius, quam perductet quispiam, Plaut. Most. 3, 2, 160."},"perductor":{"lemma":"perductor","pos":"","gen":"","def":"id., a leader, conductor"},"perfector":{"lemma":"perfector","pos":"","gen":"","def":"perficio, a finisher, perfecter (rare but class.): mearum voluptatum, Ter. Eun. 5, 8, 4: dicendi, Cic. de Or. 1, 60, 257; Scip. ap. Cic. Att. 8, 11, 1."},"perfectrix":{"lemma":"perfectrix","pos":"","gen":"","def":"perfector, she that finishes or perfects (very rare): philosophia beatae vitae perfectrix, Nep. ap. Lact. 3, 15, 10. perfectus, a, um, Part. and P. a., from perficio."},"perfectus":{"lemma":"perfectus","pos":"","gen":"","def":"perficio, a finishing or perfecting"},"perfingo":{"lemma":"perfingo","pos":"v.","gen":"-fingo","def":"a. per-fingo, to form, represent: VARIOS AVIVM CANTVS, Inscr. Fabr. p. 685. per-fixus, a, um, Part. of perfigo, q. v. perflābĭlis, e, adj. perflo. Pass."},"perfoecundus":{"lemma":"perfoecundus","pos":"","gen":"","def":"perfecundus. perfoedĕrātus, a, um, Part. , strongly leagued together, Not. Tir. p. 71. perfŏrācŭlum, i, n. perforo, a borer, an auger or gimlet (post-class.), Arn. 6, 200"},"perfosso":{"lemma":"perfosso","pos":"v.","gen":"","def":"a. id., to dig through: perfosso, διορύσσω, Gloss. Gr. Lat."},"perfossor":{"lemma":"perfossor","pos":"","gen":"-class","def":"id., a digger through, breaker through (ante- and post-class.): perfossor parietum, a house-breaker, Plaut. Ps. 4, 2, 23"},"perfringo":{"lemma":"perfringo","pos":"v.","gen":"","def":"a. perfrango, to break through, to break or dash in pieces, to shiver, shatter (class.). Lit. In gen.: elephanto pugno perfregisti bracchium, Plaut. Mil. 1, 1"},"pergo":{"lemma":"pergo","pos":"v.","gen":"-rego","def":"a. and n. per-rego. Act. In gen., to go on, continue, proceed with any thing (esp. a motion), to pursue with energy, prosecute vigorously (v. Mütz. ad Curt. 3, 8, 7"},"pergus":{"lemma":"Pergus","pos":"","gen":"","def":", a lake in Sicily, near the city of Enna, where Pluto is said to have carried off Proserpine, the mod. Lago Pergusa, Ov. M. 5, 386; Claud. Rapt. Pros. 2, 112."},"perlaxo":{"lemma":"perlaxo","pos":"v.","gen":"","def":"a., to relax greatly, Apic. 7, 7. perlĕcēbra (pellĕcēbra), ae, f. pellicio, an enticement, allurement (Plautin.): probri perlecebrae, Plaut. Bacch. 5, 2, 47 (ap. Ritschl as one word"},"permessus":{"lemma":"Permessus","pos":"adj.","gen":"","def":", = Περμησσός, a river in Boeotia sacred to Apollo and the Muses, which rises in Mount Helicon and flows into the Copaic lake, Verg. E. 6, 64.— Hence, Permessis, ĭdis or ĭdos, adj. f., Permessian"},"permissor":{"lemma":"permissor","pos":"adv.","gen":"-class","def":"id., a permitter (post-class.): mali, Tert. adv. Marc. 1, 22."},"permissum":{"lemma":"permissum","pos":"","gen":"","def":", v. permitto, P. a., A. permissus, a, um, Part. and P. a., from permitto."},"permissus":{"lemma":"permissus","pos":"","gen":"","def":"permitto, leave, permission, class. and freq. in abl. with gen. of person, by one's leave, etc.: permissu legis, Cic. Agr. 2, 14, 35; id. Balb. 19, 43: permissu tuo, Cic. Verr. 2, 3, 80, § 184"},"permixtim":{"lemma":"permixtim","pos":"adv.","gen":"-class","def":"permisceo, confusedly, promiscuously (post-class.), Prud. στεφ. 11, 191: exponere, Just. Inst. 2, 20, 3. permixtĭo (permistĭo), ōnis, f. id.. A mixing together"},"perna":{"lemma":"perna","pos":"","gen":"-bone","def":", = πέρνα. a haunch or ham together with the leg. Lit. Of men: is (i. e. his, militibus) pernas succidit, Enn. ap. Fest. pp. 304 and 305 (Ann. v. 279 Vahl.) (for which, in Liv. 22"},"perpenso":{"lemma":"perpenso","pos":"","gen":"-class","def":"freq. a. perpendo, to weigh carefully; trop., to ponder, consider (post-class.), Grat. Cyn. 298; Amm. 16, 4, 1"},"perpes":{"lemma":"perpes","pos":"adj.","gen":"-peto","def":"like perpetuus, from per-peto, lasting throughout, continuous, uninterrupted, continual, perpetual (anteand post-class.): perpetem pro perpetuo dixerunt poëtae"},"perplexim":{"lemma":"perplexim","pos":"adv.","gen":"","def":"perplexus, intricately, confusedly, perplexedly: utrum ego perplexim lacessam oratione ad hunc modum, an, etc., Plaut. Stich. 1, 2, 19 (76 Ritschl)"},"perplexor":{"lemma":"perplexor","pos":"v.","gen":"","def":"perplexarier; v. infra), v. dep. id., to make confusion, cause perplexity: scio, quo vos soleatis pacto perplexarier, Plaut. Aul. 2, 2, 81."},"perpressa":{"lemma":"perpressa","pos":"","gen":"","def":"21, 19, 77, § 132"},"perrepto":{"lemma":"perrepto","pos":"","gen":"","def":"freq. a. perrepo, to creep or crawl through: omnes plateas perreptavi, Plaut. Am. 4, 1, 3; so, omnes latebras, id. Rud. 1, 4, 4: perreptavi usque omne oppidum ad portam, Ter. Ad. 4, 6, 3."},"perrhaebi":{"lemma":"Perrhaebi","pos":"adj.","gen":"","def":", = Περραιβοί, a people of Thessaly about Tempe and Mount Olympus, the Perrhoebians, Liv. 33, 32; 34"},"persa":{"lemma":"Persa","pos":"","gen":"","def":", v. Persae."},"persae":{"lemma":"Persae","pos":"adj.","gen":"-class","def":", = Πέρσαι, the Persians, originally the inhabitants of the country of Persis, afterwards of the great kingdom of Persia, Plaut. Curc. 3, 1, 72; Cic. Rep. 3, 9, 15; id. Tusc. 1, 45, 108"},"perscriptor":{"lemma":"perscriptor","pos":"","gen":"","def":"id., a drawer up in writing, a writer: fenerationis, Cic. Verr. 2, 3, 72, § 168. perscriptūra, ae, f. id., a drawing up in writing, a writing (jurid. Lat.): cum testamenti faciunt perscripturam"},"persector":{"lemma":"persector","pos":"","gen":"-class","def":"freq. , to follow or pursue eagerly, to investigate (ante-class.): persectari hoc volo, Sceledre, nos nostri an alieni simus, Plaut. Mil. 2, 5, 20"},"perses":{"lemma":"Perses","pos":"adj.","gen":"","def":", = Πέρσης. A Persian"},"persis":{"lemma":"Persis","pos":"","gen":"","def":"Persae, II. A."},"persolla":{"lemma":"persolla","pos":"","gen":"","def":"dim. persona, a little mask"},"perspecto":{"lemma":"perspecto","pos":"","gen":"","def":"freq. a. id.. * To look at or behold to the end: quinquennale certamen gymnicum perspectavit, Suet. Aug. 98.— To look through, look all about: otiose perspecta aedis, ut lubet, Plaut. Most. 3, 2, 128."},"perspector":{"lemma":"perspector","pos":"","gen":"","def":"id., one who understands, a discerner (eccl. Lat.): mentis perspector Jesus, Juvenc. 2, 275 (al. prospector). perspectus, a, um, Part. and P. a., from perspicio."},"perspectus":{"lemma":"perspectus","pos":"","gen":"","def":"perspicio, a viewing thoroughly, an inspection, Luc. 8, 484 (al. prospectus). per-spĕcŭlor, ātus, 1, v. dep., to examine or explore thoroughly, to reconnoitre well: perspeculatus locorum situs"},"perspergo":{"lemma":"perspergo","pos":"v.","gen":"-spargo","def":"a. per-spargo, to besprinkle, to wet. Lit.: ligna amureā crudā perspergito, Cato, R. R. 130: unde haustā aquā templum deae perspersum est, Tac. A. 15, 44: Prusiadem urbem perspergit Hylas lacus"},"perstillo":{"lemma":"perstillo","pos":"v.","gen":"","def":"n., to leak, drip: tecta jugiter perstillantia, Vulg. Prov. 19, 13"},"pertaedesco":{"lemma":"pertaedesco","pos":"","gen":"-class","def":"inch. n. , to become disgusted or wearied with any thing (ante- and post-class.): ne pertaedescat, Cato, R. R. 156: cum jam omnes pertaeduissent, Gell. 1, 2, 6. per-taedet, taesum est"},"pertractus":{"lemma":"pertractus","pos":"","gen":"-class","def":"pertraho, delay, duration (post-class.), Tert. Orat. 5. per-trăho, xi, ctum, 3, v. a., to draw or drag, to bring or conduct forcibly to a place (not in Cic. or Caes.). Lit.: aliquem in castra, Liv. 7"},"pertrecto":{"lemma":"pertrecto","pos":"","gen":"","def":"pertracto. per-trĕmisco, ĕre, v. inch. a., to tremble greatly at, to be in great fear of (late Lat.); with acc.: manum domini, Hier. in Isa. 4, 10, 4"},"pertunda":{"lemma":"Pertunda","pos":"","gen":"","def":"pertundo, the goddess that presides over the loss of virginity, Arn. 4, 131; Tert. ad Nat. 2, 11; Aug. Civ. Dei, 6, 9. per-tundo, tŭdi, tūsum (tussum"},"peruector":{"lemma":"pervector","pos":"","gen":"-carrier","def":"id., a bringer, conveyer (late Lat.): apicum, a letter-carrier, Symm. Ep. 4, 65. pervectus, a, um, Part., from perveho. per-vĕho, xi, ctum, 3, v. a., to bear, carry"},"peruentor":{"lemma":"perventor","pos":"","gen":"-class","def":"id., a comer, arriver (post-class.), Sid. Ep. 3, 13"},"peruinca":{"lemma":"pervinca","pos":"","gen":"","def":"vinca pervinca."},"peruinco":{"lemma":"pervinco","pos":"v.","gen":"","def":"n. and a. Lit. Neutr., to conquer completely, gain a complete victory: pervicit Bardanes, Tac. A. 11, 10.— Act., to conquer or defeat completely"},"peruincus":{"lemma":"Pervincus","pos":"","gen":"","def":", i. e. Achiever, a Roman surname, Inscr. Grut. 16, 7. per-vĭo, āre, v. n., to go on, proceed, Auct. Itin. Alex. M. 104 Mai. per-vĭrens, entis, Part. , ever flourishing, ever green (post-class.)"},"peruolgo":{"lemma":"pervolgo","pos":"","gen":"","def":"pervulgo. pervŏlĭtantĭa, ae, f. pervolito, a flying around, circumvolation: mundi circa terram, Vitr. 9, 7. pervŏlĭto, āre, v. freq. n. , to fly through or around"},"pesoluta":{"lemma":"pesoluta","pos":"","gen":"","def":", an Egyptian plant used for making garlands, Plin. 21, 33, 108, § 184. pessārĭum, ii, n. 2. pessum, a pessary, Cael. Aur. Acut. 3, 18, 185"},"pessum":{"lemma":"pessum","pos":"adv.","gen":"-versum","def":"prob. contr. from pedis-versum, πέξα, πέδον, towards the feet; like susum, sursum, from sub-versum; hence, in gen., to the ground, to the bottom, down (mostly ante-class. and postAug."},"pessus":{"lemma":"pessus","pos":"","gen":"","def":"2. pessum init. pestĭbĭlis, e, adj. pestis, pestilential, destructive, noxious (post-class.): fundus, Cod. Just. 4, 58, 4. pestĭfer and (rarely, Cels. 2, 6) pes-tĭfĕrus, ĕra, ĕrum"},"pestis":{"lemma":"pestis","pos":"","gen":"-tis","def":"perh. for perd-tis, from perdo, a deadly, esp. an infectious or contagious disease, a plague, pest, pestilence; also, a noxious atmosphere, unhealthy weather (class., but rare for pestilentia"},"petra":{"lemma":"Petra","pos":"","gen":"","def":", a Roman proper name, Tac. A. 11, 4. petrăbŭlum, i, n., = πετρόβολον, a stone-thrower, catapult, Not. Tir. p. 179."},"petraeus":{"lemma":"petraeus","pos":"adj.","gen":"","def":", = πετραῖος, that grows among rocks, rock- (post-Aug.) brassica, Plin. 20, 9, 36, § 92. Pĕtraeus, a, um, v. 2. Petra, I. B. petrālis, e, adj. petra, stony (eccl. Lat.), Cassiod. in Psa. 39"},"petrenses":{"lemma":"Petrenses","pos":"","gen":"","def":", the inhabitants of the city of Petra, in Sicily, Sol. 5."},"petrensis":{"lemma":"petrensis","pos":"adj.","gen":"-class","def":"1. petra, found among rocks or stones (post-class.): pisces, Cael. Aur. Tard. 2, 1, 26. Petrĕus, a, um, adj. 1. petra or Petrus, Petrean (eccl. Lat.): istae spinae, Petra et Petro transeunte"},"petro":{"lemma":"Petro","pos":"","gen":"","def":"1. petra, a Roman surname, Suet. Vesp. 1. Petrŏcŏrĭi, ōrum, m., a Gallic tribe in Aquitania, in the mod. Périgueux, Caes. B. G. 7, 75; Plin. 4, 19, 33, § 109"},"pexsus":{"lemma":"Pexsus","pos":"","gen":"","def":""},"phacus":{"lemma":"Phacus","pos":"","gen":"","def":", = Φάκος, a fortified place near Pella in Macedonia, where the treasury of the Macedonian kings was kept, Liv. 44, 6, 2: Arx Phacus, id. 44, 46, 6. Phaeāces, um, m., = Φαίακες, the Phoeacians"},"phaedra":{"lemma":"Phaedra","pos":"","gen":"","def":", = Φαίδρα, the daughter of king Minos, of Crete, sister of Ariadne and wife of Theseus; she slew herself for hopeless love of Hippolytus, Verg. A. 6, 445; Ov. A. A. 1, 511; id. H. 4, 74"},"phaenon":{"lemma":"Phaenon","pos":"","gen":"-class","def":", = Φαίνων (shining), the planet Saturn (post-class.): quae Stilbon volvat, quae secula Phaenon, Aus. Idyll. 18, 11"},"phaestum":{"lemma":"Phaestum","pos":"adj.","gen":"-st","def":", = Φαῖστος. A town of Crete, near Cortyna, founded by Minos, Plin. 4, 12, 20, § 59.—Hence, Phae-stĭas, ădis, f., = Φαιστιάς, a female inhabitant of Phoestum, a Phoestian (poet.): inter Phaestiadas"},"phalannaeus":{"lemma":"Phalannaeus","pos":"adj.","gen":"","def":", of or belonging to Phalanna, a city of Thessaly, Phalannoean: ager, Liv. 42, 65. Phălantus, i, m., = Φάλαντος"},"phaliscus":{"lemma":"Phaliscus","pos":"","gen":"","def":"Faliscus. phallovitrobŏlus, i, m., or -vitro-bŏlum, i, n., a drinking-vessel shaped like a phallus, Capitol. Pertin. 8, 5 dub. (Momms. vitro, fundibuli)."},"phallus":{"lemma":"phallus","pos":"","gen":"","def":", = φαλλός, a figure of an obscene shape, carried about at the festival of Bacchus, originally a symbol of the generative power of nature; a phallus, Arn. 5, 176"},"phantasma":{"lemma":"phantasma","pos":"adv.","gen":"","def":", = φάντασμα. An apparition, spectre, phantom (postAug."},"pharnuprium":{"lemma":"pharnuprium","pos":"","gen":"","def":", a kind of figwine, Plin. 14, 16, 19, § 102 Jan. Phăros, i, v. Pharus. Pharsālos or Pharsālus, i, f., = Φάρσαλος, a city in Thessaly, where Coesar defeated Pompey, now Fersala, Liv. 32, 33; 34, 23"},"phase":{"lemma":"Phase","pos":"","gen":"-born","def":"indecl., the Passover, a Jewish feast commemorative of the rescue of the first-born among the Jews from the destruction which visited the Egyptians: est enim Phase (id est transitus) Domini"},"phasma":{"lemma":"phasma","pos":"","gen":"","def":", = φάσμα, an apparition, spectre, phantom. The title of a comedy of Menander"},"phatnae":{"lemma":"Phatnae","pos":"","gen":"","def":", = Φάτναι, the Cribs, the space between two stars in the constellation Cancer (pure Lat. Praesepia), Cic. Fragm. ap. Prisc. p. 1170 P. phaulĭus, a, um, adj., = φαύλιος, bad"},"phaunos":{"lemma":"phaunos","pos":"","gen":"","def":", a parasitic plant, Plin. 16, 44, 92, § 244. Phăyllēus, false reading for Phalaceus, q. v., Ov. Ib. 504. Phēgeus, i, m., = Φηγεύς, the father of Alphesiboea, Hyg. Fab. 244.—Hence, Phēgēïus, a, um"},"phellos":{"lemma":"phellos","pos":"","gen":"-tree","def":", = φέλλος, the cork-tree; transf., the part of the water-clock made from it, the cork, Vitr. 9, 8, 5. Phēmĭus, ĭi, m., = Φήμιος. A celebrated player on the cithara in Ithaca"},"philistus":{"lemma":"Philistus","pos":"","gen":"","def":", = Φίλιστος, a historian in Syracuse in the reign of the tyrant Dionysius, an imitator of Thucydides, Cic. de Or. 2, 13, 57; 2, 23, 94; id. Brut. 17, 66; id. Q. Fr. 2, 13, 4; Nep. Dion. 3, 2"},"philtrum":{"lemma":"philtrum","pos":"","gen":"-potion","def":", = φίλτρον, a love-potion, philter (poet."},"phlegra":{"lemma":"Phlegra","pos":"adj.","gen":"","def":", = Φλέγρα, a country of Macedonia, afterwards called Pallene, where the giants are fabled to have been struck with lightning when fighting with the gods, Plin. 4, 10, 17, § 36; Stat. Th. 2, 595"},"phlegraeus":{"lemma":"Phlegraeus","pos":"","gen":"","def":"Phlegra, II. Phlegraeus (-os), i, m., = Φλεγραῖος, one of the Centaurs, Ov. M. 12, 378. Phlĕgyae, ārum, m., a predatory people from Thrace or Thessaly, who destroyed the temple at Delphi, Ov. M. 11"},"phlox":{"lemma":"phlox","pos":"","gen":"","def":", = φλόξ (flame), a flower, otherwise unknown, Plin. 21, 11, 38, § 64. phŏba, ae, f., = φόβη, a corymb, Plin. 18, 7, 10, § 53"},"phoebas":{"lemma":"Phoebas","pos":"","gen":"","def":"Phoebus, C. Phoēbē, ēs, f., = Φοίβη. The moongoddess, sister of Phoebus, i. e. Diana, Luna, or the moon: vento semper rubet aurea Phoebe, Verg. G. 1, 431; id. A. 3, 371"},"phoebus":{"lemma":"Phoebus","pos":"adj.","gen":"-b","def":", = Φοῖβος (the radiant), a poetical appellation of Apollo as the god of light: quae mihi Phoebus Apollo Praedixit, Verg. A. 3, 251; Hor. C. S. 62"},"phoenissus":{"lemma":"Phoenissus","pos":"","gen":"","def":"1. Phoenice, D."},"phoenix":{"lemma":"Phoenix","pos":"","gen":"","def":"1. Phoenice, A."},"phorbas":{"lemma":"Phorbas","pos":"","gen":"","def":", = Φόρβας, the name of several mythic personages, Ov. M. 5, 74; 11, 414; 12, 322; Hyg. Fab. 14."},"phorcis":{"lemma":"Phorcis","pos":"","gen":"","def":"2. Phorcus, A. († phorcus, i, m., a false reading for porcus, Plin. 32, 11, 53, § 150.) Phorcus, i (also Phorcys, yos, and Phorcyn, ȳnos, acc. to Prisc. p. 690 P., but acc. to Serv., Verg. A. 5, 240"},"phradmon":{"lemma":"Phradmon","pos":"","gen":"","def":", a celebrated statuary of Argos, Plin. 34, 8, 19, § 49."},"phragandae":{"lemma":"Phragandae","pos":"","gen":"","def":", a city in Thrace, Liv. 26, 25. phragmītes, is, m., = φραγμίτης, a kind of reed growing in hedges, Plin. 32, 10, 52, § 141. Phrăhātes, is, v. Phraates. phrăsis, is, f., = φράσις, in rhetoric"},"phryx":{"lemma":"Phryx","pos":"","gen":"","def":", = Φρύξ, a river in Ionia, rising in Lydia, and falling into the Hermus, otherwise called Hyllus, Plin. 5, 29, 31, § 119; oftener, Phrygius amnis, Liv. 37, 37, 9; 37, 38, 2"},"phryxus":{"lemma":"Phryxus","pos":"","gen":"","def":"Phrixus init."},"phthas":{"lemma":"Phthas","pos":"","gen":"","def":", = Φθάς, the Egyplian Vulcan: secundus Vulcanus Nilo natus, Phthas, ut Aegyptii appellant, Cic. N. D. 3, 22, 55. Phthīa, ae, f., = Φθία, a city in Thessaliotis, the birthplace of Achilles, Mel. 2, 3"},"phthongus":{"lemma":"phthongus","pos":"","gen":"","def":", = φθόγγος, a sound, tone: Saturnum dicebat Dorico moveri phthongo, Jovem Phrygio, Plin. 2, 22, 20, § 84; Fulg. Myth. 3, 2 sq."},"phy":{"lemma":"phy","pos":"interj.","gen":"","def":", pish! tush! Ter. Ad. 3, 3, 58"},"phylarchus":{"lemma":"phylarchus","pos":"","gen":"","def":", = φύλαρχος, the chief of a tribe, a prince, emir: phylarchus Arabum, Cic. Fam. 15, 1, 2: Saracenorum, Amm. 24, 2; Sex. Ruf. Brev. 14. Phȳlē, ēs, f., = Φυλή, a castle in Attica, Nep. Thras. 2, 1"},"phyllanthes":{"lemma":"phyllanthes","pos":"","gen":"","def":", = φυλλανθές, a plant with prickly leaves, Plin. 21, 16, 59, § 99. Phyllēis, ĭdis, adj. f., = Φυλληίς, of or from the city of Phyllus, in Thessaly: matres Phylleides, i. e. Thessalian, Ov. H. 13"},"phyllis":{"lemma":"Phyllis","pos":"","gen":"-tree","def":", = Φυλλίς. Daughter of King Sithon of Thrace; she was changed into an almond-tree, Ov. H. 2, 98; Hyg. Fab. 59, 243; Plin. 16, 26, 45, § 108; Serv. Verg. E. 5, 10"},"phyllon":{"lemma":"phyllon","pos":"","gen":"","def":", = φύλλον, a plant, called also leucacantha, Plin. 22, 16, 18, § 40."},"phyllos":{"lemma":"Phyllos","pos":"","gen":"","def":", a region in Arcadia, Stat. Th. 4, 45. phȳma, ătis, n., = φῦμα, a kind of boil or tumor, Cels. 5, 28; 5, 18, 23; 33."},"phynon":{"lemma":"phynon","pos":"","gen":"-salve","def":", a kind of eye-salve, Cels. 6, 6, 20. phȳrāma, ătis, n., = φύραμα, the gum of the tree called metops, Plin. 12, 23, 49, § 107."},"physcon":{"lemma":"Physcon","pos":"","gen":"-belly","def":", = Φύσκων (Pot-belly, Fat-paunch), an epithet of Ptolemy Euergetes II. of Egypt, Just. 38, 8; Tert. Pall. 4. phȳsēma, ătis, n., = φύσημα (a bladder"},"physis":{"lemma":"physis","pos":"","gen":"","def":", = φύσις, nature. Lit.: seu cupis genitor vocari et auctor orbis aut physis ipsa Panque, Poët. in Anth. Lat. t. 2, p. 474 Burm.— In partic."},"phyteuma":{"lemma":"phyteuma","pos":"","gen":"","def":", = φύτευμα, groundsel, Plin. 27, 12, 99, § 125. pĭābĭlis, e, adj. pio, that may be expiated, expiable: piabile fulmen, Ov. F. 3, 289. pĭācŭlāris, e, adj. piaculum, atoning, expiatory, piacular (rare"},"picra":{"lemma":"picra","pos":"","gen":"","def":", prob. a medicine made of aloes: picrae solutio, Theod. Prisc. 1, 19. picrĭdĭae, ārum, f., bitter salad, Aug. Serm. ad Catechum. de Cataclysm. 4 fin."},"picris":{"lemma":"picris","pos":"","gen":"","def":", = πικρίς. Bitter lettuce, a kind of salad (in Greek letters, Plin. 19, 8, 38, § 126).— A plant that blooms all the year round, Plin. 21, 17, 65, § 105. pictăcĭum, i, n., i. q. pittacium"},"picti":{"lemma":"Picti","pos":"","gen":"","def":"pingo, the painted people, a people of Britain, the Picts or ancient Caledonians (so named from their practice of tattooing themselves), Amm. 20, 1, 1; Claud. III. Cons. Hon. 54"},"pictor":{"lemma":"pictor","pos":"","gen":"","def":"pingo. A painter, Cic. Ac. 2, 7, 20; Cic. Verr. 2, 4, 13, § 30; Hor. A. P. 9; Plin. 35, 8, 34, § 53 sq.; Juv. 3, 76; 12, 28.— Transf., an embroiderer, Coripp. Laud. Just. 2, 280."},"pigmentum":{"lemma":"pigmentum","pos":"","gen":"-class","def":"pingo, a material for coloring, a color, paint, pigment. Lit. For painting, a paint: aspersa temere pigmenta in tabulā, oris lineamenta efficere possunt, Cic. Div. 1, 13"},"pilastilus":{"lemma":"pilastilus","pos":"","gen":"","def":", perh. a javelinmaker, Inscr. Murat. 538. pilates or pellates, only in nom. , a kind of stone: lapidis genus, cujus meminit Cato originum l. V.: lapis candidior quam pilates"},"pincerna":{"lemma":"pincerna","pos":"","gen":"-class","def":", = πιγκέρνης (v. Du Cange, Gloss. Graec. s. h. v.; prop. one who mixes drinks; hence, in gen.), a cupbearer, butler (post-class.), Ascon. Cic. Verr. 2, 1, 26; Lampr. Alex. Sev. 41"},"pingo":{"lemma":"pingo","pos":"v.","gen":"","def":"a., to represent pictorially with the pencil or needle, to paint, embroider (cf.: depingo, delineo, adumbro). Lit.: quas (comas) Dione Pingitur sustinuisse manu, is represented in painting, Ov. Am. 1"},"pinguesco":{"lemma":"pinguesco","pos":"","gen":"","def":"inch. n. , to become or grow fat. Lit.: emaciatum armentum medicā (herbā) pinguescit, Col. 2, 11, 2: attilus (piscis) in Pado inertiā pinguescens, Plin. 9, 15, 17, § 44"},"pinguis":{"lemma":"pinguis","pos":"adj.","gen":"","def":"root pag-, pak-, of pango, q. v.; cf. Gr. παχύς, stout, = πίων, fat (opp. macer"},"pinna":{"lemma":"pinna","pos":"","gen":"","def":", v. penna. pinna, a kind of mussel; prop. pīnă, q. v. pinnācŭlum, i, n. 1. pinna, a peak, pinnacle of a building (late Lat.), Tert. adv. Jud. 8"},"pinsor":{"lemma":"pinsor","pos":"","gen":"","def":"pinso, for pistor, a baker, Varr. ap. Non. 152, 14. pinsus, a, um, Part., from pinso. pīnus, ūs and i (dat. pinu, Prop. 3, 19, 19; abl. sing. only pinu"},"pisaurum":{"lemma":"Pisaurum","pos":"adj.","gen":"","def":". a city of Umbria, at the mouth of the Pisaurus, the mod. Pesaro, Mel. 2, 4, 5; Liv. 39, 44; Vell. 1, 15, 2; Caes. B. C. 1, 11 sq.; Cic. Fam. 16, 12, 2"},"piscis":{"lemma":"piscis","pos":"","gen":"","def":"etym. dub.; cf. Angl. -Sax. fisk, Germ. Fisch, a fish. Lit.: ubi lanigerum pecus piscibus pascit, Enn. ap. Paul. ex Fest. s. v. cyprio, p. 59 Müll. (Sat. v. 42 Vahl.)"},"piscor":{"lemma":"piscor","pos":"v.","gen":"","def":"dep. n. , to fish: ut ante suos hortulos piscarentur, Cic. Off. 3, 14, 58: piscemur, venemur, Hor. Ep. 1, 6, 57: animi laxandi causā piscabatur hamo, Suet. Aug. 83: piscatus est rete aurato"},"pissasphaltus":{"lemma":"pissasphaltus","pos":"","gen":"-pitch","def":", = πισσάσφαλτος, earth-pitch, pissasphalt (a kind of soft bitumen), Plin. 24, 7, 25, § 41"},"pistillum":{"lemma":"pistillum","pos":"","gen":"","def":", and pistillus, i, m., a pounder, pestle of a mortar, Plaut. Aul. 1, 2, 17: semen sinapis in mortarium conicito et pistillis conterito, Col. 12, 55"},"pisto":{"lemma":"pisto","pos":"","gen":"","def":"freq. a. piso, pinso, to pound (late Lat.), Veg. Vet. 1, 32: herba senecion pistatā cum axungiā, App. Herb. 75. pistŏlŏchĭa, v. plistolochia."},"pistor":{"lemma":"pistor","pos":"","gen":"-mill","def":"pinso; root in Sanscr. pish-, to crush"},"pistrilla":{"lemma":"pistrilla","pos":"","gen":"-mill","def":"dim. pistrina, a little pounding-mill, Ter. Ad. 4, 2, 45. pistrīna, ae, f. pistor, a bakehouse, bakery, Plin. 18, 9, 20, § 86; 19, 8, 52, § 167; Varr. L. L. 5, 31, 138"},"pistrix":{"lemma":"pistrix","pos":"","gen":"","def":"pistor, a woman who pounds corn"},"pitydion":{"lemma":"pitydion","pos":"","gen":"","def":", a reading in Plin. 15, 10, 9, § 36"},"pix":{"lemma":"pix","pos":"","gen":"","def":"akin to Gr. πικρός, bitter, πίτυς, pine; cf. πεύκη, = πίσσα, pitch: picem meminisse debemus non aliud esse quam combustae resinae fluxum, Plin. 23, 1, 24, § 47"},"planca":{"lemma":"planca","pos":"","gen":"","def":"root πλακ-"},"planctus":{"lemma":"planctus","pos":"","gen":"","def":"plango. In gen., a striking or beating accompanied by a loud noise, a banging, rustling, roaring (postAug. and mostly poet.): unum omnes incessere planctibus, of the flappings of the Harpies' wings"},"plancus":{"lemma":"plancus","pos":"","gen":"","def":", = πλάγκος, a kind of eagle, Plin. 10, 3, 3, § 7."},"plango":{"lemma":"plango","pos":"v.","gen":"","def":"a. from the root ΠΛΑΓ, πλήσσω; cf. Lat. plāga, to strike, beat, esp. with a noise. In gen. (poet.; cf. plaudo): fluctus plangentes saxa, Lucr. 2, 1155"},"plangor":{"lemma":"plangor","pos":"","gen":"","def":"plango, a striking, beating, attended with noise. In gen. (poet.): (undae) leni resonant plangore cachinni, Cat. 64, 272: feminis, Auct. Her. 3, 15"},"planta":{"lemma":"planta","pos":"","gen":"","def":"for plancta; cf. plānus"},"planto":{"lemma":"planto","pos":"v.","gen":"","def":"a. planta. To set, plant, transplant (cf. sero): hoc modo plantantur punicae, Plin. 17, 10, 13, § 67"},"plasma":{"lemma":"plasma","pos":"","gen":"-class","def":", = πλάσμα, something formed or moulded. Lit., an image, figure, a creature (eccl. Lat.): emancipator servientis plasmatis, Prud. Cath. 7, 184.— Transf."},"plasmo":{"lemma":"plasmo","pos":"v.","gen":"","def":"a. plasma, to form, mould, fashion (eccl. Lat.): corporis effigiem, Prud. Apoth. 933: homo plasmatus, Tert. adv. Jud. 13 med.: me, Vulg. Psa. 118, 73: aestatem, id. ib. 73, 17."},"plasso":{"lemma":"plasso","pos":"v.","gen":"-class","def":"a., = πλάσσω = plasmo, to form, mould, shape (post-class.), Apic. 2, 1."},"plastes":{"lemma":"plastes","pos":"","gen":"","def":", = πλάστης, a moulder, potter, modeller, statuary (post-Aug.; syn. fictor), Vell. 1, 17, 4: laudatissimi, Plin. 35, 12, 45, § 154; Vitr. 1, 1, 13; Tert. Idol. 3"},"plastus":{"lemma":"plastus","pos":"adj.","gen":"","def":", = πλαστός (formed)"},"plaustra":{"lemma":"plaustra","pos":"","gen":"","def":"plaustrum. plaustrārĭus (plostr-), a, um, adj. plaustrum, plostrum, of or belonging to a wagon, wagon-: asini, Cato, R. R. 11, 1: juga duo, id. ib. 2.— Subst.: plau-strārĭus (plostr-), ii"},"plaustrix":{"lemma":"plaustrix","pos":"","gen":"","def":"plausor, a female applauder, acc. to Non. 150, 29. plaustrum (plostrum, Cato, R. R. 2, 10; 62; Varr. R. R. 1, 22, 3; cf. Suet. Vesp. 22: plaustra, ae, f., v. infra), i, n. Sanscr. plavas, ship"},"plausus":{"lemma":"plausus","pos":"","gen":"","def":"3. plausus init. plausus (plōsus, Macr. S. 6, 1), ūs (a later collat. form, plausus, i, Cod. Th. 15, 9, 2), m. plaudo, a clapping sound"},"plautus":{"lemma":"Plautus","pos":"adj.","gen":"-foot","def":"flat-foot, v. 1. plautus, an Umbrian surname.—So, T. Maccius (or Maccus) Plautus, a celebrated Roman comic poet, a native of the Umbrian village Sarsina.—(On the name Maccius"},"plecta":{"lemma":"plecta","pos":"","gen":"","def":"1. plecto, archit. t. t., a border of interwoven lines in relief, Vulg. 3 Reg. 7, 29. plectĭbĭlis, e, adj. 2. plecto. Pass., deserving punishment (post-class.): invidia, Sid. Ep. 4, 6: usurpatio"},"plestina":{"lemma":"Plestina","pos":"","gen":"","def":", a town of the Marsi, Liv. 10, 3, 5. plētūra, ae, f. pleo. Lit., fulness, a filling (post-class.), Paul. Nol. Carm. 21, 47.— Transf., fulness of blood, excess of blood, plethora (post-class.)"},"pleuron":{"lemma":"Pleuron","pos":"adj.","gen":"","def":", = Πλευρών, a city in Aetolia, now Castle of Irene, Plin. 4, 2, 3, § 6; Stat. Th. 2, 727"},"plexippus":{"lemma":"Plexippus","pos":"","gen":"","def":", = Πλήξιππος. One of the fifty sons of Aegyptus, Hyg. Fab. 170.— A son of Thestius, Hyg. Fab. 173. plexus, a, um, Part. and P. a., from 1. plecto."},"plexus":{"lemma":"plexus","pos":"","gen":"","def":"1. plecto, a twining, plaiting, braid (poet.), Manil. 5, 147 dub. (al. flexum, fluctum). Plias and Pliades, v. Pleias. plĭcātĭlis, e, adj. plico, that may be folded together or doubled up, flexible"},"plinthis":{"lemma":"plinthis","pos":"","gen":"-surveying","def":", = πλινθίς (a square tile). A square; in architect., a square base, a plinth, for plinthus, Vitr. 3, 3, 2"},"plitendum":{"lemma":"Plitendum","pos":"","gen":"","def":", a town of Asia, Liv. 38, 18, 3. plŏcē, ēs, f., = πλοκή. In rhetoric, a repeating of the same word with a different meaning, Mart. Cap. 5, § 532"},"plostellum":{"lemma":"plostellum","pos":"","gen":"","def":"dim. plostrum, plaustrum, a small wagon or cart: plostellum Poenicum, Varr. R. R. 1, 52: plostello adjungere mures, Hor. S. 2, 3, 247; Aug. Civ. Dei, 7, 21. plostrārĭus, a, um, v. plaustrarius."},"plostrum":{"lemma":"plostrum","pos":"","gen":"","def":"plaustrum. plōsus, v. plausus. Plōtae, ārum, f., an ancient name of the Strophades, Mel. 2, 7"},"plumbo":{"lemma":"plumbo","pos":"v.","gen":"-class","def":"a. id.. To lead, to solder with lead (ante-class. and post-Aug.): modiolos indet et plumbet, Cato, R. R. 21: argentum, Plin. 34, 17, 48, § 161: scyphum alieno plumbo, Dig. 41, 1"},"plumbum":{"lemma":"plumbum","pos":"n. n.","gen":"-i","def":"lead (the metal); lead pipe; a leaden bullet; black lead (graphite)"},"poeni":{"lemma":"Poeni","pos":"adj.","gen":"-cus","def":", the Phoenicians, i. e. the Carthaginians (descended from the Phoenicians): Poeni stipendia pendunt, Enn. ap. Varr. L. L. 5, § 182 Müll. (Ann. v. 269 Vahl.)"},"poenus":{"lemma":"Poenus","pos":"","gen":"","def":"Poeni."},"poetneum":{"lemma":"Poetneum","pos":"","gen":"","def":", a fortress of Athamania, Liv. 39, 25. pŏēto, āre, v poëtor. pŏētor, āri, v. dep. poëta, to be a poet, to write poetry, to poetize (ante- and postclass.): numquam poëtor nisi si podager"},"pogonus":{"lemma":"Pogonus","pos":"","gen":"","def":", a harbor in Argolis, Mel. 2, 3."},"pol":{"lemma":"pol","pos":"interj.","gen":"","def":", v. Pollux."},"pola":{"lemma":"Pola","pos":"","gen":"","def":", a maritime town of Istria, Mel. 2, 3"},"polla":{"lemma":"Polla","pos":"","gen":"","def":"another form for Paulla, Paula, a female proper name. The wife of D. Brutus, Cic. Fam. 11, 8, 1.— The wife of the poet Lucan, Stat. S. 2, 7, 62; 82; Mart. 7, 21, 2; 7, 23, 3; 10, 64, 1."},"pollen":{"lemma":"pollen","pos":"","gen":"","def":", and pollis, ĭnis, m. and f . Lit., fine flour, milldust, Cato, R. R. 156; 157; Plin. 13, 12, 26, § 82; 18, 9, 20, § 87"},"pollenter":{"lemma":"pollenter","pos":"adv.","gen":"","def":", v. polleo, P. a. fin. pollentĭa, ae, f. polleo, might, power (ante-class.): impiorum, Plaut. Rud. 3, 2, 4"},"pollex":{"lemma":"pollex","pos":"adv.","gen":"-branch","def":"polleo"},"pollingo":{"lemma":"pollingo","pos":"v.","gen":"-class","def":"a., to wash a corpse, and prepare it for the funeral pile (ante- and post-class.): pollingo, περιστέλλω νεκρόν, σιροπλόκω, ταριχεύω, ἐνταφιάζω, Gloss. Philox.: quia mihi pollinctor dixit"},"pollis":{"lemma":"pollis","pos":"","gen":"","def":"pollen. pollūbrum (pōlūbr-), i, n. polluo, a wash-basin, laver: polubrum pelluvium vas, quod nos pelvem vocamus, Paul. ex Fest. p. 247 Müll.: polubrum quod Graeci χέρνιβα"},"polusca":{"lemma":"Polusca","pos":"","gen":"","def":", a small and very ancient town in Latium, Liv. 2, 33; 39"},"pompa":{"lemma":"pompa","pos":"","gen":"","def":", = πομπή, a solemn procession, a public procession of any kind (at public festivals, games, triumphs, marriages, funerals, etc.). Lit. In gen.: in pompā cum magna vis auri argentique ferretur"},"pompo":{"lemma":"pompo","pos":"v.","gen":"-class","def":", ātum, 1, v. a., to make or do any thing with pomp (post-class.): grandisonis pompare modis, Sedul. 1, 2.— Hence, pompātus, a, um, P. a., magnificently ordered, pompous"},"pondo":{"lemma":"pondo","pos":"adv.","gen":"","def":"abl. from pondus, by weight, in weight. In gen.: neque piscium ullam unciam hodie pondo cepi, an ounce weight, Plaut. Rud. 4, 2, 8: ut exercitus coronam auream dictatori libram pondo decreverit"},"pondus":{"lemma":"pondus","pos":"","gen":"","def":"pendo, a weight. Lit. In gen., a weight used in a scale, Cic. Tusc. 5, 24, 69: pondera ab Gallis allata iniqua, Liv. 5, 48 fin.: utuntur taleis ferreis ad certum pondus examinatis pro numo"},"pons":{"lemma":"pons","pos":"","gen":"","def":"kindred with Sanscr. pathi, a path; Gr. πάτος; old Germ. phat, pfat; mod. Germ. Pfad; Angl.-Sax. padh"},"pontia":{"lemma":"Pontia","pos":"","gen":"","def":", = Ποντία, an island in the Tuscan Sea, now Ponza, Suet. Tib. 54. —Plur.: Pontiae, ārum, the group of little islands which includes Ponza, Liv. 9, 28; Mel. 2, 7; Plin. 3, 6, 12, § 81"},"ponto":{"lemma":"ponto","pos":"","gen":"","def":"1. pons. A kind of Gallic transport, a punt, Caes. B. C. 3, 29.— A floating bridge, a pontoon, Aus. Idyll. 12, 10; Dig. 8, 3, 38"},"pontus":{"lemma":"pontus","pos":"","gen":"-wave","def":", = πόντος. Lit., the sea (poet. for mare): mulserat huc navem pontus, Enn. ap. Prisc. p. 870 P. (Ann. v. 257 Vahl.): placidus, Lucr. 2, 559: pontus Libyae, Verg. A. 1"},"poppaeus":{"lemma":"Poppaeus","pos":"adj.","gen":"-nus","def":"; Poppaea, ae, f., the name of a Roman gens. Masc., Poppaeus Sabinus, Tac. A. 1, 80; 4, 46; 5, 10; 6, 39: Poppaeus Silvanus, id. H. 2, 86"},"poppysma":{"lemma":"poppysma","pos":"","gen":"-mus","def":", and poppys-mus, i, m., = πόππυσμα and ποππυσμός, a smacking or clucking with the tongue, as a sign of approbation, Juv. 6, 584"},"poppysmus":{"lemma":"poppysmus","pos":"","gen":"","def":"poppysma. poppȳzon, ontis, m., = ποππύζων, one who clucks with the tongue: cum pingeret poppyzonta retinentem equum, Plin. 35, 10, 36, § 104. pŏpŭlābĭlis, e, adj. populor"},"por":{"lemma":"por","pos":"","gen":"","def":"e. servus; e. g. Marcipor, Lucipor, etc., i. e. servus Marci, etc., Prisc. 6.—Thus also pora for puera, i. e. serva, Inscr. Rein. Class. 17, n. 180."},"porca":{"lemma":"porca","pos":"","gen":"","def":"porcus, a female swine, a sow, Cato, R. R. 134; Pall. 3, 26.— By poet. license for a male swine, a boar, Verg. A. 8, 641 Serv.; cf. Quint. 8, 3, 19: tenera, Juv. 2, 86."},"porcastrum":{"lemma":"porcastrum","pos":"","gen":"","def":", a plant, also called portulaca, purslain, App. Herb. 103."},"porcella":{"lemma":"porcella","pos":"","gen":"","def":"dim. porcula, a little female pig, Plaut. Mil. 4, 2, 68"},"porcellus":{"lemma":"porcellus","pos":"","gen":"","def":"dim. porculus, a little pig, Varr. R. R. 2, 4, 14; Suet. Ner. 33"},"porcius":{"lemma":"Porcius","pos":"adj.","gen":"","def":""},"porcus":{"lemma":"porcus","pos":"","gen":"-hog","def":"cf. Gr. πόρκος, Varr. L. L. 5, § 97 Müll."},"porgo":{"lemma":"porgo","pos":"","gen":"","def":"porrigo init. porphyrētĭcus, a, um, adj. πορφύρα, purple-red, porphyretic: marmor, Suet. Ner. 50: saxa, Lampr. Elag. 24: porticus, Vop. Prob. 2: columnae, Capitol. in Anton. Pio, 11: tabulae"},"porrixo":{"lemma":"porrixo","pos":"","gen":"","def":"freq. a. 1. porrigo, to stretch out strongly, App. M. Fragm. p. 717 Oud."},"porro":{"lemma":"porro","pos":"adv.","gen":"","def":"root pra-; Sanscr. prathamus, primus; Lat. prae, pro, prior"},"porrum":{"lemma":"porrum","pos":"","gen":"","def":", and porrus, i, m. πράσον, a leek, scallion; of two kinds, capitatum and sectile, the latter our chives, Col. 8, 11, 14; Plin. 19, 6, 33, § 108; Mart. 3, 47, 8; 3, 13, 18; 19; Juv. 3, 293"},"porta":{"lemma":"porta","pos":"","gen":"-perior","def":"Gell. ap. Charis. p. 40 P.), f. from root par-, to pierce, pass through; Gr. περάω, πείρω, πόρος, ford"},"portella":{"lemma":"portella","pos":"","gen":"","def":"dim. porta, a small door: portella, ῥυμοπύλιον, παραπύλιον, Gloss. Lat. Gr."},"portendo":{"lemma":"portendo","pos":"v.","gen":"","def":"pres. portendier, Plaut. Poen. 3, 5, 4), v. a. an archaic collat. form in relig. lang. of protendo, to stretch forth, to point out, indicate (future events, misfortunes, etc.), to foretell, predict"},"portentum":{"lemma":"portentum","pos":"","gen":"","def":"portendo fin. portentus, a, um, Part., from portendo. Porthmeus (dissyl.), ĕi and ĕos, m., = Πορθμεύς, the ferryman, a name given to Charon (poet.): navita Porthmeus, Petr. 121.—Acc. Porthmea, Juv. 3"},"porthmos":{"lemma":"porthmos","pos":"","gen":"","def":",= πορθμός, a strait (pure Lat. fretum), Plin. 3, 5, 10, § 74."},"porto":{"lemma":"porto","pos":"","gen":"-to","def":"freq. a. root porfor for-to, kindr. with fer-o; Sanscr. vhri, ferre, to bear or carry along; to convey any thing heavy (class."},"portus":{"lemma":"portus","pos":"","gen":"-duty","def":"sing. porti, Turp. ap. Non. 491, 20: dat. plur. portibus, Liv. 27, 30, 7 et saep.; a better form than portubus), m. por, whence porto, portitor.—Prop., an entrance"},"posca":{"lemma":"Posca","pos":"","gen":"","def":", a Roman surname: M. Pinarius Posca, Liv. 40, 18."},"poscaenium":{"lemma":"poscaenium","pos":"","gen":"","def":"postscaenium. poscĭnummius (-nūmius), a, um, adj. posco-nummus, money-seeking, mercenary: oscula, App. M. 10, p. 248, 36. posco, pŏposci, 3 (old perf. peposci, Val. Antias ap. Gell. 7, 9, 9)"},"possessor":{"lemma":"possessor","pos":"","gen":"","def":"id., a possessor (class.) Lit., Cic. Phil. 5, 7, 20: bonorum, id. Quint. 8, 30: regni inertis, i. e. Pluto, Luc. 6, 779"},"possestrix":{"lemma":"possestrix","pos":"","gen":"-class","def":"possessor, she that possesses (ante-class.), Afran. ap. Non. 150, 28. possĭbĭlis, e, adj. possum, that may exist or may be done, possible (post-Aug.): melius qui tertiam partem dixerunt δυνατόν"},"possum":{"lemma":"possum","pos":"v.","gen":"-sum","def":"n. irreg. (old forms, potis sum, for possum, Plaut. Poen. 5, 2, 26; id. Curc. 5, 3, 23"},"possunt":{"lemma":"possum","pos":"v.","gen":"-sum","def":"n. irreg. (old forms, potis sum, for possum, Plaut. Poen. 5, 2, 26; id. Curc. 5, 3, 23","form_of":"possum"},"post-hac":{"lemma":"post-hac","pos":"adv.","gen":"-hac","def":", after this time, hereafter, henceforth, in future (class.): aliam posthac invenito, Plaut. Men. 4, 3, 21; id. Am. 2, 2, 165; S. C. de Bacchan.; Ter. Eun. 5, 2, 59; id. Ad. 1, 2, 55"},"post-partor":{"lemma":"post-partor","pos":"","gen":"-partor","def":", an inheritor, successor, heir (ante-class.): unde anteparta demus postpartoribus, Plaut. Truc. 1, 1, 42. post-pōno, pŏsŭi, pŏsĭtum, 3, v. a., to put after, postpone"},"postella":{"lemma":"postella","pos":"","gen":"","def":", i. q. postilena, a crupper, acc. to Isid. Orig. 20, 16. post-ĕo, īre, v. n., to go after or behind; trop., to be inferior to; with acc. (postclass.): aliquem honore, Sid. Ep. 1, 11."},"poster":{"lemma":"poster","pos":"","gen":"","def":"posterus. postergānĕus, a, um, adj. post-tergum, that is behind one's back (post-class.), Arn. 4, 130: raptus, Cael. Aur. Acut. 3, 6. postĕri, ōrum, v. posterus, I. postĕrĭor, us"},"posthinc":{"lemma":"posthinc","pos":"adv.","gen":"","def":", after this, hereafter, etc.; in Verg. A. 8, 546"},"potamo":{"lemma":"Potamo","pos":"","gen":"","def":", the secretary of the quoestor Coecilius in Sicily, Cic. Div. in Caecil. 9, 29. pŏtămŏgēton or pŏtămŏgīton, ŏnis, f., = ποταμογείτων (a neighbor of the river), a water-plant, water-milfoil, pondweed"},"potest":{"lemma":"possum","pos":"v.","gen":"-sum","def":"n. irreg. (old forms, potis sum, for possum, Plaut. Poen. 5, 2, 26; id. Curc. 5, 3, 23","form_of":"possum"},"potitus":{"lemma":"Potitus","pos":"","gen":"","def":", a Roman surname: C. Valerius Potitus, Liv. 4, 53. pōtĭuncŭla, ae, f. dim. 1. potio, a small draught or potion (post-Aug.): modica, Suet. Dom. 21: crebrae, Petr. 47. pŏtĭus, adv."},"potuit":{"lemma":"possum","pos":"v.","gen":"-sum","def":"n. irreg. (old forms, potis sum, for possum, Plaut. Poen. 5, 2, 26; id. Curc. 5, 3, 23","form_of":"possum"},"prae":{"lemma":"prae","pos":"adj.","gen":"-class","def":", and prep. with abl. [for prai, kindred with Sanscr. prefix pra-, before; Gr. πρό, πρίν, πρόσω"},"prae-aequo":{"lemma":"prae-aequo","pos":"v.","gen":"-aequo","def":"a., to make equal before, Not. Tir. p. 76. praealtē, adv., v. praealtus fin."},"prae-altus":{"lemma":"prae-altus","pos":"adj.","gen":"-altus","def":"(not in Cic. or Caes.). Verg high: praealtae rupes, Liv. 40, 58: jugum, Auct. B. Afr. 37, 3: volatus volucrum, Plin. 2, 10, 7, § 48.—Comp.: Saturni praealtius omnibus sidus, Mart. Cap. 8"},"prae-caeco":{"lemma":"prae-caeco","pos":"v.","gen":"-caeco","def":"a., to blind beforehand, Ven. Fort. v. Ger. 33."},"prae-caedo":{"lemma":"prae-caedo","pos":"","gen":"-caedo","def":"praecido init. prae-călĕfactus and prae-cal-factus, a, um, Part. , warmed very much, heated (post-class.): prae-calefacta apponere, Cael. Aur. Acut. 1, 17, 169"},"prae-caluus":{"lemma":"prae-calvus","pos":"adj.","gen":"-calvus","def":", very bald (post-Aug.): caput, Suet. Galb. 21. prae-candĭdus, a, um, adj., very white (very rare): margarita (al. percandida), Maecen. ap. Isid. Orig. 19, 32. prae-căno, ĕre (perf. praececini)"},"prae-canto":{"lemma":"prae-canto","pos":"v.","gen":"-canto","def":", ātum, 1, v. a. To foretell, prophesy (ante-class.), Lucil. ap. Non. 102, 9.— To enchant, bewitch (postAug.), Petr. 131 (for Cic. Fin. 2, 29, 94, v. praecento."},"prae-carpo":{"lemma":"prae-carpo","pos":"","gen":"-carpo","def":"praecerpo. prae-cătēchīzātus, a, um, Part. , previously instructed (eccl. Lat.): praecatechizatus a prophetis, Vulg. Interpr. Iren. 4. praecautĭo, ōnis, f. praecaveo"},"prae-celsus":{"lemma":"prae-celsus","pos":"adj.","gen":"-celsus","def":", very high or lofty (class.; poet. and late Lat.; cf.: arduus, sublimis, excelsus). Lit.: rupes, Verg. A. 3, 245"},"prae-cingo":{"lemma":"prae-cingo","pos":"v.","gen":"-cingo","def":"a., to gird about, to gird. Lit.: cincticulo praecinctus in sellā aput magistrum adsidere, Plaut. Bacch. 3, 3, 26: det tunicam locuples: ego te praecingere possum, Mart. 14, 153, 1: ilia cultro"},"prae-coepi":{"lemma":"prae-coepi","pos":"v.","gen":"-coepi","def":"a., to begin before: urbem, Auct. Itin. Alex. M. 84 Mai. praecōgĭtātĭo, ōnis, f. praecogito, a thinking or considering beforehand, forethought, precogitation (post-class.): praecogitationem"},"prae-cognosco":{"lemma":"prae-cognosco","pos":"v.","gen":"-cognosco","def":", gnĭtum, 3, v. a., to foreknow, foresee (very rare): praecognito nostro adventu, Planc. ap. Cic. Fam. 10, 15, 4: mors praecognita est, Suet. Aug. 97: Christus praecognitus ante mundi constitutionem"},"prae-con-trecto":{"lemma":"prae-con-trecto","pos":"v.","gen":"-con","def":"a. tracto, to feel or handle beforehand, i. e. in thought: praecontrectare videndo, Ov. M. 6, 478. praecŏquē, adv., and praecŏquis, e, adj., v. praecox. prae-cŏquo, xi, ctum, 3"},"prae-corrumpo":{"lemma":"prae-corrumpo","pos":"v.","gen":"-corrumpo","def":", ruptum, 3, v. a., to corrupt or bribe beforehand (Ovid.): aliquem donis, Ov. M. 14, 134: illa praecorrupta, id. ib. 9, 295."},"prae-crassus":{"lemma":"prae-crassus","pos":"adj.","gen":"-crassus","def":", very thick: cortex, Plin. 16, 8, 13, § 34. praecrĕpo, crĕpŭi, 1, v. n., to sound or resound beforehand: in domo patris praecrepuisse symphoniam, Ambros. in Psa. 118, 11, 26. prae-crūdesco, crūdui"},"prae-culco":{"lemma":"prae-culco","pos":"v.","gen":"-culco","def":"a. calco, to impress strongly or beforehand (post-class.), Tert. Monog. 10. praecultus, a, um, Part. and P. a., from praecolo. prae-cŭpĭdus, a, um, adj."},"prae-curro":{"lemma":"prae-curro","pos":"v.","gen":"-curro","def":"8, 30, 13 Weissenb.), cursum, 3, v. n. and a., to run before, hasten on before, precede (class."},"prae-damno":{"lemma":"prae-damno","pos":"v.","gen":"-damno","def":"a., to condemn beforehand, to precondemn (not in Cic. or Caes.). Lit.: praedamnatus collega, Liv. 4, 41 fin.: amicum, Suet. Aug. 56.— Trop.: spem, i. e. to give it up or renounce beforehand, Liv. 27"},"prae-densus":{"lemma":"prae-densus","pos":"adj.","gen":"-densus","def":", very thick, very dense (post-Aug.): farrago, Plin. 18, 16, 41, § 142: grana, id. 18, 7, 10, § 53: terra, id. 18, 18, 48, § 171. prae-dēsignātus, a, um, Part."},"prae-dexter":{"lemma":"prae-dexter","pos":"adj.","gen":"-dexter","def":", very skilful, Grat. Cyn. 67 (acc. to Barth, i. q. ambidexter, aequimanus). praedĭātor, ōris, m. praedium, a purchaser of mortgaged estates sold at auction, a dealer in landed estates, Cic. Att. 12"},"prae-disco":{"lemma":"prae-disco","pos":"v.","gen":"-disco","def":"a., to learn beforehand, make one's self acquainted with beforehand (rare but class.): aliquid, Cic. de Or. 1, 32, 147: ventos et varium caeli praediscere morem, Verg. G. 1"},"prae-dulcis":{"lemma":"prae-dulcis","pos":"adj.","gen":"-dulcis","def":"Lit., very sweet, luscious (perh. not ante-Aug.): mel, Plin. 13, 4, 9, § 44: ficus, id. 15, 18, 19, § 72: vina, id. 14, 6, 8, § 64: sapor, id. 12, 5, 11, § 23.—In plur. absol.: praedulcĭa, ium, n."},"prae-emptor":{"lemma":"prae-emptor","pos":"","gen":"-emptor","def":"emo, one who purchases before others, a pre-emptor: προαγοραστής, praeemptor, Gloss. Gr. Lat. prae-ĕo (sometimes written in inscrr. with one e, PRAERAT, etc.), īvi and ĭi, ĭtum, īre, v. n. and a."},"prae-formo":{"lemma":"prae-formo","pos":"v.","gen":"-formo","def":"a., to form or fashion beforehand, to instruct beforehand, to prepare, etc. (post-Aug.): his praeformat dictis, Sil. 7, 385"},"prae-fortis":{"lemma":"prae-fortis","pos":"adj.","gen":"-fortis","def":", very strong (postclass."},"prae-fringo":{"lemma":"prae-fringo","pos":"v.","gen":"-fringo","def":"a. frango, to break off before or at the end, to break to pieces, shiver (class.): ne caulis praefringatur, Cato, R. R. 33 (cited by Plin. 17, 22, 35, § 20): hastas, Liv. 8, 10"},"prae-fundo":{"lemma":"prae-fundo","pos":"v.","gen":"-fundo","def":"a., to pour out before or in addition to, to add by pouring (post-class.), Simplic. p. 87 Goes.: semine cucuminis praefuso, Cael. Aur. Tard. 5, 10, 124.— To pour upon, to wet"},"prae-fuscus":{"lemma":"prae-fuscus","pos":"adj.","gen":"-fuscus","def":", very swarthy or black, Manil. 4, 721 dub. prae-gaudĕo, ēre, to rejoice greatly"},"prae-gestio":{"lemma":"prae-gestio","pos":"v.","gen":"-gestio","def":"n., to desire greatly, to delight (rare but class.): videre, Cic. Cael. 28, 67: apisci, Cat. 64, 145: ludere, Hor. C. 2, 5, 9. praegestus, a, um, Part., from prae, gero. prae-gigno, ĕre"},"prae-grandis":{"lemma":"prae-grandis","pos":"adj.","gen":"-grandis","def":", very large, huge, colossal (ante-class. and post-Aug.). Lit.: praegrandi gradu, Pac. ap. Fest. s. v. torvitas, p. 355 Müll. (Trag. Rel. p. 67 Rib.): arbores, Plin. 13, 25, 49, § 138: aures, id. 4"},"prae-gusto":{"lemma":"prae-gusto","pos":"v.","gen":"-gusto","def":"a. To taste beforehand (poet. and in post-Aug. prose): cibos, Ov. Am. 1, 4, 33"},"prae-gypso":{"lemma":"prae-gypso","pos":"v.","gen":"-gypso","def":"a., to cover over with gypsum (post-class.): os vasculi, Cael. Aur. Tard. 3, 2. prae-hĭbĕo, ēre (old inf. praehiberier, Plaut. Am. 4, 2, 7 Fleck.), v. a. habeo (for praebeo"},"prae-infundo":{"lemma":"prae-infundo","pos":"v.","gen":"-infundo","def":"a., to pour into beforehand (post-class.), Cael. Aur. Acut. 2, 34. prae-innŭo, ĕre, v. a., to indicate beforehand, Varr. ap. Non. 91, 4 dub. (al. pertimuerint). prae-jăcĕo, ŭi, 2, v. n."},"prae-lambo":{"lemma":"prae-lambo","pos":"v.","gen":"-lambo","def":"a., to lick or taste beforehand or first (poet.). Lit.: (mus) praelambens omne, quod affert, Hor. S. 2, 6, 109.— Transf., to wash or touch lightly, to bathe gently"},"prae-largus":{"lemma":"prae-largus","pos":"adj.","gen":"-largus","def":", very copious or abundant (poet.): pulmo animae praelargus, Pers. 1, 14: dapes, Juvenc. 3, 754. prae-lassātus, a, um, Part. , wearied beforehand, Front. Strat. 2, 5. praelātĭo, ōnis, f. praefero"},"prae-lautus":{"lemma":"prae-lautus","pos":"adj.","gen":"-lautus","def":", very elegant, sumptuous, or luxurious (post-Aug.): homines, Suet. Ner. 30"},"prae-longus":{"lemma":"prae-longus","pos":"adj.","gen":"-longus","def":", very long (not in Cic. or Caes.): homo, i. e. very tall, Quint. 6, 3, 67: gladii, Liv. 22, 46: cauda, Plin. 8, 33, 51, § 121: hasta, Tac. A. 6, 3: gracilitas, Plin. 13, 4, 9, § 46.—Of time"},"prae-lustris":{"lemma":"prae-lustris","pos":"adj.","gen":"-lustris","def":"1. lustro, very illustrious or magnificent (poet.): praelustria vita, shun worldly grandeur, Ov. Tr. 3, 4, 5. prae-mācĕro, āre, v. a., to soak or steep beforehand (post-class.): mala cydonia"},"prae-mando":{"lemma":"prae-mando","pos":"v.","gen":"-mando","def":"a. To order or command beforehand"},"prae-mitto":{"lemma":"prae-mitto","pos":"v.","gen":"-mitto","def":"a., to send forward or before, to despatch in advance. Lit. (class.): a portu me praemisisti domum, Plaut. Am. 2, 1, 55: nuntium, id. Truc. 2, 4, 58: legiones in Hispaniam, Caes. B. C. 1"},"prae-moenio":{"lemma":"prae-moenio","pos":"","gen":"-moenio","def":"praemunio. prae-mŏlestĭa, ae, f., trouble beforehand, anxiety, apprehension"},"prae-mollis":{"lemma":"prae-mollis","pos":"adj.","gen":"-mollis","def":", very soft (postAug.): ova, Plin. 9, 51, 75, § 165: involucrum, id. 11, 37, 69, § 181. prae-mŏnĕo, ŭi, ĭtum, 2, v. a. In gen., to forewarn, to advise, or admonish beforehand, to remind beforehand"},"prae-narro":{"lemma":"prae-narro","pos":"v.","gen":"-narro","def":"a., to tell or relate beforehand: rem, Ter. Eun. 5, 5, 12. prae-năto, āre, v. n. To swim before or in front: praenatans musculus, Plin. 9, 62, 88, § 186: praenatante pisciculo, id. 9, 45, 68"},"prae-nosco":{"lemma":"prae-nosco","pos":"v.","gen":"-nosco","def":"a., to learn or become acquainted with beforehand, to foreknow (class.): futura, Cic. Div. 1, 38, 82; Suet. Ner. 56"},"prae-opto":{"lemma":"prae-opto","pos":"v.","gen":"-opto","def":"a., to choose or wish rather, to desire more, to prefer (class.; not in Cic.); constr. aliquid alicui, with an object-clause, or with ut: praeoptantes exsilio modicam domi fortunam, Liv. 29, 30, 12"},"prae-pando":{"lemma":"prae-pando","pos":"v.","gen":"-pando","def":"a., to open or spread before, to spread out, extend (poet. and in post-Aug. prose). Lit., Verg. Cul. 16: vestibula, Plin. 11, 24, 28, § 80.— Trop.: lumina menti alicujus, Lucr. 1"},"prae-parcus":{"lemma":"prae-parcus","pos":"adj.","gen":"-parcus","def":", very sparing, very niggardly (post-Aug.). Lit.: apes praeparcae (opp. prodigae atque edaces), Plin. 11, 19, 21, § 67.— Trop.: animus, Plin. 22, 24, 51, § 110. prae-păro, āvi, ātum, 1, v. a."},"prae-paruus":{"lemma":"prae-parvus","pos":"adj.","gen":"-parvus","def":", very small (poet.), Juvenc. 2, 819. prae-pătĭor, păti, v. dep., to suffer very much (post-class.), Cael. Aur. Acut. 2, 34 al. praepĕdīmentum, i, n. praepedio, a hinderance, impediment (ante-class.)"},"prae-pinguis":{"lemma":"prae-pinguis","pos":"adj.","gen":"-pinguis","def":", very fat (poet. and in post-Aug. prose). Lit.: sues, Plin. 8, 51, 77, § 207: solum, i. e. very rich, very fertile, Verg. A. 3, 698: ubertas, Plin. 18, 17, 45, § 162: quod praepinguis fuerit visus"},"prae-plecto":{"lemma":"prae-plecto","pos":"v.","gen":"-plecto","def":"a., to strike before, Not. Tir. p. 107.—In part. perf.: praeplexus, Not. Tir. p. 107. praepollentĭa, ae, f. prae-polleo, excellence (late Lat.), Aug. in Psa. 70, Serm. 1, 15. prae-pollĕo, ēre, v. n."},"prae-porto":{"lemma":"prae-porto","pos":"v.","gen":"-porto","def":"a., to bear or carry before (poet.): tela, Lucr. 2, 621"},"prae-possum":{"lemma":"prae-possum","pos":"v.","gen":"-possum","def":"n., to be very powerful or more powerful, to have the superiority, get the upperhand (post-Aug.): postquam Macedones praepotuere, Tac. H. 5, 8.—Hence, praepŏtens, tis (gen. plur. praepotentum"},"prae-pulcher":{"lemma":"prae-pulcher","pos":"adj.","gen":"-pulcher","def":", very beautiful (poet.), Juvenc. 1, 432."},"prae-purgo":{"lemma":"prae-purgo","pos":"v.","gen":"-purgo","def":"a., to purge or cleanse beforehand (post-class.), Cael. Aur. Tard. 1, 4, 128. praepūtĭātĭo, ōnis, f. praeputio, a retaining of the foreskin, the state of being uncircumcised"},"prae-rumpo":{"lemma":"prae-rumpo","pos":"v.","gen":"-rumpo","def":"a., to break or tear off before or in front (class.): retinacula classis, Ov. M. 14, 547: funes praerumpebantur, were broken off, Caes. B. G. 3, 14: uncus praerumpitur, Col. 3, 18, 2. — Trop."},"prae-scindo":{"lemma":"prae-scindo","pos":"v.","gen":"-scindo","def":"a., to cut off in front: inferiores sedes praescindantur, Vitr. 5, 7: vestes, Vulg. 2 Reg. 10, 4: manus, id. 2 Macc. 7, 4. prae-scĭo, īvi, ītum, 4, v. a., to know beforehand"},"prae-scisco":{"lemma":"prae-scisco","pos":"","gen":"-scisco","def":"inch. a., to find out, or learn beforehand (not in Cic. or Caes.): animos volgi, Verg. G. 4, 70: exploratam fugam, Col. 9, 9, 4: adversos subitosque motus, Amm. 20, 6, 9.—With rel.-clause, Liv. 27"},"prae-seruo":{"lemma":"prae-servo","pos":"v.","gen":"-servo","def":"a., to observe beforehand (post-class.): aliquid, Cael. Aur. Acut. 3, 8: liberum se a dominationibus, Hilar. in Psa. 118, 16, 3. praesĕs, ĭdis (gen. plur. praesidium, Flor. 2, 17, 16)"},"prae-sicco":{"lemma":"prae-sicco","pos":"v.","gen":"-sicco","def":"a., to dry beforehand (post-class.), Cael. Aur. Tard. 2, 14, 217; 4, 3, 53.—Hence, prae-siccātus, a, um, dried beforehand (post-class.): succus sole praesiccatus, App. Herb. 124."},"prae-siccus":{"lemma":"prae-siccus","pos":"adj.","gen":"-siccus","def":", very dry (post-class.): vulnera, Prud. στεφ. 5, 141. praesĭdālis or praesĭdĭālis, e, adj. praeses, of or belonging to the governor of a province, gubernatorial (postclass.): jus"},"prae-signis":{"lemma":"prae-signis","pos":"adj.","gen":"-signis","def":"signum, distinguished before or above others, remarkable, illustrious, excellent (poet.): praesignia tempora cornu, Ov. M. 15, 611: praesignis facie, id. A. A. 3, 773"},"prae-signo":{"lemma":"prae-signo","pos":"v.","gen":"-signo","def":"a., to mark before (ante-class. and post-Aug.): ad summum praesignato (al. pertundito), Cato, R. R. 154: furunculos, Plin. 28, 4, 7, § 36. prae-sĭlĭo, īre, a false reading, Plaut. Stich. 3, 2, 13"},"prae-sterno":{"lemma":"prae-sterno","pos":"v.","gen":"-sterno","def":"a., to strew or spread beforehand, to prepare (mostly anteand post-class.): eo praesternebant folia farferi (al. prosternebant), Plaut. Poen. 2, 32: altaria, to prepare, Stat. S. 3, 2"},"prae-stringo":{"lemma":"prae-stringo","pos":"v.","gen":"-stringo","def":"a., to bind fast or hard, to bind or tie up"},"prae-stultus":{"lemma":"prae-stultus","pos":"adj.","gen":"-stultus","def":", extremely foolish: praestultus, πάνυ ἀνόητος, Gloss. Cyrill. prae-stŭpesco, ĕre, v. inch. n., to be greatly astonished: ad quam fortunam ceteris praestupescentibus, Jul. Val. Rer. Gest. Alex. M. 1"},"prae-sulsus":{"lemma":"prae-sulsus","pos":"adj.","gen":"-sulsus","def":"salsus, salted very much, very salt (post-Aug.): adeps, Col. 6, 2, 7. praesultātor, ōris, m. praesulto, one who leaps or dances before others, a public dancer (only in Livy), Liv. 2, 36, 2"},"prae-sulto":{"lemma":"prae-sulto","pos":"v.","gen":"-sulto","def":"n. salto, to leap or dance before (only in Livy): praesultare hostium signis, Liv. 7, 10, 3 (cf. praesultator)."},"prae-sum":{"lemma":"prae-sum","pos":"v.","gen":"-sum","def":"n., to be before a thing"},"prae-surgo":{"lemma":"prae-surgo","pos":"v.","gen":"-surgo","def":"n., to rise beforehand (poet.), Avien. Prognost. Arat. 172."},"prae-suspecto":{"lemma":"prae-suspecto","pos":"v.","gen":"-suspecto","def":"a., to suspect beforehand, Jul. Val. Rer. Gest. Alex. M. 1, 43. praesūtus, a, um, Part., from praesuo. praetactus, a, um, Part., from praetango."},"prae-taedescit":{"lemma":"prae-taedescit","pos":"","gen":"-taedescit","def":"impers., it disgusts beforehand: praetaedescit, praetaesus, Not. Tir. p. 177. prae-taesus, a, um, feeling disgust beforehand: praetaedescit, praetaesus, Not. Tir. p. 177."},"prae-tango":{"lemma":"prae-tango","pos":"v.","gen":"-tango","def":", tactum, 3, v. a., to touch beforehand or previously (postclass.). Lit., Cael. Aur. Tard. 5, 7, 81: leviter oleo Hispano praetactus, id. ib. 4, 3, 22.— Transf., to attack"},"prae-tendo":{"lemma":"prae-tendo","pos":"v.","gen":"-tendo","def":"praetensus, Anthol. Lat. 3, 168, 5), 3, v. a., to stretch forth or forward, to extend (syn. obtendo). Lit.: praetenta Tela, stretched forth, presented, Ov. M. 8"},"prae-testor":{"lemma":"prae-testor","pos":"v.","gen":"-testor","def":"dep. a., to bear witness to beforehand (eccl. Lat.): praetestata viam vitae, Tert. Carm. adv. Marc. 3, 176. Praetetĭānus, a, um, adj., of or belonging to the Praetetii: vina, Plin. 14, 6, 8, § 61."},"prae-texo":{"lemma":"prae-texo","pos":"v.","gen":"-texo","def":"a., to weave before or in front, to fringe, edge, border. Lit. (mostly poet.): purpura saepe tuos fulgens praetexit amictus, Ov. P. 3, 8, 7: glaucas comis praetexere frondes, weave around, Val. Fl. 3"},"prae-tingo":{"lemma":"prae-tingo","pos":"v.","gen":"-tingo","def":"a., to dip in or moisten beforehand (poet. and in postclass. prose): semina practincta veneno, Ov. M. 7, 123: aqua, in quā fuerit candens ferrum praetinctum, Cael. Aur. Tard. 1, 4. prae-tondĕo"},"prae-trunco":{"lemma":"prae-trunco","pos":"v.","gen":"-trunco","def":"a., to cut off before or in front, to cut off, clip (Plautin.): collos (for colla) tergoribus, Plaut. Capt. 4, 3, 2: linguam alicui, id. Mil. 2, 3, 47. prae-tŭmĕo, ēre, 2, v. n."},"prae-uallo":{"lemma":"prae-vallo","pos":"v.","gen":"-vallo","def":"a., to fortify in front (post-class.): pontem, Auct. B. Alex. 19"},"prae-uello":{"lemma":"prae-vello","pos":"v.","gen":"-vello","def":"a., to tear away before, to tear away (ante- and post-class.), Laber. ap. Diom. p. 369 P.; Tert. adv. Gnost. 13. prae-vēlo, āre, v. a., to veil or cover over"},"prae-uernat":{"lemma":"prae-vernat","pos":"","gen":"-vernat","def":"impers., to be spring too early or before the time (postAug.): quando praevernat, when spring opens too soon, Plin. 18, 26, 65, § 239."},"prae-uerro":{"lemma":"prae-verro","pos":"v.","gen":"-verro","def":"a., to sweep or brush before (poet.): veste vias, Ov. Am. 3, 13, 24: praeverrit cauda silices (al. perverrit), Verg. M. 23. prae-verto or -vorto, ti, 3, v. a."},"prae-uincio":{"lemma":"prae-vincio","pos":"v.","gen":"-vincio","def":"a. (postclass.). Lit., to bind before or in front, to fetter: laqueo praevinctus, Gell. 15, 10, 2. — Trop.: ferinis voluptatibus praevinctus, Gell. 19, 2, 3. prae-vĭrĭdans, antis, P. a. virido"},"prae-ungo":{"lemma":"prae-ungo","pos":"v.","gen":"-ungo","def":", unctum, 3, v. a., to smear or anoint before (post-class.): praeungendum est vulnus, Theod. Prisc. 1, 19: digitus praeunctus adipe anserino, Cael. Aur. Tard. 4, 3, 45. prae-ūro, ussi, ustum, 3"},"praebenda":{"lemma":"praebenda","pos":"","gen":"","def":"praebeo, the support or allowance afforded by the State to a private person, Cassiod. Var. 5, 39. praebĕo, ŭi, ĭtum (old inf. praeberier, Plaut. Poen. 1, 1, 49"},"praecantor":{"lemma":"praecantor","pos":"","gen":"","def":"praecano, an enchanter (late Lat.), Aug. in Psa. 127, 11."},"praecantrix":{"lemma":"praecantrix","pos":"","gen":"-class","def":"praecantor, an enchantress, sorceress (ante-class.), Plaut. Mil. 3, 1, 99 (v. Ritschl ad h. l.)"},"praecentor":{"lemma":"praecentor","pos":"","gen":"-class","def":"praecino, a leader in music, precentor (post-class.): praecentor in choris, App. Mund. p. 74, 3; cf.: praecentor qui vocem praemittit (opp. succentor), Aug. Enarr. in Psa. 87"},"praecepto":{"lemma":"praecepto","pos":"","gen":"","def":"freq. a. id., to prescribe often: praeceptat, in Saliari carmine est saepe praecipit, Fest. p. 205 Müll."},"praeceptor":{"lemma":"praeceptor","pos":"","gen":"","def":"id.. One who seizes beforehand, an anticipator (postclass.): servilium praeceptor operum (al. praereptor, al. praecerptor), Paul. Nol. Ep. 23, n. 4.— A commander, ruler (postclass.), Gell. 1, 13"},"praeceptrix":{"lemma":"praeceptrix","pos":"","gen":"","def":"praeceptor, a preceptress (class.): sapientiā praeceptrice, Cic. Fin. 1, 13, 43: praeceptrix et magistra, Vitr. 10, 1."},"praeceptum":{"lemma":"praeceptum","pos":"","gen":"","def":", v. praecipio fin. praeceptus, a, um, Part., from praecipio. prae-cerpo (praecarpo, Oppius ap. Macr. S. 2, 15), psi, ptum, 3, v. a. carpo. To pluck, break off, or gather before"},"praecessor":{"lemma":"praecessor","pos":"adv.","gen":"","def":"praecedo. A predecessor (eccl. Lat.): alicujus, Tert. adv. Prax. 1"},"praecinctus":{"lemma":"praecinctus","pos":"","gen":"-class","def":"praecingo, a girding. Lit. (ante-class.): castula est palliolum praecinctui, Varr. ap. Non. 548, 30.— Transf., in gen., a dressing, dress (post-class.): in praecinctu ponens omnem decorem, Macr. S. 2"},"praecox":{"lemma":"praecox","pos":"adj.","gen":"-c","def":"praecoquo, ripe before its time, early ripe, rareripe, premature, precocious (syn. praematurus). Lit.: allium praecox, Plin. 19, 6, 34, § 112: rosa, id. 21, 4, 10, § 19: germinationes, id. 17, 2, 2"},"praecursus":{"lemma":"praecursus","pos":"","gen":"","def":"praecurro, a forerunning, coming before, anticipation (post - Aug.): Etesiarum, Plin. 16, 25, 42, § 104: praecursu quodam gloriosae passionis, Ambros. in Luc. 5, 109. prae-cŭtĭo, cussi, cussum, 3"},"praedictum":{"lemma":"praedictum","pos":"","gen":"","def":"2. praedico fin. praedictus, a, um, Part., from 2. praedico. prae-diffĭcĭlis, e, adj., very difficult (post-class.), Tert. Bapt. 2 fin. prae-dīgestus, a, um, adj. digero"},"praedo":{"lemma":"praedo","pos":"","gen":"","def":"praedor fin."},"praeductal":{"lemma":"praeductal","pos":"","gen":"","def":"praeduco, a pencil for drawing lines: praeductal, παράγραφος, Gloss. Philox. praeductōrĭus, a, um, adj. id., of or for drawing forwards: lora, traces, Cato, R. R. 135, 5. praeductus, a, um, Part."},"praedulce":{"lemma":"praedulce","pos":"adv.","gen":"","def":", v. praedulcis fin."},"praefactus":{"lemma":"praefactus","pos":"","gen":"","def":"1. praefectus. prae-fāmen, ĭnis, n. praefor, a preface (post-class.), Symm. Ep. 2, 34. praefandus, a, um, P. a. of praefor, q. v. praefascinē, adv., v. praefiscine. prae-fătīgātus, a, um, Part."},"praefectus":{"lemma":"praefectus","pos":"","gen":"","def":", v. praeficio fin. prae-fēcundus, a, um, adj., very fruitful (post-Aug.), Plin. 16, 17, 51, § 118. praefĕrĭcŭlum, i, n. praefero"},"praefoecundus":{"lemma":"praefoecundus","pos":"","gen":"","def":"praefecundus. prae-fōmento, āre, v. a., to warm or foment beforehand (post-class.): vulnera aquā gelidā, Theod. Prisc. 1, 19 med. prae-for, fātus, 1 (old imper. praefato, Cato"},"praegnas":{"lemma":"praegnas","pos":"","gen":"","def":"praegnans init. praegnātĭo, ōnis, f. praegnas, a getting with child or with young, a making pregnant"},"praegnax":{"lemma":"praegnax","pos":"adj.","gen":"","def":"praegnas, inclined to pregnancy: divitiae, Fulg. Myth. 2, 3."},"praegno":{"lemma":"praegno","pos":"v.","gen":"","def":"n., to be pregnant (late Lat.), Dracont. Carm. 10, 577.—Hence, praegnātus, Part., pregnant, Fulg. Rusp. ad Trasim. 2, 1. prae-grăcĭlis, e, adj., very slender, very lank (post-Aug.): proceritas"},"praegressus":{"lemma":"praegressus","pos":"","gen":"","def":"praegredior, a going in advance, anticipation (postclass.): anteversio et praegressus, Amm. 21, 5, 13. prae-gŭbernans, antis, Part. , steering or guiding forwards (postclass.), Sid. Ep. 5"},"praelector":{"lemma":"praelector","pos":"","gen":"-class","def":"id., one who reads an author to others and adds explanations, a prelector (post-class."},"praelongo":{"lemma":"praelongo","pos":"v.","gen":"","def":"a. praelongus, to lengthen out very much, to make very long (post-Aug.): pedum crura, Plin. 11, 2, 1, § 3."},"praelum":{"lemma":"praelum","pos":"","gen":"","def":"prelum."},"praelumbo":{"lemma":"praelumbo","pos":"v.","gen":"","def":"a. prae - lumbus, to make lame in the loins or hipshot (anteclass.), Nov. ap. Non. 156, 12. prae-lūmĭnātus, a, um, Part. , illustrated or explained before (eccl. Lat.), Tert. Res. Carn. 33. praelūsĭo"},"praemessum":{"lemma":"praemessum","pos":"","gen":"","def":"praemetium. praemĕtĭum (al. ‡ praemessum), ĭi, n. prae-metior, the offering of the firstfruits measured out beforehand for Ceres: praemetium quod praelibationis causā ante praemetitur"},"praemissa":{"lemma":"praemissa","pos":"","gen":"","def":", v. praemitto fin. praemissus, a, um, Part., from praemitto. praemistus or praemixtus, a, um, Part. , mixed beforehand (postclass.): praemixta olera, Apic. 4, 5"},"praemixtus":{"lemma":"praemixtus","pos":"","gen":"","def":"praemistus. prae-mŏdĕrans, antis, Part. , prescribing a measure (post-class.): in proelia ingredi praemoderante citharā gressibus, Gell. 1, 11, 6. prae-mŏdŭlātus, a, um, Part."},"praeneste":{"lemma":"Praeneste","pos":"adj.","gen":"-nest","def":"and f., = Πραίνεστος or Πραίνεστε, one of the most ancient and important cities of Latium, famed for the beauty of its roses, for its nuts"},"praenum":{"lemma":"praenum","pos":"","gen":"","def":"Lit., an implement for combing flax, a hatchel, Gloss. Philox. —Hence, Transf., an instrument of torture, a rack: tentare praenum, Tert. Apol. 5."},"praenunci-":{"lemma":"praenunci-","pos":"","gen":"","def":"praenunti-. prae -nuncŭpātus, a, um, Part. , named beforehand: Emmanuel prophetico ore, Prud. Cath. 7, 179. praenuntĭa, v. praenuntius. praenuntĭātĭo or praenuncĭātĭo, ōnis, f. praenuntio"},"praeostendo":{"lemma":"praeostendo","pos":"v.","gen":"-sus","def":"a., to show beforehand, display before, make clear (late. Lat.): hoc monstrare debent, hoc ostendere vel praeostendere, Aug. Civ. Dei, 21, 8, 6.—Absol.: portenta a portendendo, id est, praeostendendo"},"praepostus":{"lemma":"praepostus","pos":"","gen":"","def":"praepono init. praepŏtens, entis, P. a., from praepossum. praepŏtentĭa, ae, f. praepotens, superior power (eccl. Lat.): praepotentia Dei, Tert. adv. Marc. 2, 7: horum (regum)"},"praequam":{"lemma":"praequam","pos":"adv.","gen":"","def":", v. prae. prae-questus, a, um, Part. , complaining beforehand (poet.): multa praequestus, Ov. M. 4, 251. prae-rădĭo, āre, v. n. and a. Neutr., to beam or glitter forth (poet.): pilenta praeradiant"},"praereptor":{"lemma":"praereptor","pos":"","gen":"","def":"praeripio, one who seizes a thing before another, a forestaller (eccl. Lat.): fllius, qui ad benedictionem fratris praereptor adstiterat, Hier. Ep. 36, n. 15. praereptus, a, um, Part."},"praerupta":{"lemma":"praerupta","pos":"","gen":"","def":"praerumpo. praerupte, a false read. for praealtus, Plin. 34, 15, 43, § 149"},"praes":{"lemma":"praes","pos":"adv.","gen":"-class","def":"prae, at hand, now (ante-class.): ibi tibi parata praes est, Plaut. Pers. 2, 4, 17. praesaepe (praesēpe), is, n., and praesaepes or praesaepis, is, f."},"praesaltor":{"lemma":"praesaltor","pos":"","gen":"","def":"prae- 2. salio, he who led the dances of the Salii: praesaltor, ὁ ἐν τοῖς ἱεροῖς προορχούμενος, Vet. Gloss. prae-sānesco, sānui, 3, v. incept., to begin to heal prematurely"},"praescriptum":{"lemma":"praescriptum","pos":"","gen":"","def":", v. praescribo fin. praescriptus, a, um, Part., from praescribo."},"praescriptus":{"lemma":"praescriptus","pos":"","gen":"","def":"praescribo, a precept (eccl. Lat.), Tert. Exhort. ad Cast. 3. praesĕca or praesĭca, ae, a word assumed for the etym. of brassica, Varr. L. L. 5, § 104 Müll. prae-sĕco, cŭi, ctum, or cātum, 1, v. a."},"praesegmen":{"lemma":"praesegmen","pos":"","gen":"","def":"praeseco, a piece cut off, a paring (ante- and postclass.): tonsor omnia abstulit praesegmina, Plaut. Aul. 2, 4, 33"},"praesens":{"lemma":"praesens","pos":"","gen":"","def":"praesum fin. praesensĭo, ōnis, f. praesentio. A foreboding, presentiment (class."},"praesentisco":{"lemma":"praesentisco","pos":"","gen":"","def":"inch. a. , to begin to have a presentiment of, Ter. Heaut. 4, 5, 21, acc. to Prisc. p. 824 P. (al. persentisceres)."},"praesento":{"lemma":"praesento","pos":"v.","gen":"","def":"(praesentisse, Pac. ap. Pan. Theod. 3), ātum, 1, v. a. praesens, to place before, exhibit to view, to show, present, hold out (post-Aug.): sarcitis bubulas carnes praesentat, looks like, Plin. 37, 10"},"praesertim":{"lemma":"praesertim","pos":"adv.","gen":"-sero","def":"prae-sero"},"praespergo":{"lemma":"praespergo","pos":"","gen":"","def":"praespargo. prae-spēro, āvi, 1, v. a., to hope beforehand (eccl. Lat.): qui praenunciabatur, ille et praesperabatur, Tert. adv. Marc. 5, 17. praespĭcĭo, cĕre, v. a. prae-specio, to look at before"},"praestanter":{"lemma":"praestanter","pos":"adv.","gen":"","def":", v. 2. praesto, P. a. fin. praestantĭa, ae, f. praestans, preeminence, superiority, excellence (class.): excellentia praestantiaque animantium reliquorum, over other creatures, Cic. Off. 1, 28"},"praestat":{"lemma":"praestat","pos":"","gen":"","def":"2. praesto. praestātĭo, ōnis, f. 2. praesto. Lit., a guaranty, warranty (post-Aug.): ut ad praestationem scribant, if they pledge themselves for the truth of what they write, Sen. Brev. Vit. 13, 9"},"praestructim":{"lemma":"praestructim","pos":"adv.","gen":"","def":"praestructus, with preparation (eccl. Lat.): ut ad hominem praestructim perveniretur, Tert. Pall. 3. praestructĭo, ōnis, f. praestruo, a foundation, preparation (eccl. Lat.), Tert. adv. Marc. 4"},"praestus":{"lemma":"praestus","pos":"","gen":"","def":"1. praesto init. prae-sūdo, āre, v. n., to sweat before (poet.). Lit.: dum matutinis praesudat solibus aër, Claud. Rapt. Pros. 2, 120.— — Trop., to exert one's self beforehand, Stat. Th. 6, 4."},"praesul":{"lemma":"praesul","pos":"","gen":"-class","def":"praesilio, one who leaps or dances before others, a dancer in public, public dancer. Lit. (class.), Cic. Div. 1, 26, 55"},"praesultor":{"lemma":"praesultor","pos":"","gen":"-class","def":"praesilio, one who leaps or dances before others, a public dancer (post-class. for praesul), Lact. 2, 7, 20; Val. Max. 1, 7, 4."},"praesumptor":{"lemma":"praesumptor","pos":"","gen":"-class","def":"id.. One who takes possession beforehand, a preoccupier (post-class.), Cassiod. Var. 1, 18.— A bold, confident, reckless, or presumptuous person"},"praesumptrix":{"lemma":"praesumptrix","pos":"","gen":"","def":"id., a presumptuous person (eccl. Lat.), Petr. Chrysol. Serm. 109. praesumptŭōsē, v. praesumptiose. praesumptŭōsus, a, um, v. praesumptiosus. praesumptus (praesumtus), a, um, Part. and P. a."},"praetempto":{"lemma":"praetempto","pos":"","gen":"","def":"praetento."},"praeter":{"lemma":"praeter","pos":"adv.","gen":"-class","def":"and prep. prae, with the demonstrative suffix ter, as in inter, subter, propter, signifies motion by or past, and hence, also, beyond, or rest outside a thing. Adv., past, by"},"praeter-curro":{"lemma":"praeter-curro","pos":"v.","gen":"-curro","def":", cursum, 3, v. n. and a., to run past or by (post-class.): equis praetercurrentibus, Veg. Mil. 3, 24: praetercursā Chalcedone, Amm. 22, 9, 3. praeter-dūco, ĕre, v. a."},"praeter-lambo":{"lemma":"praeter-lambo","pos":"v.","gen":"-lambo","def":"a., to lick, bathe, or touch in passing, to flow by (post-class.): oppidum, quod Mosa fluvius praeterlambit, Amm. 17, 2, 4. praeterlātus, a, um, Part., from praeterfero. praeter-lŭens, entis, Part."},"praeter-mitto":{"lemma":"praeter-mitto","pos":"v.","gen":"-mitto","def":"a. To allow or permit to go by, to let pass (class."},"praeter-sum":{"lemma":"praeter-sum","pos":"v.","gen":"-sum","def":"n., to be out of, not present at (eccl. Lat.): ipsis rebus praetersumus, Tert. Apol. 38. praetervectĭo, ōnis, f. praeterveho, a riding, sailing, or passing by: praetervectio omnium, qui, etc."},"praeter-uerto":{"lemma":"praeter-verto","pos":"v.","gen":"-verto","def":"a., to go or pass by (post-Aug.): solem, Plin. 2, 71, 73, § 181. praeter-vŏlo, āre, v. n. and a., to fly by or past (class.). Lit.: praetervolans aquila"},"praeterpropter":{"lemma":"praeterpropter","pos":"prep.","gen":"-propter","def":"with acc. , thereabout, more or less (ante-class.), Enn., Cato, and Varr. ap. Gell. 19, 10, 10 (see the whole passage respecting the phrase, and Hand, Turs. 4, 544 sq.). praeter-quam (separate"},"praetexta":{"lemma":"praetexta","pos":"","gen":"","def":", v. praetexo fin. B. 1. praetextātus, a, um, adj. praetexta, under praetexo fin. B. 1., clothed with or wearing the toga praetexta (class.): Clodius, qui numquam antea praetextatus fuisset"},"praetextum":{"lemma":"praetextum","pos":"","gen":"","def":", v. praetexo, P. a. B. 2. praetextus, a, um, Part. and P. a., from praetexo. praetextus, ūs (but found only in abl. sing."},"praetor":{"lemma":"praetor","pos":"","gen":"","def":"for praeitor, from praeeo. Prop., a leader, head, chief, president: regio imperio duo sunto: iique praeeundo, judicando, consulendo, praetores, judices, consules appellantor, Cic. Leg. 3, 3, 8.—So"},"praeuentor":{"lemma":"praeventor","pos":"","gen":"-class","def":"id., a kind of soldiers, perh. those who began the attack (post-class.), Amm. 18, 9, 3. praeventus, a, um, Part., from praevenio. praeventus, ūs (only in abl. sing.), m. praevenio"},"praeut":{"lemma":"praeut","pos":"","gen":"","def":"prae. prae-vādo, ĕre, 3, v. n., to pass before. —Transf., to be discharged from, rid of any thing, with gen.: Quintius dictaturam properat praevadere, Sen. Brev. Vit. 17, 6. prae-vălens, entis"},"pragma":{"lemma":"pragma","pos":"","gen":"-class","def":", = πρᾶγμα, a matter, affair, business (post-class.), Jul. Vict. Art. Rhet. 3, 4. pragmătĭcārĭus, ii, m. pragmaticus, one who writes down and prepares imperial edicts, rescripts"},"pransor":{"lemma":"pransor","pos":"","gen":"-class","def":"id., one that eats breakfast, that partakes of a meal in the forenoon, a guest (ante-class.): bonum anteponam prandium pransoribus, Plaut. Men. 2, 2, 2: cum jam manus pransores lavarent"},"prendo":{"lemma":"prendo","pos":"","gen":"","def":"prehendo. prensātĭo, ōnis, f. prenso"},"prenso":{"lemma":"prenso","pos":"","gen":"","def":"prehenso. prensōrĭum, ĭi, n. prendo, a trap, mouse-trap: prensorium ίπος, Gloss. Lat. Gr. prensus, a, um, Part., from prehendo."},"presbyter":{"lemma":"presbyter","pos":"","gen":"","def":", = πρεσβύτερος. In gen., an elder (eccl. Lat.), Tert. Cor. Mil. 15.— In partic., an elder or presbyter in the Christian Church: quid facit, exceptā ordinatione, episcopus"},"pressim":{"lemma":"pressim","pos":"adv.","gen":"-class","def":"id., with pressing, by pressing to one's self (post-class.): me pressim deosculato, App. M. 2, p. 121, 32: linteolo pressim agglutinato, i. e. closely pressed, id. ib. 2, p. 128, 23. pressĭo, ōnis"},"presso":{"lemma":"presso","pos":"","gen":"","def":"freq. a. premo, to press (poet.): vomicam, Plaut. Pers. 2, 5, 11: pressatur pede pes, mucro mucrone, viro vir, Furius Antias ap. Macr. S. 6, 3: cineres ad pectora pressant, Ov. M. 8"},"pressor":{"lemma":"pressor","pos":"","gen":"","def":"premo, a kind of hunter, Isid. Orig. 10 fin. pressōrĭŏla, ae, f. id., a repository (eccl. Lat.), Caes. Reg. ad Virg. 26. pressōrĭus, a, um, adj. id.. That serves for pressing grapes, olives"},"pressus":{"lemma":"pressus","pos":"","gen":"","def":"premo, a pressing, pressure (class.). With gen. subj.: animus intentione suā depellit pressum omnem ponderum, Cic. Tusc. 2, 23, 54.— With gen. obj.: hic pressu duplici palmarum continet anguem"},"preti":{"lemma":"Preti","pos":"","gen":"","def":", a people of India, beyond the Ganges, Plin. 6, 19, 22, § 67. prĕtĭo, āre, v. a. pretium, to prize (late Lat.), Cassiod. Var. 5, 40. prĕtĭōsē, adv., v. pretiosus fin. prĕtĭōsĭtas, ātis, f. pretiosus"},"prex":{"lemma":"prex","pos":"","gen":"-class","def":"and gen. sing. not in use; dat. and acc. sing. only ante-class."},"princeps":{"lemma":"princeps","pos":"adj.","gen":"-capio","def":"and subst. comm. , first in time or order (syn. primus).—Lit., in gen.: ut quisque in fugā postremus, ita periculo princeps erat, Cic. Verr. 2, 5, 34, § 90: princeps in proelium ibat"},"priscus":{"lemma":"priscus","pos":"adj.","gen":"-cus","def":"for prius-cus, like pris-tinus for prius-tinus, and magis for magius, a comparative form, of or belonging to former times, of many years ago, old, olden, ancient, primitive"},"prisma":{"lemma":"prisma","pos":"","gen":"","def":", = πρίσμα, a geometrical figure, the prism, Mart. Cap. 6, § 722."},"prista":{"lemma":"prista","pos":"","gen":"","def":", = πρίστης, a sawyer, Plin. 34, 8, 19, § 57. pristĭnus, a, um, adj. cf. priscus, former, early, original, primitive, pristine (class.): tua pristina dignitas et gloria, Cic. Fam. 1, 5, b"},"pristis":{"lemma":"pristis","pos":"","gen":"","def":"1. pistris."},"pristix":{"lemma":"pristix","pos":"","gen":"","def":", v. 1. pistris. prĭus and prĭusquam, v. prior, adv. prīvantĭa, ĭum, n., v. privo, II. A. prīvātārĭus, a, um, adj. privatus, private (post-class.), Edict. Dioclet. p. 22. prīvātīcĭus, a, um, adj. id."},"pro-spergo":{"lemma":"pro-spergo","pos":"v.","gen":"-spergo","def":", sum, 3, v. a. spargo, to besprinkle: haustā aquā templum prospersum est, Tac. A. 15, 44. prospĕrĭtas, ātis, f. prosper, desirable condition, good fortune, success"},"pro-ut":{"lemma":"pro-ut","pos":"adv.","gen":"-ut","def":", v. 1. pro, I. prōvectĭbĭlis, e, adj. proveho, capable of progress (post-class.), Fulg. Cont. Virg. p. 747 Stav. prōvectĭo, ōnis, f. id., an advancement, promotion (post - class.): dignitatis"},"probrus":{"lemma":"probrus","pos":"adj.","gen":"","def":"probrum, disgraceful, ignominious, infamous: animalia spurca atque probra, Gell. 9, 2, 9. prŏbus, a, um, adj. Sanscr. prabhus, prominent, strong, from pra (v. pro) and bhu = fio, good, proper"},"procilla":{"lemma":"Procilla","pos":"","gen":"","def":", or Julia Procilla, the mother of Agricola, Tac. Agr. 1. prōcinctŭālis, e, adj. procinctus. of or belonging to the setting out of an army (late Lat.): ornatus, Cassiod. Var. 6, 22. prōcinctus, a, um"},"procles":{"lemma":"Procles","pos":"","gen":"","def":", = Προκλῆς, the twinbrother of Eurysthenes, king of the Lacedoemonians, Cic. Div. 2, 43, 90"},"procris":{"lemma":"Procris","pos":"","gen":"","def":", = Πρόκρις, a daughter of the Athenian king Erechtheus, wife of Cephalus, who shot her in a wood, mistaking her for a wild beast, Ov. M. 7, 707 sq., and 795 sq.; id. A. A. 3, 727"},"proetus":{"lemma":"Proetus","pos":"","gen":"","def":", = Προῖτος, a king of Tiryns, brother of Acrisius, Ov. M. 5, 238 sq. —Proetĭdes, um, f., = Προιτιδες, his daughters, who being punished with madness by Juno for their pride"},"progesto":{"lemma":"progesto","pos":"","gen":"-class","def":"freq. a. progero, to carry before one (post-class.): nucleos, App. M. 6, p. 185, 23. prō-gigno, gĕnŭi, gĕnĭtum, 3, v. a., to beget, bear, bring forth"},"proh":{"lemma":"proh","pos":"interj.","gen":"","def":", v. 2. pro. prŏ-hĭbĕo, ŭi, ĭtum, 2 (old forms, prohibessis, Cato, R. R. 141, 2"},"prolicito":{"lemma":"prolicito","pos":"","gen":"","def":"‡ procitare. prō-līmen, ĭnis, n., a space before the threshold, Hier. in Ezech. 12, 40, 8 prō-lĭquātus, a, um, Part. , liquefied, liquid, App. Mag. p. 283, 39. prōlixē, adv."},"prolongo":{"lemma":"prolongo","pos":"","gen":"-longus","def":", to lengthen, prolong, extend (late Lat. for prorogo, profero, duco): dies, Vulg. Deut. 6, 2: iniquitatem suam, id. Psa. 128, 3; Hilar. ad loc.; id. in Psa. 119, 13"},"promnion":{"lemma":"promnion","pos":"","gen":"-colored","def":", a dark-colored gem, Plin. 37, 10, 63, § 173. prōmo, mpsi (msi), mptum (mtum), 3, v. a. pro-emo, to take, give, or bring out or forth, to produce (freq. and class."},"promptim":{"lemma":"promptim","pos":"adv.","gen":"-class","def":"1. promptus, quickly, suddenly (post-class. for the usual prompte), Tert. Carm. in Gen. 98. promptĭtūdo, ĭnis, f. id., promptitude (eccl Lat.), Fac. Defens. 3, 3."},"prompto":{"lemma":"prompto","pos":"","gen":"","def":"freq. a. promo, to give forth or out abundantly, to distribute, dispose of a thing (Plautin.): thesauros Jovis, i. e. to be Jupiter's treasurer, Plaut. Ps. 2, 2"},"promtus":{"lemma":"promtus","pos":"","gen":"","def":"promo, Part. and P. a., and 2. promptus."},"promulcum":{"lemma":"promulcum","pos":"","gen":"-rope","def":", a tow-rope: promulco agi dicitur navis, cum scaphae ducitur fune, Paul. ex Fest. p. 224 Müll."},"propagmen":{"lemma":"propagmen","pos":"","gen":"","def":"id., propagation; trop., prolongation: vitae, Enn. ap. Non. 64, 32 (Ann. v. 458 Vahl.). prōpāgo, āvi, ātum, āre, v. a. pro and root pag- of pango, πήγνυμι. Lit. To set or fasten down"},"propter":{"lemma":"propter","pos":"adv.","gen":"","def":"and prep. contr. for propiter, from prope; cf.: inter, subter. Adv., near, hard by, at hand (syn.: prope, juxta"},"prospecto":{"lemma":"prospecto","pos":"","gen":"-class","def":"freq. a. prospicio, to look forth upon, look out; to look at, view, behold, see afar off, gaze upon: mare, Cic. Att. 9, 10, 2. Lit.: pars ex tectis fenestrisque prospectant, Liv. 24, 21"},"prospector":{"lemma":"prospector","pos":"adv.","gen":"-class","def":"id.. Lit., one who looks out: sicut prospector videns casum proximi sui, Vulg. Ecclus. 11, 32.— Trop., one that foresees, one that arranges beforehand"},"prospectus":{"lemma":"prospectus","pos":"","gen":"-class","def":"prospicio. Lit., a lookout, distant view, prospect (class.): sterilis prospectus, Plaut. Mil. 3, 1, 15: cum saepibus prospectus impediretur, Caes. B. G. 2, 22"},"prostas":{"lemma":"prostas","pos":"","gen":"","def":", = προστάς, a porch, vestibule, Vitr. 6, 10. prō-sterno, strāvi, strātum, 3, v. a., to strew in front of, to strew before one"},"prostypum":{"lemma":"prostypum","pos":"","gen":"","def":", = πρόστυπον, a pattern, model, Plin. 35, 12, 43, § 152"},"prosumnus":{"lemma":"Prosumnus","pos":"","gen":"","def":", the name of a lewd favorite of Bacchus, who showed the latter the way to the infernal regions, Arn. 5, 176. pro-sūmo, prosumpserit, a false read. for praesumpserit, Plaut. Trin. 5, 2, 6"},"prosurgo":{"lemma":"prosurgo","pos":"v.","gen":"","def":"n., to rise up (late Lat.), Fulg. Serm. 11. prōsus, a, um, v. 2. prorsus. Prŏsymna, ae, or Prŏsymnē, ēs, f., = Προσυμνα, a country or town of Argolis, Stat. Th. 1, 383"},"prouolgo":{"lemma":"provolgo","pos":"","gen":"","def":"provulgo. prō-vŏlo, āvi, 1, v. n., to fly forth. Lit., Plin. 10, 58, 79, § 159: apes, id. 11, 18, 19, § 62.— Transf., to hurry or hasten forth, to rush out (class.): capillo passo in viam provolarunt"},"psacae":{"lemma":"Psacae","pos":"","gen":"","def":", a people of Scythia, near the river Imaus, Plin. 6, 17, 19, § 50."},"psallo":{"lemma":"psallo","pos":"v.","gen":"","def":"n., = ψάλλω. In gen., to play upon a stringed instrument"},"psalma":{"lemma":"psalma","pos":"","gen":"","def":", = ψάλμα, a song sung to the accompaniment of stringed instruments, a psalm (eccl. Lat.). Aug. in Psa. 4; Hier. Ep. 28"},"psalmista":{"lemma":"psalmista","pos":"adv.","gen":"-writer","def":", = ψαλμιστής, a composer or singer of psalms, a psalm-writer, psalm-singer, psalmist (eccl. Lat.), Hier. adv. Pelag. 1, 2; 3, 2"},"psalmus":{"lemma":"psalmus","pos":"adv.","gen":"","def":", = ψαλμός, i. q. psalma, a psalm (eccl. Lat.; cf.: carmen, hymnus), Tert. adv. Prax. 11; Lact. 4, 8, 14; 4, 12, 7; Vulg. Isa. 38, 20.—Esp., the Psalms of David, Vulg. Luc. 20, 42"},"psaltes":{"lemma":"psaltes","pos":"","gen":"","def":", = ψαλτής, a player on the cithara, a musician, minstrel, Quint. 1, 10, 18; Mart. Cap. 9, § 924; Sid. Ep. 8, 9; Inscr. Grut. 331, 2"},"pselcis":{"lemma":"Pselcis","pos":"","gen":"","def":", = Ψέλκις, a town of Ethiopia, now Dakke, Plin. 6, 29, 35, § 181. psēphisma, ătis, n., = ψήφισμα, an ordinance of the people among the Greeks = the plebiscitum of the Romans, Cic. Fl. 6, 15; 7, 17"},"pseudosphex":{"lemma":"pseudosphex","pos":"","gen":"","def":", = ψευδόσφηξ, a false wasp, Plin. 30, 11, 30, § 98. pseudŏthyrum, i, n., = ψευδόθυρον. Lit., a backdoor, private entrance, postern-gate: palatii, Amm. 14, 1, 3"},"psylli":{"lemma":"Psylli","pos":"","gen":"-west","def":", = Ψύλλοι, an African people south-west of the Syrtis Major, celebrated as serpent-charmers: qui Psylli nominantur, Cels. 5, 27, 3; Plin. 7, 2, 2, § 14; 8, 25, 38, § 93; Suet. Aug. 17"},"pternix":{"lemma":"pternix","pos":"","gen":"","def":", = πτέρνιξ, the straight stem of a plant, Plin. 21, 16, 57, § 97. ptĕrōma, ătis, n., = πτέρωμα, the colonnade on the two sides of a Grecian temple, Vitr. 3, 2; 4, 4"},"ptyas":{"lemma":"ptyas","pos":"","gen":"","def":", = πτυάς, a kind of serpent, said to spit venom into the eyes of men, Plin. 28, 6, 18, § 65"},"publius":{"lemma":"Publius","pos":"adj.","gen":"","def":", a Roman proenomen; in writing, abbrev. P.; e. g. P. Lentulus, to whom are addressed the letters, Cic. Fam. 1, 1 sqq."},"pugna":{"lemma":"pugna","pos":"part.","gen":"","def":"root pug, in pugno and pungo; cf. pugil, prop. a fight fist to fist, man to man"},"pugnax":{"lemma":"pugnax","pos":"adj.","gen":"","def":"pugno, fond of fighting, combative, warlike, martial. Lit.: centuriones pugnaces, Cic. Phil. 8, 9, 26: acer et pugnax, id. Rep. 5, 8, 10 (from Non. 337, 31): Minerva, Ov. Tr. 3, 9, 7: Achivi"},"pugno":{"lemma":"pugno","pos":"v.","gen":"-t","def":"n. and very rarely a. [root pug-, to thrust, strike, whence pugil, pungo, etc.], to fight, either singly or in armies, to combat, give battle, engage"},"pugnus":{"lemma":"pugnus","pos":"","gen":"","def":"root pug-"},"pulcer":{"lemma":"pulcer","pos":"","gen":"","def":"pulcher. pulchellus or pulcellus, a, um, adj. dim. , beautiful little: Bacchae (i. e. Baccharum statuae), Cic. Fam. 7, 23, 2; ironic.: audiamus pulcellum puerum, Crass. ap. Cic. de Or. 2, 65, 262"},"pulcher":{"lemma":"pulcher","pos":"adj.","gen":"-cer","def":"for pol-cer, root pol-ire, akin with parēre, apparēre, prop. bright, shining"},"pullastra":{"lemma":"pullastra","pos":"","gen":"","def":"id., a young hen, a pullet, Varr. R. R. 3, 9, 9. pullātĭo, ōnis, f. id., a hatching, Col. 8, 5, 9. pullātus, a, um, adj. 3. pullus"},"pullo":{"lemma":"pullo","pos":"v.","gen":"","def":"n. id., to put forth, sprout out, germinate, Calp. Ecl. 5, 19. pullŭlasco, ĕre, v. inch. n. , to put forth, sprout out, to bud, bourgeon, Col. 4, 21, 3"},"pullus":{"lemma":"pullus","pos":"adj.","gen":"","def":"dim. , pure: veste pullā candidi, Varr. ap. Non. 368, 28."},"pulmentum":{"lemma":"pulmentum","pos":"","gen":"","def":"contr. from pulpamentum, from pulpa. Any thing eaten with bread, a sauce, condiment, relish (fruit, vegetables, salt, etc.), App. M. 4, p. 146, 2; 9, p. 227, 19; 10, p. 244, 44"},"pulmo":{"lemma":"pulmo","pos":"","gen":"-lung","def":"kindr. with πλεύμων, for πνεύμων. Lit., a lung; and in plur.: pulmones, the two lobes of the lungs, the lungs, Cic. N. D. 2, 55, 136; Cels. 4, 1; Plin. 11, 37, 72, § 188; Plaut. Curc. 2, 1, 21"},"pulpa":{"lemma":"pulpa","pos":"","gen":"","def":"Lit., the fleshy portion of animal bodies, solid flesh: spiritus non inter nervos et pulpas, sed in visceribus, Sen. Q. N. 6, 24, 1; Cato, R. R. 83: pulpam voras, Mart. 3, 77, 6"},"pulpo":{"lemma":"pulpo","pos":"v.","gen":"","def":"n., to utter the natural cry of the vulture, Auct. Philom. 27. pulpōsus, a, um, adj. pulpa, fleshy: terga pulposis torulis obesa, App. M. 7, p. 195, 12."},"puls":{"lemma":"puls","pos":"","gen":"","def":"πόλτος, a thick pap or pottage made of meal, pulse, etc., the primitive food of the Romans before they became acquainted with bread"},"pulso":{"lemma":"pulso","pos":"","gen":"","def":"parag. pulsarier, Lucr. 4, 931), 1, v. freq. a. id., to push, strike, beat (cf.: tundo, ferio, pello). Lit.: cum pulsetur agiteturque incursione atomorum sempiternā, Cic. N. D. 1, 41"},"pulsus":{"lemma":"pulsus","pos":"","gen":"","def":"pello, a pushing, beating, striking, stamping; a push, blow (class.). Lit.: pulsu externo agitari, Cic. Tusc. 1, 23, 54: remorum, the stroke of the oars, rowing, id. de Or. 1, 33, 153"},"pulto":{"lemma":"pulto","pos":"","gen":"-class","def":"freq. a. collat. form of pulso, from pello, to beat, strike, knock (ante-class."},"puluer":{"lemma":"pulver","pos":"","gen":"","def":"pulvis init. pulvĕrārĭus, a, um, adj. pulvis, of or belonging to dust or sand: VICVS, a place in Rome, Inscr. Grut. 250. pulvĕrātĭcum, i, n., and pulvĕrā-tĭca, ae, f. pulvis"},"puncta":{"lemma":"puncta","pos":"","gen":"","def":"pungo, P. a. fin. punctātim, adv. punctum, condensed to a point, i. e. briefly, concisely, Claud. Mam. Stat. Anim. 3, 14. punctātōrĭŏlas leves pugnas appellat Cato, Fest. p. 242 Müll."},"punctillum":{"lemma":"punctillum","pos":"","gen":"","def":"dim. punctum, a little point, a dot, spot (late Lat.), Sol. 15 fin."},"punctim":{"lemma":"punctim","pos":"adv.","gen":"","def":"pungo, with the point (opp. caesim, with the edge): Hispano punctim magis quam caesim assueto petere hostem, Liv. 22, 46; so opp. caesim, Veg. Mil. 1, 12"},"punctum":{"lemma":"punctum","pos":"","gen":"","def":", v. pungo, P. a. punctūra, ae, f. pungo, a pricking, prick, puncture (post-class.): assiduae puncturae, Cels. 10, 9: teli, Firm. Math. 8, 21 dub. punctus, a, um, Part. and P. a., from pungo. punctus"},"pupiniensis":{"lemma":"Pupiniensis","pos":"","gen":"","def":"Pupinius med."},"pupinius":{"lemma":"Pupinius","pos":"adj.","gen":"","def":", Pupinian: ager, Cic. Agr. 2, 35, 96: Pupinia tribus ab agro Pupinio, Paul. ex Fest. p. 232 Müll. (Fest. ib. 233, preserved only in a fragm. form). —Also, Pupiniensis, e, adj.: ager, Liv. 9, 41"},"purgo":{"lemma":"purgo","pos":"v.","gen":"-tus","def":"a. contr. for purigo, from purum ago, to make clean or pure, to clean, cleanse, purify (class.). Lit.: oleam a foliis et stercore purgato, Cato, R. R. 65, 1: cum falcibus purgarunt locum"},"puxis":{"lemma":"puxis","pos":"","gen":"","def":"pyxis. pycnītis, ĭdis, f., = πυκνῖτις, a plant, mullein, wool-blade (pure Lat. verbascum), App. Herb. 71. pycnŏcŏmon, i, n., = πυκνόκομον, a plant, devil's-bit: Scabiosa succisa, Linn."},"pydna":{"lemma":"Pydna","pos":"","gen":"","def":", = Πύδνα, a city in Macedonia, on the Thermaic Gulf (the modern Kitro), celebrated for the battle in which Perseus was defeated by Aemilius Paulus, Liv. 44, 6, 3; 44, 42, 2 sqq."},"pygmaei":{"lemma":"Pygmaei","pos":"adj.","gen":"-maeus","def":", = Πυγμαῖοι (qs. Fistlings, Tom Thumbs), the Pygmies, a fabulous dwarfish race of antiquity, especially in Africa; at war with the cranes, by whom they were constantly defeated, Mel. 3, 8, 8"},"pylae":{"lemma":"Pylae","pos":"adj.","gen":"","def":", = Πύλαι (gates, gateways). In gen., a narrow pass, defile: Tauri, between Cappadocia and Cilicia, Cic. Att. 5, 20, 2; called also Amanicae, Curt. 3, 8, 13"},"pyra":{"lemma":"pyra","pos":"","gen":"","def":", = πυρά. A funeral pile, pyre (pure Lat. rogus), Verg. A. 6, 215; 11, 185; Ov. F. 2, 534; id. Ib. 36; Auct. B. Afr. 91"},"pyracmon":{"lemma":"Pyracmon","pos":"","gen":"","def":", = Πυράκμων, a Cyclops, a servant of Vulcan, Verg. A. 8, 425; Claud. Rapt. Pros. 1, 238; id. Cons. Hon. 3, 195."},"pyracmos":{"lemma":"Pyracmos","pos":"","gen":"","def":", a Centaur who was present at the marriage of Pirithoüs, Ov. M. 12, 460."},"pyrae":{"lemma":"Pyrae","pos":"","gen":"","def":", an ancient town of Latium, Plin. 3, 5, 9, § 59."},"pyraei":{"lemma":"Pyraei","pos":"","gen":"","def":", a people of Illyria, Plin. 3, 22, 26, § 144"},"pyrgi":{"lemma":"Pyrgi","pos":"adj.","gen":"","def":", = Πύργοι, a colony in Etruria, now the village of S. Severa, Mel. 2, 4, 9; Plin. 3, 5, 8, § 51; Liv 36, 3, 6; Verg. A. 10, 184; Suet. Ner. 5; Mart. 12, 2, 1"},"pyrgis":{"lemma":"pyrgis","pos":"","gen":"-tongue","def":", a plant, dog's-tongue, App. Herb. 96."},"pyrgo":{"lemma":"Pyrgo","pos":"","gen":"","def":", the nurse of Priam's children, Verg. A. 5, 645. Pyrgŏpŏlĭnīces, is, m., Tower-towntaker, the name of the hero in Plautus's Miles Gloriosus, 1, 1, 56; 4, 2, 9"},"pyrgus":{"lemma":"pyrgus","pos":"","gen":"-board","def":", = πύργος, a little wooden tower on the side of a gaming-board, hollow and having steps inside, through which the dice were thrown upon the board (pure Lat. turricula), Sid. Ep. 8, 12 (in Hor. S. 2"},"pyrrha":{"lemma":"Pyrrha","pos":"adj.","gen":"","def":", = Πύρρα. Daughter of Epimetheus, and wife of Deucalion, Ov. M. 1, 350 sq.; Hor. C. 1, 2, 6; Hyg. Fab. 153"},"pyrrho":{"lemma":"Pyrrho","pos":"adj.","gen":"","def":", = Πύρρων, a philosopher of Elis, contemporary with Aristotle, and founder of the sceptical school, Cic. Fin. 2, 11, 35; 4, 16, 43; 4, 18, 49; 4, 22, 60; 5, 8, 23; id. Ac. 2, 42, 130"},"pyrrhus":{"lemma":"Pyrrhus","pos":"","gen":"","def":", = Πύρρος. Son of Achilles and Deïdamia (otherwise called Neoptolemus), founder of a kingdom in Epirus, slain at Delphi by Orestes, Just. 17, 3, 18; Verg. A. 2, 469; 526 sq.; Ov. H. 8, 3"},"pysma":{"lemma":"pysma","pos":"","gen":"","def":", = πύσμα; in rhet., a question, Aquila Rom. p. 152 Ruhnk. Pȳthăgŏras, ae, m., = Πυθαγόρας, a celebrated philosopher of Samos, about 550 B.C."},"pythias":{"lemma":"Pythias","pos":"","gen":"","def":", a false reading for Phintias, v. h. v. Pȳthiăs, ădis, f., name of a female slave, Ter. Eun. 3, 2, 47 al.; also in a comedy of Caecilius, Hor. A. P. 238 Schol. Cruq and Orell."},"qua":{"lemma":"qui","pos":"conj.","gen":"-clause","def":"quei; gen. quojus; dat. quoi, and in inscrr. QVOEI, QVOIEI, and QVEI; abl. qui; plur. ques or queis; fem. QVAI; neutr. qua","form_of":"qui"},"quaad":{"lemma":"quaad","pos":"","gen":"","def":"quoad. quā-cumquē (-cunque) (in tmesi: quā porro cumque, Lucr. 1, 508: quā se cunque tulit, Verg. A. 11, 762), adv. By whatever way, wherever, wheresoever (class.): quācumque iter fecit, Cic. Verr. 2"},"quae":{"lemma":"qui","pos":"conj.","gen":"-clause","def":"quei; gen. quojus; dat. quoi, and in inscrr. QVOEI, QVOIEI, and QVEI; abl. qui; plur. ques or queis; fem. QVAI; neutr. qua","form_of":"qui"},"quaeso":{"lemma":"quaeso","pos":"v.","gen":"-class","def":"a. old form of quaero; root kis-"},"quam":{"lemma":"qui","pos":"conj.","gen":"-clause","def":"quei; gen. quojus; dat. quoi, and in inscrr. QVOEI, QVOIEI, and QVEI; abl. qui; plur. ques or queis; fem. QVAI; neutr. qua","form_of":"qui"},"quande":{"lemma":"quande","pos":"","gen":"","def":"quam init. quandĭu, v. quamdiu. quando (old form quandod, acc. to Fest. p. 258 b Müll.), adv. and conj. Adv. Interrog."},"quanquam":{"lemma":"quanquam","pos":"","gen":"","def":"quamquam."},"quantillus":{"lemma":"quantillus","pos":"adj.","gen":"","def":"dim. , how small a deal, i. e. how little, how small, how diminutive (Plautin.). Interrog.: huic debet Philolaches paulum. Then. Quantillum? Tra. Quasi quadraginta minas, Plaut. Most. 3, 1, 95"},"quantisper":{"lemma":"quantisper","pos":"adv.","gen":"-class","def":"[quantum, how much), how long (ante-class.). Interrog.: velim paulisper opperiri te. Quantisper? Non plus triduum, Caecil. ap. Non. 511, 30.— Rel.: possum exorare te"},"quantum":{"lemma":"quantum","pos":"adv.","gen":"","def":", v. quantus fin."},"quantumcumque":{"lemma":"quantumcumque","pos":"","gen":"","def":"quantuscumque. quantumlĭbet, v. quantuslibet. quantumvīs, adv., v. quantusvis fin."},"quantus":{"lemma":"quantus","pos":"adj.","gen":"-class","def":"quam, how great. Bellum, Nep. Dat. 5, 1: calamitates, Cic. Tusc. 1, 35, 86: homo in dicendo, id. de Or. 2, 12, 51: gravitas, Vell. 2, 129"},"quantus-cumque":{"lemma":"quantus-cumque","pos":"adj.","gen":"-cumque","def":", how great soever, of whatever size (class.): quantuscumque sum ad judicandum, Cic. de Or. 2, 28, 122: bona, quantacumque erant, id. Phil. 5, 8, 22: adfectus, quantuscumque est, Sen. Ep. 85"},"quantus-quantus":{"lemma":"quantus-quantus","pos":"","gen":"-quantus","def":"quantus. quantus-vīs, tăvis, tumvis, adj., as much as you will, as great as you please, however great, ever so great (class.): et manus una regit quantovis impete euntem (navem), Lucr. 4, 903"},"quartum":{"lemma":"quartum","pos":"adv.","gen":"","def":", v. quartus, A. fin."},"quartus":{"lemma":"quartus","pos":"adj.","gen":"-class","def":"adj. for quatertus from quattuor, kindr. with Gr. τέτϝαρτος and Sanscr. caturtha, the fourth, the fourth: perfidia, et peculatus ex urbe et avaritiā si exsulant, quarta invidia, quinta ambitio"},"quas":{"lemma":"qui","pos":"conj.","gen":"-clause","def":"quei; gen. quojus; dat. quoi, and in inscrr. QVOEI, QVOIEI, and QVEI; abl. qui; plur. ques or queis; fem. QVAI; neutr. qua","form_of":"qui"},"quassus":{"lemma":"quassus","pos":"","gen":"","def":"quatio, a shaking, Pac. ap. Cic. Tusc. 2, 21, 50. quătĕ-făcĭo, fēci, factum, 3, v. a. quatio-facio, to shake"},"quem":{"lemma":"qui","pos":"conj.","gen":"-clause","def":"quei; gen. quojus; dat. quoi, and in inscrr. QVOEI, QVOIEI, and QVEI; abl. qui; plur. ques or queis; fem. QVAI; neutr. qua","form_of":"qui"},"quercus":{"lemma":"quercus","pos":"","gen":"-k","def":"querci, Pall. 4, 7, 8; gen. plur. quercorum, Cic. Fragm. ap. Prisc. p. 717 P.; dat. and abl. plur. do not occur), f. perh. from root kar (kal-k), to be hard"},"quernus":{"lemma":"quernus","pos":"adj.","gen":"-leaves","def":"quercus"},"ques":{"lemma":"ques","pos":"","gen":"","def":"1. qui init."},"quescumque":{"lemma":"quescumque","pos":"","gen":"","def":"quicumque init."},"quesdam":{"lemma":"quesdam","pos":"","gen":"","def":"quidam. questĭo, ōnis, f. queror, a complaining, complaint: habebat enim flebile quiddam in questionibus aptumque ad misericordiam commovendam, Cic. Brut. 38"},"questus":{"lemma":"questus","pos":"","gen":"","def":"queror, a complaining, complaint, plaint (class.). Lit. In gen., Cic. Quint. 30, 94: caelum questibus implet, Verg. A. 9, 480: tantos illa suo rumpebat pectore questus, id. ib. 4"},"qui":{"lemma":"qui","pos":"conj.","gen":"-clause","def":"quei; gen. quojus; dat. quoi, and in inscrr. QVOEI, QVOIEI, and QVEI; abl. qui; plur. ques or queis; fem. QVAI; neutr. qua"},"quibus":{"lemma":"qui","pos":"conj.","gen":"-clause","def":"quei; gen. quojus; dat. quoi, and in inscrr. QVOEI, QVOIEI, and QVEI; abl. qui; plur. ques or queis; fem. QVAI; neutr. qua","form_of":"qui"},"quicquam":{"lemma":"quicquam","pos":"","gen":"","def":"quisquam."},"quicque":{"lemma":"quicque","pos":"","gen":"","def":"quisque."},"quicquid":{"lemma":"quicquid","pos":"","gen":"","def":"quisquis. quīcum, v. 1. qui init. quīcumque (or -cunque), quaecumque, quodcumque (also separately: cum quibus erat cumque una, Ter. And. 1, 1, 36"},"quid":{"lemma":"quid","pos":"","gen":"","def":"1. quis. quīdam, quaedam, quoddam, and subst. quiddam, pron. indef., a certain, a certain one, somebody, something (v. aliquis init.): quidam ex advocatis, Cic. Clu. 63"},"quidnam":{"lemma":"quidnam","pos":"","gen":"","def":"quisnam."},"quidni":{"lemma":"quidni","pos":"","gen":"","def":"1. quis, I. B."},"quidpiam":{"lemma":"quidpiam","pos":"","gen":"","def":"quispiam and quisquam."},"quidquid":{"lemma":"quidquid","pos":"","gen":"","def":"quisquis."},"quidum":{"lemma":"quidum","pos":"","gen":"","def":"2. qui, II. B. quĭes, ētis (abl. quie, Naev. ap. Prisc. p. 703 P.), f. Sanscr. çi = jacēre; Gr. κεῖμαι, to lie"},"quincenti":{"lemma":"quincenti","pos":"","gen":"","def":"quingenti init. Quinctĭānus, Quinctĭlĭānus, Quinctīlis, etc., v. Quint. quincuncĭālis, e, adj. quincunx. Containing five twelfths of a whole (of a foot, etc.): quincuncialis magnitudo"},"quincun":{"lemma":"quincun","pos":"","gen":"-uncia","def":"uncis, m. quinque-uncia, fire twelfths of a whole (of an as, a jugerum, a pound, a sextarius, etc.). Lit.: si de quincunce remota est Uncia, quid superat? from five twelfths of an as, Hor. A. P. 327"},"quinque":{"lemma":"quinque","pos":"adj.","gen":"","def":"adj. Gr. πέντε; Sanscr. pancan; Germ. fünf"},"quinquennis":{"lemma":"quinquennis","pos":"adj.","gen":"","def":"id., of five years or five years old: filia, Plaut. Poen. prol. 85: Olympias, celebrated every fifth year, quinquennial, Ov. P. 4, 6, 5: vinum, Hor. S. 2, 8, 47: oleae, id. ib. 2, 2, 57: juvenis"},"quinqueplex":{"lemma":"quinqueplex","pos":"adj.","gen":"","def":"quinqueplico, for quincuplex, fivefold: quinqueplex, πεντάπλους, Gloss. Vet. quinqueplĭco, v. quinquiplico."},"quinqueplum":{"lemma":"quinqueplum","pos":"","gen":"","def":", a quintuple: quinqueplum, πεντάπλουν, Gloss. quinquĕ-prīmi (and separated, quinque prīmi), ōrum, m., the five principal men in a city, after the magistracy in the colonies and municipia"},"quinquessis":{"lemma":"quinquessis","pos":"","gen":"-as","def":"quinque-as, five asses (post-class.): sed tum quinarius quinquessis valebat, App. ap. Prisc. p. 708 P. quinquĕ-vertex, ĭcis, adj., having five summits, five-peaked (post-class.): urbs"},"quintuplex":{"lemma":"quintuplex","pos":"adj.","gen":"-plico","def":"quintus-plico, fivefold, quintuple (post-class.): salarium, Vop. Prob. 7. quintuplĭco, v. quinquiplico. quintus (old form quinctus, Plaut. Trin. 2, 4, 123), a, um, num. adj. quinque"},"quintus":{"lemma":"Quintus","pos":"","gen":"","def":", and Quinta, ae, f., Roman praenomen; the former usually abbreviated Q.: Quintus Arrius, Cic. Mil. 17, 46: Q. Scaevola, id. Phil. 8, 10, 31.—Quinta, Cic. Cael. 14, 34; id. Har. Resp. 13, 27"},"quippe":{"lemma":"quippe","pos":"adv.","gen":"-pe","def":"and conj. , a particle of corroboration, similar to nempe (from nam-pe), surely, certainly, to be sure, by all means, indeed"},"quis":{"lemma":"quis","pos":"adj.","gen":"-class","def":"plur. QVES, S. C. Bacch.), pron. interrog. [Sanscr. kis, in nakis = nemo; Gr. τίς], who? which? what? what man? (while qui, quae, quod, interrog. is used adject."},"quisnam":{"lemma":"quisnam","pos":"pron.","gen":"-nam","def":"interrog. , who, which, what pray (class.). In direct interrogation: quisnam igitur tuebitur P. Scipionis memoriam mortui? Cic. Verr. 2, 4, 36, § 80: sed earum artificem quem? Quemnam? id. ib. 2, 4"},"quiza":{"lemma":"Quiza","pos":"","gen":"","def":", a town or fortress of Mauritania, near the present Giza, in Oran, Plin. 5, 2, 1, § 19"},"quo":{"lemma":"qui","pos":"conj.","gen":"-clause","def":"quei; gen. quojus; dat. quoi, and in inscrr. QVOEI, QVOIEI, and QVEI; abl. qui; plur. ques or queis; fem. QVAI; neutr. qua","form_of":"qui"},"quod":{"lemma":"quod","pos":"conj.","gen":"-clause","def":". That, in that, because (cf.: quia, quoniam): cum tibi agam gratias quod me vivere coëgisti, Cic. Att. 3, 3, 1: mirari, Cato se aiebat, quod non rideret haruspex, haruspicem cum vidisset, id. Div. 2"},"quoi":{"lemma":"quoi","pos":"","gen":"","def":"q. cui, v. 1. qui init. quōjas or quōjātis, e, i. q. cujas or cujatis, Plaut. Poen. prol. 109"},"quoque":{"lemma":"quoque","pos":"","gen":"","def":"(form of quoque)"},"quos":{"lemma":"qui","pos":"conj.","gen":"-clause","def":"quei; gen. quojus; dat. quoi, and in inscrr. QVOEI, QVOIEI, and QVEI; abl. qui; plur. ques or queis; fem. QVAI; neutr. qua","form_of":"qui"},"quot-cumque":{"lemma":"quot-cumque","pos":"adv.","gen":"-cumque","def":", how many soever, as many as (rare): quotcumque senatus creverit, tot sunto, Cic. Leg. 3, 3, 8: tot ... quotcumque, Manil. 4, 315. quŏtēni, ae, a, num. distrib. adj."},"quum":{"lemma":"quum","pos":"conj.","gen":"","def":", v. 2. cum."},"quummaxime":{"lemma":"quummaxime","pos":"","gen":"","def":"2. cum. R R, r, indecl. n. or (sc. littera) f. The seventeenth letter of the Latin alphabet, which derives its form from the Greek P, but is not, like that, aspirated. Thus Burrus, arrabo"},"rabocentus":{"lemma":"Rabocentus","pos":"","gen":"","def":", a Bessic prince, put to death by L. Piso, Cic. Pis. 34. răbŭla, ae, m. 1. rabo, a brawling, wrangling advocate, a pettifogger (cf.: clamator"},"racco":{"lemma":"racco","pos":"v.","gen":"","def":"n., to utter the natural cry of the tiger, Auct. Carm. Philom. 49 (al. rancant). răcēmārĭus, a, um, adj. racemus, of or belonging to grape-stalks, stalky: pampini, that bear nothing but stalks"},"racilius":{"lemma":"Racilius","pos":"","gen":"","def":"; Racilia, ae, f., the name of a Roman gens; e. g. L. Racilius, a tribune of the people, Cic. Q. Fr. 2, 6, 5; Cic. Verr. 2, 2, 12, § 31"},"raia":{"lemma":"raia","pos":"","gen":"-fish","def":", a sea-fish, the ray, Plin. 9, 24, 40, § 78; 9, 42, 67, § 144."},"ralla":{"lemma":"Ralla","pos":"","gen":"","def":", a Roman surname in the Marcian gens. M. Marcius Ralla, Liv. 29, 11.— Q. Marcius Ralla, Liv. 34, 52."},"rallum":{"lemma":"rallum","pos":"","gen":"","def":"rado, an instrument for scraping off the earth from the ploughshare, Plin. 18, 19, 49, § 179."},"rallus":{"lemma":"rallus","pos":"adj.","gen":"","def":"dim. , thin: tunica, a thin tunic, Plaut. Ep. 2, 2, 46; cf. Non. 539, 15. rāmāle, is, n. ramus, twigs, shoots, sticks, brushwood"},"ramises":{"lemma":"Ramises","pos":"","gen":"","def":"(also Rhamises or Rhamses), an ancient king of Egypt, Plin. 36, 8, 14, § 65"},"rancesco":{"lemma":"rancesco","pos":"","gen":"","def":"inch. n., to become stinking, grow rancid, Arn. 1, 12. rancĭdē, adv., v. rancidus. rancĭdŭlus, a, um, adj. dim. (post-Aug.). Lit., stinking, rank, rancid: opsonia, Juv. 11, 135.— Trop., disgusting"},"ranco":{"lemma":"ranco","pos":"","gen":"","def":"racco."},"rancor":{"lemma":"rancor","pos":"","gen":"","def":"ranceo, rancens. Lit., a stinking smell or flavor, rankness, rancidity (late Lat.), Pall. 1, 20, 2"},"rapso":{"lemma":"rapso","pos":"","gen":"","def":"q. rapto, to snatch or hurry away: RAPSATA, Inscr. Orell. 4859."},"raptim":{"lemma":"raptim","pos":"adv.","gen":"","def":"raptus, from rapio, by snatching or hurrying away, i. e., Violently, greedily, rapaciously (very rare): ludunt raptim pila, Nov. ap. Non. 96, 20: semine raptim avium fame devorato, Plin. 17, 14, 22"},"rapto":{"lemma":"rapto","pos":"","gen":"","def":"pass. paragog. raptarier, Enn. Trag. 192), 1, v. freq. a. id., to seize and carry off, to snatch, drag, or hurry away (mostly poet.). Lit. In gen.: vidi Hectorem curru quadrijugo raptarier"},"raptor":{"lemma":"raptor","pos":"","gen":"","def":"rapio, one who seizes by force, a robber, plunderer, abductor, ravisher (only poet. and in post-Aug. prose"},"raptrix":{"lemma":"raptrix","pos":"","gen":"","def":"raptor, she that carries off, ravishes: aquila (that carried off Ganymede), Hier. Chron."},"raptum":{"lemma":"raptum","pos":"","gen":"","def":", robbery, rapine, plunder, etc., v. rapio, I. O. 1. fin. raptus, a, um, Part., from rapio."},"raptus":{"lemma":"raptus","pos":"","gen":"","def":"rapio, a carrying off by force. In gen. (very rare): Inoo lacerata est altera raptu, violent rending, Ov. M. 3, 722: runcinarum, Plin. 16, 42, 82, § 225: lenes cucurbitarum, Cael. Aur. Acut. 1"},"rarungae":{"lemma":"Rarungae","pos":"","gen":"","def":", a people of India, Plin. 6, 20, 23, § 74. rārus, a, um, adj. etym. dub."},"rasta":{"lemma":"rasta","pos":"","gen":"","def":"Germ.; O. H. Germ. rasta or rast, rest; Goth. rasta, a mile; cf. the Slav. werst, a German measure of a mile (late Lat.), Hier. in Joel, 3, 18."},"rastellus":{"lemma":"rastellus","pos":"","gen":"","def":"dim. rastrum, a hoe, rake, mattock, Varr. L. L. 5, 31, 38; id. R. R. 1, 49, 1; Col. 2, 12, 6 (for which, id. 2, 10, 27, rastra), Suet. Ner. 19."},"raster":{"lemma":"raster","pos":"","gen":"","def":"rastrum init. rastrārĭus, a, um, adj. rastrum, of or belonging to the hoe, i. e. to husbandry or a country life: Hypobolimaea, the title of a comedy of Caecilius, Non. 16, 19; 40, 4; 89, 16 al."},"rastrum":{"lemma":"rastrum","pos":"","gen":"-stri","def":", usually in plur., ra-stri, ōrum, m. (so nom. rastri, Varr. L. L. 5, § 136 Müll.; Verg. G. 1, 164; Ov. M. 11, 36; acc. rastros, Cato, R. R. 10, 3; 11, 4; Plaut. Merc. 2, 2, 6; Ter. Heaut. 1, 1, 36"},"rataneum":{"lemma":"Rataneum","pos":"","gen":"","def":", a city in Dalmatia, Plin. 3, 22, 26, § 142. rătārĭae, ārum, f. ratis, small vessels made of logs fastened together, rafts, acc. to Gell. 10, 25 fin."},"rauca":{"lemma":"rauca","pos":"","gen":"-roots","def":", a species of worm that breeds in oak-roots, Plin. 17, 18, 30, § 130"},"raucesco":{"lemma":"raucesco","pos":"v.","gen":"","def":"n. id., to grow hoarse, become hoarse: quomodo raucescit vox (gallinae), Aug. in Psa. 58; Isid. 12, 7, 15. raucĭdŭlus, a, um, adj. dim. , a little hoarse: cornix, Hier. Ep. 40, 2."},"raucio":{"lemma":"raucio","pos":"v.","gen":"","def":", sum, 4, v. n. id., to be hoarse: rausuro tragicus qui carmina perdit Oreste, Lucil. ap. Prisc. p. 907 P. raucĭ-sŏnus, a, um, adj. id., hoarsesounding (only in the foll. passages): cantus cornicum"},"raucus":{"lemma":"raucus","pos":"adj.","gen":"","def":"from root ru-, to make a loud noise, ravus, hoarse. Lit. (freq. and class.): rogitando sum raucus factus, Plaut. Ep. 2, 1, 16: expurigabo ad raucam ravim omnia, id. Fragm. ap. Non. 164"},"rebilus":{"lemma":"Rebilus","pos":"","gen":"","def":", surname of the legate C. Caninius, v. h. v. rĕ-bīto, ĕre, v. n. bēto, to turn back, return (ante-class.): si non rebitas huc, Plaut. Capt. 2, 3, 20; cf. id. ib. 2, 3, 49"},"rechamus":{"lemma":"rechamus","pos":"","gen":"","def":"In mechanics, like trochlea, a block or case containing a set of pulleys, Vitr. 10, 2, 1, and 2. rĕcharmĭdo, āre, v. n. re and Charmides, a character in Plautus"},"rector":{"lemma":"rector","pos":"","gen":"-driver","def":"rego, a guider, leader, director, ruler, master (cf.: moderator, gubernator). Lit. (mostly post-Aug.), of a helmsman: navium rectores, Cic. Div. 1, 14, 24; so Verg. A. 5, 161; 176; Ov. M. 2. 186"},"rectrix":{"lemma":"rectrix","pos":"","gen":"","def":"rector, she that leads or guides"},"red-undo":{"lemma":"red-undo","pos":"v.","gen":"-undo","def":"n.; of water, from being over full, to run back or over, to pour over, stream over, overflow (freq. and class.; a favorite word of Cic., esp. in trop. senses; not in Caes., Verg., or Hor."},"regno":{"lemma":"regno","pos":"v.","gen":"","def":"n. and a. . Neutr., to have royal power, to be king, to rule, reign: ubi Pterela rex regnavit, Plaut. Am. 1, 1, 257: Romulus cum septem et triginta regnavisset annos, Cic. Rep. 2, 10, 17"},"regnum":{"lemma":"regnum","pos":"adv.","gen":"-bout","def":"rex, kingly government, royal authority, kingship, royalty (cf.: imperium, principatus): cum penes unum est omnium summa rerum, regem illum unum vocamus et regnum ejus rei publicae statum"},"remansor":{"lemma":"remansor","pos":"","gen":"","def":"id.. A soldier who stays at home by permission of his commander, Inscr. Murat. 347, 2. — A soldier who overstays his furlough, Dig. 49, 16, 5, § 6 (but emansor is the true reading, Dig. 49, 16, 4"},"remoria":{"lemma":"remoria","pos":"","gen":"","def":"‡ remurinus. rĕ-mŏror, ātus, 1, v. dep. n. and a. Neutr., to stay, tarry, linger, loiter, delay (so rarely): nam quid illaec nunc tam diu intus remorantur remeligines? Plaut. Cas. 4, 3"},"replum":{"lemma":"replum","pos":"","gen":"-door","def":", a bolt for covering the commissure of the folding-door, Vitr. 4, 6; 10, 17. rĕ-plumbo, no perf., ātum, 1, v. a., to free from lead, to unsolder (post-Aug.), Dig. 34, 2, 19; 34, 2, 32"},"repperi":{"lemma":"repperi","pos":"","gen":"","def":"reperio. rĕ-praesentānĕus, a, um, adj., present: potestas, Tert. Apol. 28. rĕpraesentātĭo, ōnis, f. repraesento. A bringing before one; a showing, exhibiting, manifesting"},"repto":{"lemma":"repto","pos":"part.","gen":"-t","def":"freq. n. and a. , to creep, crawl (mostly poet. and postAug."},"respecto":{"lemma":"respecto","pos":"","gen":"","def":"freq. n. and a. , to look back, look round or behind repeatedly or intently, to look or gaze about"},"respectus":{"lemma":"respectus","pos":"","gen":"","def":"respicio, a looking back or about (class.). Lit.: fugientibus miserabilem respectum incendiorum fore, Cic. Div. 1, 32, 68: sine respiratione ac respectu pugnabant, Liv. 8"},"reudigni":{"lemma":"Reudigni","pos":"","gen":"","def":"Gothic"},"rex":{"lemma":"rex","pos":"adj.","gen":"-bee","def":"plur regerum, Gell. ap. Charis p. 40 P.), m. rego, a ruler of a country, a king. Lit.: omnis res publica, quae ut dixi populi res est, consilio quodam regenda est"},"rhaeti":{"lemma":"Rhaeti","pos":"","gen":"","def":"Raeti, etc. rhăgădes, um, f., and rhăgădia, ōrum, n., = ῥαγάδες and ῥαγάδια, a kind of sores or chaps on various parts of the body, Plin. 23, 4, 44, § 87; 23 7 64. § 129; 24, 7, 23, § 39"},"rhamnenses":{"lemma":"Rhamnenses","pos":"","gen":"","def":"Ramnes"},"rhamnos":{"lemma":"rhamnos","pos":"","gen":"-thorn","def":", = ῥάμνος, buckthorn, Christ's-thorn: Rhamnus, Linn."},"rhamses":{"lemma":"Rhamses","pos":"","gen":"","def":", an ancient and powerful king of Egypt, Tac. A. 2, 60, Plin. 36, 8, 14, § 65 (al. Ramises). Rhănis, ĭdis. f., a nymph in the train of Diana, Ov. M. 3, 171. † rhăpēĭon, ii, n., = ῥαπήϊον, a plant"},"rheuma":{"lemma":"rheuma","pos":"","gen":"","def":", = ῥεῦμα. A flow, flood: maris (i. e. aestus), Veg. Mil. 5, 12.— A catarrh, rheum, Hier. Ep. 122, 1. rheumătĭcus, i, m., = ῥευματικός, one troubled with rheum, that has a catarrh, Plin. 29, 6, 39"},"rhexia":{"lemma":"rhexia","pos":"","gen":"","def":", a plant, also called onochilis, Plin. 22, 21, 25, § 51. rhīna, ae, f., = ῥίνη, a kind of shark, of whose skin arrows were made, Plin. 32, 11, 53, § 150. rhīnenchytes, ae, m., = ῥινεγχύτης"},"rhodo":{"lemma":"Rhodo","pos":"","gen":"","def":", a friend of Q. Minucius Thermus, Cic. Fam. 2, 18, 1. rhŏdŏdaphnē, ēs, f., = ῥοδοδάφνη, the rose-bay, oleander, Plin. 16, 20, 33, § 79; 24, 11, 53, § 90"},"rhombus":{"lemma":"rhombus","pos":"","gen":"","def":", = ῥόμβος. A magician's circle, Prop. 2, 28, 35 (3, 25, 1); 3, 6, 26 (4, 5, 26); Ov. Am. 1, 8, 7; Mart. 9, 30, 9; 12, 57, 17.— A kind of fish, flatfish, turbot, Plin. 9, 54, 79, § 169"},"rhoncho":{"lemma":"rhoncho","pos":"v.","gen":"","def":"n. id., to snore, to snort, Sid. Ep. 1, 6. † rhonchus, i, m., = ῥόγχος. A snoring, Mart. 3, 82, 30.— Transf., the croaking of a frog, App. M. 1, p. 106.— Trop., a sneering, sneer, jeer, Mart. 1, 3, 5"},"rhondes":{"lemma":"Rhondes","pos":"","gen":"","def":"Icadius. rhŏpălon, i, n., = ῥόπαλον, the plant nymphaea, Plin. 25, 7, 37, § 75. Rhōsos, i, f., = Ῥῶσος, a town in Cilicia, where highly prized utensils were made, Mel. 1, 12 fin.—Hence, Rhōsĭcus, a"},"rhysaddir":{"lemma":"Rhysaddir","pos":"","gen":"","def":", a town and harbor of Mauretania Tingitana, now Melilla, Plin. 5, 1, 2, § 18"},"ricto":{"lemma":"ricto","pos":"v.","gen":"","def":"n. ringor, to make the natural cry of a leopard, Spart. Get. 5."},"rictum":{"lemma":"rictum","pos":"","gen":"","def":"rictus init. rictus, ūs, m. (collat, form rictum, i, n., Lucr. 6, 1195; Cic. Verr. 2, 4, 43, § 94; plur. ricta, Lucr. 5, 1064"},"ridica":{"lemma":"ridica","pos":"","gen":"-prop","def":"In agriculture, a stake, prop, a vine-prop, Cato, R. R. 17; 1; Varr. R. R. 1, 8, 4; 1, 26; Col. 4, 26, 1"},"ringor":{"lemma":"ringor","pos":"v.","gen":"","def":"dep. n., to open wide the mouth, to show the teeth (very rare). Lit.: saltat ridens, ringitur, Pompon. ap. Non. 517, 30 (Com. Rel. p. 206 Rib.).— Trop., to be vexed, angry"},"riscus":{"lemma":"riscus","pos":"","gen":"","def":", = ῥίσκος, a trunk, chest, Ter. Eun. 4, 6, 16; Dig. 34, 2, 26"},"rixa":{"lemma":"rixa","pos":"","gen":"-sa","def":"perh. root rig, whence ringor; the suffix -sa like noxa from noc-eo; hence, prop., the wide opening of the mouth. A quarrel, brawl, dispute, contest, strife, contention (class."},"rixo":{"lemma":"rixo","pos":"","gen":"","def":"rixor fin."},"rixor":{"lemma":"rixor","pos":"v.","gen":"","def":"dep. n. , to quarrel, brawl, wrangle, dispute. Lit. (rare but class.): multo cum sanguine saepe rixantes, Lucr. 6, 1286: cum esset cum eo de amiculā rixatus, * Cic. de Or. 2, 59, 240: de lanā caprinā"},"rosina":{"lemma":"rosina","pos":"","gen":"","def":"(sc. herba), a plant, otherwise unknown, Veg. 6, 13, 4. rōsĭo, ōnis, f. rodo; in medic. lang., a gnawing, corrosion, Cels. 7, 23"},"rostellum":{"lemma":"rostellum","pos":"","gen":"","def":"dim. rostrum, a little beak, snout, or muzzle: pullorum (avium), Col. 8, 5, 14: muris, Plin. 30, 11, 30, § 99."},"rostra":{"lemma":"rostra","pos":"","gen":"","def":"rostrum, II. C. rostrālis, e, adj. rostrum, II. C., of or belonging to the rostra: tabula (with Capitolina), i. e. a tablet on the rostra, Sid. Ep. 1, 11."},"rostrans":{"lemma":"rostrans","pos":"adj.","gen":"","def":"rostrum, striking or driving in its point: vomer, Plin. 18, 19, 49, § 178 dub. (perh. rostrato, v. rostratus). rostrātus, a, um, adj. id., having a beak, hook, or crooked point"},"rubrus":{"lemma":"rubrus","pos":"","gen":"","def":"ruber init. rŭbus, i, m. (fem., Prud. Cath. 5, 31; id. Apoth. 123) . A bramble-bush, blackberry-bush, Plin. 16, 37, 71, § 180; 17, 13, 21, § 96; 24, 13, 73, § 117 al.; Verg. E. 3, 89; id. G. 3, 315"},"ructo":{"lemma":"ructo","pos":"v.","gen":"","def":"n. and a. (dep. collat. form, ructor, Varr. R. R. 3, 2, 3: ructatur, Hor. A. P. 457: ructaretur, Cic. ap. Paul. ex Fest. p. 263 Müll.) [rugo, whence ructus, erugo, eructo], to belch"},"ructor":{"lemma":"ructor","pos":"","gen":"","def":"ructo init. ructŭo, āre, v. a. ructus, to belch forth (late Lat. for the usual ructare)"},"ructus":{"lemma":"ructus","pos":"","gen":"","def":"rugo, whence also ructo and erugo, a belching, eructation, rising of the stomach (class. in sing. and plur.): exhalas acidos ex pectore ructus, Lucil. ap. Non. 164, 33: suavis ructus mihist"},"rufius":{"lemma":"rufius","pos":"","gen":"","def":", the Gallic name for chama, a lynx, Plin. 8, 19, 28, § 70. rūfo, āre, v. a. rufus, to make or color reddish: capillum, Plin. 15, 22, 24, § 87; 23, 2, 32, § 67"},"rullus":{"lemma":"Rullus","pos":"","gen":"","def":", a Roman surname (cf. Cic. Phil. 5, 17, 48). So, P. Servilius Rullus, a tribune of the people in the consulate of Cicero, who directed against him three orations on the Agrarian law, Cic. Fam. 8, 6"},"ruma":{"lemma":"ruma","pos":"","gen":"","def":", v. rumen. rūmen, ĭnis, n. (collat. form rūma, ae,f., Arn. 7, 230 dub."},"rumpo":{"lemma":"rumpo","pos":"v.","gen":"","def":"paragog. rumpier, Afran. Com. 127), 3, v. a. root rup, to break, burst, tear, rend, rive, rupture; to break asunder, burst in pieces, force open, etc. (very freq. and class."},"rumpus":{"lemma":"rumpus","pos":"","gen":"","def":", a vine branch or runner (syn. tradux), Varr. R. R. 1, 8, 4. rūmuscŭlus, i, m. dim. rumor, idle talk"},"runco":{"lemma":"runco","pos":"v.","gen":"","def":"a. runca, runcina, to weed out, root up; to weed, clear of weeds. Lit.: spinas, Cato, R. R. 2: segetes, Varr. R. R. 1, 30; Col. 11, 2, 40; Plin. 18, 21, 50, § 184"},"ruptor":{"lemma":"ruptor","pos":"","gen":"","def":"id., a breaker (not ante-Aug.); trop.: foederis, a violator, Liv. 4, 19 (with violator juris); 1, 28; 21, 40 fin.: 25, 31; Tac. H. 4, 57"},"rusca":{"lemma":"Rusca","pos":"","gen":"","def":", a surname in the Pinarian family: M. Rusca, a tribune of the people, A.U.C. 622, Cic. de Or. 2, 65, 261. ruscārĭus (rustārĭus), a, um, adj. ruscum, of or for butcher's-broom: falculae"},"rusco":{"lemma":"rusco","pos":"","gen":"","def":", a disease of cattle, Gargil. Mart. de Cur. Boum. ruscŭlum, i, n. dim. rus, a little country-seat or farm, Gell. 19, 9, 1. ruscum (rustum), i, n., butcher'sbroom: Ruscus aculeatus, Linn."},"ruso":{"lemma":"Ruso","pos":"","gen":"","def":"Abudius. Rūsor, ōris, m. rusus for rursus"},"ruspor":{"lemma":"ruspor","pos":"v.","gen":"","def":"dep. n., to search through, examine, explore: crebro quaerere, Fest. p. 264 Müll.: scrutari, Non. 166, 19 (anteclass.): ut latebras ruspans rimarem"},"russesco":{"lemma":"russesco","pos":"","gen":"","def":"inch. n. , to become red: russescunt frundes, Enn. ap. Charis. p. 105 P. (Ann. v. 266 Vahl.). russĕus, a, um, adj. id., reddish (postAug. and very rare): tunica, Petr. 27, 1: fasciola, App. M. 2"},"russus":{"lemma":"russus","pos":"adj.","gen":"","def":", red (very rare): vela, Lucr. 4, 75: gingiva, Cat. 39, 19: tunicae, Val. Imp. ap. Treb. Claud. 14; and Vop. Aur. 13"},"sabaia":{"lemma":"sabaia","pos":"","gen":"","def":", a drink of the poor people in Illyria, prepared from barley, Amm. 26, 8, 2"},"sabis":{"lemma":"Sabis","pos":"","gen":"","def":"A river in Gallia Belgica, now the Sambre, Caes. B. G. 2, 16; 2, 18.— A river in Carmania, Mel. 3, 8, 4; Plin. 6, 23, 27, § 107.— A deity of the Saboeans, Plin. 12, 14, 32, § 63."},"sablo":{"lemma":"sablo","pos":"","gen":"","def":"sabulo."},"sabota":{"lemma":"Sabota","pos":"","gen":"","def":", a city in Arabia Felix, Plin. 6, 28, 32, § 155; 12, 13, 30, § 52 al. Sābrăta (Sābrătha), ae, f., a town of Africa, near the Lesser Syrtis, now Sabart, Plin. 5, 4, 3, § 25"},"sabus":{"lemma":"Sabus","pos":"","gen":"","def":"A king of India, Curt. 9, 8, 11.— The progenitor and god of the Sabines, Sil. 8, 423. Săcae (Săgae), ārum, m., = Σάκαι, a people of Northern Asia, a part of the Scythians, Mel. 3, 7, 1"},"saccellus":{"lemma":"saccellus","pos":"","gen":"","def":"dim. saccus, a little bag: sonantes aere, Petr. 140 fin.: calidi, i.e. dry poultices for the sick, Cels. 4, 4 med.; so Veg. 2, 24, 5; 3, 28, 3 al."},"sacco":{"lemma":"sacco","pos":"v.","gen":"","def":", ātum, 1, v. a. saccus, to strain through a bag, to strain, filter. Lit.: saccata aqua (opp. turbida), Sen. Ep. 86, 11; Plin. 18, 7, 17, § 77; 29, 2, 10, § 35"},"saccus":{"lemma":"saccus","pos":"","gen":"-water","def":", = σάκκος, a sack, bag. Cum iste civitatibus frumentum, coria, cilicia, saccos imperaret, Cic. Verr. 2, 1, 38, § 95: (mulus ferebat) tumentes multo saccos hordeo, Phaedr. 2, 7, 3.—Esp."},"sacrum":{"lemma":"sacrum","pos":"","gen":"","def":"sacer."},"sadala":{"lemma":"Sadala","pos":"","gen":"","def":"A king of Thrace (perh. the father of Cotys), Cic. Verr. 2, 1, 24, § 63; v. Zumpt N. cr."},"saepe":{"lemma":"saepe","pos":"adv.","gen":"","def":"old acc. n. of saepis. Often, oft, oftentimes, many times, frequently (at indefinite intervals, while crebro denotes in close succession): aperitur ostium, unde saturitate saepe ego exii ebrius"},"saepis":{"lemma":"saepis","pos":"adj.","gen":"","def":", = συχνός , that happens often, frequent. —As an adj. cited only once in the comp. saepior, by Prisc. p. 1016 P."},"saeuis":{"lemma":"saevis","pos":"","gen":"","def":"saevus. saevĭtas, ātis, f. saevus, rage, violence, fury (late Lat.), Prud. στεφ. 10, 483; Firm. Math. 5, 5; Ambros. in Luc. 9, § 32"},"saganos":{"lemma":"Saganos","pos":"","gen":"","def":", = Σαγανός, a small river of Carmania, Plin. 6, 25, 28, § 110 (Jahn, Saccanas); called also Saganis, Amm. 23, 6, 49. săgăpēnon, i, v. sacopenium. Săgăris, is; Săgărĭus, ii; Să-gĭārĭus, ii"},"sagda":{"lemma":"sagda","pos":"","gen":"","def":", a precious stone of a leekgreen color, Plin. 37, 10, 67, § 181. săgēna, ae, f.,=σαγήνη, a large fishing-net, a seine, Manil. 5, 678 (cf. Dig. 47, 10, 13, § 7); Vulg. Ezech. 26, 5; 47, 10"},"sagma":{"lemma":"sagma","pos":"","gen":"-saddle","def":", = σάγμα, a pack-saddle, Veg. 3, 59, 1; Vulg. Lev. 15, 9"},"sagmen":{"lemma":"sagmen","pos":"","gen":"","def":"root sag, to fill, feed; cf. Gr. σεσαγμένος, σάττω"},"sagra":{"lemma":"Sagra","pos":"","gen":"","def":", = Σάγρας, a river of Lower Italy (of the Bruttii), Cic. N. D. 2, 2, 6; 3, 5, 11"},"sal":{"lemma":"sal","pos":"n. m.","gen":"salis","def":"salt; brine; sea-water; wit, smartness"},"salassi":{"lemma":"Salassi","pos":"","gen":"","def":", an Alpine tribe in the modern Savoy, Liv. 21, 38; Plin. 3, 17, 21, § 134; 18, 20, 49, § 182 al. sălax, ācis, adj. salio"},"salmo":{"lemma":"salmo","pos":"","gen":"","def":", a salmon, Plin. 9, 18, 32, § 68"},"salpa":{"lemma":"salpa","pos":"","gen":"-fish","def":", a kind of stock-fish, Plin. 9, 18, 32, § 68; Ov. Hal. 121. salpicta (collat. form salpista, Vop. Carin. 19), ae, m., = σαλπιγκτής (σαλπιστής), a trumpeter, Firm. Math. 8, 21"},"saltim":{"lemma":"saltim","pos":"","gen":"","def":"saltem init. saltĭto, āre, v. freq. n. , to dance much or vigorously (post-Aug. and very rare), Quint. 9, 4, 142; Macr. S. 2, 4, 14; 2, 10 fin."},"saltus":{"lemma":"saltus","pos":"","gen":"","def":"2. salio, a leaping, leap, spring, bound (class.), Sen. Ep. 15, 4: saltu uti, * Cic. Sen. 6, 19: cum alacribus saltu, cum velocibus cursu certabat, Sall. Fragm. ap. Veg. Mil. 1"},"saluo":{"lemma":"salvo","pos":"v.","gen":"","def":"a. salvus, to save (late Lat.; opp. perdere; syn.: servo, conservo), Veg. Vet. 3, 23, 3; Lact. de Ira Dei, 5, 7; Hier. Ep. 20, 4; Vulg. Isa. 4, 2; id. Amos, 2, 14"},"samara":{"lemma":"samara","pos":"","gen":"","def":"samera init. Samarabrĭae, ārum, m., a people of India, Plin. 6, 20, 23, § 78. sămardăcus, i, m. African, a juggler (late Lat.), Aug. cont. Acad. 3, 15"},"sampsa":{"lemma":"sampsa","pos":"","gen":"","def":", the pulp of olives, Col. 12, 49 in lemm.; 12, 51, 2"},"sancaptis":{"lemma":"sancaptis","pos":"","gen":"","def":"saucaptis. sanchrōmăton, i, n., a plant, otherwise called dracontea, App. Herb. 14. sancĭo, xi, ctum, 4 (pluperf. sancierat, Pompon. ap. Diom. p. 368 P."},"sanctesco":{"lemma":"sanctesco","pos":"","gen":"","def":"inch. n. , to become sacred: per nos sanctescat genus (Pelopidarum), Att. ap. Non. 143, 23 (Trag. Rel. p. 163 Rib.). sanctĭfĭcātĭo, ōnis, f. sanctifico, sanctification (eccl. Lat.)"},"sanctor":{"lemma":"sanctor","pos":"","gen":"","def":"sancio, an establisher, ordainer: legum, Tac. A. 3, 26 fin. sanctŭārĭum, ii, n. sanctus (postAug. for sacrarium). A place for keeping sacred things, a shrine, sanctuary, Aggen. Limit. p. 61 Goes."},"sanguen":{"lemma":"sanguen","pos":"","gen":"","def":"sanguis init. sanguĭcŭlus, i, m. dim. sanguis, a blood-pudding, black-pudding, Plin. 28, 14, 58, § 209. sanguĭlentus, a, um, v. sanguinolentus. sanguĭnālis, e, v. sanguinarius, I. sanguĭnārĭus, a"},"sanna":{"lemma":"sanna","pos":"","gen":"","def":"δάννας, a mimicking grimace, esp. in mockery, derision, Pers. 1, 62; 5, 91"},"sanni":{"lemma":"Sanni","pos":"","gen":"","def":", a people in Pontus, Plin. 6, 4, 4, § 12; 21, 15, 45, § 77."},"sannigae":{"lemma":"Sannigae","pos":"","gen":"","def":", a people in Pontus, Plin. 6, 4, 4, § 14. sannĭo, ōnis, m. sanna, one who makes mimicking grimaces, a buffoon (cf. scurra), Cic. de Or. 2, 61, 251; id. Fam. 9, 16, 10"},"santra":{"lemma":"Santra","pos":"","gen":"","def":", a famous grammarian, Quint. 12, 10, 16; Suet. Vit. Ter. 4; Paul. ex Fest. p 68 Müll. sānus, a, um (sanun', for sanusne, Plaut. Bacch. 3, 6, 37; id. Men. 5, 2, 66; id. Mere. 2, 2, 21; 2, 4, 21"},"sapenos":{"lemma":"sapenos","pos":"","gen":"-colored","def":"Indian, a bright hyacinth-colored amethyst found in India, Plin. 37, 9, 40, § 122"},"sapriportus":{"lemma":"Sapriportus","pos":"","gen":"","def":", a harbor between Sybaris and Tarentum, Liv. 26, 39. saprŏphăgo, ĕre, v. n., = σαπροφαγεῖν, to eat putrid meat, Mart. 3, 77, 3 (sometimes written as Greek)."},"sapros":{"lemma":"sapros","pos":"adj.","gen":"","def":", = σαπρός, rotten, putrid: caseus, Plin. 28, 9, 34, § 132."},"sapsa":{"lemma":"sapsa","pos":"pron.","gen":"-class","def":"[contr. from sa-, i. e. suaipsa; cf.: sam, sas"},"sara":{"lemma":"Sara","pos":"","gen":"","def":"Sarra init. sărăballa, ae, v. sarabara. sărăbāra, ōrum (collat. form sără-balla, Hier. Ep. 1, 9), n., or ae, f. Persian; cf. Gesen. under ], wide trowsers, such as are worn in the East, Tert. Pall. 4"},"sarcasmos":{"lemma":"sarcasmos","pos":"","gen":"","def":", = σαρκασμός, a keen or bitter jest, a taunt, gibe, sarcasm, a figure of speech, Charis. p. 247 P. (in Quint. 8, 6, 57, and Diom. p. 458 P., written as Greek). sarcīmen, ĭnis, n. sarcio, a seam"},"sarda":{"lemma":"sarda","pos":"","gen":"","def":"A kind of fish that was pickled or salted, perh. sardine, Plin. 32, 11, 53, § 151"},"sardes":{"lemma":"Sardes","pos":"","gen":"","def":"Sardis."},"sardi":{"lemma":"Sardi","pos":"adj.","gen":"-d","def":"from Σαρδώ, Sardinia, the inhabitants of the island of Sardinia, the Sardinians, Cic. Div. in Caecil. 19, 63; id. Off. 2, 14, 50; id. Balb. 18, 41"},"sardina":{"lemma":"sardina","pos":"","gen":"","def":"1. sarda, I. Sardĭnĭa, ae, v. Sardi, C. Sardĭnĭānus, a, um, v. Sardi, D. Sardĭnĭensis, e, v. Sardi, E. sardīnus, a, um, v. sardius fin."},"sardo":{"lemma":"sardo","pos":"v.","gen":"","def":"a., to understand: sardare intellegere. Naevius. Quod bruti nec satis sardare queunt, Fest. p. 322 Müll. Sardŏnĭa herba, v. Sardi, B. fin. sardŏnychātus, a, um, adj. sardonyx"},"sardus":{"lemma":"Sardus","pos":"","gen":"","def":"Sardi, A. Sarē, ēs, f., a village in Thrace, Liv. 38, 41, 8."},"sargus":{"lemma":"sargus","pos":"","gen":"-fish","def":", = σάργος, a kind of sea-fish esteemed by the Romans, Plin. 9, 17, 30, § 65; 9, 51, 74, § 162; Lucil. ap. Fest. p. 322 Müll.; Enn. ap. App. Mag. p. 299; Ov. Hal. 105."},"sari":{"lemma":"sari","pos":"","gen":"","def":", = σάρι, or saripha, ae, f., a shrub growing on the banks of the Nile, Plin. 13, 23, 45, § 128. sarĭo, īre, v. sarrio init. sarīsa (-issa), ae, f., = σάρισα. A long Macedonian lance, Liv. 9, 19"},"sarmen":{"lemma":"sarmen","pos":"","gen":"","def":"sarpo (for the usu. sarmentum), twigs, brushwood, Plaut. Most. 5, 1, 65. sarmentīcĭus or -tĭus, a, um, adj. sarmentum, of or belonging to twigs, cuttings, or brushwood: cinis, Col. 6, 26"},"sarmentum":{"lemma":"sarmentum","pos":"","gen":"","def":"sarpo, twigs, light branches, brushwood; a fagot, fascine (class.; usu. in plur.; only so in Cic. and Caes.; cf.: lignum, materia); sing., Varr. R. R. 1, 31, 2; Col. 3, 10, 1"},"sarnus":{"lemma":"Sarnus","pos":"","gen":"","def":", a river in Campania, near Pompeii, now the Sarno, Plin. 3, 5, 9, § 62; Verg. A. 7, 738; Sil. 8, 539; Stat. S. 1, 2, 265. Sărōnĭcus sĭnus, the Saronic Gulf"},"sarpo":{"lemma":"sarpo","pos":"v.","gen":"","def":", sarptum, 3, v. a. root sarp-; Gr. ἁρπάζω"},"sarrastes":{"lemma":"Sarrastes","pos":"","gen":"","def":", a people of Campania, near the Sarnus, Verg. A. 7, 738; Sil. 8, 538. sarrio (sario), ŭi and īvi (the former in Cato, R. R. 161, 2; the latter in Col. 11, 2, 10), ītum, 4, v. a."},"sartor":{"lemma":"sartor","pos":"","gen":"","def":"sarcio, a patcher, botcher, mender, Non. 7, 28: sartoris arte se pascere, Aug. Civ. Dei, 22, 8, n. 10."},"sartrix":{"lemma":"sartrix","pos":"","gen":"","def":"sartor, she who patches or mends, Cael. Aur. Acut. 3, 9, 100. sartūra, ae, f. sarcio, a patching, mending, Col. 4, 26, 2: sarturae veteris lintei, Sen. Vit. Beat. 25, 2. sartūra, ae, f."},"saserna":{"lemma":"Saserna","pos":"","gen":"","def":", a friend of Antony, Cic. Phil. 13, 13, 28; id. Att. 15, 2, 3.— Sasernae, father and son, Latin writers on agriculture, Varr. R. R. 1, 16, 5; 1, 18, 2; 5, 2, 22"},"satraps":{"lemma":"satraps","pos":"","gen":"","def":"satrapes init. Satrĭcum, i, n., an ancient town in Latium, on the Appian Way, near Antium, now Casale di Conca, Cic. Q. Fr. 3, 1, 2, § 4; Liv. 2, 39; 6, 8; 6, 22"},"satum":{"lemma":"satum","pos":"","gen":"","def":", = σάτον, a Hebrew measure of corn, etc., containing about a modius and a half (eccl. Lat.), Vulg. Gen. 18, 6; id. Matt. 13, 33"},"saucaptis":{"lemma":"saucaptis","pos":"","gen":"","def":", a fictitious spice, Plaut. Ps. 3, 2, 43 Ritschl (al. sancaptis). saucĭātĭo, ōnis, f. saucio, a wounding, Cic. Caecin. 15, 43. saucĭĕtas, ātis, f. saucius, a hurting, hurt, Cael. Aur. Tard. 2"},"sauillum":{"lemma":"savillum","pos":"","gen":"-cake","def":"suavis, a cheese-cake, Cato, R. R. 84. sāvĭo, sāvĭŏlum, sāvĭor, sāvĭ-um, v. suav-. Sāvus (Saus), i, m., = Σαοῦος, a river in Pannonia, a tributary of the Danube, now the Save, Claud. Laud. Stil. 2"},"saulus":{"lemma":"Saulus","pos":"","gen":"","def":", Saul, the name of St. Paul before his conversion, Prud. Ench. 186; Arat. A. Ap. 1, 709; Vulg. Act. 9, 1 et saep. saumārĭus, a late form for sagmā-rĭus, Ven. Fort. v. Germ. 3."},"saurea":{"lemma":"Saurea","pos":"","gen":"","def":", the name of a slave, Plaut. As. 2, 1, 16. saurĭon, i, n., = σαύριον, mustard, Plin. 19, 8, 54, § 171. saurītis, is, f., = σαυρῖτις (lizardstone), a precious stone, otherwise unknown, Plin. 37, 10"},"saurix":{"lemma":"saurix","pos":"","gen":"","def":"sorix. Saūroctŏnos, i, m., = Σαυροκτόνος, the lizard-killer, an epithet of Apollo; hence, Apollo Sauroctonos, a statue by Praxiteles, Plin. 34, 8, 19, § 70"},"saxa":{"lemma":"Saxa","pos":"","gen":"","def":", a surname of L. Decidius, a partisan of Coesar, Caes. B. C. 1, 66; Cic. Phil. 10, 10, 22; 11, 5, 12"},"saxo":{"lemma":"Saxo","pos":"","gen":"","def":", a Saxon; acc. Saxona, Claud. Laud. Stil. 2, 255; id. Epith. Pallad. et Cel. 89; abl. Saxone, id. IV. Cons. Hon. 31; id. Nupt. Hon. et Mar. 219"},"scaena":{"lemma":"scaena","pos":"","gen":"","def":"Prol. in Verg. p. 387 Rib.), f., = σκηνή. Lit., the stage, boards, scene of a theatre: dum histrio in scaenă siet, Plaut. Poen. prol. 20: in scaenă esse Roscium intellegat, Cic. Brut. 84"},"scaeua":{"lemma":"scaeva","pos":"","gen":"","def":", v. scaevus."},"scaeuus":{"lemma":"scaevus","pos":"adj.","gen":"","def":"kindred with Sanscr. savya, laevus, sinister, as the Gr. σκαιός and the Germ. schief, oblique, left, that is on the left, towards the left side (rare; most freq. in Appul."},"scaldis":{"lemma":"Scaldis","pos":"","gen":"","def":", the Scheldt, a river of Gallia Belgica; acc. Scaldem, Caes. B. G. 6, 33 Oud. N. cr.: Scaldim, Plin. 4, 14, 28, § 98; abl. Scalde, id. 4, 17, 31, or Scaldi, ib. scălēnus, a, um, adj., = σκαληνός"},"scalmus":{"lemma":"scalmus","pos":"","gen":"-pin","def":", = σκαλμός, a peg to which an oar was strapped; a thole, tholepin, Vitr. 10, 8 med.; Cic. Brut. 53, 197; id. de Or. 1, 38, 174"},"scalpellum":{"lemma":"scalpellum","pos":"","gen":"-pellus","def":"(collat. form scal-pellus, i, m., Cels. 2, 10 twice), dim. scalprum, a small surgical knife, a scalpel, a lancet: scalpellum adhibere, Cic. Sest. 65, 135; id. Div. 2, 46, 96; Col. 6, 32, 3"},"scalper":{"lemma":"scalper","pos":"","gen":"","def":"scalprum."},"scalpo":{"lemma":"scalpo","pos":"v.","gen":"","def":"a. root skalp-; Gr. σκάλοψ, mole; Lat. talpa; cf. scalprum; also Gr. γλύφω. To cut, carve, scrape, scratch, engrave (class.; syn. caelo), said of surface work, = ξέειν"},"scalprum":{"lemma":"scalprum","pos":"","gen":"-knife","def":"(collat. form scalper, ri, m., Cels. 8, 3) , a sharp cutting instrument; a chisel, knife, etc., of sculptors, husbandmen, shoemakers, surgeons, etc., Liv. 27, 49; Col. 4, 25, 1; Hor. S. 2, 3, 106"},"scalptor":{"lemma":"scalptor","pos":"","gen":"","def":"id., a cutter, graver in metal or stone (cf. sculptor), Vell. 1, 17, 4; Plin. 20, 13, 51, § 134; 36, 6, 5, § 44"},"scambus":{"lemma":"scambus","pos":"adj.","gen":"-legged","def":", = σκαμβός, bow-legged, bandy-legged (pure Lat. varus), Suet. Oth. 12. scămellum, i, v. scamillus. scămillus, i, m. (acc. to Prisc. p. 615 P., scămellum, i, n.) dim. scamnum"},"scamma":{"lemma":"scamma","pos":"adv.","gen":"-place","def":", = σκάμμα, a wrestling-place in the Palaestra. Lit. (late Lat.), Cael. Aur. Tard. 2, 1 fin.; Hier. Joann. Hieros. 16; id. Ep. 61, 5"},"scamnum":{"lemma":"scamnum","pos":"","gen":"-num","def":"for scap-num; root skap-; Gr. σκήπτω, to support; cf.: scabellum, scapus, scipio, a bench, stool, step, etc. In gen.: quă simplici scansione scandebant in lectum non altum, scabellum"},"scandila":{"lemma":"Scandila","pos":"","gen":"","def":", an island near Euboea, now Skantzoura, Plin. 4, 12, 23, § 72 (al. Scandira); Mel. 2, 7. Scandĭnāvĭa, ae, f., a large and fruitful island in Northern Europe; acc. to some, Zealand"},"scandix":{"lemma":"scandix","pos":"","gen":"","def":", = σκάνδιξ, the herb chervil: Scandix caerefolium, Linn.; Plin. 21, 15, 52, § 89; 22, 22, 38, § 81. scando (no perf. or sup."},"scapus":{"lemma":"scapus","pos":"","gen":"-beam","def":"root skap-; Gr. σκήπτω, to prop, σκῆπτρον; Doric, σκᾶπος; cf.: scipio, scamnum, scopus; Engl. shaft, a shaft, stem, stalk, trunk, etc. In gen., Varr. R. R. 1, 31, 5; Col. 9, 4, 4"},"scaurus":{"lemma":"Scaurus","pos":"adj.","gen":"","def":"1. scaurus, a frequent surname in the gens Aemilia and Aurelia. So, M. Aemilius Scaurus, whom Cicero defended in an oration, part of which is still extant.—Hence, Scaurĭānus, a, um, adj."},"schisma":{"lemma":"schisma","pos":"","gen":"","def":", = σχίσμα, a split, separation, disunion, schism (eccl. Lat.), Tert. Praescr. 5; Prud. στεφ. 11, 19; 11, 30"},"schistos":{"lemma":"schistos","pos":"adj.","gen":"","def":", = σχιστός, split, cleft, divided; a t. t. in Pliny the Elder: lapis, that easily cleaves or cracks, fissile, schistose, a name given to a kind of red oxide of iron, Plin. 29, 6, 38, § 124"},"schoeneus":{"lemma":"Schoeneus","pos":"adj.","gen":"-n","def":", = Σχοινεύς, a king of Boeotia, father of Atalanta, Hyg. Fab. 244; 246.—Hence, Schoenēïs, ĭdis, f., the daughter of Schoeneus, Atalanta, Ov. H. (15) 16, 263"},"schoenis":{"lemma":"Schoenis","pos":"","gen":"","def":"Schoeneus, C. schoenŏbătes, ae, m., = σχοινοβάτης, a rope-dancer, Juv. 3, 77."},"schoenus":{"lemma":"schoenus","pos":"","gen":"","def":"(neutr. collat. form schoenum, Col. 12, 20, 2 and 5, somewhat dub.), = σχοῖνος, ὁ. A rush, of an aromatic kind (pure Lat. juncus), used by the Romans to season wine, Cato, R. R. 105, 2; 113, 1"},"scindo":{"lemma":"scindo","pos":"v.","gen":"-class","def":"redupl. scicidi, Enn., Naev., Att, and Afran. ap. Prisc. p. 890 P.; or Enn. p. 133 Vanl.; Com. Rel. pp. 19 and 164 Rib.; cf. also, sciciderat. Gell 6, 9, 16), v. a. akin to Gr. σχίζω, to split"},"scintilla":{"lemma":"scintilla","pos":"","gen":"","def":"dim. kindr. with σπινθήρ, a spark (class.). Lit.; sing.: videmus Accedere ex unā scintillā incendia passim, Lucr. 5, 609; 4, 606; Verg. A. 1, 174; Ov. M. 7, 80"},"scintillo":{"lemma":"scintillo","pos":"v.","gen":"","def":"n. scintilla, to sparkle, glitter, glow, gleam, flash (poet. and in post-Aug. prose"},"scirros":{"lemma":"scirros","pos":"","gen":"","def":", = σκίρρος, a hard swelling or tumor, Plin. 7, 15, 13, § 63. scirrōsis, is, f., = σκίρρωσις, a hardening in the flesh, = saxitas, Cael. Aur. Tard. 3, 4, 49. sciscĭtātĭo, ōnis, f. sciscitor"},"scissim":{"lemma":"scissim","pos":"adv.","gen":"","def":"id., by rending, cleaving, or dividing (late Lat.), Prud. Enchir. Vet. Test. 9. scissĭo, ōnis, f. id., a cleaving, dividing, scission of a number (late Lat.), Macr. Somn. Scip. 1, 6"},"scissis":{"lemma":"Scissis","pos":"","gen":"","def":", a town of Hispania Tarraconensis, probably in the territory of the Lacetani, Liv. 21, 60 fin."},"scissor":{"lemma":"scissor","pos":"","gen":"","def":"scinde. One who cleaves or divides, a carver, Petr. 36, 6.— A kind of gladiator, Inscr. Orell. 2569. scissūra, ae, f. id., a tearing, rending, dividing"},"scodra":{"lemma":"Scodra","pos":"","gen":"","def":", a town of Dalmatia, now Scutari, on Lake Labeatis, Liv. 44, 31; 44, 32; 45, 26; Plin. 3, 22, 26, § 144.—Hence, Scodrenses, ium, m., the inhabitants of Scodra, Liv. 45, 26."},"scodrus":{"lemma":"Scodrus","pos":"","gen":"","def":"Scordus. scŏla, v. schola. scōlēcĭa, v. scolex. scōlēcĭon, ii, n., = σκωλήκιον, a kind of scarlet berry (which is apt to be wormeaten), Plin. 24, 4, 4, § 8. scōlex, lēcis, m., = σκώληξ"},"scomber":{"lemma":"scomber","pos":"","gen":"","def":", = σκόμβρος, a kind of tunny, a mackerel: Scomber scomber, Linn.; Plin. 9, 15, 19, § 49; 31, 8, 43, § 94; 32, 11, 53, § 151; Col. 8, 17, 12; Plaut. Capt. 4, 2, 71; Cat. 95, 8; Pers. 1, 43"},"scomma":{"lemma":"scomma","pos":"","gen":"","def":", = σκῶμμα, a teasing, taunting expression; a taunt,jeer, scoff, cavil (late Lat. for convicium, maledictum), Macr. S. 7, 3. scōpa, ae, and plur.: scōpae, ārum (cf. on plur., Varr. L. L. 8, § 7 Müll."},"scordisci":{"lemma":"Scordisci","pos":"","gen":"","def":"A people on the borders of Illyria, Liv. 40, 57; 41, 19; id. Epit. 56.— A people of Pannonia, Plin. 3, 25, 28, § 148; Just. 32, 3, 5. scordŏtis, v. scordion."},"scordus":{"lemma":"Scordus","pos":"","gen":"","def":", a mountain of Illyria, Liv. 43, 20, 1.—Called also Scodrus, Liv. 44, 31, 4. scōrĭa, ae, f., = σκωρία, dross, slag, scoria of metals, Plin. 33, 4, 21, § 69; 33, 6, 35, § 105; 34, 11, 24, § 107"},"scoria":{"lemma":"scoria","pos":"n. f.","gen":"-ae","def":"dross, slag, scum from smelted ore"},"scorpaena":{"lemma":"scorpaena","pos":"","gen":"-scorpion","def":", = σκόρπαινα, a sea-scorpion, Plin. 32, 11, 53, § 151"},"scortillum":{"lemma":"scortillum","pos":"","gen":"","def":"dim. scortum, II., a little or young harlot, Cat. 10, 3; cf. ‡ scortulum."},"scortor":{"lemma":"scortor","pos":"v.","gen":"-class","def":"scortarier, Plaut. Merc. 5, 4, 58), v. dep. n. , to employ or associate with harlots (ante- and post-class.): scortari est saepius meretriculam ducere, Varr. L. L. 7, § 84 Müll.; Plaut. As. 2, 2, 4"},"scortum":{"lemma":"scortum","pos":"pron.","gen":"-class","def":"cf. Gr. χόριον, corium"},"scriplum":{"lemma":"scriplum","pos":"","gen":"","def":"scrupulus, I. B. scriptĭlis, e, adj. scribo, that can be written (post-class.): elementa, Amm. 17, 4, 15: elementorum viginti quattuor scriptiles formae incisae perite, letters, id. 29, 1"},"scriptor":{"lemma":"scriptor","pos":"","gen":"","def":"scribo, one who writes. In gen. (acc. to scribo, I.), a writer, scribe, secretary (syn. librarius; very rare): addebat etiam, scriptores illos male multatos exisse cum Galbā, Cic. Brut. 22, 88"},"scriptum":{"lemma":"scriptum","pos":"","gen":"","def":"scribo fin. scriptūra, ae, f. scribo, a writing, written characters. In gen. (acc. to scribo, I."},"scriptus":{"lemma":"scriptus","pos":"","gen":"","def":"scribo, the office of a scribe or secretary, a clerkship, secretaryship (rare): quem aliquanto ante desisse scriptum facere arguit, etc., Liv. 9, 46"},"sculna":{"lemma":"sculna","pos":"","gen":"","def":"contr. from seculna, in vulg. lang. = sequester, a mediator, arbiter, umpire, Lavin. and Varr. ap. Gell. 20, 11, 2; Macr. S. 2, 13 fin."},"sculpo":{"lemma":"sculpo","pos":"v.","gen":"","def":"a. cf. γλύφω, to hollow out, grave; also scalpo, γλάφω, to carve, cut, grave, chisel in stone, brass, wood, etc.; to form, fashion, or produce by carving, graving, etc. (very rare but class."},"sculptor":{"lemma":"sculptor","pos":"","gen":"-cutter","def":"id., one who cuts, carves, or engraves in stone, wood, etc. (cf.: fictor, plastes), a stone-cutter, graver, sculptor, Plin. 29, 6, 38, § 132; 36, 5, 4, § 11 (Jahn reads throughout scalptor)"},"scultenna":{"lemma":"Scultenna","pos":"","gen":"","def":", a river of Upper Italy, near Mutina, flowing into the Po, now Panaro, Liv. 41, 12 and 18; Plin. 3, 16, 20, § 118."},"scurra":{"lemma":"scurra","pos":"","gen":"-bred","def":"Orig., an elegant, town-bred man; a fine gentleman, gallant, dandy: tu urbanus vero scurra, deliciae popli, Rus mihi tu objectas? Plaut. Most. 1, 1, 14; cf. (opp. militaris) id. Ep. 1, 1, 13"},"scurror":{"lemma":"scurror","pos":"v.","gen":"","def":"dep. n. , to act the part of a jester"},"scutriscum":{"lemma":"scutriscum","pos":"","gen":"","def":"dim. scutra, a little dish, Cato, R. R. 10, 2; 11, 3. scŭtŭla, ae, f. dim. scutra; cf. scutella. Lit., a little dish or platter of a nearly square form (cf. lanx), Cato, R. R. 68, 1; Mart. 11, 31, 19"},"scydra":{"lemma":"Scydra","pos":"","gen":"","def":", a city of Macedonia, Plin. 4, 10, 17, § 34. Scylăcē, ēs, f., = Σκυλάκη, a city of Asia Minor, near Cyzicus, Mel. 1, 19, 2"},"scylax":{"lemma":"Scylax","pos":"","gen":"","def":", a native of Halicarnassus, and friend of Panoetius, Cic. Div. 2, 42, 88."},"scylla":{"lemma":"Scylla","pos":"adj.","gen":"-monster","def":", = Σκύλλα. A celebrated rock between Italy and Sicily, opposite to Charybdis: Scylla saxum est, Charybdis mare, utrumque noxium appulsis, Mel. 2, 7, 14"},"scyllaeus":{"lemma":"Scyllaeus","pos":"","gen":"","def":"Scylla, I. and II."},"scymnus":{"lemma":"scymnus","pos":"","gen":"","def":", = σκύμνος, a young animal, a cub, whelp: leonum, Lucr. 5, 1036. scyphŭlus, i, m. dim. scyphus, a small cup, Paul. Nol. Carm. 26, 463."},"scyphus":{"lemma":"scyphus","pos":"","gen":"","def":", = σκύφος, a cup, goblet (cf.: calix, poculum), Plaut. As. 2, 4, 38; Varr. ap. Gell. 3, 14, 3; Cic. Verr. 2, 4, 14, § 32; Tib. 1, 10, 8; Verg. A. 8, 278; Hor. C. 1, 27, 1; id. Epod. 9, 33 al."},"scytha":{"lemma":"Scytha","pos":"adj.","gen":"-th","def":", and Scythes, ae, m., = Σκύθης, a Scythian; sing. form Scytha, Phaedr. 3, prol. 52; Luc. 10, 454; Vulg. Col. 3, 11; cf. Lact. 3, 25, 18; Tac. A. 2, 60; form Scythes (class.), Cic. Tusc. 5, 32, 90"},"scythes":{"lemma":"Scythes","pos":"","gen":"","def":"Scytha. Scythĭcē, ēs, v. Scytha, C. fin. Scythŏpŏlis, is, f., = Σκυθόπολις, a town of Palestine, now Bysān, Plin. 5, 18, 16, § 74"},"scyzinum":{"lemma":"scyzinum","pos":"","gen":"","def":", a kind of wine, called also itaeomelis, Plin. 14, 16, 19, § 111. sē, pron. reflex., v. sui. sē (sēd). Prep., v. sine init.— Prep. insepar. For sine, without"},"secta":{"lemma":"secta","pos":"part.","gen":"","def":"part. perf. of seco, sc. via, v. seco, I. C. 2., and II. B. fin.; prop., a trodden or beaten way, a path; footsteps"},"sector":{"lemma":"sector","pos":"","gen":"","def":"id., one who cuts or cuts off, a cutter (rare but class.). Lit.: zonarius, a cutpurse, Plaut. Trin. 4, 2, 20: collorum, a cutthroat, Cic. Rosc. Am. 29, 80 (v. II.)"},"sectrix":{"lemma":"sectrix","pos":"","gen":"","def":"id., she that purchases confiscated goods: proscriptionum, Plin. 36, 15, 24, § 116. sectūra, ae, f. seco, a cutting (very rare). Lit.: scutum a secturā, Varr. L. L. 5"},"sedda":{"lemma":"sedda","pos":"","gen":"","def":"sella init. sēdĕcennis, e, adj. sedecim-annus, sixteen years old: matrona, Aus. Epit. 32 in lemm. sē-dĕcĭes, num. adv. , sixteen times: sedecies ad eorum filios sedecies computatos, Dig. 38, 10, 10"},"sedusii":{"lemma":"Sedusii","pos":"","gen":"","def":", a people of Germany, Caes. B. G. 1, 51. sĕgĕs, ĕtis, f. etym. dub.; perh. root sag-, to fill, feed; Gr. σάττω"},"segestes":{"lemma":"Segestes","pos":"","gen":"-in","def":", a German prince, father-in-law of Arminius, and friend of the Romans, Tac. A. 1, 55"},"segmen":{"lemma":"segmen","pos":"","gen":"","def":"seco, what is cut off, a cutting, shred, little bit (very rare): unguium et capilli segmina, Fab. Pictor ap. Gell. 10, 15, 15: nulli secabile segmen, i. e. atom, Aus. Ecl. 1"},"segmentum":{"lemma":"segmentum","pos":"","gen":"","def":"seco, a cutting, cut; a piece cut off, a slice (not ante-Aug.; mostly in the plur."},"segnesco":{"lemma":"segnesco","pos":"v.","gen":"","def":"n. segnis, to become slow; to abate, decrease, Cael. Aur. Acut. 2, 18, 110."},"segni":{"lemma":"Segni","pos":"","gen":"","def":", a German tribe in Gallia Belgica, between the Eburones and Treviri, now Signei, near Condroy, Caes. B. G. 6, 32. segnĭ-pēs, pĕdis, m. segnis, slowfool, a poet. designation of a worn-out horse"},"segnis":{"lemma":"segnis","pos":"adj.","gen":"-flowing","def":"commonly referred to sequor, that follows after, creeps after, slow, tardy, slack, dilatory, lingering, sluggish, inactive, unenergetic, lazy (in posit. not freq. till after the Aug. per."},"segullum":{"lemma":"segullum","pos":"","gen":"","def":"segutilum. Sĕgūsĭāvi, ōrum, m., = Σεγοσιανοί or Σεγουσιανοί, a people in Gallia Lugdunensis, neighbors of the Allobroges and Aedui, in the mod. Feurs (Dép. de la Loire), Caes. B. G. 1, 10 fin.; 7, 64"},"sembella":{"lemma":"sembella","pos":"","gen":"-libella","def":"contr. from semi and libella, a half-libella (a coin): sembella quod libellae dimidium, quod semis assis, Varr. L. L. 5, § 174 Müll.: eandem rationem habere assem ad semissem"},"semnion":{"lemma":"semnion","pos":"","gen":"","def":", a plant of great virtue, = theobrotion, Plin. 24, 17, 102, § 162. Semnŏ_nes, um, m., = Σέμνωνες, Strab."},"semper":{"lemma":"semper","pos":"adv.","gen":"-per","def":"root sam-; Gr. ἁμ-; v. semel and -per = παρά"},"seniae":{"lemma":"Seniae","pos":"","gen":"","def":": balneae, the name of a public bath at Rome, Cic. Cael. 25, 62 (this the correct read., not Xeniae). sĕnĭca, ae, m. or f. senicus"},"sensa":{"lemma":"sensa","pos":"","gen":"","def":"sentio fin. sensātus, a, um, adj. 2. sensus, gifted with sense, intelligent: homines (with callidi and astuti), Firm. Math. 3, 10; 5, 12"},"sensim":{"lemma":"sensim","pos":"adv.","gen":"","def":"sentio (prop. sensibly, i. e. perceptibly, observably, visibly; hence, as opp. to what is unforeseen, unexpected, sudden), slowly, gently, soflly, gradually (freq. and class."},"sensus":{"lemma":"sensus","pos":"","gen":"","def":"sentio, the faculty or power of perceiving, perception, feeling, sensation, sense, etc. Corporeal, perception, feeling"},"senta":{"lemma":"Senta","pos":"","gen":"","def":", a place in Dalmatia, noted for a curious cavern, Plin. 2, 45, 44, § 115. sententĭa, ae, f. for sentientia, from sentio, a way of thinking, opinion, judgment, sentiment"},"sentis":{"lemma":"Sentis","pos":"","gen":"","def":"Sentinas."},"sentisco":{"lemma":"sentisco","pos":"","gen":"","def":"inch. n. , to perceive, note, observe (Lucretian), Lucr. 3, 392; 4, 586."},"sentius":{"lemma":"Sentius","pos":"","gen":"","def":", the name of a Roman gens. Sentius Saturninus, a proproetor in Macedonia, A. U.C. 671, Cic. Verr. 2, 3, 93, § 217; id. Pis. 34, 84.— Cn. Sentius, a governor of Syria, Tac. A. 2, 74; 3, 7."},"sentix":{"lemma":"sentix","pos":"","gen":"","def":"sentis, the plant cynosbatos or sentis canis, dog rose, wildbrier, App. Herb. 87, Isid. Orig. 17, 7, 59 sq. sentōsus (-tŭōsus), a, um, adj. id., full of thorns, thorny (late Lat.), Paul. Nol. Carm. 6"},"sentus":{"lemma":"sentus","pos":"adj.","gen":"","def":"id., Lit., thorny, rough, rugged (poet. and very rare): loca senta situ, * Verg. A. 6, 462"},"seps":{"lemma":"seps","pos":"adv.","gen":"-louse","def":", = σήψ. A venomous serpent, whose bite occasioned putrefaction, Luc. 9, 764 sq.; 9, 723.—Acc. sing. sepa, Plin. 29, 5, 32, § 102.—Acc. Plur. sepas, Plin. 23, 2, 29, § 61"},"sepse":{"lemma":"sepse","pos":"pron.","gen":"","def":"reflex. fem. , one's self. quae (virtus) omnes magis quam sepse diligit, Cic. Rep. 3, 8 (also cited by Sen. Ep. 108, 32)."},"septa":{"lemma":"septa","pos":"","gen":"","def":", v. saepio fin."},"septages":{"lemma":"septages","pos":"","gen":"","def":"Indian, = ψίττακος, a parrot, Plin. 10, 41, 58, § 117. ‡† septăs, ădis, f. ἑπτάς, the number seven, acc. to Macr. Somn. Scip. 1, 6 med. septĕjŭgis, is, m. (sc. currus) , a team of seven"},"septem":{"lemma":"septem","pos":"adj.","gen":"-stars","def":"adj. indecl. [Sanscr. saptan; Gr. ἑπτά; Goth. sibun; Germ. sieben"},"septem-nerua":{"lemma":"septem-nerva","pos":"","gen":"-nerva","def":"septem-nervus, an herb, called also plantago, App. Herb. 1. septem-pĕdālis, e, adj., of seven feet, seven feet high: statua, Plaut. Curc. 3, 71."},"septem-plex":{"lemma":"septem-plex","pos":"adj.","gen":"-plex","def":"plico, sevenfold (poet.): clipeus (consisting of layers of ox-hides, the Homer. ἑπταβόειον σάκος, Il. 7, 220 sq.), Verg. A. 12, 925"},"september":{"lemma":"September","pos":"adj.","gen":"-ber","def":"septem; as, October, Novem-ber, Decem-ber; cf. Varr. L. L. 6, § 34 Müll., the seventh month of the Roman year, reckoning from March, i. e. our ninth, September (consisting, as now, of thirty days)"},"septemuir":{"lemma":"septemvir","pos":"","gen":"","def":"septemviri. septemvĭrālis, e, adj. septemviri, of or belonging to the septemvirs, septemviral: auctoritas, Cic. Phil. 12, 9, 23.— Subst.: septemvĭrāles, ĭum, m., the septemvirs, Cic. Phil. 13, 12"},"septennis":{"lemma":"septennis","pos":"","gen":"","def":"septuennis. septennĭum, ii, v. septuennium. septentrĭo, ōnis, v. septentriones. septentrĭōnālis, e, adj. septentriones, II., of or belonging to the north, northern, north-: pars (terrae), circulus"},"septingenti":{"lemma":"septingenti","pos":"adj.","gen":"","def":"adj. septemcentum, seven hundred: anni, Enn. ap. Varr. R. R. 3, 1, 2 (Ann. v. 493 Vahl.)"},"septio":{"lemma":"septio","pos":"","gen":"","def":"saeptio. septĭ-pēs, pĕdis, adj. septem, sevenfoot; hence, poet., excessively tall, gigantic (late Lat.): Burgundio, Sid. Ep. 8, 9 in carm."},"septum":{"lemma":"septum","pos":"","gen":"","def":"saeptum; s. v. saepio."},"septunx":{"lemma":"septunx","pos":"","gen":"-uncia","def":"septem-uncia; cf. Varr. L. L. 5, § 171 Müll.. Lit., seven twelfths of a whole (v. as, 1.): jugeri, Col. 5, 1, 11"},"sepyra":{"lemma":"Sepyra","pos":"","gen":"","def":", a village in Cilicia, on Mount Amanus, Cic. Fam. 15, 4, 9. sĕquācĭtas, ātis, f , a facility in following, a disposilion to follow, sequaciousness, sequacity (late Lat.): saltuosa scribarum"},"serdica":{"lemma":"Serdica","pos":"adj.","gen":"-dicensis","def":", a city of Moesia, Cassiod. Hist. Eccl. 4, 21.—Hence, Ser-dicensis, e, adj., Serdican, of Serdica: concilium, Cassiod. Hist. Eccl. 4, 24.— Serdicēnus, a, um, adj., Serdican, of Serdica"},"sergestus":{"lemma":"Sergestus","pos":"","gen":"","def":", a steersman among the followers of Aeneas; acc. to Vergil, the ancestor of the Sergian family, Verg. A. 1, 510; 5, 121; 5, 184; 5, 221 et saep. Sergĭus, i, m."},"sermo":{"lemma":"sermo","pos":"","gen":"","def":"2. sero, qs. serta, conserta oratio, a speaking or talking with any one"},"serpens":{"lemma":"serpens","pos":"","gen":"","def":"serpo fin. serpentārĭa, ae, f. (sc. herba) , snakeweed, otherwise called veperina, App. Herb. 5. serpentĭgĕna, ae, m. serpens-gigno, serpent-born, i. e. sprung from a serpent, Ov. M. 7"},"serpillum":{"lemma":"serpillum","pos":"","gen":"","def":"serpyllum. serpo, psi, ptum, 3 (serpsit antiqui pro serpserit usi sunt, Fest. p. 348 Müll.), v. n. root serp, kindr. with ἕρπω, repo, to creep, crawl (freq. and class.). Lit. (only of animals"},"serpullum":{"lemma":"serpullum","pos":"","gen":"","def":"serpyllum init. serpyllĭfer, fĕra, fĕrum, adj. serpyllum-fero, thyme-bearing: catinae, Sid. Ep. 8, 11 in carm. serpyllum or serpillum (Varr. L. L. 5, § 103 Müll. p. 30 Bip."},"serra":{"lemma":"serra","pos":"","gen":"","def":"perh. = sec - ra, seg - ra, from seco. A saw, the invention of Daedalus, Ov. M. 8, 246; Sen. Ep. 90, 8; Plin. 7, 56, 57, § 198"},"serrapilli":{"lemma":"Serrapilli","pos":"","gen":"","def":", a people of Pannonia, on the Danube, Plin. 3, 25, 28, § 147. serrātim, adv. serra, in the manner of a saw, like a saw, Vitr. 6, 11: scissa folia, App. Herb. 2. serrātōrĭus, a, um, adj. serro"},"serretes":{"lemma":"Serretes","pos":"","gen":"","def":", a people of Pannonia, on the Danube, Plin. 3, 25, 28, § 147. Serrhēum (-rhīum, -rīum), i, n., a promontory in Thrace, with a fortification: alia castella, Cypsela et Doriscon et Serrheum, Liv. 31"},"serro":{"lemma":"serro","pos":"v.","gen":"","def":"a. serra, to saw, to saw up, saw in pieces (late Lat.): pali serrantur, Veg. Mil. 2, 25; Hier. in Isa. 15, 57, 1; Vulg. Isa. 41, 15"},"serta":{"lemma":"serta","pos":"","gen":"","def":"2. sero, I. B. serta Campānĭca, or simply serta, ae, f., a plant, called also melilotos, Cato, R. R. 107; 113.—Also called ser-tŭla Campāna, Plin. 21, 9, 29, § 53. sertātus, a, um, adj. 1. serta"},"sertor":{"lemma":"Sertor","pos":"","gen":"","def":", a Latin proenomen [of disputed origin; perh. 2. sero], Fest. p. 340, 22 Müll."},"sertum":{"lemma":"sertum","pos":"","gen":"","def":"2. sero, I. B. sertus, a, um, Part. of 2. sero. sĕrum, i, n. (collat. form sĕrū, acc. to Charis. p. 23 P.) . The watery part of curdled milk, whey, Plin. 11, 41, 96, § 239; 28, 9, 33, § 126"},"serua":{"lemma":"serva","pos":"","gen":"","def":"servus. servābĭlis, e, adj. servo. * That can be kept or preserved, preservable: uva sine ullis vasis, Plin. 14, 3, 4, § 40.—* That can be saved or rescued: caput nulli, Ov. Tr. 4, 5, 21. servācŭlum"},"seruus":{"lemma":"servus","pos":"adj.","gen":"-class","def":"referred by the ancients to servo: servi ex eo appellati sunt, quod imperatores servos vendere, ac per hoc servare, nec occidere solent, Just. Inst. 1, 3, 3; but prob. from root svar-"},"sesquunx":{"lemma":"sesquunx","pos":"","gen":"","def":"sescuncia. Sessĭa, ae, v. Sesia. sessĭbŭlum, i, n. sedeo, a seat, chair (ante- and post-class.), Plaut. Poen. 1, 2, 56"},"sessor":{"lemma":"sessor","pos":"","gen":"","def":"sedeo, one who sits in a place, a sitter (not ante-Aug. and very rare). In gen., a sitter in the theatre, Hor. Ep. 2, 2, 130.— A sitter upon a horse, a horseman, rider, Sen. Const. 12 fin."},"sessus":{"lemma":"sessus","pos":"","gen":"","def":"id., a sitting: locum sessui impertiunt, App. Flor. p. 353, 36. sestertĭārĭus, a, um, adj. sestertius, worth but a sesterce"},"set":{"lemma":"set","pos":"","gen":"","def":"sed init. sēta, v. saeta. Sētăbis, v. Saetabis. sētănĭa, ae, f., and sētănĭum (-on), i, n., = σητανία and σητάνιον. The name of a kind of medlar: setania, Plin. 15, 20, 22"},"seu":{"lemma":"seu","pos":"adv.","gen":"","def":", v. sive. sĕvērē, adv., v. 1, severus fin. A. sĕvērĭtas, ātis, f. 1. severus, seriousness, gravity, sternness, strictness, severity, in a good and bad sense (class. and very freq."},"seuo":{"lemma":"Sevo","pos":"","gen":"","def":", a mountain of northern Germany, in the island of Scandia, the mod. Kjölen, between Sweden and Norway, Plin. 4, 13, 27, § 90"},"sexcenti":{"lemma":"sexcenti","pos":"","gen":"","def":"sescenti. sexcentĭes, v. sescenties. Sexcentŏ-plāgus, v. Sescentoplagus. sexdĕcim, v. sedecim."},"sexennis":{"lemma":"sexennis","pos":"adj.","gen":"-annus","def":"sex-annus, of six years, six years old: erus, Plaut. Poen. 4, 2, 80"},"sexis":{"lemma":"sexis","pos":"","gen":"","def":"indecl. id.. * The number six: ut ex duobus, triplo sexis implevit, Mart. Cap. 7, § 767.—* Six asses: s littera i praecedente finita neutra monoptota sunt, ut tressis, sexis, Mart. Cap. 3"},"sextans":{"lemma":"sextans","pos":"","gen":"","def":"sex. A sixth part of an as (v. as): sextans ab eo quod sexta pars assis, ut quadrans quod quarta et triens quod tertia pars, Varr. L. L. 5, § 171 Müll.: heredes in sextante, Cic. Fam. 13, 29"},"sextus":{"lemma":"sextus","pos":"adj.","gen":"","def":"ord. adj. , the sixth, Plaut. Ps. 4, 2, 5: sextus ab urbe lapis, Ov. F. 2, 682: sextus decimus ab Hercule, Vell. 1, 6, 5: hic annus sextus, postquam ei rei operam damus, Plaut. Men. 2, 1, 9"},"sexuir":{"lemma":"sexvir","pos":"","gen":"","def":"sevir. sī (orig. and ante-class. form seī), conj. [from a pronominal stem = Gr. ἑ; Sanscr. sva-, self; cf. Corss. Ausspr. 1, 778"},"sibonis":{"lemma":"sibonis","pos":"","gen":"","def":", = sibina, Gell. 10, 25, 2. sibus, callidus sive acutus, Fest. p. 336 Vahl."},"sicca":{"lemma":"Sicca","pos":"","gen":"-town","def":", a border-town on the east of Numidia, with a temple of Venus, now Kef, Plin. 5, 3, 2, § 22; Sall. J. 56, 3"},"siccenses":{"lemma":"Siccenses","pos":"","gen":"","def":"Sicca."},"siccesco":{"lemma":"siccesco","pos":"","gen":"","def":"inch. n. , to grow or become dry, to dry up (not anteAug.), Cels. 7, 7, 15; Vitr. 2, 10; Col. 12, 28"},"sicco":{"lemma":"sicco","pos":"v.","gen":"","def":"a. and n. id.. Act., to make dry, to dry, to dry up. In gen. (freq. and class.): venti et sol siccare prius confidunt omnia posse, Lucr. 5, 390"},"siccus":{"lemma":"siccus","pos":"adj.","gen":"","def":"cf. Sanscr. cush, to dry up; Gr. αὔω, dry. Lit. In gen. (mostly poet. and in post-Aug. prose"},"sicimina":{"lemma":"Sicimina","pos":"","gen":"","def":"45, 12. sīcĭnē (less correctly, siccĭne), adv. sice, orig. form of sic, q. v., and the interrog. particle ne, so, thus"},"siclus":{"lemma":"siclus","pos":"","gen":"","def":"Heb. , a shekel (a Hebrew coin), Hier. in Ezech. 1, 4, 9; Vulg. Exod. 21, 32 et saep."},"sido":{"lemma":"Sido","pos":"","gen":"","def":", a chief of the Suevi about the middle of the first century, Tac. H. 3, 5; 3, 21; id. A. 12, 29 sq. Sīdon, ōnis (usu. ō, as in Greek"},"siggos":{"lemma":"Siggos","pos":"","gen":"","def":"Singos. sĭgilla, ōrum (sing.: SIGILLVM VOLKANI, Inscr. Marin. Fratr. Arv. p. 357"},"sigla":{"lemma":"sigla","pos":"","gen":"","def":"contr. from sigilla, signs of abbreviation, abbreviations (late Lat.): sigla in libris ponere, Just. Ep. ad Antecess. § 8: leges per siglorum obscuritates conscribere, Cod. Just. 1, 17, 2, § 22."},"sigma":{"lemma":"sigma","pos":"","gen":"-tub","def":", = σίγμα (the Greek letter sigma; hence, from its more ancient form, C). A semicircular couch for reclining at meals, Mart. 10, 48, 6; 14, 87, 2"},"signanter":{"lemma":"signanter","pos":"adv.","gen":"","def":", v. signo fin. A. signārĭus, ii, m. signum, a sculptor: ARTIFEX, Inscr. Orell. 4282. signātē, adv., v. signo, P. a. B. fin. signātĭo, ōnis, f. signo, a marking, signing: furtiva (crucis)"},"signo":{"lemma":"signo","pos":"v.","gen":"-clause","def":"a. signum, to set a mark upon, to mark, mark out, designate (syn.: noto, designo). Lit. In gen. (mostly poet. and in post-Aug. prose): discrimen non facit neque signat linea alba, Lucil. ap. Non. 405"},"signum":{"lemma":"signum","pos":"pron.","gen":"-clause","def":"perh. Sanscr. sag-, to cling to, adhere; cf. sigilla. In gen., a mark, token, sign, indication (very frequent in all styles and periods"},"sil":{"lemma":"sil","pos":"","gen":"","def":", a kind of yellowish earth, yellow ochre, Plin. 33, 12, 56, § 158; Vitr. 7, 11; Veg. 5, 26; 5, 39; 6, 28 fin."},"silana":{"lemma":"Silana","pos":"","gen":"","def":", a town of Thessaly, Liv. 36, 13. Silanĭo or Silanĭion, ōnis, m., a celebrated statuary, Cic. Verr. 2, 4, 57, § 126; Plin. 34, 8, 19, § 51"},"silaus":{"lemma":"silaus","pos":"","gen":"","def":", a kind of parsley, smallage: Apium graveolens, Linn."},"silis":{"lemma":"Silis","pos":"","gen":"","def":", the name of several rivers."},"sillybus":{"lemma":"sillybus","pos":"","gen":"","def":", = σίλλυβον, a kind of thistle, Plin. 22, 22, 42, § 85; 26, 7, 25, § 40 (but the true reading, Cic. Att. 4, 5, 3"},"silpia":{"lemma":"Silpia","pos":"","gen":"","def":", a city of Hispania Baetica, prob. Linares, Liv. 28, 12. Silŭres, um, m., = Σίλυρες, a warlike people of Britain, Plin. 4, 16, 30, § 103; Tac. A. 12, 32; id. Agr. 11 and 17"},"simpla":{"lemma":"simpla","pos":"","gen":"","def":"simplus, II. B. simplāris, e, adj. simplus"},"simplo":{"lemma":"simplo","pos":"v.","gen":"","def":"a. id., to make simple, simplify (late Lat.), Sedul. 1, 281. simplŭdĭārĕa funera sunt, quibus adhibentur duntaxat ludi, Fest. p. 334; Paul. ex Fest. p. 335 Müll. ."},"simplus":{"lemma":"simplus","pos":"adj.","gen":"-class","def":"Adj. kindr. with simplex, simple"},"sindenses":{"lemma":"Sindenses","pos":"","gen":"","def":", the inhabitants of Sinda (Σινδα), a town of Pisidia, near Cibyra and the river Caularis, Liv. 38, 15."},"sindes":{"lemma":"Sindes","pos":"","gen":"","def":"; acc. sinden, a river in Asia, Tac. A. 11, 10 Ritter (al. Gyndes)."},"sindica":{"lemma":"Sindica","pos":"","gen":"","def":", a part of Scythia on the Black Sea, Plin. 4, 12, 26, § 84."},"sindon":{"lemma":"sindon","pos":"","gen":"","def":", = σινδών, a kind of fine cotton stuff, muslin, Mart. 4, 19, 12; 11, 1, 2; Aus. Ephem. in Parecb. 2; Vulg. Matt. 27, 59; id. Marc. 14, 52"},"sindus":{"lemma":"Sindus","pos":"","gen":"","def":", an Indian name of the river Indus, Plin. 6, 20, 23, § 71. sĭne (old form sē or sēd; v. the foll.), prep. with abl. [si and ne; si, the demonstrative instrumental, and the negative ne"},"singidonensis":{"lemma":"Singidonensis","pos":"adj.","gen":"","def":", of or belonging to the town Singido in Pannonia, Aur. Vict. Epit. 44. Singĭli, ōrum, m., a city in Hispania Baetica, Plin. 3, 1, 3, § 10. singĭlĭo, ōnis, m., perh. a plain, short garment"},"singulti":{"lemma":"singulti","pos":"adv.","gen":"","def":"adv. from singultus"},"singulto":{"lemma":"singulto","pos":"v.","gen":"","def":", ātum, 1, v. n. and a. . Neutr., to hiccup; to sob: singultantium modo, Quint. 10, 7, 10.— Transf., poet., of persons dying, to rattle in the throat, Verg. A. 9, 333; Sil. 2, 362; 1, 388"},"singultus":{"lemma":"singultus","pos":"","gen":"","def":"singuli, and hence, an uttering of single sounds. Lit., a sobbing, speech interrupted by sobs (class.); sing.: multas lacrimas et fletum cum singultu videre potuisti, Cic. Planc. 31, 76"},"sinon":{"lemma":"sinon","pos":"","gen":"","def":"27, 13, 109, § 136. Sĭnon, ōnis, m., son of Aesimus, through whose perfidy the Trojans were induced to take the wooden horse within their city, Verg. A. 2, 79 sq.; Hyg. Fab. 108; Dict. Cret. 5, 12"},"sint":{"lemma":"sum","pos":"","gen":"","def":"(form of sum)"},"siphae":{"lemma":"Siphae","pos":"","gen":"","def":", a city of Boeotia, on the borders of Phocis, Plin. 4, 3, 4, § 8. Siphnĭus, v. Siphnus fin. Siphnus (-os), i, f., one of the Cyclades, now Sifano, Mel. 2, 7; Plin. 4, 12, 22, § 66"},"sipo":{"lemma":"sipo","pos":"","gen":"","def":"supo."},"sipolindrum":{"lemma":"sipolindrum","pos":"","gen":"","def":"cepolindrum. Sīpontum, i, n., = Σιποῦς (cf. Cic. Att. 6, 2, 3), an important maritime town in Appulia, now S. Maria di Siponto, Mel. 2, 4, 7; Plin. 3, 11, 16, § 103; Cic. Att. 9, 15, 1; 10, 7, 1"},"siraci":{"lemma":"Siraci","pos":"","gen":"","def":", a people of Asiatic Sarmatia, Plin. 4, 12, 26, § 83; Tac. 12, 15 and 16."},"sirae":{"lemma":"Sirae","pos":"","gen":"","def":", a town of the Odomantic region in Thrace, Liv. 45, 4. sĭraeum, i, n., = σίραιον, new wine boiled down (pure Lat. sapa), Plin. 14, 9, 11, § 80. sirbēnus, a, um, adj., = συρβηνός"},"sirbitum":{"lemma":"Sirbitum","pos":"","gen":"","def":", a city in Ethiopia, Plin. 6, 30, 35, § 194 al. Sirbonis lacus, a lake on the borders of Palestine, Plin. 5, 13, 14, § 68. sircitŭla, ae, f., a kind of grape, Col. 12, 45, 1. sircŭla, ae, f."},"siria":{"lemma":"Siria","pos":"","gen":"","def":"Syria. sīrĭăcus, a, um, adj., = σειριακός, of or belonging to the dog-star: calor, Avien. Arat. 285. sīrĭăsis, is, f., = σειρίασις, an inflammatory disease of children, siriasis"},"sirmio":{"lemma":"Sirmio","pos":"","gen":"","def":", a peninsula on the shores of the Lacus Benacus, in Upper Italy, now Sermione, Cat. 32, 1."},"sirmium":{"lemma":"Sirmium","pos":"","gen":"","def":", an important city of Pannonia Inferior, now Mitrovitz, Sid. Pan. 774"},"sirpe":{"lemma":"sirpe","pos":"","gen":"","def":"σίλφιον, a plant, called also silphium and laser, asafoetida, Plaut. Rud. 3, 2, 16"},"sirpo":{"lemma":"sirpo","pos":"","gen":"","def":"scirpo."},"sirpus":{"lemma":"sirpus","pos":"","gen":"","def":"scirpus. sīrus, i, m., = σιρός, a pit to keep corn in, an underground granary (cf. cumera), Plin. 18, 30, 73, § 306; Col. 1, 6, 15; Curt. 7, 4, 24; cf. Auct. B. Afr. 65"},"siscia":{"lemma":"Siscia","pos":"","gen":"","def":", a city of Pannonia, now Siszek, Vell. 2, 113; Plin. 3, 25, 28, § 147"},"sisygambis":{"lemma":"Sisygambis","pos":"","gen":"","def":", a Persian female name; esp., the mother of Darius, Curt. 3, 3, 22; 5, 2, 18. sĭsymbrĭum, ii, n., = σισύμβριον, a fragrant herb sacred to Venus, perh. wildthyme or mint, Plin. 20, 22, 91, § 247"},"sisyrus":{"lemma":"sisyrus","pos":"","gen":"","def":", a plant, also called erice, Plin. 11, 16, 15, § 42. sītănĭus, a, um, adj., = σητάνιος, of this year, this year's: panis, of summer wheat, Plin. 22, 25, 68, § 139. sītarchĭa, ae, f."},"sit":{"lemma":"sum","pos":"","gen":"","def":"(form of sum)"},"sitiogagus":{"lemma":"Sitiogagus","pos":"","gen":"","def":", a river of Asia, Plin. 6, 23, 26, § 99. sĭtis, is (abl. site, Ven. Carm. 2, 13, 3; acc. sitem, Prud. στεφ. 2, 250), f. etym. dub.; perh. akin with siccus, thirst (class."},"sitones":{"lemma":"Sitones","pos":"","gen":"","def":", a people of northern Germany, in the neighborhood of the Suiones, Tac. G. 45 fin. sītōnĭa, ae, f., = σιτωνία, the office of a sitona, commissariat, purveyance, Dig. 50, 5, 2 init. sittăcē, ēs"},"sittybus":{"lemma":"sittybus","pos":"","gen":"","def":", a strip of parchment, attached to a roll or book, bearing the title and the author's name, Cic. Att. 4, 5, 3; 4, 8, a, 2 B. and K. (in some editions sillybus"},"smerdis":{"lemma":"Smerdis","pos":"","gen":"","def":"A brother of Cambyses, king of Persia, by whom he was put to death, Just. 1, 9, 4.— An impostor named Oropastes, who assumed the name of Smerdis after the death of Cambyses, Just. 1, 9, §§ 9, 10."},"smigma":{"lemma":"smigma","pos":"","gen":"","def":"smegma fin. smīla, ae, f., = σμίλη, a knife (syn. scalprum), Arn. 5, 172 Orell. N. cr. smīlax, ăcis, f., = σμῖλαξ. Bindweed, withwind, rough smilax: Smilax aspera, Linn.; Plin. 16, 35, 63, § 153"},"smyrna":{"lemma":"smyrna","pos":"","gen":"","def":", = σμύρνα, myrrh, Lucr. 2, 504; Dig. 39, 4, 16, § 7. Smyrna (in the best MSS. Zmyr-na), ae, f., = Σμύρνα, a celebrated maritime city of Ionia"},"soccus":{"lemma":"soccus","pos":"","gen":"-heeled","def":"A kind of low-heeled, light shoe, worn by the Greeks; a slipper, sock, Plaut. Trin. 3, 2, 94; id. Ep. 5, 2, 60; id. Bacch. 2, 3, 98; id. Pers. 1, 3, 44"},"socra":{"lemma":"socra","pos":"","gen":"","def":"socrus. Sōcrătes, is, m., = Σωκράτης. The celebrated Greek philosopher: parens philosophiae, Cic. Fin. 2, 1, 1: fons et caput philosophiae, id. de Or. 1, 10"},"sodanus":{"lemma":"Sodanus","pos":"","gen":"","def":", a river of Gedrosia, Plin. 6, 23, 25, § 94. sōdes contr. from si audes, for audies, Cic. Or. 45, 154; cf.: dic mihi si audes, quis ea est, etc., Plaut. Fragm. ap. Prisc. p. 960"},"sodii":{"lemma":"Sodii","pos":"","gen":"","def":", an Iberian people in Asia, Plin. 6, 10, 11, § 29. Sŏdŏma, ōrum, n., = Σόδομα (Heb. ), the city of Sodom in Palestine, Tert. Apol. 40"},"soldus":{"lemma":"soldus","pos":"","gen":"","def":"solidus init. sŏlĕa, ae, f. solum. A slipper consisting of a sole fastened on by a strap across the instep, a sandal: omnia ferme id genus, quibus plantarum calces tantum infimae teguntur"},"soletum":{"lemma":"Soletum","pos":"","gen":"","def":", a town in Calabria, Plin. 3, 11, 16, § 101. Sŏli (collat. form Soloe, Mel. 1, 13, 2"},"sollus":{"lemma":"sollus","pos":"adj.","gen":"","def":"cf. Sanscr. sarva, entire; Gr. ὅλος; Lat. salvus"},"solorius":{"lemma":"Solorius","pos":"","gen":"","def":", a mountain in Hispania Tarraconensis, Plin. 3, 1, 2, § 6. sŏlox, ōcis, adj. (cf.: salvus, solidus; v. Corss. Ausspr. 1, 486"},"solua":{"lemma":"Solva","pos":"adj.","gen":"","def":", a city of Noricum, Inscr. Grut. 537, 1.—Hence, Solvensis, e, adj., of or belonging to Solva: Flavium Solvense (sc. oppidum), Plin. 3, 24, 27, § 146."},"soluo":{"lemma":"solvo","pos":"v.","gen":"-luo","def":"a. (perf. soluit, trisyll., Cat. 2, 13: soluisse, Tib. 4, 5, 16) [for se-luo"},"somnurnus":{"lemma":"somnurnus","pos":"adj.","gen":"","def":"id.; in analogy with nocturnus, diurnus, of or belonging to sleep: imagines, seen in sleep, Varr. ap. Non. 172, 3."},"somnus":{"lemma":"somnus","pos":"","gen":"-nas","def":"Sanscr. svap-nas; Gr. ὕπνος; som-nus for sop-nus; cf.: sopor, sopio. Lit., sleep: hostes vino domiti somnoque sepulti, Enn. ap. Macr. S. 6 (Ann. v. 291 Vahl.)"},"sonchus":{"lemma":"sonchus","pos":"","gen":"-thistle","def":", = σόγχος, the herb sow-thistle: Sonchus oleraceus, Linn."},"sons":{"lemma":"sons","pos":"adj.","gen":"-mi","def":"(nom. sing., Fest. p. 297; Aus. Idyll. 12) [Part. from root as-, es-; Sanscr. as-mi; Gr. εὶμί; Lat. esum, sum; cf. Gr. ἐτεός, ἐτήτυμος"},"sontini":{"lemma":"Sontini","pos":"","gen":"","def":", a people of Lucania, Plin. 3, 11, 15, § 98. Sontĭus, ii, m., a river in Carinthia, now the Lisonzo, Cassiod. Ep. 1, 18"},"sopolis":{"lemma":"Sopolis","pos":"","gen":"","def":", a celebrated painter in the time of Cicero, Cic. Att. 4, 16; acc. Sopolin, Plin. 35, 11, 40, § 148. sŏpor, ōris, m. Sanscr. root svap-, sleep; cf. somnus"},"soranus":{"lemma":"Soranus","pos":"","gen":"","def":", an epithet of Dis, acc. to Serv. Verg. A. 11, 785. sorbĕo, ŭi, 2 (collat. forms: pres. subj. sorbamus, App. M. 2, p. 119; perf. sorpsi, acc. to Charis. p. 217, and Diom. p. 363"},"sorbillo":{"lemma":"sorbillo","pos":"","gen":"-class","def":"dim. a. , to sip (ante- and post-class.). Lit.: cyathos, Ter. Ad. 4, 2, 52: vinum dulciter, App. M. 2, p. 121, 36.—* Transf.: sorbillantibus saviis, App. M. 3, p. 135, 35. sorbĭlō, adv. id."},"sorbum":{"lemma":"sorbum","pos":"","gen":"","def":"sorbus, the fruit of the sorbus, a sorb - apple, sorb, service - berry, Plin. 15, 21, 23, § 85; Cato, R. R. 7, 5; Varr. R. R. 1, 59, 3; Col. 12, 16, 4; Verg. G. 3, 380."},"sorbus":{"lemma":"sorbus","pos":"","gen":"","def":", the true sorb- or servicetree: Sorbus domestica, Linn.; Col. 5, 10, 19; Plin. 16, 18, 30, § 74; Pall. Jan. 15, 1 al. sordĕo, ēre, v. n. cf. Goth. svarts"},"sordesco":{"lemma":"sordesco","pos":"","gen":"","def":"inch. n. , to become dirty, grow filthy (not ante-Aug., and very rare): contrectatus ubi manibus sordescere vulgi Coeperis (liber), * Hor. Ep 1, 20, 11: mel, Plin. 11, 12, 12, § 31: manus, id. 33, 3"},"sordones":{"lemma":"Sordones","pos":"","gen":"","def":", a people of Gaul, towards the Pyrenees, Plin. 3, 4, 5, § 32 Jan. (al. Sardones)"},"sorsum":{"lemma":"sorsum","pos":"","gen":"","def":"seorsum. sortĭcŭla, ae, f dim. , a little lot, a small tablet or ticket, Suet. Ner. 21; Inscr. Grut. 590, 7"},"sortis":{"lemma":"sortis","pos":"","gen":"","def":"sors init. sortītĭo, ōnis, f. sortior, a casting or drawing of lots, a choosing or determining by lot, sortition (class.): deos quaeso, mihi ut sortitio eveniat, * Plaut. Cas. 2, 6"},"sosus":{"lemma":"Sosus","pos":"","gen":"","def":", a proper name, Plin. 36, 25, 60, § 184."},"spagas":{"lemma":"spagas","pos":"","gen":"","def":"14, 20, 25, § 123. Spalāthra, ae, f., = Σπάλαθρα, a city on the Thessalian coast, Plin. 4, 9, 16, § 32. spălax, ăcis, f., = σπάλαξ, a plant, otherwise unknown, Plin. 19, 6, 31, § 99."},"spalei":{"lemma":"Spalei","pos":"","gen":"","def":", a people on the Tanais, Plin. 6, 7, 7, § 22. Spărāx, m., the name of a slave, Plaut. Rud. 3, 2, 43. spargănĭon, ii, n., = σπαργάνιον, the plant bur-weed, Plin. 25, 9, 63, § 109."},"spargo":{"lemma":"spargo","pos":"v.","gen":"-clause","def":"spargier, Hor. C. 4, 11, 8), v. a. Sanscr. root sparç, to touch, sprinkle; M. H. Germ. Sprengen; cf. Gr. σπείρω, to strew, throw here and there, cast, hurl, or throw about, scatter; to bestrew"},"sparsim":{"lemma":"sparsim","pos":"adv.","gen":"","def":"sparsus, from 1. spargo, scatteredly, dispersedly, here and there (postclass. and very rare): defluere, App. M. 10, p. 255, 39: commeninisse haec, Gell. 11, 2, 5: dicere, Lact. 1, 2, 6. sparsĭo, ōnis"},"spasmus":{"lemma":"spasmus","pos":"","gen":"","def":", = σπασμός, a cramp, convulsion, spasm (post-Aug. for convulsio), Plin. 22, 8, 9, § 21; 24, 7, 24, § 40; 30, 12, 36, § 110; Scrib. Comp. 171"},"spectrum":{"lemma":"spectrum","pos":"","gen":"","def":"specio, an appearance, form, image of a thing"},"spectus":{"lemma":"spectus","pos":"","gen":"","def":"id., look, appearance, aspect: spectu sine praepositione Pacuvius in Duloreste usus est, cum ait: spectu protervo ferox, Fest. s. h. v. p. 330 Müll."},"spegma":{"lemma":"spegma","pos":"","gen":"","def":"psegma. spēlaeum (spēlēum), i, n., = σπήλαιον, a cave, cavern, den (poet. and in postclass. prose; syn. antrum): in silvis, inter spelaea ferarum, * Verg. E. 10, 52"},"spelta":{"lemma":"spelta","pos":"","gen":"","def":", spelt: totidem speltas, i. e. grains of spelt, Rhemn. Fann. Pond. 10; Hier. in Ezech. 1, 4, 9. spēlunca, ae, f., = σπήλυγξ, gen. γγος. A cave, cavern, den (class."},"sperma":{"lemma":"sperma","pos":"","gen":"","def":", = σπέρμα, seed, semen, sperm, Sulp. Sev. Hist. Sacr. 1, 11. spermătĭcus, a, um, adj., = σπερματικός, of or relating to seed, seminal, spermatic: pori, Cael. Aur. Acut. 3, 18, 180."},"spernax":{"lemma":"spernax","pos":"adj.","gen":"","def":"sperno, despising, showing contempt, contemptuous (post-Aug. and very rare): viri spernaces mortis, Sil. 8, 465: in admittendo consilio spernax, Sid. Ep. 4, 9."},"sperno":{"lemma":"sperno","pos":"v.","gen":"-itar","def":"sync. sprērunt, Prud. Dittoch. 31), v. a. root spar-, to part; Sanscr. spar-itar, enemy; cf. Lat. parcus; Germ. sperren, to sever, separate, remove (syn.: segrego, separo"},"spes":{"lemma":"spes","pos":"","gen":"-clause","def":"spe, Liv. 1, 40, 7 dub.; Weissenb. spei; plur. nom. and acc. speres, Enn. ap. Fest. p. 333 Müll., or Ann. v. 410 and 132 Vahl.; gen. sperum, Eum. Paneg. Const. 15"},"speusippus":{"lemma":"Speusippus","pos":"","gen":"","def":", = Σπεύσιππος, a nephew of Plato, and his successor in the Academy, Cic. Ac. 1, 4, 17; id. N. D. 1, 13, 32"},"sphaerista":{"lemma":"sphaerista","pos":"","gen":"-player","def":", = σφαιριστής, a ball-player, Sid. Ep. 2, 9 med.; 5, 17. sphaeristērĭum, ii, n., = σφαιριστήριον. Lit., a place for playing ball, a ball-court, tennis-court, Plin. Ep. 2, 17, 12; 5, 6, 27"},"sphaerus":{"lemma":"Sphaerus","pos":"","gen":"","def":", = Σφαῖρος. A Stoic, a pupil of Zeno, Cic. Tusc. 4, 24, 53.— A freedman of Augustus, Suet. Aug. 89. Sphăgĭae, ārum, f., three rocky islands near Pylos, Plin. 4, 12, 19, § 55."},"sphagnos":{"lemma":"sphagnos","pos":"","gen":"","def":", = σφάγνος, a kind of fragrant moss, Plin. 12, 23, 50, § 108; 24, 6, 17, § 27."},"sphincter":{"lemma":"sphincter","pos":"","gen":"","def":", = σφιγκτήρ, the sphincter, the muscle of the anus, Cael. Aur. Tard. 2, 1. Sphinga (Spin-), ae, f., = Sphinx (late Lat.), Aug. Civ. Dei, 18, 13.—Plur., Hyg. Fab. 67; Sid. Ep. 5, 7"},"spiclum":{"lemma":"spiclum","pos":"","gen":"","def":"spiculum. spīco, no perf., ātum, 1, v. a. spica, to furnish with spikes or ears (post-Aug., and usually in the part. perf.): grana in stipulā crinito textu spicantur, shoot out or put forth ears"},"spinther":{"lemma":"spinther","pos":"","gen":"","def":"spinter."},"spintum":{"lemma":"Spintum","pos":"","gen":"","def":", a town of Ethiopia, Plin. 6, 29, 35, § 180. spinturnīcĭum, ii, n. dim. spinturnix, a little bird of ill-omen, Plaut. Mil. 4, 1, 42."},"spinturnix":{"lemma":"spinturnix","pos":"","gen":"","def":"σπινθαρίς, an unsightly bird, otherwise unknown, Poët. ap. Fest. p. 330 sq. Müll."},"spiritus":{"lemma":"spiritus","pos":"n. m.","gen":"-us","def":"breath, breathing; air, breeze; spirit, soul; inspiration"},"spissesco":{"lemma":"spissesco","pos":"","gen":"","def":"inch. n. , to become thick, to thicken, condense (very rare), * Lucr. 6, 176"},"spisso":{"lemma":"spisso","pos":"v.","gen":"","def":"a. id.. Lit., to thicken, make thick, condense (poet. and in post-Aug. prose; esp. freq. in Pliny the elder; cf. denso): omne lac igne spissatur, Plin. 11, 41, 96, § 238"},"spissus":{"lemma":"spissus","pos":"adj.","gen":"","def":"root spi-, to press; cf. Lith. spitu. Lit., thick, crowded, close, compact, dense (mostly poet and in post-Aug. prose"},"splanchnoptes":{"lemma":"splanchnoptes","pos":"","gen":"","def":", = σπλαγχνόπτης, the roaster of entrails; a bronze statue by Styppax, Plin. 22, 17, 20, § 44; 34, 8, 19, § 81. splēn, ēnis, m., = σπλήν, the milt or spleen, Plin. 23, 1, 16, § 25; 24, 15, 80, § 131"},"splendentia":{"lemma":"splendentia","pos":"","gen":"","def":"splendeo, brilliancy (late Lat.), Hier. Ep. 57, 11. splendĕo, ēre (perf. splendui, Aug. Conf. 10, 27), v. n., to shine, be bright; to gleam, glitter, glisten (mostly poet."},"splendor":{"lemma":"splendor","pos":"","gen":"","def":"splendeo, sheen, brightness, brilliance, lustre, splendor. Lit. In gen. (mostly poet. and in post-Aug. prose"},"sponda":{"lemma":"sponda","pos":"","gen":"","def":"Lit., the frame of a bedstead, sofa, etc., Ov. M. 8, 657; Petr. 97, 4; 94, 8.— Transf. A bed, couch, sofa (syn. lectus), Verg. A. 1, 698; Hor. Epod. 3, 22; Ov. F. 2, 345; Mart. 3, 91, 9"},"spondaeus":{"lemma":"spondaeus","pos":"","gen":"","def":"spondeus. spondăĭcus, v. spondiacus. spondālĭum or spondaulĭum (the form is uncertain), ii, n., a sacrificial hymn, accompanied by the flute: spondalium canere, Diom. p. 472 fin. P.: spondalia dicens"},"spongos":{"lemma":"spongos","pos":"","gen":"","def":", a sponge (late Lat.), Juvenc. 4, 696."},"spons":{"lemma":"spons","pos":"","gen":"","def":"sponte."},"sponsa":{"lemma":"sponsa","pos":"","gen":"","def":"spondeo, P. a., E. sponsālīcĭus or -tĭus, a, um, adj. sponsalia, of or belonging to betrothal, spousal (post-class.): arrha, Cod. Just. 5, 1, 5"},"sponso":{"lemma":"sponso","pos":"v.","gen":"-class","def":"a. sponsus, to betroth, affiance, espouse (post-class.). Lit.: aliquam, Dig. 23, 2, 38"},"sponsor":{"lemma":"sponsor","pos":"","gen":"","def":"spondeo, one who becomes answerable for another. Lit., a bondsman, surety (cf.: vas"},"sponsum":{"lemma":"sponsum","pos":"","gen":"","def":"spondeo, P. a., C. sponsus, a, um, Part. and P. a. of spondeo."},"sponsus":{"lemma":"sponsus","pos":"","gen":"","def":"spondeo, P. a., A."},"spontis":{"lemma":"spontis","pos":"","gen":"","def":"sponte, II. Spŏrădes, um, f., = Σποράδες, islands in the Aegean Sea, between the Cyclades and Crete, Mel. 2, 7, 11; Plin. 4, 12, 23, § 63.—Acc. Sporadas, Prisc. Perieg. 550."},"sporta":{"lemma":"sporta","pos":"","gen":"","def":"cf. Gr. σπυρίς, basket σπάρτον, σπεῖρα, a plaited basket or ham per, Cato, R. R. 11, 4; Varr. and Sall. ap. Non. 177, 22 sq.; Col. 8, 7, 1; 12, 6, 1.— A sieve, Plin. 18, 7, 17, § 77; Mart. 10, 37, 17"},"sportella":{"lemma":"sportella","pos":"","gen":"-basket","def":"dim. sporta, a little basket, a fruit-basket, Cic. Fam. 9, 20, 2; Petr. 40, 3; Suet. Dom. 4. sportŭla, ae, f. dim. id.. Lit., a little basket: sportulam cape atque argentum, Plaut. Men. 1, 4, 1"},"spurco":{"lemma":"spurco","pos":"v.","gen":"","def":", ātum, 1, v. a. id., to make filthy, to befoul, defile (rare"},"spurcus":{"lemma":"spurcus","pos":"adj.","gen":"","def":"cf. spargo, dirty, unclean, impure (class.; syn.: immundus, impurus, obscenus). Lit.: res, Lucr. 6, 782"},"squilla":{"lemma":"squilla","pos":"","gen":"","def":"scilla."},"st":{"lemma":"st","pos":"interj.","gen":"","def":", hist! whist! hush! st, tale verbum cave faxis, Naev. ap. Charis. p. 214 P.: st, st, tacete, Plaut. Ep. 2, 2, 1: st, tacete, quid hoc clamoris? Poët. ap. Cic. de Or. 2, 64, 257: st"},"stacta":{"lemma":"stacta","pos":"","gen":"-oil","def":", = στακτή, myrrh-oil. Stacta, Lucr. 2, 847; Plaut. Truc. 2, 5, 23; id. Most. 1, 3, 151; Plin. 12, 15, 35, § 70.— Stacte, Plaut. Curc. 1, 2, 5"},"stacton":{"lemma":"stacton","pos":"","gen":"-salve","def":", = στακτόν, a kind of eye-salve, Scrib. Comp. 34. stacŭla, ae, f., a kind of vine, also called sircula, Plin. 14, 2, 4, § 34 (Jahn, scapula)."},"stadia":{"lemma":"Stadia","pos":"","gen":"","def":", an ancient name of the town of Cnidus in Caria, Plin. 5, 28, 29, § 104. stădĭālis, e, adj. stadium, of or containing a stadium: ager, Auct. Grom. ap. Goes. p. 321. stădĭātus, a, um, adj. id."},"stadisis":{"lemma":"Stadisis","pos":"","gen":"","def":", a town in Ethiopia, Plin. 6, 29, 35, § 81. stădĭum, ii, n. (masc. collat. form, acc. plur. stadios, Macr. Somn. Scip. 1, 15 med.; gen. plur. usu. stadium; but stadiorum, Plin. 2, 108, 112, § 247"},"stadius":{"lemma":"Stadius","pos":"","gen":"","def":", the name of a man, Pers. 6, 65. Stăgīra, ōrum, n., = Στάγειρα, a town in Macedonia, the birthplace of Aristotle, Plin. 4, 10, 17, § 38"},"stagnensis":{"lemma":"stagnensis","pos":"adj.","gen":"","def":"stagnum. of or belonging to ponds or pools: aves, Aug. in Psa. 1, 103. stagnĕus, a, um, v. stanneus. stagnīnus, a, um, adj. stagnum, resembling stagnant water: color perviridis, Front. Aquaed. 7 dub."},"stagno":{"lemma":"stagno","pos":"v.","gen":"","def":"n. and a. . Neutr. Lit., to form a pool of standing water, to stagnate, be stagnant (mostly poet. and in post-Aug. prose; not in Cic."},"stagnum":{"lemma":"stagnum","pos":"","gen":"","def":"cf. Gr. τέναγος = vadum. Lit., a piece of standing water (whether permanent or formed by the overflowing of a stream], a pool, pond, swamp, fen, etc. (cf.: lacus, palus): propter stagna"},"stannum":{"lemma":"stannum","pos":"n. n.","gen":"-i","def":"an alloy of silver and lead; tin"},"staphylus":{"lemma":"Staphylus","pos":"","gen":"","def":", a son of Silenus, who taught the art of mixing wine with water, Sall. H. 1, 87 Dietsch; Plin. 7, 56, 57, § 199. Stasĕas, ae, m., a Peripatetic philosopher of Neapolis, Cic. Or. 1, 22, 104"},"statelli":{"lemma":"Statelli","pos":"","gen":"","def":"Statielli. stăter, ēris, m., = στατήρ, a small silver coin of the Jews, of the value of four drachmae, Hier. in Matt. 3, 17, 26; Vulg. 1 Reg. 9, 8"},"statones":{"lemma":"Statones","pos":"adj.","gen":"-quarries","def":", the people of Statonia in Southern Etruria, celebrated for its vines and stone-quarries, Plin. 3, 5, 8, § 52. —Hence, Statonĭensis, e, adj., of or belonging to Statonia: ager, Plin. 2, 95, 96"},"staures":{"lemma":"Staures","pos":"","gen":"","def":", a people on the Caspian Sea, Plin. 6, 16, 18, § 46. stĕătītis, ĭdis, f., = στεατῖτις, a precious stone, otherwise unknown"},"stegnus":{"lemma":"stegnus","pos":"adj.","gen":"","def":", = στεγνός, making close, drawing together, costive: febres, Plin. 23, 7, 63, § 120. stēla, ae, f., = στήλη, a pillar, column, stele, Plin. 6, 28, 32, § 150; 6, 29, 34, § 174"},"stella":{"lemma":"stella","pos":"","gen":"-star","def":"for sterula; cf. Sanscr. staras; cf. Gr. ἀστήρ; Germ. Stern; Engl. star; perh. root ster- of sterno; Gr. στορέννυμι. Lit., a star (whereas sidus denotes a group of stars, a constellation; v. sidus"},"stellans":{"lemma":"stellans","pos":"","gen":"","def":"stello, I. stellāris, e, adj. stella, of or belonging to a star, starry (post-class.): essentia, Macr. Somn. Scip. 1, 14 med. Stellātīnus, a, um, v. Stellatis. Stellātis ăger or campus"},"stellio":{"lemma":"Stellio","pos":"","gen":"","def":"1. stellio, a Roman surname, e. g. C. Afranius Stellio, Liv. 39, 23, 2. stellĭōnātus, ūs, m. 1. stellio, B., cozenage, trickery, cheating, stellionate (jurid. Lat.): stellionatum obici posse his"},"stello":{"lemma":"stello","pos":"v.","gen":"-eyed","def":", ātum, 1, v. n. and a. . Neutr., to be set or covered with stars. So only in the part. pres. stellans, antis, bestarred, starry (poet.): caelo stellante, Lucr. 4, 212"},"stemma":{"lemma":"stemma","pos":"","gen":"-class","def":", = στέμμα. In gen., a garland, wreath (post-class.), Prud. στεφ. 10, 908; Firm. Math. 3, 8.— In partic., a garland hung upon an ancestral image (post-Aug.), Sen. Ben. 3, 28, 1"},"stentor":{"lemma":"Stentor","pos":"adj.","gen":"-sounding","def":", = Στέντωρ, a Greek warrior in the army before Troy, celebrated for the strength of his lungs, Juv. 13, 112. —Hence, Stentŏrĕus, a, um, adj., Stentorian, i. e. loud-sounding: vagitus, Arn. 2"},"stercus":{"lemma":"stercus","pos":"","gen":"","def":"Gr. σκώρ; gen. σκατός, dung; Sanscr. cakrt = sakart. Lit., dung, excrements, ordure (syn.: fimus, merda), Varr. R. R. 1, 38; Col. 2, 15; Cato, R. R. 29; 37; Cic. Div. 1, 27, 57; Hor. Epod. 12, 11 al."},"sternax":{"lemma":"sternax","pos":"adj.","gen":"","def":"sterno, that throws to the ground (poet.): equus, that throws his rider, Verg. A. 12, 364; Sil. 1, 261: cives, that fall prostrate, Sid. Ep. 5, 14 fin.; so of a suppliant, id. ib. 4, 12 fin."},"sterno":{"lemma":"sterno","pos":"v.","gen":"-class","def":"sync. strarat, Manil. 1, 774: strasset, Varr. ap. Non. 86, 8), v. a. Gr. root ΣΤΟΡ, στορέννυμι, to spread; στρατός, camp; Sanscr. star- strnāmi = sterno"},"sthennis":{"lemma":"Sthennis","pos":"","gen":"","def":", = Σθένις, a sculptor of Olynthus, Plin. 34, 8, 19, § 90. Sthĕno, ūs, f., = Σθενώ, a daughter of Phorcus and Ceto, sister of Medusa, Hyg. Fab. praef. stĭbădĭum, ii, n., = στιβάδιον"},"stigma":{"lemma":"stigma","pos":"","gen":"","def":"(fem. collat. form, acc. stigmam, Petr. 45, 9; 69, 1), = στίγμα, a prick, puncture (post-Aug.). A mark burned in, a brand impressed upon slaves or others, as a mark of disgrace. Lit., Petr. 103, 2"},"stigmo":{"lemma":"stigmo","pos":"v.","gen":"","def":"a. stigma, to brand, stigmatize (late Lat.), Prud. στεφ. 10, 1079. stigmōsus, a, um, adj. id., full of brand-marks, branded, Petr. 109, 8; Regul. ap. Plin. Ep. 1, 5, 2."},"stilbon":{"lemma":"Stilbon","pos":"","gen":"","def":", = Στίλβων (the shining, glittering), a name of the planet Mercury, Aus. Idyll. 18, 11; Mart. Cap. 8, § 851"},"stilla":{"lemma":"stilla","pos":"","gen":"","def":"dim. of stĭria; cf. Fest. s. v. stiricipium, p. 345 Müll.; Corss. 1, p. 518, a drop (a dense, viscous, gummy, fatty drop"},"stillanter":{"lemma":"stillanter","pos":"adv.","gen":"","def":"stillo, drop by drop, Ambros. Ep. 41, 14. stillārĭum, ii, n. stilla, an added drop, a trifling addition, Sen. Ep. 97, 2. stillātīcĭus, a, um, adj. stillo, dropping, dripping, stillatitious: resina"},"stillo":{"lemma":"stillo","pos":"v.","gen":"","def":"n. and a . Neutr., to drop, drip, trickle, distil (mostly poet."},"stimmi":{"lemma":"stimmi","pos":"","gen":"","def":"stibium. Stĭmŭla (Sĭmĭla, Liv. 39, 12), ae, f. stimulus, the goddess who pricks on, excites, stimulates to action or pleasure, Aug. Civ Del, 4, 11; 4, 16; perh. for Semele, Ov. F. 6, 503"},"stinguo":{"lemma":"stinguo","pos":"v.","gen":"","def":"a. cf. stig; Gr. στίζω"},"stipa":{"lemma":"stipa","pos":"","gen":"","def":"stuppa. stīpātio, ōnis, f. stipo, a crowd pressing around any one, a suite, retinue, train. Lit.: latrones dicti ab latere, qui circum latera erant regi"},"stips":{"lemma":"stips","pos":"","gen":"","def":"does not occur, although stips is assumed by Varr. L. L. 5, § 182 Müll.; Charis. 85 P.; cf. Gloss. stips, ἔρανος), f. kindr. with stipo, and therefore, orig., small coin in heaps"},"stirpes":{"lemma":"stirpes","pos":"","gen":"","def":"stirps init."},"stirpesco":{"lemma":"stirpesco","pos":"","gen":"","def":"inch. n. , to run to stalk: asparagus, Plin. 19, 8, 42, § 149. stirpĭtus, adv. id."},"stlis":{"lemma":"stlis","pos":"","gen":"","def":"lis init. stlŏcus, v. locus init."},"stloppus":{"lemma":"stloppus","pos":"","gen":"","def":", a slap (the sound produced by striking upon the inflated cheek), Pers. 5, 13. sto, stĕti, stătum, 1 (scanned stĕtĕrunt, Verg. A. 2, 774; 3, 48; Ov. H. 7, 166; Prop. 2, 8, 10), v. n. root sta-"},"stobrus":{"lemma":"stobrus","pos":"","gen":"","def":", a tree in Carmania yielding an odorous gum, Plin. 12, 17, 40, § 79. stoebē, ēs, f., = στοιβή, a plant, called also pheos, Plin. 21, 15, 54, § 91"},"storbus":{"lemma":"storbus","pos":"","gen":"","def":"stobrus. stŏrĕa (in good MSS. also stŏrĭa; cf. Caes. B. C. 2, 9), ae, f. from the root ster, sterno; Gr. στοπέννυμι, to spread out, a mat or covering made of plaited straw, rushes, rope, etc."},"straor":{"lemma":"Straor","pos":"","gen":"","def":"Stratos, II. strāta, ae, v. sterno fin. strătēgēma, ătis (dat. and abl. plur. strategematibus, Front. 4 praef.), n., = στρατήγημα. Lit., a piece of generalship"},"stratii":{"lemma":"Stratii","pos":"","gen":"","def":"Stratos, I. strătĭo, ōnis, f. sterno, the laying of cloths and coverings, the preparation of a room for a feast, Inscr. Fabr. 404, 306"},"stremma":{"lemma":"stremma","pos":"","gen":"","def":", = στρέμμα, a dislocation, Pelag. Vet. 16. strēna, ae, f. Sabine. Lit., a sign, prognostic, omen (Plautin.), Plaut. Stich. 3, 2, 8"},"streptos":{"lemma":"streptos","pos":"adj.","gen":"","def":", = στρεπτός, twisted: uva, a kind of grape, Plin. 14, 3, 4, § 39. strĭa, ae, f., a furrow, channel, hollow: quā aratrum vomere striam facit, sulcus vocatur, Varr. R. R. 1, 29, 3"},"strictim":{"lemma":"strictim","pos":"adv.","gen":"","def":"strictus, from stringo, straitly, closely. Lit. (ante- and postclass., and very rare): strictim attondere, i. e. close to the skin, Plaut. Capt. 2, 2, 18: juncta crates, Pall. 1"},"strictor":{"lemma":"strictor","pos":"","gen":"","def":"id., one who strips or plucks off: olearum, Cato, R. R. 144, 3. strictōrĭa, ae, f. id., a shirt with long sleeves, Edict. Diocl. 7, 56 al. strictūra, ae, f. id.. In abstr., a contraction, compression"},"strigmentum":{"lemma":"strigmentum","pos":"","gen":"","def":"id.. In gen., that which is scratched or scraped off, a scraping (post-Aug.), Plin. 20, 3, 8, § 17.— In partic., filth or dirt scraped off, Cels. 2, 6 med.; 5, 2, 4; Plin. 9, 51, 74, § 160"},"stringo":{"lemma":"stringo","pos":"v.","gen":"","def":"a. root strig; Gr. στραγγ-, to squeeze; στράγξ, a drop; cf. O. H. Germ. streng; Engl. strong, to draw tight, to bind or tie tight"},"stringor":{"lemma":"stringor","pos":"","gen":"","def":"stringo, a touching, touch, shock: gelidae aquaï, Lucr. 3, 693. strĭo, no perf., ātum, 1, v. a. stria, to furnish with furrows or channels"},"strittabillae":{"lemma":"strittabillae","pos":"","gen":"","def":"strictivilla. strittāre, to be weak in the feet: strittare ab eo, qui sistit aegre, Varr. L. L. 7, § 65 Müll."},"strix":{"lemma":"strix","pos":"","gen":"-owl","def":"Lachm. Lucr. II. p. 36), f., = στρίγξ [from στρίζω, τρίζω, the screecher], a screech-owl, which, according to the belief of the ancients, sucked the blood of young children, Plaut. Ps. 3, 2, 31"},"strombus":{"lemma":"strombus","pos":"","gen":"","def":", = στρομβος, a kind of spiral snail, Plin. 32, 10, 39, § 117; 32, 11, 53, § 151."},"strongyla":{"lemma":"strongyla","pos":"","gen":"","def":", = στρογγύλη, a bust, Tert. Pall. 4 med. strongylē, ēs, f., = στρογγύλη, a kind of alum, Plin. 35, 15, 52, § 187. Strongylē, ēs, f., = Στρογγύλη, one of the Lipari islands, now Stromboli"},"stroppus":{"lemma":"stroppus","pos":"","gen":"","def":"struppus. structē, adv., v. struo fin. structĭlis, e, adj. struo, of or belonging to building; that is built or constructed"},"structor":{"lemma":"structor","pos":"","gen":"","def":"id.. One who erects a building, a builder, mason, carpenter: res agebatur multis structoribus, Cic. Q. Fr. 2, 6, 2; id. Att. 14, 3, 1; Cod. Just. 10, 64, 1; Dig. 50, 6, 6; Capitol. Ver. 5"},"structus":{"lemma":"structus","pos":"","gen":"","def":"struo, a heap, pile: lignorum structibus incensis, Arn. 7, 15 Hildeb. strŭes, is, f. id., a heap, pile of things put together. In gen. (class."},"struix":{"lemma":"struix","pos":"","gen":"-class","def":"struo, a heap, pile of things put together (ante- and post-class. for the class. strues). Lit.: struices antiqui dicebant exstructiones omnium rerum"},"strychnos":{"lemma":"strychnos","pos":"","gen":"","def":", = στρύχνος, a kind of nightshade, Plin. 27, 8, 44, § 68.—Called also trychnos, Plin. 21, 31, 105, § 177; App. Herb. 74. Strȳmon (nom. Strymo, Sen. Q. N. 1 praef. med."},"stubera":{"lemma":"Stubera","pos":"","gen":"","def":", a city in Macedonia, Liv. 31, 39; 43, 18"},"stultus":{"lemma":"stultus","pos":"adj.","gen":"","def":"root star-; v. stolidus, foolish, simple, silly, fatuous, etc. (cf.: insulsus, ineptus, insipiens, brutus). Lit.: stulti, stolidi, fatui, fungi, bardi, blenni, buccones, Plaut. Bacch. 5, 1, 2"},"stura":{"lemma":"Stura","pos":"","gen":"","def":", a river of Cisalpine Gaul, that flows into the Po near Turin, Plin. 3, 16, 20, § 118."},"sturii":{"lemma":"Sturii","pos":"","gen":"","def":", a German tribe, who held an island in the Rhine, Plin. 4, 15, 29, § 101."},"sturium":{"lemma":"Sturium","pos":"","gen":"","def":", an island in the Mediterranean, near the coast of Gaul, Plin. 3, 5, 11, § 79. Sturnīni, ōrum, m., a people of Calabria, Plin. 3, 11, 16, § 105. sturnīnus, a, um, adj. sturnus, speckled"},"sturnus":{"lemma":"sturnus","pos":"","gen":"-ling","def":"Gr. ψάρ; mod. Gr. ψαρόνι; Germ. star; Engl. star-ling, a starling or stare: Sturnus vulgaris, Linn.; Plin. 10, 24, 35, § 72; 18, 17, 45, § 160; 10, 42, 59, § 120; Mart. 9, 55, 7; Stat. S. 2, 4, 18"},"stylus":{"lemma":"stylus","pos":"","gen":"","def":"stilus."},"stymma":{"lemma":"stymma","pos":"","gen":"","def":", = στύμμα, the chief ingredient or foundation of an unguent, Plin. 13, 1, 2, § 7"},"styx":{"lemma":"Styx","pos":"adj.","gen":"-cold","def":", = Στύξ. A fountain in Arcadia, the icy-cold water of which caused death, Plin. 2, 103, 106, § 231; Sen. Q. N. 3, 25, 1; Vitr. 8, 3, 16; Just. 12, 14, 7"},"suanenses":{"lemma":"Suanenses","pos":"","gen":"","def":", the inhabitants of Suana, in Etruria, Plin. 3, 5, 8, § 52."},"suanetes":{"lemma":"Suanetes","pos":"","gen":"","def":", an Alpine people, Plin. 3, 20, 24, § 137."},"suani":{"lemma":"Suani","pos":"","gen":"","def":", a people of Pontus, Plin. 6, 4, 4, § 13"},"suasani":{"lemma":"Suasani","pos":"","gen":"","def":", a people of Umbria, Plin. 3, 14, 19, § 114. suāsĭo, ōnis, f. suadeo, a counselling, advice, exhortation, suasion, persuasion. In gen., Sen. Ep. 95"},"sub-do":{"lemma":"sub-do","pos":"v.","gen":"-do","def":"a. To put, place, set, or lay under (syn.: suppono, sterno). Lit. (class.). In gen.: ego puerum interead ancillae subdam lactantem meae, Liv. Andron. ap. Non. p. 153"},"sub-dulcis":{"lemma":"sub-dulcis","pos":"adj.","gen":"-dulcis","def":", somewhat sweet, sweetish (Plinian): radix, Plin. 26, 8, 37, § 58"},"sub-iungo":{"lemma":"sub-jungo","pos":"v.","gen":"-jungo","def":"pass. subjungier, Prud. ap. Symm. 2, 586), v. a., to yoke, harness (rare): curru subjungere tigres, Verg. E. 5, 29: (juvencos) plostro, Col. 6, 2, 8: carpento suo equas, Plin. 11, 49, 109"},"sub-nascor":{"lemma":"sub-nascor","pos":"v.","gen":"-nascor","def":"dep. n., to grow up under, out of, or after"},"sub-necto":{"lemma":"sub-necto","pos":"v.","gen":"-necto","def":"a., to bind or tie under, bind on beneath (poet. and in post-Aug. prose"},"sub-offendo":{"lemma":"sub-offendo","pos":"v.","gen":"-offendo","def":"n., to give some offence: apud faecem populi, Cic. Q. Fr. 2, 6, 5. sŭb-ŏlĕo (-ŏlo, pres. subj. subolat, Ter. Heaut. 5, 1, 26; cf. oleo init.), ēre, v. n. (prop. to emit a smell"},"sub-quartus":{"lemma":"sub-quartus","pos":"adj.","gen":"-quartus","def":", = ὑποτέταρτος, one fourth less (late Lat.), Mart. Cap. 7, § 761."},"sub-salsus":{"lemma":"sub-salsus","pos":"adj.","gen":"-salsus","def":", somewhat salt, brackish: aqua, Cels. 5, 12: herba, Plin. 21, 29, 103, § 175. sub-sannātĭo, ōnis, f. subsanno, mockery by gestures, derision in pantomime, Vulg. Psa. 34, 16"},"sub-sanno":{"lemma":"sub-sanno","pos":"v.","gen":"-sanno","def":"a. sanna, to insult by derisive gestures, to deride, mock (late Lat.): ecce ipsi quasi subsannantes, Tert. adv. Jud. 11 med.; Hier. Ep. 40, 2; Vulg. Psa. 34, 16"},"sub-scalpo":{"lemma":"sub-scalpo","pos":"v.","gen":"-scalpo","def":"a., to scratch or rub underneath, Mart. Cap. 1, § 7. sub-scrībendārĭus, ii, m. scribo, an under-secretary (late Lat.), Cod. Th. 7, 4, 1"},"sub-signo":{"lemma":"sub-signo","pos":"v.","gen":"-signo","def":"a., to mark or write beneath, to undersign, subscribe (mostly post - Aug."},"sub-spargo":{"lemma":"sub-spargo","pos":"v.","gen":"-spargo","def":"n., to scatter under: semina versutiis haereticorum, Tert. Res. Carn. 63 fin."},"sub-sterno":{"lemma":"sub-sterno","pos":"v.","gen":"-sterno","def":"a., to strew, scatter, spread, or lay under or beneath (class.; cf. subicio). Lit.: segetem ovibus, Cato, R. R. 37, 2: verbenas, Ter. And. 4, 3, 12: casias et nardi lenis aristas, Ov. M. 15, 398"},"sub-sto":{"lemma":"sub-sto","pos":"v.","gen":"-sto","def":"n. To stand or be under or among, to be present (very rare; not in Cic.): si pure substante non rumpuntur hi tumores, Cels. 6, 10 med.: nullo dolore substante, id. 2, 7 med."},"sub-summo":{"lemma":"sub-summo","pos":"v.","gen":"-summo","def":"a. sub-summa, to sum up, to multiply (late Lat.), Primas in Apoc. V. 21. sub -surdus, a, um, adj., somewhat deaf: vox, indistinct, Quint. 11, 3, 32 Halm. (al. surda). subsūtūra, ae, f. sub-suo"},"sub-tendo":{"lemma":"sub-tendo","pos":"v.","gen":"-tendo","def":", tum, 3, v. a. and n. Act., to stretch underneath: lectos loris, Cato, R. R. 10, 5"},"sub-texo":{"lemma":"sub-texo","pos":"v.","gen":"-texo","def":"a., to weave under or below any thing; hence, to join on, fasten, affix (mostly poet. and in post-Aug. prose"},"sub-triplus":{"lemma":"sub-triplus","pos":"adj.","gen":"-triplus","def":", contained three times in a larger number, Boëth. Inst. Arith. 1, 23."},"sub-tristis":{"lemma":"sub-tristis","pos":"adj.","gen":"-tristis","def":", somewhat sad or sorrowful (ante- and post-class.): subtristis visus est mihi, Ter. And. 2, 6, 16"},"sub-turpis":{"lemma":"sub-turpis","pos":"adj.","gen":"-turpis","def":", somewhat mean or disgraceful: quae sint, quod ridiculi proprium est, subturpia, Cic. de Or. 2, 66, 264."},"sub-uello":{"lemma":"sub-vello","pos":"v.","gen":"-vello","def":", vulsum (volsum), 3, v. a., to pluck up, pull out (only in the two foll. passages): rador, subvellor, desquamor, Lucil. ap. Non. 95, 15: qui barba volsa feminibusque subvolsis ambulet"},"sub-uoluo":{"lemma":"sub-volvo","pos":"v.","gen":"-volvo","def":"a., to roll up or along: manibus saxa, Verg. A. 1, 424. sub-vultŭrĭus, a, um, adj., somewhat vulture-like, a facetiously formed word: corpus, Plaut. Rud. 2, 4, 9. Sucasīni (Succas-), ōrum, m."},"subc-":{"lemma":"subc-","pos":"","gen":"","def":"succ-. sub-dĕalbo, āre, v. a., to whiten a little, make whilish, Varr. ap. Non. 72, 11. sub-dēbĭlis, e, adj., somewhat weak or enfeebled: femur, Suet. Vit. 17. sub-dēbĭlĭtātus, a, um, adj. debilito"},"subdescendo":{"lemma":"subdescendo","pos":"v.","gen":"-descendo","def":"n. sub-descendo, to descend lower (late Lat.), Mar. Merc. Commonit. 4, 6. sub -dĭăcŏnus, i, m., a sub - deacon, Cod. Just. 1, 3, 6; Aug. Ep. 53; 63"},"subf-":{"lemma":"subf-","pos":"","gen":"","def":"suff-."},"subg-":{"lemma":"subg-","pos":"","gen":"","def":"sugg-. sŭb-haerĕo, ēre, v. n., to stick under or behind"},"subi":{"lemma":"Subi","pos":"","gen":"","def":"indecl., a river of Spain, Plin. 3, 3, 4, § 21.—Called also Subis, is, m., Mel. 2, 6. sŭbĭces, um, f. subicio, underlayers, supports: Ennius in tragoediā, quae Achilles inscribitur"},"subiacto":{"lemma":"subjacto","pos":"","gen":"","def":"subjecto init. subjectē, adv., v. subicio, P. a. fin. subjectĭbĭlis, e, adj. subicio, submissive, Vulg. Baruch, 1, 18. subjectĭo, ōnis, f. id., a laying, putting"},"subiector":{"lemma":"subjector","pos":"","gen":"","def":"id., one who substitutes, a substitutor, forger: testamentorum, Cic. Cat. 2, 4, 7."},"subiectum":{"lemma":"subjectum","pos":"","gen":"","def":"subicio, II. C. subjectus, a, um, Part. and P. a., from subicio."},"subiectus":{"lemma":"subjectus","pos":"","gen":"","def":"subicio, a laying under (post-Aug. and very rare), Plin. 26, 15, 90, § 154. subjĭcĭo, v. subicio. sub-jŭgālis, e, adj., accustomed to the yoke: subjugales beluae, Prud. στεφ. 10, 333.—Subst."},"subis":{"lemma":"subis","pos":"","gen":"","def":", a kind of bird that breaks eagles' eggs, otherwise unknown, Nigid. ap. Plin. 10, 14, 17, § 37."},"sublecto":{"lemma":"sublecto","pos":"","gen":"-lacio","def":"freq. a. sub-lacio, to wheedle, cajole: os, Plaut. Mil. 4, 2, 74. sublectus, a, um, Part. of sublego. sub-lĕgo, lēgi, lectum, 3, v. a. To gather from below, to gather or search for underneath"},"sublestus":{"lemma":"sublestus","pos":"adj.","gen":"-class","def":"acc. to Döderl. Synon. 2, p. 101 sq., perh. from sublevo"},"sublustris":{"lemma":"sublustris","pos":"adj.","gen":"-lux","def":"sub-lux, giving some light, having a faint light, glimmering (not ante-Aug., and very rare). Lit.: nox, Hor. C. 3, 27, 31; Liv. 5, 47: umbra (noctis), Verg. A. 9, 373"},"subm-":{"lemma":"subm-","pos":"","gen":"","def":"summ-."},"subneruo":{"lemma":"subnervo","pos":"v.","gen":"-nervus","def":"a. sub-nervus, to cut the sinew beneath, to hamstring, hough (post-class.). Taurum, Tert. adv. Jud. 10 med.: equos, Vulg. Jos. 11, 6: jugales, id. 2 Reg. 8, 4.—* Trop., to invalidate"},"subota":{"lemma":"Subota","pos":"","gen":"","def":", an island of the Aegean Sea, Liv. 44, 28, 6."},"subp-":{"lemma":"subp-","pos":"","gen":"","def":"supp-."},"subr-":{"lemma":"subr-","pos":"","gen":"","def":"surr-."},"subscriptor":{"lemma":"subscriptor","pos":"","gen":"-signer","def":"id.. (Acc. to subscribo, I. B. 1.) A signer or joint-signer of an accusation, Cic. Div. in Caecil. 15, 47"},"subsessa":{"lemma":"subsessa","pos":"","gen":"-class","def":"subsido, an ambush, ambuscade (post-class.): subsessas occultius collocare, Veg. Mil. 3, 6 med.: in subsessā esse, id. ib. 3, 22; cf.: hostium dolos subsessas vocamus, Serv. Verg. A. 11, 268."},"subsessor":{"lemma":"subsessor","pos":"","gen":"-in","def":"id., a waylayer, lier-in-wait (post-Aug.). Lit.: subsessores vocantur, qui occisuri aliquem delitescunt, Serv. Verg. A. 11, 268"},"subsistentia":{"lemma":"subsistentia","pos":"","gen":"","def":"subsisto, = ὑπὀστασις, the substance, reality, Cassiod. Hist. Eccl. 5, 38; 9, 3; 12, 4 fin."},"subspissus":{"lemma":"subspissus","pos":"adj.","gen":"-spissus","def":"sub-spissus, thickish, medic. t. t.: pleureticorum pulsus, Ps.-Soran. Puls. p. 279. sub-stāmen, ĭnis, n., the woof or weft in weaving (late Lat.), Vet. Schol. Juv. 2, 66. substantĭa, ae, f. substo"},"substillus":{"lemma":"substillus","pos":"adj.","gen":"-lum","def":"sub - stillo (ante- and post - class.), slightly dropping, dribbling. Adj.: lotium, i. e. strangury, Cato, R. R. 156, 6.— Subst.: substil-lum, i, n., a slight dropping"},"subsultim":{"lemma":"subsultim","pos":"adv.","gen":"","def":"subsilio, with leaps or jumps. decurrere, Suet. Aug. 83."},"subsulto":{"lemma":"subsulto","pos":"","gen":"","def":"freq. n. , to spring up, to leap, jump, hop (rare"},"subtegmen":{"lemma":"subtegmen","pos":"","gen":"","def":"subtemen. sub-tĕgo, xi, ĕre, v. a., to cover underneath: caelum, Amm. 19, 7, 3 (al. sub-texunt)"},"subter-fundo":{"lemma":"subter-fundo","pos":"v.","gen":"-fundo","def":"a., to found or establish beneath: terram, Lact. 2, 8, 52. subtĕr-insĕro, ĕre, 3, v. a., to insert, Aldh. Sept. col. 219, t. 89 med. subtĕr-intendo, ĕre, 3, v. a., to look askance"},"subter-mitto":{"lemma":"subter-mitto","pos":"v.","gen":"-mitto","def":"a., to place underneath, Aug. Quaest. in Heptat. 2, 177, 14. subter-mŏvĕo, ēre, v. a., to push under, Isid. 16, 4, 2. subter-nătans, antis, Part. , swimming under any thing, Sol. 32, 26."},"subter-sterno":{"lemma":"subter-sterno","pos":"v.","gen":"-sterno","def":"a., to spread under, strew under: aëra jaculis et sagittis, Jul. Val. Rer. Gest. Alex. 2, 17. subter-tĕnŭo, āre, v. a., to make thin below or at the lower part: anulum, Lucr. 1"},"subternus":{"lemma":"subternus","pos":"adj.","gen":"-class","def":"subter, that is underneath, lower, = infernus (post-class.): antra, Prud. adv. Symm. 1, 392: nox, id. Hamart. 930. sub-tĕro, trīvi, trītum, 3, v. a., to rub off or wear away underneath"},"subterraneus":{"lemma":"subterraneus","pos":"adj.","gen":"-a, -um","def":"underground, subterranean"},"subtus":{"lemma":"subtus","pos":"adv.","gen":"-class","def":"from sub; like intus, from in, below, beneath, underneath (mostly ante-class."},"subuecto":{"lemma":"subvecto","pos":"","gen":"","def":"freq. a. id., to bring up from below (on the shoulder, by ship, etc.), to bring, carry, convey, transport to a place (poet. and in post-Aug. prose): asini"},"subuector":{"lemma":"subvector","pos":"","gen":"","def":"subveho, a bearer, carrier, conveyer: Bosporus Inachiae subvector virginis olim, Avien. Perieg. 199. subvectus, a, um, Part. of subveho."},"subuectus":{"lemma":"subvectus","pos":"","gen":"","def":"subveho, a carrying, conveying, conveyance, Tac. A. 15, 4"},"subuento":{"lemma":"subvento","pos":"","gen":"","def":"freq. n. , to come with assistance to one: spes bona, opsecro, subventa mihi, Plaut. Rud. 1, 4, 11."},"subuentor":{"lemma":"subventor","pos":"","gen":"","def":"id., one who comes in aid, a helper: CIVIVM, Inscr. Orell. 6: POPVLI, ib. 3766. subventrālis, e, adj. sub-venter, subventral, med. t. t., Ps. - Soran. Quaest. Med. 235. sub-ventrīle, is, n. id."},"subuerbustus":{"lemma":"subverbustus","pos":"adj.","gen":"-class","def":"perhaps contr. from sub verubus ustus, branded under the spear, an epithet of a male or female slave (ante- and post-class.): subverbustam veribus ustam significat Plautus cum ait: ulcerosam"},"subuersor":{"lemma":"subversor","pos":"","gen":"","def":"id., an overturner, overthrower, subverter (very rare): legum (opp. auctor), Tac. A. 3, 28: naturae (diabolus), Alcim. 2, 75. subversus, a, um, Part. of subverto. sub-verto (-vorto), ti, sum, 3"},"subuexus":{"lemma":"subvexus","pos":"adj.","gen":"","def":"subveho, sloping upwards (opp. devexus): omnia fastigio leni subvexa, Liv. 25, 36. sub-vīlĭcus, i, m., an under-steward: HORTORVM, Inscr. Orell. 2860. sub-vĭrĭdis, e, adj., somewhat green"},"suc-cendo":{"lemma":"suc-cendo","pos":"v.","gen":"-cendo","def":"a. sub-candeo"},"suc-coelestis":{"lemma":"suc-coelestis","pos":"","gen":"-coelestis","def":"succaelestis."},"suc-coeno":{"lemma":"suc-coeno","pos":"","gen":"-coeno","def":"succeno. succoerŭlĕus, a, um, v. succaer-. suc-collo (subc-), āvi, ātum, 1, v. a. collum, to take upon the neck or shoulder, to shoulder (very rare): apes fessum (regem) sublevant"},"succabar":{"lemma":"Succabar","pos":"","gen":"","def":", a town in Mauritania, Plin. 5, 2, 1, § 21. suc-caelestis (subc-), e, adj., that which is under the heavens, subcelestial, sublunary: hebdomas, Tert. adv. Val. 31. suc-caerŭlĕus (subc-), a, um, adj."},"succasses":{"lemma":"Succasses","pos":"","gen":"","def":", a people of Gaul, Plin. 4, 19, 33, § 108. suc-căvus (subc-), a, um, adj., hollow below or underneath (ante- and postclass.): areae, Cato, R. R. 151, 3: loca, Lucr. 6, 557"},"succensus":{"lemma":"succensus","pos":"","gen":"","def":"Part. from succendo.— Part. from succenseo. succentīvus, a, um, adj. succino, sounding to, accompanying: tibia, Varr. R. R. 1, 2, 15."},"succentor":{"lemma":"succentor","pos":"","gen":"","def":"id., an accompanier in singing, Aug. Enarr. in Psa. 87, 1; Isid. 7, 12, 26.— Trop., a furtherer, promoter: fabularum, Amm. 19, 12, 13"},"succentus":{"lemma":"succentus","pos":"","gen":"","def":"succino, an accompanying, accompaniment, Mart. Cap. 1, § 11. suc-cerno (subc-), crēvi, crētum, 3, v. a., to sift through, to sift. Lit.: vinaceos cottidie recentes succernito, Cato, R. R. 25; 10, 5"},"successor":{"lemma":"successor","pos":"","gen":"","def":"succedo, II., a follower, successor in office, possession, time, etc. (class.; cf. vicarius): conjunctissimus, Cic. Fam. 3, 3, 1; cf.: successori decessor invidit, id. Scaur. Fragm. 33"},"succi":{"lemma":"Succi","pos":"","gen":"","def":", a people of Thrace, Amm. 26, 7, 12. succīdānĕus, a, um, v. succedaneus, init. succīdĭa, ae, f. 2. succido. A leg or side of meat cut off, esp. of pork"},"succinctim":{"lemma":"succinctim","pos":"adv.","gen":"","def":"succingo, briefly, succinctly: denotare, Claud. Mam. Stat. Anim. praef. succinctĭo, ōnis,f. id., a girding about (late Lat.), Aug. c. Jul. 2, 6. succinctōrĭum, ii, n. id., an apron (late Lat.)"},"succlausus":{"lemma":"succlausus","pos":"adj.","gen":"-claudo","def":"sub-claudo, half-closed , Polem. Physiogn. p. 128. succlīno, āre, 1, v. n. sub-clino, to bend or incline somewhat, Ven. Fort. Ep. Praem. Carm. 5, lib. 6."},"succo":{"lemma":"succo","pos":"","gen":"","def":"suco."},"succus":{"lemma":"succus","pos":"n. m.","gen":"-i","def":"juice, sap; liquid; a potion; moisture"},"sucerda":{"lemma":"sucerda","pos":"","gen":"","def":"sus and root skar-; Gr. σκώρ; cf. stercus, the dung of swine, Lucil. ap. Non. 175, 14; Titin. ap. Fest. p. 302 Müll. (Com. Rel. v. 178 Rib."},"sucro":{"lemma":"Sucro","pos":"adj.","gen":"-nensis","def":"A river of Hispania Tarraconensis, now the Xucar, Mel. 2, 6; Plin. 3, 3, 4, § 20.— A town at the mouth of this river, now Sueca, Plin. 3, 3, 4, § 20; Liv. 28, 24; 28, 26; 28, 29; Sen. Ben. 5, 24, 1"},"suctus":{"lemma":"suctus","pos":"","gen":"","def":"sugo, a sucking, Varr. ap. Non. 169, 15; Plin. 9, 30, 48, § 91; 10, 46, 63, § 129"},"suebri":{"lemma":"Suebri","pos":"","gen":"","def":", a people of Gaul, Plin. 3, 4, 5, § 35. Suël, f., a town in Spain, Plin. 3, 1, 3, § 8; Mel. 2, 6. Suellēni, ōrum, m., a people of Arabia, Plin. 6, 28, 32, § 157."},"suelteri":{"lemma":"Suelteri","pos":"","gen":"","def":", a people of Gallia Narbonensis, Plin. 3, 4, 5, § 35. sŭĕo, ēre assumed as a stem for the form sŭēmus, which is probably a contracted perf., = suevimus from suesco"},"suessa":{"lemma":"Suessa","pos":"adj.","gen":"-ni","def":", = Σύεσσα. A city of Latium, five miles south of the Liris and eight from the sea, founded B. C. 337 by the Aurunci, and afterwards made their capital. It was often called Suessa Aurunca, now Sessa"},"suetri":{"lemma":"Suetri","pos":"","gen":"","def":", an Alpine people, Plin. 3, 20, 24, § 137. suētūdo, ĭnis, f. suesco, custom, habit (late Lat.): blanda, Paul. Pell. Euchar. 179"},"sufferctus":{"lemma":"sufferctus","pos":"","gen":"","def":"suffertus. suffĕrentĭa (subf-), ae, f. suffero, a bearing, enduring, toleration, sufferance (post-class.), Tert. adv. Marc. 4, 15; id. Or. 4 med.; Vulg. Jacob. 5, 11"},"suffes":{"lemma":"suffes","pos":"","gen":"","def":"sufes. suffībŭlum, i, n. sub-fibula, a white four-cornered veil, worn on the head by priests and priestesses, Varr. L. L. 6, § 21 Müll."},"suggestum":{"lemma":"suggestum","pos":"","gen":"","def":"id., a raised place, height, mound: ex suggesto faleris prodeunt anates in stagnum, Varr. R. R. 3, 5, 16.— Esp., a platform, stage"},"suismontium":{"lemma":"Suismontium","pos":"","gen":"","def":", a mountain of Liguria, Liv. 39, 2; 40, 41."},"sulca":{"lemma":"Sulca","pos":"","gen":"","def":", a Roman surname: Q. Baetius Sulca, Liv. 42, 6. sulcāmen, ĭnis, n. sulco, a furrow, = sulcus, App. M. 6, p. 174, 9. sulcātor, ōris, m. id., one who draws furrows, a furrower"},"sulci":{"lemma":"Sulci","pos":"","gen":"","def":", an ancient maritime city on the southern coast of Sardinia, founded by Carthage, now the ruins of Palma de Solo near Sulci, Mel. 2, 7, 19.— Hence, Sulcensis, e, of Sulci: promuntorium, Plin. 3, 7"},"sulco":{"lemma":"sulco","pos":"v.","gen":"","def":"a. sulcus, to furrow, cut furrows through, to plough (mostly poet. and in post-Aug. prose"},"sulcus":{"lemma":"sulcus","pos":"adj.","gen":"-tree","def":", only ficus sulca, an unknown species of fig-tree, Col. 5, 10, 11."},"sulmo":{"lemma":"Sulmo","pos":"adj.","gen":"-mont","def":"A town in the territory of the Peligni, near Corfinium, the birthplace of Ovid, now Sulmona: aquosus, Ov. Am. 3, 15, 11: gelidus, id. F. 4, 81; Sil. 9, 76; 8, 511; Ov. Tr. 4, 10, 3; Cic. Att. 8, 4, 3"},"sulphur":{"lemma":"sulphur","pos":"n. n.","gen":"-uris","def":"sulphur, brimstone; a sulphurous flame"},"summa":{"lemma":"summa","pos":"","gen":"-eminence","def":"(sc. res; old gen. summai, Lucr. 1, 984"},"summara":{"lemma":"Summara","pos":"","gen":"","def":", a town in Ethiopia, Plin. 6, 30, 35, § 193. summārĭum, ĭi, n. summa, a summary, epitome, abstract: oratio, quae nunc vulgo breviarium dicitur, olim, cum Latine loqueremur, summarium, vocabatur"},"summas":{"lemma":"summas","pos":"","gen":"-born","def":"id., of high or noble birth, high-born, noble, eminent, distinguished (ante- and post-class.): vir, Plaut. Ps. 1, 2, 90; id. Stich. 3, 2, 36; Amm. 14, 6, 12"},"summerso":{"lemma":"summerso","pos":"","gen":"","def":"freq. a. id., to plunge repeatedly or thoroughly, Jul. Val. Rer. Gest. Alex. 3, 26. summersus (subm-), a, um, Part. of summergo. summersus (subm-), ūs, m. summergo, a plunging under water"},"summus":{"lemma":"summus","pos":"adj.","gen":"","def":", v. superus. summussi = murmuratores (murmurers). Naevius: odi, inquit, summussos"},"sumptus":{"lemma":"sumptus","pos":"","gen":"","def":"sumpti, Cato, R. R. 22, 3; Lucil., Turp., Caecil., and Varr. ap. Non. 484, 30 sq.; Turp. ib. 132, 16; Plaut. Trin. 2, 1, 21; id. Cas. 2, 7, 2), m. sumo, II. D., expense, cost, charge (class."},"sunt":{"lemma":"sum","pos":"","gen":"","def":"(form of sum)"},"sunuci":{"lemma":"Sunuci","pos":"","gen":"","def":", a Belgic people, Tac. H. 4, 66; Plin. 4, 17, 31, § 106. sŭo, sŭi, sūtum, 3, v. a. Sanscr. siv-, sivjāmi, sew"},"super-incendo":{"lemma":"super-incendo","pos":"v.","gen":"-incendo","def":"n., to inflame more or greatly: hanc (Venus), Val. Fl. 2, 124. sŭpĕrincerno, ĕre, 3, v. a. super-incerno, to sift upon, Plin. 17, 10, 14, § 74. sŭpĕr-incĭdens, entis, Part. , falling from above"},"suppus":{"lemma":"suppus","pos":"adj.","gen":"","def":"(of uncertain signif."},"sura":{"lemma":"Sura","pos":"","gen":"","def":", a river of Germany, now the Saur, Aus. Mos. 355."},"surae":{"lemma":"Surae","pos":"","gen":"","def":", a people of India, Plin. 6, 20, 23, § 73."},"surclo":{"lemma":"surclo","pos":"","gen":"","def":"surculo, II. surcŭlācĕus, a, um, adj. surculus, woody, like wood: durities seminum, Plin. 19, 7, 36, § 119. surcŭlāris, e, adj. id., producing young shoots or sprouts: terra, Col. 3, 11"},"surdaones":{"lemma":"Surdaones","pos":"","gen":"","def":", a people of Spain. Plin. 3, 3, 4, § 24."},"surdaster":{"lemma":"surdaster","pos":"adj.","gen":"","def":"dim. , somewhat deaf, hard of hearing, Cic. Tusc. 5, 40, 116; cf. Prisc. pp. 618 and 628 P. surdē, adv., v. surdus fin."},"surdesco":{"lemma":"surdesco","pos":"","gen":"","def":"inch. n. , to become deaf: aures, Aug. Ep. 157, 4. surdīgo, ĭnis, f. id., deafness (post class.), Marc. Emp. 9 al. surdĭtas, ātis,f. surdus, deafness (rare but ciass.), Cic. Tusc. 5, 40, 116"},"surdus":{"lemma":"surdus","pos":"adj.","gen":"-deaf","def":"Sanscr. svar, heavy; svaras, weight; cf. O. H. Germ. swārida, weight, deaf. Lit.: ne mi ut surdo verbera auris, Plaut. Mil. 3, 1, 204"},"surio":{"lemma":"surio","pos":"v.","gen":"","def":"n., to be in heat (cf. subare), Fest. s. v. suillum, p. 310 Müll.; App. Mag p. 298, 23; Arn. 5, 177."},"surium":{"lemma":"Surium","pos":"","gen":"","def":"A town in Colchis, Plin. 6, 4, 4, § 13.— A town in Dalmatia, Plin. 3, 26, 30, § 152. Surĭus, ii, m., a river of Colchis, Plin. 2, 103, 106, § 226. surpĭcŭlus, v. scirpiculus. sur -rădĭo (subr-), āre"},"surrentum":{"lemma":"Surrentum","pos":"adj.","gen":"-t","def":", a maritime town of Campania, now Sorrento, Mel. 2, 4, 9; Sil. 8, 544"},"surus":{"lemma":"Surus","pos":"","gen":"","def":", a celebrated elephant in the Carthaginian army, mentioned by Cato, Plin. 8, 5, 5, § 12 (v. Syrus). sūs, sŭis (nom. suis, Prud. adv. Symm. 2, 813"},"suscepto":{"lemma":"suscepto","pos":"","gen":"","def":"freq. a. id., to undertake, App. M. 2, p. 128, 22."},"susceptor":{"lemma":"susceptor","pos":"","gen":"-class","def":"id. (post-class.). One who undertakes any thing, an undertaker, contractor (syn.: conductor, redemptor): susceptores sollicitare, Just. 8, 3, 8: nemo militantium fiat susceptor defensorve causarum"},"susceptum":{"lemma":"susceptum","pos":"","gen":"","def":", v. suscipio fin. susceptus, a, um, Part. of suscipio. suscĭpĭo (sometimes succĭpĭo; cf. Serv. Verg. A. 1, 175 and 144"},"suspecto":{"lemma":"suspecto","pos":"","gen":"-class","def":"freq. a. and n. id., to look up at"},"suspector":{"lemma":"suspector","pos":"","gen":"","def":"suspecto fin."},"suspectus":{"lemma":"suspectus","pos":"","gen":"","def":"1. suspicio, a looking up or upwards (poet. and in postAug. prose). Lit.: color nigricans aspectu idemque suspectu refulgens, Plin. 9, 38, 62, § 135: in suspectu esse, id. 37, 9, 40, § 123"},"suspendo":{"lemma":"suspendo","pos":"v.","gen":"-post","def":"a. sus, from subs, for sub"},"sustento":{"lemma":"sustento","pos":"","gen":"","def":"freq. a. sustineo, to hold up or upriqht, to uphold, support, prop, sustain (syn. sustineo). Lit. (only poet. and in post-Aug. prose): multos per annos Sustentata ruet moles et machina mundi, Lucr. 5"},"sustollo":{"lemma":"sustollo","pos":"v.","gen":"-class","def":"a. [subs for sub (v. sub, III.), and tollo], to lift or take up, to raise up, raise (ante- and post-class.; cf.: erigo, effero). In gen.: amiculum, Plaut. Cist. 1, 1, 117"},"susum":{"lemma":"susum","pos":"","gen":"","def":"sursum. sŭsurrāmen, ĭnis, n. 1. susurro, a muttering, murmuring (post-class.): magicum, App. M. 1, p. 103, 23"},"suthul":{"lemma":"Suthul","pos":"","gen":"","def":", a fortress in Numidia, Sall. J. 37, 3"},"sycurium":{"lemma":"Sycurium","pos":"","gen":"","def":", a town of Thessaly, Liv. 42, 54; 42, 56 sq. al."},"sycussa":{"lemma":"Sycussa","pos":"","gen":"","def":", an island in the Aegean Sea, Plin. 5, 31, 38, § 137."},"sydraci":{"lemma":"Sydraci","pos":"","gen":"","def":", a people of India, Plin. 12, 6, 12, § 24. Syēnē, ēs, f., = Συήνη, a town at the southern extremity of Upper Egypt, now Essouan, Plin. 2, 73, 75, § 183 sqq.; Ov. P. 1, 5, 79; Mel. 1, 9, 9"},"sygambri":{"lemma":"Sygambri","pos":"","gen":"","def":"Sigambri."},"sygaros":{"lemma":"Sygaros","pos":"","gen":"","def":", an island of Arabia. Plin. 6, 28, 32, § 155. Sylēum (Syllēum), i, n., = Σύλειον, a stronghold in Pamphylia, Liv. 38, 14, 10."},"sylla":{"lemma":"Sylla","pos":"","gen":"","def":"Sulla. syllăba (sul-), ae, f., = συλλαβή, a syllable. Lit., Plaut. Bacch. 3, 3, 29: syllaba brevior aut longior, Cic. Par. 3, 2, 26: syllabarum numerus, id. de Or. 3, 47"},"syllepsis":{"lemma":"syllepsis","pos":"","gen":"","def":", = σύλληψις, a grammatical figure, by which one word is referred to another in the sentence to which it does not grammatically belong, a syllepsis (e. g. hic arma, Hic currus fuit, Verg. A. 1, 16"},"syllus":{"lemma":"Syllus","pos":"","gen":"","def":", the name of a general, Liv. 42, 51, 7. sylva, sylvānus, etc., v. silva, etc."},"symaethum":{"lemma":"Symaethum","pos":"adj.","gen":"-maeth","def":", or Symaethus i, m., = Σύμαιθος, a river and town situated upon it on the east coast of Sicily, near Catina, Plin. 3, 8, 14, § 89; Sil. 14, 231; 9, 410"},"symmysta":{"lemma":"symmysta","pos":"","gen":"-priest","def":", = συμμύστης, a fellow-priest, colleague in the priesthood, App. Mag. p. 310; Hier. Ep. 58, 11; 66, 9; Schol. Juv. 6, 533."},"sympasma":{"lemma":"sympasma","pos":"","gen":"","def":", = σύμπασμα; in medicine, a powder for sprinkling over the body, Cael. Aur. Acut. 2, 38, 218 al. sympăthīa, ae, f., = συμπάθεια, a feeling in common, sympathy, Varr. ap. Non. 458, 24"},"symphyton":{"lemma":"symphyton","pos":"","gen":"","def":", = σύμφυτον. Wallwort, comfrey, boneset, Plin. 27, 6, 24, § 41. — A plant, called also helenion, Plin. 14, 16, 19, § 108. Symplēgădes, um, f."},"symplegma":{"lemma":"symplegma","pos":"part.","gen":"","def":", = σύμπλεγμα (a twining together), a group of persons embracing or wrestling, Plin. 36, 5, 4, §§ 24 and 35.—In mal. part., Mart. 12, 43, 8"},"sympsalma":{"lemma":"sympsalma","pos":"","gen":"","def":", = σύμψαλμα, a playing together of music, Aug. in Psa. 4, 4; Isid. Orig. 6, 19. synăgōga, ae, f., = συναγωγή, a congregation, synagogue of Jews, Tert. adv. Jud. 8; id. adv. Marc. 3, 22"},"synaxis":{"lemma":"synaxis","pos":"","gen":"","def":", = σύναξις, a gathering, collecting, Ven. Carm. 8, 17. syncĕrastum, i, n., = συγκεραστόν, a dish composed of a variety of ingredients, a hash, hotch-potch: Plautus in Phagone: honos syncerasto perit"},"synchrisma":{"lemma":"synchrisma","pos":"","gen":"-mae","def":"-mae, Veg. 4, 18), n., = σύγχρισμα, an anointing, Veg. 2, 45"},"synopsis":{"lemma":"synopsis","pos":"","gen":"","def":", = σύνοψις, a general view, a list, synopsis: pupillarium bonorum, Dig. 27, 9, 5, § 11. synōris, ĭdis, f., = συνωρίς, a yoke, pair, Hier. Ep. 130, n. 7."},"syntaxis":{"lemma":"syntaxis","pos":"","gen":"","def":", = σύνταξις, the connection of words, Prisc. 17, 1, 1. syntēctĭcus, a, um, adj., = συντηκτικός, ill of consumption, consumptive, syntectic, Plin. 22, 23, 49, § 105; 28, 8, 24, § 88; 28, 9, 33, § 125"},"syra":{"lemma":"Syra","pos":"","gen":"","def":", the name of a slave, Plaut. Merc. 4, 5, 18"},"syrbotae":{"lemma":"Syrbotae","pos":"","gen":"","def":", a people of Ethiopia remarkable for stature, Plin. 6, 30, 35, § 190"},"syriscus":{"lemma":"Syriscus","pos":"","gen":"","def":"Syria, F. sȳrītes, ae, m., = συρίτης, a stone found in the bladder of the wolf, Plin. 11, 37, 83, § 208. Sȳrĭus, a, um, v. Syria, A. Sȳrĭus, a, um, v. Syros."},"syrma":{"lemma":"syrma","pos":"","gen":"","def":"(neutr., Juv. 8, 229; Sen. Herc. Fur. 474), = σύρμα. A robe with a train, Sen. Oed. 423; Prud. Psych. 362; worn esp. by trag. actors, Juv. 8, 229; Val. ap. Prisc. p. 679 P."},"syrnos":{"lemma":"Syrnos","pos":"","gen":"","def":", an island in the Aegean Sea, one of the Sporades, Plin. 4, 12, 23, § 69."},"syron":{"lemma":"syron","pos":"","gen":"","def":", another name for the plant molon, Plin. 26, 7, 19, § 33. Syrŏphoenix, īcis, m., = Συροφοίνιξ, a Syrophoenician (on the borders of Syria and Phoenicia), Lucil. ap. Non. 397, 27"},"syrtis":{"lemma":"Syrtis","pos":"adj.","gen":"-bank","def":"Syrtidos, Luc. 9, 710), f., = Σύρτις, a sand-bank in the sea; esp. on the northern coast of Africa, Syrtis Major, near Cyrenaica, now Gulf of Sidra"},"syrus":{"lemma":"syrus","pos":"","gen":"","def":", a broom, besom, Varr. ap. Non. 46, 10."},"tabae":{"lemma":"Tabae","pos":"","gen":"","def":"A town of Caria, on the boundaries of Phrygia, now Damas, Liv. 38, 13, 11.— A city in the inner part of Sicily, Sil. 14, 272.— A city of Paroetacene, between Persis and Media, Curt. 5, 1, 13. tăbānus"},"tabis":{"lemma":"Tabis","pos":"","gen":"","def":", a mountain of Eastern Asia, Plin. 17, 17, 29, § 53; Mel. 3, 7, 1. tābĭtūdo, ĭnis, f. tabidus, consumption, decline: morbo ad tabitudinem redactus, Plin. 22, 25, 61, § 129"},"tactor":{"lemma":"tactor","pos":"","gen":"","def":"id., a toucher (late Lat.), Aug. in Psa. 95, 6. tactus, a, um, Part. of tango."},"tactus":{"lemma":"tactus","pos":"","gen":"","def":"tango, a touching, touch, handling (class.). Lit.: salutantum tactu praeterque meantum, Lucr. 1, 318: quae (chordae) ad quemque tactum respondeant, Cic. de Or. 3, 57, 216: leo asper tactu, Hor. C. 3"},"tader":{"lemma":"Tader","pos":"","gen":"","def":", a river in Spain, Plin. 3, 1, 3, § 9; 3, 3, 4, § 19. Tadĭātes, um, m., an extinct tribe of Central Italy, Plin. 3, 12, 17, § 108. Tadinātes, um, m., a people of Umbria, Plin. 3, 14, 19 § 114."},"tadius":{"lemma":"Tadius","pos":"","gen":"","def":", a painter of the Age of Augustus, Plin. 35, 10, 37, § 116."},"tadu":{"lemma":"Tadu","pos":"","gen":"","def":", an island near Meroë in Ethiopia, Plin. 6, 29, 33, § 185 Jan. (al. Tado). taeda (tēda), ae (gen. taedaï, Lucr. 6, 897), f. etym. dub."},"taedeo":{"lemma":"taedeo","pos":"","gen":"","def":"taedet, II."},"taedescit":{"lemma":"taedescit","pos":"","gen":"","def":"impers. inch. , it disgusts: quos prius taedescit impudicitiae suae quam pudescit, who are disgusted, Min. Oct. 28 fin."},"taedet":{"lemma":"taedet","pos":"","gen":"","def":"impers. [perh. root tau-; Sanscr. tu-, to be strong; tiv-, to grow fat; cf. tumeo]. It disgusts, offends, wearies one; I (thou, he, etc.) am disgusted, offended, tired, weary of, I loathe, etc."},"tagrus":{"lemma":"Tagrus","pos":"","gen":"","def":", a mountain in Lusitania, Varr. R. R. 2, 1, 19. Tăgus, i, m., a river in Lusitania, celebrated for its golden sands, now Tajo or Tagus, Liv. 21, 5, 8; Mel. 3, 1, 6; Plin. 4, 22, 35, § 115"},"talla":{"lemma":"talla","pos":"","gen":"","def":", a peel or coat of an onion, Lucil. ap. Non. 201, 2; cf.: talla κρομμύου λέπυρον, Gloss. Philox."},"talpa":{"lemma":"talpa","pos":"","gen":"","def":"(masc., Verg. G. 1, 183) [root scalp-; Gr. σκάλοψ; cf. Lat.: scalpo, scalprum], a mole, Cic. Ac. 2, 25, 81; Plin. 9, 7, 6, § 17; 10, 69, 88, § 191; 30, 5, 12, § 38; Sen. Q. N. 3, 16, 5"},"talutatium":{"lemma":"talutatium","pos":"","gen":"","def":""},"tam":{"lemma":"tam","pos":"adv.","gen":"-clause","def":"orig. acc. fem. of the demonstrative root ta-"},"tamarici":{"lemma":"Tamarici","pos":"","gen":"","def":", a people of Hispania Tarraconensis, on the river Tamaris, Plin. 4, 20, 34, § 111; Mel. 3, 1, 8; cf. Plin. 31, 2, 18, § 23. tămărix, īcis, f., a tamarisk, tamariskshrub, Col. 8, 15, 4"},"tamfana":{"lemma":"Tamfana","pos":"","gen":"","def":", the name of a deity worshipped by the Marsi, Tac. A. 1, 51. tămĭăcus, a, um, adj., = ταμιακός, of or belonging to the imperial treasury or fisc. Adj.: praedia, crown-lands, imperial domains"},"tamnus":{"lemma":"tamnus","pos":"","gen":"","def":"taminia. Tamphĭlus, i, m., a Roman surname. Cn. Baebius Tamphilus, Liv. 31, 49 fin."},"tandem":{"lemma":"tandem","pos":"adv.","gen":"","def":"tam and the demonstr. termination dem; prop. just so far"},"tanos":{"lemma":"tanos","pos":"","gen":"","def":", a precious stone, otherwise unknown, Plin. 37, 5, 19, § 74."},"tanquam":{"lemma":"tanquam","pos":"adv.","gen":"","def":", v. tamquam. Tantălĕus, Tantălĭdes, Tantă-lis, v. Tantalus. Tantălus (-los), i (Greek collat. form of dat. Tantaleo, after the form Τανταλεύς), m., = Τάνταλος, a king of Phrygia, son of Jupiter"},"tantillus":{"lemma":"tantillus","pos":"adj.","gen":"-clause","def":"dim. , so little, so small; in neutr. subst., so little a thing, such a little thing (mostly anteclass."},"tantis-per":{"lemma":"tantis-per","pos":"adv.","gen":"-per","def":"tantus, for so long a time, so long"},"tantum":{"lemma":"tantum","pos":"adv.","gen":"","def":", v. tantus fin. tantummŏdo, v. tantus, II. B. b."},"tantundem":{"lemma":"tantundem","pos":"","gen":"","def":"tantusdem. tantus, a, um, adj. perh. for tavantus; cf. Sanscr. tāvant, so great"},"tantus-dem":{"lemma":"tantus-dem","pos":"adj.","gen":"-dem","def":", just so great or large, as great (as an adj. rare, but freq. and class. in the neutr. as a subst.). Adj.: malo bene facere tantundem est periculum, Quantum bono male facere, Plaut. Poen. 3, 3"},"taphrae":{"lemma":"Taphrae","pos":"","gen":"","def":", = Τάφραι. The isthmus of the Tauric Chersonese, Mel. 2, 1"},"taposiris":{"lemma":"Taposiris","pos":"","gen":"","def":", a town in Egypt, Plin. 27, 7, 29, § 53"},"taranucnus":{"lemma":"Taranucnus","pos":"","gen":"","def":", the name of a German deity, Inscr. Orell. 2055 sq."},"tarbelli":{"lemma":"Tarbelli","pos":"adj.","gen":"-bell","def":", a people in Aquitanian Gaul, extending southwards from Burdigala to the Pyrenees, in the neighborhood of the mod. Dax, Caes. B. G. 3, 27; Plin. 4, 19, 33, § 108"},"tarcondimotus":{"lemma":"Tarcondimotus","pos":"","gen":"","def":", a Cilician prince and faithful ally of the Romans, Cic. Fam. 15, 1, 2. tardābĭlis, e, adj. tardo, that renders slow: rigor, Tert. Anim. 43. tardātĭo, ōnis, f. id., slowness, sluggishness"},"tardesco":{"lemma":"tardesco","pos":"","gen":"","def":"inch. n., to become slow: tardescit lingua, grows sluggish, hesitates, stammers, Lucr. 3, 479"},"tardo":{"lemma":"tardo","pos":"v.","gen":"","def":"a. and n. id.. Act., to make slow, to hinder, delay, retard, impede, prevent (freq. and class."},"tardor":{"lemma":"tardor","pos":"","gen":"","def":"tardus, slowness (anteclass. form for tarditas): versuum, Varr. ap. Non. 229, 22."},"tardus":{"lemma":"tardus","pos":"adj.","gen":"","def":", slow, not swift, sluggish, tardy (freq. and class."},"targines":{"lemma":"Targines","pos":"","gen":"","def":", a river of Magna Graecia, Plin. 3, 10, 15, § 96 (al. Thagines or Thargines). Tarichēa, ae, f., the sea or lake of Galilee, Plin. 5, 15, 15, § 71. Tarichēae, ārum, f., a town of Galilee"},"tariotae":{"lemma":"Tariotae","pos":"","gen":"","def":", a people of Dalmatia, Plin. 3, 22, 26, § 141. tarmĕs, ĭtis, m. root tero; Gr. τείρω, to bore, a worm that eats wood, a woodworm, Plaut. Most. 3, 2, 140.—Written also termes, Isid. Orig. 12, 5, 10"},"tarnis":{"lemma":"Tarnis","pos":"","gen":"","def":", a river of Gaul falling into the Garonne, now the Tarn, Aus. in Mos. 465; Plin. 4, 19, 33, § 109; Sid. 24, 44."},"tarpa":{"lemma":"Tarpa","pos":"","gen":"","def":"Maecius. Tarpēius, i, m.; Tarpēia, ae, f., a Roman proper name; so esp., Sp. Tarpeius, the father of Tarpeia, who opened the citadel to the Sabines, Liv. 1, 11"},"tarsatica":{"lemma":"Tarsatica","pos":"","gen":"","def":", a city of Illyria, Plin. 3, 21, 25, § 140."},"tarsus":{"lemma":"Tarsus","pos":"adj.","gen":"","def":", the capital of Cilicia, now Tersoos, Cic. Fam. 2, 17, 1; id. Att. 5, 20, 3; Luc. 3, 225"},"tarum":{"lemma":"tarum","pos":"","gen":"-wood","def":", aloe-wood, Plin. 12, 20, 44, § 98. Tarusātes, ĭum, m., a people of Aquitanian Gaul, Caes. B. G. 3, 23; 3, 27; Plin. 4, 19, 33, § 108."},"tarutius":{"lemma":"Tarutius","pos":"","gen":"","def":", a Roman proper name: L. Tarutius Firmanus, a celebrated astrologer, Cic. Div. 2, 47, 98. tasconĭum, ii, n., a white, clayey kind of earth, Plin. 33, 4, 21, § 69. Tasgetĭus, ii, m."},"tatae":{"lemma":"tatae","pos":"interj.","gen":"","def":", an exclamation of surprise, so! the deuce! Sa. Fac tu hoc modo. St. At tu hoc modo. Sa. Babae! St. Tatae! Sa. Papae! St. Pax! Plaut. Stich. 5, 5, 31"},"tattaeus":{"lemma":"Tattaeus","pos":"","gen":"","def":": sal, the name of a marsh in Phrygia, Plin. 31, 7, 41, § 84; 31, 9, 45, § 99. tătŭla, ae, m. dim. tata, daddy, Inscr. Donat. 4, 68."},"tau":{"lemma":"tau","pos":"","gen":"","def":"indecl., a Celtic word of unknown meaning, Verg. Cat. ap. Quint. 8, 3, 28; cf. Aus. Idyll. 12, 6."},"taueni":{"lemma":"Taveni","pos":"","gen":"","def":", a people of Arabia, Plin. 6, 28, 32, § 157. tax, an onomatopee, expressing the sound of blows, Engl. whack: tax tax tergo meo erit: non curo, my back will get whack, whack, Plaut. Pers. 2, 3"},"taum":{"lemma":"Taum","pos":"","gen":"","def":", an arm of the sea in Britain, now the Firth of Tay, Tac. Agr. 22."},"taunus":{"lemma":"Taunus","pos":"","gen":"","def":", a mountain range in Western Germany (between Frankfort and Mayence), now called Taunus, or the Höhe, Mel. 3, 3, 3; Tac. A. 1, 56; 12, 28."},"taura":{"lemma":"taura","pos":"","gen":"-martin","def":", = ταῦρα, a barren, hybrid cow, a free-martin, Varr. R. R. 2, 5, 6; Col. 6, 22, 1"},"tauri":{"lemma":"Tauri","pos":"adj.","gen":"","def":", the Taurians, a Thracian people, living in what is now Crimea, who sacrificed foreigners to Diana, Mel. 2, 1, 11; Cic. Rep. 3, 9, 15"},"tauris":{"lemma":"Tauris","pos":"","gen":"","def":", an island near Illyria, Auct. B. Alex. 45, 1 sq."},"taurisci":{"lemma":"Taurisci","pos":"adj.","gen":"","def":", an Alpine tribe in Pannonia, Plin. 3, 25, 28, § 148; 3, 19, 23, § 133.—Hence, Tauriscus, a, um, adj., of or belonging to the Taurisci: gens, Plin. 3, 20, 24, § 134."},"tauriscus":{"lemma":"Tauriscus","pos":"","gen":"","def":"Taurisci."},"taurophthalmon":{"lemma":"taurophthalmon","pos":"","gen":"-eye","def":", = ταυρόφθαλμον, the ox-eye, a kind of rosemary, App. Herb. 79. Taurŏpōlos, i, f., an appellation of Diana, who, under this name, had a temple at Amphipolis, Liv. 44, 44"},"taurus":{"lemma":"taurus","pos":"","gen":"","def":"= Gr. ταῦρος; Sanscr. sthūrus; Goth. stiur; Germ. Stier, a bull, bullock, ox, steer. Lit., Varr. R. R. 2, 5; Col. 6, 20; Plin. 8, 45, 70, § 176; Plaut. Ps. 1, 2, 66; Cic. Div. 2, 16, 36 sq."},"taxa":{"lemma":"taxa","pos":"","gen":"","def":", a kind of laurel, Plin. 15, 30, 39, § 130. taxātĭo, ōnis, f. taxo, a rating, valuing, appraisal, estimation. In gen. (cf. aestimatio): ejus rei taxationem nos fecimus"},"taxilae":{"lemma":"Taxilae","pos":"","gen":"","def":", the name of a people in India, Plin. 6, 20, 23, § 78."},"taxillus":{"lemma":"taxillus","pos":"","gen":"","def":"acc. to Cic. Or. 45, 153, the primitive whence talus, a small die, Pompon. ap. Prisc. p. 615 P. (Com. Fragm. v. 190 Rib.); Vitr. 10, 8, 2."},"taxim":{"lemma":"taxim","pos":"","gen":"","def":"for tetigerim; v. tango init."},"taxo":{"lemma":"taxo","pos":"","gen":"","def":"freq. a. tago, tango, to touch sharply, to feel, handle (post-Aug.; but cf. taxatio"},"taxus":{"lemma":"taxus","pos":"","gen":"-tree","def":", a yew, yew-tree. Lit., Plin. 16, 10, 20, § 50; Caes. B. G. 6, 31; Verg. E. 9, 30"},"tazata":{"lemma":"Tazata","pos":"","gen":"","def":", an island in the Caspian Sea, Plin. 6, 17, 19, § 52. tē, v. tu. tĕ, a pronominal suffix, e. g. tute, tete"},"teba":{"lemma":"teba","pos":"","gen":"","def":", an old Latin term, in Varro's time still used among the Sabines, signifying a hill: lingua prisca et in Graeciā Aeolis Boeotii sine afflatu vocant colles tebas: et in Sabinis"},"tecmon":{"lemma":"Tecmon","pos":"","gen":"","def":", a town of Epirus, Liv. 45, 26, 4. tēcŏlĭthos, i, m., = τηκόλιθος (stonedissolver), a stone, otherwise unknown, Plin. 36, 19, 35, § 143; 37, 10, 68, § 184"},"tector":{"lemma":"tector","pos":"","gen":"","def":"tego, one that overlays walls with plaster, stucco, etc., a plasterer, pargeter: villa tua, quam neque pictor neque tector vidit umquam, Varr. R. R. 3, 2, 9; Cic. Planc. 25, 62; Front. Aquaed. 117"},"tectum":{"lemma":"tectum","pos":"","gen":"","def":"tego. Lit., a covering. A roof: quojus (villae) Deturbavit ventus tectum ac tegulas, Plaut. Rud. prol. 78: de tecto deturbavit tegulas, id. ib. 1, 1, 5. tecta domorum, Lucr. 2, 191"},"ted":{"lemma":"ted","pos":"","gen":"","def":"tu"},"tegmen":{"lemma":"tegmen","pos":"","gen":"","def":"tegimen. tĕgo, xi, ctum, 3, v. a. Gr. στέγω, to cover; τέγος, στέγος, roof; Sanscr. sthag-, to hide; Germ. decken"},"telandria":{"lemma":"Telandria","pos":"","gen":"","def":", an island near Lycia, Plin. 5, 31, 35, § 131. Telchīnes, um, m., = Τελχῖνες, a fabled family of priests in Rhodes, famous for their magic arts, Ov. M. 7, 365"},"telendos":{"lemma":"Telendos","pos":"","gen":"","def":", an island near Lycia, Plin. 5, 31, 35, § 131. tēlĕphĭon, ii, n., = τηλέφιον, a kind of herb resembling purslane: Sedum telephium, Linn."},"telluster":{"lemma":"telluster","pos":"adj.","gen":"","def":"tellus, of or belonging to the earth, terrestrial: tellustres silvicolaeque divi, Mart. Cap. 7, § 729."},"telmessus":{"lemma":"Telmessus","pos":"adj.","gen":"-m","def":", = Τελμησσος or Τελμισσός, a town in Lycia, near to Caria, at the head of the Glaucus Sinus, now Makri; it was famed for the skill of its inhabitants in divination, Cic. Div. 1, 41, 91"},"temarunda":{"lemma":"Temarunda","pos":"","gen":"","def":", a Scythian name of the Palus Maeotis, Plin. 6, 7, 7, § 20. Tĕmĕnītis, ĭdis, f., v. Temenos. Tĕmĕnītis, ĭdis, f., = Τεμενῖτις (Polyb. c. 27, 7): porta, a gate of Tarentum, Liv. 25, 9"},"temno":{"lemma":"temno","pos":"v.","gen":"","def":"a. root tam-, to cut; Gr. τέμνω, to slight, scorn, disdain, despise, contemn (poet. and very rare for the class. contemnere); semper aves quod abest praesentia temnis, Lucr. 3, 957"},"temo":{"lemma":"temo","pos":"","gen":"","def":", a sum of money paid instead of furnishing recruits, commutationmoney, Cod. Th. 6, 26, 14 sq. temōnārĭus, a, um, adj. 2. temo, of or belonging to the commutation for recruits: onera, Cod. Just. 12"},"templum":{"lemma":"templum","pos":"","gen":"","def":"prob. for temulum; root τεμ- of τέμνω; cf. τέμενος, a sacred enclosure; hence, Lit., a space marked out"},"tendor":{"lemma":"tendor","pos":"","gen":"","def":"tendo, a stretching, straining, tension: faucium, App. M. 4, p. 153, 32. Tenĕa, ae, f., = Τενέα, a town between Corinth and Mycenae, now Klenia, Cic. Att. 6, 2, 3. tĕnĕbellae, ārum, f. dim. tenebrae"},"tensa":{"lemma":"tensa","pos":"","gen":"","def":", the chariot or car on which the images of the gods were borne in the Circensian games. Lit.: tensam ait vocari Sinnius Capito vehiculum"},"tentor":{"lemma":"tentor","pos":"","gen":"","def":", a holder, a sort of servant or attendant employed at chariotraces, Inscr. Grut. 339, 5; 340, 3. tentōrĭŏlum, i, n. dim. tentorium, a little tent, Auct. B. Afr. 47, 5. tentōrĭum, ii, n. tendo"},"tentus":{"lemma":"tentus","pos":"","gen":"","def":"Part. of tendo.— Part. of teneo. tentŭs, ūs, m. teneo, a checking: haemorrhoidarum fluoris, Cael. Aur. Tard. 5, 1, 2."},"tentyra":{"lemma":"Tentyra","pos":"adj.","gen":"","def":", = Τέντυρα, τά, a city in Upper Egypt, the modern village of Denderah, Juv. 15, 35 and 76.—Called also Tentyris, Plin. 5, 9, 11, § 60.— Hence, Tentyrītes, ae, adj., of or belonging to Tentyra"},"ter-nox":{"lemma":"ter-nox","pos":"","gen":"-nox","def":", a threefold night: Herculea, in which Hercules was begotten, Stat. Th. 12, 301."},"tercentum":{"lemma":"tercentum","pos":"num.","gen":"","def":", three hundred, v. ter. ter-dĕcĭes or -ĭens, adv. num., thirteen times: quem circulum luna terdecies in duodecim mensibus percurrit, Vitr. 9, 4: respirare, Juv. 14, 28: HS. terdeciens, Cic. Verr. 2"},"terensis":{"lemma":"Terensis","pos":"","gen":"","def":"(sc. dea) , the goddess that presides over threshing, Arn. 4, p 131. Tĕrentĭānus, v. Terentius, B. Terentillns, a, the name of a Roman gens, e g C Terentillus Arsa, author of the lex Terentilla"},"tereses":{"lemma":"Tereses","pos":"","gen":"","def":", a people of Spain, Plin 3, 1, 3, § 14. Tēreus, ĕi or ĕos, m., = Τηρεύς. A king of Thrace, husband of Procne, the sister of Philomela, whom he violated, Hyg. Fab. 45; Ov. F. 2, 629"},"tergedum":{"lemma":"Tergedum","pos":"","gen":"","def":", a town of Ethiopia, Plin. 6, 29, 35, § 184. ter-gĕmĭnus, a, um, v. trigeminus. ter-gĕnus, adv., of a threefold kind"},"tergeste":{"lemma":"Tergeste","pos":"adj.","gen":"","def":", the northernmost town on the coast of Istria, the mod. Trieste, Mel. 2, 4, 3; Plin. 3, 18, 22, § 127"},"tergilla":{"lemma":"tergilla","pos":"","gen":"","def":"dim. tergum, the skin, sward, or rind of pork, Apic. 4, 3"},"tergo":{"lemma":"tergo","pos":"","gen":"","def":"tergeo. tergŏro, ăre, v. a. tergus, to cover cover over with any thing: sues luto se ter gorantes, Plin. 8, 52, 78, § 212. tergum, i (poet. and in post-Aug. prose also tergus, ŏris)"},"tergus":{"lemma":"tergus","pos":"","gen":"","def":"tergum. Tĕrīna, ae, f., a town in the Bruttian territory, Plin. 3, 5, 10, § 72"},"termen":{"lemma":"termen","pos":"","gen":"","def":"terminus init."},"termentum":{"lemma":"termentum","pos":"","gen":"","def":": termentum pro eo, quod nunc dicitur detrimentum, utitur Plautus in Bacchidibus (4, 9, 5), Fest. p. 363 Müll."},"termes":{"lemma":"termes","pos":"","gen":"","def":"tarmes."},"termessus":{"lemma":"Termessus","pos":"","gen":"","def":", = Τερμησσός, a town in Pisidia, now Karabunar Kini, Liv. 38, 15. — Hence, Termessenses, ĭum, m., the inhabitants of Termessus, Liv. l. l. termĭnālis, e, adj. terminus. Of or belonging to boundaries"},"termo":{"lemma":"termo","pos":"","gen":"","def":"terminus init. ternārĭus, a, um, adj. terni, containing or consisting of three, ternary. Adj.: scrobes, i. e. of three feet, Col. 11, 2, 28: numerus, Aus. Idyll. 11 praef. — Subst.: ternārĭus, ii, m."},"terni":{"lemma":"terni","pos":"adj.","gen":"","def":"distr. adj. . Lit., three each: ea partes habet novem discretas, ter ternas, Varr. R. R. 2, 1, 12"},"ternus":{"lemma":"ternus","pos":"","gen":"","def":"terni. tĕro, trīvi, trītum, 3 (perf. terii, acc. to Charis. p. 220 P.; perf. sync. tristi, Cat. 66, 30), v. a. root ter; Gr. τείρω, τρύω, τρίβω, to rub; cf. Lat. tribulare, triticum"},"terra":{"lemma":"terra","pos":"n. f.","gen":"-ae","def":"earth, land, ground, soil; a country, region, territory"},"terrae":{"lemma":"terra","pos":"n. f.","gen":"-ae","def":"earth, land, ground, soil; a country, region, territory","form_of":"terra"},"terram":{"lemma":"terra","pos":"n. f.","gen":"-ae","def":"earth, land, ground, soil; a country, region, territory","form_of":"terra"},"terrarum":{"lemma":"terra","pos":"n. f.","gen":"-ae","def":"earth, land, ground, soil; a country, region, territory","form_of":"terra"},"terras":{"lemma":"terra","pos":"n. f.","gen":"-ae","def":"earth, land, ground, soil; a country, region, territory","form_of":"terra"},"terrestris":{"lemma":"terrestris","pos":"adj.","gen":"-journey","def":"masc. terrester, Flor 2, 2, 4"},"terror":{"lemma":"terror","pos":"","gen":"","def":"terreo, great fear, affright, dread, alarm, terror (syn.: pavor, trepidatio, metus). Lit.: definiunt terrorem metum concutientem: ex quo fit, ut pudorem rubor"},"tersus":{"lemma":"tersus","pos":"","gen":"-powder","def":"tergeo, a wiping off, cleansing (Appuleian): lintea tersui profer, App. M. 1, p. 113, 2: tersui dentium petere aliquid, i.e. for tooth-powder, id. Mag. p. 277, 2."},"tertia":{"lemma":"Tertia","pos":"","gen":"","def":", v. tertius, a, um, II. B. tertĭa-dĕcĭmāni, ōrum, m. (sc. milites) , soldiers of the thirteenth legion, Tac. H. 3, 27. tertĭānus, a, um, adj. id., of or belonging to the third"},"tessella":{"lemma":"tessella","pos":"","gen":"","def":"dim. tessera, a small square piece of stone, a little cube, for pavements, etc., Sen. Q. N. 6, 31, 2; Juv. 11, 132; Plin. 37, 10, 54, § 144; 17, 16, 26, § 120"},"testa":{"lemma":"testa","pos":"","gen":"-ware","def":"= tosta, from torreo, a piece of burned clay, a brick, tile, ὄστρακον. Lit., Cic. Dom. 23, 61; Cato, R. R. 18, 7; 18, 110; Varr. R. R. 2, 3, 6; Vitr. 2, 8 fin.; 7, 1; 7, 4"},"testis":{"lemma":"testis","pos":"","gen":"-clause","def":"(neutr. form: caelum teste vocat, Alcim. 6, 576), one who attests any thing (orally or in writing), a witness (cf. superstes): testes vinctos attines, Plaut. Truc. 4, 3"},"testum":{"lemma":"testum","pos":"","gen":"","def":"testu."},"teta":{"lemma":"teta","pos":"","gen":"","def":", a kind of dove: columbae, quas vulgus tetas vocat, Serv. Verg. E. 1, 58. tĕtănĭcus, i, m., = τετανικός, one affected with tetanus (cramp in the neck), Plin. 20, 22, 87, § 239; 26, 12, 81, § 130"},"teucer":{"lemma":"Teucer","pos":"adj.","gen":"-in","def":"Teucrus, Verg. A. 3, 108; Lact. 1, 21, 1), m., = Τεῦκρος. Son of Telamon, king of Salamis, and brother of Ajax, Hor. C. 1, 7, 21; 1, 7, 27; 1, 15, 24; 4, 9, 17; id. S. 2, 3, 204; Ov. M. 13, 157"},"teucri":{"lemma":"Teucri","pos":"","gen":"","def":"Teucer, II. 1. and 2. b. teucrĭon, ĭi, n., = τεύκριον. A plant, the germander: Teucrium chamaedrys, Linn.; Plin. 24, 15, 80, § 130 (al. Teucria).— The herb spleenwort: Teucrium flavium, Linn."},"teucris":{"lemma":"Teucris","pos":"","gen":"","def":"Teucer. Tĕus, i, v Teos."},"teuta":{"lemma":"Teuta","pos":"","gen":"","def":", a queen of Illyria, Plin. 34, 6, 11, § 24. — Called also Teutāna, Flor. 2, 5, 2. Teutāni, ōrum, m., a people of the Peloponnesus, Plin. 3, 5, 8, § 50. Teutātes, ae, m., a deity of the Gauls"},"teuthras":{"lemma":"Teuthras","pos":"adj.","gen":"-t","def":", = Τεύθρας. A king of Mysia, father of Thespius, Hyg. Fab. 99 and 100.—Hence, Teuthran-tēus, a, um, adj., of or belonging to Teuthras"},"teutobodiaci":{"lemma":"Teutobodiaci","pos":"","gen":"","def":", a people of Galatia, Plin. 5, 32, 42, § 146."},"teutoburgiensis":{"lemma":"Teutoburgiensis","pos":"adj.","gen":"","def":", of or belonging to the citadel of the Teutones: saltus, a forest of Western Germany in which Varus was defeated A. D. 9, Tac. A. 1, 60."},"teutomatus":{"lemma":"Teutomatus","pos":"","gen":"","def":", a king of the Nitiobriges, Caes. B. G. 7, 31; 7, 46. Teutŏni, ōrum (collat. form Teutŏ-nes, um, Caes. B. G. 7, 77 fin.; Vell. 2, 12, 4; Aur. Vict. Vir. Ill. 67"},"texo":{"lemma":"texo","pos":"v.","gen":"","def":"paragog. texier, Plaut. Trin. 3, 3, 69), 3, v. a. root tek-; Gr. ἔτεκον, τίκτω, to beget; Sanscr. takman, child; taksh, to make, to weave (class."},"textor":{"lemma":"textor","pos":"","gen":"","def":"texo, a weaver, Plaut. Aul. 3, 5, 45; Hor. Ep. 1, 19, 13; Mart. 12, 59, 6"},"textrix":{"lemma":"textrix","pos":"","gen":"","def":"textor, a female weaver, Mart. 4, 19, 1; Inscr. Rein. cl. 9, n. 77; Dig. 33, 9, 3, § 6; Tib. 2, 1, 65; App. M. 6, p. 181, 25. — In apposition: anus, i. e. the Fates, App. M. 6, p. 180, 39."},"textum":{"lemma":"textum","pos":"","gen":"","def":"texo fin. textūra, ae, f. texo, a web, texture (very rare). Lit.: aranearum, Plaut. Stich. 2, 2, 24: Minervae, Prop. 4 (5), 5, 23. Sen. Ep. 121, 22.— Transf., a construction"},"textus":{"lemma":"textus","pos":"","gen":"","def":"texo, I. B., texture, tissue, structure (poet. and in post - Aug. prose). Lit.: haec sunt tenuia textu, Lucr. 4, 728: capiuntur purpurae parvulis rarique textu, Plin. 9, 37, 61, § 132"},"thabraca":{"lemma":"Thabraca","pos":"","gen":"","def":", a city of Numidia on the coast of the Mediterranean, Mel. 1, 7, 1; Juv 10, 194, Plin. 5, 3, 2, § 22. Thāis, ĭdis, f., = Θαΐς, a celebrated courtesan of Athens, Prop. 2, 6, 3; 4 (5), 5, 43"},"thala":{"lemma":"Thala","pos":"","gen":"","def":", = Θάλα, an important town of Numidia, Sall. J. 75, 1 sq.; Tac. A. 3, 21"},"thalli":{"lemma":"Thalli","pos":"","gen":"","def":", a people on the Caspian Sea, Plin. 6, 5, 5, § 17. Thallumētus, i, m., a slave of Atticus, Cic. Att. 5, 12, 2."},"thallus":{"lemma":"thallus","pos":"","gen":"","def":", = θαλλός, a green stalk, green bough: cepae, Col. 11, 3, 58; Pall. Febr. 24, 4: Amyclaeus, perh. a myrtlebough, Verg. Cir. 376; Vulg. 2 Macc. 14, 4."},"thalna":{"lemma":"Thalna","pos":"","gen":"","def":", a Roman surname of the Juventian gens, Liv. 39, 31."},"thamnum":{"lemma":"thamnum","pos":"","gen":"","def":"thannum. Thămyras, ae, m., a Thracian poet who entered into a contest with the Muses, and, being vanquished, was deprived of his eyes, Prop. 2, 22 (3, 15), 19; Ov. Am. 3, 7, 62; id. A. A. 3, 399"},"thaumas":{"lemma":"Thaumas","pos":"adj.","gen":"-t","def":", = Θαύμας, the father of Iris, Cic. N. D. 3, 20, 51.—Hence, Thaumantēus, a, um, adj., of or belonging to Thaumas, Thaumantian: virgo, i. e. Iris, Ov. M. 14, 845.— Thauman-tĭăs, ădis, f."},"theangelis":{"lemma":"theangelis","pos":"","gen":"","def":", a kind of plant growing on Libanus, Plin. 24, 17, 102, § 164. thĕātrālis, e, adj. theatrum, of or belonging to the theatre, theatrical: theatrales gladiatoriique consessus, Cic. Sest. 54"},"theium":{"lemma":"Theium","pos":"","gen":"","def":", a town of Athamania, Liv. 38, 1. Thĕlis, is, v. Thetis. Thelxĭnŏē, ēs, f., one of the first four Muses, Cic. N. D. 3, 21, 54. thēlygŏnon, i, n."},"thensaurus":{"lemma":"thensaurus","pos":"","gen":"","def":"thesaurus. Thĕōcrĭtus, i, m., = Θεόκριτος, a celebrated Grecian idyllic poet, Quint. 10, 1, 55; Macr. S. 5, 2, 4"},"thermae":{"lemma":"thermae","pos":"adj.","gen":"-t","def":"(sc. aquae), = θερμὰ ὕδατα, warm springs, warm baths (natural or artificial; cf.: tepula aqua): Agrippae, Plin. 34, 8, 19, § 62; 35, 4, 9, § 26; 36, 25, 64, § 189: Neronianae, Mart. 7, 34, 5"},"thermus":{"lemma":"Thermus","pos":"","gen":"","def":", a Roman cognomen in the Minucian gens: Q. Minucius Thermus, Cic. Fam. 2, 17, 6; 2, 17, 18"},"thespis":{"lemma":"Thespis","pos":"","gen":"","def":", = Θέσπις, the founder of the Greek drama, Hor. A. P. 276; id. Ep. 2, 1, 163. Thesprōti, ōrum, m., = Θεσπρωτοί, a people in the south-western part of Epirus, Luc. 3, 179"},"thestor":{"lemma":"Thestor","pos":"","gen":"","def":", = Θέστωρ, the father of the soothsayer Calchas, Hyg. Fab. 128.— Hence, Thestŏrĭdes, ae, m., the son of Thestor, i. e. Calchas, Ov. M. 12, 19; 12, 27"},"theuma":{"lemma":"Theuma","pos":"","gen":"","def":", a village of Thessaly, Liv. 32, 13 fin. Theumēsus, i, m., a mountain of Boeotia, near Thebes, Stat. Th. 4, 372. — Hence, Theumēsius, a, um, adj., Theban, amnis, i. e. Ismenus, Stat. Th. 8"},"thibii":{"lemma":"Thibii","pos":"","gen":"","def":", a fabulous people of Pontus, Plin. 7, 2, 2, § 17."},"thieldones":{"lemma":"thieldones","pos":"","gen":"","def":"Span., a kind of Spanish horse, Plin. 8, 42, 67, § 166."},"thimanli":{"lemma":"Thimanli","pos":"","gen":"","def":", a people of Arabia, Plin. 6, 28, 32, § 157."},"thirmida":{"lemma":"Thirmida","pos":"","gen":"","def":", a town of Numidia, Sall. J. 12, 3. Thisbē, ēs, f., = Θίσβη. A little town on the coast of Boeotia, celebrated for its wild doves, now Kakosia, Plin. 4, 7, 12, § 26; Stat. Th. 7, 261"},"thlaspi":{"lemma":"thlaspi","pos":"","gen":"","def":", = θλάσπι, a kind of cress, Plin. 27, 13, 113, § 139; Cels. 5, 23, 3"},"thranis":{"lemma":"thranis","pos":"","gen":"","def":", = θράνις, a fish, called also xiphias, Plin. 32, 11, 53, § 151. Thrascĭas, ae, m., = θρασκίας, the north-by-a-third-northwest wind, Vitr. 1, 6 med.; Plin. 2, 47, 46, § 120"},"thrausi":{"lemma":"Thrausi","pos":"","gen":"","def":", a Thracian people, Liv. 38, 41."},"thrauston":{"lemma":"thrauston","pos":"","gen":"","def":", = θραυστόν, a kind of metopion (gum), Plin. 12, 23, 49, § 107."},"thrax":{"lemma":"Thrax","pos":"","gen":"","def":"Thracia, E. Thrēcē, ēs, v. Thracia. Thrēcĭcus, a, um, v. Thracia, C. Thrēcĭdĭcus, a, um, v. Thracia, E. 2. b. Thrēĭcĭus, a, um, v. Thracia, D."},"threx":{"lemma":"Threx","pos":"","gen":"","def":"Thracia, E. 2. thrĭdax, ăcis, f., = θρίδαξ, wild lettuce, Ser. Samm. 24, 448; App. Herb. 30."},"thrips":{"lemma":"thrips","pos":"","gen":"-worm","def":", = θρίψ, a wood-worm. Lit., Plin. 16, 41, 80, § 220.— Transf., trifles, worthless things, = quisquiliae, Mart. Cap. 2, § 164 (al. thriptes). Thrŏnĭum (-on), ii, n."},"thryallis":{"lemma":"thryallis","pos":"","gen":"-shaped","def":", = θρυαλλίς, the name of two different plants. A plant, called also lychnitis, Plin. 25, 10, 74, § 121. — An ear-shaped plant, Plin. 21, 17, 61, § 101. Thūcȳdĭdes, is, m., = Θουκυδίδης"},"thybris":{"lemma":"Thybris","pos":"","gen":"","def":"Tiberis init. Thyēnē, ēs, f., one of the Hyades who nursed Jupiter and Bacchus, Ov. F. 6, 711."},"thyestes":{"lemma":"Thyestes","pos":"adj.","gen":"","def":", = Θυέστης, son of Pelops and brother of Atreus, who set before him for food the flesh of his own son; he was the father of Aegisthus, Hyg. Fab. 88; Plaut. Rud. 2, 6, 25; Cic. Tusc. 3, 12, 26"},"thymbra":{"lemma":"thymbra","pos":"","gen":"","def":", = θύμβρα, a plant, savory: Satureia hortensis, Linn.; Plin. 19, 8, 50, § 165; Col. 9, 4, 6; 9, 10, 233; Verg. G. 4, 31; Stat. S. 1, 2, 21; Petr. 135."},"thymum":{"lemma":"thymum","pos":"","gen":"","def":", = θύμον, thyme (both the common or Roman, Thymus vulgaris, Linn., and the Cretan or Greek, Satureia capitata, ib.), Plin. 21, 21, 89, § 154; Quint. 12, 10, 25; Verg. E. 7, 37; id. A. 1, 436"},"thynnus":{"lemma":"thynnus","pos":"","gen":"","def":"thunnus. Thȳnus, a, um, v. Thyni, A. Thyōnē, ēs, f., = Θυώνη, the mother of the fifth Bacchus, enumerated in Cic. N. D. 3, 23, 58.—Hence, Thyōneus, ĕi, m., the son of Thyone"},"thyraeus":{"lemma":"thyraeus","pos":"adj.","gen":"","def":", = θυραῖος, of or belonging to a door, a gate: Apollo, the god of the entrance, Tert. Mil. 13 fin. Thyrē, ēs, f., = Θύρη, a little town in the Peloponnesus"},"thyrsis":{"lemma":"Thyrsis","pos":"","gen":"","def":", = Θύρσις, the name of a shepherd, Verg. E. 7, 2."},"thyrsus":{"lemma":"thyrsus","pos":"","gen":"-shoots","def":", = θύρσος, a stalk, stem of a plant. Lit., Plin. 19, 8, 39, § 129; 25, 8, 41, § 81; 26, 8, 33, § 51; Suet. Aug. 77"},"tibigensis":{"lemma":"Tibigensis","pos":"adj.","gen":"","def":", of or belonging to the town Tibiga, in Numidia: oppidum, Plin. 5, 4, 4, § 29."},"tibilis":{"lemma":"Tibilis","pos":"adj.","gen":"-nus","def":", a town in Numidia, Aug. Ep. 128. — Hence, adj.: Tibilitā-nus, a, um, of Tibilis: aquae, Aug. Civ. Dei, 22, 8. tībĭnus, a, um, adj. tibia, of or belonging to the pipe or flute: modi"},"tibris":{"lemma":"Tibris","pos":"","gen":"","def":"Tiberis. Tĭbullus, i, m., Albius, a celebrated Roman elegiac poet, born about 700 A. U. C., died about 735, a contemporary and friend of Ovid and Horace, Quint. 10, 1, 93; Ov. Am. 1, 15, 28"},"tifernum":{"lemma":"Tifernum","pos":"","gen":"","def":", the name of three towns of Italy. A town in Umbria, on the Tiber, called also Tifernum Tiberinum, near the mod. Citta di Castello, Plin. 3, 5, 9, § 53; Plin. Ep. 4, 1, 4"},"tignum":{"lemma":"tignum","pos":"","gen":"-stuff","def":"(masc. collat. form, plur. tigni, Liv. 44, 5, 4; but Weissenb. reads tigno) [root tek-"},"tinca":{"lemma":"tinca","pos":"","gen":"","def":", a small fish, perh. the tench: Cyprinus tinca, Linn.; Aus. Idyll. 10, 125."},"tincta":{"lemma":"tincta","pos":"","gen":"","def":"tingo fin. tinctĭlis, e, adj. tingo, in which something is dipped: volucri ferro tinctile virus inest, Ov. Tr. 3, 10, 63."},"tinctor":{"lemma":"tinctor","pos":"","gen":"","def":"id., a dyer, Inscr. Marin. Papir. Dipl. 251"},"tinctus":{"lemma":"tinctus","pos":"","gen":"-sauce","def":"tingo, a dipping into, a dyeing; meton., a sauce into which something is dipped: avis croceo tinctu cibis gratissima, i. e. saffron-sauce, Plin. 10, 48, 68, § 134. tĭnĕa, ae, f. tan-, root of tondeo"},"tinnunculus":{"lemma":"tinnunculus","pos":"","gen":"","def":", a kind of hawk, the kestrel: Falco tinnunculus, Linn.; Plin. 10, 37, 52, § 109"},"tintinnum":{"lemma":"tintinnum","pos":"","gen":"","def":"tintinno, a jingling, tinkling, Ven. Carm. 2, 20, 49. tintĭno, āre, v. tintinno. tīnus, i, m., a plant: Viburnum tinus, Linn.; Plin. 15, 30, 39, § 128"},"tiphyon":{"lemma":"tiphyon","pos":"","gen":"","def":", = τίφυον, a kind of narcissus, Plin. 21, 11, 39, § 67 (dub.; Jahn, iphyon). Tīphys, yos (voc. Tiphy), m., = Τῖφυς, the pilot of the Argo, Verg. E. 4, 34; Ov. H. 6, 48; id. Tr. 4, 3, 77"},"tis":{"lemma":"tis","pos":"","gen":"","def":"e. tui, Plaut. Mil. 4, 2, 42; v. tu. Tīsaeus, i, m., or Tīsaeum, i, n., = Τισαῖον, a mountain of Thessaly, now Bardjora, Liv. 28, 5, 17"},"tityus":{"lemma":"Tityus","pos":"","gen":"","def":", a river of Illyria, Plin. 3, 21, 25, § 139; Flor. 2, 5. Tlēpŏlĕmus, i, m., = Τληπόλεμος, a son of Hercules, leader of the Rhodians before Troy, Hyg. Fab. 81, 97"},"todi":{"lemma":"todi","pos":"","gen":"","def":": todi genus avium parvarum. Plautus: cum todillis crusculis, Fest. pp. 352 and 353 Müll."},"toecharchus":{"lemma":"toecharchus","pos":"","gen":"","def":", = τοίχαρχος, the commander of the rowers, Hyg. Fab. 14 fin. tōfācĕus or -ĭus, a, um, adj. tofus, of tufa, tufaceous: argilla, Plin. 17, 7, 4, § 43: lapis, Pall. Aug. 9, 2. tōfĭcĭus, a, um, adj. id."},"tolles":{"lemma":"tolles","pos":"","gen":"","def":"toles."},"tollo":{"lemma":"tollo","pos":"v.","gen":"-born","def":"a. (perf. tollit, Pers. 4, 2: tollisse, Dig. 46, 4, 13) [root Sanscr. tul-, tulajāmi, lift up, weigh; Gr. ταλ-, τελ, in τλῆναι, τάλαντον"},"tolostobogii":{"lemma":"Tolostobogii","pos":"","gen":"","def":"Tolistobogii. Tŏlumnĭus, ii, m. A king of the Veientes, Liv. 4, 17.— A Rutulian soothsayer, Verg. A. 11, 429"},"tonsa":{"lemma":"tonsa","pos":"","gen":"","def":"perh. from tundo, an oar (poet.; mostly in plur."},"tonsus":{"lemma":"tonsus","pos":"","gen":"-class","def":"tondeo, the cut or mode of dressing the hair (ante-class.): pes, statura, tonsus, oculi, etc., Plaut. Am. 1, 1, 288: mulier tonsu lugubri, Att. ap. Non. 179, 20. tŏnus, i, m., = τόνος. The stretching"},"topper":{"lemma":"topper","pos":"adv.","gen":"","def":"contr. from toto opere, with all diligence, speedily, forthwith (anteclass."},"torini":{"lemma":"Torini","pos":"","gen":"","def":", a people of Scythia, Val. Fl. 6, 148."},"tormentum":{"lemma":"tormentum","pos":"","gen":"-press","def":"torqueo, an instrument with which any thing is turned or twisted. An engine for hurling missiles. Lit.: tormenta telorum, Cic. Tusc. 2, 24, 57: tormentis Mutinam verberavit, id. Phil. 8, 7, 20"},"torno":{"lemma":"torno","pos":"v.","gen":"","def":"a. tornus, to turn in a lathe, to round off. Lit. (class."},"tornus":{"lemma":"tornus","pos":"","gen":"","def":", = τόρνος, a turner's wheel, lathe. Lit.: fit quasi ut ad tornum saxorum structa tuamur, Lucr. 4, 361; Plin. 7, 56, 57, § 198; 16, 40, 76, § 205"},"torpesco":{"lemma":"torpesco","pos":"","gen":"","def":"inch. n. , to grow stiff or numb, to become useless or torpid. Lit.: pars corporis torpescit, Plin. 11, 37, 89, § 220: elaeomeli qui bibere, torpescunt, id. 23, 4, 50"},"torpor":{"lemma":"torpor","pos":"","gen":"","def":"torpeo, numbness, stupefaction, torpor (syn.: languor, veternus). Lit.: tutantur se torpore torpedmes, * Cic. N. D. 2, 50, 127; cf. Cels. 2, 8 med.; Plin. 2, 101, 104, § 223; 19, 8, 44, § 155"},"torrenter":{"lemma":"torrenter","pos":"adv.","gen":"","def":", v. torreo, P. a. fin. torreo, torrui, tostum (part. gen. plur. torrentum, Stat. Th. 2, 6; Claud. III. Cons. Hon. 46; abl. torrenti, Sen. Brev. Vit. 9, 2), 2, v. a. Sanscr. tarsh, to thirst"},"torresco":{"lemma":"torresco","pos":"","gen":"","def":"inch. n. , to become parched or burned: torrescere flammis, Lucr. 3, 890. torrĭdo, no perf., ātum, 1, v. a. torridus, to scorch, parch, burn: torris dicitur fax, unde et torridare dicimus comburere"},"torror":{"lemma":"torror","pos":"","gen":"","def":"torreo, a drying up, parching, scorching (late Lat.): solis, Cael. Aur. Tard. 5, 4, 76: corporis, a transl. of ἡλίωσις, id. ib. 3, 6 fin. torsĭo, ōnis, f. torqueo, a wringing or griping: ventris"},"torto":{"lemma":"torto","pos":"","gen":"-class","def":"freq. a. id., to torture, torment (ante- and post-class.; syn.: torqueo, crucio): ubi insilui in cochleatum eculeum, ibi tolutim tortor, Pompon. ap. Non. 105, 15, and 182, 5; Lucr. 3, 661"},"tortor":{"lemma":"tortor","pos":"","gen":"","def":"torqueo, I. B. 2., an executioner, tormentor, torturer. Lit. In gen.: cum jam tortor, atque essent tormenta ipsa defessa, Cic. Clu. 63, 177; id. Phil. 11, 3, 7; id. Fin. 4, 12, 31; Sen. Ep. 14, 5"},"tortum":{"lemma":"tortum","pos":"","gen":"","def":"torqueo, a cord, rope, Pac. ap. Non. 179, 16 (Trag. Fragm. v. 159 Rib.). tortŭōsē, adv., v. tortuosus fin. tortŭōsĭtas, ātis, f. tortuosus, crookedness, shuffling"},"tortus":{"lemma":"tortus","pos":"","gen":"","def":"torqueo. a twisting, winding"},"toruus":{"lemma":"torvus","pos":"adj.","gen":"-vus","def":"perh. for torg-vus; Sanscr. root targ-, to threaten, orig. of the eyes, staring, keen, piercing, wild, stern"},"tosilla":{"lemma":"tosilla","pos":"","gen":"","def":"tonsilla. tostus, a, um, Part. of torreo. tŏt, num. adj. indecl., so many. Lit. With a corresp. quot, quotiens, quantum, ut. With quot: hoc brevissime dicam, neminem umquam tam impudentem fuisse"},"tracta":{"lemma":"tracta","pos":"v.","gen":"","def":"traho, P. a. B. 2. tractābĭlis, e, adj. tracto, that may be touched, handled, or taken hold of"},"tractim":{"lemma":"tractim","pos":"adv.","gen":"","def":"tractus, by drawing along, i. e. little by little, by degress"},"tracto":{"lemma":"tracto","pos":"part.","gen":"-clause","def":"plur. part. tractantum, Ov. P. 3, 3, 20), 1, v. freq. a. traho. To draw violently, to drag, tug, haul, etc. (so, very rare): qui te (Hectorem) sic tractavere? Enn. ap. Macr. S. 6"},"tractum":{"lemma":"tractum","pos":"v.","gen":"","def":", v. traho, P. a. B. tractŭōsus, a, um, adj. traho, that draws to itself, clammy, gluey, viscous (late Lat.): sudor crassus et tractuosus atque viscosus, Cael. Aur. Acut. 2, 32, § 167: semen"},"tractus":{"lemma":"tractus","pos":"","gen":"","def":"traho, a drawing, dragging, hauling, pulling, drawing out, trailing. Lit. (mostly poet.): tractu gementem Ferre rotam, Verg. G. 3, 183: tractu taurea terga domant, Val. Fl. 6"},"tragasaeus":{"lemma":"Tragasaeus","pos":"adj.","gen":"","def":", of or belonging to the town Tragasa in Troas: sal, Plin. 31, 7, 41, § 85 sq."},"tragurium":{"lemma":"Tragurium","pos":"","gen":"","def":", a town in Dalmatia, Plin. 3, 22, 26, § 141"},"tralles":{"lemma":"Tralles","pos":"adj.","gen":"-ni","def":", a town in Lydia, the modern Aidin Guzel - Hissar, Cic. Fl. 24, 57; 29, 71; id. Agr. 2, 15, 39; id. Att. 5, 14, 1; id. Fam. 3, 5, 1; id. Q. Fr. 1, 1, 6, § 17; Caes. B. C. 3, 105, 5; Liv. 37, 45"},"tranquillo":{"lemma":"tranquillo","pos":"v.","gen":"","def":"a. tranquillus, to make calm or still, to calm, still. Lit. (very rare"},"trans":{"lemma":"trans","pos":"prep.","gen":"","def":"with acc. [Sanscr. tar-, to put across; tiram, brink; Gr. τέρμα, goal"},"trans-formo":{"lemma":"trans-formo","pos":"v.","gen":"-formo","def":"a., to change in shape, transform (poet. and in post-Aug. prose"},"trans-fundo":{"lemma":"trans-fundo","pos":"v.","gen":"-fundo","def":"a., to pour out from one vessel into another, to pour off, decant, transfuse. Lit.: aquam in alia vasa, Col. 12, 12, 1: harenam liquatam in alias fornaces, Plin. 36, 26, 66, § 194"},"trans-iungo":{"lemma":"trans-jungo","pos":"v.","gen":"-jungo","def":"a., to harness differently, to tackle in elsewhere: mulam, Dig. 21, 1, 38, § 8 sq. trans-lapsus, a, um, Part. , gliding past, hastening by: (diva) uno Padum translapsa volatu, Claud. ap. Eutr. 1"},"trans-planto":{"lemma":"trans-planto","pos":"v.","gen":"-planto","def":"a., to transplant, remove: et erit quasi lignum quod transplantatur, Vulg. Jer. 17, 8: in desertum, id. Ezech. 19, 13: in mare, id. Luc. 17, 6: di transplantati, i. e. deified human beings, Sedul. 2"},"trans-porto":{"lemma":"trans-porto","pos":"v.","gen":"-porto","def":"a., to carry over or across, to carry or convey from one place to another"},"trans-pungo":{"lemma":"trans-pungo","pos":"v.","gen":"-pungo","def":"a., to prick or pierce through, Cael. Aur. Tard. 3, 4, 66. Trans-rhēnānus, a, um, adj., that is beyond the Rhine, Transrhenish: Germani, Caes. B. G. 5, 2, 5: hostes, i. e. the Batavians, Plin. 19, 1"},"trans-uendo":{"lemma":"trans-vendo","pos":"v.","gen":"-vendo","def":"a., to dispose of by sale, to sell, alienate, Inscr. Orell. 4431. trans-vĕnĭo, īre, v. n., to come from another place or person (eccl. Lat.): anima inde (a Deo) transvenit"},"trans-uoluo":{"lemma":"trans-volvo","pos":"v.","gen":"-volvo","def":"a., to roll past or by, i. e. to unroll, Prud. Cath. 11, 29; cf. Juvenc. 3, 380. transvŏrātĭo, ōnis, f. transvoro, a gulping or swallowing down, Cael. Aur. Acut. 1, 14, 113; 3, 6, 66"},"transactor":{"lemma":"transactor","pos":"","gen":"","def":"id., a manager, transactor: rerum transactor et administer, Cic. Verr. 2, 2, 28, § 69. transactus, a, um, Part. of transigo. transădactus, a, um, Part. of transadigo. trans-ădĭgo, ēgi, actum, 3"},"transcensus":{"lemma":"transcensus","pos":"","gen":"","def":"transcendo, a climbing over, surmounting: scalarum, Amm. 19, 5, 6"},"transcursim":{"lemma":"transcursim","pos":"adv.","gen":"","def":"transcurro, cursorily (late Lat.), Petr. Chrysol. Serm. 17. transcursĭo, ōnis, f. id., a passing over, lapse of a period of time (post-class.): decennii, Cod. Just. 6, 23, 27 fin.— A hasty treatment"},"transcursus":{"lemma":"transcursus","pos":"","gen":"","def":"transcurro (post-Aug.). Lit., a running, darting, or flying through: fulguris, a flash of lightning, Suet. Aug. 90: avibus maximis minimisque per aëra transcursus est, Sen. Q. N. 2, 7, 1.— Trop."},"transdo":{"lemma":"transdo","pos":"v.","gen":"","def":"trado. transdūco, ĕre, and its derivatives; v. traduco, etc. transenna (trāsenna), ae, f. (orig. perh. plaited work"},"transformis":{"lemma":"transformis","pos":"adj.","gen":"","def":"id., changed in shape, transformed (poet.): (Proteus) transformis, Ov. F. 1, 373: corpora, id. M. 8, 871."},"transgressor":{"lemma":"transgressor","pos":"","gen":"","def":"id., an infringer, transgressor of the law (late Lat.), Arn. 7, 215; Tert. Res. Carn. 39; Alcim. 2, 120. transgressus, a, um, Part. of transgredior."},"transgressus":{"lemma":"transgressus","pos":"","gen":"","def":"transgredior, a passing over, passage (very rare)"},"transmissus":{"lemma":"transmissus","pos":"","gen":"","def":"transmitto. * A giving or handing over, a transferring, transmission: nunc regnum potitur transmissu patris, Pac. ap. Non. 481, 32 (Trag. Rel. p. 69 Rib.).— A passing over"},"transno":{"lemma":"transno","pos":"v.","gen":"","def":"trano. transnōmĭnātĭo, ōnis, f. transnomino, a pure Lat. appellation for metonymy, Don. p. 1776 P."},"transpectus":{"lemma":"transpectus","pos":"","gen":"","def":"transpicio, a looking or seeing through, Lucr. 4, 272 (corresp. to the preced. and foll. transpiciuntur). trans-pertūsus, a, um, Part. , pierced through, perforated: terminus"},"transscendo":{"lemma":"transscendo","pos":"v.","gen":"","def":"transcendo, etc. transscīdo, ĕre, v. transcido. transscrībo, ĕre, v. transcribo. transsĕro, ēre, v. transero. transsĭlĭo, īre, v. transilio."},"transspectus":{"lemma":"transspectus","pos":"v.","gen":"","def":"transpectus. transspĭcĭo, ĕre, v. transpicio."},"transsulto":{"lemma":"transsulto","pos":"v.","gen":"","def":"transulto. transsūmo, ĕre, and its derivatives, v. transumo, etc. transsŭo, ĕre, v. transuo. Transthēbăītānus, a, um, adj. trans-Thebais, that is beyond Thebais, Treb. Pol. Gall. 4. Trans-tĭbĕrīnus"},"transtillum":{"lemma":"transtillum","pos":"","gen":"-beam","def":"dim. transtrum, a little cross-beam, Vitr. 5, 12. trans-tĭnĕo, ēre, v. n. teneo, II., to go through, pass through: commeatus transtinet trans parietem, Plaut. Mil. 2, 5, 58."},"transtrum":{"lemma":"transtrum","pos":"","gen":"-bank","def":"root tra-, to cross; cf. trans (cf. jugum). In gen., a crossbeam, transom, Vitr. 2, 1; 4, 2; 5, 1 fin.; 10, 21; Plin. 34, 12, 32, § 123 al."},"transuersim":{"lemma":"transversim","pos":"v.","gen":"","def":", v. transverto fin. transversus (-vorsus) or trāver-sus, a, um, Part. and P. a. of transverto. trans-verto, ti, sum, 3, v. a."},"transuorsus":{"lemma":"transvorsus","pos":"v.","gen":"","def":"transversus. trăpētus, i, m., = τραπητός, an olivemill, oil-mill, Cato, R. R. 20, 1; 20, 12; 22, 3; Verg. G. 2, 519; Plin. 15, 6, 6, § 23.—Collat. form trăpētum, i, n., = τραπητόν, Col. 12, 52, 6"},"tressis":{"lemma":"tressis","pos":"","gen":"-as","def":"tres-as, Three asses, Varr. L. L. 5, § 169"},"triballi":{"lemma":"Triballi","pos":"","gen":"","def":", a people of Lower Moesia, Plin. 3, 26, 29, § 149; 4, 1, 1, § 3; 4, 10, 17, § 33. trĭbăs, ădis, f., = τριβάς (rubbing), a woman who practises lewdness with women, Phaedr. 4, 14, 3; Mart. 1, 91 tit."},"tricca":{"lemma":"Tricca","pos":"adj.","gen":"","def":", = Τρίκκη, a town of Thessaly, on the Peneus, now Trikala, Plin. 4, 8, 15, § 29; Liv. 32, 13, 5"},"trichrus":{"lemma":"trichrus","pos":"","gen":"","def":", = τρίχρους, a tricolored gem, Plin. 37, 10, 68, § 183. trīcĭes, trīcĭens (also trīcĕsĭes, Auct. B. Afr. 97, 2 twice: trīgĭes, Mart. Cap. 7, § 737), adv. num. triginta"},"trinso":{"lemma":"trinso","pos":"v.","gen":"","def":"trisso. Trĭnummus (Trĭnūmus), i, m., the name of a comedy by Plautus"},"triorchis":{"lemma":"triorchis","pos":"","gen":"","def":", = τριορχίς, a plant, a kind of centaury, Plin. 25, 6, 32, § 69. trĭpālis, e, adj. ter-palus, that has, or is propped up by, three stakes or pales: vineae, Varr. ap. Non. 219, 18. trĭ-parcus, a, um"},"trispastos":{"lemma":"trispastos","pos":"","gen":"-tackle","def":"(sc. machina), = τρίσπαστος, a hoisting-tackle with three pulleys, two in the upper and one in the lower block, a trispast, Vitr. 10, 3. Trispĭthămi, ōrum, m., = Τρισπιθαμοί (three spans high)"},"trisso":{"lemma":"trisso","pos":"v.","gen":"","def":"n., of the note of the swallow, to twitter, Auct. Carm. Philom. 26 (al. trinsat). Tristătae, ārum, m., = Τριστάται, the three highest nobles of a country next to the king, Hier. in Ezech. 7, 23"},"tristis":{"lemma":"tristis","pos":"adj.","gen":"-humored","def":"etym. dub.; cf. Sanscr. trastas, frightened"},"tristor":{"lemma":"tristor","pos":"v.","gen":"","def":"dep. n. , to be sad, grieved, or downcast (very rare): numquam flere, numquam tristari, Sen. Prov. 2, 3"},"trocmi":{"lemma":"Trocmi","pos":"","gen":"","def":", a people of Galatia, Liv. 38, 16; called also Trogmi, Cic. Div. 2, 37, 79"},"trogini":{"lemma":"Trogini","pos":"","gen":"","def":", a people of Galatia, Cic. Div. 2, 37. Trōglŏdytae or Trōgŏdytae, ārum, m., = Τρωγλοδύται, a people of Ethiopia who dwelt in caves, the Troglodytes, Mel. 1, 4, 4; 1, 8, 6; Plin. 2, 73, 75, § 183"},"trogmi":{"lemma":"Trogmi","pos":"","gen":"","def":"Trocmi. Trogus Pompēĭus, a Roman historian in the time of Augustus, whose work was abridged by Justin, Just. praef.; id. 38, 3; 43, 1 and 5 fin.; Plin. 11, 15, 114, § 274"},"trosmis":{"lemma":"Trosmis","pos":"","gen":"","def":", = Τροσμίς, a town of Lower Moesia, on the Ister, Ov. P. 4, 9, 79. Trossŭli, ōrum, m., a name given to the Roman cavalry, from Trossulum, a town of Etruria, which was conquered by them"},"tructa":{"lemma":"tructa","pos":"","gen":"-tus","def":", = τρώκτης, a kind of trout, Isid. Orig. 12, 6.—Also called truc-tus, i, m., Plin. Val. 5, 43. trŭcŭlentē, adv., v. truculentus fin. trŭcŭlentĭa, ae, f. truculentus, savageness, ferocity, roughness"},"trulla":{"lemma":"trulla","pos":"","gen":"-cups","def":"dim. trua. Lit., a small ladle, dipper, or scoop (esp. for dipping wine from the crater into the drinking-cups), Varr. L. L. 5, § 118; Cato, R. R. 13, 2 sq.; Cic. Verr. 2, 4, 27, § 62 sq."},"trullisso":{"lemma":"trullisso","pos":"v.","gen":"-cast","def":"a. trulla, II. B., to plaster, rough-cast: parietes, Vitr. 7, 3; 7, 4"},"trunco":{"lemma":"trunco","pos":"v.","gen":"","def":"a. 2. truncus, to maim, mutilate, mangle, or shorten by cutting off, to cut off (mostly poet. and in post-Aug. prose"},"truncus":{"lemma":"truncus","pos":"","gen":"","def":"torqueo], maimed, mutilated, mangled, dismembered, disfigured, deprived of some of its parts (mostly poet. and perh. not ante-Aug."},"trychnos":{"lemma":"trychnos","pos":"","gen":"","def":"strychnos. tryga antiqui vinum appellabant. unde trygetus adhuc dicitur, Fest. p. 366 Müll. . trygĭnon, i, n., = τρύγινον, a black coloring matter made from the lees of wine, Plin. 35, 6, 25"},"tryphon":{"lemma":"Tryphon","pos":"","gen":"","def":"A surgeon, Cels. 6, 5; 7 praef.— A king in Syria, Just. 36, 1, 7; 38, 9, 3; 39, 1, 3.— A surname of Ptolemy Philopator, Plin. 7, 56, 57, § 208. — A publisher of Rome, Quint. ad Tryph. 1 sqq."},"tubantes":{"lemma":"Tubantes","pos":"","gen":"","def":", a people of Germany, between the Rhine and the Elbe, Tac. A. 1, 51; 13, 55 sq."},"tueo":{"lemma":"tueo","pos":"","gen":"","def":"tueor fin. tŭĕor, tuĭtus, 2 (perf. only post-Aug., Quint. 5, 13, 35; Plin. Ep. 6, 29, 10; collat. form tūtus, in the part., rare, Sall. J. 74, 3; Front. Strat. 2, 12, 13; but constantly in the P. a."},"tuisco":{"lemma":"Tuisco","pos":"","gen":"","def":", the progenitor of the Germans, honored by them as a god, Tac. G. 2"},"tulingi":{"lemma":"Tulingi","pos":"","gen":"","def":", a German or Helvetic tribe on the Rhine, Caes. B. G. 1, 5. Tullĭa, ae, v. Tullius. Tullĭānē, adv., v. Tullius fin. Tullĭānus, a, um, v. Tullius. Tullĭŏla, ae, f. dim. Tullia, a pet name for Tullia"},"tullus":{"lemma":"Tullus","pos":"","gen":"","def":", a Roman proenomen, e.g. Tullus Hostilius, the third king of Rome, Liv. 1, 22 sqq.; Val. Max. 3, 4, 1; 9, 12, 1: Tullus Cluilius, a Roman ambassador, Cic. Phil. 9, 2, 5 al."},"tulo":{"lemma":"tulo","pos":"v.","gen":"-class","def":"a. akin with tollo"},"tumba":{"lemma":"tumba","pos":"","gen":"","def":", = τύμβα (τύμβος), a sepulchral mound, a sepulchre, tomb, Prud. στεφ. 11, 9. tumbŭla, ae, f. tumba, a little tomb (late Lat.), Aldhelm. Carm. Virg. 889. tŭmĕ-făcĭo, fēci, factum, 3, v. a. tumeo"},"tundo":{"lemma":"tundo","pos":"v.","gen":"-d","def":"Neue, Formenl. II. 568), 3 (old collat. form of the perf. tuserunt, Naev. 1, 1: tunsi, acc. to Diom. p. 369 P.; inf. tundier, Lucr. 4, 934), v. a. Sanscr. tu-dāmi, thrust"},"tungri":{"lemma":"Tungri","pos":"","gen":"","def":", a people of Gallia Belgica, near the modern Tongres, Plin. 4, 17, 31, § 106; 31, 2, 8, § 12; Tac. G. 2; id. H. 2, 14 sq.; 4, 16, 55; Amm. 15, 11, 7"},"turba":{"lemma":"turba","pos":"","gen":"","def":"= τύρβη; cf. Sanscr. turāmi, to hasten; turas, hasty"},"turben":{"lemma":"turben","pos":"","gen":"","def":"2. turbo init. turbĭdē, adv., v. turbidus fin. turbĭdo, āvi, ātum, 1, v. a. turbidus, to trouble, to make turbid, to disturb, obscure (post-class.). Lit.: aquam, Sol. 49 fin.: aër turbidatus"},"turbo":{"lemma":"turbo","pos":"v.","gen":"","def":"a. (fut. perf. turbassit, for turbaverit, Cic. Leg. 3, 4; al. turbassitur) , to disturb, agitate, confuse, disorder; to throw into disorder or confusion (freq. and class."},"turbor":{"lemma":"turbor","pos":"","gen":"","def":"1. turbo, restlessness, unquietness, disturbance, tumult (late Lat.), Cael. Aur. Acut. 1, 15, n. 149"},"turda":{"lemma":"turda","pos":"","gen":"","def":"turdus. turdārĭum, ii, n. turdus, a place where thrushes are kept, Varr. L. L. 6, § 2 Müll."},"turdelix":{"lemma":"turdelix","pos":"","gen":"","def":", Varr. L. L. 6, § 2 Müll. Turdētāni, ōrum, m., a people of Hispania Baetica, near the mod. Seville, Liv. 21, 6, 1"},"turdus":{"lemma":"turdus","pos":"","gen":"","def":"(collat. form turda, ae, f., Pers. 6, 24; denied by Varr. L. L. 9, § 55 Müll.; cf. id. R. R. 3, 5, 6) [cf. O. H. Germ. trosca; Angl. Sax. throsle"},"turgesco":{"lemma":"turgesco","pos":"","gen":"","def":"inch. n. , to begin to swell, to swell up, swell. Lit.: ne aqua in eorum corpore turgescat, Varr. R. R. 8, 9, 13: hoc (umore) aetas illa (puerilis) turgescit, Quint. 11, 3"},"turgor":{"lemma":"turgor","pos":"","gen":"-class","def":"id., a swelling, turgidity (post-class.), Mart. Cap. 2, § 135; 5, § 566. Tūrĭa, ae, m., a river in Hispania Tarraconensis, now the Turia or Guadalaviar, Mel. 2, 6, 6; Sall. H. 2, 96, 6 Dietsch"},"turma":{"lemma":"turma","pos":"","gen":"-two","def":"Sanscr. root tvar-, tur-, hasten; v. turba, a division of Roman cav alry, the tenth part of an ala, consisting at first of thirty, and afterwards of thirty-two men"},"turnus":{"lemma":"Turnus","pos":"","gen":"","def":"A king of the Rutuli, killed by Aeneas, Liv. 1, 2, 3; Verg. A. 7, 344 sq.; Ov. M. 14, 451 sq.; Tib. 2, 5, 48"},"turpis":{"lemma":"turpis","pos":"adj.","gen":"-clause","def":"Sanscr. root tarp-, to be ashamed, ugly, unsightly, unseemly, foul, filthy (class.; esp. freq. in a trop. sense"},"turpo":{"lemma":"turpo","pos":"v.","gen":"","def":"a. id., to make ugly or unsightly, to soil, defile, pollute, disfigure, deform (mostly poet.; cf. deformo). Lit.: Jovis aram sanguine turpari, to be defiled or polluted, Enn. ap. Cic. Tusc. 1, 35, 85"},"turtur":{"lemma":"turtur","pos":"","gen":"-dove","def":"(fem. turturis marinae os, Dict Cret. 6, 15; Plin. 30, 8, 21, § 68), a turtle-dove: Columba turtur, Linn.; Plin. 10, 34, 52, § 105; Varr. R. R. 3, 8; Col. 8, 9; Pall. 1, 25; Plaut. Most. 1, 1, 44"},"turunda":{"lemma":"turunda","pos":"","gen":"","def":"A ball of paste for fattening geese, Cato, R. R. 89; Varr. R. R. 3, 9, 20.— A kind of sacrificial cake, Varr. ap. Non. 552, 3.— A tent or roll of lint for wounds, Cato, R. R. 157, 14"},"tuscus":{"lemma":"Tuscus","pos":"","gen":"","def":"Tusci, B. tussēdo, ĭnis, f. tussis, a cough, App. M. 9, p. 222, 38. tussĭcŭla, ae, f. dim. id., a little or slight cough, Cels. 3, 22; Plin. Ep. 5, 19, 6"},"tussiens":{"lemma":"tussiens","pos":"","gen":"","def":", one who has a cough: nuces tussientibus inimicae, Plin. 23, 8, 77, § 147; 21, 20, 83, § 140"},"tussis":{"lemma":"tussis","pos":"","gen":"","def":", a cough, Cels. 4, 4, 4; 4, 4, 6; 4, 8, 9; Col. 6, 10, 1 sq.; Plin. 23, 4, 51, § 136; 21, 20, 83, § 140; 26, 6, 16, § 30; Ter. Heaut. 2, 3, 132; Cat. 44, 7; Verg. G. 3, 497"},"tyba":{"lemma":"Tyba","pos":"","gen":"","def":", a village on the Euphrates, now Taibe, Cic. Fam. 15, 1, 2 Tȳbris, v. Tiberis."},"tycha":{"lemma":"Tycha","pos":"","gen":"","def":", = Τύχη (fortuna), the name of a part of Syracuse in the west of the Achradina, called after the temple of the goddess Τύχη, Cic. Verr. 2, 4, 53, § 119; Liv 24, 21, 7"},"typus":{"lemma":"typus","pos":"","gen":"","def":", = τύπος. A figure, image, on a wall, Cic. Att. 1, 10, 3; Plin. 35, 12, 43, § 151"},"tyra":{"lemma":"Tyra","pos":"","gen":"","def":"Tyras. tyranna, ae, f , a princess, a female tyrant (with tyrannis), Treb. XXX. Tyr. 31 fin. tyrannĭcē, adv., v. tyrannicus fin. tyrannĭcīda, ae, m. tyrannus-caedo, a killer of a tyrant"},"tyrannus":{"lemma":"tyrannus","pos":"","gen":"","def":", = τύραννος. In gen., a monarch, ruler, sovereign, king (rare, and mostly poet.): tyrannusque fuerat appellatus (Miltiades), sed justus ... omnes autem et dicuntur et habentur tyranni"},"tyras":{"lemma":"Tyras","pos":"","gen":"","def":", = Τύρας, a river in Sarmatia, now the Dniester, Mel. 2, 1, 7"},"tyrtaeus":{"lemma":"Tyrtaeus","pos":"","gen":"","def":", = Τυρταῖος, an Athenian poet, who flourished about 680 B.C., Hor. A. P. 402"},"uacca":{"lemma":"vacca","pos":"","gen":"","def":"Sanscr. vacā, cow; root vaç, to bellow; cf. vagire, a cow, Varr. R. R. 2, 5, 6; Col. 6, 21, 1; Cic. N. D. 1, 27 77; Verg. E. 9, 31; id. G. 2, 524; 3, 177; id. A. 4, 61; Ov. M. 2, 694"},"uaccaei":{"lemma":"Vaccaei","pos":"","gen":"","def":", a people of Hispania Tarraconensis, on the river Durius, Liv. 21, 5; 35, 7; Cic. Planc. 34, 84; Plin. 3, 3, 4, § 19. vaccīnĭum, ii, n., the blueberry, whortleberry: Vaccinium myrtillus, Linn."},"uaccus":{"lemma":"Vaccus","pos":"","gen":"","def":"; Vitruvius Vaccus, a general of Fundi, taken captive by L. Papirius. The vacant site of his house at Rome was called Vacci prata, Liv. 8, 19 sq."},"uada":{"lemma":"Vada","pos":"","gen":"","def":", a stronghold in Gallia Belgica, in the country of the Batavi, Tac. H. 5, 20 sq. Văda, ōrum, n., a city in Liguria, now Savona, Brut. ap. Cic. Fam. 11, 10, 3"},"uae":{"lemma":"vae","pos":"interj.","gen":"","def":"οὐαί, an exclamation of pain or dread, ah! alas! Absol.: Mantua, vae, miserae nimium vicina Cremonae, Verg. E. 9, 28"},"uaecors":{"lemma":"vaecors","pos":"","gen":"","def":"vecors. vaenĕo, īre, and vaenum, i, v. veneo and venum. văfellus, a, um, adj. dim., from vafer, acc. to Fest. s. v. altellus, p. 7 Müll. văfer, fra, frum, adj., sly, cunning, crafty, artful"},"uaha":{"lemma":"vaha","pos":"interj.","gen":"","def":", v. vah init. Văhălis, is, m., the Waal, the left arm of the Rhine, Tac. A. 2, 6; Eum. Pan. ap. Constant. 8"},"ualgus":{"lemma":"valgus","pos":"adj.","gen":"-legged","def":"root varg, to turn awry, twist; Sanscr. vrginas, twisted"},"uallis":{"lemma":"vallis","pos":"","gen":"","def":"valles."},"uallo":{"lemma":"vallo","pos":"v.","gen":"","def":"a. vallum, in milit. lang., to surround with a rampart and palisades, to palisade, intrench, circumvallate (syn. saepio). Lit.: castra vallantem Fabium adorti sunt, Liv. 9, 41"},"uallum":{"lemma":"vallum","pos":"","gen":"","def":"collective of 1. vallus; the line of palisades about an intrenchment"},"uallus":{"lemma":"vallus","pos":"","gen":"","def":"cf. Gr. ἧλος, nail, a stake, pale. In gen. (rare). For supporting vines, Verg. G. 1, 264; 2, 25.— A pole set with teeth and fastened to a cart, pushed forwards by oxen placed behind"},"ualua":{"lemma":"valva","pos":"","gen":"-door","def":", the leaf of a door, a folding-door; sing. rare, Pompon. ap. Non. 19, 23; Petr. 96"},"uanga":{"lemma":"vanga","pos":"","gen":"-bar","def":", a kind of mattock, or, acc. to others, a spade with a cross-bar to put the foot upon (late Lat.), Pall. 1, 43, 3. Vangĭo, ŏnis, m., a prince of the Suevi, Tac. A. 12, 99 sq. Vangĭŏnes, um, m. Lit."},"uanno":{"lemma":"vanno","pos":"v.","gen":"-class","def":"a. vannus, to fan, winnow (ante-class.): frumentum, Lucil. ap. Non. 19, 25 and 27. vannus, i (abl. heterocl. vannu, Non. 19, 21), f., a fan, van for winnowing grain, Col. 2, 20, 4"},"uapor":{"lemma":"vapor","pos":"n. m.","gen":"-oris","def":"steam, vapour, exhalation; warmth, heat"},"uappa":{"lemma":"vappa","pos":"","gen":"-fornothing","def":"kindr. with vapor; cf. vapidus, wine that has lost its spirit and flavor"},"uappo":{"lemma":"vappo","pos":"","gen":"","def":"root vap-, to flutter; cf. Gr. ήπίολος, moth, a moth, butterfly, Lucr. (or Lucil.) Fragm. ap. Prob. p. 1450 P. (v. Lindem. Corp. Gram. I. p. 109, n. 32"},"uardaei":{"lemma":"Vardaei","pos":"","gen":"","def":", a people in Dalmatia, Vatin. ap. Cic. Fam. 5, 9, 2; Plin. 3, 22, 26, § 143. Vardŭli, ōrum, m., a people of Lusitania, Mel. 3, 10, 7; Plin. 3, 3, 4, § 27"},"uargus":{"lemma":"vargus","pos":"","gen":"","def":"Gallic, a vagabond, Eum. Pan. Const. 9, 3; Sid. Ep. 6, 4. văria, ae, v. varius, I. A. 2. Vărĭa, ae, f. A small city of the Sabines, now Vicovaro, Hor. Ep. 1, 14, 3"},"uarro":{"lemma":"Varro","pos":"adj.","gen":"-one","def":", a surname in the gens Terentia, e. g. M. Terentius Varro, a contemporary of Cicero, who wrote De Re Rusticā and De Linguā Latinā.— The poet P. Terentius Varro Atacinus, Hor. S. 1, 10"},"uaruari":{"lemma":"Varvari","pos":"","gen":"","def":", a people of Istria, Plin. 3, 19, 23, § 130."},"uaruarini":{"lemma":"Varvarini","pos":"","gen":"","def":", a people of Liburnia, Plin. 3, 22, 25, § 139. văs, vădis, m., a bail, security, surety (in gen., while praes is confined to pecuniary matters"},"uascellum":{"lemma":"vascellum","pos":"","gen":"","def":"dim. 2. vas, a small vase or urn, Inscr. Orell. 4555. Vascŏnes, um, m., a people in Hispania Tarraconensis, on the Pyrenees, in the modern Navarra, the parent stock of the Basques, Plin. 3, 3, 4"},"uascus":{"lemma":"vascus","pos":"adj.","gen":"","def":"perh. incorrectly for vastus: tibia, a kind of flute, Sol. 5"},"uastesco":{"lemma":"vastesco","pos":"","gen":"","def":"inch. n. , to become desert or waste: ne scelere tuo Thebani vastescant agri, Att. ap. Non. 185, 10. vastĭfĭcus, a, um, adj. vastus-facio, laying waste, ravaging"},"uasto":{"lemma":"vasto","pos":"v.","gen":"","def":"a. id."},"uastus":{"lemma":"vastus","pos":"adj.","gen":"-sounding","def":"cf.: vanus, vacuus, empty, unoccupied, i.e. waste, desert. Lit. (so rare but class."},"ucubis":{"lemma":"Ucubis","pos":"","gen":"-im","def":"(acc. -im; abl. -i), a city of Hispania Baetica. Auct. B. Hisp. 7"},"uecta":{"lemma":"Vecta","pos":"","gen":"","def":", v. Vectis. vectābĭlis, e, adj. vecto, that can be carried, portable: materia insulae, Sen. Q. N. 3, 25, 9. vectābŭlum, i, n. id., a carriage, vehicle, Gell. 20, 1, 28. vectācŭlum, i, n. id."},"uectis":{"lemma":"Vectis","pos":"","gen":"-ta","def":", an island south of Britain, now the Isle of Wight, Plin. 4, 16, 30, § 130; Suet. Vesp. 4.—Also called Vec-ta, f., Eutr 7, 19. vectĭtātus, a, um, Part. [vectito, acc. to Gell. 9, 6, 3"},"uecto":{"lemma":"vecto","pos":"","gen":"","def":"freq. a , to bear, carry, convey (perh. not ante-Aug.): delphinum dorso super fluctus edito vectavisse (Arionem), Gell. 16, 19, 16: corpora viva nefas Stygiā vectare carinā, Verg. A. 6"},"uector":{"lemma":"vector","pos":"part.","gen":"","def":"veho. Act., one that bears, carries, or conveys any thing; a bearer, carrier (poet. and in post-Aug. prose)"},"uectrix":{"lemma":"vectrix","pos":"","gen":"","def":"vector, I., she that carries or transports: navis, Paul. Nol. Ep. 49, 8 fin.: equa, Poët. ap. Anth. Lat. Burm. 1, p 628. vectūra, ae, f. veho, a bearing, carrying, conveying"},"uela":{"lemma":"vela","pos":"","gen":"","def":", the Gallic name for the plant erysimon, Plin. 22, 25, 75, § 158. Vēlābrensis, e, v. 2. Velabrum. vēlābrum, i, n. velo, a covering or awning stretched above the theatre, Amm. 14, 6, 25. Vēlābrum, i"},"uella":{"lemma":"vella","pos":"","gen":"","def":"villa init. vellātūra, ae, f. contr. from vehelatura, from veho, a carrying, conveyance: vellaturam facere, Varr. R. R. 1, 2, 14. Vellaunodūnum, i, n., a town of Gallia Celtica"},"uello":{"lemma":"vello","pos":"v.","gen":"-class","def":"velli, Calp. Ecl. 4, 155; Prisc. 10, 6, 36, p. 897 P.; Diom. 1, p. 369 ib.; ante-class. form of sup. volsum"},"uellus":{"lemma":"vellus","pos":"","gen":"-flakes","def":"Sanscr. ura for vara, sheep; root var, to cover; Gr. ἔρ-ιον, εἶρος, wool; Goth. vulla"},"uelocasses":{"lemma":"Velocasses","pos":"","gen":"","def":"Bellocassi. vēlōcĭtas, ātis, f. velox, swiftness, fleetness, speed, rapidity, velocity. Lit.: velocitate ad cursum valere, Cic. Off. 1, 30, 107: pernicitatem et velocitatem, id. Tusc. 5, 15"},"uena":{"lemma":"vena","pos":"n. f.","gen":"-ae","def":"a vein of ore, mineral vein; blood-vessel, vein; a stream, channel"},"uenae":{"lemma":"vena","pos":"n. f.","gen":"-ae","def":"a vein of ore, mineral vein; blood-vessel, vein; a stream, channel","form_of":"vena"},"uenam":{"lemma":"vena","pos":"n. f.","gen":"-ae","def":"a vein of ore, mineral vein; blood-vessel, vein; a stream, channel","form_of":"vena"},"uenami":{"lemma":"Venami","pos":"","gen":"","def":", a people of Gaul, Plin. 4, 19, 33, § 108."},"uenaria":{"lemma":"Venaria","pos":"","gen":"","def":", an island in the Tuscan Sea, Plin. 3, 6, 12, § 81. vēnātīcĭus or -tĭus, a, um, adj. venaticus, of or belonging to hunting or the chase (late Lat.): praeda, game, Amm. 29, 3, 3"},"uenarum":{"lemma":"vena","pos":"n. f.","gen":"-ae","def":"a vein of ore, mineral vein; blood-vessel, vein; a stream, channel","form_of":"vena"},"uenas":{"lemma":"vena","pos":"n. f.","gen":"-ae","def":"a vein of ore, mineral vein; blood-vessel, vein; a stream, channel","form_of":"vena"},"uendax":{"lemma":"vendax","pos":"adj.","gen":"","def":"vendo, fond of selling: patrem familias vendacem, non emacem esse oportet, Cato, R. R. 2 fin. vendĭbĭlis, e, adj. id., that may be sold, salable"},"uendo":{"lemma":"vendo","pos":"v.","gen":"-do","def":"a. contr. from venum-do, venundo"},"uenit":{"lemma":"venio","pos":"","gen":"","def":"(form of venio)"},"ueniunt":{"lemma":"venio","pos":"","gen":"","def":"(form of venio)"},"uennenses":{"lemma":"Vennenses","pos":"","gen":"","def":", a people of Hispania Tarraconensis, Plin. 3, 3, 4, § 26. Vennōnĭus, ĭi, m., a Roman historian whose works are lost, Cic. Att. 12, 391"},"uenter":{"lemma":"venter","pos":"","gen":"","def":"perh. for gventer; cf. Gr. γαστήρ; Sanscr. gatharas. Lit. In gen., the belly (syn.: alvus, abdomen), Plin. 11, 37, 82. § 207; Cels. 7, 16; Varr. R. R. 2, 7, 4"},"uento":{"lemma":"vento","pos":"","gen":"","def":"freq. a. id., to be wont to come, to come, Varr. ap. Non. 119, 2. ventōsē, adv., v. ventosus fin. ventōsĭtas, ātis, f. ventosus (postclass.). Lit., windiness, flatulence, ventosity: ventris"},"uentus":{"lemma":"ventus","pos":"","gen":"","def":"Sanscr. vā, blow; vatas, wind; Gr. root αϝ-, ἄω, ἄημι, to blow; whence ἀήρ, αὔρα, etc.; Goth. vaia, to breathe"},"uerbannus":{"lemma":"Verbannus","pos":"","gen":"","def":", the name of a lake in Upper Italy, now Lago Maggiore: lacus, Plin. 2, 103, 106, § 224; 3, 19, 23, § 131."},"uerbascum":{"lemma":"verbascum","pos":"","gen":"","def":", a plant, mullein, Plin. 25, 10, 73, § 120; 26, 4, 11, § 23."},"uerbeia":{"lemma":"Verbeia","pos":"","gen":"","def":", a goddess worshipped by the Gauls and Britons, perh. = VICTORIA, Inscr. Grut. 89, 7; 1017, 2. verbēna, ae, f. (v. Don. ad Ter. And. 4, 3, 11)"},"uerber":{"lemma":"verber","pos":"","gen":"","def":", dat., and acc. sing. do not occur, and the sing. in gen. very rarely; Neue, Formenl. 1, p. 476), n., a lash, whip, scourge, rod (syn.: scutica, flagrum), Lit. (rare"},"uerbum":{"lemma":"verbum","pos":"","gen":"","def":"plur. verbūm, Plaut. As. 1, 3, 1; id. Bacch. 4, 8, 37; id. Truc. 2, 8, 14), n. from the root er; Gr. ΕΡω, whence εἴρω and ῥῆμα, what is spoken or said; cf. Goth. vaurd; Germ. Wort; Engl. word, a word"},"uercellae":{"lemma":"Vercellae","pos":"adj.","gen":"","def":", a town in Gallia Cisalpina, now Borgo Vercelli, Plin. 3, 17, 21, § 124; Brut. ap. Cic. Fam. 11, 19, 2"},"uergellus":{"lemma":"Vergellus","pos":"","gen":"","def":", a river of Apulia, Val. Max. 9, 2, ext. 2; Flor. 2, 6, 18."},"uergentum":{"lemma":"Vergentum","pos":"","gen":"","def":", a town in Hispania Baetica, Plin. 3, 1, 3, § 11. Vergĭlĭae, ārum, f. vergo, the constellation of the seven stars, that rises at the end of spring, the Pleiades, Cic. N. D. poët. 2, 44, 112"},"uergo":{"lemma":"vergo","pos":"v.","gen":"","def":"and sup. wanting, acc. to Neue, Formenl. 2, pp. 507, 584; but versi is assumed as perf. by Prob. Cath. 1486, and is read, Ov. P. 1, 9, 52, by Merkel, ex conj. for the MS. vertit"},"uermesco":{"lemma":"vermesco","pos":"v.","gen":"","def":"n. (eccl. Lat.), Aug. in Joan. tr. 35, 8. vermĭcŭlātē, adv., v. vermiculor fin. vermĭcŭlātĭo, ōnis, f. vermiculor, a being worm-eaten, of plants, Plin. 17, 24, 37, §§ 218 and 230"},"uermis":{"lemma":"vermis","pos":"","gen":"","def":"Gr. ἕλμις; cf. Sanscr. krmis, worm; Goth. vaùrms, serpent, a worm, Lucr. 2, 871; 2, 928; 3, 719; 3, 723; Plin. 18, 17, 45, § 159; 24, 5, 11, § 18; 30, 13, 39, § 114; Col. 6, 30 fin."},"uerna":{"lemma":"verna","pos":"","gen":"-nus","def":"root vas, to dwell; Sanscr. vāstu, house; Gr. ἄστυ, city, a slave born in his master's house, a homeborn slave. Lit.: vernas alere, Plaut. Mil. 3, 1, 104; id. Am. 1, 1, 24; Just. 38, 6, 7"},"uerno":{"lemma":"verno","pos":"v.","gen":"","def":"n. ver, to appear like spring, to flourish, be verdant; to spring, bloom, grow young, renew itself, etc. (poet. and in post-Aug. prose"},"uernum":{"lemma":"vernum","pos":"","gen":"","def":"2. vernus, II."},"uernus":{"lemma":"vernus","pos":"","gen":"","def":"verna, II. B."},"uerpa":{"lemma":"verpa","pos":"","gen":"","def":", = membrum virile, Cat. 28, 12; Mart. 11, 46, 2; Auct. Priap. 35."},"uerpus":{"lemma":"verpus","pos":"","gen":"","def":", a circumcised man, Cat. 47, 4; Juv. 14, 104; Mart. 7, 82, 6; 11, 94, 2. verres, is (collat. form of the nom. sing. verris, Varr. R. R. 2, 4, 8), m. Sanscr. root varsh-, to rain, wet"},"uerres":{"lemma":"Verres","pos":"adj.","gen":"-us","def":", the surname of the proetor C. Cornelius, notorious for his bad government of Sicily"},"uerro":{"lemma":"verro","pos":"v.","gen":"","def":"versi, Serv. ad Verg. A. 1, 59: verri, Charis. p. 218; Prisc. p. 900; neither form in use, acc. to Macr. D. Diff. 23, 8), 3, v. a. root var-; cf. vello, to scrape, sweep, brush, scour"},"uerrugo":{"lemma":"Verrugo","pos":"","gen":"","def":", a town of the Volsci, now Colle Ferro or Colle Sacco, near Segni, Liv. 4, 1; 4, 55; 4, 58; 5, 28; Val. Max. 3, 2, 8."},"uerrunco":{"lemma":"verrunco","pos":"v.","gen":"","def":"n., to turn, turn about; hence, in relig. lang., to turn out well, have a fortunate issue: bene, Att. and Pac. ap. Non. 185, 24; Att. ap. Cic. Div. 1, 22, 45; Liv. 29, 27, 2; cf. Fest. p. 373."},"uerrutius":{"lemma":"Verrutius","pos":"","gen":"","def":"Verrucius. versābĭlis, e, adj. verso, movable, mobile; changeable, mutable, versatile (postAug."},"uersor":{"lemma":"versor","pos":"","gen":"","def":"verso, II. versōrĭa (vors-), ae, f. verto, a rope that guides a sail, a sheet (Plautin.)"},"uertacomacori":{"lemma":"Vertacomacori","pos":"","gen":"","def":", a tribe of the Vocontii, Plin. 3, 17, 21, § 124. vertăgus, i, m. Celtic, a greyhound, Mart. 14, 200, 1"},"ueruactum":{"lemma":"vervactum","pos":"","gen":"","def":"vervago, fallow ground, a fallow field, Cato, R. R. 27; Varr. R. R. 1, 44, 2; Col. 11, 2, 32; 11, 2, 52; Plin. 18, 19, 49, § 176; Pall. 4, 2. vervăgo, ĕre, v. a. etym. unknown"},"uescia":{"lemma":"Vescia","pos":"adj.","gen":"-ni","def":", a little town in Latium, on the river Liris, Liv. 8, 11; 9, 25.—Hence, Vescīnus, a, um, adj., of or belonging to Vescia, Vescinian: ager, Cic. Agr. 2, 25, 66; Liv. 10, 21"},"uesco":{"lemma":"vesco","pos":"v.","gen":"","def":"a. vescor, to feed with any thing: quis nos vescet carne, Tert. Jejun. 5.—Pass., Isid. Orig. 20, 2, 27: vescendi pupilli causā, Dig. 42, 5, 33."},"uescor":{"lemma":"vescor","pos":"v.","gen":"","def":"dep. n. and a. [ve- and root ed- of edo; cf. esca], to fill one's self with food, to take food, feed, eat. Lit. (class."},"uescus":{"lemma":"vescus","pos":"adj.","gen":"","def":"contr. from veesca. Small, little, thin, weak, feeble: farra (opp. vegrandia), Ov. F. 3, 445: papaver, Verg. G. 4, 131: frondes, id. ib. 3, 175 Serv.: corpus, Plin. 7, 20, 19, § 81: vires"},"uespa":{"lemma":"vespa","pos":"","gen":"","def":"Gr. σφήξ; O. H. Germ. wefsa; Engl. wasp, a wasp, Varr. R. R. 3, 16, 19; Plin. 11, 21, 24, § 71; 20, 13, 51, § 133"},"uespillo":{"lemma":"vespillo","pos":"","gen":"-bearer","def":"dim. 2. vespa, a corpse-bearer who carried out the bodies of the poor at night, Suet. Dom. 17 fin.; Mart. 1, 48, 1; cf. vespae."},"uesta":{"lemma":"Vesta","pos":"adj.","gen":"-st","def":"Sanscr. root vas, to burn; vasaras, day; whence also Gr. Εστία. Another name for Ops, Cybele, Terra, the wife of Coelus and mother of Saturn, Cic. N. D. 2, 27, 67"},"uestis":{"lemma":"vestis","pos":"","gen":"","def":"Sanscr. root vas-, to put on; Gr. ἑσ-, ϝεσ-; cf. ἕννυμι, ἐσθής, the covering for the body, clothes, clothing, attire, vesture (syn. amictus"},"uestras":{"lemma":"vestras","pos":"","gen":"","def":"vester, of your family or nation, acc. to Charis. p. 133 P.; Diom. p. 317 ib.; Prisc. p. 1095 ib. Vĕsŭlus, i, m., a mountain in Liguria, now Monte Viso, Mel. 2, 4, 4; Verg. A. 10, 708"},"uesuni":{"lemma":"Vesuni","pos":"","gen":"","def":", a people of Libya, Plin. 5, 2, 1, § 17. Vĕsŭvĭus, ii, m. ve and σβε-, root of σβέννυμι; v. Lidd. and Scott s. v., a celebrated volcano in Campania, Liv. 8, 8, 19; Mel. 2, 4, 9; Plin. 14, 2, 4, § 22"},"uettius":{"lemma":"Vettius","pos":"","gen":"","def":", the name of a Roman gens, Cic. Att. 2, 4, 7; 6, 1, 15"},"uexillum":{"lemma":"vexillum","pos":"","gen":"","def":"dim. of vēlum, a military ensign, standard, banner, flag. In gen., Caes. B. G. 6, 36; Cic. Phil. 2, 40, 102; 5, 11, 29; id. Att. 10, 15, 2; id. Agr. 2, 32, 86"},"uffugum":{"lemma":"Uffugum","pos":"","gen":"","def":", a town in the territory of the Bruttii, now Fagnano, Liv. 30, 19. ulcĕrārĭa, ae, f. (sc. herba) , the plant horehound, App. Herb. 45. ulcĕrātĭo, ōnis, f. ulcero, a breaking out into sores"},"uibo":{"lemma":"vibo","pos":"","gen":"","def":", the flower of the herb called Britannica, Plin. 25, 3, 6, § 21. Vibo or Vibon, ōnis, f., a town in the territory of the Bruttii, now Monteleone, Mel. 2, 4, 9; Plin. 3, 5, 10, § 73"},"uicta":{"lemma":"Victa","pos":"","gen":"","def":"2. victus, the goddess that presides over food, Arn. 3, 115. victĭma, ae, f. perh. root vig- of vigeo; with superl. ending"},"uictor":{"lemma":"victor","pos":"","gen":"","def":"vinco. In gen., a conqueror, vanquisher, victor. Prop. Absol.: quod (sc. stipendium) victores victis imponere consuērint, Caes. B. G. 1, 44: multa victori, eorum arbitrio, per quos vicit"},"uillum":{"lemma":"villum","pos":"","gen":"","def":"dim. contr. from vinulum, from vinum, a sup of wine: hoc villi, Ter. Ad. 5, 2, 11."},"uillus":{"lemma":"villus","pos":"","gen":"","def":"Sanscr. urā, sheep; Gr. εἶρος, wool; cf. vellus, shaggy hair, a tuft of hair; of beasts, Cic. N. D. 2, 47, 121; id. ib. 2, 63, 158; Verg. G. 3, 446; id. A. 5, 352; Ov. H. 6, 49; Mart. 14, 136, 2"},"uinco":{"lemma":"vinco","pos":"v.","gen":"-vicax","def":"a. and n. perh. causat. of root ικ-; Gr. εἴκω, to yield; but cf. per-vicax"},"uinctor":{"lemma":"vinctor","pos":"","gen":"","def":"id., a binder (postclass.); (with congregator) Arn. 6, 199. vinctūra, ae, f. id., a bandage, ligature, vincture, Cels. 7, 20; 8, 10, 1; Plin. 16, 37, 68, § 174"},"uinctus":{"lemma":"vinctus","pos":"","gen":"","def":"vincio, a binding: vinctu, quod antiqui vocabant cestum, Varr. R. R. 1, 8, 6. vincŭlo, āvi, ātum, 1, v. a. id., to fetter, bind, chain: multa animalia redimiculis gaudent"},"uindex":{"lemma":"vindex","pos":"","gen":"","def":"vindico. One who lays legal claim to a thing, a claimant"},"uindicta":{"lemma":"vindicta","pos":"","gen":"-rod","def":"vindico, the staff or rod with which a slave was touched in the ceremony of manumission, a liberating-rod, manumission - staff. Lit., Dig. 4, 16"},"uirga":{"lemma":"virga","pos":"","gen":"-plant","def":"root varg; v. virgo, a slender green branch, a twig, sprout, switch, rod. Lit. In gen., Cato, R. R. 101; Varr. R. R. 1, 59, 4; Plin. 17, 18, 30, § 136; 24, 19, 112, § 172; Verg. G. 1, 266"},"uirgo":{"lemma":"virgo","pos":"adv.","gen":"-jami","def":"root varg-; Sanscr. ūrg, strength, ūrga-jami, nourish"},"uirgultus":{"lemma":"virgultus","pos":"adj.","gen":"","def":"virgultum, full of bushes or thickets, shrubby: vallis, Sall. Fragm. ap. Serv. Verg. A. 3, 516; Sil. 12, 354. virguncŭla, ae, f. dim. virgo, a little maid, young girl, Petr. 18; 20"},"uisco":{"lemma":"visco","pos":"v.","gen":"","def":"a., to smear, besmear: cum se inter articulorum conjunctiones usu commotionum viscaverit (sanies), Theod. Prisc. 2, 21: spirat et hinc miseri viscantur labra mariti, are glued, smeared, Juv. 6"},"uiscum":{"lemma":"viscum","pos":"","gen":"","def":"(m. collat. form viscus, i, Plaut. Bacch. 1, 1, 16) [cf. Gr. ἰξός, ϝιξος; Lat. viscus], the mistletoe. Lit., Plin. 16, 44, 94, § 248; 24, 4, 6, § 11"},"uiscus":{"lemma":"viscus","pos":"","gen":"","def":"viscum init. vīsĭbĭlis, e, adj. video. Pass., that may be seen, visible (late Lat. for adspectabilis): exhalationes tenues vixque visibiles, App. de Mundo, p. 60, 37"},"uisor":{"lemma":"visor","pos":"","gen":"","def":", a scout, only in a gloss ap. Tac. A. 16, 2; omitted by Draeg. and Halm."},"uispellio":{"lemma":"vispellio","pos":"","gen":"-clothes","def":", a class of thieves who robbed corpses of their grave-clothes, Dig. 21, 2, 31; 36, 1, 7 fin."},"uitellenses":{"lemma":"Vitellenses","pos":"","gen":"","def":", a people of Latium, Plin. 3, 5, 9, § 69. Vitellĭa, ae, f., an ancient town of the Aequi, near the modern Valmontone, Liv. 2, 39; 5, 29"},"uitiparra":{"lemma":"vitiparra","pos":"","gen":"","def":", a small bird, otherwise unknown, perh. the titmouse, Plin. 10, 33, 50, § 96. vītis, is, f. root in Sanscr. vjā, to cover; cf. Goth. vindan; Germ. winden, to bind; Lat. vieo"},"uitta":{"lemma":"vitta","pos":"","gen":"-band","def":"vieo, a band, esp. a fillet or chaplet worn round the head; and, in relig. lang., a head-band, a sacrificial or sacerdotal fillet, Ov. M. 2, 413; 4, 6; 5, 110; Prop. 4 (5), 11, 34; Verg. A. 2, 133"},"uiuerra":{"lemma":"viverra","pos":"","gen":"","def":", a ferret: Mustella furo, Linn.; Plin. 11, 49, 109, § 261; 8, 55, 81, § 218"},"uix":{"lemma":"vix","pos":"adv.","gen":"","def":"etym. dub.; perh. from root vic- of vinco, with difficulty, with much ado, hardly, scarcely, barely. In gen.: quid est, sine his cur vivere velimus? mihi vero cum his ipsis vix"},"uixdum":{"lemma":"vixdum","pos":"adv.","gen":"","def":", v. vix, II. C."},"uixet":{"lemma":"vixet","pos":"","gen":"","def":"vivo init. vōbīs, dat. and abl. of vos"},"ulcisco":{"lemma":"ulcisco","pos":"","gen":"","def":"ulciscor fin."},"ulciscor":{"lemma":"ulciscor","pos":"","gen":"-personal","def":"inch. dep. . To avenge one's self on, take vengeance on, or punish for wrong done (very freq. and class."},"ulex":{"lemma":"ulex","pos":"","gen":"","def":", a shrub resembling rosemary, Plin. 33, 4, 21, § 76. Ulĭa, ae, f., a town of Hispania Baetica, Auct. B. Hisp. 3; Auct. B. Alex. 61"},"ullus":{"lemma":"ullus","pos":"adj.","gen":"","def":"ullīus; dat. ulli (gen. sing. ulli, Plaut. Truc. 2, 2, 38), adj. dim. , any, any one (usu. in neg. sentences"},"ulmus":{"lemma":"ulmus","pos":"","gen":"-tree","def":"(masc., Cat. 62, 54; v. infra), an elm, elm-tree. Lit., Plin. 17, 11, 15, § 76; Col. 5, 6; Verg. G. 1, 2; 2, 446; Ov. M. 10, 100; 14, 661; Hor. C. 1, 2, 9; 2, 15, 5; id. Ep. 1, 16, 3"},"ulna":{"lemma":"ulna","pos":"","gen":"","def":"Gr. ὠλένη; Goth. aleina; Germ. Elle; cf. Ellenbogen; Engl. ell, the elbow. Lit., Plin. 11, 43, 98, § 243.— Transf. Poet., in gen., the arm: tremula patris dormientis in ulnā, Cat. 17, 13"},"ulpius":{"lemma":"Ulpius","pos":"adj.","gen":"","def":", the name of a Roman gens. So esp., M. Ulpius Trajanus, the celebrated Roman emperor of that name.—Hence, Ulpĭus, a, um, adj., of or belonging to Ulpius: porticus, Sid. Carm. 8, 8. uls (ouls"},"ulter":{"lemma":"ulter","pos":"adj.","gen":"-t","def":"(comp. ulterior, us; sup. ultimus) [cf.: uls, ollus, olim"},"ultor":{"lemma":"ultor","pos":"","gen":"","def":"ulciscor, a punisher, avenger, revenger. In gen. (class.): conjurationis investigator atque ultor, Cic. Sull. 30, 85: Publius nostrarum injuriarum ultor, id. Brut. 77, 268"},"ultrix":{"lemma":"ultrix","pos":"adj.","gen":"","def":"ultor, avenging, vengeful. Adj. (poet.): ultricesque sedent in limine Dirae, the avenging goddesses, i. e. the Furies, Verg. A. 4, 473; cf. Furiae, Claud. Ep. 1, 14"},"ultrorsum":{"lemma":"ultrorsum","pos":"adv.","gen":"","def":"contr. from ultroversum, farther onwards: pergere, Sulp. Sev. Hist. Sacr. 2, 26. ultrōtrĭbūta, ōrum, v. ultro fin. ultus, a, um, Part. of ulciscor. Ŭlūbrae, ārum, f., a small town of Latium"},"ulua":{"lemma":"ulva","pos":"","gen":"","def":"root or-, ol-; cf. origo, sedge: Ulva conferva, Linn.; Plin. 16, 1, 1, § 4; 17, 23, 35, § 209; 21, 17, 68, § 111; Cato, R. R. 37, 2; Col. 4, 13, 2; Verg. G. 3, 175; id. E. 8, 87; Ov. M. 4, 299"},"ulucus":{"lemma":"ulucus","pos":"","gen":"-owl","def":", a screech-owl, = ulula, Serv. Verg. E. 8, 55 (al. alucos). ŭlŭla, ae, f. (sc. avis) [kindr. with Sanscr. ulūka; old Germ. uwila, ūla; new Germ. Eule; Engl. owl"},"umbella":{"lemma":"umbella","pos":"","gen":"","def":"dim. umbra (a little shadow, i. e. meton.), a sunshade, parasol, umbrella, Mart. 14, 28 in lemm.; 11, 73, 6; Juv. 9, 50."},"umber":{"lemma":"Umber","pos":"","gen":"","def":"Umbri, A. umbĭlīcāris, e, adj. umbilicus, of or belonging to the navel, umbilical: nervus, the navel-string, umbilical cord, Tert. Carn. Chr. 20 med. umbĭlīcātus, a, um, adj. id., navel-shaped"},"umbo":{"lemma":"umbo","pos":"","gen":"-stone","def":"kindr. with ἄμβων, ὀμφαλός, umbilicus; Germ. Nabel; Engl. navel; prop. any convex elevation; hence, A boss of a shield, Enn. ap. Macr. S. 6, 3 (Ann. v. 432 Vahl.)"},"umbra":{"lemma":"umbra","pos":"","gen":"","def":"etym. dub."},"umbresco":{"lemma":"umbresco","pos":"","gen":"","def":"inch. n. , to shadow, become shadowy, darken, Cassiod. Compl. Apoc. 3."},"umbri":{"lemma":"Umbri","pos":"adj.","gen":"-br","def":", a people of Italy, in the district of Umbria, which was named after them, Plin. 3, 5, 8, § 50; 3, 14, 19, § 112; Liv. 5, 35"},"umbro":{"lemma":"umbro","pos":"v.","gen":"","def":"a. and n. umbra, to shade, shadow, overshadow, overspread, cover; to make or cast a shade (mostly poet. and in post-Aug. prose"},"unco":{"lemma":"unco","pos":"v.","gen":"","def":"n., to sound or roar like a bear, Carm. Philom. 50. unctĭo, ōnis, f. ungo, a besmearing. anointing. Lit.: sudatoriae, Plaut. Stich. 1, 3, 73: cottidiana, Col. 12, 53"},"unctor":{"lemma":"unctor","pos":"","gen":"","def":"ungo, an anointer, Plaut. Trin. 2, 1, 22; Mart. 12, 70, 3; 7, 32, 6; 12, 70, 3; Cic. Fam. 7, 24, 2; Quint. 11, 3, 26; Aug. Civ. Dei, 6, 10, 2; Inscr. Orell. 2791"},"unctum":{"lemma":"unctum","pos":"","gen":"","def":", v. ungo, P. a. fin. unctūra, ae, f. ungo, an anointing of the dead: servilis, Cic. Leg. 2, 24, 60. unctus, a, um, Part. and P. a. of ungo."},"unctus":{"lemma":"unctus","pos":"","gen":"","def":"ungo, an anointing, anointment: oleum unctui profer, App. M. 1, p. 113, 3: cochlearum cinis cum melle unctu sanat, Plin. 30, 10, 27, § 90 (al. linitu)."},"uncus":{"lemma":"uncus","pos":"","gen":"","def":"Sanscr. root ak, ankami, bend; Gr. ἀγκών, ὄγκος; cf.: ancus, ungulus, a hook, barb. In gen., Liv. 30, 10, 16; Col. 3, 18, 2: ferrei, Cato, R. R. 10"},"undanter":{"lemma":"undanter","pos":"adv.","gen":"","def":", v. undo fin. undātim, adv. undo, in a waving manner, like waves: mensae undatim crispae, Plin. 13, 15, 30, § 96: crispum marmor, id. 36, 7, 11, § 55.— In a throng, Amm. 21, 3, 2. undĕ, adv."},"undo":{"lemma":"undo","pos":"v.","gen":"-like","def":"n. and a. . Neutr., to rise in waves or surges, to throw up waves, to surge, swell (poet. and in postAug. prose). Lit.: undantem salum, Enn. ap. Non. 223, 24 (Trag. v. 226 Vahl.)"},"unelli":{"lemma":"Unelli","pos":"","gen":"","def":", a people in Gallia Lugdunensis, bordering on the Curiosolitoe and Lexovii, whose country formed part of the Tractus Armoricus"},"unguen":{"lemma":"unguen","pos":"","gen":"","def":"id., a fatty substance, fat; an ointment, unguent: in aënum caldum unguen indito, Cato, R. R. 79; 80: pingues unguine ceras, Verg. G. 3, 450: cras. sum, Pers. 6, 40: pingue, Val. Fl. 6, 360"},"unguento":{"lemma":"unguento","pos":"v.","gen":"","def":"a. id., to rub with sweet ointments, to anoint, perfume (in verb. finit. very rare): DEAS VNGVENTAVERVNT, Inscr. Fratr. Arval. Orell. 2271, 391 (cf. Cic. Verr. 2, 4, 35"},"unguentum":{"lemma":"unguentum","pos":"","gen":"","def":"plur. unguentūm, Plaut. Curc. 1, 2, 5; id. Poen. 3, 3, 88), n. unguo, an ointment, unguent, perfume: non omnes possunt olere unguenta exotica, Plaut. Most. 1, 1, 41; 1, 3, 115 sq."},"unguilla":{"lemma":"unguilla","pos":"","gen":"-box","def":"unguo, ungo, an ointment-box, Sol. 27 fin. unguĭnōsus, a, um, adj. unguen, full of fat or oil, fat, oily, unctuous: unguentum, Plin. 13, 1, 2, § 17: opus, Cels. 5, 26, 20.—Comp.: nuces, Plin. 23, 8"},"unguo":{"lemma":"unguo","pos":"","gen":"","def":"ungo. ungustus fustis uncus, Fest. p. 377 Müll. ūnĭ-ănĭmis, e, = unanimis, Schol. Juv. 5, 134. ūnĭ-călămus, a, um, adj. unus, having a single stem or straw: frumentum, Plin. 18, 7, 12"},"unquam":{"lemma":"unquam","pos":"adv.","gen":"","def":", v. umquam. ūnus (old forms OINOS and OENOS; cf. Cic. Leg. 3, 3, 9; C. I. L. 1, 32, 35), a, um (scanned gen. sing. unĭus, Lucr. 2, 379; Verg. A. 1, 41; Hor. S. 1, 6, 13 al.: unīus, Verg. A. 1, 251"},"unxia":{"lemma":"Unxia","pos":"","gen":"","def":"ungo, the goddess of anointing, Arn. 3, 115; 7, 227; Mart. Cap. 2, § 149. ūpĭlĭo (eollat. form of ōpĭlĭo, q. v.), ōnis, m. ovis, a shepherd, Verg. E. 10, 19"},"uocio":{"lemma":"Vocio","pos":"","gen":"","def":", a king of the Norici, Caes. B. G. 1, 53. vŏcĭto, āvi, ātum, 1, v. freq. a. and n. voco. Act., to be wont to call, to call, name (class.): igneus Vertex, quem patrio vocitamus nomine fulmen, Lucr. 6"},"uolana":{"lemma":"Volana","pos":"","gen":"","def":", a town of the Samnites, Liv. 10, 44 and 45."},"uolandum":{"lemma":"Volandum","pos":"","gen":"","def":", a fortress of Armenia, Tac. A. 13, 39. vŏlans, antis, Part. and P. a. of 2. volo. Vŏlāterrae, ārum, f., an ancient town in Etruria, now Volterra, Liv. 10, 12"},"uolcae":{"lemma":"Volcae","pos":"","gen":"","def":", a numerous and powerful people in Gallia Narbonensis, divided into the Volcae Arecomici and the Volcae Tectosages, Caes. B. G. 7, 7; 7, 64; id. B. C. 1, 35; id. B. G. 6, 24"},"uolcentes":{"lemma":"Volcentes","pos":"","gen":"","def":", a people of Lucania, Liv. 27, 15"},"uolsce":{"lemma":"Volsce","pos":"","gen":"","def":"Volsci fin."},"uolscens":{"lemma":"Volscens","pos":"","gen":"","def":", an officer of the Latins, Verg. A. 9, 420 al."},"uolsci":{"lemma":"Volsci","pos":"adj.","gen":"","def":", the most considerable people in Latium, the Volsci, Volscians, Mel. 2, 4, 2; Liv. 1, 53; 2, 22 sq.; 3, 6 sq.; Cic. Brut. 10, 41; id. Balb. 13, 31; id. Off. 1, 11, 35"},"uolso":{"lemma":"Volso","pos":"","gen":"","def":"Vulso. volsūra, ae, v. vulsura. volsus, a, um, Part. of vello. volt, voltis, old forms for vult, vultis, from volo, q. v."},"uolta":{"lemma":"Volta","pos":"","gen":"","def":"2, 53, 54, § 140. voltĭcŭlus, i, v. vulticulus. Voltinĭa trĭbus, one of the Roman tribes, of unknown locality, Cic. Planc. 16, 38; 17, 43; Inscr. Grut. 418, 3"},"uoltumna":{"lemma":"Voltumna","pos":"","gen":"","def":", the tutelary goddess of the Etruscan Confederation, in whose temple their general assemblies were held, Liv. 4, 23; 4, 25; 4, 61; 5, 17. voltŭōsus, voltur, etc., v. vult-."},"uolturnus":{"lemma":"Volturnus","pos":"","gen":"","def":"Vulturnus."},"uoltus":{"lemma":"voltus","pos":"","gen":"","def":"vultus. vŏlūbĭlis, e, adj. volvo, that is turned round or (more freq.) that turns itself round, turning, spinning, whirling, circling, rolling, revolving. Lit.: buxum, i. e. a top, Verg. A. 7"},"uoluo":{"lemma":"volvo","pos":"v.","gen":"","def":"pass. volvier, Lucr. 5, 714), v. a. Sanscr. varas, circumference; Gr. ἐλύω, to wrap"},"uorsipellis":{"lemma":"vorsipellis","pos":"","gen":"","def":"versipellis. vorso, vorsōrĭus, vorsum, etc., v. vers-. vortex, vortĭcōsus, vorto, etc., v. vert-."},"uos":{"lemma":"vos","pos":"pron.","gen":"","def":", v. tu. Vŏsĕgus (Vŏsăgus, and, less correctly, Vŏgĕsus), i, m., a chain of mountains in Gaul, the modern Vosges, Caes. B. G. 4, 10; Luc. 1, 397; Inscr. Orell. 2072."},"uoster":{"lemma":"voster","pos":"","gen":"","def":"vester. vōtĭfer, fĕra, fĕrum, adj. votum-fero, vow-bearing, votive: arbor, Stat. S. 4, 4, 92"},"uox":{"lemma":"vox","pos":"","gen":"","def":"voco, a voice, sound, tone, cry, call. Lit.: omnes voces hominis, ut nervi in fidibus, ita sonant, ut a motu animi quoque sunt pulsae, etc., Cic. de Or. 3, 57, 216: exsurge praeco ... Exerce vocem"},"urna":{"lemma":"urna","pos":"","gen":"-pot","def":"prop. a vessel of burnt clay; root uro, a vessel for drawing water, a water-pot, water-jar, urn. Lit.: urnae dictae, quod urinant in aquā hauriendā ut urinator, Varr. L. L. 5, § 126 Müll."},"urruncum":{"lemma":"urruncum","pos":"","gen":"","def":"cf. Gr. οὐρά, tail, the lowest part of an ear of corn, Varr. R. R. 1, 48, 3."},"ursa":{"lemma":"ursa","pos":"","gen":"-bear","def":"ursus, a she-bear. Lit., Ov. M. 2, 485; 13, 803; 13, 836; 15, 379; id. F. 2, 181; Mart. 6, 25, 2.— Poet., a bear, in gen., Verg. A. 5, 37; Ov. M. 12, 319"},"ursus":{"lemma":"ursus","pos":"","gen":"-baiting","def":"for urcsus; Sanscr. arća; Gr. ἄρκτος, a bear, Plin. 8, 36, 54, § 131; Ov. M. 2, 494; 10, 540; Hor. Epod. 16, 51; id. C. 3, 4, 18; id. A. P. 472; Juv. 4, 106; Sen. Ira, 2, 31, 6; 3, 43, 2"},"uruca":{"lemma":"uruca","pos":"","gen":"","def":"Plin. vocab. and eruca. ūrus, i, m. Celtic, a kind of wild ox, a ure-ox, urus, Caes. B. G. 6, 28; Plin. 8, 15, 15, § 38; Verg. G. 2, 374; 3, 532"},"usquam":{"lemma":"usquam","pos":"adv.","gen":"","def":"us for ubs, from ubi; indef. suffix quam, as in quisquam, etc."},"usta":{"lemma":"usta","pos":"","gen":"","def":"uro, a kind of red color, burnt cinnabar, Plin. 35, 6, 20, § 38; Vitr. 7, 11 fin."},"ustor":{"lemma":"ustor","pos":"","gen":"-burner","def":"id., a burner of dead bodies, a corpse-burner, Cic. Mil. 33, 90; Cat. 59, 5; Mart. 3, 93, 26"},"usurpo":{"lemma":"usurpo","pos":"v.","gen":"-class","def":"a. perh. contr. from usu rapio, to seize to one's own use, to take into use; to make use of; to use, employ, apply, practise, exercise, enjoy (class."},"uulpis":{"lemma":"vulpis","pos":"","gen":"","def":"vulpes init."},"uulsella":{"lemma":"vulsella","pos":"","gen":"","def":"volsella. Vulsĭnĭī and Vulsĭnĭenses, v. Volsinii. vulsĭo, ōnis, f. vello, a plucking, Veg. 3, 65. Vulso (Vols-), ōnis, m., a cognomen in the Manlian gens: Manlius Vulso, Liv. 22, 35"},"uultum":{"lemma":"vultum","pos":"","gen":"","def":"vultus init. vultŭōsus (volt-), a, um, adj. vultus, of an expressive countenance, full of expression, full of airs or grimaces, grimacing, affected: homo, Prud. στεφ. 10, 171: frons, App. M. 3"},"uulua":{"lemma":"vulva","pos":"","gen":"","def":"volva. vulvŭla, ae, v. volvula. X X, x"},"xanthippus":{"lemma":"Xanthippus","pos":"","gen":"","def":", = Ξάνθιππος. The father of Pericles, Cic. Brut. 11, 44.— A Lacedoemonian, who took Regulus prisoner, Cic. Off. 3, 26, 99."},"xantho":{"lemma":"Xantho","pos":"","gen":"-nymph","def":", = Ξανθώ, a sea-nymph, daughter of Nereus and Doris, Verg. G. 4, 336."},"xanthos":{"lemma":"xanthos","pos":"","gen":"","def":", = ξάνθος, a precious stone of a golden color, otherwise unknown, Plin. 37, 10, 60, § 169."},"xanthus":{"lemma":"Xanthus","pos":"","gen":"","def":", = Ξάνθος, the name of several rivers. A river of Troas, confounded by many with the Scamander, Plin. 5, 30, 33, § 124; 2, 103, 106, § 230; Verg. A. 1, 473; 5, 634 al.; Ov. M. 2, 245; 9, 646"},"xylon":{"lemma":"xylon","pos":"","gen":"-tree","def":", = ξύλον (wood"},"xyris":{"lemma":"xyris","pos":"","gen":"","def":", = ξυρίς, wild iris, Plin. 21, 20, 83, § 143."},"xystarches":{"lemma":"xystarches","pos":"","gen":"","def":", = ξυστάρχης, the master, director, or manager of a xystus, Amm. 21, 1, 4"},"xystus":{"lemma":"xystus","pos":"","gen":"","def":", or xystum, i, n., = ξυστός or ξυστόν. Among the Greeks, a covered portico or gallery, where the athletes exercised in winter, Vitr. 5, 11, 4; 6, 10, 5"},"zancha":{"lemma":"zancha","pos":"","gen":"","def":", a kind of soft Parthian shoe, Gallien. ap. Treb. Claud. 17; Cod. Th. 14, 10, 2. Zanclē, ēs, f., = Ζάγκλη, an older name of the city of Messana (Messina), in Sicily, Ov. M. 14, 5; 15, 290"},"zanthenes":{"lemma":"zanthenes","pos":"","gen":"","def":", a yellow gem, Plin. 37, 10, 70, § 185. zāplūtus, a, um, adj., = ζάπλουτος, very rich, Petr. 37. zēa, ae, f., = ζειἀ. A kind of grain, spelt: Triticum spelta, Linn. (pure Lat. alica)"},"zeros":{"lemma":"zeros","pos":"","gen":"","def":", a precious stone, otherwise unknown, Plin. 37, 9, 53, § 138 (al. leros). Zērynthĭus, a, um, adj., = Ζηρύνθιος, of or belonging to the Thracian town of Zerynthus, Zerynthian: litora, Ov. Tr. 1, 10"},"zeugma":{"lemma":"zeugma","pos":"","gen":"","def":", = ζεῦγμα, a grammatical figure, according to which two nouns or two infinitives are united to a verb which is applicable to only one of them, Ascon. ad Cic. Verr. 1, 18."},"zirbus":{"lemma":"zirbus","pos":"","gen":"","def":", = omentum, the caul, omentum, Apic. 8, 6 fin. zīzānĭa, ōrum, n., = ζιζάνια, darnel, cockle, tares (eccl. Lat.), Prud. Apoth. 6, 8; Vulg. Matt. 13, 25; 13, 26 sq."},"zmaragdachates":{"lemma":"zmaragdachates","pos":"","gen":"","def":"smarag-."},"zmaragdus":{"lemma":"zmaragdus","pos":"","gen":"","def":"smaragdus init."},"zmaris":{"lemma":"zmaris","pos":"","gen":"","def":"smaris. zmectĭcus, v. smecticus."},"zmegma":{"lemma":"zmegma","pos":"","gen":"","def":"smegma."},"zmilampis":{"lemma":"zmilampis","pos":"","gen":"","def":", a precious stone, otherwise unknown, Plin. 37, 10, 70, § 185."},"zmilax":{"lemma":"zmilax","pos":"","gen":"","def":"smilax."},"zmintha":{"lemma":"zmintha","pos":"","gen":"","def":", an aromatic plant, a kind of mint, Plin. 19, 10, 57, § 176. Zmyrna and Zmyrnaeus, a, um, v. Smyrn-."},"zmyrus":{"lemma":"zmyrus","pos":"","gen":"","def":"smyrus. zōdĭăcus, i, m., = ζωδιακός, the zodiac (pure Lat. orbis signifer), Cic. Arat. 317"},"zoranisceos":{"lemma":"zoranisceos","pos":"","gen":"","def":", a precious stone, otherwise unknown, Plin. 37, 10, 70, § 185. Zōrŏastres, is, m., Zoroaster, a lawgiver of the Medes, Just. 1, 1, 9; Plin. 30, 1, 2, § 3"},"zoster":{"lemma":"zoster","pos":"","gen":"","def":", = ζωστήρ (a girdle). A kind of herpes, the shingles (cf. zona, II. E.), Plin. 26, 11, 74, § 121.— A kind of sca shrub (called also prason), Plin. 13, 25, 48, § 135."},"zura":{"lemma":"zura","pos":"","gen":"-thorn","def":"African, the seed of the Christ's-thorn (paliurus), Plin. 24, 13, 71, § 115. zygĭa, ae, f., = ζυγία (prop. an adj. from ζύγιος, belonging to or fit for yokes). A tree, called also carpinus"},"zygia":{"lemma":"Zygia","pos":"","gen":"","def":", a name of Juno, as the goddess of marriage, App. M. 6, p. 174, 38."},"zygis":{"lemma":"zygis","pos":"","gen":"","def":", = ζυγίς, wild thyme, App. Herb. 99. zygostăsĭum, ii, n., = ζυγόστασις, the office of a weigh-master, Cod. Th. 15, 26, 1. zygostătes, ae, m., = ζυγοστάτης, a master of the weights, weigh-master"},"zythum":{"lemma":"zythum","pos":"","gen":"-liquor","def":", = ζῦθος, a kind of malt-liquor among the Egyptians, Plin. 22, 25, 82, § 164; Col. 10, 116; Dig. 33, 6, 9 praef."}};
